export const recipes=[{"id":1,"servings":4,"tipType":"pasta","pairingsType":"pasta","nutrition":{"cal":784,"prot":33,"carb":76,"fat":38,"fib":3},"origin":{"hi":"इटली","en":"Italy","ro":"Italia"},"name":{"hi":"स्पैगेटी कार्बोनारा","en":"Spaghetti Carbonara","ro":"Spaghete Carbonara"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"hi":["400 ग्राम स्पैगेटी","200 ग्राम guanciale (या pancetta), 1 सेमी क्यूब में कटा","4 बड़े अंडे की जर्दी + 1 साबुत अंडा","80 ग्राम Pecorino Romano, बारीक कद्दूकस","40 ग्राम Parmigiano Reggiano, बारीक कद्दूकस","1 छोटा चम्मच ताज़ी कुटी काली मिर्च","पास्ता के पानी के लिए बारीक समुद्री नमक"],"en":["400g spaghetti","200g guanciale (or pancetta), cut into 1cm cubes","4 large egg yolks + 1 whole egg","80g Pecorino Romano, finely grated","40g Parmigiano Reggiano, finely grated","1 tsp freshly cracked black pepper","Fine sea salt for pasta water"],"ro":["400g spaghete","200g guanciale (sau pancetta), tăiat cuburi de 1 cm","4 gălbenușuri de ou mari + 1 ou întreg","80g Pecorino Romano, ras fin","40g Parmigiano Reggiano, ras fin","1 linguriță piper negru proaspăt măcinat","Sare de mare fină pentru apa de fiert"]},"howIsMade":{"hi":"4 लीटर पानी को तेज़ उबाल पर लाएं, खुलकर नमक डालें जब तक स्वाद सुखद रूप से समुद्र जैसा न हो, फिर स्पैगेटी को पैकेट के al dente समय से 2 मिनट कम पकाएं — वह सॉस में पूरी होगी। इस बीच, guanciale को एक ठंडे चौड़े पैन में मध्यम-धीमी आँच पर रखें और चर्बी को 8–10 मिनट तक धीरे-धीरे रेंडर होने दें जब तक वह सुनहरी हो जाए और किनारे कुरकुरे हो जाएं; ठंडे से शुरू करना जलने से बचाता है और अधिकतम स्वाद निकालता है। जब guanciale रेंडर हो रहा है, अंडे की जर्दी और साबुत अंडा को दोनों चीज़ों और भरपूर मोटी कुटी काली मिर्च के साथ फेंटें जब तक एक गाढ़ा, हल्का, क्रीमी पेस्ट न बन जाए — यही सॉस है। पास्ता छानने से ठीक पहले, कम से कम 250 मिली धुंधले पास्ता पानी को निकालकर पास रखें; घुला हुआ स्टार्च ही चिकनी इमल्शन बनाता है। guanciale पैन को आँच से पूरी तरह उतार लें — यह क़दम बिना समझौता है — फिर छाने हुए, भाप उठते स्पैगेटी को सीधे उसमें डालें और 30 सेकंड तक उछालें ताकि हर लच्छा रेंडर हुई चर्बी सोख ले। अंडे की क्रीम पास्ता पर डालें, फिर पास्ता पानी को थोड़ा-थोड़ा कर के डालते जाएं, लगातार चलाते और मोड़ते रहें; अवशिष्ट गर्मी अंडे को चिकनी, चमकीली सॉस में बदल देती है — पानी डालना बंद करें जब सॉस पास्ता को ढक ले बिना जमा हुए। चखें और नमक समायोजित करें — guanciale और Pecorino पहले से नमकीन हैं — फिर थोड़ा और पास्ता पानी डालें अगर प्लेट करते वक़्त सॉस सख्त हो जाए। तुरंत गर्म कटोरों में परोसें, ऊपर Pecorino की कुछ और छीलन और काली मिर्च की कई आत्मविश्वासपूर्ण घुमाव चढ़ाएं।","en":"Bring 4 litres of water to a rolling boil, salt it generously until it tastes pleasantly of the sea, then cook the spaghetti for 2 minutes less than the packet's al dente time — it will finish in the sauce. Meanwhile, place the guanciale in a cold, wide pan over medium-low heat and let the fat render slowly for 8–10 minutes until it turns golden and the edges crisp; starting from cold prevents burning and draws out maximum flavour. While the guanciale renders, beat the egg yolks and whole egg with both cheeses and a generous amount of coarsely cracked pepper until you have a thick, pale, creamy paste — this is the sauce. Just before draining, scoop out at least 250 ml of the cloudy pasta water and keep it within reach; the dissolved starch is what makes a smooth emulsion possible. Take the guanciale pan completely off the heat — this step is non-negotiable — then add the drained, steaming spaghetti directly into it and toss for 30 seconds so every strand absorbs the rendered fat. Pour the egg cream over the pasta, then add pasta water a small splash at a time, tossing and folding constantly; the residual heat sets the egg into a smooth, glossy sauce — stop adding water when the sauce coats the pasta without pooling. Taste and adjust salt — the guanciale and Pecorino are already salty — then add a little more pasta water if the sauce tightens as you plate. Serve immediately in warm bowls, finish with an extra shaving of Pecorino and several confident turns of the pepper mill."}},{"id":2,"origin":{"hi":"रोमानिया","en":"Romania","ro":"România"},"name":{"hi":"ट्राइप सूप","en":"Tripe Soup","ro":"Ciorbă de burtă"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"soup","pairingsType":"soup","nutrition":{"cal":320,"prot":27,"carb":8,"fat":20,"fib":1},"ingredients":{"hi":["800 ग्राम पहले से साफ़ की हुई बीफ़ बुर्ता (tripe), 5×1 सेमी पट्टियों में कटी","2 मध्यम गाजर (लगभग 200 ग्राम)","1 अजमोद की जड़","1 टुकड़ा celeriac (लगभग 150 ग्राम)","1 बड़ी प्याज़","4 लहसुन की कलियाँ, कुचली हुई","3 बड़े अंडे, केवल जर्दी","300 मिली पूरी वसा वाली खट्टी क्रीम (कम से कम 20%)","3 बड़े चम्मच वाइट वाइन सिरका","नमक और सफ़ेद मिर्च स्वादानुसार","ताज़े lovage के पत्ते (वैकल्पिक)"],"en":["800g pre-cleaned beef tripe, cut into 5×1 cm strips","2 medium carrots (about 200g)","1 parsley root","1 piece celeriac (about 150g)","1 large onion","4 garlic cloves, crushed","3 large eggs, yolks only","300ml full-fat sour cream (min. 20%)","3 tbsp white wine vinegar","salt and white pepper to taste","fresh lovage leaves (optional)"],"ro":["800g burtă de vită (precurățată și fiartă), tăiată fâșii de 5×1 cm","2 morcovi medii (aprox. 200g)","1 rădăcină de pătrunjel","1 bucată țelină rădăcină (aprox. 150g)","1 ceapă mare","4 căței de usturoi, pisați","3 ouă mari, gălbenușurile separate","300ml smântână grasă (min. 20%)","3 linguri oțet de vin alb","sare și piper alb după gust","frunze de leuștean proaspăt (opțional)"]},"howIsMade":{"hi":"अगर बुर्ता पहले से साफ़ नहीं है, उसे ठंडे बहते पानी के नीचे मोटे नमक से अच्छी तरह रगड़ें और 3–4 बार धोएं। बुर्ता को नमकीन पानी में धीमी आँच पर 2–3 घंटे उबालें जब तक काँटे से आसानी से छेद हो जाए — या प्रेशर कुकर में 40–50 मिनट। छानें और 5×1 सेमी पट्टियों में काटें। 2 लीटर नमकीन पानी में गाजर, अजमोद की जड़, celeriac और प्याज़ को 40 मिनट तक उबालें, फिर सब्ज़ियाँ निकाल दें (या ब्लेंड कर के गाढ़े सूप के लिए वापस डालें)। बुर्ता की पट्टियाँ शोरबे में डालें और 15 मिनट उबालें। अंडे की जर्दी को खट्टी क्रीम के साथ चिकना होने तक फेंटें। मिश्रण को टेम्पर करें: क्रीम में गरम शोरबे के कई चम्मच धीरे-धीरे डालें, लगातार फेंटते रहें, फिर वापस बर्तन में डालें — यह फटने से बचाता है। कुचला हुआ लहसुन, सिरका, नमक और सफ़ेद मिर्च मिलाएं। liaison डालने के बाद दोबारा उबालें नहीं — वह फट जाएगा। बहुत गरम परोसें, साथ में मिर्च और लहसुन की चटनी।","en":"If tripe is not pre-cleaned, rub thoroughly with coarse salt under cold running water and rinse 3–4 times. Boil tripe in salted water for 2–3 hours on low heat until easily pierced with a fork — or 40–50 minutes in a pressure cooker. Drain and cut into 5×1 cm strips. Simmer carrots, parsley root, celeriac, and onion in 2L salted water for 40 minutes, then discard the vegetables (or blend and return for a thicker soup). Add the tripe strips to the broth and simmer 15 minutes. Whisk egg yolks with sour cream until smooth. Temper the mixture: ladle several spoonfuls of hot broth into the cream gradually, whisking constantly before pouring it back into the pot — this prevents curdling. Stir in crushed garlic, vinegar, salt, and white pepper. Do not boil again after adding the liaison — it will curdle. Serve piping hot with chilli and garlic sauce on the side."}},{"id":3,"servings":6,"tipType":"def","pairingsType":"def","nutrition":{"cal":770,"prot":21,"carb":27,"fat":62,"fib":1},"origin":{"hi":"फ्रांस","en":"France","ro":"Franța"},"name":{"hi":"क्विश लोरेन","en":"Quiche Lorraine","ro":"Quiche Lorraine"},"category":{"hi":"नाश्ता","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"hi":["200 ग्राम शॉर्टक्रस्ट पेस्ट्री (1 शीट), ब्लाइंड-बेक्ड","200 ग्राम स्मोक्ड लार्डन या स्मोक्ड बेकन, क्यूब में कटी हुई","3 बड़े अंडे","300 मिली डबल क्रीम (कम से कम 35% वसा)","60 ग्राम ग्रुयेर चीज़, बारीक कसा हुआ","1/4 छोटा चम्मच ताज़ा कसा जायफल","नमक और सफेद मिर्च स्वाद अनुसार","सांचे को चिकना करने के लिए मक्खन"],"en":["200g shortcrust pastry (1 sheet), blind-baked","200g smoked lardons or diced smoked bacon","3 large eggs","300ml double cream (min. 35% fat)","60g Gruyère cheese, finely grated","1/4 tsp freshly grated nutmeg","salt and white pepper to taste","butter for greasing"],"ro":["200g aluat scurt (1 foaie), copt în alb","200g lardon afumat sau bacon afumat, tocat cuburi","3 ouă mari","300ml smântână grasă (min. 35%)","60g Gruyère, ras fin","1/4 linguriță nucșoară rasă proaspăt","sare și piper alb după gust","unt pentru uns forma"]},"howIsMade":{"hi":"पेस्ट्री को बेलें और 23 सेमी के टार्ट टिन में लाइन करें, किनारों पर मजबूती से दबाएं। 20 मिनट के लिए ठंडा करें। 180°C पर ब्लाइंड-बेक करें: बेकिंग पेपर से ढकें, बेकिंग बीन्स से भरें, 15 मिनट बेक करें; बीन्स और पेपर हटाएं और 5 मिनट और बेक करें। इस बीच, लार्डन को सूखे पैन में सुनहरा होने तक, लगभग 5 मिनट पकाएं; निकालें। अंडे, क्रीम, जायफल, नमक और सफेद मिर्च को एक साथ फेंटें। लार्डन को बेस पर समान रूप से फैलाएं, अंडे का मिश्रण डालें और ग्रुयेर छिड़कें। 180°C पर 25–30 मिनट बेक करें जब तक सेट न हो जाए — बीच में हल्का कंपन होना चाहिए। काटने से पहले 10 मिनट ठंडा होने दें।","en":"Roll out the pastry and line a 23cm tart tin, pressing firmly into the edges. Chill 20 minutes. Blind-bake at 180°C: line with baking paper, fill with baking beans, bake 15 minutes; remove beans and paper and bake a further 5 minutes until pale golden. Meanwhile, cook the lardons in a dry pan until golden and the fat is rendered, about 5 minutes; drain on paper. Whisk together eggs, cream, nutmeg, salt and white pepper. Scatter the lardons evenly over the base, pour the egg mixture over, and sprinkle with Gruyère. Bake 25–30 minutes at 180°C until just set — the centre should tremble slightly when you shake the tin. Cool 10 minutes before slicing. A true Quiche Lorraine contains no onion or vegetables, only lardons and the classic custard."}},{"id":4,"origin":{"hi":"स्पेन","en":"Spain","ro":"Spania"},"name":{"hi":"गज़्पाचो","en":"Gazpacho","ro":"Gazpacho"},"category":{"en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"veg","nutrition":{"cal":260,"prot":4,"carb":24,"fat":16,"fib":3},"ingredients":{"hi":["800 ग्राम पके टमाटर (San Marzano या plum), मोटे कटे","1 लाल शिमला मिर्च (लगभग 200 ग्राम), बीज निकाल कर कटी","1 मध्यम खीरा (लगभग 200 ग्राम), छिला और कटा","2 लहसुन की कलियाँ","100 ग्राम बासी सफ़ेद ब्रेड, क्रस्ट निकाली हुई","60 मिली extra-virgin olive oil","2 बड़े चम्मच रेड वाइन सिरका","1 छोटा चम्मच बारीक नमक","200 मिली ठंडा पानी"],"en":["800g ripe tomatoes (San Marzano or plum), roughly chopped","1 red bell pepper (about 200g), deseeded and chopped","1 medium cucumber (about 200g), peeled and chopped","2 garlic cloves","100g day-old white bread, crusts removed","60ml extra-virgin olive oil","2 tbsp red wine vinegar","1 tsp fine salt","200ml cold water"],"ro":["800g roșii coapte (San Marzano sau roșii de câmp), tăiate cuburi","1 ardei gras roșu (aprox. 200g), curățat de semințe și tocat","1 castravete mediu (aprox. 200g), curățat și tocat","2 căței de usturoi","100g pâine albă veche de o zi, fără coajă","60ml ulei de măsline extravirgin","2 linguri oțet de vin roșu","1 linguriță sare fină","200ml apă rece"]},"howIsMade":{"hi":"ब्रेड को टुकड़ों में फाड़ें और 200 मिली ठंडे पानी में 10 मिनट के लिए भिगोएं। टमाटर, शिमला मिर्च, खीरा और लहसुन को ब्लेंडर में डालें और तेज़ गति पर 1 मिनट चलाएं। भीगी हुई ब्रेड को उसके भिगोने वाले पानी, सिरके और नमक के साथ डालें; फिर से चलाएं। मोटर चलते हुए olive oil को पतली धार में डालें — यह emulsification सूप को रेशमी बनावट देता है। चखें और नमक तथा सिरका समायोजित करें। चिकने नतीजे के लिए बारीक छलनी से छानें, या देहाती रहने दें। कम से कम 2 घंटे ठंडा करें — 6–8°C पर gazpacho कमरे के तापमान से कहीं ज़्यादा स्वादिष्ट है। ठंडे कटोरों में परोसें और ऊपर olive oil की एक धार डालें।","en":"Tear the bread into pieces and soak in 200ml cold water for 10 minutes. Put tomatoes, pepper, cucumber, and garlic into a blender and blitz for 1 minute on high. Add the soaked bread along with its soaking water, vinegar, and salt; blitz again. With the motor running, pour olive oil in a thin stream — this emulsification gives the soup its silky texture. Taste and adjust salt and vinegar. Pass through a fine-mesh sieve for a smoother result, or leave it rustic. Chill at least 2 hours — gazpacho at 6–8°C is vastly more flavourful than at room temperature. Serve in chilled bowls with a drizzle of olive oil on top."}},{"id":5,"origin":{"hi":"जापान","en":"Japan","ro":"Japonia"},"name":{"hi":"सुशी","en":"Sushi","ro":"Sushi"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"japanese","nutrition":{"cal":430,"prot":15,"carb":51,"fat":14,"fib":3},"ingredients":{"hi":["2 कप जापानी शॉर्ट-ग्रेन sushi चावल","2½ कप पानी","60 मिली राइस विनेगर","1 बड़ा चम्मच चीनी","1 छोटा चम्मच नमक","4 nori शीट (20×18 सेमी)","200 ग्राम sashimi-ग्रेड सैल्मन फ़िलेट, पतला कटा","1 पका avocado, कटा","½ छोटा खीरा, julienne किया","परोसने के लिए सोया सॉस","परोसने के लिए wasabi और अचारी अदरक (gari)"],"en":["2 cups Japanese short-grain sushi rice","2½ cups water","60ml rice vinegar","1 tbsp sugar","1 tsp salt","4 nori sheets (20×18 cm)","200g sashimi-grade salmon fillet, thinly sliced","1 ripe avocado, sliced","½ small cucumber, julienned","soy sauce to serve","wasabi and pickled ginger (gari) to serve"],"ro":["2 căni orez japonez pentru sushi (bob scurt)","2½ căni apă","60ml oțet de orez","1 lingură zahăr","1 linguriță sare","4 foi nori (20×18 cm)","200g file de somon sashimi-grade, feliat subțire","1 avocado copt, feliat","½ castravete mic, julienizat","sos de soia pentru servire","wasabi și ghimbir murat (gari) pentru servire"]},"howIsMade":{"hi":"चावल पकाएं: ठंडे पानी के नीचे तब तक धोएं जब तक पानी साफ़ निकले (4–5 बार)। चावल और 2½ कप पानी को उबाल पर लाएं, ढक दें, सबसे धीमी आँच पर 12 मिनट तक पकाएं, फिर आँच से उतार कर 10 मिनट विश्राम दें। एक छोटे कटोरे में सिरका, चीनी और नमक घोलें। पके चावल को एक बड़ी ट्रे पर फैलाएं और लकड़ी के पैडल से काटने जैसी गति से ड्रेसिंग को मोड़ें — गोल-गोल न चलाएं वरना चावल मसला बन जाएगा। एक नम कपड़े से ढकें और कमरे के तापमान तक ठंडा करें (फ्रिज में नहीं)। एक nori शीट को बांस की चटाई पर चमकीली ओर नीचे रखें। 3 सेमी का अंतर दूर वाले किनारे पर छोड़ कर nori के ¾ हिस्से पर मसाले वाला चावल फैलाएं। पास वाले किनारे पर सैल्मन, avocado और खीरा एक पंक्ति में सजाएं। पास वाले किनारे से मज़बूती से रोल करें, साथ-साथ दबाते जाएं; खुले nori को कुछ चावल के दानों से सील करें। तेज़, थोड़े गीले चाकू से 8 गोलों में काटें। तुरंत सोया सॉस, wasabi और अचारी अदरक के साथ परोसें।","en":"Cook the rice: rinse under cold water until the water runs clear (4–5 washes). Bring rice and 2½ cups water to a boil, cover, reduce to lowest heat for 12 minutes, then rest off heat 10 minutes. Dissolve vinegar, sugar, and salt in a small bowl. Spread cooked rice onto a large tray and fold the dressing in using a wooden paddle with cutting motions — do not stir in circles or the rice turns mushy. Cover with a damp cloth and cool to room temperature (not fridge). Lay a nori sheet shiny-side down on the bamboo mat. Spread seasoned rice over ¾ of the nori (leaving a 3 cm gap at the far edge). Arrange salmon, avocado, and cucumber along the near edge in a single row. Roll firmly from the near edge, pressing as you go; seal the bare nori with a few rice grains. Slice with a sharp, lightly wet knife into 8 rounds. Serve at once with soy sauce, wasabi, and pickled ginger."}},{"id":7,"servings":4,"tipType":"meat","pairingsType":"meat","nutrition":{"cal":775,"prot":40,"carb":39,"fat":49,"fib":1},"origin":{"hi":"अमेरिका","en":"USA","ro":"SUA"},"name":{"hi":"चीज़बर्गर","en":"Cheeseburger","ro":"Cheeseburger"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["500 ग्राम कीमा बनाया हुआ बीफ (80% लीन, 20% फैट)","4 ब्रियोश बन, आधे काटकर टोस्ट किए हुए","4 अमेरिकन चेडर चीज़ के स्लाइस","2 पके टमाटर, मोटे स्लाइस में","4 बड़े आइसबर्ग लेट्यूस के पत्ते","1 मध्यम आकार का प्याज, पतले रिंग में","2 बड़े चम्मच बर्गर सॉस (मेयोनेज़, केचप, सरसों, कटे हुए अचार)","नमक और ताज़ी पिसी हुई काली मिर्च"],"en":["500g ground beef (80% lean, 20% fat)","4 brioche buns, halved and toasted","4 slices American cheddar","2 ripe tomatoes, thickly sliced","4 large iceberg lettuce leaves","1 medium onion, thinly sliced into rings","2 tbsp burger sauce (mayo, ketchup, mustard, diced pickles)","salt and freshly ground black pepper"],"ro":["500g carne de vită tocată (80% carne / 20% grăsime)","4 chifle brioche, tăiate și prăjite","4 felii cheddar american","2 roșii coapte, tăiate felii groase","4 frunze de salată iceberg","1 ceapă medie, tăiată rondele subțiri","2 linguri sos de burger (maioneză, ketchup, muștar, castraveți murați tocați)","sare și piper negru proaspăt măcinat"]},"howIsMade":{"hi":"कीमे को नमक और काली मिर्च के साथ मिलाएं और चार 125 ग्राम की गोलियां बनाएं। एक कास्ट-आयरन स्किलेट को तेज़ आंच पर धुआं निकलने तक गर्म करें। एक मज़बूत स्पैटुला से प्रत्येक गोली को पैन पर सपाट दबाएं — स्मैश तकनीक 90 सेकंड में कुरकुरी परत बनाती है। पलटें, चेडर चीज़ डालें और 30 सेकंड ढककर पिघलाएं। बन को कटे हुए हिस्से से 1 मिनट टोस्ट करें। असेंबल करें: नीचे का बन, बर्गर सॉस, लेट्यूस, टमाटर, पिघले चीज़ वाला पैटी, प्याज के छल्ले, ऊपर का बन। तुरंत परोसें।","en":"Season the ground beef with salt and pepper and divide into four 125g balls. Heat a cast-iron skillet over high heat until smoking. Press each ball flat on the pan with a firm spatula — the smash technique creates a crisp, lacy crust in about 90 seconds. Flip, add a slice of cheddar, and cover for 30 seconds to melt. Toast the buns cut-side down for 1 minute. Assemble: bottom bun, burger sauce, lettuce, tomato, patty with melted cheese, onion rings, top bun. Serve immediately — the crust fades fast."}},{"id":8,"servings":4,"tipType":"meat","pairingsType":"meat","nutrition":{"cal":390,"prot":26,"carb":32,"fat":18,"fib":4},"origin":{"hi":"मेक्सिको","en":"Mexico","ro":"Mexic"},"name":{"hi":"टैकोस","en":"Tacos","ro":"Tacos"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["500 ग्राम कीमा बनाया हुआ बीफ (80% लीन)","8 छोटी कॉर्न टॉर्टिला (15 सेमी)","1 छोटा चम्मच पिसा जीरा","1 छोटा चम्मच स्मोक्ड पापरिका","2 पके टमाटर, बारीक कटे हुए (पिको डे गाल्यो के लिए)","1 छोटा सफेद प्याज, बारीक कटा हुआ","ताज़ा धनिया, नींबू के टुकड़े, साल्सा और खट्टी क्रीम परोसने के लिए","नमक और काली मिर्च"],"en":["500g ground beef (80% lean)","8 small corn tortillas (15cm)","1 tsp ground cumin","1 tsp smoked paprika","2 ripe tomatoes, finely diced (for pico de gallo)","1 small white onion, finely diced","fresh cilantro, lime wedges, salsa, and sour cream for serving","salt and black pepper"],"ro":["500g carne de vită tocată (80% carne)","8 tortilla mici din porumb (15cm)","1 linguriță chimion măcinat","1 linguriță boia afumată","2 roșii coapte, tocate mărunt (pico de gallo)","1 ceapă albă mică, tocată mărunt","coriandru proaspăt, felii de lime, sos salsa și smântână pentru servit","sare și piper negru"]},"howIsMade":{"hi":"एक सूखी कड़ाही में तेज़ आंच पर कीमे को भूरा करें, उसे बारीक टुकड़ों में तोड़ते हुए — शुरुआत में ज्यादा न हिलाएं ताकि रंग आए। अतिरिक्त चर्बी निकाल दें। जीरा, पापरिका, नमक और मिर्च डालें; 2 मिनट और पकाएं। टॉर्टिला गर्म करें: गैस की लौ पर सीधे 15 सेकंड प्रति साइड तक बुलबुले आने तक, या गर्म पैन में सूखा टोस्ट करें। पिको डे गाल्यो: टमाटर और प्याज को चुटकी नमक और नींबू के रस के साथ मिलाएं। प्रत्येक टैको के लिए दो टॉर्टिला एक-दूसरे के ऊपर रखें। सीज़न्ड कीमा, पिको डे गाल्यो, धनिया, नींबू का रस और साल्सा या खट्टी क्रीम से सजाएं।","en":"Brown the ground beef in a dry skillet over high heat, breaking it into fine crumbles — do not stir too much at first so the meat develops colour. Drain excess fat. Add cumin, paprika, salt and pepper; cook 2 more minutes. Warm the corn tortillas: hold them directly over a gas flame for 15 seconds per side until they blister and char lightly, or dry-toast in a hot pan. For quick pico de gallo: toss diced tomato with diced onion, a pinch of salt, and a squeeze of lime. Double-stack two tortillas per taco to prevent splitting. Spoon on the seasoned beef, then top with pico de gallo, cilantro leaves, a squeeze of lime, and salsa or sour cream to taste."}},{"id":9,"servings":4,"tipType":"meat","pairingsType":"meat","nutrition":{"cal":375,"prot":23,"carb":11,"fat":19,"fib":3},"origin":{"hi":"भारत","en":"India","ro":"India"},"name":{"hi":"चिकन करी","en":"Chicken Curry","ro":"Curry de pui"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"hi":["800 ग्राम हड्डी वाले चिकन के थाई और ड्रमस्टिक, त्वचा हटाई हुई","2 बड़ी प्याज़ (लगभग 350 ग्राम), बारीक कटी","400 ग्राम डब्बाबंद कुटे टमाटर","1 बड़ा चम्मच अदरक का पेस्ट (3 सेमी के टुकड़े से)","1 बड़ा चम्मच लहसुन का पेस्ट (5 कलियों से)","3 बड़े चम्मच सूरजमुखी का तेल","1 छोटा चम्मच जीरा","2 छोटे चम्मच धनिया पाउडर","1 छोटा चम्मच गरम मसाला","½ छोटा चम्मच हल्दी","1 छोटा चम्मच कश्मीरी लाल मिर्च (या हल्की paprika)","200 मिली पूरी वसा वाला दही, फेंटा हुआ","नमक स्वादानुसार","ताज़े धनिया पत्ते सजावट के लिए"],"en":["800g bone-in chicken thighs and drumsticks, skin removed","2 large onions (about 350g), finely diced","400g canned crushed tomatoes","1 tbsp ginger paste (from a 3cm piece)","1 tbsp garlic paste (from 5 cloves)","3 tbsp sunflower oil","1 tsp cumin seeds","2 tsp ground coriander","1 tsp garam masala","½ tsp turmeric","1 tsp Kashmiri chili powder (or mild paprika)","200ml full-fat yogurt, whisked","Salt to taste","Fresh coriander leaves to finish"],"ro":["800g pulpe de pui cu os, fără piele","2 cepe mari (aprox. 350g), tăiate mărunt","400g roșii tocate din conservă","1 lingură pastă de ghimbir (bucată de 3 cm)","1 lingură pastă de usturoi (5 căței)","3 linguri ulei de floarea-soarelui","1 linguriță semințe de chimen","2 lingurițe coriandru măcinat","1 linguriță garam masala","½ linguriță turmeric","1 linguriță praf de ardei Kashmiri (sau boia dulce)","200ml iaurt gras, bătut","Sare după gust","Frunze de coriandru proaspăt pentru finisare"]},"howIsMade":{"hi":"एक भारी तले वाले बर्तन में मध्यम-तेज़ आँच पर तेल गरम करें। जीरा डालें और 30 सेकंड तक चटकने दें। कटी प्याज़ डालें और बार-बार चलाते हुए 15–18 मिनट तक भूनें जब तक गहरी सुनहरी न हो जाए — यह caramelisation स्वाद की नींव बनाती है। अदरक और लहसुन का पेस्ट डालें; 2 मिनट तक पकाएं जब तक कच्चापन ख़त्म हो जाए। धनिया पाउडर, हल्दी और कश्मीरी मिर्च डालें; 1 मिनट चलाएं। कुटे टमाटर डालें और मध्यम आँच पर 10 मिनट तक बार-बार चलाते हुए पकाएं जब तक तेल किनारों पर अलग होने लगे। चिकन के टुकड़े डालें, मसाले में लपेटें और 5 मिनट तक सेकें। आँच से उतार लें; फेंटा हुआ दही एक-एक बड़ा चम्मच कर के मिलाएं ताकि फटे नहीं। मध्यम-धीमी आँच पर वापस रखें, ढक दें और 25–30 मिनट तक धीमी आँच पर पकाएं जब तक चिकन हड्डी से आसानी से अलग हो जाए। गरम मसाला मिलाएं, नमक समायोजित करें, ताज़े धनिए से सजाएं। बासमती चावल या नान के साथ परोसें।","en":"Heat oil in a heavy-bottomed pot over medium-high heat. Add cumin seeds and let sizzle 30 seconds. Add diced onions and fry, stirring often, for 15–18 minutes until deep golden — this caramelisation builds the flavour base. Stir in ginger and garlic paste; cook 2 minutes until the raw smell disappears. Add ground coriander, turmeric, and Kashmiri chili; stir 1 minute. Pour in crushed tomatoes and cook over medium heat, stirring often, for 10 minutes until the oil separates to the sides. Add chicken pieces, coat in masala, and sear 5 minutes. Remove from heat; stir in whisked yogurt one tablespoon at a time to prevent curdling. Return to medium-low heat, cover, and simmer 25–30 minutes until the chicken falls easily from the bone. Stir in garam masala, adjust salt, finish with fresh coriander. Serve with basmati rice or naan."}},{"id":10,"servings":4,"tipType":"def","pairingsType":"veg","nutrition":{"cal":215,"prot":4,"carb":19,"fat":13,"fib":4},"origin":{"hi":"फ्रांस","en":"France","ro":"Franța"},"name":{"hi":"रतातुई","en":"Ratatouille","ro":"Ratatouille"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["1 मध्यम बैंगन (लगभग 300 ग्राम), 2 सेमी के टुकड़ों में","2 मध्यम तोरी (लगभग 400 ग्राम), 2 सेमी के गोल टुकड़ों में","1 लाल शिमला मिर्च, बीज निकालकर कटी हुई","1 पीली शिमला मिर्च, बीज निकालकर कटी हुई","4 पके प्लम टमाटर (लगभग 400 ग्राम), मोटे कटे हुए","1 बड़ा प्याज, कटा हुआ","4 लहसुन की कलियां, पतली स्लाइस में","4 बड़े चम्मच एक्स्ट्रा-वर्जिन जैतून का तेल","1 छोटा चम्मच सूखी प्रोवेंकल जड़ी-बूटियां","नमक और काली मिर्च स्वाद अनुसार"],"en":["1 medium aubergine (about 300g), cut into 2cm cubes","2 medium courgettes (about 400g), cut into 2cm rounds","1 red bell pepper, deseeded and diced","1 yellow bell pepper, deseeded and diced","4 ripe plum tomatoes (about 400g), roughly chopped","1 large onion, diced","4 garlic cloves, thinly sliced","4 tbsp extra-virgin olive oil","1 tsp dried herbes de Provence","salt and black pepper to taste"],"ro":["1 vânătă medie (aprox. 300g), cuburi de 2cm","2 dovlecei medii (aprox. 400g), rondele de 2cm","1 ardei gras roșu, curățat și tocat","1 ardei gras galben, curățat și tocat","4 roșii prune coapte (aprox. 400g), tocate grosier","1 ceapă mare, tocată","4 căței de usturoi, feliați subțire","4 linguri ulei de măsline extravirgin","1 linguriță herbes de Provence uscate","sare și piper negru după gust"]},"howIsMade":{"hi":"बैंगन के टुकड़ों पर हल्का नमक छिड़कें और 15 मिनट के लिए छोड़ दें, फिर किचन टिशू से सुखाएं। एक चौड़े पैन में 1 बड़ा चम्मच तेल मध्यम-तेज आंच पर गर्म करें। बैंगन को हल्का सुनहरा होने तक, लगभग 5 मिनट भूनें; निकालकर अलग रख दें। इसी तरह तोरी को 3 मिनट और शिमला मिर्च को 4 मिनट भूनें; अलग रखें। उसी पैन में बचा हुआ तेल गर्म करें और प्याज को 5 मिनट पारदर्शी होने तक भूनें। लहसुन डालें और 1 मिनट पकाएं। टमाटर और जड़ी-बूटियां डालें; 10 मिनट पकाएं जब तक टमाटर सॉस बन जाएं। सभी सब्जियां वापस डालें, धीरे से मिलाएं, नमक-मिर्च से सीजन करें और बिना ढके 15–20 मिनट धीमी आंच पर पकाएं। गर्म या कमरे के तापमान पर परोसें।","en":"Lightly salt the aubergine cubes and set aside for 15 minutes to draw out bitterness, then pat dry. Heat 1 tbsp oil in a wide pan over medium-high heat. Saute the aubergine until lightly golden, about 5 minutes; remove and set aside. Saute the courgettes 3 minutes, then the peppers 4 minutes; remove each in turn. In the same pan, heat the remaining oil and sweat the onion until soft and translucent, 5 minutes. Add garlic and cook 1 minute. Add the tomatoes and herbes de Provence; cook 10 minutes until the tomatoes collapse into a sauce. Return all vegetables, stir gently, season with salt and pepper, and simmer uncovered 15–20 minutes until everything is tender and fragrant. Serve warm or at room temperature — ratatouille tastes even better the next day."}},{"id":11,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"hi":"यूनान","en":"Greece","ro":"Grecia"},"name":{"hi":"सूवलाकी","en":"Souvlaki","ro":"Souvlaki"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["700 ग्राम पोर्क शोल्डर, 3 सेमी टुकड़ों में कटा हुआ","3 टेबलस्पून एक्स्ट्रा-वर्जिन ऑलिव ऑयल","1 नींबू का रस","3 लहसुन की कलियां, कुचली हुई","2 चम्मच सूखा ग्रीक ओरेगैनो","1 चम्मच सूखा थाइम","नमक और ताजी पिसी काली मिर्च","लकड़ी या धातु की सीख"],"en":["700g pork shoulder, cut into 3cm cubes","3 tbsp extra-virgin olive oil","juice of 1 lemon","3 garlic cloves, crushed","2 tsp dried Greek oregano","1 tsp dried thyme","salt and freshly ground black pepper","wooden or metal skewers"],"ro":["700g ceafă de porc, tăiată cuburi de 3 cm","3 linguri ulei de măsline extravirgin","sucul de la 1 lămâie","3 căței de usturoi, zdrobiți","2 linguriță oregano grecesc uscat","1 linguriță cimbru uscat","sare și piper negru proaspăt măcinat","frigărui de lemn sau metal"]},"howIsMade":{"hi":"एक कटोरे में जैतून का तेल, नींबू का रस, कुचला लहसुन, ओरेगैनो और थाइम मिलाएं। पोर्क के टुकड़े डालें, अच्छी तरह मिलाएं, ढकें और कम से कम 1 घंटे रेफ्रिजरेटर में रखें — रात भर और बेहतर। लकड़ी की सीखें इस्तेमाल करें तो उन्हें 30 मिनट पानी में भिगोएं। हर सीख पर 5-6 टुकड़े छोटे अंतराल के साथ पिरोएं। तेज आंच पर (कोयला सबसे अच्छा) 8-10 मिनट ग्रिल करें, हर 2 मिनट पर पलटें जब तक बाहर से जला हुआ और रस साफ न हो। तुरंत गर्म पिता ब्रेड में त्ज़ात्ज़ीकी, टमाटर और लाल प्याज के साथ परोसें।","en":"Combine olive oil, lemon juice, crushed garlic, oregano and thyme in a bowl. Add the pork cubes, toss to coat thoroughly, cover and refrigerate for at least 1 hour — overnight is better. If using wooden skewers, soak them in water for 30 minutes. Thread 5-6 cubes per skewer, leaving small gaps between pieces. Grill over high heat (charcoal is ideal) for 8-10 minutes total, turning every 2 minutes, until the outside is charred and the juices run clear. The meat should be firm but not dry — pull it at 70°C internal. Serve immediately in warm pita with tzatziki, sliced tomatoes and red onion."},"nutrition":{"cal":420,"prot":35,"carb":3,"fat":29,"fib":0}},{"id":12,"origin":{"hi":"भारत","en":"India","ro":"India"},"name":{"hi":"दाल","en":"Dhal","ro":"Dhal"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"veg","ingredients":{"hi":["300 ग्राम सूखी मसूर दाल (लाल)","2 बड़े चम्मच घी (या वनस्पति तेल)","1 बड़ी प्याज़, बारीक कटी","4 लहसुन की कलियाँ, कीमा की हुई","2 सेमी ताज़ी अदरक, कद्दूकस","400 ग्राम डब्बाबंद कटे टमाटर (या 3 बड़े ताज़े टमाटर)","1 छोटा चम्मच हल्दी पाउडर","1 छोटा चम्मच जीरा पाउडर","1 छोटा चम्मच धनिया पाउडर","½ छोटा चम्मच गरम मसाला","½ छोटा चम्मच लाल मिर्च पाउडर","400 मिली नारियल का दूध (या पानी)","नमक स्वादानुसार","परोसने के लिए ताज़ा धनिया और नींबू के टुकड़े"],"en":["300g dried red lentils (masoor dal)","2 tbsp ghee (or vegetable oil)","1 large onion, finely chopped","4 garlic cloves, minced","2 cm fresh ginger, grated","400g canned chopped tomatoes (or 3 large fresh tomatoes)","1 tsp ground turmeric","1 tsp ground cumin","1 tsp ground coriander","½ tsp garam masala","½ tsp ground red chilli","400ml coconut milk (or water)","salt to taste","fresh coriander and lemon wedges to serve"],"ro":["300g linte roșie uscată (masoor dal)","2 linguri ghee (sau ulei vegetal)","1 ceapă mare, tocată fin","4 căței de usturoi, tocați","2 cm ghimbir proaspăt, ras","400g roșii din conservă, tăiate cuburi (sau 3 roșii mari proaspete)","1 linguriță turmeric măcinat","1 linguriță chimen măcinat","1 linguriță coriandru măcinat","½ linguriță garam masala","½ linguriță ardei iute roșu măcinat","400ml lapte de nucă de cocos (sau apă)","sare după gust","coriandru proaspăt și felii de lămâie pentru servire"]},"howIsMade":{"hi":"मसूर दाल को ठंडे पानी के नीचे 3–4 बार धोएं जब तक पानी साफ़ निकले। एक बड़े पैन में मध्यम आँच पर घी पिघलाएं। प्याज़ डालें और बार-बार चलाते हुए 10–12 मिनट तक पकाएं जब तक सुनहरी और नरम न हो जाए — इस क़दम को न छोड़ें, caramelised नींव ही स्वाद की रीढ़ है। लहसुन और अदरक डालें, 1 मिनट भूनें। हल्दी, जीरा, धनिया और लाल मिर्च डालें, 30 सेकंड चलाएं जब तक ख़ुशबू उठे। टमाटर डालें, 3–4 मिनट तक उबालें जब तक थोड़ा गाढ़ा हो जाए। धुली दाल और नारियल का दूध (या पानी) डालें, हल्के उबाल पर लाएं और बिना ढके 20–25 मिनट तक पकाएं, बीच-बीच में चलाते रहें, जब तक दाल बिखर जाए और दाल गाढ़ी और क्रीमी हो जाए। गरम मसाला मिलाएं और नमक समायोजित करें। ज़रूरत पड़े तो थोड़े गरम पानी से पतला करें। चावल या नान के साथ परोसें, ऊपर ताज़ा धनिया और नींबू निचोड़ कर।","en":"Rinse the red lentils under cold water 3–4 times until the water runs clear. In a large pan melt ghee over medium heat. Add the onion and cook, stirring often, for 10–12 minutes until golden and soft — do not skip this step, the caramelised base is the backbone of flavour. Add garlic and ginger, fry 1 minute. Add turmeric, cumin, coriander, and red chilli, stir 30 seconds until fragrant. Add tomatoes, simmer 3–4 minutes until slightly thickened. Add the rinsed lentils and coconut milk (or water), reduce to a gentle simmer and cook uncovered for 20–25 minutes, stirring occasionally, until lentils collapse and the dhal is thick and creamy. Stir in garam masala and adjust salt. Thin with a little hot water if needed. Serve with rice or naan, topped with fresh coriander and a squeeze of lemon."},"nutrition":{"cal":490,"prot":21,"carb":56,"fat":19,"fib":13}},{"id":13,"timeMins":{"total":20,"active":20},"servings":4,"tipType":"def","pairingsType":"veg","origin":{"hi":"मेक्सिको","en":"Mexico","ro":"Mexic"},"name":{"hi":"गुआकामोले","en":"Guacamole","ro":"Guacamole"},"category":{"hi":"नाश्ता","en":"Snack","ro":"Gustare"},"ingredients":{"hi":["3 पके हास एवोकाडो","2 नींबू का रस (लगभग 3 बड़े चम्मच)","1 छोटा लाल प्याज, बारीक कटा हुआ","2 पके रोमा टमाटर, बीज निकालकर कटे हुए","1 छोटी हरी मिर्च (जलापेनो), बारीक कटी हुई (हल्की तीखेपन के लिए बीज हटाएं)","15 ग्राम ताज़ा धनिया, मोटा कटा हुआ","आधा छोटा चम्मच बारीक समुद्री नमक, स्वाद अनुसार"],"en":["3 ripe Hass avocados","juice of 2 limes (about 3 tbsp)","1 small red onion, finely diced","2 ripe Roma tomatoes, deseeded and diced","1 small jalapeño, finely chopped (seeds removed for mild heat)","15g fresh cilantro, roughly chopped","1/2 tsp fine sea salt, plus more to taste"],"ro":["3 avocado Hass coapte","sucul a 2 lime (aprox. 3 linguri)","1 ceapă roșie mică, tocată mărunt","2 roșii Roma coapte, curățate de semințe și tocate","1 ardei jalapeno mic, tocat fin (fără semințe pentru mai puțin iute)","15g coriandru proaspăt, tocat grosier","1/2 linguriță sare fină de mare"]},"howIsMade":{"hi":"एवोकाडो को आधा काटें, बीज निकालें और चम्मच से गूदा निकाल कर कटोरे में डालें। तुरंत नींबू का रस डालें — अम्ल भूरा होने से रोकता है। अपनी पसंद की बनावट के लिए कांटे से मैश करें: मोटा या लगभग मुलायम। प्याज, टमाटर, हरी मिर्च और धनिया मिलाएं। नमक से सीज़न करें। स्वाद लें और नींबू व नमक को समायोजित करें। स्टोर करने के लिए, हवा बाहर निकालने के लिए प्लास्टिक रैप को सीधे सतह पर दबाएं — नींबू का रस बीज से बेहतर भूरा होने से बचाता है। 2 घंटे के भीतर परोसें।","en":"Halve and stone the avocados. Scoop the flesh into a bowl and add the lime juice immediately — the acid slows browning. Mash with a fork to your preferred texture: very chunky or almost smooth. Fold in the diced onion, tomato, jalapeño, and cilantro. Season with salt. Taste and adjust lime and salt. To store, press cling film directly onto the surface of the guacamole to exclude air — the lime juice prevents browning far better than the avocado stone. Serve within 2 hours for best colour and flavour."},"nutrition":{"cal":200,"prot":3,"carb":13,"fat":17,"fib":9}},{"id":14,"servings":4,"tipType":"soup","pairingsType":"soup","origin":{"hi":"रूस","en":"Russia","ro":"Rusia"},"name":{"hi":"बोर्श","en":"Borscht","ro":"Bors"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"hi":["500 ग्राम कच्चा चुकंदर, छिला और मोटा कद्दूकस किया","300 ग्राम सफ़ेद पत्तागोभी, बारीक कतरी","300 ग्राम मोमी आलू, 2 सेमी क्यूब में कटे","2 मध्यम गाजर, julienne की","1 बड़ी प्याज़, कटी","3 लहसुन की कलियाँ, कीमा की हुई","2 बड़े चम्मच टमाटर पेस्ट","1.5 लीटर बीफ़ या सब्ज़ी का शोरबा","2 बड़े चम्मच सूरजमुखी का तेल","1 बड़ा चम्मच सेब का सिरका (गहरे लाल रंग को ठीक करने के लिए)","नमक और काली मिर्च स्वादानुसार","परोसने के लिए खट्टी क्रीम और ताज़ा dill"],"en":["500g raw beetroot, peeled and coarsely grated","300g white cabbage, thinly shredded","300g waxy potatoes, cut into 2cm cubes","2 medium carrots, julienned","1 large onion, diced","3 garlic cloves, minced","2 tbsp tomato paste","1.5 litres beef or vegetable broth","2 tbsp sunflower oil","1 tbsp apple cider vinegar (to fix the deep red colour)","Salt and black pepper to taste","Sour cream and fresh dill to serve"],"ro":["500g sfeclă roșie crudă, curățată și rasă grosier","300g varză albă, feliată subțire","300g cartofi waxy, cuburi de 2 cm","2 morcovi medii, julien","1 ceapă mare, tocată","3 căței de usturoi, tocați","2 linguri pastă de roșii","1,5 litri supă de vită sau legume","2 linguri ulei de floarea-soarelui","1 lingură oțet de mere (pentru culoare vie)","Sare și piper după gust","Smântână și mărar proaspăt pentru servire"]},"howIsMade":{"hi":"मध्यम आँच पर तेल गरम करें, प्याज़ और गाजर डालें और 7–8 मिनट तक नरम होने तक भूनें। टमाटर पेस्ट और लहसुन मिलाएं; 2 मिनट पकाएं। कद्दूकस किया चुकंदर और सेब का सिरका डालें; 5 मिनट पकाएं — सिरका गहरे लाल रंग को ठीक करता है। गरम शोरबा डालें और आलू मिलाएं। उबाल पर लाएं, आँच कम करें और 15 मिनट तक धीमी आँच पर पकाएं। कतरी पत्तागोभी डालें और 10 मिनट और पकाएं जब तक पत्तागोभी बस नरम हो जाए और आलू नरम लेकिन टूटे नहीं हों। नमक चखें, काली मिर्च और ज़रूरत पड़े तो थोड़ा और सिरका डालें ताकि सूप में चमक आए। गहरे कटोरों में निकालें और ऊपर खट्टी क्रीम का बड़ा चम्मच और ताज़ा कटा dill डालें।","en":"Heat oil over medium heat, add onion and carrots, and sauté 7–8 minutes until softened. Stir in tomato paste and garlic; cook 2 minutes. Add the grated beetroot and apple cider vinegar; cook 5 minutes — the vinegar fixes the deep red colour. Pour in the hot broth and add potatoes. Bring to a boil, reduce heat and simmer 15 minutes. Add shredded cabbage and simmer another 10 minutes until the cabbage is just tender and the potatoes are soft but not falling apart. Taste for salt, add pepper and extra vinegar if the soup needs brightness. Ladle into deep bowls and top with a generous spoonful of sour cream and fresh chopped dill."},"nutrition":{"cal":260,"prot":5,"carb":28,"fat":9,"fib":7}},{"id":15,"servings":4,"tipType":"dessert","pairingsType":"dessert","origin":{"hi":"अमेरिका","en":"USA","ro":"SUA"},"name":{"hi":"अमेरिकन पैनकेक","en":"Pancakes","ro":"Clătite americane"},"category":{"hi":"नाश्ता","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"hi":["200 ग्राम मैदा","2 चम्मच बेकिंग पाउडर","1 टेबलस्पून चीनी","1/2 चम्मच नमक","240 मिली फुल क्रीम दूध","2 बड़े अंडे","30 ग्राम पिघला हुआ मक्खन, और पैन के लिए अतिरिक्त","1 चम्मच वेनिला एक्सट्रेक्ट"],"en":["200g plain flour","2 tsp baking powder","1 tbsp sugar","1/2 tsp salt","240ml whole milk","2 large eggs","30g melted butter, plus extra for the pan","1 tsp vanilla extract"],"ro":["200g făină albă","2 linguriță praf de copt","1 lingură zahăr","1/2 linguriță sare","240ml lapte integral","2 ouă mari","30g unt topit, plus extra pentru tigaie","1 linguriță extract de vanilie"]},"howIsMade":{"hi":"एक बड़े कटोरे में मैदा, बेकिंग पाउडर, चीनी और नमक मिलाएं। दूसरे कटोरे में दूध, अंडे, पिघला मक्खन और वेनिला फेंटें। तरल मिश्रण को सूखी सामग्री में डालें और स्पैचुला से हल्के से मिलाएं — कुछ गुच्छे ठीक हैं; ज्यादा मिलाने से ग्लूटेन बनता है और पैनकेक सख्त हो जाते हैं। बैटर को 5 मिनट आराम दें। नॉन-स्टिक पैन को मध्यम आंच पर गर्म करें, थोड़ा मक्खन लगाएं और अतिरिक्त पोंछ लें। प्रति पैनकेक लगभग 80ml बैटर डालें। 2-3 मिनट पकाएं जब तक सतह पर बुलबुले न आएं और किनारे सूखे न लगें। पलटें और 1-2 मिनट और पकाएं। तुरंत मेपल सिरप, ताजे मक्खन और फलों के साथ परोसें।","en":"In a large bowl, whisk together flour, baking powder, sugar and salt. In a second bowl, whisk milk, eggs, melted butter and vanilla. Pour the wet ingredients into the dry and fold gently with a spatula — a few lumps are fine and even desirable; over-mixing develops gluten and makes the pancakes tough. Rest the batter 5 minutes: the baking powder bubbles will rise to the surface. Heat a non-stick pan over medium heat, add a small knob of butter and wipe away the excess. Pour one ladle (about 80ml) of batter per pancake. Cook 2-3 minutes until bubbles break on the surface and the edges look set and dry. Flip and cook 1-2 minutes more until golden on the underside. Serve immediately — pancakes deflate as they cool. Top with real maple syrup, fresh butter and seasonal fruit."},"nutrition":{"cal":340,"prot":10,"carb":45,"fat":13,"fib":1}},{"id":16,"servings":4,"tipType":"def","pairingsType":"fish","origin":{"hi":"थाईलैंड","en":"Thailand","ro":"Thailanda"},"name":{"hi":"पैड थाई","en":"Pad Thai","ro":"Pad Thai"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"hi":["200 ग्राम सूखी फ्लैट राइस नूडल्स (30 मिनट भिगोई)","200 ग्राम कच्चे मध्यम झींगे, छिले और शिरा निकाली","2 अंडे","2 बड़े चम्मच इमली का पेस्ट","2 बड़े चम्मच मछली की सॉस","1 बड़ा चम्मच oyster sauce","1 छोटा चम्मच पाम शुगर या ब्राउन शुगर","2 बड़े चम्मच न्यूट्रल तेल","2 लहसुन की कलियाँ, कीमा की हुई","1 shallot, पतला कटा","100 ग्राम मूँग के अंकुर","3 हरी प्याज़, 3 सेमी के टुकड़ों में कटी","3 बड़े चम्मच भुनी मूँगफली, मोटे कुटे","1 नींबू, फाँकों में कटा","परोसने के लिए सूखी मिर्च के फ्लेक्स"],"en":["200g dried flat rice noodles (soaked 30 min)","200g raw medium prawns, peeled and deveined","2 eggs","2 tbsp tamarind paste","2 tbsp fish sauce","1 tbsp oyster sauce","1 tsp palm sugar or brown sugar","2 tbsp neutral oil","2 cloves garlic, minced","1 shallot, thinly sliced","100g bean sprouts","3 spring onions, cut into 3cm pieces","3 tbsp roasted peanuts, roughly crushed","1 lime, cut into wedges","Dried chili flakes to serve"],"ro":["200g tăiței lat de orez (înmuiați 30 min)","200g creveți cruzi, curățați","2 ouă","2 linguri pastă de tamarind","2 linguri sos de pește","1 lingură sos de stridii","1 linguriță zahăr de palmier","2 linguri ulei neutru","2 căței de usturoi, tocați","1 șalotă, feliată","100g germeni de fasole","3 cepe verzi, tăiate 3cm","3 linguri alune prăjite, zdrobite","1 lime, pentru servire","Fulgi de ardei iute, după gust"]},"howIsMade":{"hi":"राइस नूडल्स को ठंडे पानी में 30 मिनट के लिए भिगोएं, फिर छानें। एक छोटे कटोरे में इमली पेस्ट, मछली सॉस, oyster sauce और चीनी मिलाकर सॉस बनाएं। एक wok में बहुत तेज़ आँच पर तेल को बस धुआँ उठने तक गरम करें; लहसुन और shallot को 30 सेकंड भूनें, झींगे डालें और 2 मिनट तक पकाएं जब तक बस गुलाबी हो जाएं। सबकुछ एक ओर सरकाएं, अंडे फोड़ें और 30 सेकंड हल्के से scramble करें, फिर सब कुछ मिला दें। छनी नूडल्स डालें और सॉस ऊपर डालें; लगातार 2–3 मिनट तक उछालें जब तक नूडल्स सॉस सोख लें और किनारों पर caramelise होने लगें। आँच से उतारें, मूँग के अंकुर और हरी प्याज़ मिलाएं; तुरंत परोसें, ऊपर कुटी मूँगफली, नींबू की फाँक और मिर्च के फ्लेक्स।","en":"Soak rice noodles in cold water for 30 minutes, then drain. Mix tamarind paste, fish sauce, oyster sauce and sugar in a small bowl to make the sauce. Heat oil in a wok over very high heat until just smoking; fry garlic and shallot for 30 seconds, add prawns and cook 2 minutes until just pink. Push everything to the side, crack in eggs and scramble lightly for 30 seconds, then toss everything together. Add drained noodles and pour the sauce over; toss constantly for 2–3 minutes until the noodles absorb the sauce and begin to caramelise at the edges. Remove from heat, fold in bean sprouts and spring onions; serve immediately topped with crushed peanuts, a lime wedge and chili flakes to taste."},"nutrition":{"cal":380,"prot":18,"carb":40,"fat":13,"fib":2}},{"id":17,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"hi":"जर्मनी","en":"Germany","ro":"Germania"},"name":{"hi":"श्निट्ज़ेल","en":"Schnitzel","ro":"Schnitzel"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"ingredients":{"hi":["4 बोनलेस पोर्क लोइन चॉप (लगभग 150 ग्राम प्रत्येक), काट-छांट कर","80 ग्राम साधारण मैदा, नमक और मिर्च के साथ सीज़न किया हुआ","2 बड़े अंडे, फेंटे हुए","150 ग्राम बारीक सूखे ब्रेडक्रम्ब्स","200 मिली हल्का तेल (सूरजमुखी या कैनोला) तलने के लिए","1 नींबू, सर्व करने के लिए वेज में कटा हुआ","नमक और सफेद मिर्च"],"en":["4 boneless pork loin chops (about 150g each), trimmed","80g plain flour, seasoned with salt and pepper","2 large eggs, beaten","150g fine dry breadcrumbs (Semmelbrösel)","200ml neutral oil (sunflower or rapeseed) for frying","1 lemon, cut into wedges for serving","salt and white pepper"],"ro":["4 cotlete de porc din spată (aprox. 150g fiecare), dezosate și degresate","80g făină simplă, condimentată cu sare și piper","2 ouă mari, bătute","150g pesmet fin uscat (Semmelbrösel)","200ml ulei neutru (floarea-soarelui sau rapiță) pentru prăjit","1 lămâie, tăiată fâșii pentru servit","sare și piper alb"]},"howIsMade":{"hi":"प्रत्येक चॉप को दो प्लास्टिक रैप के बीच रखें और मीट मैलेट या बेलन से समान रूप से 4–5mm मोटाई तक पीटें — यह पतली, समान मोटाई असली श्निट्ज़ेल की पहचान है। थपथपाकर सुखाएं और नमक और सफेद मिर्च से सीज़न करें। तीन उथले बर्तन तैयार करें: सीज़न किया हुआ मैदा, फेंटे हुए अंडे, ब्रेडक्रम्ब्स। प्रत्येक श्निट्ज़ेल को मैदे में लपेटें (अतिरिक्त झाड़ें), अंडे में डुबोएं, फिर ब्रेडक्रम्ब्स में दृढ़ता से दबाएं — बहुत ज्यादा न दबाएं, कोटिंग हवादार रहनी चाहिए ताकि गर्म तेल में फूले और फफोले बनाए। एक चौड़े पैन में 1cm गहराई तक तेल डालें और 170–180°C पर गर्म करें। हर तरफ 2–3 मिनट तक गहरा सुनहरा और कुरकुरा होने तक तलें। वायर रैक पर निकालें — कभी टिशू पेपर पर नहीं, जो भाप को फंसाकर क्रस्ट को बर्बाद करता है। तुरंत नींबू के टुकड़ों के साथ परोसें।","en":"Place each pork chop between two sheets of cling film and beat with a meat mallet or rolling pin until evenly 4–5mm thick — the thin, even cut is the defining feature of a proper schnitzel. Pat dry and season with salt and white pepper. Set up three shallow dishes: seasoned flour, beaten eggs, breadcrumbs. Coat each schnitzel in flour (shake off the excess), dip in egg, then press firmly into breadcrumbs to coat evenly — do not press the crumb down too hard; it should stay airy so it puffs and blisters in hot oil. Pour oil into a wide pan to a depth of 1cm and heat to 170–180°C. Fry 2–3 minutes per side until deep golden and crisp. Drain on a wire rack — never on paper towel, which traps steam and kills the crust. Serve immediately with lemon wedges."},"nutrition":{"cal":570,"prot":45,"carb":15,"fat":35,"fib":1}},{"id":18,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"hi":"ब्राज़ील","en":"Brazil","ro":"Brazilia"},"name":{"hi":"फेइजोआदा","en":"Feijoada","ro":"Feijoada"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["400 ग्राम सूखी काली बींस, रात भर भिगोई हुई","400 ग्राम स्मोक्ड पोर्क रिब्स","200 ग्राम चोरिजो या स्मोक्ड सॉसेज, कटा हुआ","200 ग्राम स्मोक्ड बेकन, टुकड़ों में","1 बड़ा प्याज, कटा हुआ","4 लहसुन की कलियां, बारीक कटी","2 तेज पत्ते","3 टेबलस्पून जैतून का तेल","नमक, काली मिर्च और मिर्च के गुच्छे स्वादानुसार"],"en":["400g dried black beans, soaked overnight","400g smoked pork ribs","200g chourico or smoked sausage, sliced","200g smoked bacon, diced","1 large onion, chopped","4 garlic cloves, minced","2 bay leaves","3 tbsp olive oil","salt, pepper and chilli flakes to taste"],"ro":["400g fasole neagră uscată, înmuiată 12 ore","400g coaste de porc afumate","200g chouriço sau cârnați afumați, feliați","200g bacon afumat, tăiat cuburi","1 ceapă mare, tocată","4 căței de usturoi, tocați","2 foi de dafin","3 linguri ulei de măsline","sare, piper și fulgi de ardei iute după gust"]},"howIsMade":{"hi":"भिगोई हुई बींस छान लें और एक बड़े बर्तन में 5 सेमी ऊपर तक ताज़ा पानी डालें। स्मोक्ड रिब्स और तेज पत्ते डालें। उबाल आने के बाद मध्यम आंच पर 1 घंटे पकाएं, झाग हटाते रहें। इस दौरान एक पैन में जैतून के तेल में प्याज को 8 मिनट भूनें, लहसुन डालें और 2 मिनट और पकाएं। चोरिजो और बेकन डालकर 5 मिनट तक सुनहरा होने तक भूनें। सब कुछ बींस वाले बर्तन में डालें, अच्छे से मिलाएं और धीमी आंच पर 45-60 मिनट तक पकाएं जब तक बींस पूरी तरह नरम और शोरबा गाढ़ा न हो जाए। लकड़ी के चम्मच से कुछ बींस बर्तन की दीवार पर दबाकर मसलें — इससे शोरबा प्राकृतिक रूप से गाढ़ा होता है। नमक और काली मिर्च से स्वाद लें। सफेद चावल, ताज़े संतरे के टुकड़ों और फारोफा (मक्खन में भुना हुआ कसावा आटा) के साथ परोसें।","en":"Drain the soaked beans and place in a large pot with fresh cold water to cover by 5cm. Add the smoked ribs and bay leaves. Bring to a boil, then simmer over medium heat for 1 hour, skimming any foam. Meanwhile, heat olive oil in a skillet, saute onion 8 minutes until soft and golden, add garlic and cook 2 minutes more. Add chourico and bacon, brown for 5 minutes. Transfer everything to the bean pot, stir well and simmer on low heat for 45-60 minutes until the beans are completely tender and the broth has thickened. Crush a handful of beans against the pot side with a wooden spoon — this thickens the stew naturally. Adjust salt and pepper. Serve in deep bowls with white rice, fresh orange slices and farofa (toasted manioc flour)."},"nutrition":{"cal":620,"prot":38,"carb":45,"fat":32,"fib":14}},{"id":19,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"hi":"चीन","en":"China","ro":"China"},"name":{"hi":"कुंग पाओ चिकन","en":"Kung Pao Chicken","ro":"Pui Gong Bao"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"hi":["500 ग्राम चिकन ब्रेस्ट, 2 सेमी क्यूब में कटा","100 ग्राम अनसाल्टेड भुनी मूँगफली","8–10 सूखी चीनी मिर्च (Sichuan या समान)","4 हरी प्याज़, 3 सेमी के टुकड़ों में कटी","3 लहसुन की कलियाँ, पतली कटी","2 सेमी अदरक का टुकड़ा, पतला कटा","2 बड़े चम्मच Sichuan मिर्च का तेल या सूरजमुखी का तेल","मैरीनेड: 1 बड़ा चम्मच सोया सॉस, 1 छोटा चम्मच कॉर्नस्टार्च, 1 छोटा चम्मच तिल का तेल","सॉस: 2 बड़े चम्मच सोया सॉस, 1 बड़ा चम्मच काला राइस विनेगर (Chinkiang), 1 बड़ा चम्मच चीनी, 1 छोटा चम्मच कॉर्नस्टार्च, 2 बड़े चम्मच पानी"],"en":["500g chicken breast, cut into 2cm cubes","100g unsalted roasted peanuts","8–10 dried Chinese chili peppers (Sichuan or similar)","4 spring onions, cut into 3cm pieces","3 garlic cloves, thinly sliced","2cm piece of ginger, thinly sliced","2 tbsp Sichuan chili oil or sunflower oil","Marinade: 1 tbsp soy sauce, 1 tsp cornstarch, 1 tsp sesame oil","Sauce: 2 tbsp soy sauce, 1 tbsp black rice vinegar (Chinkiang), 1 tbsp sugar, 1 tsp cornstarch, 2 tbsp water"],"ro":["500g piept de pui, tăiat cuburi de 2 cm","100g arahide prăjite nesărate","8–10 ardei iuți uscați chinezești (chili Sichuan)","4 cepe verzi, tăiate bucăți de 3 cm","3 căței de usturoi, feliați subțire","1 bucată ghimbir de 2 cm, feliată subțire","2 linguri ulei cu ardei Sichuan sau ulei de floarea-soarelui","Marinată: 1 lingură sos de soia, 1 linguriță amidon de porumb, 1 linguriță ulei de susan","Sos: 2 linguri sos de soia, 1 lingură oțet de orez negru (Chinkiang), 1 lingură zahăr, 1 linguriță amidon de porumb, 2 linguri apă"]},"howIsMade":{"hi":"चिकन को मैरीनेड के साथ मिलाएं और 15 मिनट के लिए छोड़ दें। एक छोटे कटोरे में सॉस की सामग्री मिलाएं। wok को सबसे तेज़ आँच पर धुआँ उठने तक गरम करें; तेल डालें और सूखी मिर्च तथा Sichuan peppercorns को 30 सेकंड भूनें जब तक गहरे रंग के हो जाएं पर काले नहीं — उनकी ख़ुशबू भुनी हुई होनी चाहिए, जली हुई नहीं। चिकन के टुकड़े डालें और बिना हिलाए 3–4 मिनट तक सेकें जब तक एक ओर सुनहरे हो जाएं; उछालें और 2 मिनट और पकाएं। लहसुन, अदरक और हरी प्याज़ के सफ़ेद हिस्से डालें; 1 मिनट stir-fry करें। सॉस डालें, 1 मिनट तक ज़ोर से उछालें जब तक गाढ़ा हो जाए और चिकन से चिपके। मूँगफली और हरी प्याज़ के हरे हिस्से डालें; 30 सेकंड उछालें। तुरंत jasmine चावल के साथ परोसें।","en":"Toss chicken with marinade ingredients and leave for 15 minutes. Combine sauce ingredients in a small bowl. Heat wok over highest heat until smoking; add oil and fry dried chilis and Sichuan peppercorns 30 seconds until darkened but not black — they should smell toasted, not burnt. Add chicken pieces and sear 3–4 minutes without stirring, until golden on one side; toss and cook 2 more minutes. Add garlic, ginger, and the white parts of the spring onion; stir-fry 1 minute. Pour in the sauce, toss vigorously for 1 minute until thickened and clinging to the chicken. Throw in peanuts and green spring onion tops; toss 30 seconds. Serve immediately with jasmine rice."},"nutrition":{"cal":400,"prot":32,"carb":11,"fat":22,"fib":2}},{"id":20,"servings":4,"tipType":"fish","pairingsType":"fish","origin":{"hi":"यूनाइटेड किंगडम","en":"United Kingdom","ro":"Marea Britanie"},"name":{"hi":"फिश एंड चिप्स","en":"Fish and Chips","ro":"Fish and Chips"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"hi":["4 cod या haddock फ़िलेट (लगभग 180 ग्राम प्रत्येक), त्वचा हटाई हुई","1 किलो मैली आलू (Maris Piper या King Edward), मोटे chips में कटे","डीप-फ्राई के लिए वनस्पति तेल (लगभग 2 लीटर)","बैटर: 180 ग्राम मैदा, डस्टिंग के लिए अतिरिक्त","1 छोटा चम्मच बेकिंग पाउडर","1 छोटा चम्मच बारीक नमक","300 मिली बर्फ़-ठंडी lager या pale ale","परोसने के लिए नमक और माल्ट विनेगर"],"en":["4 cod or haddock fillets (about 180g each), skin removed","1kg floury potatoes (Maris Piper or King Edward), cut into thick chips","Vegetable oil for deep-frying (about 2 litres)","Batter: 180g plain flour, plus extra for dusting","1 tsp baking powder","1 tsp fine salt","300ml ice-cold lager or pale ale","Salt and malt vinegar to serve"],"ro":["4 fileuri de cod sau haddock (aprox. 180g fiecare), fără piele","1 kg cartofi floury (Maris Piper sau King Edward), tăiați bețe groase","Ulei vegetal pentru prăjit (aprox. 2 litri)","Pentru aluat: 180g făină tip 550 + extra pentru tăvălit","1 linguriță praf de copt","1 linguriță sare fină","300ml bere blondă rece (lager sau ale)","Sare și oțet de malt pentru servire"]},"howIsMade":{"hi":"Chips को दो चरणों में पकाएं: 140°C पर 8 मिनट तक तलें जब तक नरम हो जाएं पर रंग न पकड़ें; छानें और ठंडा करें रैक पर। मैदा, बेकिंग पाउडर और नमक को साथ फेंटें, फिर धीरे-धीरे बर्फ़-ठंडी बीयर मिलाएं जब तक double cream जैसी consistency न हो जाए — ज़्यादा न फेंटें। मछली के फ़िलेट को कागज़ के तौलिये से पूरी तरह सुखाएं। तेल को 185°C तक गरम करें। हर फ़िलेट को अतिरिक्त मैदा में लपेटें, अतिरिक्त झाड़ दें, बैटर में डुबोएं और कुछ सेकंड टपकने दें। 6–8 मिनट तक तलें — आधे रास्ते पर ऊपर से गरम तेल चम्मच से डालते रहें ताकि बराबर कुरकुरा हो — जब तक बैटर गहरा सुनहरा और कुरकुरा न हो जाए। कागज़ पर छानें। तेल को 200°C तक बढ़ाएं और chips को दूसरी बार 3–4 मिनट तक तलें जब तक हर ओर सुनहरे और कुरकुरे हो जाएं। तुरंत नमक और माल्ट विनेगर के साथ परोसें।","en":"Cook chips in two stages: fry at 140°C for 8 minutes until soft but not coloured; drain and cool on a rack. Make the batter by whisking flour, baking powder, and salt together, then gradually whisk in ice-cold beer until the consistency of double cream — do not overmix. Pat fish fillets completely dry with paper towels. Heat oil to 185°C. Dust each fillet in the extra flour, shake off excess, dip into batter and let it drip for a few seconds. Fry 6–8 minutes — halfway through, spoon hot oil over the top for even crisping — until the batter is deep golden and crunchy. Drain on paper. Raise oil to 200°C and fry chips a second time for 3–4 minutes until golden and crisp all over. Serve immediately with salt and malt vinegar."},"nutrition":{"cal":850,"prot":35,"carb":85,"fat":42,"fib":5}},{"id":21,"origin":{"hi":"वियतनाम","en":"Vietnam","ro":"Vietnam"},"name":{"hi":"फो","en":"Pho","ro":"Pho"},"category":{"en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","timeMins":{"total":225,"active":75},"pairingsType":"def","ingredients":{"hi":["400 ग्राम सूखी राइस नूडल्स (banh pho, 5 मिमी चौड़ी)","500 ग्राम बीफ़ brisket या flank (शोरबे के लिए)","1 किलो बीफ़ की हड्डियाँ (marrow या knuckle)","2 मध्यम प्याज़, आधी कटी","5 सेमी ताज़ी अदरक, लंबाई में आधी कटी","3 चक्र फूल (star anise)","1 दालचीनी की डंडी (5 सेमी)","3 लौंग","2 बड़े चम्मच मछली की सॉस (nuoc mam)","1 छोटा चम्मच चीनी","नमक स्वादानुसार","200 ग्राम ताज़े मूँग के अंकुर","ताज़ा धनिया और थाई तुलसी","2 लाल मिर्चें, कटी (मेज़ पर)","2 नींबू, चौथाई में कटे (मेज़ पर)","hoisin sauce और sriracha (मेज़ पर)"],"en":["400g dried rice noodles (banh pho, 5mm width)","500g beef brisket or flank (for the broth)","1kg beef bones (marrow or knuckle)","2 medium onions, halved","5 cm fresh ginger, halved lengthways","3 star anise","1 cinnamon stick (5 cm)","3 cloves","2 tbsp fish sauce (nuoc mam)","1 tsp sugar","salt to taste","200g fresh bean sprouts","fresh coriander and Thai basil","2 red chillies, sliced (at the table)","2 limes, quartered (at the table)","hoisin sauce and sriracha (at the table)"],"ro":["400g tăiței de orez (banh pho, lățime 5mm), uscați","500g piept de vită sau flacără (pentru supă)","1kg oase de vită (măduvă sau coadă)","2 cepe medii, înjumătățite","5 cm ghimbir proaspăt, înjumătățit","3 anasoane stelate","1 baton de scorțișoară (5 cm)","3 cuișoare","2 linguri sos de pește (nuoc mam)","1 linguriță zahăr","sare după gust","200g muguri de soia proaspeți","coriandru proaspăt și busuioc thai","2 ardei iuți roșii, feliați (la masă)","2 lămâi verzi, tăiate în sferturi (la masă)","sos hoisin și sos sriracha (la masă)"]},"howIsMade":{"hi":"बीफ़ की हड्डियों को उबलते पानी में 5 मिनट तक blanch करें, पानी फेंक दें, अच्छी तरह धोएं — यह अशुद्धियाँ हटाता है और शोरबा साफ़ रखता है। प्याज़ के आधे टुकड़े और अदरक को सीधे गैस की आँच पर या grill के नीचे तब तक भूनें जब तक किनारे हल्के काले हो जाएं (2–3 मिनट प्रत्येक ओर) — यह शोरबे को सुनहरा रंग और गहराई देता है। एक बड़े बर्तन में 3 लीटर ठंडा पानी, हड्डियाँ, brisket, भुनी प्याज़, अदरक, चक्र फूल, दालचीनी और लौंग डालें। उबाल पर लाएं, बिल्कुल धीमी आँच पर 3 घंटे बिना ढके पकाएं, बीच-बीच में चर्बी निकालते रहें। 1½ घंटे बाद brisket निकालें, ठंडा करें, पतला काटें। शोरबे को बारीक छलनी से छानें, मछली सॉस, चीनी और नमक से स्वाद दें। नूडल्स को ठंडे पानी में 20 मिनट भिगोएं, 30 सेकंड उबालें, छानें। नूडल्स को कटोरों में बाँटें, ऊपर खौलता शोरबा डालें, मांस के टुकड़े जोड़ें। मेज़ पर मूँग के अंकुर, धनिया, तुलसी, मिर्च, नींबू और सॉस के साथ परोसें।","en":"Blanch beef bones in boiling water for 5 minutes, discard water, rinse well — this removes impurities and keeps the broth clear. Char the onion halves and ginger directly over a gas flame or under the grill until lightly blackened on the edges (2–3 minutes per side) — this gives the broth its golden colour and depth. Fill a large pot with 3L cold water, add bones, brisket, charred onion, ginger, star anise, cinnamon, and cloves. Bring to a boil, reduce to a bare simmer, cook uncovered for 3 hours, skimming fat periodically. Remove the brisket after 1½ hours, let cool, slice thinly. Strain broth through a fine sieve, season with fish sauce, sugar, and salt. Soak noodles in cold water 20 minutes, boil 30 seconds, drain. Divide noodles into bowls, ladle boiling broth over, add meat slices. Serve with bean sprouts, coriander, basil, chilli, lime, and sauces at the table."},"nutrition":{"cal":380,"prot":28,"carb":42,"fat":10,"fib":2}},{"id":22,"origin":{"hi":"स्पेन","en":"Spain","ro":"Spania"},"name":{"hi":"पैया","en":"Paella","ro":"Paella"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"fish","ingredients":{"hi":["300 ग्राम bomba चावल (या शॉर्ट-ग्रेन चावल)","400 ग्राम बोनलेस चिकन थाई, टुकड़ों में कटे","300 ग्राम कच्चे झींगे (छिलके वाले या छिले)","400 ग्राम mussels, साफ़ की हुई और beard निकाली","1 बड़ी प्याज़, बारीक कटी","4 लहसुन की कलियाँ, कीमा की हुई","1 लाल शिमला मिर्च, कटी","400 ग्राम डब्बाबंद कुटे टमाटर","½ छोटा चम्मच केसर के रेशे (2 बड़े चम्मच गुनगुने पानी में भिगोए)","1 छोटा चम्मच smoked paprika (pimentón de la Vera)","800 मिली गुनगुना चिकन शोरबा","3 बड़े चम्मच olive oil","नमक और काली मिर्च स्वादानुसार","परोसने के लिए ताज़ा अजमोद और नींबू की फाँकें"],"en":["300g bomba rice (or short-grain rice)","400g boneless chicken thighs, cut into pieces","300g raw prawns (shell-on or peeled)","400g mussels, scrubbed and debearded","1 large onion, finely chopped","4 garlic cloves, minced","1 red bell pepper, diced","400g canned crushed tomatoes","½ tsp saffron threads (soaked in 2 tbsp warm water)","1 tsp smoked paprika (pimentón de la Vera)","800ml warm chicken stock","3 tbsp olive oil","salt and black pepper to taste","fresh parsley and lemon wedges to serve"],"ro":["300g orez bomba (sau orez cu bob scurt)","400g pulpe de pui dezosate, tăiate în bucăți","300g creveți crudi (cu coajă sau fără)","400g midii, spălate și curățate","1 ceapă mare, tocată","4 căței de usturoi, tocați","1 ardei gras roșu, tăiat cuburi","400g roșii din conservă, concasate","½ linguriță șofran (înmuiat în 2 linguri apă caldă)","1 linguriță boia de ardei afumată (pimentón de la Vera)","800ml fond de pui cald","3 linguri ulei de măsline","sare și piper negru după gust","pătrunjel proaspăt și felii de lămâie pentru servire"]},"howIsMade":{"hi":"केसर को 2 बड़े चम्मच गुनगुने पानी में भिगो दें; पाएला पैन (या चौड़े उथले पैन) में जैतून का तेल मध्यम-तेज आँच पर गर्म करें. चिकन में नमक डालकर हर तरफ 4–5 मिनट तक गहरा सुनहरा होने तक भूनें; निकालकर अलग रख दें; उसी पैन में प्याज 5 मिनट तक भूनें, फिर लहसुन और लाल मिर्च डालकर 3 मिनट और पकाएँ. कुचले हुए टमाटर और स्मोक्ड पैप्रिका डालें, 3–4 मिनट तक पकाएँ जब तक गाढ़ा न हो जाए — यह सोफ्रितो है, पाएला की आत्मा; अब चावल डालें, 1 मिनट हल्के से भूनें. गर्म स्टॉक को केसर और उसके भीगे पानी के साथ डालें, समान रूप से फैलाएँ; चिकन वापस रखें. आँच मध्यम कर दें और फिर हिलाएँ नहीं — स्टॉक डालने के बाद पाएला को कभी न हिलाएँ; बिना ढके 10 मिनट पकाएँ. ऊपर झींगा और मसल्स रखें, चावल में हल्के से दबाएँ; 8–10 मिनट और पकाएँ जब तक झींगा गुलाबी न हो जाए और मसल्स खुल न जाएँ (जो बंद रहें उन्हें फेंक दें). सोकाररात (वो प्यारी कुरकुरी तह) के लिए, अंतिम 2 मिनट तेज आँच कर दें — हल्की चटचटाहट सुनें; 5 मिनट विश्राम दें; अजमोद से सजाएँ और नींबू के टुकड़ों के साथ परोसें.","en":"Soak saffron in 2 tbsp warm water; heat olive oil in a paella pan (or wide shallow pan) over medium-high heat. Season chicken, sear 4–5 minutes per side until deeply golden; remove and set aside; in the same pan fry onion 5 minutes, add garlic and red pepper, cook 3 more minutes. Add crushed tomatoes and smoked paprika, cook 3–4 minutes until thickened — this is the sofrito, the soul of the paella; add the rice, stir 1 minute to toast lightly. Pour in the warm stock with the saffron and its soaking water, spread evenly; return the chicken. Adjust to medium heat and do not stir again — never stir paella once the stock is added; cook uncovered for 10 minutes. Place prawns and mussels on top, pressing gently into the rice; cook 8–10 minutes more until prawns are pink and mussels open (discard any that stay shut). For socarrat (the coveted crispy bottom crust), raise to high heat the last 2 minutes — listen for a light crackling; rest 5 minutes; garnish with parsley and serve with lemon wedges."},"nutrition":{"cal":520,"prot":32,"carb":58,"fat":16,"fib":3}},{"id":23,"servings":4,"tipType":"def","pairingsType":"korean","origin":{"hi":"दक्षिण कोरिया","en":"South Korea","ro":"Coreea de Sud"},"name":{"hi":"बीबीम्बैप","en":"Bibimbap","ro":"Bibimbap"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"hi":["2 कप शॉर्ट-ग्रेन सफ़ेद चावल","200 ग्राम बीफ़ sirloin, रेशे के विपरीत पतला कटा","1 मध्यम तोरी, julienne की","1 मध्यम गाजर, julienne की","200 ग्राम बेबी पालक","100 ग्राम मूँग के अंकुर","4 shiitake मशरूम, डंठल हटाए","4 अंडे","4 बड़े चम्मच gochujang (कोरियाई मिर्च पेस्ट)","3 बड़े चम्मच तिल का तेल","2 बड़े चम्मच सोया सॉस","1 छोटा चम्मच चीनी","3 लहसुन की कलियाँ, कीमा की हुई","सजावट के लिए तिल"],"en":["2 cups short-grain white rice","200g beef sirloin, thinly sliced against the grain","1 medium courgette, julienned","1 medium carrot, julienned","200g baby spinach","100g bean sprouts","4 shiitake mushrooms, stems removed","4 eggs","4 tbsp gochujang (Korean chili paste)","3 tbsp sesame oil","2 tbsp soy sauce","1 tsp sugar","3 cloves garlic, minced","Sesame seeds to garnish"],"ro":["2 căni orez cu bob scurt","200g vită (antricot), felii subțiri","1 dovlecel mediu, julien","1 morcov mediu, julien","200g spanac baby","100g germeni de fasole","4 ciuperci shiitake, fără codiță","4 ouă","4 linguri gochujang (pastă de ardei coreean)","3 linguri ulei de susan","2 linguri sos de soia","1 linguriță zahăr","3 căței de usturoi, tocați","Semințe de susan, pentru decor"]},"howIsMade":{"hi":"चावल को 2.5 कप पानी में पकाएं: उबाल पर लाएं, ढक दें और सबसे धीमी आँच पर 12 मिनट तक धीमी आँच पर पकाएं, फिर आँच से उतार कर 10 मिनट विश्राम दें। बीफ़ को 1 बड़ा चम्मच सोया सॉस, 1 बड़ा चम्मच तिल का तेल, 1 छोटा चम्मच चीनी और आधे लहसुन के साथ 15 मिनट के लिए मैरीनेट करें। पालक को उबलते नमकीन पानी में 30 सेकंड blanch करें, निचोड़कर सुखाएं, 1 छोटा चम्मच तिल के तेल और नमक से स्वाद दें; मूँग के अंकुरों को लहसुन और नमक के साथ 2 मिनट भूनें; गाजर और तोरी को अलग-अलग 2-2 मिनट तिल के तेल की धार के साथ stir-fry करें। मैरीनेटेड बीफ़ को तेज़ आँच पर 3–4 मिनट तक caramelise होने तक सेकें; shiitake को काटें और सोया सॉस की एक छिड़काव के साथ 2 मिनट भूनें; अंडे को तिल के तेल में sunny-side up तलें। चावल को 4 कटोरों में बाँटें, सब्ज़ियाँ और बीफ़ खंडों में सजाएं, बीच में एक अंडा रखें, हर कटोरे में 1 बड़ा चम्मच gochujang डालें, तिल का तेल छिड़कें और तिल छिड़कें — खाने से पहले सब कुछ मिला लें।","en":"Cook rice in 2.5 cups water: bring to a boil, cover and simmer on the lowest heat for 12 minutes, then rest off the heat for 10 minutes. Marinate beef with 1 tbsp soy sauce, 1 tbsp sesame oil, 1 tsp sugar and half the garlic for 15 minutes. Blanch spinach 30 seconds in boiling salted water, squeeze dry, season with 1 tsp sesame oil and salt; sauté bean sprouts 2 minutes with garlic and salt; stir-fry carrot and courgette separately for 2 minutes each with a drizzle of sesame oil. Sear marinated beef over high heat 3–4 minutes until caramelised; slice shiitake and sauté 2 minutes with a splash of soy sauce; fry eggs sunny-side up in sesame oil. Divide rice among 4 bowls, arrange vegetables and beef in sections, place an egg in the centre, add 1 tbsp gochujang per bowl, drizzle with sesame oil and scatter sesame seeds — mix everything together before eating."},"nutrition":{"cal":450,"prot":22,"carb":65,"fat":12,"fib":5}},{"id":24,"servings":4,"tipType":"def","pairingsType":"veg","origin":{"hi":"सीरिया","en":"Syria","ro":"Siria"},"name":{"hi":"हम्मस","en":"Hummus","ro":"Hummus"},"category":{"hi":"नाश्ता","en":"Snack","ro":"Gustare"},"ingredients":{"hi":["400 ग्राम पका हुआ छोला (1 डिब्बा), छिलके हटाए हुए","80 ग्राम ताहिनी (अच्छी गुणवत्ता, अच्छे से हिलाई हुई)","2 नींबू का रस (लगभग 4 बड़े चम्मच)","2 लहसुन की कलियां, कद्दूकस की हुई","आधा छोटा चम्मच बारीक नमक","3–5 बड़े चम्मच बर्फ जैसा ठंडा पानी","2 बड़े चम्मच एक्स्ट्रा-वर्जिन जैतून का तेल परिष्करण के लिए"],"en":["400g (1 can) cooked chickpeas, skins removed","80g tahini (good quality, stirred well)","juice of 2 lemons (about 4 tbsp)","2 garlic cloves, grated","1/2 tsp fine salt","3–5 tbsp ice-cold water","2 tbsp extra-virgin olive oil for finishing"],"ro":["400g năut gătit (1 conservă), coaja îndepărtată","80g pastă de susan (tahini de calitate, bine amestecată)","sucul a 2 lămâi (aprox. 4 linguri)","2 căței de usturoi, rași","1/2 linguriță sare fină","3–5 linguri apă rece cu gheață","2 linguri ulei de măsline extravirgin pentru finalizare"]},"howIsMade":{"hi":"सबसे मुलायम हम्मस के लिए, प्रत्येक छोले को हल्के से दबाकर उसकी छिलका निकालें — यह छोटा कदम बड़ा फर्क डालता है। फूड प्रोसेसर में, ताहिनी और नींबू का रस अकेले 1 मिनट के लिए तब तक पीसें जब तक हल्के और मलाईदार न हो जाएं। लहसुन और नमक डालें; 30 सेकंड पीसें। छोले डालें और 1 मिनट प्रोसेस करें। मशीन चालू करते हुए, बर्फीला ठंडा पानी एक-एक चम्मच डालें — ठंडा पानी हम्मस को हल्का और हवादार बनाता है। कुल 3–5 मिनट प्रोसेस करें, किनारों को खुरचते हुए, जब तक पूरी तरह मुलायम न हो जाए। स्वाद लें और नींबू और नमक को समायोजित करें। एक कटोरे में फैलाएं, जैतून का तेल डालें और स्मोक्ड पापरिका या सुमैक से सजाएं।","en":"For the smoothest hummus, pop the skins off the chickpeas by gently squeezing each one — a small step that makes a big difference. In a food processor, blitz tahini and lemon juice alone for 1 minute until pale and creamy. Add garlic and salt; blitz 30 seconds. Add the chickpeas and process 1 minute. With the machine running, drizzle in ice-cold water tablespoon by tablespoon — the cold water aerates and lightens the hummus. Process 3–5 minutes total, scraping down the sides, until completely smooth. Taste and adjust lemon and salt. Spread in a bowl, drizzle with olive oil, and finish with smoked paprika or sumac. Keeps refrigerated up to 5 days."},"nutrition":{"cal":220,"prot":8,"carb":22,"fat":12,"fib":6}},{"id":25,"servings":4,"tipType":"def","pairingsType":"veg","origin":{"hi":"लेबनान","en":"Lebanon","ro":"Liban"},"name":{"hi":"तब्बूलेह","en":"Tabbouleh","ro":"Tabbouleh"},"category":{"hi":"सलाद","en":"Salad","ro":"Salate"},"ingredients":{"hi":["200 ग्राम फ्लैट-लीफ अजमोद, केवल पत्तियां, बारीक कटी","50 ग्राम बारीक बुलगर, ठंडे पानी में 20 मिनट भिगोकर निचोड़ें","3 पके टमाटर (लगभग 300g), छोटे टुकड़ों में","4 हरे प्याज, बारीक कटे","20 ग्राम ताज़ी पुदीना पत्तियां, बारीक कटी","2 नींबू का रस (लगभग 80ml)","4 टेबलस्पून एक्स्ट्रा-वर्जिन ऑलिव ऑयल, नमक और काली मिर्च स्वादानुसार"],"en":["200g flat-leaf parsley, leaves only, finely chopped","50g fine bulgur wheat, soaked in cold water 20 min then squeezed dry","3 ripe tomatoes (about 300g), finely diced","4 spring onions, finely sliced","20g fresh mint leaves, finely chopped","juice of 2 lemons (about 80ml)","4 tbsp extra-virgin olive oil, salt and black pepper to taste"],"ro":["200g pătrunjel plat, frunze tocate mărunt","50g bulgur fin, înmuiat 20 min în apă rece, stors bine","3 roșii coapte (cca 300g), tăiate cuburi mici","4 cepe verzi, tocate fin","20g frunze de mentă proaspătă, tocate mărunt","sucul de la 2 lămâi (cca 80ml)","4 linguri ulei de măsline extravirgin, sare și piper negru după gust"]},"howIsMade":{"hi":"बुलगर को 20 मिनट ठंडे पानी में भिगोएं, फिर छानकर हाथों से अच्छे से निचोड़ें — यह सूखा होना चाहिए, गीला नहीं। अजमोद को जितना हो सके बारीक काटें; असली तब्बूलेह एक हर्ब सलाद है, अनाज सलाद नहीं। एक बड़े कटोरे में अजमोद, पुदीना, हरे प्याज, टमाटर और निचोड़ा बुलगर मिलाएं। नींबू का रस और जैतून का तेल डालें, अच्छे से मिलाएं और 10 मिनट रखें। नमक और काली मिर्च से स्वाद लें। कमरे के तापमान पर परोसें।","en":"Soak the bulgur in cold water for 20 minutes, then drain and squeeze out as much water as possible with your hands — it should be dry, not wet. Chop the parsley as finely as you can; authentic tabbouleh is herb-forward, not grain-forward. Combine parsley, mint, spring onions, tomatoes and squeezed bulgur in a large bowl. Add lemon juice and olive oil, toss well and let rest 10 minutes — the lemon juice continues to soften the bulgur and blooms the herbs. Adjust salt and pepper. Serve at room temperature. True tabbouleh is a parsley salad with bulgur, not a bulgur salad with a little parsley."},"nutrition":{"cal":180,"prot":4,"carb":20,"fat":10,"fib":4}},{"id":26,"servings":4,"tipType":"pasta","pairingsType":"pasta","origin":{"hi":"इटली","en":"Italy","ro":"Italia"},"name":{"hi":"रिसोट्टो","en":"Risotto","ro":"Risotto"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["320 ग्राम आर्बोरियो या कार्नारोली चावल","1 बड़ा शैलट या छोटा प्याज, बारीक कटा हुआ","50 ग्राम अनसाल्टेड मक्खन, विभाजित","100 मिली सूखी सफेद वाइन","1.2 लीटर गर्म चिकन या सब्जी का स्टॉक","40 ग्राम पर्मिजानो-रेजियानो, ताज़ा कसा हुआ","1 बड़ा चम्मच एक्स्ट्रा-वर्जिन जैतून का तेल","नमक और सफेद मिर्च स्वाद अनुसार"],"en":["320g Arborio or Carnaroli rice","1 large shallot or small onion, finely diced","50g unsalted butter, divided","100ml dry white wine","1.2L warm chicken or vegetable stock","40g Parmigiano-Reggiano, freshly grated","1 tbsp extra-virgin olive oil","salt and white pepper to taste"],"ro":["320g orez Arborio sau Carnaroli","1 șalotă sau ceapă mică, tocată fin","50g unt nesărat, împărțit","100ml vin alb sec","1,2L supă caldă de pui sau legume","40g Parmigiano-Reggiano, ras proaspăt","1 lingură ulei de măsline extravirgin","sare și piper alb după gust"]},"howIsMade":{"hi":"पूरी रसोई के दौरान स्टॉक को कम आंच पर गर्म रखें — ठंडा स्टॉक डालने से खाना बनना रुक जाता है और मलाईदारपन नष्ट हो जाता है। एक चौड़े, भारी पैन में मध्यम आंच पर तेल और आधा मक्खन गर्म करें। शैलट को 3 मिनट तक नरम होने तक भूनें। चावल डालें और 2 मिनट हिलाते हुए भूनें जब तक दाने के किनारे हल्के पारदर्शी न हो जाएं। वाइन डालें और तब तक हिलाएं जब तक पूरी तरह अवशोषित न हो जाए। गर्म स्टॉक को एक-एक चम्मच डालें, लगातार हिलाते हुए और प्रत्येक चम्मच के पूरी तरह अवशोषित होने के बाद अगला डालें — यह आवश्यक कदम 16–18 मिनट लेता है। चावल al dente होना चाहिए। आंच से हटाकर बचे हुए ठंडे मक्खन और पर्मिजानो को जोरदार तरीके से मिलाएं (इसे mantecatura कहते हैं)। 1 मिनट आराम दें, फिर गर्म कटोरे में तुरंत परोसें।","en":"Keep the stock warm over low heat throughout cooking — adding cold stock stops the cooking and ruins the creaminess. Heat oil and half the butter in a wide, heavy pan over medium heat. Sweat the shallot until soft, 3 minutes. Add the rice and toast, stirring, for 2 minutes until grains are slightly translucent at the edges. Pour in the wine and stir until completely absorbed. Add warm stock one ladleful at a time, stirring constantly and waiting for each ladleful to be absorbed before adding the next — this is the essential step and takes 16–18 minutes. The rice should be al dente with a creamy coating. Off the heat, beat in the remaining cold butter and the Parmigiano vigorously — the fat emulsifies into the starches creating a glossy sauce (this is called mantecatura). Rest 1 minute, then serve immediately in warm bowls."}},{"id":27,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"hi":"स्वीडन","en":"Sweden","ro":"Suedia"},"name":{"hi":"स्वीडिश मीटबॉल","en":"Swedish Meatballs","ro":"Chifteluțe suedeze"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"ingredients":{"hi":["सूअर और गाय का मिश्रित कीमा 500 ग्राम (आधा-आधा)","1 मध्यम आकार का प्याज, कद्दूकस किया हुआ","1 सफेद ब्रेड का टुकड़ा बिना किनारे के, 3 बड़े चम्मच दूध में भिगोया हुआ","1 बड़ा अंडा","1/4 छोटा चम्मच पिसा हुआ ऑलस्पाइस","1/4 छोटा चम्मच ताज़ा कद्दूकस किया जायफल","तलने के लिए 2 बड़े चम्मच मक्खन","250 मिली बीफ स्टॉक","150 मिली डबल क्रीम"],"en":["500g mixed ground pork and beef (50/50)","1 medium onion, grated","1 slice white bread, crusts removed, soaked in 3 tbsp milk","1 large egg","1/4 tsp ground allspice","1/4 tsp freshly grated nutmeg","2 tbsp butter for frying","250ml beef stock","150ml double cream"],"ro":["500g carne tocată amestecată porc și vită (50/50)","1 ceapă medie, rasă","1 felie de pâine albă fără coajă, înmuiată în 3 linguri lapte","1 ou mare","1/4 linguriță ienibahar măcinat","1/4 linguriță nucșoară rasă","2 linguri unt pentru prăjit","250ml supă de vită","150ml smântână pentru frișcă"]},"howIsMade":{"hi":"भिगोई हुई ब्रेड को दबाकर अतिरिक्त दूध निकालें, फिर कीमे, कद्दूकस किए प्याज (दबाकर पानी निकाला), अंडे, ऑलस्पाइस, जायफल, नमक और मिर्च के साथ मिलाएं। अच्छी तरह मिलाएं लेकिन ज्यादा न मिलाएं — ज्यादा मिलाने से मीटबॉल सख्त हो जाते हैं। गीले हाथों से लगभग 3 सेमी व्यास की गोलियां बनाएं (20–24 गोलियां)। एक चौड़े स्किलेट में मध्यम आंच पर मक्खन पिघलाएं। मीटबॉल को बैचों में तलें, धीरे-धीरे घुमाकर सभी तरफ भूरा करें, प्रति बैच 6–8 मिनट। निकालकर अलग रखें। उसी पैन में बीफ स्टॉक डालें, तले को खुरचते हुए उबाल लाएं। क्रीम डालें और 5 मिनट पकाएं जब तक थोड़ा गाढ़ा न हो जाए। मीटबॉल को सॉस में वापस डालें और धीमी आंच पर 5 मिनट और पकाएं। लिंगोनबेरी जैम, उबले आलू या मसले हुए आलू, और अचार के साथ परोसें।","en":"Squeeze the soaked bread to remove excess milk, then mix with the ground meat, grated onion (squeeze out excess liquid), egg, allspice, nutmeg, salt and pepper. Mix well but do not overwork — overworking makes the meatballs tough. With wet hands, roll into balls about 3cm in diameter, yielding about 20–24 meatballs. Melt butter in a wide skillet over medium heat. Fry the meatballs in batches, rolling gently to brown all sides evenly, 6–8 minutes per batch. Remove and set aside. In the same pan, stir in the beef stock, scraping up the fond, and bring to a simmer. Add the cream and simmer 5 minutes until slightly thickened. Return the meatballs to the sauce and cook on low heat 5 more minutes. Serve with lingonberry jam, boiled or mashed potatoes, and pickled cucumber."}},{"id":28,"servings":4,"tipType":"meat","timeMins":{"total":720,"active":75},"pairingsType":"japanese","origin":{"hi":"जापान","en":"Japan","ro":"Japonia"},"name":{"hi":"क्लासिक जापानी रामेन","en":"Classic Japanese Ramen","ro":"Ramen clasic japonez"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"ingredients":{"hi":["4 सर्विंग ताज़े या सूखे रामेन नूडल्स (कुल लगभग 400 ग्राम)","चिकन या पोर्क बोन ब्रोथ 1 लीटर","सोया सॉस 100 मिली (स्वाद अनुसार)","मिरिन 2 बड़े चम्मच","200 ग्राम पोर्क बेली या कंधे की मांस, पतले स्लाइस में (चाशु)","4 सॉफ्ट-बॉइल्ड अंडे (रात भर सोया सॉस और मिरिन में मैरिनेट किए)","2 नोरी की शीट (सूखे समुद्री शैवाल), आधे काटे हुए","बांस की कोंपलें 4 बड़े चम्मच (मेनमा)","2 हरे प्याज, पतले स्लाइस","तिल का तेल 1 बड़ा चम्मच"],"en":["4 portions fresh or dried ramen noodles (about 400g total)","1L chicken or pork bone broth","100ml soy sauce (or to taste)","2 tbsp mirin","200g pork belly or shoulder, thinly sliced (chashu)","4 soft-boiled eggs (marinated overnight in soy sauce and mirin)","2 sheets nori (dried seaweed), halved","4 tbsp bamboo shoots (menma)","2 spring onions, thinly sliced","1 tbsp sesame oil"],"ro":["4 porții tăiței ramen proaspeți sau uscați (aprox. 400g total)","1L supă de pui sau os de porc","100ml sos de soia (sau după gust)","2 linguri mirin","200g burtă de porc sau pulpă, feliată subțire (chashu)","4 ouă fierte moi (marinate în soia și mirin peste noapte)","2 foi nori (alge uscate), tăiate în jumătate","4 linguri mlădițe de bambus (menma)","2 cepe verzi, feliați subțire","1 lingură ulei de susan"]},"howIsMade":{"hi":"ब्रोथ में सोया सॉस और मिरिन मिलाएं; 10 मिनट उबालें और चखें — ब्रोथ गहरा स्वादिष्ट, थोड़ा नमकीन और हल्की मिठास वाला होना चाहिए। रामेन अंडे (रात पहले बनाना सबसे अच्छा): अंडों को ठीक 6 मिनट 30 सेकंड उबालें, तुरंत बर्फ के पानी में ठंडा करें, छीलें और रात भर 3 बड़े चम्मच सोया सॉस, 2 बड़े चम्मच मिरिन और 50 मिली पानी में मैरिनेट करें। चाशु: पोर्क बेली को कसकर रोल करें, रसोई की सुतली से बांधें और सोया सॉस, मिरिन, साके और चीनी में धीमी आंच पर 2 घंटे ब्रेज़ करें। ठंडा होने पर स्लाइस करें। पैकेज के निर्देशों के अनुसार नूडल्स पकाएं (आमतौर पर 2–3 मिनट), पानी निकालें और गर्म कटोरों में परोसें। गर्म ब्रोथ डालें। ऊपर 2–3 स्लाइस चाशु, आधा रामेन अंडा, खड़ा नोरी का टुकड़ा, बांस की कोंपलें, हरे प्याज और तिल का तेल की एक बूंद डालें। तुरंत परोसें।","en":"Combine the broth with soy sauce and mirin; simmer 10 minutes and taste — the broth should be deeply savoury, slightly salty, with a hint of sweetness. Ramen eggs (best made the night before): boil eggs for exactly 6 minutes 30 seconds, shock in ice water, peel, and marinate overnight in 3 tbsp soy sauce, 2 tbsp mirin, and 50ml water. Chashu pork: roll pork belly tightly, tie with kitchen string, and braise in soy sauce, mirin, sake, and sugar over a gentle simmer for 2 hours until tender. Slice when cool. Cook noodles per package directions (usually 2–3 minutes), drain, and portion into warmed bowls. Ladle hot broth over. Top with 2–3 slices of chashu pork, a halved ramen egg, a piece of nori standing upright, bamboo shoots, spring onions, and a drop of sesame oil. Serve immediately."}},{"id":29,"servings":4,"tipType":"meat","pairingsType":"latin","origin":{"hi":"अर्जेंटीना","en":"Argentina","ro":"Argentina"},"name":{"hi":"एम्पानादास","en":"Empanadas","ro":"Empanadas"},"category":{"hi":"स्नैक","en":"Snack","ro":"Gustare"},"ingredients":{"hi":["400 ग्राम मैदा","100 ग्राम लार्ड या ठंडा मक्खन, टुकड़ों में","150 मिली गुनगुना पानी","1 चम्मच नमक","300 ग्राम कीमा (बीफ)","1 मध्यम प्याज, बारीक कटा हुआ","2 उबले अंडे, कटे हुए","12 हरे जैतून, बीज निकाले और कटे हुए","1 चम्मच जीरा पाउडर","1 चम्मच मीठी पापरिका"],"en":["400g plain flour","100g lard or cold butter, diced","150ml warm water","1 tsp salt","300g ground beef","1 medium onion, finely chopped","2 hard-boiled eggs, chopped","12 green olives, pitted and sliced","1 tsp ground cumin","1 tsp sweet paprika"],"ro":["400g făină albă","100g untură sau unt rece, cuburi","150ml apă caldă","1 linguriță sare","300g carne de vită tocată","1 ceapă medie, tocată fin","2 ouă fierte tari, tăiate","12 măsline verzi, fără sâmburi și tăiate","1 linguriță chimen măcinat","1 linguriță boia dulce"]},"howIsMade":{"hi":"आटा बनाएं: मैदा और नमक मिलाएं, लार्ड या ठंडे मक्खन को उंगलियों की नोक से मिलाकर ब्रेडक्रंब जैसा बनाएं, फिर धीरे-धीरे गुनगुना पानी डालें और 5 मिनट गूंधें। लपेटें और 30 मिनट आराम करने दें। भरावन के लिए: प्याज को थोड़े तेल में 8 मिनट भूनें, कीमा डालें और मध्यम आंच पर 10 मिनट अच्छे से भूनें। जीरा, पापरिका, नमक और काली मिर्च से सीज़न करें। पूरी तरह ठंडा होने दें, फिर कटे अंडे और जैतून मिलाएं। आटे को 3 मिमी मोटा बेलें और 12 सेमी के गोले काटें। बीच में एक चम्मच भरावन रखें, किनारों को गीला करें, अर्धचंद्र में मोड़ें और मुड़े हुए किनारे से बंद करें। 200°C पर 20-25 मिनट सुनहरा होने तक बेक करें, या 180°C के तेल में हर तरफ 3-4 मिनट डीप फ्राई करें।","en":"Make the dough: combine flour and salt, rub in the lard or cold butter with your fingertips until the mixture resembles breadcrumbs, then add warm water gradually and knead 5 minutes to a smooth, elastic dough. Wrap and rest 30 minutes. For the filling, saute onion in a little oil for 8 minutes, add ground beef and cook 10 minutes over medium heat, breaking it up well. Season with cumin, paprika, salt and pepper. Cool completely, then fold in the chopped boiled eggs and olives. Roll dough to 3mm thick and cut 12cm circles. Place a tablespoon of filling in the centre, moisten the edges, fold into a half-moon and seal with a twisted rope border (repulge). Bake at 200 degrees C for 20-25 minutes until golden, or deep-fry at 180 degrees C for 3-4 minutes per side."}},{"id":30,"servings":4,"tipType":"def","pairingsType":"mediterranean","origin":{"hi":"यूनान","en":"Greece","ro":"Grecia"},"name":{"hi":"त्ज़ात्ज़िकी","en":"Tzatziki","ro":"Tzatziki"},"category":{"hi":"स्नैक","en":"Snack","ro":"Gustare"},"ingredients":{"hi":["500 ग्राम फुल-फैट ग्रीक योगर्ट (संभव हो तो रात भर छानें)","1 बड़ा खीरा (लगभग 300g), कद्दूकस करके अच्छे से निचोड़ें","2 लहसुन की कलियां, बारीक कद्दूकस की","2 टेबलस्पून एक्स्ट्रा-वर्जिन ऑलिव ऑयल, परोसने के लिए अतिरिक्त","1 टेबलस्पून ताज़ा डिल, बारीक कटा","आधे नींबू का रस","बारीक समुद्री नमक स्वादानुसार"],"en":["500g full-fat Greek yogurt (strained overnight if possible)","1 large cucumber (about 300g), grated and well squeezed","2 garlic cloves, finely grated","2 tbsp extra-virgin olive oil, plus a drizzle to serve","1 tbsp fresh dill, finely chopped","juice of half a lemon","fine sea salt to taste"],"ro":["500g iaurt grecesc integral (scurs peste noapte dacă e posibil)","1 castravete mare (cca 300g), ras și bine stors","2 căței de usturoi, rași fin","2 linguri ulei de măsline extravirgin, plus un pic pentru servit","1 lingură mărar proaspăt, tocat mărunt","sucul de la jumătate de lămâie","sare fină după gust"]},"howIsMade":{"hi":"सबसे महत्वपूर्ण चरण: खीरे को बड़े छेद वाले कद्दूकस पर रगड़ें और एक साफ कपड़े या छन्नी में रखें। थोड़ा नमक छिड़कें, 10 मिनट रखें, फिर जोर से निचोड़ें — खीरा अपने वजन का लगभग आधा पानी छोड़ देगा। अतिरिक्त नमी ही त्ज़ात्ज़िकी को पानी जैसा बनाती है। योगर्ट में अच्छे से निचोड़ा खीरा, कद्दूकस लहसुन, जैतून का तेल, नींबू का रस और डिल मिलाएं। नमक से स्वाद लें। ढककर कम से कम 30 मिनट फ्रिज में रखें। ऑलिव ऑयल और ताज़े डिल से सजाकर गर्म पिता ब्रेड के साथ परोसें।","en":"The most important step: grate the cucumber on the coarse side of a box grater and place in a clean tea towel or colander. Sprinkle with a little salt, leave 10 minutes, then squeeze out hard — the cucumber will shed almost half its weight in water. Excess moisture is what makes tzatziki watery and weak. Combine the yogurt with the well-squeezed cucumber, grated garlic, olive oil, lemon juice and dill. Taste and adjust salt. Cover and refrigerate at least 30 minutes before serving — the flavours deepen as it rests. Serve drizzled with olive oil and a few fresh dill sprigs, alongside warm pita bread or souvlaki."}},{"id":31,"servings":4,"tipType":"soup","pairingsType":"french","origin":{"hi":"फ्रांस","en":"France","ro":"Franța"},"name":{"hi":"फ्रेंच प्याज सूप","en":"French Onion Soup","ro":"Supă de ceapă franțuzească"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"ingredients":{"hi":["1 किलो पीला प्याज, पतला कटा हुआ","60 ग्राम अनसाल्टेड मक्खन","1 टेबलस्पून मैदा","200ml ड्राई व्हाइट वाइन","1.2 लीटर अच्छा बीफ स्टॉक","बैगेट की 4 मोटी स्लाइस, टोस्ट की हुई","150g ग्रुयेर चीज़, कद्दूकस किया हुआ","नमक, काली मिर्च और ताज़ा थाइम"],"en":["1kg yellow onions, thinly sliced","60g unsalted butter","1 tbsp plain flour","200ml dry white wine","1.2 litres good beef stock","4 thick slices baguette, toasted","150g Gruyere, grated","salt, black pepper and fresh thyme sprigs"],"ro":["1kg ceapă galbenă, tăiată julienne","60g unt nesărat","1 lingură făină","200ml vin alb sec","1,2 litri supă bună de vită","4 felii groase de baghetă, prăjite","150g Gruyère, ras","sare, piper negru și crenguțe de cimbru proaspăt"]},"howIsMade":{"hi":"एक भारी-तले के बर्तन में मध्यम-कम आंच पर मक्खन पिघलाएं। प्याज और एक चुटकी नमक डालें और हर 5 मिनट में हिलाते हुए 45-60 मिनट पकाएं — यहां धैर्य ही सब कुछ है। प्याज कैरमल रंग का होना चाहिए, जला नहीं। थाइम और मैदा डालें, 1 मिनट हिलाएं। वाइन डालें और 3 मिनट उबलने दें। बीफ स्टॉक डालें, उबाल लाएं और 20 मिनट धीमी आंच पर पकाएं। नमक और काली मिर्च से स्वाद लें। ओवन-सेफ कटोरों में डालें, प्रत्येक में टोस्टेड बैगेट की स्लाइस रखें, ग्रुयेर से ढकें और ग्रिल पर 3-4 मिनट तक पनीर बुदबुदाने और सुनहरे भूरे होने तक रखें। तुरंत परोसें।","en":"Melt the butter in a heavy-bottomed pot over medium-low heat. Add the onions with a pinch of salt and cook for 45-60 minutes, stirring every 5 minutes — patience is everything here. The onions must turn the colour of caramel, not burnt. Add a splash of water whenever they stick. Add the thyme and flour, stir for 1 minute. Pour in the wine and let it bubble for 3 minutes. Add the beef stock, bring to a simmer and cook 20 minutes. Taste and adjust salt and pepper. Ladle into oven-safe bowls, float a slice of toasted baguette in each, pile on the Gruyere and grill (broil) for 3-4 minutes until the cheese is bubbling and golden brown. Serve immediately — the cheese will set as it cools."}},{"id":32,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"hi":"हंगरी","en":"Hungary","ro":"Ungaria"},"name":{"hi":"गुलाश","en":"Goulash","ro":"Gulaș"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["700 ग्राम बीफ चक या शिन, 3 सेमी टुकड़ों में","400 ग्राम वैक्सी आलू, छीलकर टुकड़ों में","2 बड़े प्याज, बारीक कटे","2 लाल शिमला मिर्च, टुकड़ों में","3 टेबलस्पून मीठा हंगेरियन पापरिका","400 ग्राम कैन्ड कटे टमाटर","1 लीटर बीफ स्टॉक","3 टेबलस्पून लार्ड या वेजिटेबल ऑयल","2 चम्मच कैरावे सीड्स, नमक और काली मिर्च"],"en":["700g beef chuck or shin, cut into 3cm cubes","400g waxy potatoes, peeled and diced","2 large onions, finely chopped","2 red bell peppers, diced","3 tbsp sweet Hungarian paprika","400g canned chopped tomatoes","1 litre beef stock","3 tbsp lard or vegetable oil","2 tsp caraway seeds, salt and black pepper to taste"],"ro":["700g carne de vită (spată sau greabăn), cuburi de 3 cm","400g cartofi cerosi, curățați și tăiați cuburi","2 cepe mari, tocate mărunt","2 ardei grași roșii, tăiați cuburi","3 linguri boia ungurească dulce","400g roșii tocate la conservă","1 litru supă de vită","3 linguri untură sau ulei vegetal","2 linguriță semințe de chimen, sare și piper negru după gust"]},"howIsMade":{"hi":"बीफ के टुकड़ों को पोंछकर सुखाएं और नमक-काली मिर्च से सीज़न करें। एक भारी बर्तन में लार्ड को तेज़ आंच पर गर्म करें और मांस को बैच में तेज़ गर्मी पर भूनें — ज्यादा न हिलाएं, क्रस्ट बनानी है। निकालकर रखें। मध्यम आंच पर प्याज को 10 मिनट भूनें। पापरिका डालें और 1 मिनट हिलाएं — जलने न दें वरना कड़वा हो जाएगा। शिमला मिर्च, टमाटर, कैरावे सीड्स और बीफ स्टॉक डालें। मांस वापस डालें, उबाल लाएं, ढककर धीमी आंच पर 60-75 मिनट पकाएं। आलू डालें और 25 मिनट और पकाएं। नमक से स्वाद लें। गहरे कटोरों में रस्टिक ब्रेड के साथ परोसें।","en":"Pat the beef cubes dry and season with salt and pepper. Heat the lard or oil in a heavy pot over high heat and brown the meat in batches — do not stir too much; you want a crust, not steamed meat. Remove and set aside. Reduce heat to medium, add the onions and cook 10 minutes. Add the paprika and stir for 1 minute — do not let it burn or it turns bitter. Add the peppers, tomatoes, caraway seeds and beef stock. Return the beef, bring to a boil, cover and simmer on low heat for 60-75 minutes. Add the potatoes and simmer 25 more minutes until tender and the beef flakes easily under pressure. Taste and adjust salt. Serve in deep bowls with crusty bread to mop up the rich broth."}},{"id":33,"servings":4,"tipType":"def","pairingsType":"middle-eastern","origin":{"hi":"मिस्र","en":"Egypt","ro":"Egipt"},"name":{"hi":"कोशरी","en":"Koshari","ro":"Koshari"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"ingredients":{"hi":["200 ग्राम लंबे दाने वाला सफेद चावल","200 ग्राम हरी दाल","150 ग्राम छोटा मैकरोनी या डिटालिनी","400 ग्राम कैन्ड छोले, छाने हुए","800 ग्राम कैन्ड कुटे टमाटर","3 बड़े प्याज (2 सॉस के लिए, 1 क्रिस्पी टॉपिंग के लिए)","4 टेबलस्पून वेजिटेबल ऑयल","3 लहसुन की कलियां, कटी, नमक, जीरा और सिरका स्वादानुसार"],"en":["200g long-grain white rice","200g green lentils","150g small macaroni or ditalini","400g canned chickpeas, drained","800g canned crushed tomatoes","3 large onions (2 for sauce, 1 for crispy topping)","4 tbsp vegetable oil","3 garlic cloves, minced, salt, cumin and vinegar to taste"],"ro":["200g orez cu bob lung","200g linte verde","150g macaroane mici sau ditalini","400g năut la conservă, scurs","800g roșii tocate la conservă","3 cepe mari (2 pentru sos, 1 pentru topping crocant)","4 linguri ulei vegetal","3 căței de usturoi, tocați, sare, chimen și oțet după gust"]},"howIsMade":{"hi":"दाल को बिना नमक के पानी में 20 मिनट अल डेंटे पकाएं, छानें। चावल को नमक वाले पानी में 15 मिनट पकाएं। मैकरोनी को अल डेंटे पकाकर छानें। तीसरे प्याज को पतले छल्लों में काटें और तेल में मध्यम-तेज आंच पर 15-20 मिनट तक बार-बार हिलाते हुए गहरे सुनहरे और कुरकुरे होने तक तलें। पेपर टॉवल पर निकालें। उसी तेल में बचे कटे प्याज को 10 मिनट भूनें, लहसुन, जीरा, कैन टमाटर, थोड़ा सिरका और नमक डालें। सॉस को 20-25 मिनट गाढ़ा होने तक पकाएं। छोले डालें और 5 मिनट और पकाएं। दाल को चावल में मिलाएं। परतों में परोसें: चावल-दाल, मैकरोनी, टमाटर-छोले की सॉस, और ऊपर कुरकुरे प्याज के छल्ले।","en":"Cook the lentils in unsalted water for 20 minutes until al dente, then drain. Cook the rice in salted water for 15 minutes. Cook the pasta al dente and drain. Slice the third onion into thin rings and fry in oil over medium-high heat for 15-20 minutes, stirring often, until deep golden brown and crispy — this is the prized topping. Drain on paper towels. In the same oil, saute the remaining chopped onions 10 minutes, add garlic, cumin, canned tomatoes, a splash of vinegar and salt. Simmer the sauce 20-25 minutes until thick. Add the chickpeas and simmer 5 more minutes. Mix lentils into the rice. To serve, layer rice-lentil mixture, pasta, tomato-chickpea sauce, and top with the crispy onion rings. Koshari is eaten at room temperature."}},{"id":35,"servings":8,"tipType":"dessert","pairingsType":"dessert","origin":{"hi":"तुर्की","en":"Turkey","ro":"Turcia"},"name":{"hi":"बक्लावा","en":"Baklava","ro":"Baklava"},"category":{"hi":"मिठाई","en":"Dessert","ro":"Desert"},"ingredients":{"hi":["500g फाइलो पेस्ट्री शीट, डीफ्रोस्ट","200g अनसाल्टेड मक्खन, पिघला हुआ","200g अखरोट, बारीक कटे","100g पिस्ता, बारीक कटे","1 चम्मच दालचीनी पाउडर","300g चीनी","200ml पानी","2 टेबलस्पून शहद और 1 टेबलस्पून नींबू का रस"],"en":["500g phyllo pastry sheets, thawed","200g unsalted butter, melted","200g walnuts, finely chopped","100g pistachios, finely chopped","1 tsp ground cinnamon","300g sugar","200ml water","2 tbsp honey plus 1 tbsp lemon juice"],"ro":["500g foi de plăcintă (phyllo), dezghețate","200g unt nesărat, topit","200g nuci, tocate mărunt","100g fistic, tocat mărunt","1 linguriță scorțișoară măcinată","300g zahăr","200ml apă","2 linguri miere plus 1 lingură suc de lămâie"]},"howIsMade":{"hi":"पहले चाशनी बनाएं: चीनी को पानी में घोलें, 5 मिनट उबालें, शहद और नींबू का रस डालें, 5 मिनट और उबालें; पूरी तरह ठंडा होने दें — चाशनी ठंडी होनी चाहिए जब गर्म बक्लावा पर डालें. अखरोट, पिस्ता और दालचीनी मिलाएं; 33x23 सेमी बेकिंग ट्रे को पिघले मक्खन से चिकना करें. 8 फाइलो शीट रखें, हर एक पर मक्खन लगाएं; अखरोट की मिश्रण की एक उदार परत बिछाएं. 4 मक्खन लगी शीट से ढकें, फिर एक और परत; अखरोट खत्म होने तक दोहराएं, 8 शीट से खत्म करें. बेक करने से पहले हीरे के आकार में काटें; 160 डिग्री C पर 45-50 मिनट हल्के सुनहरे रंग तक बेक करें. ओवन से निकालते ही ठंडी चाशनी ऊपर से डालें; परोसने से पहले 2-3 घंटे रखें.","en":"Make the syrup first: dissolve sugar in water, boil 5 minutes, add honey and lemon juice, boil 5 more minutes; leave to cool completely — the syrup must be cold when poured over hot baklava. Mix the walnuts with pistachios and cinnamon; grease a 33x23cm baking tray with melted butter. Layer 8 phyllo sheets, brushing each with butter; scatter a generous layer of nut mixture. Cover with 4 buttered phyllo sheets, then another nut layer; repeat until the nuts are used up, finishing with 8 buttered phyllo sheets. Cut into diamonds or squares before baking; bake at 160 degrees C for 45-50 minutes until pale golden. The moment it comes out of the oven, pour the cold syrup all over — the temperature contrast helps the baklava absorb every drop; leave to rest 2-3 hours before serving."}},{"id":36,"servings":4,"tipType":"meat","pairingsType":"mexican","origin":{"hi":"मेक्सिको","en":"Mexico","ro":"Mexic"},"name":{"hi":"चिली कॉन कार्ने","en":"Chili con carne","ro":"Chili con carne"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["500 ग्राम बीफ कीमा (न्यूनतम 20% फैट)","400 ग्राम कैन्ड रेड किडनी बींस, छाने हुए","400 ग्राम कैन्ड कटे टमाटर","2 बड़े प्याज, कटे हुए","3 लहसुन की कलियां, कटी हुई","2 टेबलस्पून चिपोटल पेस्ट या 2 सूखे चिपोटल मिर्च","1 टेबलस्पून जीरा पाउडर और 1 टेबलस्पून स्मोक्ड पापरिका","2 टेबलस्पून वेजिटेबल ऑयल","नमक और काली मिर्च"],"en":["500g beef mince (min. 20% fat)","400g canned red kidney beans, drained","400g canned chopped tomatoes","2 large onions, chopped","3 garlic cloves, minced","2 tbsp chipotle paste or 2 dried chipotle chillies, rehydrated","1 tbsp ground cumin and 1 tbsp smoked paprika","2 tbsp vegetable oil","salt and black pepper"],"ro":["500g carne de vită tocată (min. 20% grăsime)","400g fasole roșie kidney la conservă, scursă","400g roșii tocate la conservă","2 cepe mari, tocate","3 căței de usturoi, tocați","2 linguri pastă de chipotle sau 2 ardei iuți uscați","1 lingură chimen măcinat și 1 lingură boia afumată","2 linguri ulei vegetal","sare și piper negru"]},"howIsMade":{"hi":"एक बड़े बर्तन में तेज़ आंच पर तेल गर्म करें। कीमे को दो बैच में भूनें, अच्छे से तोड़ते हुए — छोटे कैरमलाइज़्ड टुकड़े चाहिए, कोई भूरा-सफेद गट्ठर नहीं। मांस निकालें और उसी तेल में प्याज को 8 मिनट भूनें। लहसुन, जीरा और स्मोक्ड पापरिका डालें, 1 मिनट हिलाएं। चिपोटल पेस्ट, टमाटर, बींस, भुना मांस और 200ml पानी डालें। उबाल लाएं, आंच कम करें, आधा ढकें और 45-60 मिनट पकाएं। बहुत पतला हो तो आखिरी 15 मिनट खुला पकाएं। नमक से स्वाद लें। खट्टी क्रीम, कद्दूकस चीज़, जलापेनो और ताज़े धनिए के साथ परोसें।","en":"Heat the oil in a large pot over high heat. Brown the mince in two batches, breaking it up well — you want small caramelised pieces, not a grey steamed mass. Remove the meat and in the same oil, saute the onion for 8 minutes. Add garlic, cumin and smoked paprika, stir for 1 minute. Add chipotle paste, canned tomatoes, drained beans, the browned meat and 200ml water. Bring to a boil, reduce to low, partially cover and simmer 45-60 minutes, stirring occasionally. Chili should be thick, not watery — uncover for the last 15 minutes if too thin. Taste and adjust salt. Serve in bowls with sour cream, grated cheddar, sliced jalapeños, fresh coriander and tortilla chips."}},{"id":37,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"hi":"चीन","en":"China","ro":"China"},"name":{"hi":"मीठी खट्टी चिकन","en":"Sweet and Sour Chicken","ro":"Pui dulce-acrișor"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["500 ग्राम चिकन ब्रेस्ट, 3 सेमी टुकड़ों में","1 टेबलस्पून कॉर्नस्टार्च (कोटिंग के लिए)","200g कैन्ड पाइनएप्पल, जूस बचाएं","1 लाल और 1 हरी शिमला मिर्च, टुकड़ों में","1 छोटा प्याज, टुकड़ों में","3 टेबलस्पून राइस विनेगर","2 टेबलस्पून चीनी, 2 टेबलस्पून सोया सॉस, 1 टेबलस्पून केचप","2 टेबलस्पून वेजिटेबल ऑयल और 1 चम्मच तिल का तेल"],"en":["500g chicken breast, cut into 3cm pieces","1 tbsp cornstarch (for coating)","200g canned pineapple chunks, juice reserved","1 red and 1 green bell pepper, diced","1 small onion, diced","3 tbsp rice vinegar","2 tbsp sugar, 2 tbsp soy sauce, 1 tbsp ketchup","2 tbsp vegetable oil plus 1 tsp sesame oil"],"ro":["500g piept de pui, tăiat cuburi de 3 cm","1 lingură amidon de porumb (pentru acoperire)","200g bucăți de ananas la conservă, sucul rezervat","1 ardei roșu și 1 ardei verde, tăiați cuburi","1 ceapă mică, tăiată cuburi","3 linguri oțet de orez","2 linguri zahăr, 2 linguri sos de soia, 1 lingură ketchup","2 linguri ulei vegetal plus 1 linguriță ulei de susan"]},"howIsMade":{"hi":"पहले सॉस बनाएं: राइस विनेगर, चीनी, सोया सॉस, केचप और 3 टेबलस्पून पाइनएप्पल का जूस मिलाएं। चिकन को कॉर्नस्टार्च में लपेटें और अतिरिक्त झटकें। वोक या बड़े पैन में तेज आंच पर तेल गर्म करें। चिकन को बैच में 4-5 मिनट सुनहरा और कुरकुरा होने तक भूनें। अलग रखें। उसी वोक में थोड़ा और तेल डालें, प्याज 2 मिनट भूनें, शिमला मिर्च डालें और 2 मिनट तेज आंच पर भूनें — कुरकुरा रहे। पाइनएप्पल डालें, सॉस डालें और 1-2 मिनट उबलने दें जब तक गाढ़ा और चमकदार न हो जाए। चिकन वापस डालें और सब मिलाएं। तिल का तेल डालें। तुरंत उबले चावल के साथ परोसें।","en":"Make the sauce first: mix rice vinegar, sugar, soy sauce, ketchup and 3 tbsp of the pineapple juice. Toss the chicken pieces in cornstarch and shake off excess. Heat vegetable oil in a wok or large skillet over high heat. Fry the chicken in batches for 4-5 minutes until crisp and golden — do not crowd the pan. Set aside. In the same wok, add a little more oil and stir-fry the onion 2 minutes, add the peppers and cook 2 more minutes on high — they should stay crisp. Add the pineapple, pour in the sauce and bubble for 1-2 minutes until thick and glossy. Return the chicken and toss everything together. Finish with sesame oil. Serve immediately over steamed rice."}},{"id":38,"servings":8,"tipType":"dessert","pairingsType":"dessert","origin":{"hi":"ऑस्ट्रेलिया","en":"Australia","ro":"Australia"},"name":{"hi":"पावलोवा","en":"Pavlova","ro":"Pavlova"},"category":{"hi":"मिठाई","en":"Dessert","ro":"Desert"},"ingredients":{"hi":["4 बड़े अंडे की सफेदी, कमरे के तापमान पर","220 ग्राम बारीक चीनी (कास्टर शुगर)","2 चम्मच कॉर्नस्टार्च","1 चम्मच सफेद वाइन सिरका","1 चम्मच वेनिला एक्सट्रैक्ट","300 मिली डबल क्रीम, फेंटने के लिए (न्यूनतम 35% वसा)","200 ग्राम ताजी स्ट्रॉबेरी, कटी हुई","2 पैशन फ्रूट, गूदा निकाला हुआ"],"en":["4 large egg whites, room temperature","220g caster sugar","2 tsp cornstarch","1 tsp white wine vinegar","1 tsp vanilla extract","300ml double cream, for whipping","200g fresh strawberries, sliced","2 passion fruits, pulp scooped"],"ro":["4 albușuri mari, la temperatura camerei","220g zahăr fin (caster sugar)","2 lingurițe amidon de porumb","1 linguriță oțet de vin alb","1 linguriță extract de vanilie","300ml smântână pentru frișcă (min. 35% grăsime)","200g căpșuni proaspete, feliate","2 fructe ale pasiunii, pulpă"]},"howIsMade":{"hi":"ओवन को 120°C पर प्रीहीट करें और बेकिंग पेपर पर 22 सेमी का घेरा बनाएं। अंडे की सफेदी में एक चुटकी नमक डालकर तब तक फेंटें जब तक नरम चोटियां न बन जाएं। कास्टर शुगर एक-एक चम्मच डालें और हर बार अच्छे से फेंटें — 8-10 मिनट लगेंगे जब तक मेरिंग्यू चमकदार, कड़ा और बिना चीनी के दाने का न हो जाए। कॉर्नस्टार्च, सिरका और वेनिला को स्पैटुला से धीरे से मिलाएं। मेरिंग्यू को घेरे पर रखें, किनारों को थोड़ा ऊंचा करें। 90 मिनट बेक करें — खोल सूखा और हल्के क्रीम रंग का हो जाना चाहिए। ओवन बंद करें और पावलोवा को दरवाजा थोड़ा खुला रखकर कम से कम 2 घंटे ओवन में ही ठंडा होने दें। परोसने से ठीक पहले क्रीम फेंटें और मेरिंग्यू पर फैलाएं। स्ट्रॉबेरी और पैशन फ्रूट के गूदे से सजाएं।","en":"Preheat oven to 120°C and trace a 22cm circle on baking paper. Whisk egg whites with a pinch of salt to soft peaks. Add caster sugar one tablespoon at a time, whisking well after each addition — takes 8-10 minutes until the meringue is glossy, stiff, and has no sugar grains when rubbed between fingers. Fold in cornstarch, vinegar, and vanilla with a spatula. Mound the meringue onto the paper circle, building the sides slightly higher than the centre. Bake 90 minutes — the shell should be dry and faintly cream-coloured. Turn off oven and leave the pavlova to cool completely inside with the door ajar, at least 2 hours. Just before serving, whip cream to soft peaks and spread over the meringue. Top with strawberries and passion fruit pulp."}},{"id":39,"servings":4,"tipType":"def","pairingsType":"def","origin":{"hi":"कनाडा","en":"Canada","ro":"Canada"},"name":{"hi":"पुटीन","en":"Poutine","ro":"Poutine"},"category":{"hi":"नाश्ता","en":"Snack","ro":"Gustare"},"ingredients":{"hi":["800 ग्राम Russet या Maris Piper आलू, छिले हुए","150 ग्राम ताजे पनीर के टुकड़े (cheese curds), कमरे के तापमान पर","2 बड़े चम्मच बिना नमक का मक्खन","2 बड़े चम्मच मैदा","500 मिली बीफ स्टॉक, गर्म","1 चम्मच वॉर्सेस्टरशायर सॉस","तलने के लिए वनस्पति तेल","नमक और काली मिर्च"],"en":["800g Russet or Maris Piper potatoes, peeled","150g fresh cheese curds, room temperature","2 tbsp unsalted butter","2 tbsp plain flour","500ml beef stock, hot","1 tsp Worcestershire sauce","vegetable oil for frying","salt and black pepper"],"ro":["800g cartofi Russet sau Desiree, curatati","150g cas proaspat (cheese curds), la temperatura camerei","2 linguri unt nesarat","2 linguri făină alba","500ml supa de vita, fierbinte","1 lingurita sos Worcestershire","ulei vegetal pentru prajit","sare si piper negru"]},"howIsMade":{"hi":"आलू को 1 सेमी मोटे बैटन में काटें और 30 मिनट ठंडे पानी में भिगोएं ताकि स्टार्च निकल जाए — यही उन्हें कुरकुरा बनाता है। अच्छी तरह सुखाएं। पहली बार तलना: तेल को 150°C पर गर्म करें और 5-6 मिनट तलें जब तक पक जाएं पर रंग न आए। निकालें और 10 मिनट आराम दें। दूसरी बार तलना: 190°C पर 3-4 मिनट जब तक सुनहरे और बहुत कुरकुरे न हों। तुरंत नमक डालें। ग्रेवी के लिए: मध्यम आंच पर मक्खन पिघलाएं, मैदा डालें और 2 मिनट हिलाते हुए पकाएं। धीरे-धीरे गर्म स्टॉक डालें और लगातार फेंटते हुए 3-4 मिनट में गाढ़ा करें। वॉर्सेस्टरशायर सॉस और मसाले डालें। गर्म आलू को एक गहरे कटोरे में रखें, कमरे के तापमान पर पनीर के टुकड़े बिखेरें और तुरंत गर्म ग्रेवी डालें।","en":"Cut potatoes into 1cm batons and soak in cold water for 30 minutes to remove starch — this is what makes them crispy. Dry thoroughly. First fry: heat oil to 150°C and fry potatoes 5-6 minutes until cooked through but without colour. Drain and rest 10 minutes. Second fry: heat oil to 190°C and fry 3-4 minutes until golden and very crispy. Season immediately with salt. For the gravy: melt butter over medium heat, add flour and cook 2 minutes stirring — it should turn pale golden. Add hot stock gradually, whisking constantly until thickened, 3-4 minutes. Add Worcestershire, season. Pile hot fries into a deep bowl, scatter room-temperature cheese curds over, and immediately pour the hot gravy on top — the heat partially melts the curds while keeping their signature squeak."}},{"id":40,"servings":4,"tipType":"def","pairingsType":"def","origin":{"hi":"पोलैंड","en":"Poland","ro":"Polonia"},"name":{"hi":"पिएरोगी","en":"Pierogi","ro":"Pierogi"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cina"},"ingredients":{"hi":["300 ग्राम मैदा, छानने के लिए थोड़ा अतिरिक्त","1 बड़ा अंडा और 150 मिली गर्म पानी (आटे के लिए)","500 ग्राम आलू, उबालकर मैश किए हुए","200 ग्राम ताजा पनीर (twaróg) या सूखा पनीर","2 मध्यम प्याज, बारीक कटे हुए","40 ग्राम बिना नमक का मक्खन","100 ग्राम स्मोक्ड बेकन के टुकड़े","नमक, सफेद मिर्च और ताजी चाइव्स परोसने के लिए"],"en":["300g plain flour, plus extra for dusting","1 large egg plus 150ml warm water (for dough)","500g floury potatoes, boiled and mashed","200g farmer's cheese (twarog) or dry cottage cheese","2 medium onions, finely diced","40g unsalted butter","100g smoked bacon lardons","salt, white pepper and fresh chives to serve"],"ro":["300g făină alba, plus extra pentru intins","1 ou mare plus 150ml apa calda (pentru aluat)","500g cartofi fainosi, fierti si zdrobiti","200g branza de vaci (twarog) sau branza proaspata","2 cepe medii, taiate marunt","40g unt nesarat","100g bacon afumat, taiat cubulete","sare, piper alb si ceapa verde proaspata pentru servit"]},"howIsMade":{"hi":"मैदे को अंडे और गर्म पानी के साथ मिलाएं, 5 मिनट गूंधें जब तक चिकना और लोचदार आटा न बन जाए, ढककर 30 मिनट आराम दें। आलू को नरम होने तक उबालें, पनीर, नमक और सफेद मिर्च के साथ मैश करें। एक पैन में आधी प्याज को मक्खन में सुनहरा होने तक भूनें (10 मिनट), भरावन में मिलाएं। आटा 3mm मोटा बेलें, 8cm के गोल काटें। हर गोले पर एक चम्मच भरावन रखें, आधा मोड़ें और किनारों को मजबूती से दबाकर बंद करें। नमकीन पानी में 3-4 मिनट उबालें — ऊपर तैरने लगें तो पक गए। इसी दौरान बेकन को कुरकुरा होने तक भूनें, बाकी प्याज डालें और भूनें। उबले पिएरोगी को मक्खन में हर तरफ 2-3 मिनट सुनहरे होने तक भूनें। बेकन, भुनी प्याज और खट्टी क्रीम के साथ परोसें।","en":"Mix flour with egg and warm water, knead 5 minutes to a smooth, elastic dough, cover and rest 30 minutes. Boil potatoes until tender, mash with farmer's cheese, salt and white pepper. In a pan, fry half the onion in butter until golden (10 min), stir into filling. Roll dough to 3mm, cut 8cm circles. Place a teaspoon of filling on each disc, fold in half and seal the edges firmly by pressing with fingers or a fork. Boil in salted water 3-4 minutes — they float when done. Meanwhile, fry bacon until crisp, add remaining onion and brown. Pan-fry the boiled pierogi in butter 2-3 minutes per side until golden patches appear. Serve with bacon, fried onion and sour cream."}},{"id":41,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"hi":"इंडोनेशिया","en":"Indonesia","ro":"Indonezia"},"name":{"hi":"नासी गोरेंग","en":"Nasi Goreng","ro":"Nasi Goreng"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"hi":["4 कप एक दिन पुराने पके jasmine चावल","300 ग्राम बोनलेस चिकन थाई, 1 सेमी क्यूब में कटी","4 अंडे","4 shallots, पतले कटे","4 लहसुन की कलियाँ, कीमा की हुई","2 लाल bird's eye मिर्चें, पतली कटी","2 बड़े चम्मच kecap manis (मीठी सोया सॉस)","1 बड़ा चम्मच सोया सॉस","1 छोटा चम्मच झींगा पेस्ट (terasi), भुना","3 बड़े चम्मच वनस्पति तेल","नमक और सफ़ेद मिर्च स्वादानुसार","परोसने के लिए खीरे की कतरन और तले shallots"],"en":["4 cups day-old cooked jasmine rice","300 g boneless chicken thigh, cut into 1 cm cubes","4 eggs","4 shallots, thinly sliced","4 garlic cloves, minced","2 red bird's eye chillies, thinly sliced","2 tbsp kecap manis (sweet soy sauce)","1 tbsp soy sauce","1 tsp shrimp paste (terasi), toasted","3 tbsp vegetable oil","salt and white pepper to taste","cucumber slices and fried shallots to serve"],"ro":["4 căni orez jasmin fiert în ziua precedentă","300 g pulpă de pui dezosată, tăiată cubulețe de 1 cm","4 ouă","4 eșalote, feliate subțire","4 căței de usturoi, tocați","2 ardei iuți roșii, feliați subțire","2 linguri kecap manis (sos de soia dulce)","1 lingură sos de soia","1 linguriță pastă de creveți (terasi), prăjită","3 linguri ulei vegetal","sare și piper alb după gust","felii de castravete și eșalote prăjite pentru servire"]},"howIsMade":{"hi":"ठंडे चावल को हाथों से तोड़ें ताकि कोई गाँठ अलग हो जाए। एक wok में तेज़ आँच पर 1 बड़ा चम्मच तेल धुआँ उठने तक गरम करें। चिकन के क्यूब डालें और 3–4 मिनट तक stir-fry करें जब तक पक जाएं और हल्के सुनहरे हो जाएं; निकाल कर रखें। wok में बचा 2 बड़े चम्मच तेल डालें। shallots डालें और 2 मिनट stir-fry करें जब तक नरम हो जाएं। लहसुन, मिर्च और झींगा पेस्ट डालें और 1 मिनट stir-fry करें जब तक ख़ुशबू उठे। चावल डालें, एक समतल परत में फैलाएं, और 1 मिनट के लिए बिना छेड़े छोड़ दें ताकि हल्का crust बने, फिर 2–3 मिनट तक ज़ोर से उछालें। चिकन वापस डालें, kecap manis और सोया सॉस डालें, और बराबर coat होने तक उछालें। नमक और सफ़ेद मिर्च से स्वाद दें। चावल को एक ओर सरकाएं, अंडे फोड़ें, थोड़ा scramble करें, फिर चावल में मोड़ कर 1 मिनट पकाएं जब तक बस set हो जाएं। कटोरों में परोसें, ऊपर खीरे की कतरन और तले shallots।","en":"Break up the cold rice with your hands to separate any clumps. Heat 1 tbsp of oil in a wok over high heat until smoking. Add the chicken cubes and stir-fry for 3–4 minutes until cooked through and lightly golden; remove and set aside. Add the remaining 2 tbsp of oil to the wok. Add the shallots and stir-fry for 2 minutes until softened. Add the garlic, chilli, and shrimp paste and stir-fry for 1 minute until fragrant. Add the rice, spread into an even layer, and leave untouched for 1 minute to form a slight crust, then toss vigorously for 2–3 minutes. Return the chicken, add the kecap manis and soy sauce, and toss to coat evenly. Season with salt and white pepper. Push the rice to the side, crack in the eggs, scramble briefly, then fold into the rice and cook for 1 minute until just set. Serve in bowls topped with cucumber slices and fried shallots."}},{"id":42,"servings":4,"tipType":"def","pairingsType":"def","origin":{"hi":"स्विट्ज़रलैंड","en":"Switzerland","ro":"Elveția"},"name":{"hi":"फॉन्ड्यू","en":"Fondue","ro":"Fondue"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"hi":["400 ग्राम Gruyère, मोटा कद्दूकस","200 ग्राम Emmental, मोटा कद्दूकस","1 लहसुन की कली, आधी कटी","300 मिली ड्राई वाइट वाइन (Fendant या Chasselas)","1 बड़ा चम्मच कॉर्नस्टार्च","2 बड़े चम्मच kirsch (चेरी ब्रांडी)","एक चुटकी ताज़ा कद्दूकस किया जायफल","ताज़ी पिसी काली मिर्च स्वादानुसार","1 बड़ी crusty baguette (लगभग 500 ग्राम), 2 सेमी क्यूब में कटी","परोसने के लिए cornichons और उबले नए आलू"],"en":["400 g Gruyère, coarsely grated","200 g Emmental, coarsely grated","1 garlic clove, halved","300 ml dry white wine (Fendant or Chasselas)","1 tbsp cornstarch","2 tbsp kirsch (cherry brandy)","a pinch of freshly grated nutmeg","freshly ground black pepper to taste","1 large crusty baguette (about 500 g), cut into 2 cm cubes","cornichons and boiled new potatoes to serve"],"ro":["400 g Gruyère, ras grosier","200 g Emmental, ras grosier","1 cățel de usturoi, tăiat pe jumătate","300 ml vin alb sec (Fendant sau Chasselas)","1 lingură amidon de porumb","2 linguri kirsch (rachiu de cireșe)","un praf de nucșoară rasă proaspăt","piper negru proaspăt măcinat după gust","1 baghetă mare crocantă (cca. 500 g), tăiată cubulețe de 2 cm","cornișoni și cartofi noi fierți pentru servire"]},"howIsMade":{"hi":"fondue बर्तन के अंदर लहसुन की कटी सतह से रगड़ें; लहसुन फेंक दें। बर्तन में वाइन डालें और मध्यम आँच पर तब तक गरम करें जब तक उबाल से ठीक नीचे रहे। कद्दूकस किए Gruyère और Emmental को कॉर्नस्टार्च के साथ तब तक मिलाएं जब तक बराबर coat हो जाए। पनीर को गरम वाइन में तीन बार में डालें, हर बार figure-eight गति में चलाएं जब तक पूरी तरह पिघल कर चिकना हो जाए, कुल लगभग 8–10 मिनट। kirsch, जायफल और काली मिर्च का घुमाव मिलाएं; fondue इतना गाढ़ा होना चाहिए कि चम्मच पर coat कर ले। बर्तन को fondue burner पर रखें जो हल्की आँच पर हो ताकि वह धीरे-धीरे bubble करता रहे। ब्रेड के क्यूब को fondue काँटों पर लगाएं और पनीर में घुमाएं, बर्तन के तले तक पहुँचें ताकि crust न बने। cornichons और उबले नए आलू के साथ परोसें।","en":"Rub the inside of a fondue pot with the cut sides of the garlic clove; discard the garlic. Pour the wine into the pot and heat over medium heat until just below simmering. Toss the grated Gruyère and Emmental with the cornstarch until evenly coated. Add the cheese to the warm wine in three batches, stirring in a figure-eight motion after each addition until fully melted and smooth, about 8–10 minutes total. Stir in the kirsch, nutmeg, and a grind of black pepper; the fondue should be thick enough to coat a spoon. Place the pot over a fondue burner set to low to keep it gently bubbling. Spear bread cubes on fondue forks and swirl into the cheese, reaching the bottom of the pot to prevent a crust from forming. Serve with cornichons and boiled new potatoes."}},{"id":43,"servings":4,"tipType":"fish","pairingsType":"middle-eastern","origin":{"hi":"इराक","en":"Iraq","ro":"Irak"},"name":{"hi":"मसगौफ","en":"Masgouf","ro":"Masgouf"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"hi":["1 साबुत carp या sea bass (लगभग 1.5 किलो), पेट साफ़ की हुई","4 बड़े चम्मच olive oil","1 छोटा चम्मच नमक","1 छोटा चम्मच हल्दी पाउडर","1 छोटा चम्मच जीरा पाउडर","2 टमाटर, मोटे कटे","1 नींबू, कटा","4 लहसुन की कलियाँ, कीमा की हुई","1 छोटी प्याज़, मोटी कटी","2 बड़े चम्मच टमाटर पेस्ट","ताज़ी पिसी काली मिर्च स्वादानुसार","परोसने के लिए 4 flatbreads","परोसने के लिए कटी प्याज़, टमाटर और अचार"],"en":["1 whole carp or sea bass (about 1.5 kg), gutted and cleaned","4 tbsp olive oil","1 tsp salt","1 tsp ground turmeric","1 tsp ground cumin","2 tomatoes, roughly chopped","1 lemon, sliced","4 garlic cloves, minced","1 small onion, roughly chopped","2 tbsp tomato paste","freshly ground black pepper to taste","4 flatbreads to serve","sliced onion, tomato, and pickles to serve"],"ro":["1 crap sau biban întreg (cca. 1,5 kg), curățat și eviscerat","4 linguri ulei de măsline","1 linguriță sare","1 linguriță turmeric măcinat","1 linguriță chimen măcinat","2 roșii, tăiate grosier","1 lămâie, feliată","4 căței de usturoi, tocați","1 ceapă mică, tocată grosier","2 linguri pastă de roșii","piper negru proaspăt măcinat după gust","4 pâini plate pentru servire","ceapă feliată, roșii și murături pentru servire"]},"howIsMade":{"hi":"एक तेज़ चाकू से रीढ़ की हड्डी के साथ गहरा चीरा लगाएं ताकि मछली खुली सपाट हो जाए (butterfly)। मांस पर हर 4 सेमी पर तिरछा निशान लगाएं। Olive oil, हल्दी, जीरा, नमक और काली मिर्च मिलाएं; मांस और गुहा के अंदर अच्छी तरह रगड़ें। कमरे के तापमान पर 20 मिनट के लिए मैरीनेट होने दें। इस बीच, टमाटर, प्याज़, लहसुन, नींबू की स्लाइस और टमाटर पेस्ट मिलाकर basting सॉस बनाएं। मछली को दो लंबे skewers पर पिरोएं (या मछली grill टोकरी का उपयोग करें) ताकि वह सपाट रहे। चमकते लकड़ी के अंगारों या कोयले पर grill करें (खुली लौ पर नहीं) 30–40 मिनट तक: पहले 20 मिनट मांस की ओर नीचे जब तक मांस अपारदर्शी हो जाए और हड्डी से अलग होने लगे, फिर त्वचा की ओर 10–15 मिनट जब तक त्वचा कुरकुरी हो जाए। हर 5 मिनट पर सॉस से baste करें। तुरंत flatbread, कटी प्याज़, टमाटर और अचार के साथ परोसें।","en":"Using a sharp knife, make a deep cut along the backbone to butterfly the fish open flat. Score the flesh diagonally every 4 cm. Mix the olive oil, turmeric, cumin, salt, and pepper; rub all over the flesh and inside the cavity. Leave to marinate for 20 minutes at room temperature. Meanwhile, combine the tomatoes, onion, garlic, lemon slices, and tomato paste to make the basting sauce. Thread the fish onto two long skewers (or use a fish grill basket) to hold it flat. Grill over glowing wood embers or charcoal (not open flames) for 30–40 minutes: flesh side down for the first 20 minutes until the flesh is opaque and pulls away from the bone, then skin side down for 10–15 minutes until the skin is crisp. Baste with the sauce every 5 minutes. Serve immediately with flatbread, sliced onion, tomato, and pickles."}},{"id":44,"servings":4,"tipType":"def","pairingsType":"middle-eastern","origin":{"hi":"इज़राइल","en":"Israel","ro":"Israel"},"name":{"hi":"शक्शुका","en":"Shakshuka","ro":"Shakshuka"},"category":{"en":"Breakfast","ro":"Mic dejun"},"ingredients":{"hi":["2 बड़े चम्मच olive oil","1 बड़ी प्याज़, बारीक कटी","1 लाल शिमला मिर्च, बारीक कटी","4 लहसुन की कलियाँ, कीमा की हुई","1 छोटा चम्मच जीरा पाउडर","1 छोटा चम्मच मीठी paprika","½ छोटा चम्मच smoked paprika","¼ छोटा चम्मच मिर्च के फ्लेक्स","2 × 400 ग्राम डब्बाबंद कुटे टमाटर","1 छोटा चम्मच चीनी","नमक और ताज़ी पिसी काली मिर्च स्वादानुसार","6 अंडे","ताज़े flat-leaf अजमोद या धनिए की एक छोटी मुट्ठी, मोटी कटी","परोसने के लिए crusty ब्रेड या pita"],"en":["2 tbsp olive oil","1 large onion, finely diced","1 red bell pepper, finely diced","4 garlic cloves, minced","1 tsp ground cumin","1 tsp sweet paprika","½ tsp smoked paprika","¼ tsp chilli flakes","2 x 400 g cans crushed tomatoes","1 tsp sugar","salt and freshly ground black pepper to taste","6 eggs","a small handful of fresh flat-leaf parsley or coriander, roughly chopped","crusty bread or pita to serve"],"ro":["2 linguri ulei de măsline","1 ceapă mare, tăiată mărunt","1 ardei kapia roșu, tăiat mărunt","4 căței de usturoi, tocați","1 linguriță chimen măcinat","1 linguriță boia dulce","½ linguriță boia afumată","¼ linguriță fulgi de ardei iute","2 x 400 g roșii zdrobite la conservă","1 linguriță zahăr","sare și piper negru proaspăt măcinat după gust","6 ouă","o mână de frunze de pătrunjel sau coriandru, tocate grosier","pâine crocantă sau pita pentru servire"]},"howIsMade":{"hi":"मध्यम आँच पर एक चौड़े, गहरे फ्राइंग पैन में olive oil गरम करें। प्याज़ और लाल शिमला मिर्च डालें और बीच-बीच में चलाते हुए 8 मिनट तक पकाएं जब तक नरम हो जाएं और रंग पकड़ने लगें। लहसुन, जीरा, मीठी paprika, smoked paprika और मिर्च के फ्लेक्स डालें और 1 मिनट चलाएं जब तक ख़ुशबू उठे। कुटे टमाटर डालें, चीनी मिलाएं, और नमक तथा काली मिर्च से उदारता से स्वाद दें। 10 मिनट तक धीमी आँच पर पकाएं, बीच-बीच में चलाते रहें, जब तक सॉस गाढ़ा हो जाए और रंग गहरा हो जाए। चम्मच से सॉस में 6 गड्ढे बनाएं। हर गड्ढे में एक अंडा फोड़ें, फिर पैन को ढक्कन से ढक दें और 8–10 मिनट तक पकाएं जब तक सफ़ेदी बस set हो जाए पर जर्दी बहती रहे। ऊपर अजमोद या धनिया छिड़कें और तुरंत पैन से crusty ब्रेड या pita के साथ परोसें।","en":"Heat the olive oil in a wide, deep frying pan over medium heat. Add the onion and red pepper and cook, stirring occasionally, for 8 minutes until softened and beginning to colour. Add the garlic, cumin, sweet paprika, smoked paprika, and chilli flakes and stir for 1 minute until fragrant. Pour in the crushed tomatoes, add the sugar, and season generously with salt and pepper. Simmer for 10 minutes, stirring occasionally, until the sauce thickens and deepens in colour. Make 6 wells in the sauce with a spoon. Crack one egg into each well, then cover the pan with a lid and cook for 8–10 minutes until the whites are just set but the yolks are still runny. Scatter the parsley or coriander over the top and serve immediately from the pan with crusty bread or pita."}},{"id":45,"servings":4,"tipType":"soup","pairingsType":"soup","origin":{"hi":"फ़िनलैंड","en":"Finland","ro":"Finlanda"},"name":{"hi":"सैल्मन सूप","en":"Salmon Soup","ro":"Lohikeitto"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"hi":["600 ग्राम ताजा सालमन फिलेट, बिना त्वचा, 3 सेमी के टुकड़ों में","500 ग्राम मजबूत आलू (शार्लट या समकक्ष), छिले और 2 सेमी के क्यूब्स में","1 बड़ा लीक, सफेद और हल्का हरा हिस्सा, पतले छल्लों में काटा हुआ","2 मध्यम आकार की गाजर, छिली और 5 मिमी मोटे गोल टुकड़ों में","1 लीटर अच्छी गुणवत्ता का फिश स्टॉक","200 मिली डबल क्रीम","1 तेज पत्ता","5 साबुत ऑलस्पाइस के दाने","1 छोटा चम्मच बारीक नमक, स्वाद अनुसार","¼ छोटा चम्मच पिसी सफेद मिर्च","1 बड़ा गुच्छा ताजा डिल (लगभग 30 ग्राम), मोटा कटा हुआ"],"en":["600 g fresh salmon fillet, skin removed, cut into 3 cm chunks","500 g waxy potatoes (Charlotte or similar), peeled and cut into 2 cm cubes","1 large leek, white and pale-green parts, thinly sliced into rings","2 medium carrots, peeled and sliced 5 mm thick","1 litre good-quality fish stock","200 ml double cream","1 bay leaf","5 whole allspice berries","1 tsp fine sea salt, plus more to taste","¼ tsp ground white pepper","1 large bunch fresh dill (about 30 g), roughly chopped"],"ro":["600 g file de somon proaspăt, fără piele, tăiat cuburi de 3 cm","500 g cartofi cu pulpă fermă (Charlotte sau similari), curățați, cuburi de 2 cm","1 praz mare, partea albă și verde deschis, tăiat rondele subțiri","2 morcovi medii, curățați, rondele de 5 mm","1 litru supă de pește bine aromatizată","200 ml smântână dulce pentru gătit","1 frunză de dafin","5 boabe de ienibahar","1 linguriță sare fină, plus după gust","¼ linguriță piper alb măcinat","1 mănunchi mare de mărar proaspăt (cca 30 g), tocat grosier"]},"howIsMade":{"hi":"एक बड़े बर्तन में फिश स्टॉक डालें और मध्यम आंच पर धीरे-धीरे उबाल आने दें। आलू, गाजर, लीक, तेज पत्ता और ऑलस्पाइस के दाने डालें। धीमी आंच पर 12–15 मिनट पकाएं जब तक आलू चाकू से छेद करने पर बस नरम हो जाएं। आंच को न्यूनतम कर दें — स्टॉक बस हल्का कंपन करे, उबले नहीं। सालमन के टुकड़े डालें और 4–5 मिनट पकाएं जब तक मछली बस अपारदर्शी हो जाए और हल्के दबाव पर आसानी से फट जाए। क्रीम मिलाएं और 2 मिनट बिना उबाले गर्म करें। नमक और सफेद मिर्च से स्वाद लें। तेज पत्ता और ऑलस्पाइस के दाने निकाल दें। गर्म कटोरों में परोसें और हर हिस्से पर भरपूर ताजा डिल डालें। डार्क राई ब्रेड के साथ परोसें।","en":"Pour the fish stock into a large pot and bring to a gentle simmer over medium heat. Add the potatoes, carrots, leek, bay leaf, and allspice berries. Cook at a gentle simmer for 12–15 minutes until the potatoes are just tender when pierced with a knife. Lower the heat so the stock barely trembles — do not boil. Add the salmon chunks and cook for 4–5 minutes until the fish is just opaque and flakes easily when nudged. Stir in the cream and heat for 2 minutes without letting it boil. Season with salt and white pepper. Remove the bay leaf and allspice berries. Ladle into warmed bowls and heap each portion with a generous amount of fresh dill. Serve with dark rye bread alongside."}},{"id":46,"servings":4,"tipType":"meat","timeMins":{"total":300,"active":60},"pairingsType":"middle-eastern","origin":{"hi":"ईरान","en":"Iran","ro":"Iran"},"name":{"hi":"घोरमे सब्ज़ी","en":"Ghormeh Sabzi","ro":"Ghormeh Sabzi"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"hi":["700 ग्राम बोनलेस मटन (कंधे की बोटी) या स्टू के लिए बीफ, 4 सेमी के टुकड़ों में","200 ग्राम सूखे राजमा, रातभर भिगोए और निथारे (या 400 ग्राम डिब्बाबंद, निथारे)","1 बड़ा प्याज, बारीक कटा हुआ","80 ग्राम ताजी मेथी के पत्ते (या 3 बड़े चम्मच सूखी मेथी / कसूरी मेथी)","100 ग्राम ताजा फ्लैट-लीफ पार्सले, बारीक कटा हुआ","80 ग्राम ताजा धनिया, बारीक कटा हुआ","50 ग्राम ताजा पालक, बारीक कटा हुआ","4 सूखे फारसी नींबू (लिमू अमानी), कांटे से छेद किए हुए","1 छोटा चम्मच हल्दी पाउडर","½ छोटा चम्मच काली मिर्च पाउडर","1 छोटा चम्मच बारीक नमक, स्वाद अनुसार","3 बड़े चम्मच वनस्पति तेल, अलग-अलग"],"en":["700 g boneless lamb shoulder (or beef chuck), cut into 4 cm cubes","200 g dried red kidney beans, soaked overnight and drained (or 400 g canned, drained)","1 large onion, finely diced","80 g fresh fenugreek leaves (or 3 tbsp dried fenugreek / kasuri methi)","100 g fresh flat-leaf parsley, finely chopped","80 g fresh coriander (cilantro), finely chopped","50 g fresh spinach, finely chopped","4 dried Persian limes (limoo amani), pierced with a skewer","1 tsp ground turmeric","½ tsp ground black pepper","1 tsp fine sea salt, plus more to taste","3 tbsp vegetable oil, divided"],"ro":["700 g carne de miel fără os (spată) sau vită pentru tocăniță, tăiată cuburi de 4 cm","200 g fasole boabe roșie uscată, hidratată peste noapte și scursă (sau 400 g la conservă, scursă)","1 ceapă mare, tăiată mărunt","80 g frunze proaspete de schinduf (sau 3 linguri schinduf uscat / kasoori methi)","100 g pătrunjel frunze plate proaspăt, tocat mărunt","80 g coriandru proaspăt, tocat mărunt","50 g spanac proaspăt, tocat mărunt","4 lămâi persane uscate (limoo amani), înțepate cu un frigărui","1 linguriță turmeric măcinat","½ linguriță piper negru măcinat","1 linguriță sare fină, plus după gust","3 linguri ulei vegetal, separat"]},"howIsMade":{"hi":"एक बड़े भारी बर्तन में मध्यम-तेज आंच पर 1 बड़ा चम्मच तेल गर्म करें; मांस को दो बैच में 3–4 मिनट प्रति बैच, सभी तरफ से गहरे भूरे रंग तक भूनें. निकालें और अलग रखें; उसी बर्तन में मध्यम आंच पर प्याज 8 मिनट सुनहरा होने तक पकाएं. हल्दी और काली मिर्च डालें; 1 मिनट चलाएं; मांस वापस डालें, निथारे हुए राजमा और छेद किए नींबू डालें. बस ढकने भर पानी डालें; उबाल आने दें, झाग हटाएं, फिर सबसे धीमी आंच पर कर दें. इस बीच बचे हुए तेल में एक बड़े पैन को तेज आंच पर गर्म करें; सभी जड़ी-बूटियां (मेथी, पार्सले, धनिया, पालक) डालकर 15–20 मिनट लगातार चलाते हुए गहरे हरे रंग तक और सारी नमी उड़ने तक भूनें — यह कदम व्यंजन का विशिष्ट गहरा स्वाद बनाता है. भुनी जड़ी-बूटियां स्टू में मिलाएं; नमक से स्वाद लें. ढककर न्यूनतम आंच पर 2–2.5 घंटे (सूखे राजमा) या 1.5 घंटे (डिब्बाबंद) पकाएं, बीच-बीच में चलाते हुए, जब तक मांस बहुत नरम न हो जाए; उबले बासमती चावल पर परोसें.","en":"Heat 1 tbsp oil in a large heavy pot over medium-high heat; brown the meat in two batches, 3–4 minutes per batch, until deep brown on all sides. Remove and set aside; in the same pot, cook the onion over medium heat for 8 minutes until golden. Add the turmeric and black pepper; stir for 1 minute; return the meat to the pot. Add the drained kidney beans and pierced dried limes; pour over just enough water to barely cover. Bring to the boil, skim the foam, then reduce to the lowest possible simmer; meanwhile, heat the remaining 2 tbsp oil in a large frying pan over medium-high heat. Add all the herbs (fenugreek, parsley, coriander, spinach) and stir-fry for 15–20 minutes, until the herbs turn very dark green and all moisture has fully evaporated — this step is critical and builds the stew's characteristic deep flavour; stir the fried herbs into the stew. Season with salt; cover and simmer on the lowest heat for 2–2.5 hours (if using dried beans) or 1.5 hours (canned beans), stirring occasionally, until the meat is very tender and pulls apart easily. The stew should be thick and deeply coloured; serve over steamed basmati rice."}},{"id":47,"servings":4,"tipType":"fish","pairingsType":"fish","origin":{"hi":"पुर्तगाल","en":"Portugal","ro":"Portugalia"},"name":{"hi":"बकालहाव अ ब्रास","en":"Bacalhau à Brás","ro":"Bacalhau à Brás"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"hi":["500 ग्राम नमकीन कॉड, 24–48 घंटे ठंडे पानी में भिगोकर टुकड़ों में तोड़ा हुआ","600 ग्राम मोमी आलू, छीलकर बहुत पतली माचिस जैसी पट्टियों में कटे","6 बड़े अंडे, हल्के फेंटे हुए","2 मध्यम सफेद प्याज़, पतले स्लाइस","4 बड़े चम्मच एक्स्ट्रा-वर्जिन ज़ैतून का तेल","3 लहसुन की कलियां, पतले स्लाइस","ताज़े पार्सले का छोटा गुच्छा, मोटा कटा","80 ग्राम बीज निकाले काले जैतून","स्वाद अनुसार नमक और सफेद मिर्च"],"en":["500g salted cod (bacalhau), soaked 24–48h in cold water and shredded into flakes","600g waxy potatoes, peeled and cut into very thin matchstick strips","6 large eggs, lightly beaten","2 medium white onions, thinly sliced","4 tbsp extra-virgin olive oil","3 garlic cloves, thinly sliced","Small bunch of fresh flat-leaf parsley, roughly chopped","80g black olives, pitted, to serve","Salt and white pepper to taste"],"ro":["500g cod sărat (bacalhau), înmuiat 24–48h și desfăcut în fâșii","600g cartofi cerați, curățați și tăiați în bețișoare foarte subțiri","6 ouă mari, ușor bătute","2 cepe medii albe, tăiate felii subțiri","4 linguri ulei de măsline extravirgin","3 căței de usturoi, tăiați felii subțiri","Legătură mică de pătrunjel proaspăt, tocat grosier","80g măsline negre, fără sâmburi","Sare și piper alb"]},"howIsMade":{"hi":"कटी हुई कॉड को ठंडे पानी में भिगोएं, 24–48 घंटों में चार बार पानी बदलते हुए, जब तक एक छोटा टुकड़ा सुखद नमकीन न लगे; पानी निकाल कर सुखाएं. आलू को बहुत पतली माचिस जैसी पट्टियों में काटें; एक गहरे फ्राइंग पैन में 2 सेमी न्यूट्रल तेल 170°C तक गर्म करें और आलू की पट्टियां बैचों में 3–4 मिनट फ्राई करें जब तक हल्की सुनहरी न हो जाएं. किचन पेपर पर निकालें, तेल फेंक दें; पैन पोंछें. मध्यम-कम आंच पर ज़ैतून का तेल गर्म करें, प्याज़ और लहसुन बार-बार हिलाते हुए 12–15 मिनट तक पकाएं; कॉड के टुकड़े डालें और 2 मिनट हिलाएं. आलू की पट्टियां डालें और धीरे से मिलाएं; सफ़ेद मिर्च से मसाला किया हुआ फेंटा अंडा डालें. धीमी आंच पर लगातार चौड़े धीमे मोड़ों में 2–3 मिनट हिलाएं — अंडा नरम, मलाईदार परतें बनाए; जब अंडा थोड़ा कच्चा लगे तब आंच से उतारें. नमक चखें; पार्सले छिड़कें और काले जैतून के साथ परोसें.","en":"Soak the shredded cod in cold water, changing the water four times over 24–48 hours until a small piece tastes pleasantly savoury rather than sharp; drain and pat dry. Cut potatoes into very thin matchstick strips; heat 2cm of neutral oil in a deep frying pan to 170°C and fry the potato strips in batches for 3–4 minutes until pale golden; drain on paper. Discard the frying oil and wipe the pan; heat olive oil over medium-low heat and cook the onion and garlic, stirring often, for 12–15 minutes until very soft and lightly golden. Add the cod flakes and stir for 2 minutes until warmed through; tip in the potato strips and toss once. Pour in the beaten eggs seasoned with white pepper; stir continuously over low heat with slow, wide folds for 2–3 minutes — the eggs should set in soft, creamy layers, never dry or granular. Remove from heat while the eggs still look slightly underdone; residual heat finishes the dish; taste for salt before adding any — the cod may already hold enough; scatter with parsley and serve straight from the pan with black olives alongside."}},{"id":48,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"hi":"फिलीपींस","en":"Philippines","ro":"Filipine"},"name":{"hi":"अडोबो","en":"Adobo","ro":"Adobo"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"hi":["1.2 किलो बोन-इन स्किन-ऑन चिकन जांघ और ड्रमस्टिक (या 4 सेमी टुकड़ों में कटा 1 किलो पोर्क बेली)","6 लहसुन की कलियां, कुचली हुई","125 मिली गन्ने का सिरका या सफेद वाइन सिरका","80 मिली सोया सॉस","3 तेज पत्ते","1 छोटा चम्मच साबुत काली मिर्च","80 मिली पानी","2 बड़े चम्मच वनस्पति तेल"],"en":["1.2 kg chicken thighs and drumsticks, bone-in skin-on (or 1 kg pork belly cut into 4 cm cubes)","6 garlic cloves, crushed","125 ml cane vinegar or white wine vinegar","80 ml soy sauce","3 bay leaves","1 tsp whole black peppercorns","80 ml water","2 tbsp vegetable oil"],"ro":["1,2 kg pulpe și tobe de pui (cu os, cu piele) sau 1 kg burtă de porc tăiată cuburi de 4 cm","6 căței de usturoi, zdrobiți","125 ml oțet de trestie sau oțet alb de vin","80 ml sos de soia","3 frunze de dafin","1 linguriță boabe de piper negru","80 ml apă","2 linguri ulei vegetal"]},"howIsMade":{"hi":"एक बड़े बर्तन में चिकन (या पोर्क), लहसुन, सिरका, सोया सॉस, तेज पत्ते, काली मिर्च और पानी मिलाएं। कमरे के तापमान पर 30 मिनट मैरिनेट करें। बिना चलाए मध्यम-तेज आंच पर उबाल आने दें। उबाल आने के बाद आंच धीमी करें, ढककर 30 मिनट (चिकन) या 45 मिनट (पोर्क) तक पकाएं जब तक मांस नरम हो जाए। ढक्कन हटाएं और आंच मध्यम करें। मांस को कभी-कभी पलटते हुए 15–20 मिनट और पकाएं जब तक सॉस गाढ़ा चमकदार ग्लेज न बन जाए जो चम्मच की पीठ पर टिके। अलग पैन में तेज आंच पर तेल गर्म करें। टुकड़ों को त्वचा नीचे रखकर 3–4 मिनट सुनहरा और कुरकुरा होने तक तलें। सॉस में वापस डालकर मिलाएं। तेज पत्ते निकाल दें। उबले सफेद चावल पर परोसें।","en":"Combine the chicken (or pork), garlic, vinegar, soy sauce, bay leaves, peppercorns, and water in a large pot. Marinate for 30 minutes at room temperature. Bring to the boil over medium-high heat without stirring. Once boiling, reduce heat to low, cover, and simmer for 30 minutes (chicken) or 45 minutes (pork) until the meat is tender. Uncover and increase heat to medium. Continue simmering, turning the meat occasionally, for 15–20 minutes until the sauce reduces to a glossy, thick glaze that coats the back of a spoon. In a separate pan, heat the oil over high heat. Add the cooked pieces skin-side down and fry for 3–4 minutes until the skin is golden brown and crisp. Return to the sauce and toss to coat. Discard bay leaves. Serve over steamed white rice."}},{"id":49,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"hi":"जमैका","en":"Jamaica","ro":"Jamaica"},"name":{"hi":"जर्क चिकन","en":"Jerk Chicken","ro":"Jerk Chicken"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"hi":["1.5 किलो चिकन जांघ और ड्रमस्टिक, चमड़ी सहित, चाकू से गहरे निशान लगाए","6 हरे प्याज़, मोटे कटे","3 स्कॉच बॉनेट या हबानेरो मिर्च, बीज निकाले","5 लहसुन की कलियां","2 सेमी ताज़े अदरक का टुकड़ा, छिला","2 बड़े चम्मच डार्क सोया सॉस","2 बड़े चम्मच ब्राउन शुगर","1 बड़ा चम्मच ऑलस्पाइस पाउडर","1 छोटा चम्मच सूखी थाइम","½ छोटा चम्मच दालचीनी पाउडर","½ छोटा चम्मच काली मिर्च","2 बड़े चम्मच वनस्पति तेल","2 नींबू का रस, साथ में परोसने के लिए नींबू के टुकड़े"],"en":["1.5kg chicken thighs and drumsticks, skin-on, scored deeply with a knife","6 spring onions, roughly chopped","3 Scotch bonnet chilies or habaneros, seeds removed for moderate heat","5 garlic cloves","2cm piece fresh ginger, peeled","2 tbsp dark soy sauce","2 tbsp brown sugar","1 tbsp ground allspice","1 tsp dried thyme","½ tsp ground cinnamon","½ tsp black pepper","2 tbsp vegetable oil","Juice of 2 limes, plus wedges to serve"],"ro":["1,5 kg pulpe și copane de pui, cu piele, crestați adânc","6 fire ceapă verde, tăiate grosier","3 ardei Scotch bonnet (sau habanero), semințele îndepărtate","5 căței de usturoi","Bucată de 2cm ghimbir proaspăt, curățat","2 linguri sos de soia închis la culoare","2 linguri zahăr brun","1 lingură ienibahar măcinat","1 linguriță cimbru uscat","½ linguriță scorțișoară măcinată","½ linguriță piper negru","2 linguri ulei vegetal","Suc de la 2 lămi verzi, plus felii pentru servire"]},"howIsMade":{"hi":"फूड प्रोसेसर में हरे प्याज़, स्कॉच बॉनेट, लहसुन, अदरक, सोया सॉस, ब्राउन शुगर, ऑलस्पाइस, थाइम, दालचीनी, काली मिर्च, तेल और नींबू का रस डालकर दरदरा पेस्ट बनाएं। हर चिकन टुकड़े पर हड्डी तक गहरे निशान लगाएं — जर्क तभी काम करता है जब मैरिनेड अंदर तक पहुंचे। पेस्ट सभी तरफ और हर निशान में दबाएं। कम से कम 4 घंटे, आदर्श रूप से रात भर फ्रिज में रखें। पकाने से 30 मिनट पहले निकालें। चारकोल ग्रिल पर: मध्यम-उच्च आंच पर 35–45 मिनट, हर 10 मिनट पर पलटते हुए, जब तक रस साफ बहे और बाहर कहीं-कहीं जले निशान हों। ओवन में: 200°C पर रैक पर 40 मिनट, फिर 5 मिनट ग्रिल करें। 5 मिनट रेस्ट करें। चावल-मटर, फ्राइड प्लान्टेन और नींबू के टुकड़ों के साथ परोसें।","en":"Blend spring onions, Scotch bonnets, garlic, ginger, soy sauce, brown sugar, allspice, thyme, cinnamon, black pepper, oil, and lime juice in a food processor until a rough paste forms. Score the chicken pieces deeply down to the bone — jerk only works if the marinade penetrates inside the meat. Rub the paste all over and into every cut. Cover and marinate in the refrigerator for at least 4 hours, ideally overnight. Remove from the fridge 30 minutes before cooking. To grill over charcoal: cook over medium-hot coals for 35–45 minutes, turning every 10 minutes, until the juices run clear and the exterior is deeply charred in places. To oven-roast: place on a rack over a baking tray at 200°C for 40 minutes, then finish under a hot grill for 5 minutes to char the skin. Allspice is the defining spice — do not substitute with mixed spice. Rest 5 minutes before serving. Serve with rice and peas, fried plantain, and lime wedges."}},{"id":50,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"hi":"इथियोपिया","en":"Ethiopia","ro":"Etiopia"},"name":{"hi":"डोरो वाट","en":"Doro Wat","ro":"Doro Wat"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"hi":["1.2 किलो चिकन के टुकड़े (जांघ और ड्रमस्टिक, हड्डी सहित)","3 बड़े चम्मच नींबू का रस","4 बड़े प्याज (लगभग 800 ग्राम), बारीक-बारीक कटे","80 ग्राम नितेर किबे (इथियोपियन मसालेदार मक्खन) या घी","6 लहसुन की कलियां, बारीक कुटी हुई","2 बड़े चम्मच ताजा कद्दूकस किया अदरक (लगभग 3 सेमी टुकड़ा)","4 बड़े चम्मच बर्बेरे मसाला मिश्रण","1 छोटा चम्मच इलायची पाउडर","½ छोटा चम्मच मेथी पाउडर","250 मिली पानी या चिकन स्टॉक","4 उबले अंडे, छिले हुए और कांटे से चारों तरफ छेद किए हुए","नमक स्वाद अनुसार"],"en":["1.2 kg chicken pieces (thighs and drumsticks, bone-in)","3 tbsp lemon juice","4 large onions (about 800 g), very finely diced","80 g niter kibbeh (Ethiopian spiced butter) or clarified butter","6 garlic cloves, minced","2 tbsp fresh ginger, finely grated (about 3 cm piece)","4 tbsp berbere spice blend","1 tsp ground cardamom","½ tsp ground fenugreek","250 ml water or chicken stock","4 hard-boiled eggs, shelled and scored all over with a fork","salt to taste"],"ro":["1,2 kg piese de pui (pulpe și tobe cu os)","3 linguri suc de lămâie","4 cepe mari (cca 800 g), tăiate mărunt fin","80 g unt etiopian niter kibbeh (sau unt clarificat)","6 căței de usturoi, tocați mărunt","2 linguri ghimbir proaspăt ras (cca 3 cm bucată)","4 linguri amestec de condimente berbere","1 linguriță cardamom măcinat","½ linguriță schinduf măcinat","250 ml apă sau supă de pui","4 ouă fierte tari, curățate, înțepate cu furculița","sare după gust"]},"howIsMade":{"hi":"चिकन को फोर्क से चारों तरफ से छेदें और नींबू के रस से मलें; बारीक कटे प्याज को बिना तेल या घी के एक बड़े भारी बर्तन में धीमी आंच पर रखें. बार-बार चलाते हुए 25–30 मिनट पकाएं जब तक प्याज बहुत नरम, गहरा सुनहरा भूरा न हो जाए और कारमेल की खुशबू न आने लगे — यह लंबा सूखा भूनना स्टू की स्वाद नींव बनाता है; नितेर किबे डालें और मिलाएं. लहसुन, अदरक, बर्बेरे, इलायची और मेथी डालें; 5 मिनट लगातार चलाते हुए पकाएं जब तक मसाले खिल उठें और घी गहरे लाल-नारंगी रंग का हो जाए. चिकन के टुकड़े डालें और पूरी तरह मसाले में लपेटें; 5 मिनट पलटते हुए पकाएं जब तक सभी तरफ से सील हो जाए. पानी या स्टॉक डालें; उबाल आने दें, फिर सबसे धीमी आंच पर करें. ढककर 40–45 मिनट पकाएं, बीच में पलटें, जब तक मांस बहुत नरम न हो जाए; अंडों में फोर्क से छेद करें और सॉस में डालें. बिना ढके 10 मिनट और पकाएं जब तक अंडे लाल न हो जाएं; नमक से स्वाद लें; इंजेरा ब्रेड या चावल पर परोसें.","en":"Prick the chicken all over with a fork and rub with lemon juice; put the finely diced onions into a large heavy pot over low heat with no oil or fat. Cook, stirring often, for 25–30 minutes until the onions are very soft, deep golden-brown, and smell caramel-like — this long dry fry builds the stew's flavour base; add the niter kibbeh and stir to coat. Add the garlic, ginger, berbere, cardamom, and fenugreek; cook for 5 minutes, stirring constantly, until the spices bloom and the butter turns deep red-orange. Add the chicken pieces and turn to coat completely; cook 5 minutes, turning, until sealed on all sides. Pour in the water or stock; bring to the boil, then reduce to the lowest simmer. Cover and cook for 40–45 minutes, turning the chicken halfway through, until the meat is very tender and nearly falling off the bone; score the eggs all over with a fork and nestle them into the sauce. Simmer uncovered for 10 more minutes until the eggs are stained red from the sauce and the sauce has thickened; season with salt; serve on injera flatbread or steamed rice."}},{"id":51,"servings":4,"tipType":"meat","pairingsType":"middle-eastern","origin":{"hi":"सीरिया","en":"Syria","ro":"Siria"},"name":{"hi":"किब्बेह","en":"Kibbeh","ro":"Kibbeh"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"hi":["खोल: बारीक बुलगुर गेहूं (#1 ग्रेड) 300 ग्राम, धोकर निथारा हुआ","बहुत दुबला मटन (या बीफ) कीमा 400 ग्राम, ठंडा","1 मध्यम प्याज, बारीक कसा हुआ","1 छोटा चम्मच पिसा ऑलस्पाइस","1 छोटा चम्मच पिसी दालचीनी","1 छोटा चम्मच बारीक नमक","½ छोटा चम्मच पिसी काली मिर्च","भरावन: मटन (या बीफ) कीमा 300 ग्राम","1 मध्यम प्याज, बारीक कटा हुआ","पाइन नट्स (या काजू) 80 ग्राम","1 छोटा चम्मच पिसा ऑलस्पाइस","½ छोटा चम्मच पिसी दालचीनी","1 बड़ा चम्मच वनस्पति तेल","तलने के लिए वनस्पति तेल लगभग 1 लीटर"],"en":["Shell: 300 g fine bulgur wheat (#1 grade), rinsed and drained","400 g very lean lamb (or beef) mince, chilled","1 medium onion, finely grated","1 tsp ground allspice","1 tsp ground cinnamon","1 tsp fine salt","½ tsp ground black pepper","Filling: 300 g lamb (or beef) mince","1 medium onion, finely diced","80 g pine nuts (or cashews)","1 tsp ground allspice","½ tsp ground cinnamon","1 tbsp vegetable oil","Vegetable oil for deep-frying (about 1 litre)"],"ro":["Coajă: 300 g bulgur fin (#1), clătit și scurs bine","400 g carne de miel sau vită slabă, tocată fin și răcită","1 ceapă medie, rasă sau blenderizată","1 linguriță condiment allspice (ienibahar măcinat)","1 linguriță scorțișoară măcinată","1 linguriță sare fină","½ linguriță piper negru măcinat","Umplutură: 300 g carne de miel sau vită tocată","1 ceapă medie, tăiată mărunt","80 g nuci de pin (sau nuci caju)","1 linguriță allspice","½ linguriță scorțișoară","1 lingură ulei vegetal","Ulei vegetal pentru prăjit adânc (cca 1 litru)"]},"howIsMade":{"hi":"बुलगुर को 15 मिनट ठंडे पानी में भिगोएं, फिर निथारकर हाथों से पूरी नमी निचोड़ें; ठंडे दुबले कीमे, कसे प्याज, ऑलस्पाइस, दालचीनी, नमक और काली मिर्च के साथ फूड प्रोसेसर में मिलाएं. 3–4 मिनट प्रोसेस करें, जरूरत हो तो एक-एक बड़ा चम्मच बर्फ का पानी मिलाते हुए, जब तक सख्त एकसार आटा न बन जाए; 30 मिनट फ्रिज में रखें. भरावन: मध्यम आंच पर तेल गर्म करें; प्याज 5 मिनट नरम होने तक भूनें. कीमा डालें और तोड़ते हुए 6–8 मिनट भूनें; ऑलस्पाइस, दालचीनी, मिर्च और पाइन नट्स मिलाएं; 2 मिनट पकाएं. पूरी तरह ठंडा करें; आकार देना: हाथ ठंडे पानी से गीले करें. 60 ग्राम आटा लें और अपनी तर्जनी के चारों ओर 5 मिमी मोटी दीवारों वाला खोखला टारपीडो आकार बनाएं; 1 बड़ा चम्मच भरावन भरें. खुले सिरे को कसकर बंद करें; दोहराएं. कम से कम 30 मिनट फ्रिज में रखें; तलना: तेल 175°C तक गर्म करें. 4–5 के बैच में 4–5 मिनट धीरे पलटते हुए तलें जब तक सभी तरफ से गहरे सुनहरे न हो जाएं; पेपर पर निथारें; दही या लहसुन की चटनी और पिटा ब्रेड के साथ गर्म परोसें.","en":"Soak the bulgur in cold water for 15 minutes, then drain and squeeze out all moisture firmly with your hands; combine with the chilled lean mince, grated onion, allspice, cinnamon, salt, and pepper in a food processor. Process for 3–4 minutes, adding ice water a tablespoon at a time if needed, until you have a smooth, stiff dough; refrigerate for 30 minutes. Make the filling: heat the oil over medium heat; cook the onion for 5 minutes until soft. Add the mince and brown, breaking it up, for 6–8 minutes; stir in allspice, cinnamon, pepper, and pine nuts; cook 2 minutes. Cool completely; shape: wet your hands with cold water. Take a 60 g piece of dough and mould it around your index finger into a hollow torpedo shape with 5 mm thick walls; fill the hollow with about 1 tablespoon of filling. Pinch the open end firmly to seal it into a pointed torpedo; repeat with the remaining dough and filling. Refrigerate for at least 30 minutes; fry: heat oil to 175°C. Fry in batches of 4–5 for 4–5 minutes, turning gently, until deep golden brown all over; drain on paper; serve warm with yoghurt or garlic sauce and pita bread."}},{"id":52,"servings":4,"tipType":"veg","pairingsType":"veg","origin":{"hi":"नीदरलैंड","en":"Netherlands","ro":"Olanda"},"name":{"hi":"स्टम्पट","en":"Stamppot","ro":"Stamppot"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"hi":["1 किलो आटेदार आलू (मैरिस पाइपर जैसे), छीले और चार टुकड़ों में काटे गए","400 ग्राम घुंघराले पत्तागोभी (बोरेनकूल), कड़े डंठल हटाए गए, पत्ते मोटे-मोटे काटे गए","400 ग्राम धुएंदार सूअर का सॉसेज (रूकवोर्स्ट) या ब्रैटवुर्स्ट","80 ग्राम बिना नमक का मक्खन, टुकड़ों में कटा","100 मिली पूर्ण वसा वाला दूध, गर्म किया गया","1/4 छोटी चम्मच ताजी कसी जायफल","1 1/2 छोटी चम्मच बारीक समुद्री नमक, विभाजित","1/2 छोटी चम्मच ताजी पिसी काली मिर्च"],"en":["1 kg floury potatoes (such as Maris Piper or Russet), peeled and quartered","400 g curly kale (boerenkool), tough stems removed, leaves roughly chopped","400 g smoked pork sausage (rookworst) or bratwurst","80 g unsalted butter, cut into cubes","100 ml whole milk, warmed","1/4 tsp freshly grated nutmeg","1 1/2 tsp fine sea salt, divided","1/2 tsp freshly ground black pepper"],"ro":["1 kg cartofi făinoși (tip Maris Piper sau Russet), curățați și tăiați în sferturi","400 g varză creață (boerenkool), tulpini dure îndepărtate, frunze tocate grosier","400 g cârnați afumați din porc (rookworst) sau bratwurst","80 g unt nesărat, tăiat cubulețe","100 ml lapte integral, încălzit","1/4 linguriță nucșoară proaspăt rasă","1 1/2 linguriță sare fină de mare, împărțită","1/2 linguriță piper negru proaspăt măcinat"]},"howIsMade":{"hi":"एक बड़े बर्तन में 1 छोटी चम्मच नमक के साथ पानी उबालें, आलू डालें और 18-20 मिनट तक उबालें जब तक चाकू से आसानी से छेद न हो जाए। जब आलू पक रहे हों, दूसरे बर्तन में नमकीन पानी उबालें, घुंघराले पत्तागोभी डालें और 5-6 मिनट तक उबालें जब तक वे मुलायम न हो जाएं; अच्छी तरह छान लें, अतिरिक्त पानी निचोड़ें और मोटे-मोटे काट लें। धुएंदार सॉसेज को एक पैन में रखें, ढकने लायक पानी डालें और मध्यम आंच पर 20 मिनट तक उबालें जब तक अंदर से गर्म न हो जाए — या थोड़े तेल में मध्यम आंच पर 8-10 मिनट तक भूनें, बीच में पलटते हुए, जब तक सभी तरफ से सुनहरे न हो जाएं। आलू छान लें और गर्म बर्तन में वापस डालें, धीमी आंच पर 1-2 मिनट तक बर्तन हिलाते हुए भाप से सुखाएं जिससे पानीदार मैश न बने। मक्खन और गर्म दूध डालें और आलू मैशर से जोर से मैश करें जब तक चिकना और क्रीमी न बने। छाने हुए पत्तागोभी को मैश में मिलाएं, बचा हुआ नमक, काली मिर्च और जायफल से सीजन करें और समान रूप से मिलाएं। तुरंत गहरे कटोरों में परोसें, कटे हुए सॉसेज को ऊपर से सजाकर।","en":"Bring a large pot of water with 1 tsp salt to the boil, add the potatoes, and cook for 18-20 minutes until completely tender when pierced with a knife. While the potatoes cook, bring a separate pot of salted water to the boil, add the kale, and blanch for 5-6 minutes until wilted and tender; drain well, squeeze out excess water, and chop roughly. Place the smoked sausage in a pan, add enough water to just cover, and simmer over medium heat for 20 minutes until heated through — or pan-fry in a little oil over medium heat for 8-10 minutes, turning halfway, until browned on all sides. Drain the potatoes and return them to the hot pot over low heat for 1-2 minutes, shaking the pot to steam-dry them and prevent a watery mash. Add the butter and warm milk and mash vigorously with a potato masher until smooth and creamy. Fold in the drained kale, season with the remaining salt, black pepper, and nutmeg, and stir until evenly combined. Serve immediately in deep bowls with the sliced sausage on top."}},{"id":53,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"hi":"न्यूज़ीलैंड","en":"New Zealand","ro":"Noua Zeelandă"},"name":{"hi":"हांगी","en":"Hangi","ro":"Hangi"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"hi":["हड्डी सहित मेमने का कंधा या पसलियां 600 ग्राम, 4 सेमी के टुकड़ों में कटी","4 चिकन ड्रमस्टिक (लगभग 600 ग्राम कुल), छिलके सहित","500 ग्राम वैक्सी आलू, छीले और आधे में काटे गए","300 ग्राम कुमारा (नारंगी शकरकंद), छीला और 4 सेमी घन में काटा गया","300 ग्राम बटरनट कद्दू, छीला और 4 सेमी घन में काटा गया","1/4 सेवॉय पत्तागोभी (लगभग 300 ग्राम), 4 टुकड़ों में काटी","3 बड़े चम्मच वनस्पति तेल","1 1/2 छोटी चम्मच बारीक नमक","1/2 छोटी चम्मच पिसी काली मिर्च"],"en":["600 g bone-in lamb shoulder or ribs, cut into 4 cm pieces","4 chicken drumsticks (about 600 g total), skin-on","500 g waxy potatoes, peeled and halved","300 g kumara (orange sweet potato), peeled and cut into 4 cm cubes","300 g butternut pumpkin, peeled and cut into 4 cm cubes","1/4 head savoy cabbage (about 300 g), cut into 4 wedges","3 tbsp vegetable oil","1 1/2 tsp fine salt","1/2 tsp ground black pepper"],"ro":["600 g carne de miel cu os (spată sau coaste), tăiată în bucăți de 4 cm","4 pulpe inferioare de pui (cca 600 g total), cu os și piele","500 g cartofi waxy, curățați și tăiați în jumătăți","300 g kumara (batată portocalie), curățată și tăiată cubulețe de 4 cm","300 g dovleac butternut, curățat și tăiat cubulețe de 4 cm","1/4 dintr-un cap de varză Savoy (cca 300 g), tăiată în 4 sferturi","3 linguri ulei vegetal","1 1/2 linguriță sare fină","1/2 linguriță piper negru măcinat"]},"howIsMade":{"hi":"ओवन को 180°C (फैन 160°C) पर पहले से गर्म करें। मेमने और चिकन को नमक और काली मिर्च से पूरी तरह सीजन करें। एक बड़े ओवन-सेफ कैसरोल में तेल गर्म करें और मेमने के टुकड़ों को हर तरफ 3-4 मिनट तक गहरे रंग का होने तक भूनें, फिर एक प्लेट पर रखें। उसी बर्तन में चिकन ड्रमस्टिक को चमड़ी नीचे की तरफ 4-5 मिनट तक सुनहरी और कुरकुरी होने तक भूनें, फिर अलग रखें। सारा भुना मांस कैसरोल में लगाएं और आलू, कुमारा, कद्दू और पत्तागोभी के टुकड़ों को मांस के बीच कसकर भरें। 200 मिली पानी डालें और कैसरोल को दोहरी एल्युमिनियम फॉयल से किनारों पर दबाकर बहुत कसकर बंद करें, फिर ढक्कन लगाएं। ओवन में 2 घंटे पकाएं जब तक मेमना पूरी तरह नरम न हो जाए और हड्डी से आसानी से न अलग होने लगे, और सभी सब्जियां कांटे से छेदने पर नरम न हों — अगर तैयार नहीं हैं तो फिर से ढककर 30 मिनट और पकाएं। ढक्कन और फॉयल हटाएं, ओवन को 220°C पर बढ़ाएं और खुला 15 मिनट तक भूनें जब तक चमड़ी कुरकुरी न हो जाए। 10 मिनट आराम करने दें, फिर सब कुछ बड़े थाल में रखें और इकट्ठा हुए रस को ऊपर से डालकर परोसें।","en":"Heat the oven to 180°C (160°C fan). Season the lamb and chicken all over with salt and pepper. Heat the oil in a large flameproof casserole over high heat and brown the lamb pieces for 3-4 minutes per side until deeply coloured, then transfer to a plate. In the same pot, brown the chicken drumsticks skin-side down for 4-5 minutes until the skin is golden and crisp, then set aside. Arrange all the browned meat in the casserole and tuck the potatoes, kumara, pumpkin, and cabbage wedges snugly around and between the pieces. Pour in 200 ml of water, then seal the casserole very tightly with a double layer of foil pressed against the rim and put the lid on. Cook in the oven for 2 hours until the lamb is completely tender and pulls away from the bone easily, and all the vegetables are soft when pierced with a fork — if not quite done, cover again and cook for 30 minutes more. Remove the lid and foil, raise the oven to 220°C, and roast uncovered for 15 minutes until the skin crisps. Rest for 10 minutes before transferring everything to a large platter and spooning the collected juices over the top."}},{"id":54,"servings":4,"tipType":"fish","pairingsType":"fish","origin":{"hi":"बेल्जियम","en":"Belgium","ro":"Belgia"},"name":{"hi":"मूल्स-फ्रित्स","en":"Moules-frites","ro":"Moules-frites"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"hi":["2 किलो ताज़े जीवित मसल्स, साफ़ किए और दाढ़ी निकाली","800 ग्राम आटेदार आलू, छीलकर मोटे बेटन में काटे","50 ग्राम अनसाल्टेड बटर","4 शैलोट्स, बारीक कटे","4 लहसुन की कलियां, पतले स्लाइस","200 मिलीलीटर सूखी सफ़ेद वाइन","2 अजवाइन के डंठल, पतले कटे","ताज़े पार्सले का छोटा गुच्छा, बारीक कटा","डीप-फ्राई के लिए वनस्पति तेल या बीफ ड्रिपिंग","नमक और काली मिर्च"],"en":["2kg fresh live mussels, scrubbed and beards removed","800g floury potatoes, peeled and cut into thick batons","50g unsalted butter","4 shallots, finely diced","4 garlic cloves, thinly sliced","200ml dry white wine","2 celery stalks, finely sliced","Small bunch of fresh parsley, finely chopped","Vegetable oil or beef dripping, for deep-frying","Salt and black pepper"],"ro":["2 kg midii proaspete vii, curățate și cu beard-ul îndepărtat","800g cartofi făinoși, curățați și tăiați bețe groase","50g unt nesărat","4 șalote, tocate mărunt","4 căței de usturoi, felii subțiri","200ml vin alb sec","2 tulpini de țelină, feliate subțire","Legătură mică de pătrunjel proaspăt, tocat mărunt","Ulei vegetal sau grăsime de vită, pentru prăjit","Sare și piper negru"]},"howIsMade":{"hi":"फ्रिट्स के लिए: आलू को मोटे बेटन में काटें और 30 मिनट ठंडे पानी में भिगोएं, फिर निकाल कर पूरी तरह सुखाएं; पहली बार 140°C पर 6–8 मिनट तलें जब तक पक जाएं लेकिन रंग न आए; निकालें और पूरी तरह ठंडे होने दें. हर खुले मसल को काउंटर पर थपथपाएं — जो बंद न हों उन्हें फेंक दें; बड़े भारी बर्तन में मध्यम-उच्च आंच पर बटर पिघलाएं. शैलोट्स और अजवाइन डालें और 3 मिनट पकाएं; लहसुन डालें और 1 मिनट पकाएं. सफ़ेद वाइन डालें, उबाल आने दें, मसल्स डालें और ढक्कन कसकर बंद करें; 4–5 मिनट भाप दें, बर्तन एक-दो बार हिलाएं, जब तक सभी शेल खुल जाएं. बंद रहे वाले फेंक दें; ज़्यादातर पार्सले मिलाएं और शोरबा सीज़न करें. तेल 190°C करें और ब्लांच किए बेटन बैचों में 2–3 मिनट तक सुनहरे और बहुत कुरकुरे होने तक तलें; तुरंत नमक डालें; मसल्स उनके शोरबे में परोसें, फ्रिट्स बगल में रखें.","en":"For the frites: cut potatoes into thick batons and soak in cold water for 30 minutes to remove surface starch, then drain and dry thoroughly; first fry at 140°C for 6–8 minutes until cooked through but uncoloured; drain and cool completely. Tap each open mussel on the counter — discard any that do not close; melt butter in a large heavy pot over medium-high heat. Add shallots and celery and cook for 3 minutes until softened; add garlic and cook for 1 minute. Pour in the white wine, bring to a boil, then add the mussels and cover tightly; steam for 4–5 minutes, shaking the pot once or twice, until the shells have opened wide. Discard any that remain shut; stir in most of the parsley and season the broth. Raise the frying oil to 190°C and fry the blanched batons in batches for 2–3 minutes until golden and very crisp; drain and season immediately with salt; serve the mussels in wide bowls in their broth, the frites alongside, with the remaining parsley and mayonnaise on the side."}},{"id":55,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"hi":"ग्रीस","en":"Greece","ro":"Grecia"},"name":{"hi":"मूसाका","en":"Moussaka","ro":"Moussaka"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"hi":["2 बड़े बैंगन (कुल लगभग 1 किग्रा), 1 सेमी मोटे टुकड़ों में कटे","500 ग्राम मेमने का कीमा (या बीफ का कीमा)","1 बड़ा प्याज़, बारीक कटा हुआ","3 लहसुन की कलियाँ, कुचली हुई","400 ग्राम कटे टमाटर डिब्बाबंद (1 डिब्बा)","2 बड़े चम्मच टमाटर पेस्ट","100 मिली रेड वाइन","1 छोटा चम्मच सूखा ऑरेगानो","1/2 छोटा चम्मच पिसी दालचीनी","60 ग्राम मक्खन (बेशामेल के लिए)","60 ग्राम मैदा (बेशामेल के लिए)","700 मिली गुनगुना दूध","2 अंडे की जर्दी","80 ग्राम कद्दूकस किया केफालोटीरी (या परमेज़न)","3 बड़े चम्मच जैतून का तेल","नमक और ताज़ी पिसी काली मिर्च"],"en":["2 large eggplants (about 1 kg total), sliced 1 cm thick","500 g lamb mince (or beef mince)","1 large onion, finely diced","3 garlic cloves, minced","400 g chopped tomatoes (1 can)","2 tbsp tomato paste","100 ml red wine","1 tsp dried oregano","1/2 tsp ground cinnamon","60 g butter (for the bechamel)","60 g plain flour (for the bechamel)","700 ml warm milk","2 egg yolks","80 g grated kefalotyri (or parmesan)","3 tbsp olive oil","Salt and freshly ground black pepper"],"ro":["2 vinete mari (aproximativ 1 kg in total), feliate de 1 cm grosime","500 g carne tocata de miel (sau de vita)","1 ceapa mare, tocata marunt","3 căței de usturoi, zdrobiti","400 g rosii tocate in conserva (1 conserva)","2 linguri pasta de rosii","100 ml vin rosu","1 lingurita oregano uscat","1/2 lingurita scortisoara macinata","60 g unt (pentru bechamel)","60 g făină alba (pentru bechamel)","700 ml lapte cald","2 galbenusuri de ou","80 g kefalotyri ras (sau parmezan)","3 linguri ulei de masline","Sare si piper negru proaspat macinat"]},"howIsMade":{"hi":"2 बड़े बैंगन को 1 सेमी मोटे गोल टुकड़ों में काटें, उन पर अच्छी तरह नमक छिड़कें और छलनी में 30 मिनट रखें ताकि कड़वा पानी निकल जाए; किचन पेपर से थपथपा कर सुखाएँ. टुकड़ों पर जैतून का तेल लगाएँ और 200 C पर 20-25 मिनट के लिए, बीच में एक बार पलटते हुए, सुनहरे और नर्म होने तक भूनें. एक चौड़े पैन में 2 बड़े चम्मच तेल मध्यम-तेज़ आँच पर गरम करें और 500 ग्राम मेमने के कीमे को एक कटे प्याज़ और 3 लहसुन की कलियों के साथ 8-10 मिनट तक भूनें, फिर 100 मिली रेड वाइन डालकर तली खुरचें और कम होने दें. 400 ग्राम कटे टमाटर, 2 बड़े चम्मच टमाटर पेस्ट, आधा छोटा चम्मच दालचीनी और 1 छोटा चम्मच ऑरेगानो डालें; धीमी आँच पर 20 मिनट तक पकाएँ जब तक सॉस गाढ़ा हो जाए और किनारों पर अतिरिक्त रस न रहे. बेशामेल के लिए एक पैन में 60 ग्राम मक्खन पिघलाएँ, 60 ग्राम मैदा डालकर 2 मिनट हल्के सुनहरे रंग तक पकाएँ, फिर 700 मिली गुनगुना दूध धीरे-धीरे डालते हुए लगातार फेंटें जब तक गाढ़ा हो जाए; आँच से उतार कर 30 सेकंड ठंडा करें और 2 अंडे की जर्दी 80 ग्राम कद्दूकस किए केफालोटीरी या परमेज़न के साथ मिलाएँ. 30x20 सेमी की बेकिंग डिश में बैंगन की एक परत, आधा मेमने का सॉस, बैंगन की दूसरी परत, बचा हुआ सॉस लगाएँ, फिर ऊपर से बेशामेल डालकर स्पैचुला से समतल करें. 180 C पर 40-45 मिनट तक बेक करें जब तक ऊपरी सतह गहरी सुनहरी हो जाए और किनारों पर सॉस बुलबुले छोड़े. मूसाका को काटने से पहले 15-20 मिनट आराम दें; यह चरण ज़रूरी है ताकि परतें जम जाएँ और टुकड़े अपना आकार बनाए रखें.","en":"Slice 2 large eggplants into 1 cm rounds, salt them generously and let them sit in a colander for 30 minutes to draw out the bitter water; pat dry with paper towels. Brush the slices with olive oil and roast at 200 C for 20-25 minutes, turning once, until golden and tender. In a wide pan heat 2 tbsp oil over medium-high and brown 500 g minced lamb with one chopped onion and 3 garlic cloves for 8-10 minutes, then deglaze with 100 ml red wine and let it reduce. Add 400 g chopped tomatoes, 2 tbsp tomato paste, half a tsp cinnamon and 1 tsp oregano; simmer 20 minutes until thick and no excess liquid pools at the edge. For the bechamel melt 60 g butter in a saucepan, whisk in 60 g flour and cook 2 minutes until blond, then gradually add 700 ml warm milk whisking constantly until thick; off the heat, let it cool 30 seconds and beat in 2 egg yolks with 80 g grated kefalotyri or parmesan. In a 30x20 cm baking dish layer half the eggplant, all the lamb sauce, the remaining eggplant, then pour the bechamel on top and level it with a spatula. Bake at 180 C for 40-45 minutes until the top is deeply golden and the sauce bubbles at the edges. Rest the moussaka for 15-20 minutes before cutting; this step is non-negotiable so the layers set and the slices hold their shape."},"timeMins":{"total":105,"active":35}},{"id":56,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"hi":"चेक गणराज्य","en":"Czech Republic","ro":"Republica Cehă"},"name":{"hi":"स्विचकोवा","en":"Svíčková","ro":"Svíčková"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"hi":["1.2 किलो बीफ सिरलोइन (टॉप राउंड या टॉपसाइड)","100 ग्राम स्मोक्ड बेकन, लार्डिंग के लिए पतली पट्टियों में कटा (वैकल्पिक)","30 ग्राम मक्खन","1 बड़ा चम्मच न्यूट्रल तेल","1 बड़ा प्याज, बारीक कटा","2 बड़ी गाजर, बारीक कटी","1 पार्सनिप, बारीक कटा","150 ग्राम सेलेरियाक, बारीक कटा","2 तेज पत्ते","6 ऑलस्पाइस के दाने","10 साबुत काली मिर्च","आधे नींबू का छिलका","1 बड़ा चम्मच डिजॉन सरसों","2 बड़े चम्मच टमाटर पेस्ट","200 मिली सूखी सफेद वाइन","500 मिली बीफ स्टॉक","200 मिली हैवी क्रीम (33% वसा)","1 बड़ा चम्मच मैदा (वैकल्पिक, गाढ़ा करने के लिए)","1 छोटी चम्मच चीनी","आधे नींबू का रस","नमक, स्वादानुसार","परोसने के लिए: फेंटी हुई क्रीम, क्रैनबेरी कॉम्पोट, नींबू की स्लाइस, knedliky"],"en":["1.2 kg beef sirloin (top round or topside)","100 g smoked bacon, cut in thin strips for larding (optional)","30 g butter","1 tbsp neutral oil","1 large onion, diced","2 large carrots, diced","1 parsnip, diced","150 g celeriac, diced","2 bay leaves","6 allspice berries","10 black peppercorns","Zest of 1/2 lemon","1 tbsp Dijon mustard","2 tbsp tomato paste","200 ml dry white wine","500 ml beef stock","200 ml heavy cream (33% fat)","1 tbsp plain flour (optional, for thickening)","1 tsp sugar","Juice of 1/2 lemon","Salt, to taste","To serve: whipped cream, cranberry compote, lemon slice, knedliky"],"ro":["1,2 kg mușchi de vită (vrabia sau pulpă top)","100 g bacon afumat, tăiat fâșii subțiri pentru lardonare (opțional)","30 g unt","1 lingură ulei neutru","1 ceapă mare, tăiată cuburi","2 morcovi mari, tăiați cuburi","1 rădăcină de păstârnac, tăiată cuburi","150 g țelină rădăcină, tăiată cuburi","2 foi de dafin","6 boabe de ienibahar","10 boabe de piper negru","Coaja de la 1/2 lămâie","1 lingură de muștar Dijon","2 linguri de pastă de roșii","200 ml vin alb sec","500 ml supă de vită","200 ml smântână grasă (33% grăsime)","1 lingură de făină albă (opțional, pentru îngroșare)","1 linguriță de zahăr","Zeama de la 1/2 lămâie","Sare, după gust","Pentru servire: frișcă bătută, dulceață de merișoare, felie de lămâie, knedlíky"]},"howIsMade":{"hi":"1.2 किलो बीफ सिरलोइन में स्मोक्ड बेकन की पतली पट्टियाँ लार्ड करें या किचन की डोरी से कसकर बांधें; चारों ओर नमक और ताजी पिसी काली मिर्च से उदारता से सीजन करें. एक भारी डच ओवन में 30 ग्राम मक्खन और 1 बड़ा चम्मच तेल मध्यम-तेज आंच पर गर्म करें और मांस को हर तरफ 8-10 मिनट सीयर करें जब तक गहरी भूरी परत न बन जाए, फिर एक प्लेट में निकाल लें. उसी बर्तन में मिरेपोइक्स (1 बड़ी गाजर, 1 पार्सनिप, 150 ग्राम सेलेरियाक, 1 बड़ा प्याज, सभी कटे हुए) को 10-12 मिनट तक भूनें जब तक किनारे कैरामेलाइज़ न हो जाएं; 2 तेज पत्ते, 6 ऑलस्पाइस के दाने, 10 साबुत काली मिर्च, आधे नींबू का छिलका और 1 बड़ा चम्मच सरसों डालें. 2 बड़े चम्मच टमाटर पेस्ट डालकर 2 मिनट पकाएं जब तक रंग गहरा हो जाए, फिर 200 मिली सूखी सफेद वाइन और 500 मिली बीफ स्टॉक से डीग्लेज़ करें, तले को खुरचते हुए, और मांस को सब्जियों के ऊपर वापस रखें. ढककर 160°C पर 1.5-2 घंटे ब्रेज़ करें, हर 30 मिनट में मांस पलटते रहें, जब तक कांटा बिना प्रतिरोध के अंदर न जाए. मांस को बोर्ड पर निकाल कर फॉइल से ढककर रेस्ट करने दें; पकाने के तरल और सब्जियों को हैंड ब्लेंडर से चिकना होने तक ब्लेंड करें और सॉस को महीन छलनी से वापस बर्तन में छानें. 200 मिली हैवी क्रीम मिलाएं और जरूरत हो तो थोड़े ठंडे पानी में घोला 1 बड़ा चम्मच आटा डालें; 5 मिनट उबालें जब तक सॉस चमचे की पीठ पर चमकदार परत न बनाए, फिर नमक, 1 छोटी चम्मच चीनी और थोड़ा नींबू निचोड़कर मीठा-खट्टा संतुलन बनाएं. मांस को रेशे के विपरीत 1 सेमी मोटे टुकड़ों में काटें, ऊपर से गरम सॉस डालें और एक चम्मच फेंटी हुई क्रीम, क्रैनबेरी कॉम्पोट और नींबू की एक स्लाइस से सजाएं; knedliky (ब्रेड डम्पलिंग) के साथ परोसें.","en":"Lard the beef sirloin (1.2 kg) with thin strips of smoked bacon, or truss it tightly with kitchen twine; season generously with salt and freshly ground pepper on all sides. Heat 30 g butter and 1 tbsp oil in a heavy Dutch oven over medium-high and sear the beef on every side for 8-10 minutes until a deep brown crust forms, then transfer to a plate. In the same pot brown the mirepoix (1 large carrot, 1 parsnip, 150 g celeriac, 1 large onion, all diced) for 10-12 minutes until caramelised at the edges; add 2 bay leaves, 6 allspice berries, 10 whole black peppercorns, the zest of half a lemon and 1 tbsp mustard. Stir in 2 tbsp tomato paste and cook 2 minutes until it darkens, then deglaze with 200 ml dry white wine and 500 ml beef stock, scraping the bottom, and nestle the beef back in on top of the vegetables. Cover and braise at 160°C for 1.5 to 2 hours, turning the beef every 30 minutes, until a fork slides in with no resistance. Lift the beef onto a board and tent with foil to rest; blend the cooking liquid and vegetables with a stick blender until smooth and pass the sauce through a fine sieve back into the pot. Stir in 200 ml heavy cream and, if needed, 1 tbsp flour slaked in a little cold water; simmer 5 minutes until the sauce coats the back of a spoon glossily, then adjust with salt, 1 tsp sugar and a squeeze of lemon to balance the sweet-sour. Slice the beef against the grain into 1 cm slices, ladle the warm sauce over the top and garnish with a spoon of whipped cream, cranberry compote and a lemon slice; serve with houskove knedliky (bread dumplings)."}},{"id":57,"servings":4,"tipType":"meat","timeMins":{"total":195,"active":45},"pairingsType":"meat","origin":{"hi":"नॉर्वे","en":"Norway","ro":"Norvegia"},"name":{"hi":"फॉरीकोल","en":"Fårikål","ro":"Fårikål"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"hi":["हड्डी सहित मेमने का कंधा या गर्दन 1.2 किलो, 5 सेमी के टुकड़ों में कटी","सफेद पत्तागोभी 1.2 किलो (लगभग 1 बड़ा सिर), बीज निकाला, 8 मोटे टुकड़ों में काटी","साबुत काली मिर्च 1 बड़ा चम्मच","ठंडा पानी 600 मिली","बारीक नमक 1 1/2 छोटी चम्मच"],"en":["1.2 kg bone-in lamb shoulder or neck, cut into 5 cm pieces","1.2 kg white cabbage (about 1 large head), cored and cut into 8 thick wedges","1 tbsp whole black peppercorns","600 ml cold water","1 1/2 tsp fine salt"],"ro":["1,2 kg carne de miel cu os (spata sau gat), taiata in bucati de 5 cm","1,2 kg varza alba (1 cap mare), miezul indepartat, taiata in 8 sferturi groase","1 lingura boabe intregi de piper negru","600 ml apa rece","1 1/2 lingurita sare fina"]},"howIsMade":{"hi":"मेमने के टुकड़ों को 1 छोटी चम्मच नमक से चारों तरफ सीजन करें। एक बड़े और भारी बर्तन के तले में आधे पत्तागोभी के टुकड़े समान परत में बिछाएं। ऊपर मेमने के टुकड़े रखें, काली मिर्च के दाने और बचा हुआ 1/2 छोटी चम्मच नमक छिड़कें, फिर बाकी पत्तागोभी ऊपर रखें। ठंडा पानी सावधानी से बर्तन की अंदरूनी दीवार से डालें — हिलाएं नहीं। ढक्कन कसकर बंद करें और मध्यम आंच पर हल्की उबाल आने तक गर्म करें, लगभग 8-10 मिनट। आंच को न्यूनतम पर कम करें और बिना हिलाए 2 से 2.5 घंटे पकाएं जब तक मेमना पूरी तरह नरम न हो जाए और हड्डी से गिरने न लगे, और पत्तागोभी पूरी तरह पिघलकर मांस के रस को न सोख ले। 2 घंटे बाद जांचें कि मेमना बिना प्रतिरोध के हड्डी से अलग हो और शोरबा समृद्ध और सुगंधित हो — अगर तैयार नहीं है तो ढककर 30 मिनट और पकाएं। नमक का स्वाद लें और समायोजित करें। गहरे कटोरों में शोरबे के साथ परोसें, यह सुनिश्चित करते हुए कि प्रत्येक परोसे में मेमना और पत्तागोभी दोनों हों।","en":"Season the lamb pieces all over with 1 tsp of the salt. Arrange half the cabbage wedges in an even layer at the bottom of a large, heavy pot. Lay the lamb pieces on top, scatter over the peppercorns and the remaining 1/2 tsp salt, then arrange the remaining cabbage on top. Pour the cold water carefully down the inside wall of the pot — do not stir. Cover tightly and bring to a gentle boil over medium heat, about 8-10 minutes. Reduce the heat to the lowest possible simmer and cook undisturbed for 2 to 2.5 hours until the lamb is completely tender and falls off the bone, and the cabbage has collapsed and fully absorbed the meat juices. After 2 hours check that the lamb pulls away from the bone with no resistance and the broth is rich and fragrant — if not quite done, cover and simmer for 30 minutes more. Taste and adjust salt. Ladle into deep bowls with the broth, ensuring each serving has both lamb and cabbage."}},{"id":58,"servings":4,"tipType":"veg","pairingsType":"middle-eastern","origin":{"hi":"सूडान","en":"Sudan","ro":"Sudan"},"name":{"hi":"फूल मेदमेस","en":"Ful Medames","ro":"Ful Medames"},"category":{"en":"Breakfast","ro":"Mic dejun"},"ingredients":{"hi":["400 ग्राम सूखी छोटी सेम (फावा बीन्स), रात भर ठंडे पानी में भिगोई हुई (या 800 ग्राम डिब्बाबंद फावा बीन्स, धोकर छानी हुई)","4 लहसुन की कलियां, बारीक कटी","60 मिली ताजा नींबू का रस (लगभग 1 बड़ा नींबू), स्वाद अनुसार अधिक","4 बड़े चम्मच एक्स्ट्रा-वर्जिन जैतून का तेल, विभाजित","1 छोटी चम्मच जीरा पाउडर","1/2 छोटी चम्मच धनिया पाउडर","1/2 छोटी चम्मच बारीक समुद्री नमक, स्वाद अनुसार अधिक","1/4 छोटी चम्मच लाल मिर्च पाउडर या गरम पापरिका","2 मध्यम पके टमाटर (लगभग 250 ग्राम), बारीक कटे","1 छोटा लाल प्याज (लगभग 100 ग्राम), बारीक कटा","20 ग्राम पत्ते वाला धनिया (फ्लैट-लीफ पार्सले), पत्ते मोटे-मोटे काटे"],"en":["400 g dried small fava beans, soaked overnight in cold water (or 800 g canned fava beans, rinsed and drained)","4 garlic cloves, finely minced","60 ml fresh lemon juice (about 1 large lemon), plus more to taste","4 tbsp extra-virgin olive oil, divided","1 tsp ground cumin","1/2 tsp ground coriander","1/2 tsp fine sea salt, plus more to taste","1/4 tsp cayenne pepper or hot paprika","2 medium ripe tomatoes (about 250 g), finely diced","1 small red onion (about 100 g), finely diced","20 g flat-leaf parsley, leaves roughly chopped"],"ro":["400 g fasole fava uscata, inmuiata peste noapte in apa rece (sau 800 g fasole fava la conserva, clatita si scursa)","4 căței de usturoi, tocati marunt","60 ml suc proaspat de lamaie (cca 1 lamaie mare), plus dupa gust","4 linguri ulei de masline extravirgin, impartit","1 lingurita chimen macinat","1/2 lingurita coriandru macinat","1/2 lingurita sare fina de mare, plus dupa gust","1/4 lingurita ardei iute macinat sau boia picanta","2 rosii mijlocii coapte (cca 250 g), taiate marunt","1 ceapa rosie mica (cca 100 g), taiata marunt","20 g patrunjel plat, frunzele tocate grosier"]},"howIsMade":{"hi":"अगर सूखी फलियां इस्तेमाल कर रहे हैं, तो भिगोई हुई फलियां निकाल कर ताजे ठंडे पानी से 4-5 सेमी ऊपर तक भर दें; उबाल आने पर 1.5 से 2 घंटे तक उबालें जब तक फलियां उंगलियों से दबाने पर पूरी तरह नरम न हो जाएं; फिर छानकर 100 मिली पकाने का पानी बचा लें। डिब्बाबंद फलियां इस्तेमाल करने पर धोकर छानें और 100 मिली पानी का उपयोग करें। फलियों को धीमी आंच पर बर्तन में वापस डालें और लहसुन, नींबू का रस, 3 बड़े चम्मच जैतून का तेल, जीरा, धनिया, नमक और लाल मिर्च मिलाएं। 3-4 मिनट पकाते हुए आधी फलियों को कांटे से मसलें जिससे क्रीमी लेकिन थोड़ी दरदरी बनावट बने, बहुत गाढ़ी हो तो बचाया पानी थोड़ा-थोड़ा मिलाएं। नींबू, नमक और मसाले चखकर समायोजित करें — फुल खट्टा और मसालेदार होना चाहिए। उथले कटोरों में बांटें और ऊपर कटे टमाटर, लाल प्याज और धनिया/पार्सले डालें। बचा हुआ 1 बड़ा चम्मच जैतून का तेल हर परोसे पर डालें और गरम पिटा ब्रेड के साथ तुरंत परोसें।","en":"If using dried beans, drain the soaked beans and cover with fresh cold water by 4-5 cm; bring to the boil and simmer for 1.5 to 2 hours until the beans are completely soft when pressed between fingers, then drain, reserving 100 ml of cooking liquid. If using canned beans, rinse, drain, and use 100 ml of water as the liquid. Return the beans to the pot over low heat and add the garlic, lemon juice, 3 tbsp of the olive oil, cumin, coriander, salt, and cayenne. Cook for 3-4 minutes, mashing about half the beans with a fork to create a creamy, partly chunky texture, adding reserved cooking liquid a splash at a time if too thick. Taste and adjust lemon, salt, and spice — the ful should be tangy and warmly spiced. Divide into shallow bowls and scatter the diced tomatoes, red onion, and parsley over the top. Drizzle the remaining 1 tbsp olive oil over each serving and serve immediately with warm pita bread."}},{"id":59,"servings":4,"tipType":"fish","timeMins":{"total":50,"active":40},"pairingsType":"mediterranean","origin":{"hi":"क्रोएशिया","en":"Croatia","ro":"Croația"},"name":{"hi":"क्रनी रिज़ोटो","en":"Crni Rizot","ro":"Crni Rižot"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["ताज़ा या पिघले हुए स्क्विड 500 ग्राम, साफ किए, 2-3 स्याही की थैलियाँ अलग रखी","अर्बोरियो या कार्नारोली चावल 300 ग्राम","1 मध्यम प्याज (लगभग 150 ग्राम), बारीक कटा","लहसुन की 3 कलियाँ, बारीक कटी","सूखी डाल्मेटियन सफेद वाइन (या Pošip) 100 मिली","गर्म मछली शोरबा 1 लीटर (या पानी में 1 मछली शोरबा क्यूब)","एक्स्ट्रा वर्जिन जैतून का तेल 60 मिली","ठंडा मक्खन 30 ग्राम, क्यूब में काटा","ताज़ा अजमोद 2 बड़े चम्मच, कटा","1/2 नींबू, केवल रस","बारीक समुद्री नमक 1 छोटी चम्मच","पिसी काली मिर्च 1/2 छोटी चम्मच"],"en":["500 g fresh or thawed squid, cleaned, with 2-3 ink sacs reserved","300 g arborio or carnaroli rice","1 medium onion (about 150 g), finely chopped","3 garlic cloves, finely minced","100 ml dry Dalmatian white wine (or Pošip)","1 litre warm fish stock (or water with 1 fish stock cube)","60 ml extra-virgin olive oil","30 g cold butter, cubed","2 tbsp fresh parsley, chopped","1/2 lemon, juice only","1 tsp fine sea salt","1/2 tsp ground black pepper"],"ro":["500 g calmari proaspeti sau decongelati, curatati, cu 2-3 saculeti de cerneala separati","300 g orez arborio sau carnaroli","1 ceapa medie (cca 150 g), tocata marunt","3 căței de usturoi, tocati marunt","100 ml vin alb sec dalmatian (sau Pošip)","1 litru fond de peste cald (sau apa cu 1 cub de fond de peste)","60 ml ulei de masline extravirgin","30 g unt rece, taiat cubulete","2 linguri patrunjel proaspat, tocat","1/2 lamaie, doar zeama","1 lingurita sare fina de mare","1/2 lingurita piper negru macinat"]},"howIsMade":{"hi":"स्क्विड को सावधानी से साफ करें: स्याही की थैलियाँ अखंड रखें थोड़े पानी वाले छोटे कटोरे में, फिर शरीर को 1 सेमी के छल्लों में और सूंडों को आधा काटें। चौड़े भारी पैन में 4 बड़े चम्मच जैतून का तेल मध्यम आंच पर गर्म करें, प्याज को 4-5 मिनट तक नर्म होने तक भूनें, फिर लहसुन को 1 मिनट और डालें। स्क्विड के छल्ले और सूंडें डालें, 2-3 मिनट तक हल्का अपारदर्शी होने तक भूनें, फिर वाइन डालकर पूरी तरह वाष्पीकृत होने दें (लगभग 2 मिनट)। चावल डालकर 1 मिनट हिलाएं ताकि वसा से लिपट जाए, फिर गर्म मछली शोरबा एक-एक कलछी डालते हुए लगातार हिलाएं — कुल 16-18 मिनट। आधे रास्ते में बचे शोरबा में स्याही की थैलियाँ तोड़ें और पैन में डालें — रिज़ोटो तुरंत गहरे काले रंग का हो जाता है और समुद्री गहराई पाता है। जब चावल अल डेंटे और मलाईदार हो जाए, थोड़ा शोरबा बचा हो, तब आंच बंद कर ठंडा मक्खन, बचा हुआ 2 बड़े चम्मच जैतून का तेल, नींबू का रस और अजमोद डालें। मंतेकातुरा के लिए 30 सेकंड जोर से हिलाएं, ढकें और 2 मिनट आराम दें। तुरंत गहरे प्लेटों में और अजमोद ऊपर डालकर, साथ में नींबू का एक टुकड़ा देकर परोसें।","en":"Clean the squid carefully: lift out the ink sacs intact into a small bowl with a splash of water, then cut the bodies into 1 cm rings and halve the tentacles. In a wide heavy pan, heat 4 tbsp olive oil over medium heat and sauté the onion for 4-5 minutes until soft, then add the garlic for 1 minute more. Add the squid rings and tentacles, sauté for 2-3 minutes until just opaque, then pour in the wine and let it evaporate completely (about 2 minutes). Add the rice and stir for 1 minute to coat with fat, then begin adding the hot fish stock one ladle at a time, stirring constantly for 16-18 minutes total. Halfway through, break the ink sacs into the remaining stock and pour it in — the risotto turns deep jet black instantly and gains a profound oceanic depth. When the rice is al dente and creamy with a little stock still pooling, kill the heat and add the cold butter, the remaining 2 tbsp olive oil, the lemon juice, and the parsley. Stir vigorously for 30 seconds for the mantecatura, then cover and rest for 2 minutes. Serve immediately in shallow bowls with extra parsley on top and a wedge of lemon alongside."}},{"id":60,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"hi":"मंगोलिया","en":"Mongolia","ro":"Mongolia"},"name":{"hi":"बूज़","en":"Buuz","ro":"Buuz"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"hi":["आटा: मैदा 300 ग्राम, धूल के लिए अतिरिक्त","गर्म पानी 150 मिली (लगभग 50°C)","बारीक नमक 1/2 छोटी चम्मच","भरावन: पिसा मेमने का मांस 400 ग्राम (या आधा मेमना, आधा गोमांस)","मध्यम प्याज 1 (लगभग 150 ग्राम), बारीक कटा","3 लहसुन की कलियां, बारीक कटी","सूरजमुखी तेल 2 बड़े चम्मच","जीरा पाउडर 1 छोटी चम्मच","बारीक समुद्री नमक 1 छोटी चम्मच","पिसी काली मिर्च 1/2 छोटी चम्मच","ठंडा पानी 50 मिली"],"en":["Dough: 300 g all-purpose flour, plus extra for dusting","150 ml warm water (about 50 C)","1/2 tsp fine salt","Filling: 400 g ground lamb (or half lamb, half beef)","1 medium onion (about 150 g), finely diced","3 garlic cloves, finely minced","2 tbsp sunflower oil","1 tsp ground cumin","1 tsp fine sea salt","1/2 tsp ground black pepper","50 ml cold water"],"ro":["Aluat: 300 g făină alba, plus extra pentru intins","150 ml apa calda (cca 50 C)","1/2 lingurita sare fina","Umplutura: 400 g carne de miel tocata (sau amestec miel-vita)","1 ceapa medie (cca 150 g), taiata marunt","3 căței de usturoi, tocati marunt","2 linguri ulei de floarea-soarelui","1 lingurita chimen macinat","1 lingurita sare fina de mare","1/2 lingurita piper negru macinat","50 ml apa rece"]},"howIsMade":{"hi":"आटा बनाएं: मैदा और नमक मिलाएं, गर्म पानी डालें और 5-6 मिनट तक गूंधें जब तक चिकना और लचीला न हो जाए। गीले कपड़े से ढककर 30 मिनट आराम करने दें। भरावन बनाएं: कटोरे में पिसा मांस, प्याज, लहसुन, तेल, जीरा, नमक, काली मिर्च और ठंडा पानी मिलाएं और हाथ से अच्छी तरह मिलाएं जब तक एकसार और थोड़ा चिपचिपा न हो जाए। आटे को 20-24 बराबर टुकड़ों (लगभग 20 ग्राम प्रत्येक) में बांटें और हर टुकड़े को लगभग 10 सेमी व्यास की पतली गोल रोटी बेलें, केंद्र को किनारों से थोड़ा मोटा रखें। हर गोल के बीच में 1 भरा हुआ बड़ा चम्मच (लगभग 25 ग्राम) भरावन रखें। किनारों को भरावन के चारों ओर उठाएं और ऊपर से सिलवटें बनाकर बंद करें, बीच में एक छोटा भाप का छेद छोड़ें — मंगोलियाई पारंपरिक आकार। स्टीमर को बेकिंग पेपर से लगाएं और बुज को 2 सेमी दूरी पर एक परत में रखें। वॉक में पानी जोर से उबालें, ऊपर स्टीमर रखें और 20-22 मिनट भाप दें जब तक आटा पक न जाए और भरावन अंदर से गुलाबी न रहे। तुरंत परोसें।","en":"Make the dough: mix flour and salt, pour in the warm water, and knead for 5-6 minutes until smooth and elastic. Cover with a damp cloth and rest for 30 minutes. Make the filling: combine the lamb, onion, garlic, oil, cumin, salt, pepper, and cold water in a bowl and mix well with your hands until evenly combined and slightly sticky. Divide the dough into 20-24 equal pieces (about 20 g each) and roll each into a thin round about 10 cm across, keeping the centre slightly thicker than the edges. Place 1 heaped tablespoon (about 25 g) of filling in the centre of each round. Lift the edges up around the filling and pleat them together at the top, leaving a small steam hole in the centre — the classic Mongolian shape. Line a bamboo steamer with parchment paper or cabbage leaves and arrange the buuz in a single layer with 2 cm between each. Fill a wok or wide pot with water and bring to a rolling boil; set the steamer basket over the boiling water and steam for 20-22 minutes until the dough is cooked through and the filling is no longer pink inside. Serve immediately."}},{"id":61,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"hi":"पाकिस्तान","en":"Pakistan","ro":"Pakistan"},"name":{"hi":"बिरयानी","en":"Biryani","ro":"Biryani"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["बिना हड्डी की चिकन जांघें 800 ग्राम (या मेमने का कंधा), बड़े टुकड़ों में कटे हुए, हो सके तो हड्डी के साथ","फुल-क्रीम सादा दही 200 ग्राम, फेंटा हुआ","अदरक-लहसुन पेस्ट 2 बड़े चम्मच","गरम मसाला 1 छोटा चम्मच","लाल मिर्च पाउडर 1 छोटा चम्मच","हल्दी 1/2 छोटा चम्मच","नमक 1 छोटा चम्मच","गुनगुना दूध 3 बड़े चम्मच + एक चुटकी केसर के रेशे","बासमती चावल 400 ग्राम","पानी 2.5 लीटर (चावल को आधा पकाने के लिए)","घी 4 बड़े चम्मच","हरी इलायची 4 दाने","काली बड़ी इलायची 2 दाने","दालचीनी 1 टुकड़ा","लौंग 6 दाने","तेज पत्ता 2 पत्ते","बड़े प्याज 2, पतले स्लाइस में कटे हुए","मध्यम टमाटर 2, कद्दूकस किए हुए","ताजा पुदीना कटा हुआ 2 बड़े चम्मच","ताजा हरा धनिया कटा हुआ 2 बड़े चम्मच","अतिरिक्त घी 1 बड़ा चम्मच, पिघला हुआ (छिड़कने के लिए)","परोसने के लिए: ठंडा दही का रायता, नींबू के टुकड़े"],"en":["800g boneless chicken thighs (or lamb shoulder), cut into large pieces, bone-in if possible","200g plain whole-milk yoghurt, whisked","2 tbsp ginger-garlic paste","1 tsp garam masala","1 tsp chilli powder","1/2 tsp turmeric","1 tsp salt","3 tbsp warm milk + a pinch of saffron threads","400g basmati rice","2.5 litres water (for par-boiling the rice)","4 tbsp ghee","4 green cardamom pods","2 black cardamom pods","1 cinnamon stick","6 cloves","2 bay leaves","2 large onions, thinly sliced","2 medium tomatoes, grated","2 tbsp chopped fresh mint","2 tbsp chopped fresh coriander","1 tbsp extra ghee, melted (to drizzle)","To serve: cold yoghurt raita, lemon wedges"],"ro":["800 g pulpe de pui dezosate (sau spata de miel), taiate cuburi mari, cu os daca este posibil","200 g iaurt gras de vaca, batut","2 linguri pasta de ghimbir-usturoi","1 lingurita garam masala","1 lingurita pudra de chili","1/2 lingurita turmeric","1 lingurita sare","3 linguri lapte cald + un varf de fire de sofran","400 g orez basmati","2,5 l apa (pentru fierberea partiala a orezului)","4 linguri ghee","4 capsule cardamom verde","2 capsule cardamom negru","1 bat de scortisoara","6 cuișoare","2 foi de dafin","2 cepe mari, taiate solzi subtiri","2 rosii medii, rase","2 linguri menta proaspata, tocata","2 linguri coriandru proaspat, tocat","1 lingura ghee suplimentar, topit (pentru stropit)","Pentru servit: raita de iaurt rece, felii de lamaie"]},"howIsMade":{"hi":"800 ग्राम चिकन (या मेमना) को 200 ग्राम फेंटे हुए दही, 2 बड़े चम्मच अदरक-लहसुन पेस्ट, 1 छोटा चम्मच गरम मसाला, 1 छोटा चम्मच लाल मिर्च पाउडर, 1/2 छोटा चम्मच हल्दी, 1 छोटा चम्मच नमक और 3 बड़े चम्मच गुनगुने दूध में भिगोए केसर के कुछ रेशों के साथ मिलाएं; ढककर कम से कम 1 घंटा, आदर्श रूप से फ्रिज में 4 घंटे मेरिनेट करें. एक मोटे तले की हांडी में मध्यम आंच पर 4 बड़े चम्मच घी या तेल पिघलाएं; जब चमकने लगे तो 4 हरी इलायची, 2 बड़ी इलायची, 1 दालचीनी, 4 लौंग और 1 तेज पत्ता डालें और 30 सेकंड भुनने दें जब तक हल्की चटकने न लगें. 2 बड़े प्याज पतले कटे हुए डालें और लगातार चलाते हुए 12-15 मिनट तक भूनें जब तक गहरे भूरे और कुरकुरे न हो जाएं; आधा हिस्सा गार्निश के लिए किचन पेपर पर निकाल लें और बाकी सुगंधित तेल के साथ हांडी में रहने दें. मेरिनेट किया हुआ गोश्त 2 कद्दूकस किए टमाटर के साथ हांडी में डालें और मध्यम आंच पर 8-10 मिनट चलाते हुए पकाएं जब तक दही टूटकर तेल किनारों पर न आ जाए; आंच धीमी करके ढककर और 15 मिनट पकाएं जब तक गोश्त लगभग नरम और ग्रेवी गाढ़ी न रहे. इस बीच 400 ग्राम बासमती चावल को साफ पानी आने तक धोकर 30 मिनट भिगोएं; एक बड़े बर्तन में 2.5 लीटर पानी, 2 छोटे चम्मच नमक, 3 इलायची, 1 दालचीनी और 2 तेज पत्ते के साथ उबाल लें, चावल और कुछ बूंदें तेल डालकर ठीक 5-6 मिनट पकाएं जब तक चावल 70% पके — बीच में अब भी सख्त हों; तुरंत छान लें. गोश्त मसाले के ऊपर आधा छाना हुआ चावल फैलाएं, उसपर आधा तला प्याज, 2 बड़े चम्मच कटा पुदीना और 2 बड़े चम्मच धनिया छिड़कें, फिर बचा हुआ चावल परत लगाएं; ऊपर से 4 बड़े चम्मच गुनगुना केसर वाला दूध और 2 बड़े चम्मच पिघला घी डालें और बाकी प्याज, पुदीना और धनिया से सजाएं. हांडी को कसे ढक्कन से बंद करें (या ऐल्युमिनियम फॉयल से ढककर ढक्कन ऊपर से दबाएं), सबसे धीमी आंच पर रखें, बेहतर हो तो तवे या लोहे की प्लेट पर रखकर 25 मिनट तक दम पकाएं बिना ढक्कन उठाए — फंसी हुई भाप चावल और गोश्त को एक साथ पका देती है. आंच बंद करें और बंद हांडी को 10 मिनट आराम करने दें; ढक्कन खोलें, कांटे से किनारे से अंदर की ओर हल्के से चावल और गोश्त की परतें मिलाते हुए फुलाएं और तुरंत ठंडे दही रायते और नींबू के टुकड़ों के साथ परोसें.","en":"Mix 800 g chicken (or lamb) with 200 g whisked yoghurt, 2 tbsp ginger-garlic paste, 1 tsp garam masala, 1 tsp chilli powder, 1/2 tsp turmeric, 1 tsp salt and a pinch of saffron threads soaked in 3 tbsp warm milk; cover and marinate at least 1 hour, ideally 4 hours in the fridge. Melt 4 tbsp ghee or oil in a heavy-bottomed pot over medium heat; when it shimmers, add 4 green cardamom pods, 2 black cardamom pods, 1 cinnamon stick, 4 cloves and 1 bay leaf and let them bloom for 30 seconds until they crackle lightly. Add 2 large onions sliced thin and fry for 12-15 minutes, stirring often, until deep brown and crisp; lift out half onto kitchen paper for garnish and leave the rest in the pot with the aromatic oil. Slide the marinated meat into the pot with 2 grated tomatoes and cook 8-10 minutes over medium heat, stirring until the yoghurt breaks and the oil rises to the edges; lower the heat and simmer covered another 15 minutes until the meat is almost tender but the sauce stays thick. Meanwhile rinse 400 g basmati rice until the water runs clear and soak for 30 minutes; bring 2.5 litres of water to the boil with 2 tsp salt, 3 cardamom pods, 1 cinnamon stick and 2 bay leaves, slip in the rice with a few drops of oil and cook for exactly 5-6 minutes until the grains are 70% done — still firm in the centre; drain at once. Spread half of the drained rice over the meat masala, scatter half of the fried onions, 2 tbsp chopped mint and 2 tbsp coriander, then layer the remaining rice on top; drizzle with 4 tbsp warm saffron milk and 2 tbsp melted ghee, and finish with the remaining onions, mint and coriander. Seal the pot with a tight lid (or cover with foil and press the lid down), set it on the lowest possible flame, ideally over a heat diffuser or a cast-iron tava, and dum cook for 25 minutes without lifting the lid — the trapped steam finishes the rice and meat together. Turn off the heat and let the sealed pot rest for 10 minutes; open, gently fluff from the side inwards to fold the meat and rice layers, and serve straight away with cold yoghurt raita and lemon wedges."},"timeMins":{"total":105,"active":50}},{"id":62,"servings":4,"tipType":"def","pairingsType":"middle-eastern","origin":{"hi":"ट्यूनीशिया","en":"Tunisia","ro":"Tunisia"},"name":{"hi":"ब्रिक","en":"Brik","ro":"Brik"},"category":{"hi":"नाश्ता","en":"Snack","ro":"Gustare"},"ingredients":{"hi":["ब्रिक पेस्ट्री (या मालसुका/उआर्का) के 4 शीट, लगभग 30 सेमी व्यास (या स्प्रिंग रोल रैपर विकल्प के रूप में)","4 बड़े अंडे (प्रत्येक ब्रिक के लिए 1)","160 ग्राम जैतून के तेल में डिब्बाबंद ट्यूना, अच्छी तरह छाना हुआ","1 छोटा प्याज (लगभग 80 ग्राम), बारीक कटा","3 बड़े चम्मच छोटे केपर, धोकर मोटे-मोटे काटे","20 ग्राम फ्लैट-लीफ पार्सले, बारीक कटी","1/2 छोटी चम्मच जीरा पाउडर","1/2 छोटी चम्मच बारीक समुद्री नमक","1/4 छोटी चम्मच लाल मिर्च पाउडर या हरीसा पेस्ट","500 मिली वनस्पति तेल (तलने के लिए)","1 नींबू, 4 टुकड़ों में काटा, परोसने के लिए"],"en":["4 sheets of brik pastry (or malsouka/ouarka), about 30 cm in diameter (or spring roll wrappers as substitute)","4 large eggs (1 per brik)","160 g canned tuna in olive oil, well drained","1 small onion (about 80 g), finely diced","3 tbsp small capers, rinsed and roughly chopped","20 g flat-leaf parsley, finely chopped","1/2 tsp ground cumin","1/2 tsp fine sea salt","1/4 tsp cayenne pepper or harissa paste","500 ml vegetable oil for deep-frying","1 lemon, cut into 4 wedges, to serve"],"ro":["4 foi de brik (sau malsouka/ouarka), cca 30 cm diametru (sau foi de spring roll ca substitut)","4 oua mari (1 pe brik)","160 g ton la conserva in ulei de masline, bine scurs","1 ceapa mica (cca 80 g), taiata marunt","3 linguri capere mici, clatite si tocate grosier","20 g patrunjel plat, tocat marunt","1/2 lingurita chimen macinat","1/2 lingurita sare fina de mare","1/4 lingurita ardei iute macinat sau harissa","500 ml ulei vegetal pentru prajit adanc","1 lamaie, taiata in 4, pentru servire"]},"howIsMade":{"hi":"एक कटोरे में छाने हुए ट्यूना, प्याज, केपर, पार्सले, जीरा, नमक और लाल मिर्च मिलाकर भरावन बनाएं। एक गहरे चौड़े पैन में सब्जी तेल 3-4 सेमी गहराई में डालें और 175°C तक गर्म करें। एक ब्रिक पेस्ट्री शीट को साफ सतह पर फैलाएं और ट्यूना भरावन का एक चौथाई हिस्सा नीचे की आधी शीट पर रखें, बीच में हल्का गड्ढा बनाएं। गड्ढे में 1 अंडा तोड़ें। तेजी से काम करते हुए पेस्ट्री को आधा मोड़कर अर्ध-चंद्र आकार बनाएं, किनारों को कसकर दबाएं ताकि अंडा बाहर न निकले। ब्रिक को सावधानी से गर्म तेल में डालें और चौड़े स्पैचुला से एक बार पलटते हुए प्रत्येक तरफ 1.5-2 मिनट तक गहरे सुनहरे और कुरकुरे होने तक तलें। छेदवाले कलछे से निकालें और 30 सेकंड किचन पेपर पर रखें। तुरंत परोसें — जर्दी बहती हुई या हल्की जमी हुई होनी चाहिए और पेस्ट्री कुरकुरी चटकदार। ऊपर से नींबू निचोड़ें।","en":"Combine the drained tuna, onion, capers, parsley, cumin, salt, and cayenne in a bowl and mix well to make the filling. Pour the vegetable oil into a deep, wide pan to a depth of 3-4 cm and heat to 175°C. Lay a brik pastry sheet flat on a clean surface and spoon a quarter of the tuna filling onto the lower half, creating a slight hollow in the centre. Crack 1 egg into the hollow. Working quickly, fold the pastry in half to form a half-moon, pressing the edges firmly together to seal and prevent the egg from escaping. Carefully slide the brik into the hot oil and fry for 1.5-2 minutes per side until deep golden and crisp all over, flipping once with a wide spatula. Lift out with a slotted spoon and drain on paper towels for 30 seconds. Serve immediately — the yolk should be runny to lightly set and the pastry crackling crisp. Squeeze a lemon wedge over the top."}},{"id":63,"servings":4,"tipType":"def","pairingsType":"def","origin":{"hi":"जॉर्जिया","en":"Georgia","ro":"Georgia"},"name":{"hi":"खाचापुरी","en":"Khachapuri","ro":"Khachapuri"},"category":{"hi":"नाश्ता","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"hi":["500 ग्राम मैदा, और थोड़ा बेलने के लिए","7 ग्राम इंस्टेंट यीस्ट (1 पैकेट)","1 छोटा चम्मच चीनी","1 छोटा चम्मच बारीक नमक","250 मिलीलीटर गुनगुना पानी (लगभग 40°C)","2 बड़े चम्मच जैतून का तेल","400 ग्राम सुलुगुनी या मोज़ेरेला पनीर, मोटा कद्दूकस किया","200 ग्राम फ़ेटा पनीर, टुकड़े किया","4 बड़े अंडे (प्रत्येक खाचापुरी के लिए 1)","40 ग्राम बिना नमक का मक्खन, 4 बराबर टुकड़ों में काटा"],"en":["500 g plain flour (all-purpose), plus extra for dusting","7 g instant yeast (1 sachet)","1 tsp caster sugar","1 tsp fine sea salt","250 ml warm water (about 40°C / 105°F)","2 tbsp olive oil","400 g sulguni or mozzarella, coarsely grated","200 g feta cheese, crumbled","4 large eggs (1 per khachapuri)","40 g unsalted butter, cut into 4 equal pieces"],"ro":["500 g făină albă, plus extra pentru pudrare","7 g drojdie instant (1 plic)","1 linguriță zahăr","1 linguriță sare fină de mare","250 ml apă caldă (aproximativ 40°C)","2 linguri ulei de măsline","400 g suluguni sau mozzarella, ras grosier","200 g brânză feta, sfărâmată","4 ouă mari (câte 1 pentru fiecare khachapuri)","40 g unt nesărat, tăiat în 4 bucăți egale"]},"howIsMade":{"hi":"एक बड़े बर्तन में मैदा, यीस्ट, चीनी और नमक मिलाएं, गुनगुना पानी और जैतून का तेल डालकर आटा गूंधें, फिर हल्के आटे लगी सतह पर 8-10 मिनट तक गूंधें जब तक आटा चिकना और थोड़ा चिपचिपा न हो जाए। गेंद का आकार दें, तेल लगे बर्तन में रखें, गीले कपड़े से ढकें और गर्म जगह पर 1 घंटे के लिए रखें जब तक आटा दोगुना न हो जाए। आटा फूलने के दौरान कद्दूकस किए सुलुगुनी (या मोज़ेरेला) और टुकड़े किए फ़ेटा को एक बर्तन में मिलाएं; ओवन को 250°C पर गर्म करें और उसमें एक भारी बेकिंग ट्रे या पिज़्ज़ा स्टोन रखें। फूले हुए आटे को 4 बराबर हिस्सों में बाँटें और प्रत्येक को हल्के आटे लगी सतह पर लगभग 25 x 15 सेमी के अंडाकार आकार में बेलें। लंबे किनारों को 3 सेमी अंदर मोड़कर रोल करें जिससे उठी हुई किनारी बने, फिर दोनों छोटे सिरों को मजबूती से बंद करके नाव का आकार बनाएं। नावों को बेकिंग पेपर पर रखें, प्रत्येक को पनीर के मिश्रण के एक-चौथाई से पूरा भरें, फिर गर्म ट्रे पर रखकर 12-14 मिनट तक बेक करें जब तक क्रस्ट सुनहरा न हो जाए और पनीर उबलने लगे और हल्का भूरा हो जाए। ओवन से निकालें, प्रत्येक भरावन के बीच में एक छोटा गड्ढा बनाएं, हर एक में 1 अंडा तोड़ें और 3-4 मिनट के लिए वापस ओवन में रखें जब तक अंडे का सफेद भाग जम जाए लेकिन जर्दी बहती रहे। प्रत्येक अंडे पर मक्खन का एक टुकड़ा रखें और तुरंत परोसें — रोटी की किनारी के टुकड़े तोड़कर पिघले पनीर और जर्दी में डुबोकर खाएं।","en":"Mix the flour, yeast, sugar, and salt in a large bowl, add the warm water and olive oil and stir to a rough dough, then knead on a lightly floured surface for 8-10 minutes until smooth and slightly tacky. Shape into a ball, place in an oiled bowl, cover with a damp cloth, and leave in a warm place for 1 hour until doubled in size. While the dough rises, mix the grated sulguni (or mozzarella) and crumbled feta together in a bowl; heat the oven to 250°C (230°C fan) with a heavy baking tray or pizza stone inside. Divide the risen dough into 4 equal pieces and roll each on a lightly floured surface into an oval about 25 x 15 cm. Fold the long edges inward by 3 cm and roll them up into a thick raised border, then pinch both short ends firmly together to form a boat shape. Arrange the boats on baking parchment, fill each cavity completely with a quarter of the cheese mixture, then slide onto the hot tray and bake for 12-14 minutes until the crust is golden and the cheese is bubbling and lightly browned. Remove from the oven, press a small hollow in the centre of each cheese filling, crack 1 egg into each hollow, and return to the oven for 3-4 minutes until the white is just set but the yolk remains runny. Place a piece of butter on top of each egg and serve immediately — tear strips of the border and dip into the melted cheese and yolk."}},{"id":64,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"hi":"दक्षिण अफ्रीका","en":"South Africa","ro":"Africa de Sud"},"name":{"hi":"बोबोटि","en":"Bobotie","ro":"Bobotie"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["750 ग्राम दुबला गोमांस या मेमने का कीमा","2 मध्यम प्याज (लगभग 300 ग्राम), बारीक कटा हुआ","2 स्लाइस सफेद ब्रेड (लगभग 60 ग्राम), किनारे हटाए","125 मिलीलीटर फुल-फैट दूध, विभाजित","2 बड़े अंडे","50 ग्राम किशमिश (सुल्ताना)","30 ग्राम सूखी खुबानी (लगभग 6), बारीक कटी हुई","2 बड़े चम्मच खुबानी जैम या मीठी चटनी","2 बड़े चम्मच माइल्ड करी पाउडर","1 छोटा चम्मच हल्दी पाउडर","2 बड़े चम्मच वनस्पति तेल","1 छोटा चम्मच बारीक नमक","1/2 छोटा चम्मच काली मिर्च पाउडर","4 ताजे या सूखे तेज पत्ते"],"en":["750 g lean beef or lamb mince","2 medium onions (about 300 g total), finely diced","2 slices white bread (about 60 g), crusts removed","125 ml whole milk, divided","2 large eggs","50 g sultanas (golden raisins)","30 g dried apricots (about 6), finely chopped","2 tbsp apricot jam or sweet chutney","2 tbsp mild curry powder","1 tsp ground turmeric","2 tbsp vegetable oil","1 tsp fine sea salt","1/2 tsp ground black pepper","4 fresh or dried bay leaves"],"ro":["750 g carne tocată de vită sau miel, slabă","2 cepe medii (aproximativ 300 g), fin tocate","2 felii pâine albă (aproximativ 60 g), fără coajă","125 ml lapte integral, împărțit","2 ouă mari","50 g stafide galbene (sultane)","30 g caise uscate (aproximativ 6 bucăți), fin tocate","2 linguri gem de caise sau chutney dulce-picant","2 linguri pudră de curry blând","1 linguriță turmeric măcinat","2 linguri ulei vegetal","1 linguriță sare fină de mare","1/2 linguriță piper negru măcinat","4 foi de dafin proaspete sau uscate"]},"howIsMade":{"hi":"ब्रेड को 60 मिलीलीटर दूध में 5 मिनट के लिए भिगोएं, फिर निचोड़ें और एक छोटे बर्तन में टुकड़े कर लें। एक बड़े फ्राइंग पैन में तेल गरम करें, प्याज डालें और मध्यम-तेज आंच पर 8-10 मिनट तक हिलाते हुए पकाएं जब तक नरम और सुनहरा न हो जाए। करी पाउडर और हल्दी डालें और 1 मिनट खुशबू आने तक भूनें, फिर कीमा डालें और टुकड़े करते हुए 8-10 मिनट पकाएं जब तक भूरा न हो जाए और तरल न सूख जाए। आंच से हटाएं और भीगी ब्रेड, किशमिश, सूखी खुबानी, जैम, नमक और काली मिर्च मिलाएं। ओवन को 180°C पर गर्म करें और एक मध्यम बेकिंग डिश (लगभग 25 x 20 सेमी) में थोड़ा तेल लगाएं। मांस का मिश्रण डिश में डालें, समान परत में दबाएं और तेज पत्ते सतह में लगाएं। अंडों को बचे हुए 65 मिलीलीटर दूध और एक चुटकी नमक के साथ चिकना होने तक फेंटें, फिर मांस के ऊपर समान रूप से डालें। 35-40 मिनट बेक करें जब तक कस्टर्ड टॉपिंग सेट और सुनहरी-भूरी न हो जाए। 5 मिनट आराम दें फिर पीले चावल और चटनी के साथ परोसें।","en":"Soak the bread in 60 ml of the milk for 5 minutes, then squeeze out the excess liquid and crumble into a small bowl. Heat the oil in a large frying pan over medium-high heat, add the onions and cook, stirring, for 8-10 minutes until soft and golden. Add the curry powder and turmeric and stir for 1 minute until fragrant, then add the mince and cook for 8-10 minutes, breaking up any lumps, until browned and all liquid has evaporated. Remove from the heat and mix in the soaked bread, sultanas, dried apricots, apricot jam, salt, and pepper until evenly combined. Heat the oven to 180°C (160°C fan) and lightly grease a medium baking dish (about 25 x 20 cm). Transfer the meat mixture into the dish, press it into an even layer, and tuck the bay leaves into the surface. Beat the eggs with the remaining 65 ml milk and a pinch of salt until smooth, then pour evenly over the meat. Bake for 35-40 minutes until the custard topping is set and golden brown with no wobble in the centre. Rest for 5 minutes before serving with yellow rice, chutney, and sambals."}},{"id":65,"servings":4,"tipType":"fish","pairingsType":"latin","origin":{"hi":"पेरू","en":"Peru","ro":"Peru"},"name":{"hi":"सेविचे","en":"Ceviche","ro":"Ceviche"},"category":{"hi":"नाश्ता","en":"Snack","ro":"Gustare"},"ingredients":{"hi":["700 ग्राम बहुत ताज़ी सफेद मछली की फिलेट (सी बास, एकमात्र, या हलिबट), बिना त्वचा और हड्डी","180 मिलीलीटर ताजा नींबू का रस (लगभग 8-10 नींबू), स्वादानुसार अधिक","1 छोटा लाल प्याज (लगभग 150 ग्राम), आधा काटकर पतले अर्धचंद्र में","1-2 ají amarillo मिर्च या 1 jalapeño, बीज निकालकर बारीक कटा","1 लहसुन की कली, बारीक कसा हुआ","1 छोटा चम्मच ताजा अदरक (लगभग 1 सेमी), बारीक कसा हुआ","30 ग्राम ताजा धनिया, पत्तियां और पतले तने, मोटा कटा","1 छोटा चम्मच बारीक नमक","1/4 छोटा चम्मच सफेद काली मिर्च पाउडर","2 भुट्टे, उबालकर 5 सेमी के टुकड़ों में काटे","2 छोटे शकरकंद (लगभग 400 ग्राम), नरम होने तक उबाले, छीले और कटे"],"en":["700 g very fresh white fish fillets (sea bass, sole, or halibut), skin and bones removed","180 ml fresh lime juice (about 8-10 limes), plus more to taste","1 small red onion (about 150 g), halved and thinly sliced into half-moons","1-2 ají amarillo chillies or 1 jalapeño, deseeded and finely diced","1 garlic clove, finely grated","1 tsp fresh ginger (about 1 cm piece), finely grated","30 g fresh coriander (cilantro), leaves and fine stems, roughly chopped","1 tsp fine sea salt","1/4 tsp ground white pepper","2 ears of corn, boiled and cut into 5 cm rounds","2 small sweet potatoes (about 400 g), boiled until tender, peeled and sliced"],"ro":["700 g file de pește alb foarte proaspăt (biban de mare, limbă sau halibut), fără piele și oase","180 ml suc proaspăt de lime (aproximativ 8-10 lime-uri), plus extra după gust","1 ceapă roșie mică (aproximativ 150 g), tăiată felii subțiri în jumătate de lună","1-2 ardei ají amarillo sau 1 jalapeño, fără semințe, fin tocați","1 căței de usturoi, fin ras","1 linguriță ghimbir proaspăt (aproximativ 1 cm), fin ras","30 g coriandru proaspăt, frunze și tulpini subțiri, grosier tocat","1 linguriță sare fină de mare","1/4 linguriță piper alb măcinat","2 știuleți de porumb, fierți și tăiați în rondele de 5 cm","2 cartofi dulci mici (aproximativ 400 g), fierți, curățați și feliați"]},"howIsMade":{"hi":"मछली को किचन टॉवल से थपथपाएं, 2 सेमी के टुकड़ों में काटें और बची हुई हड्डियां निकालें, फिर गैर-प्रतिक्रियाशील कटोरे (कांच या मिट्टी) में रखें। नमक और सफेद काली मिर्च डालकर मिलाएं। लाल प्याज, मिर्च, लहसुन और अदरक डालकर धीरे-धीरे मिलाएं। नींबू का रस डालें — यह मछली को लगभग ढकना चाहिए — फिर धीरे से हिलाएं और मछली को जितना हो सके दबाएं। ढककर 10-15 मिनट के लिए फ्रिज में रखें, आधे समय में एक बार हिलाएं। जब प्रत्येक टुकड़े का बाहरी हिस्सा अपारदर्शी और हल्का कठोर हो जाए लेकिन केंद्र थोड़ा पारदर्शी रहे — यह क्लासिक पेरुवियन शैली है। नमक और नींबू का रस स्वाद के अनुसार समायोजित करें। अधिकांश धनिया मिलाएं, सजावट के लिए थोड़ा बचाएं। ठंडे बाउल में भुट्टे के टुकड़ों और शकरकंद के स्लाइस के साथ तुरंत परोसें और बचा हुआ धनिया ऊपर छिड़कें।","en":"Pat the fish dry with paper towels and cut into 2 cm cubes, removing any remaining pin bones, then place in a non-reactive bowl (glass or ceramic). Season with the salt and white pepper and toss to coat. Add the red onion, chilli, garlic, and ginger and mix gently. Pour over the lime juice — it should nearly cover the fish — then stir gently and press the fish down to submerge it as much as possible. Cover and refrigerate for 10-15 minutes, stirring once halfway through, until the outside of each cube is opaque and just firm to the touch while the very centre remains slightly translucent — the classic Peruvian style, not fully cooked through. Taste and adjust salt and lime juice. Stir in most of the coriander, reserving a little for garnish. Serve immediately in chilled bowls alongside the corn rounds and sweet potato slices, with the remaining coriander scattered over the top."}},{"id":66,"servings":8,"tipType":"korean","pairingsType":"korean","origin":{"hi":"दक्षिण कोरिया","en":"South Korea","ro":"Coreea de Sud"},"name":{"hi":"किमची","en":"Kimchi","ro":"Kimchi"},"category":{"hi":"साइड डिश","en":"Side dish","ro":"Garnitură"},"ingredients":{"hi":["1 बड़ी नापा पत्तागोभी (लगभग 2 किलो)","3 बड़े चम्मच समुद्री नमक (बिना आयोडीन)","4 बड़े चम्मच गोचुगारु (कोरियाई लाल मिर्च पाउडर)","5 लहसुन की कलियाँ, बारीक कटी","1 छोटा चम्मच ताजा अदरक, कसा हुआ","1 बड़ा चम्मच मछली की चटनी (शाकाहारी के लिए सोया सॉस)","1 छोटा चम्मच चीनी","6 हरी प्याज, 3 सेमी के टुकड़ों में","1 मध्यम गाजर, जुलियन में काटी"],"en":["1 large napa cabbage (about 2 kg)","3 tbsp sea salt (non-iodised)","4 tbsp gochugaru (Korean red pepper flakes)","5 cloves garlic, finely minced","1 tsp fresh ginger, grated","1 tbsp fish sauce (or soy sauce for vegan)","1 tsp sugar","6 spring onions, cut into 3cm pieces","1 medium carrot, julienned"],"ro":["1 varză napa mare (aprox. 2 kg)","3 linguri sare de mare (fără iod)","4 linguri gochugaru (fulgi de ardei coreean)","5 căței de usturoi, tocați mărunt","1 linguriță ghimbir proaspăt, ras","1 lingură sos de pește (sau sos de soia pentru variantă vegană)","1 linguriță zahăr","6 cepe verzi, tăiate în bucăți de 3 cm","1 morcov mediu, julien"]},"howIsMade":{"hi":"नापा पत्तागोभी को लंबाई में चार टुकड़ों में काटें, फिर चौड़ाई में 5 सेमी के टुकड़ों में काटें। समुद्री नमक डालकर 2-3 मिनट हाथों से मलें, 1-2 घंटे रखें (बीच-बीच में पलटते रहें) जब तक मुरझा न जाए और पानी न छोड़ दे। ठंडे पानी में 2-3 बार अच्छी तरह धोएं, छानें और अच्छे से निचोड़ें; हल्की नमकीन स्वाद होनी चाहिए। गोचुगारु, लहसुन, अदरक, मछली की चटनी और चीनी को एक बर्तन में मिलाएं; हरी प्याज और गाजर डालें। छानी हुई पत्तागोभी मिश्रण में डालें और (दस्ताने पहनकर) हाथों से अच्छी तरह मिलाएं जब तक हर टुकड़ा लाल पेस्ट से ढक न जाए। साफ 1 लीटर जार में कसकर भरें, 3-4 सेमी जगह छोड़ें; 1-2 दिन कमरे के तापमान पर रखें फिर फ्रिज में रखें — 3-5 दिन में तैयार।","en":"Quarter the napa cabbage lengthwise, then cut crosswise into 5cm pieces. Toss with sea salt and massage 2–3 minutes, let sit 1–2 hours turning occasionally until the cabbage has wilted and released water. Rinse the cabbage thoroughly in cold water 2–3 times, drain and squeeze firmly to remove excess moisture; it should taste pleasantly salty — rinse once more if too salty. Mix gochugaru, garlic, ginger, fish sauce and sugar in a bowl; add spring onions and carrot. Add drained cabbage to the paste and mix thoroughly with your hands (wear gloves) — every piece should be evenly coated in red paste. Pack tightly into clean 1-litre jars, press down firmly to eliminate air pockets, leaving 3–4 cm of headspace; leave at room temperature for 1–2 days, then refrigerate — kimchi is ready in 3–5 days and best after 1 week."}},{"id":67,"servings":4,"tipType":"meat","timeMins":{"total":285,"active":60},"pairingsType":"vietnamese","origin":{"hi":"वियतनाम","en":"Vietnam","ro":"Vietnam"},"name":{"hi":"बान्ह मी","en":"Banh Mi","ro":"Banh Mi"},"category":{"hi":"नाश्ता","en":"Snack","ro":"Gustare"},"ingredients":{"hi":["4 छोटी बागेट (लगभग 20 सेमी प्रत्येक), लंबाई में आधी काटी","400 ग्राम सूअर का मांस टेंडरलॉइन, पतले टुकड़ों में (लगभग 5 मिमी)","2 बड़े चम्मच सोया सॉस","1 बड़ा चम्मच मछली की चटनी","1 छोटा चम्मच तिल का तेल + 1 छोटा चम्मच चीनी + 1/4 छोटा चम्मच काली मिर्च (मैरिनेड के लिए)","2 मध्यम गाजर (लगभग 200 ग्राम), छीलकर जूलियन में काटी","100 ग्राम डाइकन, छीलकर जूलियन में (या अतिरिक्त गाजर)","3 बड़े चम्मच चावल का सिरका","1 बड़ा चम्मच चीनी + 1/2 छोटा चम्मच बारीक नमक (अचार के लिए)","60 ग्राम चिकन लिवर पाते","4 बड़े चम्मच मेयोनेज़","1 बड़ा खीरा, पतले स्टिक में काटा","2 jalapeño या लाल मिर्च, पतले छल्लों में","20 ग्राम ताजा धनिया, टहनियां"],"en":["4 small baguettes or demi-baguettes (about 20 cm each), halved lengthwise","400 g pork tenderloin, thinly sliced (about 5 mm)","2 tbsp soy sauce","1 tbsp fish sauce","1 tsp sesame oil + 1 tsp sugar + 1/4 tsp black pepper (marinade)","2 medium carrots (about 200 g), peeled and julienned","100 g daikon, peeled and julienned (or extra carrot)","3 tbsp rice vinegar","1 tbsp sugar + 1/2 tsp fine salt (for pickling)","60 g chicken liver pâté","4 tbsp mayonnaise","1 large cucumber, cut into thin batons","2 jalapeños or red chillies, thinly sliced","20 g fresh coriander, sprigs"],"ro":["4 baghetele mici (de circa 20 cm), tăiate pe lungime","400 g mușchi de porc, tăiat felii subțiri (circa 5 mm)","2 linguri sos de soia","1 lingură sos de pește","1 linguriță ulei de susan + 1 linguriță zahăr + 1/4 linguriță piper negru (pentru marinadă)","2 morcovi medii (aproximativ 200 g), curățați și tăiați julienne","100 g daikon (ridiche asiatică), curățat și juliennat (sau morcov în plus)","3 linguri oțet de orez","1 lingură zahăr + 1/2 linguriță sare (pentru murat)","60 g pate de ficat de pui","4 linguri maioneză","1 castravete mare, tăiat bețe subțiri","2 jalapeño sau ardei roșii, tăiați rondele","20 g coriandru proaspăt, crenguțe"]},"howIsMade":{"hi":"गाजर और डाइकन को चावल के सिरके, चीनी और नमक के साथ मिलाएं और कम से कम 20 मिनट (या फ्रिज में 4 घंटे तक) के लिए अचार बनने दें जब तक हल्का नरम लेकिन अभी भी कुरकुरा हो। एक बर्तन में सोया सॉस, मछली की चटनी, तिल का तेल, चीनी और काली मिर्च मिलाएं, सूअर के मांस के टुकड़े डालें और कोट करें; कमरे के तापमान पर 15-20 मिनट मैरिनेट करें। एक भारी पैन को तेज आंच पर धुआं निकलने तक गर्म करें, मांस को 2-3 बैचों में एक परत में डालें और प्रत्येक तरफ 1-2 मिनट पकाएं जब तक किनारे कैरेमलाइज़ और सुनहरे न हों। बागेट को 200°C ओवन में 4-5 मिनट के लिए बाहर से कुरकुरा होने तक भूनें। कटी हुई सतहों पर पाते और मेयोनेज़ लगाएं। गर्म मांस के टुकड़े, निकाले हुए अचार की गाजर और डाइकन, खीरे की छड़ें, जलपेनो के छल्ले और ताजे धनिए की टहनियां डालें। हल्के से दबाएं और तुरंत परोसें।","en":"Combine the carrots and daikon with the rice vinegar, sugar, and salt, toss well, and leave to pickle for at least 20 minutes (or up to 4 hours in the fridge) until slightly softened but still crunchy. Mix the soy sauce, fish sauce, sesame oil, sugar, and black pepper in a bowl, add the sliced pork, and toss to coat; marinate for 15-20 minutes at room temperature. Heat a heavy frying pan or griddle over high heat until smoking, add the pork in a single layer in 2-3 batches, and cook for 1-2 minutes per side until caramelised and golden brown at the edges. Toast the baguettes in a 200°C oven for 4-5 minutes until the crust is crisp. Spread the cut sides generously with pâté and mayonnaise. Layer in the warm pork slices, the drained pickled carrots and daikon, cucumber batons, jalapeño slices, and generous sprigs of coriander. Press gently and serve immediately."}},{"id":68,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"hi":"इंडोनेशिया","en":"Indonesia","ro":"Indonezia"},"name":{"hi":"सते","en":"Satay","ro":"Satay"},"category":{"hi":"नाश्ता","en":"Snack","ro":"Gustare"},"ingredients":{"hi":["700 ग्राम बोनलेस स्किनलेस चिकन जांघ, 2 सेमी के टुकड़ों में काटे","3 बड़े चम्मच सोया सॉस","2 बड़े चम्मच नारियल का दूध","1 बड़ा चम्मच हल्की ब्राउन शुगर","2 छोटे चम्मच धनिया पाउडर","1 छोटा चम्मच जीरा पाउडर","1 छोटा चम्मच हल्दी पाउडर","2 लहसुन की कलियां, बारीक कसी हुई","1 लेमनग्रास का डंठल, हल्का हिस्सा, बारीक कटा","200 ग्राम स्मूद मूंगफली का मक्खन","200 मिलीलीटर नारियल का दूध (सॉस के लिए)","2 बड़े चम्मच केकप मानिस (मीठी सोया सॉस)","1 बड़ा चम्मच नींबू का रस","1 छोटा चम्मच सांबल ओएलेक या श्रीराचा","20 बांस की सींख, 30 मिनट ठंडे पानी में भिगोई"],"en":["700 g boneless skinless chicken thighs, cut into 2 cm cubes","3 tbsp soy sauce","2 tbsp coconut milk","1 tbsp light brown sugar","2 tsp ground coriander","1 tsp ground cumin","1 tsp ground turmeric","2 garlic cloves, finely grated","1 lemongrass stalk, pale part only, finely minced","200 g smooth peanut butter","200 ml coconut milk (for sauce)","2 tbsp kecap manis (sweet soy sauce)","1 tbsp lime juice","1 tsp sambal oelek or sriracha","20 bamboo skewers, soaked in cold water for 30 minutes"],"ro":["700 g pulpe de pui dezosate și fără piele, tăiate cubulețe de 2 cm","3 linguri sos de soia","2 linguri lapte de cocos","1 lingură zahăr brun pal","2 lingurițe coriandru măcinat","1 linguriță chimen măcinat","1 linguriță turmeric măcinat","2 căței de usturoi, fin rași","1 tulpină lemongrass, partea palidă, fin tocată","200 g unt de arahide cremos","200 ml lapte de cocos (pentru sos)","2 linguri kecap manis (sos de soia dulce)","1 lingură suc de lime","1 linguriță sambal oelek sau sriracha","20 bețișoare de bambus, înmuiate în apă rece 30 de minute"]},"howIsMade":{"hi":"मैरिनेड के लिए एक बर्तन में सोया सॉस, नारियल का दूध, ब्राउन शुगर, धनिया पाउडर, जीरा, हल्दी, लहसुन और लेमनग्रास मिलाएं। चिकन के टुकड़े डालकर कोट करें और कम से कम 30 मिनट कमरे के तापमान पर या 4 घंटे तक फ्रिज में मैरिनेट करें। मूंगफली सॉस बनाएं: एक छोटे पैन में मूंगफली का मक्खन, नारियल का दूध, केकप मानिस, नींबू का रस और सांबल को धीमी आंच पर 3-4 मिनट तक हिलाते हुए चिकना और रेशमी बनाएं; बहुत गाढ़ा हो तो पानी मिलाएं। भिगोई हुई सींख पर 4-5 चिकन के टुकड़े कसकर गुथें। कोयले की आंच या कास्ट आयरन ग्रिल पैन को तेज आंच पर गर्म करें और हल्का तेल लगाएं। सींखों को एक बार पलटते हुए प्रत्येक तरफ 3-4 मिनट ग्रिल करें जब तक जगह-जगह गहरा भूरा हो जाए और चिकन सींख से आसानी से निकले — आंतरिक तापमान 75°C होना चाहिए। गर्म मूंगफली सॉस और खीरे के साथ तुरंत परोसें।","en":"Mix the soy sauce, coconut milk, brown sugar, ground coriander, cumin, turmeric, garlic, and lemongrass in a bowl to make the marinade. Add the chicken cubes, toss to coat, and marinate for at least 30 minutes at room temperature or up to 4 hours in the refrigerator. Make the peanut sauce: combine the peanut butter, coconut milk, kecap manis, lime juice, and sambal in a small saucepan over low heat and stir for 3-4 minutes until smooth and silky; thin with a splash of water if too thick. Thread 4-5 chicken pieces onto each soaked skewer, pressing them close together. Heat a charcoal grill, cast-iron griddle, or grill pan over high heat and brush lightly with oil. Grill the skewers for 3-4 minutes per side, turning once, until deeply charred in spots and the chicken pulls away from the skewer easily — internal temperature should reach 75°C. Serve immediately with the warm peanut sauce for dipping and sliced cucumber alongside."}},{"id":69,"servings":4,"tipType":"def","pairingsType":"soup","origin":{"hi":"मलेशिया","en":"Malaysia","ro":"Malaysia"},"name":{"hi":"लक्सा","en":"Laksa","ro":"Laksa"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"ingredients":{"hi":["3 बड़े चम्मच लक्सा पेस्ट (या 1 छोटा चम्मच झींगा पेस्ट मिलाया हुआ रेड करी पेस्ट)","2 बड़े चम्मच वनस्पति तेल","800 मिलीलीटर नारियल का दूध (2 x 400 मिलीलीटर डिब्बे)","600 मिलीलीटर चिकन स्टॉक या पानी","2 बड़े चम्मच फिश सॉस","1 छोटा चम्मच चीनी","400 ग्राम कच्चे मध्यम आकार के झींगे, छीले और सफाई किए","200 ग्राम कठोर टोफू, निकाला और 2 सेमी टुकड़ों में काटा","200 ग्राम ताजे बीन स्प्राउट्स","200 ग्राम चावल की सेवई, 3 मिनट उबलते पानी में भिगोकर छानी","4 बड़े अंडे, कड़े उबले (7 मिनट), छीले और आधे काटे","100 ग्राम हरी बीन्स, साफ करके आधी काटी","2 नींबू, टुकड़ों में","20 ग्राम ताजा धनिया, केवल पत्तियां","2 हरे प्याज, पतले कटे"],"en":["3 tbsp laksa paste (or red curry paste with 1 tsp shrimp paste added)","2 tbsp vegetable oil","800 ml coconut milk (2 x 400 ml cans)","600 ml chicken stock or water","2 tbsp fish sauce","1 tsp sugar","400 g raw medium prawns, peeled and deveined","200 g firm tofu, drained and cut into 2 cm cubes","200 g fresh bean sprouts","200 g rice vermicelli noodles, soaked in boiling water 3 minutes and drained","4 large eggs, hard-boiled (7 minutes), peeled and halved","100 g green beans, trimmed and halved","2 limes, cut into wedges","20 g fresh coriander, leaves only","2 spring onions, thinly sliced"],"ro":["3 linguri pastă laksa (sau pastă de curry roșu cu 1 linguriță pastă de creveți)","2 linguri ulei vegetal","800 ml lapte de cocos (2 conserve de 400 ml)","600 ml supă de pui sau apă","2 linguri sos de pește","1 linguriță zahăr","400 g creveți cruzi medii, curățați și devenați","200 g tofu ferm, scurs și tăiat cuburi de 2 cm","200 g muguri de soia proaspeți","200 g vermicelli de orez, înmuiați în apă clocotită 3 minute și scurși","4 ouă mari, fierte tari (7 minute), decojite și tăiate jumătate","100 g fasole verde, curățată și tăiată în jumătăți","2 lime, tăiate felii","20 g coriandru proaspăt, frunze","2 cepe verzi, feliate subțire"]},"howIsMade":{"hi":"चावल की सेवई को 3 मिनट उबलते पानी में भिगोएं, छानें, ठंडे पानी से धोएं और रख दें। अंडे 7 मिनट सख्त उबालें, बर्फ के पानी में ठंडे करें, छीलें और आधे काटें। एक बड़े वॉक या पैन में तेल गरम करें, लक्सा पेस्ट डालें और लगातार हिलाते हुए 2-3 मिनट भूनें जब तक खुशबू न आए और तेल अलग होने लगे। नारियल का दूध और चिकन स्टॉक डालकर हल्का उबाल लाएं। फिश सॉस और चीनी डालकर चखें — शोरबा समृद्ध और थोड़ा नमकीन होना चाहिए। हरी बीन्स डालकर 3 मिनट पकाएं, फिर झींगे और टोफू डालकर 2-3 मिनट पकाएं जब तक झींगे गुलाबी और पके न हों। नूडल्स को 4 गहरे बाउल में बांटें और ऊपर से गर्म शोरबा, झींगे, टोफू और बीन्स डालें। प्रत्येक बाउल को बीन स्प्राउट्स, आधे उबले अंडे, हरे प्याज और धनिया से सजाएं। नींबू के टुकड़ों के साथ तुरंत परोसें।","en":"Soak the rice vermicelli in boiling water for 3 minutes, drain, rinse under cold water, and set aside. Hard-boil the eggs for 7 minutes, cool in iced water, peel, and halve. Heat the oil in a large wok or saucepan over medium heat, add the laksa paste, and fry, stirring constantly, for 2-3 minutes until fragrant and the oil begins to separate. Pour in the coconut milk and chicken stock and bring to a steady simmer. Add the fish sauce and sugar, taste, and adjust — the broth should be rich and slightly salty. Add the green beans and cook for 3 minutes, then add the prawns and tofu and cook for 2-3 minutes until the prawns are pink and just cooked through. Divide the noodles between 4 deep bowls and ladle the hot broth with prawns, tofu, and beans on top. Finish each bowl with bean sprouts, 2 halved eggs, spring onions, and coriander. Serve immediately with lime wedges on the side."}},{"id":70,"servings":4,"tipType":"def","pairingsType":"mexican","origin":{"hi":"एल सल्वाडोर","en":"El Salvador","ro":"El Salvador"},"name":{"hi":"पुपुसा","en":"Pupusa","ro":"Pupusa"},"category":{"hi":"नाश्ता","en":"Snack","ro":"Gustare"},"ingredients":{"hi":["400 ग्राम माज़ा हरीना (नियोक्सटामलाइज्ड कॉर्न फ्लोर, जैसे Maseca), अतिरिक्त थोड़ा","350 मिलीलीटर गुनगुना पानी (लगभग 40°C), आवश्यकतानुसार अधिक","1 छोटा चम्मच बारीक नमक","200 ग्राम डिब्बाबंद रेफ्राइड काले या पिंटो बीन्स, गर्म किया हुआ","200 ग्राम केसो केसिलो या मोज़ेरेला, मोटा कद्दूकस किया","2 बड़े चम्मच वनस्पति तेल (पकाने के लिए)","300 ग्राम सफेद पत्तागोभी (लगभग 1/4 सिर), बहुत पतली कटी","1 छोटी गाजर (लगभग 80 ग्राम), छीलकर मोटा कद्दूकस","1/2 छोटा सफेद प्याज (लगभग 60 ग्राम), पतले टुकड़ों में","100 मिलीलीटर सेब का सिरका या सफेद सिरका","100 मिलीलीटर पानी (कुर्तिदो के लिए)","1 छोटा चम्मच नमक + 1 छोटा चम्मच चीनी (कुर्तिदो के लिए)","1/2 छोटा चम्मच सूखा अजवायन","200 मिलीलीटर टमाटर सालसा, परोसने के लिए"],"en":["400 g masa harina (nixtamalized corn flour, such as Maseca), plus extra","350 ml warm water (about 40°C), plus more if needed","1 tsp fine sea salt","200 g canned refried black or pinto beans, warmed","200 g queso quesillo or mozzarella, coarsely grated","2 tbsp vegetable oil (for cooking)","300 g white cabbage (about 1/4 head), very finely shredded","1 small carrot (about 80 g), peeled and coarsely grated","1/2 small white onion (about 60 g), thinly sliced","100 ml apple cider vinegar or white vinegar","100 ml water (for curtido)","1 tsp fine salt + 1 tsp sugar (for curtido)","1/2 tsp dried oregano","200 ml tomato salsa, to serve"],"ro":["400 g masa harina (făină de porumb nixtamalizată, ex. Maseca), plus extra","350 ml apă caldă (circa 40°C), plus dacă e nevoie","1 linguriță sare fină de mare","200 g fasole neagră sau pinto refulată (din conservă, încălzită)","200 g queso quesillo sau mozzarella, ras grosier","2 linguri ulei vegetal (pentru prăjit)","300 g varză albă (aprox. 1/4 căpățână), fin feliată","1 morcov mic (aprox. 80 g), curățat și ras","1/2 ceapă albă mică (aprox. 60 g), felii subțiri","100 ml oțet de mere sau oțet alb","100 ml apă (pentru curtido)","1 linguriță sare fină + 1 linguriță zahăr (pentru curtido)","1/2 linguriță oregano uscat","200 ml salsa de roșii pentru servit"]},"howIsMade":{"hi":"पहले कुर्तिदो बनाएं: पत्तागोभी, गाजर और प्याज को एक बर्तन में मिलाएं, सिरका, पानी, नमक, चीनी और अजवायन मिलाकर सब्जियों पर डालें, अच्छी तरह मिलाएं और कम से कम 30 मिनट (या रात भर फ्रिज में) के लिए छोड़ दें। आटा बनाएं: माज़ा हरीना और नमक को एक बड़े बर्तन में मिलाएं, धीरे-धीरे गुनगुना पानी डालते हुए हाथों से गूंधें जब तक चिकना और लचीला आटा न बने — बिना टूटे एक साथ रहना चाहिए; जरूरत पड़े तो एक-एक चम्मच पानी डालें। रेफ्राइड बीन्स और कद्दूकस पनीर मिलाकर भरावन बनाएं। आटे को 8 बराबर गोले (लगभग 90 ग्राम प्रत्येक) में बांटें। एक गोले को गीली हथेली पर लगभग 12 सेमी के चक्र में दबाएं, बीच में 2 भरे चम्मच भरावन रखें, फिर किनारों को ऊपर मोड़कर कसकर बंद करें; लगभग 1 सेमी मोटाई और 12 सेमी चौड़ाई में धीरे से फिर से दबाएं, दरारें ठीक करें। एक भारी ग्रिल या कास्ट आयरन पैन को मध्यम-तेज आंच पर गर्म करें और तेल लगाएं। पुपुसा को बैचों में प्रत्येक तरफ 3-4 मिनट तक पकाएं जब तक गहरे सुनहरे भूरे धब्बे न दिखें और आटा चिपचिपा न होकर सूखा लगे। गर्मागर्म कुर्तिदो ऊपर रखकर और सालसा के साथ परोसें।","en":"Make the curtido first: combine the cabbage, carrot, and onion in a bowl, mix the vinegar, water, salt, sugar, and oregano, pour over the vegetables, toss well, and set aside to pickle for at least 30 minutes (or overnight in the fridge). Make the dough: combine the masa harina and salt in a large bowl, pour in the warm water gradually, and mix with your hands until a smooth, pliable dough forms — it should hold together without cracking; add a tablespoon of water at a time if needed. Mix the refried beans and grated cheese together to make the filling. Divide the dough into 8 equal balls (about 90 g each). Press a ball flat in your damp palm into a disc about 12 cm across, place 2 heaped tablespoons of filling in the centre, then fold the edges up over the filling and pinch firmly to seal; gently re-flatten into a disc about 1 cm thick and 12 cm wide, patching any cracks. Heat a heavy griddle or cast-iron skillet over medium-high heat and brush with oil. Cook the pupusas in batches for 3-4 minutes per side until dark golden-brown patches appear and the dough feels dry rather than tacky. Serve hot with the curtido piled on top and salsa alongside."}},{"id":72,"servings":4,"tipType":"fish","pairingsType":"vietnamese","origin":{"hi":"कंबोडिया","en":"Cambodia","ro":"Cambodgia"},"name":{"hi":"अमोक","en":"Amok","ro":"Amok"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["600 ग्राम सफेद मछली फिलेट (तिलापिया, स्नैपर या कैटफिश), बिना त्वचा, 3 सेमी टुकड़ों में काटे","400 मिलीलीटर नारियल का दूध (1 x 400 मिलीलीटर डिब्बा)","2 बड़े अंडे, हल्के से फेंटे","3 बड़े चम्मच फिश सॉस","1 छोटा चम्मच चीनी","2 लेमनग्रास के डंठल, केवल हल्का हिस्सा, बहुत बारीक कटा","3 लहसुन की कलियां, बारीक कटी","3 शैलट (लगभग 100 ग्राम), बारीक कटे","1 छोटा चम्मच गलंगल पेस्ट (या 1 सेमी ताजा गलंगल, कद्दूकस)","1/2 छोटा चम्मच हल्दी पाउडर","1/2 छोटा चम्मच सूखे लाल मिर्च के टुकड़े या 1 ताजा लाल मिर्च, बारीक कटी","4 कफिर लाइम पत्ते, डंठल हटाकर बहुत पतले कटे","4 बड़े केले के पत्ते के टुकड़े (30 x 30 सेमी), आग पर नरम किए, या 4 रमेकिन","20 ग्राम ताजा तुलसी या थाई तुलसी पत्ते, सजावट के लिए"],"en":["600 g white fish fillets (tilapia, snapper, or catfish), skin removed, cut into 3 cm pieces","400 ml coconut milk (1 x 400 ml can)","2 large eggs, lightly beaten","3 tbsp fish sauce","1 tsp caster sugar","2 lemongrass stalks, pale parts only, very finely minced","3 garlic cloves, finely minced","3 shallots (about 100 g), finely minced","1 tsp galangal paste (or 1 cm fresh galangal, grated)","1/2 tsp ground turmeric","1/2 tsp dried chilli flakes or 1 fresh red chilli, finely sliced","4 kaffir lime leaves, stems removed, very finely shredded","4 large banana leaf squares (30 x 30 cm), softened over a flame, or 4 ramekins","20 g fresh basil or Thai basil leaves, to garnish"],"ro":["600 g file de pește alb (tilapia, biban sau somn), fără piele, tăiat bucăți de 3 cm","400 ml lapte de cocos (1 conservă de 400 ml)","2 ouă mari, ușor bătute","3 linguri sos de pește","1 linguriță zahăr","2 tulpini lemongrass, doar partea palidă, fin tocate","3 căței de usturoi, fin tocați","3 șalote (aproximativ 100 g), fin tocate","1 linguriță pastă de galangal (sau 1 cm galangal proaspăt, ras)","1/2 linguriță turmeric măcinat","1/2 linguriță fulgi de ardei iute uscat sau 1 ardei roșu, fin tocat","4 frunze de kaffir lime, cotoare îndepărtate, fin feliate","4 pătrate mari de frunze de bananier (30 x 30 cm), înmuiate, sau ramekine","20 g frunze de busuioc proaspăt sau busuioc thai, pentru garnitură"]},"howIsMade":{"hi":"लेमनग्रास, लहसुन, शैलट, गलंगल, हल्दी और मिर्च को ओखली में कूटें या ब्लेंडर में चिकना पेस्ट बनाएं। एक बड़े बर्तन में नारियल का दूध, फेंटे अंडे, फिश सॉस और चीनी मिलाएं। मसाले का पेस्ट और आधे कफिर लाइम के पत्ते मिलाएं। मछली के टुकड़े डालें और धीरे से लपेटें; 15 मिनट मैरिनेट करें। केले के पत्तों को गैस की आंच या गर्म पानी में 30 सेकंड नरम करें। प्रत्येक को लगभग 12 सेमी चौड़े और 4 सेमी गहरे कप के आकार में मोड़ें और टूथपिक से सुरक्षित करें। मछली का मिश्रण 4 केले के पत्ते के कपों में समान रूप से बांटें, प्रत्येक को लगभग दो-तिहाई भरें और बाकी कफिर लाइम के पत्ते ऊपर छिड़कें। कपों को उबलते पानी के ऊपर बांस के स्टीमर में रखें, कसकर ढकें और 18-20 मिनट भाप में पकाएं जब तक अमोक जम जाए — कप हिलाने पर तरल न बहे — और ऊपरी हिस्सा थोड़ा कठोर हो जाए। ताजी तुलसी के पत्तों से सजाएं और जैस्मिन चावल के साथ तुरंत परोसें।","en":"Pound or blend the lemongrass, garlic, shallots, galangal, turmeric, and chilli into a smooth paste. In a large bowl, whisk together the coconut milk, beaten eggs, fish sauce, and sugar until combined. Stir in the spice paste and half the shredded kaffir lime leaves. Add the fish pieces and fold gently to coat; marinate for 15 minutes. Soften the banana leaf squares over a gas flame or in hot water for 30 seconds until pliable. Fold each into a cup shape about 12 cm across and 4 cm deep, securing with a toothpick. Divide the fish mixture evenly among the 4 banana leaf cups, filling each about two-thirds full, then scatter the remaining kaffir lime leaves on top. Set the cups in a bamboo steamer over boiling water, cover tightly, and steam for 18-20 minutes until the amok is just set — no longer liquid when the cup is gently tilted — and the top is slightly firm to the touch. Garnish with fresh basil leaves and serve immediately with steamed jasmine rice."}},{"id":73,"servings":4,"tipType":"meat","pairingsType":"indian","origin":{"hi":"नेपाल","en":"Nepal","ro":"Nepal"},"name":{"hi":"मोमो","en":"Momo","ro":"Momo"},"category":{"hi":"नाश्ता","en":"Snack","ro":"Gustare"},"ingredients":{"hi":["300 ग्राम मैदा (ऑल-पर्पस फ्लौर), और थोड़ा बेलने के लिए","150 मिली गुनगुना पानी","500 ग्राम चिकन या पोर्क कीमा","1 मध्यम आकार का प्याज (लगभग 120 ग्राम), बहुत बारीक कटा हुआ","3 लहसुन की कलियाँ, बारीक कटी हुई","1 बड़ा चम्मच ताज़ा अदरक (लगभग 2 सेमी), कद्दूकस किया हुआ","30 ग्राम ताज़ा धनिया, बारीक कटा हुआ","1 छोटा चम्मच जीरा पाउडर","1/2 छोटा चम्मच धनिया पाउडर","1/4 छोटा चम्मच हल्दी","1 छोटा चम्मच बारीक नमक, विभाजित","4 मध्यम टमाटर (लगभग 400 ग्राम), आधे काटे हुए","2 सूखी लाल मिर्चें या 1/2 छोटा चम्मच लाल मिर्च के गुच्छे","1 बड़ा चम्मच वनस्पति तेल"],"en":["300 g plain flour (all-purpose), plus extra for dusting","150 ml warm water","500 g ground chicken or pork","1 medium onion (about 120 g), very finely diced","3 garlic cloves, finely minced","1 tbsp fresh ginger (about 2 cm piece), finely grated","30 g fresh coriander (cilantro), finely chopped","1 tsp ground cumin","1/2 tsp ground coriander","1/4 tsp ground turmeric","1 tsp fine sea salt, divided","4 medium tomatoes (about 400 g), halved","2 dried red chillies or 1/2 tsp chilli flakes","1 tbsp vegetable oil"],"ro":["300 g făină albă (tip 550), plus extra pentru pudrat","150 ml apă caldă","500 g carne tocată de pui sau porc","1 ceapă medie (circa 120 g), tocată mărunt","3 căței de usturoi, tocați mărunt","1 lingură ghimbir proaspăt (circa 2 cm), ras fin","30 g coriandru proaspăt, tocat mărunt","1 linguriță chimen măcinat","1/2 linguriță coriandru măcinat","1/4 linguriță turmeric","1 linguriță sare fină, împărțită","4 roșii medii (circa 400 g), tăiate în jumătăți","2 ardei iuți uscați sau 1/2 linguriță fulgi de ardei iute","1 lingură ulei vegetal"]},"howIsMade":{"hi":"एक कटोरे में मैदा और आधा छोटा चम्मच नमक मिलाएं, फिर धीरे-धीरे गुनगुना पानी डालते हुए 5-6 मिनट गूंधें जब तक आटा चिकना, मजबूत और न चिपकने वाला हो जाए; नम कपड़े से ढककर 30 मिनट आराम करने दें। दूसरे कटोरे में कीमा, प्याज, लहसुन, अदरक, धनिया पत्ती, जीरा, धनिया पाउडर, हल्दी, बचा हुआ आधा छोटा चम्मच नमक और तेल अच्छी तरह मिलाएं; 15 मिनट के लिए फ्रिज में रखें। सॉस के लिए टमाटर के आधे टुकड़ों और सूखी मिर्चों को सूखी कड़ाही में तेज़ आंच पर 4-5 मिनट भूनें जब तक वे नरम न हों और जगह-जगह काले निशान न पड़ जाएं, फिर लहसुन और नमक के साथ पीसकर चिकना सॉस बनाएं। आटे को 24 बराबर टुकड़ों में बांटें (प्रत्येक लगभग 15 ग्राम) और हर एक को लगभग 8 सेमी व्यास की पतली गोल लोई बेलें। बीच में एक भरा हुआ छोटा चम्मच भरावन रखें, किनारों को छोटी-छोटी तहें बनाते हुए ऊपर की ओर इकट्ठा करें और चोटी बनाकर मजबूती से बंद करें। हल्के तेल लगे बेकिंग पेपर पर स्टीमर में मोमो को कम से कम 1 सेमी की दूरी पर रखें। तेज़ उबलते पानी पर 12-15 मिनट भाप में पकाएं जब तक आटा अर्ध-पारदर्शी न हो जाए और हल्का दबाने पर वापस उभर आए। टमाटर-मिर्च सॉस के साथ तुरंत परोसें।","en":"Combine flour and 1/2 tsp of the salt in a bowl, then add warm water a little at a time, mixing until a rough dough forms; knead for 5-6 minutes until smooth, firm, and no longer sticky, then cover with a damp cloth and rest for 30 minutes. In a separate bowl, mix the ground meat, onion, garlic, ginger, coriander leaves, cumin, ground coriander, turmeric, the remaining 1/2 tsp salt, and oil until well combined; refrigerate for 15 minutes to let the flavours meld. Meanwhile, make the dipping sauce: char the tomato halves and dried chillies in a dry heavy skillet over high heat for 4-5 minutes until softened and blackened in spots, then blend with the garlic and remaining salt until smooth. Divide the rested dough into 24 equal pieces (about 15 g each) and roll each into a thin round about 8 cm across. Place a heaped teaspoon of filling in the centre of each round, then gather the edges and pleat them together with small overlapping folds, pinching firmly at the top to seal. Line a bamboo or metal steamer with lightly oiled parchment paper and arrange the momo at least 1 cm apart. Set over a pot of vigorously boiling water, cover tightly, and steam for 12-15 minutes until the wrappers turn translucent and a gently pressed momo springs back without feeling doughy inside. Serve immediately with the tomato-chilli sauce."}},{"id":74,"servings":4,"tipType":"soup","pairingsType":"soup","origin":{"hi":"इक्वाडोर","en":"Ecuador","ro":"Ecuador"},"name":{"hi":"एन्सेबोयादो","en":"Encebollado","ro":"Encebollado"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"ingredients":{"hi":["700 ग्राम ताज़ा टूना या 2 कैन पानी में टूना (कुल 400 ग्राम), छाना हुआ","600 ग्राम कसावा (यूका), छिला हुआ और 4 सेमी के टुकड़ों में कटा हुआ","1 बड़ा लाल प्याज (लगभग 200 ग्राम), पतले अर्ध-चंद्र आकार में कटा हुआ","4 मध्यम टमाटर (लगभग 400 ग्राम), मोटे-मोटे कटे हुए","4 लहसुन की कलियाँ, मोटी कटी हुई","1 छोटा चम्मच जीरा पाउडर","1 छोटा चम्मच एचिओटे पेस्ट या 1/2 छोटा चम्मच मीठी पापरिका","1.5 लीटर मछली का शोरबा या पानी","3 बड़े चम्मच नींबू का रस (लगभग 2 नींबू)","2 बड़े चम्मच वनस्पति तेल","1 छोटा चम्मच बारीक नमक","30 ग्राम ताज़ा धनिया, विभाजित — आधा पकाने के लिए, आधा परोसने के लिए","1 जलापेनो या आही मिर्च, बीज निकाला हुआ, पतली फांकों में","2 हरी प्याज, पतली कटी हुई (सजावट के लिए)"],"en":["700 g fresh tuna or 2 cans tuna in water (400 g total), drained","600 g cassava (yuca), peeled and cut into 4 cm chunks","1 large red onion (about 200 g), thinly sliced into half-moons","4 medium tomatoes (about 400 g), roughly chopped","4 garlic cloves, roughly chopped","1 tsp ground cumin","1 tsp achiote paste or 1/2 tsp sweet paprika","1.5 litres fish stock or water","3 tbsp fresh lime juice (about 2 limes)","2 tbsp vegetable oil","1 tsp fine sea salt","30 g fresh coriander (cilantro), divided — half to cook, half to garnish","1 jalapeño or aji pepper, deseeded and finely sliced","2 spring onions, thinly sliced (to garnish)"],"ro":["700 g ton proaspăt sau 2 conserve ton în apă (400 g total), scurse","600 g yuca (manioc), curățată și tăiată bucăți de 4 cm","1 ceapă roșie mare (circa 200 g), tăiată în felii subțiri","4 roșii medii (circa 400 g), tăiate grosier","4 căței de usturoi, tăiați grosier","1 linguriță chimen măcinat","1 linguriță pastă de achiote sau 1/2 linguriță paprika dulce","1,5 litri supă de pește sau apă","3 linguri zeamă de lămâie verde (circa 2 lămâi)","2 linguri ulei vegetal","1 linguriță sare fină","30 g coriandru proaspăt, împărțit — jumătate pentru gătit, jumătate pentru servit","1 jalapeno sau ardei iute, fără semințe, feliat subțire","2 fire ceapă verde, tăiate subțire (pentru decor)"]},"howIsMade":{"hi":"एक बड़े बर्तन में मध्यम आंच पर तेल गर्म करें, प्याज, लहसुन, टमाटर, जलापेनो और जीरा डालें और बीच-बीच में हिलाते हुए 8-10 मिनट पकाएं जब तक प्याज बहुत नरम न हो जाए और टमाटर गाढ़ी चटनी में न बदल जाएं। एचिओटे पेस्ट मिलाएं और 1 मिनट पकाएं जब तक तेल गहरे नारंगी रंग का न हो जाए। शोरबा डालें, उबाल लाएं, फिर कसावा डालें और 20-25 मिनट पकाएं जब तक पूरी तरह नरम न हो जाए और किनारों से टूटने न लगे। अगर ताज़ा टूना इस्तेमाल कर रहे हैं, तो हल्के नमकीन उबलते पानी में 5-6 मिनट पोच करें जब तक पक न जाए, थोड़ा ठंडा होने दें और बड़े टुकड़ों में तोड़ें। टूटे हुए टूना (या छाना हुआ कैन टूना), आधा धनिया और नींबू का रस बर्तन में डालें; 3-4 मिनट धीमी आंच पर उबालें ताकि स्वाद मिल जाएं। नमक का स्वाद लें और गहरे कटोरे में परोसें। बचा हुआ धनिया और हरी प्याज ऊपर से डालें और टोस्टादास या केले के चिप्स के साथ परोसें।","en":"Heat the oil in a large pot over medium heat, add the onion, garlic, tomatoes, jalapeño, and cumin, and cook for 8-10 minutes, stirring occasionally, until the onion is very soft and the tomatoes have broken down into a thick paste. Stir in the achiote paste and cook for 1 minute until the oil turns a deep orange. Pour in the stock, bring to a boil, then add the cassava and cook for 20-25 minutes until completely tender and just beginning to break apart at the edges. If using fresh tuna, poach the steaks in lightly salted simmering water for 5-6 minutes until just cooked through, cool slightly, and flake into large chunks. Add the flaked tuna (or drained canned tuna), half the coriander, and the lime juice to the pot; simmer for 3-4 minutes to marry the flavours. Season with salt to taste, then ladle the soup into deep bowls. Top with the remaining coriander and spring onions, and serve with tostadas or plantain chips on the side."}},{"id":75,"servings":4,"tipType":"soup","pairingsType":"middle-eastern","origin":{"hi":"मोरक्को","en":"Morocco","ro":"Maroc"},"name":{"hi":"हरीरा","en":"Harira","ro":"Harira"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"ingredients":{"hi":["400 ग्राम मेमने की कंधे की मांस, 3 सेमी के टुकड़ों में कटी हुई","400 ग्राम डिब्बाबंद छोले (1 x 400 ग्राम का डिब्बा), छाने और धुले हुए","150 ग्राम हरी या भूरी मसूर दाल, धुली हुई","4 मध्यम टमाटर (लगभग 400 ग्राम), मोटे-मोटे कटे हुए","1 बड़ा प्याज (लगभग 200 ग्राम), बहुत बारीक कटा हुआ","3 अजवाइन की डंडियाँ पत्तियों सहित (लगभग 150 ग्राम), पतली कटी हुई","3 लहसुन की कलियाँ, बारीक कटी हुई","1 छोटा चम्मच जीरा पाउडर","1 छोटा चम्मच दालचीनी + 1 छोटा चम्मच अदरक पाउडर","1/2 छोटा चम्मच हल्दी + 1 छोटा चम्मच बारीक नमक","2 बड़े चम्मच जैतून का तेल","1.5 लीटर पानी या मेमने का शोरबा","60 ग्राम पतली वर्मिसेली, 2 सेमी के टुकड़ों में तोड़ी हुई","30 ग्राम ताज़ा धनिया और फ्लैट-लीफ अजमोद, मोटे-मोटे कटे हुए"],"en":["400 g lamb shoulder, cut into 3 cm chunks","400 g canned chickpeas (1 x 400 g can), rinsed and drained","150 g green or brown lentils, rinsed","4 medium tomatoes (about 400 g), roughly chopped","1 large onion (about 200 g), finely diced","3 celery stalks with leaves (about 150 g), finely sliced","3 garlic cloves, finely minced","1 tsp ground cumin","1 tsp ground cinnamon + 1 tsp ground ginger","1/2 tsp ground turmeric + 1 tsp fine sea salt","2 tbsp olive oil","1.5 litres water or lamb stock","60 g thin vermicelli, broken into 2 cm pieces","30 g fresh coriander and flat-leaf parsley, roughly chopped"],"ro":["400 g spata de miel, taiata bucati de 3 cm","400 g naut fiert (1 cutie 400 g), scurs si clatit","150 g linte verde sau bruna, clatita","4 rosii medii (circa 400 g), taiate grosier","1 ceapa mare (circa 200 g), tocata marunt","3 tulpini de telina cu frunze (circa 150 g), feliate subtire","3 căței de usturoi, tocati marunt","1 lingurita chimen macinat","1 lingurita scortisoara + 1 lingurita ghimbir macinat","1/2 lingurita turmeric + 1 lingurita sare fina","2 linguri ulei de masline","1,5 litri apa sau supa de miel","60 g vermicelli subtire, rupt in bucati de 2 cm","30 g coriandru proaspat si patrunjel plat, tocat grosier"]},"howIsMade":{"hi":"एक बड़े बर्तन में तेज़ आंच पर तेल गर्म करें, मेमने के टुकड़े डालें और बीच-बीच में पलटते हुए 4-5 मिनट भूनें जब तक सभी तरफ से भूरे न हो जाएं। प्याज, अजवाइन और लहसुन डालें और 5 मिनट नरम होने तक पकाएं। जीरा, दालचीनी, अदरक, हल्दी और नमक मिलाएं और 1 मिनट भूनें जब तक खुशबू न आ जाए। टमाटर, छोले, मसूर डालें और पानी या शोरबा डालें; उबाल लाएं और ऊपर से झाग हटाएं। आंच धीमी करें, आधा ढककर 45-50 मिनट उबालें जब तक मेमना नरम न हो जाए और मसूर शोरबे में घुल न जाए और हल्का गाढ़ा न हो जाए। वर्मिसेली डालें और 5-6 मिनट पकाएं। आंच से हटाएं, धनिया और अजमोद मिलाएं और स्वाद के अनुसार नींबू का रस निचोड़ें। कटोरे में डालें और रोटी और खजूर के साथ तुरंत परोसें।","en":"Heat the oil in a large pot over medium-high heat, add the lamb chunks and sear for 4-5 minutes, turning occasionally, until browned on all sides. Add the onion, celery, and garlic and cook for 5 minutes until softened. Stir in the cumin, cinnamon, ginger, turmeric, and salt and cook for 1 minute until fragrant. Add the tomatoes, chickpeas, and lentils, pour in the water or stock, and bring to a boil; skim any foam from the surface. Reduce the heat to low, cover partially, and simmer for 45-50 minutes until the lamb is tender and the lentils have dissolved into the broth, thickening it slightly. Stir in the vermicelli and cook for 5-6 minutes until tender. Remove from the heat, stir in the coriander and parsley, and squeeze in lemon juice to taste. Ladle into bowls and serve immediately with crusty bread and dates."}},{"id":76,"servings":4,"tipType":"veg","pairingsType":"veg","origin":{"hi":"जॉर्जिया","en":"Georgia","ro":"Georgia"},"name":{"hi":"लोबियो","en":"Lobio","ro":"Lobio"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["500 ग्राम सूखी लाल राजमा फलियाँ (या 2 x 400 ग्राम डिब्बे, धुले हुए)","1 बड़ा प्याज (लगभग 200 ग्राम), बहुत बारीक कटा हुआ","4 लहसुन की कलियाँ, बारीक कटी हुई","100 ग्राम अखरोट के टुकड़े, बारीक पिसे या बहुत बारीक कटे हुए","1 छोटा चम्मच धनिया पाउडर","1/2 छोटा चम्मच मेथी पाउडर (utsho suneli)","1/2 छोटा चम्मच दालचीनी","1/2 छोटा चम्मच लाल मिर्च के गुच्छे या 1 छोटी लाल मिर्च बीज निकाली और कटी हुई","2 बड़े चम्मच सफेद या लाल वाइन सिरका","3 बड़े चम्मच वनस्पति तेल","1 छोटा चम्मच बारीक नमक","30 ग्राम ताज़ा धनिया, बारीक कटा हुआ","4 बड़े चम्मच अनार के दाने (लगभग आधा अनार)","4 हरी प्याज, पतली कटी हुई"],"en":["500 g dried red kidney beans (or 2 x 400 g cans, rinsed)","1 large onion (about 200 g), finely diced","4 garlic cloves, finely minced","100 g walnut halves, finely ground or very finely chopped","1 tsp ground coriander","1/2 tsp ground fenugreek (utsho suneli)","1/2 tsp ground cinnamon","1/2 tsp dried chilli flakes or 1 small red chilli, deseeded and minced","2 tbsp white wine vinegar or red wine vinegar","3 tbsp vegetable oil","1 tsp fine sea salt","30 g fresh coriander (cilantro), finely chopped","4 tbsp pomegranate seeds (about 1/2 pomegranate)","4 spring onions, thinly sliced"],"ro":["500 g fasole rosie uscata (sau 2 x 400 g conserve, clatite)","1 ceapa mare (circa 200 g), tocata marunt","4 căței de usturoi, tocati marunt","100 g miez de nuca, macinat fin sau tocat marunt","1 lingurita coriandru macinat","1/2 lingurita schinduf macinat (utsho suneli)","1/2 lingurita scortisoara","1/2 lingurita fulgi de ardei iute sau 1 ardei iute mic, fara seminte, tocat","2 linguri otet alb sau de vin rosu","3 linguri ulei vegetal","1 lingurita sare fina","30 g coriandru proaspat, tocat marunt","4 linguri boabe de rodie (circa 1/2 rodie)","4 fire ceapa verde, taiate subtire"]},"howIsMade":{"hi":"यदि सूखी फलियाँ इस्तेमाल कर रहे हैं, तो उन्हें रात भर ठंडे पानी में भिगोएं, छान लें, एक बड़े बर्तन में ताज़े ठंडे पानी से ढकें, उबाल लाएं, झाग हटाएं और 45-60 मिनट धीमी आंच पर उबालें जब तक पूरी तरह नरम न हो जाएं और टूटने न लगें, पकाने का तरल गहरा लाल और गाढ़ा होना चाहिए। एक कड़ाही में मध्यम आंच पर तेल गर्म करें, प्याज डालें और बीच-बीच में हिलाते हुए 10-12 मिनट पकाएं जब तक गहरे सुनहरे रंग का और बहुत नरम न हो जाए। लहसुन, धनिया पाउडर, मेथी, दालचीनी और मिर्च डालें और 2 मिनट भूनें जब तक खुशबू न आ जाए। प्याज का मिश्रण, पिसे अखरोट और सिरका फलियों में मिलाएं और धीमी आंच पर 10 मिनट बीच-बीच में हिलाते हुए पकाएं जब तक स्वाद मिल न जाएं और फलियाँ बहुत नरम और गाढ़ी सॉस वाली न हो जाएं — कुछ फलियाँ बर्तन की दीवार पर दबाकर मैश करें ताकि गाढ़ापन आए। नमक और सिरका स्वाद के अनुसार मिलाएं। आंच से हटाएं और आधा ताज़ा धनिया मिलाएं। एक थाली में परोसें और ऊपर से हरी प्याज, अनार के दाने और बाकी धनिया डालें। गर्म रोटी के साथ परोसें।","en":"If using dried beans, soak them overnight in cold water, then drain, cover with fresh cold water in a large pot, bring to a boil, skim any foam, and simmer for 45-60 minutes until completely tender and starting to break apart, with a thick dark-red cooking liquid. Heat the oil in a frying pan over medium heat, add the onion and cook for 10-12 minutes, stirring occasionally, until deep golden and very soft. Add the garlic, ground coriander, fenugreek, cinnamon, and chilli and cook for 2 minutes until fragrant. Stir the onion mixture, ground walnuts, and vinegar into the cooked beans and simmer over low heat for 10 minutes, stirring occasionally, until the flavours meld and the beans are very soft with a thick sauce — mash a few beans against the side of the pot to help thicken. Season with salt and more vinegar to taste. Remove from the heat and stir in half the fresh coriander. Transfer to a shallow dish and top with the spring onions, pomegranate seeds, and remaining coriander. Serve warm with flatbread."}},{"id":77,"servings":4,"tipType":"meat","pairingsType":"middle-eastern","origin":{"hi":"अल्जीरिया","en":"Algeria","ro":"Algeria"},"name":{"hi":"चखचौखा","en":"Chakhchoukha","ro":"Chakhchoukha"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"ingredients":{"hi":["600 ग्राम हड्डी सहित मेमने की कंधे की मांस या गर्दन, 4 सेमी के टुकड़ों में कटी हुई","400 ग्राम डिब्बाबंद छोले (1 x 400 ग्राम का डिब्बा), छाने और धुले हुए","4 मध्यम टमाटर (लगभग 400 ग्राम), मोटे-मोटे कटे हुए","2 मध्यम प्याज (लगभग 300 ग्राम), बहुत बारीक कटे हुए","4 लहसुन की कलियाँ, बारीक कटी हुई","2 बड़े चम्मच वनस्पति तेल","1 छोटा चम्मच जीरा पाउडर","1 छोटा चम्मच धनिया पाउडर","1 छोटा चम्मच मीठी पापरिका","1/2 छोटा चम्मच दालचीनी + 1/2 छोटा चम्मच काली मिर्च पाउडर","1 छोटा चम्मच बारीक नमक","600 मिली पानी या मेमने का शोरबा","रुगाग (अल्जीरियाई रोटी) की 4 बड़ी पर्तें या बड़ी टॉर्टिला, 5 सेमी के टुकड़ों में फाड़ी हुई","30 ग्राम ताज़ा धनिया और फ्लैट-लीफ अजमोद, मोटे-मोटे कटे हुए (सजावट के लिए)"],"en":["600 g bone-in lamb shoulder or neck, cut into 4 cm pieces","400 g canned chickpeas (1 x 400 g can), rinsed and drained","4 medium tomatoes (about 400 g), roughly chopped","2 medium onions (about 300 g), finely diced","4 garlic cloves, finely minced","2 tbsp vegetable oil","1 tsp ground cumin","1 tsp ground coriander","1 tsp sweet paprika","1/2 tsp ground cinnamon + 1/2 tsp ground black pepper","1 tsp fine sea salt","600 ml water or lamb stock","4 large sheets of rougag (Algerian flatbread) or large tortillas, torn into 5 cm pieces","30 g fresh coriander and flat-leaf parsley, roughly chopped (to garnish)"],"ro":["600 g spata de miel cu os sau gat, taiata bucati de 4 cm","400 g naut fiert (1 cutie 400 g), scurs si clatit","4 rosii medii (circa 400 g), taiate grosier","2 cepe medii (circa 300 g), tocate marunt","4 căței de usturoi, tocati marunt","2 linguri ulei vegetal","1 lingurita chimen macinat","1 lingurita coriandru macinat","1 lingurita boia dulce","1/2 lingurita scortisoara + 1/2 lingurita piper negru","1 lingurita sare fina","600 ml apa sau supa de miel","4 foi mari de rougag (lipie algeriana) sau 4 tortilla mari, rupte bucati de 5 cm","30 g coriandru proaspat si patrunjel plat, tocat grosier (pentru decor)"]},"howIsMade":{"hi":"एक बड़े भारी बर्तन में तेज़ आंच पर तेल गर्म करें, मेमने के टुकड़ों को बैचों में डालें और 4-5 मिनट सभी तरफ से भूरा होने तक सेकें। प्याज और लहसुन डालें और 5 मिनट नरम और सुनहरे होने तक पकाएं। जीरा, धनिया, पापरिका, दालचीनी, नमक और काली मिर्च मिलाएं और 1 मिनट भूनें जब तक मसालों की खुशबू न आ जाए। टमाटर डालें और बीच-बीच में हिलाते हुए 8-10 मिनट पकाएं जब तक गाढ़ी सॉस न बन जाए। पानी या शोरबा डालें, छोले मिलाएं और उबाल लाएं; आंच धीमी करें, ढकें और 50-60 मिनट उबालें जब तक मेमना पूरी तरह नरम न हो जाए और हड्डी से अलग न होने लगे। एक बड़े सर्विंग डिश की तली में फटी हुई रोटी के टुकड़े बिछाएं और ऊपर से गर्म मांस और सॉस उदारता से डालें, रोटी को हल्के से दबाएं ताकि तरल सोख ले और नरम हो जाए। ताज़े धनिया और अजमोद से सजाएं और तुरंत परोसें।","en":"Heat the oil in a large heavy pot over medium-high heat, add the lamb in batches and sear for 4-5 minutes until browned on all sides. Add the onion and garlic and cook for 5 minutes until softened and golden. Stir in the cumin, coriander, paprika, cinnamon, salt, and pepper and cook for 1 minute until the spices smell toasted. Add the tomatoes and cook for 8-10 minutes, stirring occasionally, until they break down into a thick sauce. Pour in the water or stock, add the chickpeas, and bring to a boil; reduce the heat to low, cover, and simmer for 50-60 minutes until the lamb is completely tender and falling off the bone. Scatter the torn flatbread pieces over the bottom of a large serving dish and ladle the hot meat and sauce generously on top, pressing the bread down gently so it absorbs the liquid and softens — it should be soaked through but not dissolving. Garnish with the fresh coriander and parsley and serve immediately."}},{"id":78,"servings":4,"tipType":"meat","timeMins":{"total":330,"active":60},"pairingsType":"meat","origin":{"hi":"इंडोनेशिया","en":"Indonesia","ro":"Indonezia"},"name":{"hi":"रेंदांग","en":"Rendang","ro":"Rendang"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["1 किलोग्राम बीफ (कंधे या ब्रिस्केट), 5 सेमी के क्यूब्स में कटा हुआ","800 मिली फुल-फैट नारियल का दूध (2 x 400 मिली)","5 शैलट (लगभग 150 ग्राम), मोटे-मोटे कटे हुए","4 लहसुन की कलियाँ, मोटी कटी हुई","2 बड़े चम्मच ताज़ा अदरक (लगभग 3 सेमी), मोटा कटा हुआ","1 बड़ा चम्मच ताज़ा गलंगल (लगभग 2 सेमी) या 1 छोटा चम्मच गलंगल पेस्ट","3 लेमनग्रास के डंठल, हल्के भाग केवल, मोटे कटे हुए","4-6 सूखी लाल मिर्चें, गर्म पानी में 15 मिनट भिगोई हुई, छानी हुई","4 काफिर लाइम पत्ते, डंठल हटाए हुए, बारीक कटे हुए","1 छोटा चम्मच हल्दी पाउडर","1 छोटा चम्मच धनिया पाउडर","1 छोटा चम्मच जीरा पाउडर","1 छोटा चम्मच बारीक नमक","1 बड़ा चम्मच वनस्पति तेल"],"en":["1 kg beef chuck or brisket, cut into 5 cm cubes","800 ml full-fat coconut milk (2 x 400 ml cans)","5 shallots (about 150 g), roughly chopped","4 garlic cloves, roughly chopped","2 tbsp fresh ginger (about 3 cm piece), roughly chopped","1 tbsp fresh galangal (about 2 cm) or 1 tsp galangal paste","3 lemongrass stalks, pale parts only, roughly sliced","4-6 dried red chillies, soaked in warm water 15 minutes and drained","4 kaffir lime leaves, stems removed, very finely shredded","1 tsp ground turmeric","1 tsp ground coriander","1 tsp ground cumin","1 tsp fine sea salt","1 tbsp vegetable oil"],"ro":["1 kg muschi de vita sau piept, taiat cuburi de 5 cm","800 ml lapte de cocos integral (2 x 400 ml)","5 esalote (circa 150 g), taiate grosier","4 căței de usturoi, tăiați grosier","2 linguri ghimbir proaspat (circa 3 cm), taiat grosier","1 lingura galangal proaspat (circa 2 cm) sau 1 lingurita pasta galangal","3 tulpini de lemongrass, partile palide, feliate grosier","4-6 ardei iuti rosii uscati, înmuiați in apa calda 15 minute, scursi","4 frunze de kafir lime, coada indepartata, maruntite fin","1 lingurita turmeric macinat","1 lingurita coriandru macinat","1 lingurita chimen macinat","1 lingurita sare fina","1 lingura ulei vegetal"]},"howIsMade":{"hi":"शैलट, लहसुन, अदरक, गलंगल, लेमनग्रास और भिगोई हुई मिर्चों को 2 बड़े चम्मच नारियल के दूध के साथ पूरी तरह चिकना पेस्ट बनने तक मिलाएं — लगभग 2 मिनट। एक बड़े भारी बर्तन में मध्यम आंच पर तेल गर्म करें, मसाले का पेस्ट डालें और 5-6 मिनट लगातार हिलाते हुए पकाएं जब तक गहरे सुनहरे रंग का न हो जाए और कच्ची खुशबू न जाए। बीफ के क्यूब्स डालें और पेस्ट से कोट करने के लिए मिलाएं; 3-4 मिनट हल्के रंग आने तक पकाएं। बचा हुआ नारियल का दूध डालें, काफिर लाइम पत्ते, हल्दी, धनिया, जीरा और नमक मिलाएं। उबाल लाएं, फिर आंच मध्यम-धीमी करें और बिना ढके 1.5 घंटे पकाएं, हर 15-20 मिनट में हिलाते हुए, जब तक नारियल का दूध काफी गाढ़ा हो जाए और हल्के भूरे रंग का न हो जाए। और अधिक बार हिलाते हुए (हर 5-10 मिनट) 30-45 मिनट और पकाएं जब तक सॉस लगभग पूरी तरह कम न हो जाए और तेल अलग न हो जाए; मांस अपनी खुद की चर्बी में तलने लगेगा और गहरे महागनी भूरे रंग का हो जाएगा। उबले हुए सफेद चावल के साथ परोसें।","en":"Blend the shallots, garlic, ginger, galangal, lemongrass, and soaked chillies with 2 tbsp of the coconut milk until completely smooth — about 2 minutes in a food processor. Heat the oil in a large heavy pot over medium heat, add the spice paste and cook for 5-6 minutes, stirring constantly, until deep golden and the raw smell has gone. Add the beef cubes and stir to coat with the paste; cook for 3-4 minutes until lightly coloured. Pour in the remaining coconut milk, add the kaffir lime leaves, turmeric, coriander, cumin, and salt, and stir to combine. Bring to a boil, then reduce to medium-low and simmer uncovered for 1.5 hours, stirring every 15-20 minutes, until the coconut milk thickens significantly and turns light brown. Continue cooking, stirring more frequently (every 5-10 minutes), for another 30-45 minutes as the sauce reduces to almost nothing and the oil splits from the coconut; the beef will begin to fry in its own fat and turn deep mahogany brown — this is when rendang is ready. Serve with steamed white rice."}},{"id":79,"servings":4,"tipType":"fish","timeMins":{"total":4380,"active":45},"pairingsType":"fish","origin":{"hi":"स्वीडन","en":"Sweden","ro":"Suedia"},"name":{"hi":"ग्रावलाक्स","en":"Gravlax","ro":"Gravlax"},"category":{"hi":"नाश्ता","en":"Snack","ro":"Gustare"},"ingredients":{"hi":["600 ग्राम सालमन फ़िलेट, त्वचा सहित, कांटे निकले हुए","3 बड़े चम्मच मोटा समुद्री नमक","2 बड़े चम्मच चीनी","1 छोटा चम्मच सफेद काली मिर्च के दाने, मोटे कुचले हुए","60 ग्राम ताजा डिल (1 बड़ा गुच्छा), मोटा कटा हुआ","2 बड़े चम्मच अकुआविट या वोदका (वैकल्पिक)"],"en":["600 g salmon fillet, skin-on and pin-boned","3 tbsp coarse sea salt","2 tbsp caster sugar","1 tsp white peppercorns, coarsely crushed","60 g fresh dill (1 large bunch), roughly chopped","2 tbsp aquavit or vodka (optional)"],"ro":["600 g file de somon cu piele, cu oasele îndepărtate","3 linguri sare grunjoasă de mare","2 linguri zahăr tos","1 linguriță boabe de piper alb, zdrobite grosier","60 g mărar proaspăt (1 legătură mare), tocat grosier","2 linguri aquavit sau vodcă (opțional)"]},"howIsMade":{"hi":"एक छोटे कटोरे में मोटा नमक, चीनी और कुचली हुई सफेद काली मिर्च मिलाएं। सालमन को एक बड़े क्लिंग फिल्म पर त्वचा की तरफ नीचे रखें; आधे डिल को मांस पर समान रूप से दबाएं, नमक का मिश्रण ऊपर से समान रूप से फैलाएं, अकुआविट छिड़कें यदि उपयोग कर रहे हैं, फिर बाकी डिल से ढक दें। क्लिंग फिल्म में कसकर लपेटें और एक गहरे बर्तन में रखें, मछली को दबाने के लिए ऊपर एक भारी प्लेट रखें। 48-72 घंटे रेफ्रिजरेट करें, हर 12 घंटे में पैकेज पलटें जैसे यह ठीक होता है — नमकीन पानी बर्तन में जमा होगा। खोलें, ठंडे पानी से धोएं और कागज के तौलिये से सुखाएं। एक लचीले चाकू से विकर्ण में बहुत पतले स्लाइस काटें और काली राई की रोटी पर सरसों-डिल सॉस के साथ परोसें।","en":"Mix the coarse salt, sugar, and crushed peppercorns in a small bowl. Lay the salmon skin-side down on a large piece of cling film; press half the dill evenly over the flesh, spread the cure uniformly over the top, drizzle with aquavit if using, then cover with the remaining dill. Wrap tightly in the cling film and place in a deep dish, setting a heavy plate on top to press the fish. Refrigerate for 48-72 hours, turning the parcel every 12 hours as it cures — brine will pool in the dish. Unwrap, rinse under cold water, and pat dry with paper towels. Slice very thinly on the diagonal with a sharp flexible knife and serve on dark rye bread with a mustard-dill sauce."}},{"id":80,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"hi":"बेल्जियम","en":"Belgium","ro":"Belgia"},"name":{"hi":"स्टोफ्वलीस","en":"Stoofvlees","ro":"Stoofvlees"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["1 किलो धीमी आंच पर पकाने योग्य बीफ (कंधा या सीना), 4 सेमी के टुकड़ों में काटा हुआ","330 मिली बेल्जियन डार्क बियर (Leffe Brune या समान)","500 ग्राम प्याज (लगभग 3 मध्यम), पतले कटे हुए","2 बड़े चम्मच डिजोन मस्टर्ड","2 मोटी स्लाइस (लगभग 80 ग्राम) बासी भूरी रोटी, बिना ऊपरी परत","2 बड़े चम्मच तटस्थ तेल","2 तेजपत्ते","3 ताजा थाइम की डालियां","1 बड़ा चम्मच ब्राउन शुगर","1 बड़ा चम्मच लाल वाइन सिरका","1 छोटा चम्मच बारीक नमक","आधा छोटा चम्मच पिसी काली मिर्च"],"en":["1 kg beef stew meat (chuck or brisket), cut into 4 cm cubes","330 ml dark Belgian ale (Leffe Brune or similar)","500 g onions (about 3 medium), thinly sliced","2 tbsp Dijon mustard","2 thick slices (about 80 g) stale brown bread, crusts removed","2 tbsp neutral oil","2 bay leaves","3 fresh thyme sprigs","1 tbsp brown sugar","1 tbsp red wine vinegar","1 tsp fine salt","1/2 tsp ground black pepper"],"ro":["1 kg carne de vită pentru tocăniță (capac sau piept), tăiată cuburi de 4 cm","330 ml bere belgiană brună (Leffe Brune sau similară)","500 g ceapă (circa 3 medii), feliată subțire","2 linguri muștar Dijon","2 felii groase (circa 80 g) pâine brună veche, fără coajă","2 linguri ulei neutru","2 foi de dafin","3 crenguțe de cimbru proaspăt","1 lingură zahăr brun","1 lingură oțet de vin roșu","1 linguriță sare fină","1/2 linguriță piper negru măcinat"]},"howIsMade":{"hi":"मांस को नमक और काली मिर्च से तैयार करें। एक बड़े भारी बर्तन में मध्यम-तेज आंच पर तेल गरम करें और मांस को बैचों में 3-4 मिनट प्रति तरफ गहरे सुनहरे रंग तक भूनें; फिर बाहर निकाल लें। आंच कम करें, उसी बर्तन में प्याज डालें और कभी-कभी हिलाते हुए 12-15 मिनट नरम और सुनहरा होने तक पकाएं। मांस को वापस बर्तन में डालें, तेजपत्ते और थाइम डालें, और बियर डालें — बियर को लगभग मांस को ढकना चाहिए। प्रत्येक रोटी के एक तरफ उदारता से मस्टर्ड लगाएं और मस्टर्ड वाला भाग नीचे करके स्टू पर रखें; रोटी घुलकर सॉस को गाढ़ा बनाएगी। ब्राउन शुगर और सिरका मिलाएं, धीमा उबाल आने दें, ढक्कन थोड़ा खोलकर धीमी आंच पर 2 घंटे पकाएं, हर 30 मिनट में हिलाते रहें, जब तक मांस बहुत नरम न हो जाए। आखिरी 20-30 मिनट ढक्कन हटाकर सॉस को गाढ़ा, चमकदार ग्रेवी बनाएं जो चम्मच की पीठ पर चिपके; तेजपत्ते और थाइम हटाएं और फ्राइड आलू या मैश किए आलू के साथ परोसें।","en":"Season the beef with salt and pepper. Heat the oil in a large heavy casserole over medium-high and brown the beef in batches for 3-4 minutes per side until deeply golden; transfer to a plate. Reduce heat to medium, add the onions to the same pot and cook for 12-15 minutes, stirring occasionally, until soft and golden. Return the beef to the pot, tuck in the bay leaves and thyme, and pour in the beer — it should nearly cover the meat. Spread one side of each bread slice thickly with mustard and lay them mustard-side down on top of the stew; the bread will dissolve and thicken the sauce. Stir in the brown sugar and vinegar, bring to a gentle simmer, cover with the lid slightly ajar, and cook over low heat for 2 hours, stirring every 30 minutes, until the beef is very tender. Remove the lid for the final 20-30 minutes to reduce the sauce to a glossy dark gravy that coats the back of a spoon; discard the bay leaves and thyme and serve with frites or mashed potato."}},{"id":81,"servings":4,"tipType":"soup","pairingsType":"soup","origin":{"hi":"मोल्दोवा","en":"Moldova","ro":"Moldova"},"name":{"hi":"ज़ियामा","en":"Zeama","ro":"Zeamă"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"ingredients":{"hi":["1 किलो हड्डी सहित चिकन के टुकड़े (टांगें और जांघें)","2 मध्यम गाजर (लगभग 200 ग्राम), छिली हुई और आधी कटी","1 मध्यम प्याज, आधा काटा हुआ","2 अजवाइन की डालियां पत्तियों सहित","150 ग्राम पतले अंडे के नूडल्स","200 मिली borș या 4 बड़े चम्मच ताजा नींबू का रस","ताजा लवेज का छोटा गुच्छा (लगभग 15 ग्राम), मोटा कटा हुआ, या अजमोद","1 छोटा चम्मच बारीक नमक","1/2 छोटा चम्मच सफेद काली मिर्च"],"en":["1 kg bone-in chicken pieces (legs and thighs)","2 medium carrots (about 200 g), peeled and halved","1 medium onion, halved","2 celery stalks with leaves","150 g thin egg noodles","200 ml borș (fermented wheat bran liquid) or 4 tbsp fresh lemon juice","1 small bunch fresh lovage (about 15 g), roughly chopped, or flat-leaf parsley","1 tsp fine salt","1/2 tsp white pepper"],"ro":["1 kg bucăți de pui cu os (pulpe și coapse)","2 morcovi medii (circa 200 g), curățați și tăiați în jumătate","1 ceapă medie, tăiată în jumătate","2 tulpini de țelină cu frunze","150 g tăiței subțiri de ou","200 ml borș sau 4 linguri suc proaspăt de lămâie","1 legătură mică leuștean proaspăt (circa 15 g), tocat grosier, sau pătrunjel","1 linguriță sare fină","1/2 linguriță piper alb"]},"howIsMade":{"hi":"चिकन को एक बड़े बर्तन में रखें, 2 लीटर ठंडे पानी से ढकें और मध्यम-तेज आंच पर उबालें; पहले 5-10 मिनट में ऊपर आने वाले झाग को निकालें जब तक शोरबा साफ न हो जाए। गाजर, प्याज और अजवाइन डालें, आंच को मध्यम-धीमी करें, आंशिक रूप से ढकें और 45-50 मिनट उबालें जब तक चिकन पूरी तरह पक न जाए और हड्डी से न उतर जाए। चिकन और सब्जियां निकालें; प्याज फेंक दें, गाजर को गोल टुकड़ों में काटें और चिकन को छोटे-छोटे टुकड़ों में फाड़ें, त्वचा और हड्डियां हटाएं। फाड़े हुए चिकन और गाजर के टुकड़े वापस बर्तन में डालें और मध्यम आंच पर फिर से उबाल लाएं। नूडल्स डालें और 5-7 मिनट (या पैकेट के निर्देशानुसार) तक पकाएं जब तक नरम न हो जाएं। borș या नींबू का रस डालें, हिलाएं और चखें — सूप में एक सुखद खटास होनी चाहिए; जरूरत के अनुसार और डालें। नमक और सफेद काली मिर्च से स्वाद लें, लवेज या अजमोद डालें और तुरंत परोसें।","en":"Place the chicken in a large pot, cover with 2 litres of cold water, and bring to a boil over medium-high heat; skim the foam that rises for the first 5-10 minutes until the broth runs clear. Add the carrots, onion, and celery, reduce heat to medium-low, partially cover, and simmer for 45-50 minutes until the chicken is cooked through and falling from the bone. Lift out the chicken and vegetables; discard the onion, slice the carrots into rounds, and shred the chicken into bite-sized pieces, discarding skin and bones. Return the shredded chicken and carrot rounds to the pot and bring back to a simmer over medium heat. Add the noodles and cook for 5-7 minutes (or per packet) until just tender. Pour in the borș or lemon juice, stir, and taste — the soup should have a pleasant sour edge; add more as needed. Season with salt and white pepper, stir in the lovage or parsley, and serve immediately."}},{"id":82,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"hi":"ऑस्ट्रेलिया","en":"Australia","ro":"Australia"},"name":{"hi":"मीट पाई","en":"Meat Pie","ro":"Meat Pie"},"category":{"hi":"नाश्ता","en":"Snack","ro":"Gustare"},"ingredients":{"hi":["375 ग्राम रेडीमेड शॉर्टक्रस्ट पेस्ट्री (बेस के लिए)","250 ग्राम रेडीमेड पफ पेस्ट्री (ढक्कन के लिए)","500 ग्राम लीन बीफ मिंस","1 मध्यम प्याज (लगभग 150 ग्राम), बारीक कटा हुआ","2 लहसुन की कलियां, कुचली हुई","250 मिली बीफ स्टॉक","2 बड़े चम्मच टोमेटो पेस्ट","1 बड़ा चम्मच वोर्सेस्टरशायर सॉस","2 बड़े चम्मच मैदा","1 अंडा, हल्का फेंटा हुआ, ब्रश करने के लिए","1 छोटा चम्मच बारीक नमक","1/2 छोटा चम्मच पिसी काली मिर्च"],"en":["375 g ready-made shortcrust pastry","250 g ready-made puff pastry","500 g lean beef mince","1 medium onion (about 150 g), finely diced","2 garlic cloves, minced","250 ml beef stock","2 tbsp tomato paste","1 tbsp Worcestershire sauce","2 tbsp plain flour","1 egg, lightly beaten, for brushing","1 tsp fine salt","1/2 tsp ground black pepper"],"ro":["375 g aluat fraged gata preparat","250 g aluat foietaj gata preparat","500 g carne de vită tocată (slabă)","1 ceapă medie (circa 150 g), tăiată mărunt","2 căței de usturoi, pisați","250 ml supă de vită","2 linguri pastă de roșii","1 lingură sos Worcestershire","2 linguri făină albă","1 ou, bătut ușor, pentru uns","1 linguriță sare fină","1/2 linguriță piper negru măcinat"]},"howIsMade":{"hi":"ओवन को 200°C (180°C फैन) पर पहले से गर्म करें। एक बड़े फ्राइंग पैन में थोड़ा तेल गरम करें मध्यम-तेज आंच पर, प्याज और लहसुन डालें और 3-4 मिनट नरम होने तक पकाएं। बीफ मिंस डालें और चम्मच से तोड़ते हुए 6-8 मिनट तक सभी तरफ से भूरा होने तक पकाएं। मैदा मिलाएं, 1 मिनट पकाएं, फिर स्टॉक, टोमेटो पेस्ट, वोर्सेस्टरशायर सॉस, नमक और काली मिर्च डालें; अच्छे से मिलाएं। मध्यम आंच पर 12-15 मिनट उबालें, कभी-कभी हिलाते हुए, जब तक ग्रेवी गाढ़ी होकर चम्मच की पीठ पर चिपके — भरावन गीला होना चाहिए लेकिन पतला नहीं; आंच से हटाएं और 15 मिनट ठंडा करें। शॉर्टक्रस्ट पेस्ट्री बेलें और 4 गोल काटें जो 4 व्यक्तिगत पाई टिन (लगभग 12 सेमी) में बिछाएं; टिन में दबाएं और बेस को कांटे से छेदें। भरावन को टिनों में समान रूप से बांटें, पफ पेस्ट्री की ढक्कन रखें, किनारे दबाकर सील करें और पीटे हुए अंडे से ब्रश करें। 25-30 मिनट तक बेक करें जब तक पेस्ट्री गहरे सुनहरे रंग की और ढक्कन फूले हुए व कुरकुरे न हो जाएं; 5 मिनट आराम दें फिर टमाटर सॉस के साथ परोसें।","en":"Preheat the oven to 200°C (180°C fan). Heat a drizzle of oil in a large frying pan over medium-high heat, add the onion and garlic and cook for 3-4 minutes until softened. Add the beef mince and cook, breaking it up with a spoon, for 6-8 minutes until browned all over. Stir in the flour, cook for 1 minute, then add the stock, tomato paste, Worcestershire sauce, salt, and pepper; stir to combine. Simmer over medium heat for 12-15 minutes, stirring occasionally, until the gravy thickens to coat the back of a spoon — the filling should be moist but not runny; remove from heat and cool for 15 minutes. Roll out the shortcrust pastry and cut 4 circles to line 4 individual pie tins (about 12 cm diameter); press into the tins and prick the bases with a fork. Divide the filling evenly between the tins, top with puff pastry lids, press the edges to seal, and brush with beaten egg. Bake for 25-30 minutes until deep golden and the lids are puffed and crisp; rest for 5 minutes then serve with tomato sauce."}},{"id":83,"servings":4,"tipType":"def","pairingsType":"middle-eastern","origin":{"hi":"सीरिया","en":"Syria","ro":"Siria"},"name":{"hi":"फत्ते","en":"Fatteh","ro":"Fatteh"},"category":{"hi":"नाश्ता","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"hi":["2 बड़े पीटा ब्रेड (लगभग 200 ग्राम), एक-एक निवाले के आकार में फाड़े हुए","400 ग्राम डिब्बाबंद छोले (1 x 400 ग्राम), छाने और धोए हुए","500 ग्राम फुल-फैट सादा दही","3 लहसुन की कलियां, कुचली हुई","2 बड़े चम्मच तहिनी","2 बड़े चम्मच ताजा नींबू का रस","3 बड़े चम्मच अनसाल्टेड मक्खन","50 ग्राम चीड़ के बीज (पाइन नट्स)","1 छोटा चम्मच पिसा जीरा","1 छोटा चम्मच मीठी पापरिका","1/2 छोटा चम्मच बारीक नमक","2 बड़े चम्मच ताजा अजमोद, बारीक कटा हुआ"],"en":["2 large pita breads (about 200 g), torn into bite-sized pieces","400 g canned chickpeas (1 x 400 g can), drained and rinsed","500 g full-fat plain yogurt","3 garlic cloves, minced","2 tbsp tahini","2 tbsp fresh lemon juice","3 tbsp unsalted butter","50 g pine nuts","1 tsp ground cumin","1 tsp sweet paprika","1/2 tsp fine salt","2 tbsp fresh parsley, finely chopped"],"ro":["2 pâini pita mari (circa 200 g), rupte în bucăți","400 g năut din conservă (1 x 400 g), scurs și clătit","500 g iaurt integral simplu","3 căței de usturoi, pisați","2 linguri tahini","2 linguri suc proaspăt de lămâie","3 linguri unt nesărat","50 g semințe de pin","1 linguriță chimion măcinat","1 linguriță boia dulce","1/2 linguriță sare fină","2 linguri pătrunjel proaspăt, tocat fin"]},"howIsMade":{"hi":"ओवन को 200°C पर पहले से गर्म करें। पीटा के टुकड़ों को थोड़े तेल के साथ मिलाएं, बेकिंग ट्रे पर फैलाएं और 8-10 मिनट तक सुनहरे और कुरकुरे होने तक बेक करें। छोले निथारें; एक छोटे बर्तन में नमक की एक चुटकी और जीरे के साथ मध्यम आंच पर 3-4 मिनट गर्म करें। दही, कुचला हुआ लहसुन, तहिनी, नींबू का रस और नमक को चिकनी चटनी बनने तक मिलाएं; स्वाद के अनुसार समायोजित करें। बेक किए हुए पीटा के टुकड़े एक बड़े सर्विंग प्लेट पर समान परत में फैलाएं। गरम छोले पीटा परत के ऊपर समान रूप से बिछाएं। दही की चटनी छोले के ऊपर उदारतापूर्वक डालें, सब कुछ ढकें। एक छोटे पैन में मध्यम आंच पर मक्खन पिघलाएं; चीड़ के बीज डालें और 2-3 मिनट हिलाते हुए सुनहरा होने तक भूनें; पापरिका डालें और तुरंत गर्म मक्खन और बीज दही के ऊपर डालें। कटा हुआ अजमोद ऊपर से छिड़कें और पीटा नरम होने से पहले तुरंत परोसें।","en":"Preheat the oven to 200°C. Toss the pita pieces with a drizzle of oil, spread on a baking tray and bake for 8-10 minutes until golden and crisp. Drain the chickpeas; heat in a small saucepan with a pinch of salt and cumin over medium heat for 3-4 minutes until warmed through. Whisk the yogurt, garlic, tahini, lemon juice, and salt until smooth; taste and adjust seasoning. Spread the toasted pita pieces in an even layer on a large serving platter. Spoon the warm chickpeas evenly over the pita. Pour the yogurt sauce over the chickpeas, covering everything generously. Melt the butter in a small pan over medium heat; add the pine nuts and cook for 2-3 minutes, stirring, until golden; stir in the paprika and immediately drizzle the hot butter and pine nuts over the yogurt. Scatter the chopped parsley on top and serve immediately before the pita softens."}},{"id":84,"servings":4,"tipType":"def","pairingsType":"def","origin":{"hi":"डेनमार्क","en":"Denmark","ro":"Danemarca"},"name":{"hi":"स्मोरेब्रोड","en":"Smørrebrød","ro":"Smørrebrød"},"category":{"hi":"नाश्ता","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"hi":["8 मोटी डेनिश राई ब्रेड (रगब्रोड) की स्लाइस, लगभग 400 ग्राम","100 ग्राम अनसाल्टेड मक्खन, नरम किया हुआ","400 ग्राम अचारी हेरिंग फ़िलेट्स (8 फ़िलेट्स), छाने हुए","4 अंडे, 10 मिनट उबाले हुए, छिले और गोल कटे हुए","1 छोटा लाल प्याज (लगभग 80 ग्राम), बहुत पतले छल्लों में कटा हुआ","4 मूली, पतले गोल कटी हुई","2 बड़े चम्मच केपर्स, छाने हुए","4 बड़े चम्मच खट्टी क्रीम या क्रेम फ्रेशे","1 छोटा चम्मच डिजोन मस्टर्ड","ताजा डिल की छोटी गुच्छी (लगभग 15 ग्राम)","1/2 छोटा चम्मच बारीक नमक"],"en":["8 slices dark rye bread (rugbrød), about 400 g","100 g unsalted butter, softened","400 g pickled herring fillets (8 fillets), drained","4 eggs, hard-boiled (10 minutes), peeled and sliced into rounds","1 small red onion (about 80 g), very finely sliced into rings","4 radishes, thinly sliced into rounds","2 tbsp capers, drained","4 tbsp soured cream or crème fraîche","1 tsp Dijon mustard","1 small bunch fresh dill (about 15 g)","1/2 tsp fine salt"],"ro":["8 felii de pâine daneză de secară (rugbrød), circa 400 g","100 g unt nesărat, înmuiat","400 g hering murat (8 fileuri), scurs","4 ouă fierte tari (10 minute), decojite și feliate în rondele","1 ceapă roșie mică (circa 80 g), feliată subțire în inele","4 ridichi, feliate subțire în rondele","2 linguri capere, scurse","4 linguri smântână sau crème fraîche","1 linguriță muștar Dijon","1 legătură mică de mărar proaspăt (circa 15 g)","1/2 linguriță sare fină"]},"howIsMade":{"hi":"अंडे उबालें: उन्हें उबलते पानी में 10 मिनट पकाएं, फिर 5 मिनट के लिए ठंडे पानी में रखें; छीलें और गोल स्लाइस करें। एक छोटे कटोरे में खट्टी क्रीम, डिजोन मस्टर्ड और नमक की एक चुटकी मिलाएं। प्रत्येक राई ब्रेड स्लाइस को किनारों तक नरम मक्खन से उदारतापूर्वक फैलाएं — प्रति स्लाइस लगभग 1 बड़ा चम्मच। प्रत्येक मक्खन लगी स्लाइस पर 1-2 अचारी हेरिंग फ़िलेट्स रखें, उन्हें सतह पर स्वाभाविक रूप से मुड़ने दें। हेरिंग के ऊपर मस्टर्ड क्रीम की एक छोटी चम्मच डालें, फिर बगल में 2-3 अंडे के गोल रखें। ऊपर से लाल प्याज के छल्ले, मूली के स्लाइस और केपर्स छिड़कें। ताजे डिल की टहनियों से सजाएं और ठंडी बियर या अकुआविट के साथ तुरंत परोसें।","en":"Hard-boil the eggs: lower into boiling water and cook for 10 minutes, then transfer to cold water for 5 minutes before peeling and slicing into rounds. Mix the soured cream with the Dijon mustard and a pinch of salt in a small bowl. Spread each slice of rye bread generously with softened butter right to the edges — about 1 tablespoon per slice. Lay 1-2 pickled herring fillets on each buttered slice, letting them curve naturally over the surface. Spoon a small dollop of mustard cream onto the herring, then arrange 2-3 egg rounds alongside. Scatter red onion rings, radish slices, and capers over the top. Finish with fresh dill sprigs and serve immediately with a cold beer or aquavit."}},{"id":85,"origin":{"hi":"उत्तर कोरिया","en":"North Korea","ro":"Coreea de Nord"},"name":{"hi":"नेंगम्योन","en":"Naengmyeon","ro":"Naengmyeon"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","timeMins":{"total":600,"active":60},"pairingsType":"korean","ingredients":{"hi":["400 ग्राम सूखे कुट्टू के नूडल्स (मेमिल-गुकसू)","300 ग्राम बीफ ब्रिस्किट, नरम होने तक उबाला, ठंडा किया और पतला कटा हुआ","1.5 लीटर बीफ ब्रिस्किट शोरबा, पूरी तरह ठंडा और चर्बी हटाया हुआ","1 कोरियाई नाशपाती (नाशी), छीली और पतली कटी हुई","1 मध्यम खीरा, जूलियन कटा हुआ","4 कड़े उबले अंडे, आधे कटे हुए","2 बड़े चम्मच चावल का सिरका","1 छोटा चम्मच कोरियाई मस्टर्ड (ग्योजा) या अंग्रेजी मस्टर्ड","1 बड़ा चम्मच गोचुगारू (वैकल्पिक, टेबल मसाले के रूप में)","शोरबे के लिए स्वादानुसार नमक और चीनी","जरूरत के अनुसार बर्फ के टुकड़े"],"en":["400g dried buckwheat noodles (memil-guksu)","300g beef brisket, simmered until tender, chilled, thinly sliced","1.5L beef brisket broth, fully chilled and defatted","1 Korean pear (nashi), peeled, thinly sliced","1 medium cucumber, julienned","4 hard-boiled eggs, halved","2 tbsp rice vinegar","1 tsp Korean mustard (gyeoja) or English mustard","1 tbsp gochugaru (optional, as table condiment)","salt and sugar to taste for the broth","ice cubes as needed"],"ro":["400g tăiței de hrișcă uscați (memil-guksu)","300g piept de vită, fiert și refrigerat, feliat subțire","1.5L supă de piept de vită (răcită complet la frigider, degresată)","1 pară coreeană (nashi), curățată, feliată subțire","1 castravete mediu, feliat julien","4 ouă fierte tari, înjumătățite","2 linguri oțet de orez","1 linguriță muștar coreean (gyeoja) sau muștar englez","1 lingură gochugaru (opțional, pentru condiment la masă)","sare și zahăr după gust pentru supa de bază","cuburi de gheață — câte este necesar"]},"howIsMade":{"hi":"एक दिन पहले: बीफ ब्रिस्किट को 2 लीटर पानी में 1 छोटा चम्मच नमक, 2 सेमी अदरक का टुकड़ा और 3 हरे प्याज के साथ धीमी आंच पर 1.5–2 घंटे पकाएं। मांस को शोरबे में ठंडा होने दें, फिर रात भर फ्रिज में रखें। अगले दिन जमी हुई चर्बी की परत हटाएं। ठंडे शोरबे को चावल के सिरके, चीनी और नमक से सीज़न करें — यह हल्का खट्टा और हल्का मीठा होना चाहिए। जरूरत पड़े तो बर्फ से और ठंडा करें। नूडल्स को पैकेट के निर्देशानुसार पकाएं (आमतौर पर 3–4 मिनट), छान लें और तुरंत 30 सेकंड के लिए ठंडे बहते पानी के नीचे हाथों से रगड़ते हुए धोएं। गहरे कटोरों में नूडल्स रखें और उन्हें ढकने के लिए ठंडा शोरबा डालें। ऊपर से कटे हुए ब्रिस्किट, नाशपाती, जूलियन खीरा और आधा कटा अंडा रखें। सिरके और मस्टर्ड के साथ तुरंत परोसें।","en":"Day before: simmer beef brisket in 2L water with 1 tsp salt, a 2 cm piece of ginger, and 3 spring onions over low heat for 1.5–2 hours. Let meat cool in the broth, then refrigerate overnight. Next day, lift off the solidified fat layer. Season the cold broth with rice vinegar, sugar, and salt — it should be lightly tart and subtly sweet. Chill further with ice if needed. Cook noodles per packet (usually 3–4 minutes), drain and immediately rinse under cold running water for 30 seconds, rubbing with hands to remove starch and chill completely. Nest noodles in deep bowls. Ladle cold broth to cover. Top with sliced brisket, pear, julienned cucumber, and halved egg. Serve at once with vinegar and mustard on the side."}},{"id":86,"origin":{"hi":"पाकिस्तान","en":"Pakistan","ro":"Pakistan"},"name":{"hi":"निहारी","en":"Nihari","ro":"Nihari"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"indian","ingredients":{"hi":["1 किलो हड्डी-सहित गाय की पतली नली (बीफ शैंक), 5 सेमी टुकड़ों में कटी हुई","2 नली की हड्डी (मैरो बोन), प्रत्येक लगभग 5 सेमी लंबी","4 बड़े चम्मच घी या मक्खन","2 बड़े प्याज (~300 ग्राम), पतले कटे हुए","2 बड़े चम्मच अदरक-लहसुन का पेस्ट","1.5 छोटे चम्मच लाल मिर्च पाउडर","1 छोटा चम्मच धनिया पाउडर","1/2 छोटा चम्मच हल्दी पाउडर","1.5 छोटे चम्मच नमक","1 छोटा चम्मच निहारी मसाला या गरम मसाला","3 बड़े चम्मच आटा, 100 मिली ठंडे पानी में मिलाकर","5 सेमी ताजा अदरक, छीलकर कतरा हुआ, परोसने के लिए","1 नींबू, टुकड़ों में काटा, और ताजी धनिये की पत्तियाँ, परोसने के लिए"],"en":["1 kg bone-in beef shanks, cut into 5 cm pieces","2 marrow bones, each about 5 cm long","4 tbsp ghee or clarified butter","2 large onions (~300 g), thinly sliced","2 tbsp ginger-garlic paste","1.5 tsp red chilli powder","1 tsp ground coriander","1/2 tsp ground turmeric","1.5 tsp salt","1 tsp nihari masala or garam masala","3 tbsp plain flour mixed with 100 ml cold water","5 cm piece of fresh ginger, peeled and julienned, to serve","1 lemon cut into wedges and a handful of fresh coriander leaves, to serve"],"ro":["1 kg rasol de vită cu os, tăiat în bucăți de 5 cm","2 oase cu măduvă, fiecare de aproximativ 5 cm","4 linguri unt clarificat (ghee) sau ulei","2 cepe mari (~300 g), feliate subțire","2 linguri pastă de ghimbir și usturoi","1,5 linguriță praf de ardei iute roșu","1 linguriță coriandru măcinat","1/2 linguriță turmeric măcinat","1,5 linguriță sare","1 linguriță masala nihari sau garam masala","3 linguri făină albă amestecate cu 100 ml apă rece","5 cm ghimbir proaspăt, curățat și juliennat, pentru servire","1 lămâie tăiată în felii și un mănunchi de frunze de coriandru, pentru servire"]},"howIsMade":{"hi":"एक बड़े भारी बर्तन में 3 बड़े चम्मच घी मध्यम-तेज़ आंच पर गर्म करें और प्याज को 12–15 मिनट तक बार-बार हिलाते हुए गहरा सुनहरा होने तक भूनें, फिर छलनी चम्मच से निकाल लें। बचा हुआ घी डालें, आंच तेज़ करें और गाय की पतली नली और नली की हड्डियों को बैचों में 3–4 मिनट प्रति साइड तक भूरा कर लें। आंच मध्यम करें, अदरक-लहसुन पेस्ट डालकर 1–2 मिनट भूनें, फिर लाल मिर्च, धनिया और हल्दी डालकर 30 सेकंड चलाएं। मांस और भूना प्याज वापस बर्तन में डालें, नमक और पानी डालें ताकि मांस के ऊपर 5 सेमी पानी हो (लगभग 1.2 लीटर), उबाल आने पर झाग हटाएं। आंच न्यूनतम करें, ढक्कन कसकर बंद करें और 3–4 घंटे पकाएं जब तक मांस हड्डी से आसानी से अलग न हो जाए। निहारी मसाला मिलाएं, आटे का घोल पतली धारा में डालते हुए लगातार हिलाएं और बिना ढक्कन के 10–15 मिनट पकाएं जब तक शोरबा गाढ़ा न हो जाए और चम्मच की पीठ पर चढ़ने लगे। कटोरे में परोसें, कतरे अदरक, धनिये की पत्तियाँ और नींबू का रस डालें, नान या कुरकुरी ब्रेड के साथ परोसें।","en":"Heat 3 tbsp ghee in a large heavy pot over medium-high heat and fry the onions for 12–15 minutes, stirring often, until deep golden brown, then remove with a slotted spoon and set aside. Add the remaining ghee, raise the heat to high, and sear the beef shanks and marrow bones in batches for 3–4 minutes per side until browned, then set aside. Reduce heat to medium, add the ginger-garlic paste and fry for 1–2 minutes until fragrant, then add the chilli powder, coriander, and turmeric and stir for 30 seconds. Return the meat and fried onions to the pot, add the salt and enough water to cover by 5 cm (about 1.2 litres), bring to a boil and skim any foam. Reduce heat to the lowest setting, cover tightly, and simmer for 3–4 hours until the beef is completely tender and falling from the bone. Stir in the nihari masala, pour in the flour slurry in a thin stream while stirring, and simmer uncovered for 10–15 minutes until the broth thickens to a glossy consistency that coats the back of a spoon. Ladle into bowls, top with julienned ginger, coriander leaves, and a squeeze of lemon, and serve with naan or crusty bread."}},{"id":87,"origin":{"hi":"वियतनाम","en":"Vietnam","ro":"Vietnam"},"name":{"hi":"बून बो ह्ये","en":"Bún bò Huế","ro":"Bún bò Huế"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","timeMins":{"total":195,"active":75},"pairingsType":"vietnamese","ingredients":{"hi":["600 ग्राम हड्डी-सहित सुअर की नली (पोर्क हॉक), 4 सेमी के टुकड़ों में कटी हुई","500 ग्राम गाय की हड्डियाँ, उबाली हुई","400 ग्राम गाय की नली (बीफ शैंक), पतली कटी हुई","400 ग्राम सूखे गोल चावल के सेवईं (बून)","3 लेमनग्रास डंडी, कुचलकर 5 सेमी में काटी हुई","3 शैलॉट, आधे काटकर सेंके हुए","4 लहसुन की कलियाँ, कुचली हुई","2 बड़े चम्मच किण्वित झींगे का पेस्ट (माम रुओक)","3 बड़े चम्मच फिश सॉस","2 बड़े चम्मच मिर्च का तेल या 1 छोटा चम्मच सूखी मिर्च के टुकड़े","1 छोटा चम्मच चीनी","1 छोटा चम्मच नमक","परोसने के लिए: 200 ग्राम अंकुरित सोयाबीन, ताजी जड़ी-बूटियाँ (पुदीना या वियतनामी धनिया), 2 नींबू चतुर्थांश में काटे और 2 लाल मिर्च पतली कटी हुई"],"en":["600 g bone-in pork hock, cut into 4 cm pieces","500 g beef bones, blanched","400 g beef shank, thinly sliced","400 g dried round rice vermicelli (bún)","3 lemongrass stalks, bruised and cut into 5 cm pieces","3 shallots, halved and charred","4 garlic cloves, bruised","2 tbsp fermented shrimp paste (mắm ruốc)","3 tbsp fish sauce","2 tbsp chilli oil or 1 tsp dried chilli flakes","1 tsp sugar","1 tsp salt","to serve: 200 g bean sprouts, fresh herbs (mint, perilla or Vietnamese coriander), 2 limes cut into wedges, and 2 red chillies sliced"],"ro":["600 g picior de porc cu os, tăiat în bucăți de 4 cm","500 g oase de vită, opărite","400 g rasol de vită, feliat subțire","400 g tăiței rotunzi de orez uscați (bún)","3 tulpini de lemongrass, zdrobite și tăiate în bucăți de 5 cm","3 șalote, tăiate pe jumătate și pârlite","4 căței de usturoi, zdrobiți","2 linguri pastă de creveți fermentați (mắm ruốc)","3 linguri sos de pește","2 linguri ulei de ardei iute sau 1 linguriță fulgi de ardei iute","1 linguriță zahăr","1 linguriță sare","pentru servit: 200 g muguri de fasole, ierburi proaspete (mentă sau coriandru vietnamez), 2 lămâi verzi în sferturi și 2 ardei iuți roșii felieți"]},"howIsMade":{"hi":"सुअर की नली और गाय की हड्डियों को 5 मिनट उबलते पानी में डालें, फिर छान लें और ठंडे पानी से धो लें। शैलॉट और लहसुन को कटे हुए भाग नीचे करके सूखे तवे पर तेज़ आंच पर 3–4 मिनट तक थोड़ा झुलसने तक सेंकें। बड़े बर्तन में सुअर की नली, हड्डियाँ, लेमनग्रास, सेंके हुए शैलॉट और लहसुन डालें, 2.5 लीटर ठंडा पानी डालें, उबाल लें, झाग निकालें और धीमी आंच पर 1 घंटे पकाएं। 100 मिली गर्म शोरबे में झींगे का पेस्ट घोलकर बर्तन में मिलाएं, फिर फिश सॉस, चीनी, नमक और मिर्च का तेल डालकर स्वाद को नमकीन, हल्का तीखा और खुशबूदार होने तक समायोजित करें। पतली कटी गाय की नली डालें और धीमी आंच पर 15–20 मिनट तक पोच करें जब तक पूरी तरह पक न जाए, फिर निकालकर पतला काटें। पैकेट के निर्देशों के अनुसार चावल के सेवईं पकाएं (आमतौर पर 3–5 मिनट), छानें और 4 गहरे कटोरों में बांटें। गर्म शोरबा ऊपर से डालें, सुअर और गाय के मांस के टुकड़े रखें और तुरंत अंकुरित सोयाबीन, ताजी जड़ी-बूटियाँ, नींबू के टुकड़े और मिर्च के साथ परोसें।","en":"Blanch the pork hock and beef bones in boiling water for 5 minutes, drain and rinse under cold water. Char the shallots and garlic cut-side down in a dry pan over high heat for 3–4 minutes until lightly blackened. Place the pork hock, bones, lemongrass, charred shallots, and garlic in a large pot, add 2.5 litres of cold water, bring to a boil, skim well, then simmer over low heat for 1 hour. Dissolve the shrimp paste in 100 ml of hot broth, stir into the pot, then add fish sauce, sugar, salt, and chilli oil, adjusting until the broth is savoury, lightly spicy, and fragrant. Add the beef shank slices and poach over gentle heat for 15–20 minutes until just cooked through and tender, then remove and slice thinly. Cook the rice vermicelli according to packet instructions (usually 3–5 minutes), drain, and divide among 4 deep bowls. Ladle the hot broth over the noodles, top with slices of pork hock and beef shank, and serve immediately with bean sprouts, fresh herbs, lime wedges, and sliced chilli on the side."}},{"id":88,"origin":{"hi":"ब्राज़ील","en":"Brazil","ro":"Brazilia"},"name":{"hi":"मोकेका","en":"Moqueca","ro":"Moqueca"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"fish","pairingsType":"latin","ingredients":{"hi":["800 ग्राम सफेद मछली के मोटे फिलेट (बास, कॉड या मॉन्कफिश), 5 सेमी टुकड़ों में कटे हुए","2 नींबू (लाइम), केवल रस","1 छोटा चम्मच नमक","1 बड़ा प्याज (~180 ग्राम), पतला कटा हुआ","4 लहसुन की कलियाँ, बारीक कटी हुई","1 लाल शिमला मिर्च (~150 ग्राम), बीज निकाली और कटी हुई","1 हरी शिमला मिर्च (~150 ग्राम), बीज निकाली और कटी हुई","2 बड़े पके टमाटर (~300 ग्राम), टुकड़ों में कटे हुए","400 मिली फुल-फैट नारियल दूध","2 बड़े चम्मच लाल पाम तेल (डेंडे)","20 ग्राम ताजी धनिया, मोटी कटी हुई, परोसने के लिए अतिरिक्त भी","1/2 छोटा चम्मच काली मिर्च पाउडर"],"en":["800 g firm white fish fillets (sea bass, cod, or monkfish), cut into 5 cm chunks","2 limes, juice only","1 tsp salt","1 large onion (~180 g), thinly sliced","4 garlic cloves, finely minced","1 red bell pepper (~150 g), deseeded and sliced","1 green bell pepper (~150 g), deseeded and sliced","2 large ripe tomatoes (~300 g), diced","400 ml full-fat coconut milk","2 tbsp dendê (red palm oil)","20 g fresh coriander, roughly chopped, plus extra to serve","1/2 tsp ground black pepper"],"ro":["800 g fileuri de pește alb ferm (biban de mare, cod sau merluciu), tăiate în bucăți de 5 cm","2 lămâi verzi (lime), sucul","1 linguriță sare","1 ceapă mare (~180 g), feliată subțire","4 căței de usturoi, tocați mărunt","1 ardei gras roșu (~150 g), curat și feliat","1 ardei gras verde (~150 g), curat și feliat","2 roșii coapte mari (~300 g), tocate cuburi","400 ml lapte de cocos integral","2 linguri ulei de palmier roșu (dendê)","20 g coriandru proaspăt, tocat grosier, plus extra pentru garnit","1/2 linguriță piper negru măcinat"]},"howIsMade":{"hi":"मछली के टुकड़ों को नींबू के रस, 1/2 छोटा चम्मच नमक और काली मिर्च के साथ मिलाएं और सब्जियाँ तैयार करते समय 15–20 मिनट के लिए मैरीनेट करें। एक बड़े चौड़े पैन में 1 बड़ा चम्मच डेंडे तेल मध्यम आंच पर गर्म करें, प्याज डालें और 6–8 मिनट तक नरम और हल्का सुनहरा होने तक भूनें। लहसुन, दोनों शिमला मिर्च और टमाटर डालकर अच्छी तरह चलाएं और 5 मिनट पकाएं जब तक टमाटर टूटने न लगें। मैरीनेट की हुई मछली सब्जियों के ऊपर एक परत में रखें, ऊपर से नारियल दूध डालें और मछली को बिना हिलाए धीरे से तरल में दबाएं। धीमी उबाल पर लाएं, ढकें और 12–15 मिनट पकाएं जब तक मछली अपारदर्शी न हो जाए और दबाने पर आसानी से टूटने लगे। बचा हुआ 1 बड़ा चम्मच डेंडे तेल ऊपर से डालें, धनिया छिड़कें और नमक समायोजित करें। सफेद चावल या ब्रेड के साथ नींबू के टुकड़े रखकर सीधे पैन से परोसें।","en":"Toss the fish chunks with the lime juice, 1/2 tsp salt, and the black pepper and leave to marinate for 15–20 minutes while you prepare the vegetables. Heat 1 tbsp dendê oil in a large wide pan over medium heat, add the onion slices, and cook for 6–8 minutes until softened and lightly golden. Add the garlic, bell peppers, and tomatoes, stir well, and cook for 5 minutes until the tomatoes begin to break down. Lay the marinated fish over the vegetables in a single layer, pour the coconut milk over the top, and gently push the fish down into the liquid without stirring. Bring to a gentle simmer, cover, and cook for 12–15 minutes until the fish is opaque and flakes easily when pressed. Drizzle the remaining 1 tbsp dendê oil over the surface, scatter the coriander on top, and taste for salt. Serve directly from the pan with white rice or crusty bread, with lime wedges on the side."}},{"id":89,"origin":{"hi":"इज़राइल","en":"Israel","ro":"Israel"},"name":{"hi":"साबिच","en":"Sabich","ro":"Sabich"},"category":{"hi":"नाश्ता","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"def","pairingsType":"middle-eastern","ingredients":{"hi":["4 बड़े पीटा ब्रेड","1 बड़ा बैंगन (~400 ग्राम), 1 सेमी मोटे गोल टुकड़ों में कटा हुआ","तलने के लिए 4 बड़े चम्मच तेल","4 अंडे","300 ग्राम आलू, नरम होने तक उबाले और 1 सेमी मोटे टुकड़ों में कटे","4 बड़े चम्मच ताहिनी पेस्ट","1 नींबू, केवल रस","1 लहसुन की कली, कुचली हुई","4 बड़े चम्मच अम्बा सॉस (किण्वित आम अचार की चटनी)","2 टमाटर (~200 ग्राम), बारीक कटे हुए","1 खीरा (~150 ग्राम), बारीक कटा हुआ","1 छोटा चम्मच नमक","4 टुकड़े अचारी खीरे और ताजी अजमोद, परोसने के लिए"],"en":["4 large pita breads","1 large aubergine (~400 g), cut into 1 cm rounds","4 tbsp oil for frying","4 eggs","300 g waxy potatoes, boiled until tender and sliced 1 cm thick","4 tbsp tahini paste","1 lemon, juice only","1 garlic clove, crushed","4 tbsp amba sauce (fermented mango pickle sauce)","2 tomatoes (~200 g), finely diced","1 cucumber (~150 g), finely diced","1 tsp salt","4 slices pickled cucumber and fresh parsley, to serve"],"ro":["4 lipii pita mari","1 vânătă mare (~400 g), tăiată în felii de 1 cm","4 linguri ulei pentru prăjit","4 ouă","300 g cartofi galbeni, fierți până sunt moi și feliați la 1 cm grosime","4 linguri pastă de tahini","1 lămâie, sucul","1 cățel de usturoi, zdrobit","4 linguri sos amba (sos din mango murat)","2 roșii (~200 g), tăiate mărunt","1 castravete (~150 g), tăiat mărunt","1 linguriță sare","4 felii castraveți murați și pătrunjel proaspăt, pentru servire"]},"howIsMade":{"hi":"अंडों को सख्त उबालें: उबलते पानी में डालें, 10 मिनट पकाएं, फिर 5 मिनट ठंडे पानी में रखें, छीलें और गोल टुकड़ों में काटें। बैंगन के टुकड़ों पर दोनों तरफ 1/2 छोटा चम्मच नमक छिड़कें और 10 मिनट रखें, फिर किचन टॉवल से पोंछ लें। एक बड़े पैन में तेल मध्यम-तेज़ आंच पर गर्म करें और बैंगन को बैचों में प्रत्येक साइड 3–4 मिनट तक गहरा सुनहरा और अंदर से नरम होने तक तलें, फिर कागज पर निकालें। ताहिनी को नींबू के रस, लहसुन और 3–4 बड़े चम्मच ठंडे पानी के साथ मिलाकर मलाईदार और बहने वाला बनाएं। कटे हुए टमाटर और खीरे को 1/2 छोटा चम्मच नमक और थोड़े से जैतून के तेल के साथ मिलाकर सलाद बनाएं। प्रत्येक पीटा ब्रेड को सूखे पैन में दोनों तरफ 1-1 मिनट गर्म करें, फिर सावधानी से जेब खोलें। प्रत्येक पीटा में तला बैंगन, आलू और अंडे के टुकड़े, सब्जी सलाद, भरपूर ताहिनी, अम्बा सॉस का एक चम्मच, अचारी खीरा और ताजी अजमोद भरें और तुरंत परोसें।","en":"Hard-boil the eggs: lower into boiling water, cook for 10 minutes, then transfer to cold water for 5 minutes, peel, and slice into rounds. Sprinkle the aubergine slices on both sides with 1/2 tsp salt and leave for 10 minutes, then pat dry with kitchen paper. Heat the oil in a large non-stick pan over medium-high heat and fry the aubergine in batches for 3–4 minutes per side until deep golden and tender throughout, then drain on kitchen paper. Whisk the tahini with the lemon juice, crushed garlic, and 3–4 tbsp cold water until creamy and pourable. Combine the diced tomatoes and cucumber with the remaining 1/2 tsp salt and a drizzle of olive oil. Warm each pita for 1 minute per side in a dry pan, then carefully open the pocket without tearing. Layer each pita with fried aubergine, sliced potato and egg, the tomato-cucumber salad, a generous drizzle of tahini sauce, a spoonful of amba sauce, pickled cucumber, and fresh parsley, and serve immediately."}},{"id":90,"origin":{"hi":"क्यूबा","en":"Cuba","ro":"Cuba"},"name":{"hi":"रोपा विएजा","en":"Ropa Vieja","ro":"Ropa Vieja"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"latin","ingredients":{"hi":["700 ग्राम गाय का फ्लैंक स्टेक या ब्रिस्केट","2 बड़े चम्मच जैतून का तेल","1 बड़ा प्याज (~200 ग्राम), पतला कटा हुआ","1 लाल शिमला मिर्च और 1 हरी शिमला मिर्च (प्रत्येक ~150 ग्राम), बीज निकालकर स्ट्रिप्स में कटी हुई","4 लहसुन की कलियाँ, बारीक कटी हुई","400 ग्राम डिब्बाबंद कुचले टमाटर","2 बड़े चम्मच टोमैटो पेस्ट","100 मिली सूखी सफेद वाइन","1 छोटा चम्मच जीरा पाउडर","1 छोटा चम्मच सूखा अजवायन (ओरेगानो)","2 तेज पत्ते","1 छोटा चम्मच नमक और 1/2 छोटा चम्मच काली मिर्च पाउडर"],"en":["700 g beef flank steak or brisket","2 tbsp olive oil","1 large onion (~200 g), thinly sliced","1 red bell pepper and 1 green bell pepper (~150 g each), deseeded and sliced","4 garlic cloves, finely minced","400 g canned crushed tomatoes","2 tbsp tomato paste","100 ml dry white wine","1 tsp ground cumin","1 tsp dried oregano","2 bay leaves","1 tsp salt and 1/2 tsp ground black pepper"],"ro":["700 g antricot sau piept de vită","2 linguri ulei de măsline","1 ceapă mare (~200 g), feliată subțire","1 ardei gras roșu și 1 ardei gras verde (~150 g fiecare), curățați și feliați","4 căței de usturoi, tocați mărunt","400 g roșii zdrobite la conservă","2 linguri pastă de roșii","100 ml vin alb sec","1 linguriță chimion măcinat","1 linguriță oregano uscat","2 foi de dafin","1 linguriță sare și 1/2 linguriță piper negru măcinat"]},"howIsMade":{"hi":"मांस को एक बर्तन में रखें, नमकीन ठंडे पानी से ढकें, उबाल आने पर झाग हटाएं, आंच कम करें और ढककर 1.5–2 घंटे पकाएं जब तक मांस आसानी से फाड़ा न जा सके। मांस निकालें, 200 मिली शोरबा बचाएं और मांस को लंबे रेशों में फाड़ लें। एक चौड़े पैन में जैतून का तेल मध्यम आंच पर गर्म करें, प्याज और दोनों शिमला मिर्च डालकर 8–10 मिनट नरम और हल्का रंगीन होने तक भूनें। लहसुन, जीरा और अजवायन डालकर 1 मिनट भूनें, फिर वाइन डालें और 2 मिनट आधी होने तक पकाएं। कुचले टमाटर, टोमैटो पेस्ट, बचाया शोरबा और तेज पत्ते डालें, नमक-मिर्च से स्वाद लें और 10 मिनट हल्का गाढ़ा होने तक पकाएं। फाड़ा हुआ मांस डालें, अच्छी तरह मिलाएं और 10–15 मिनट और पकाएं जब तक मांस सॉस सोख ले और मिश्रण रसीला हो जाए। तेज पत्ते निकालें और सफेद चावल और तले हुए केले के साथ परोसें।","en":"Place the beef in a pot, cover with cold salted water, bring to a boil, skim, reduce heat, and simmer covered for 1.5–2 hours until the meat pulls apart easily. Remove the beef, reserve 200 ml of the cooking liquid, and shred the meat into long strips. Heat the oil in a wide heavy pan over medium heat, add the onion and both bell peppers, and cook for 8–10 minutes until softened and beginning to colour. Add the garlic, cumin, and oregano and stir for 1 minute, then pour in the white wine and cook for 2 minutes until reduced by half. Stir in the crushed tomatoes, tomato paste, reserved cooking liquid, and bay leaves, season with salt and pepper, and simmer for 10 minutes until the sauce thickens slightly. Add the shredded beef, stir to combine, and simmer for 10–15 minutes more until the beef absorbs the sauce and the mixture is juicy but not soupy. Remove the bay leaves and serve with white rice and fried plantains."}},{"id":91,"origin":{"hi":"स्कॉटलैंड","en":"Scotland","ro":"Scoția"},"name":{"hi":"कुलेन स्किंक","en":"Cullen Skink","ro":"Cullen Skink"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"hi":["600 ग्राम स्मोक्ड हैडॉक फिलेट (बिना रंग के, यदि संभव हो)","700 मिली फुल-फैट दूध","500 ग्राम आटे वाले आलू, छीलकर 2 सेमी के टुकड़ों में कटे","1 बड़ा प्याज (~200 ग्राम), बारीक कटा हुआ","2 बड़े चम्मच बिना नमक का मक्खन","2 तेज पत्ते","100 मिली डबल क्रीम","10 ग्राम ताजी अजमोद, बारीक कटी हुई","1/2 छोटा चम्मच सफेद मिर्च","1/2 छोटा चम्मच नमक"],"en":["600 g undyed smoked haddock fillets","700 ml whole milk","500 g floury potatoes (such as Maris Piper), peeled and cut into 2 cm cubes","1 large onion (~200 g), finely diced","2 tbsp unsalted butter","2 bay leaves","100 ml double cream","10 g fresh parsley, finely chopped","1/2 tsp white pepper","1/2 tsp salt"],"ro":["600 g fileuri de eglefin afumat (de preferință necolorat)","700 ml lapte integral","500 g cartofi făinoși, curățați și tăiați cuburi de 2 cm","1 ceapă mare (~200 g), tăiată mărunt","2 linguri unt fără sare","2 foi de dafin","100 ml frișcă grasă","10 g pătrunjel proaspăt, tocat mărunt","1/2 linguriță piper alb","1/2 linguriță sare"]},"howIsMade":{"hi":"स्मोक्ड हैडॉक को त्वचा की तरफ नीचे करके एक चौड़े बर्तन में रखें, दूध डालें, तेज पत्ते डालें और मध्यम आंच पर हल्के उबाल तक गर्म करें। 8–10 मिनट तक पकाएं जब तक मछली अपारदर्शी न हो जाए और सबसे मोटे भाग पर फ्लेक्स न बनने लगें। मछली को छलनी चम्मच से निकालें, त्वचा और कांटे हटाएं, बड़े टुकड़ों में तोड़ें और पोचिंग का दूध छान लें। उसी बर्तन में मक्खन मध्यम आंच पर पिघलाएं, प्याज डालें और 8–10 मिनट बार-बार हिलाते हुए पकाएं जब तक पूरी तरह नरम हो जाए पर रंग न बदले। आलू के टुकड़े और छाना हुआ दूध डालें, हल्का उबाल आने दें, ढक्कन थोड़ा खुला रखें और 15–18 मिनट पकाएं जब तक आलू पूरी तरह नरम न हों। एक तिहाई आलू को चम्मच की पीठ से बर्तन की दीवार पर दबाकर सूप गाढ़ा करें, बाकी टुकड़ों में रहने दें। क्रीम मिलाएं, हैडॉक के टुकड़े वापस डालें और 2–3 मिनट धीमी आंच पर गर्म करें। सावधानी से सफेद मिर्च और नमक से स्वाद लें क्योंकि मछली पहले से नमकीन होती है। गर्म कटोरे में परोसें, अजमोद छिड़कें और कुरकुरी ब्रेड के साथ दें।","en":"Place the smoked haddock skin-side down in a wide pan, pour over the milk, add the bay leaves, and bring to a gentle simmer over medium heat; poach for 8–10 minutes until the fish is just opaque and flakes at the thickest part. Lift the fish out with a slotted spoon, remove the skin and any bones, break the flesh into large flakes, and strain the poaching milk through a sieve into a jug. Melt the butter in the same pan over medium heat, add the diced onion, and cook for 8–10 minutes, stirring occasionally, until completely soft but not coloured. Add the potato cubes and the strained milk, bring to a simmer, cover loosely, and cook for 15–18 minutes until the potatoes are completely tender when pierced with a knife. Lightly mash about one-third of the potatoes against the side of the pan with the back of a spoon to thicken the soup, leaving the rest in chunks. Stir in the double cream, return the flaked haddock to the pan, and simmer gently for 2–3 minutes until just heated through; season with white pepper and salt, tasting carefully as the haddock is already salty. Ladle into warmed bowls, scatter with chopped parsley, and serve with crusty bread."}},{"id":92,"origin":{"hi":"इंडोनेशिया","en":"Indonesia","ro":"Indonezia"},"name":{"hi":"गाडो-गाडो","en":"Gado-Gado","ro":"Gado-Gado"},"category":{"hi":"सलाद","en":"Salad","ro":"Salată"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"hi":["400 ग्राम सख्त टोफू, दबाकर और 2 सेमी के टुकड़ों में काटा हुआ","150 ग्राम टेम्पे, 2 सेमी के टुकड़ों में काटा हुआ","4 बड़े अंडे","300 ग्राम मोमी आलू, छीलकर चार भागों में काटे हुए","200 ग्राम हरी बीन्स, सिरे कटे हुए","200 ग्राम सफेद गोभी, बारीक कटी हुई","150 ग्राम बीन स्प्राउट्स","1 खीरा (~200 ग्राम), अर्धचंद्राकार टुकड़ों में कटा","3 बड़े चम्मच वनस्पति तेल","200 ग्राम मुलायम मूंगफली का मक्खन","200 मिली नारियल का दूध","2 बड़े चम्मच कीकैप मानिस (मीठा सोया सॉस)","2 बड़े चम्मच इमली का पेस्ट, 4 बड़े चम्मच गर्म पानी में घुला हुआ","1 चम्मच ताड़ की चीनी या नरम भूरी चीनी","2 लहसुन की कलियाँ, बारीक कद्दूकस की हुई","1/2 चम्मच लाल मिर्च के टुकड़े","1/2 चम्मच नमक","झींगा क्रैकर्स (क्रुपुक) और नींबू के टुकड़े परोसने के लिए"],"en":["400 g firm tofu, pressed and cut into 2 cm cubes","150 g tempeh, cut into 2 cm cubes","4 large eggs","300 g waxy potatoes, peeled and quartered","200 g green beans, trimmed","200 g white cabbage, thinly shredded","150 g bean sprouts","1 cucumber (~200 g), sliced into half-moons","3 tbsp vegetable oil","200 g smooth peanut butter","200 ml coconut milk","2 tbsp kecap manis (sweet soy sauce)","2 tbsp tamarind paste dissolved in 4 tbsp warm water","1 tsp palm sugar or soft brown sugar","2 garlic cloves, finely grated","1/2 tsp chilli flakes","1/2 tsp salt","prawn crackers (krupuk) and lime wedges to serve"],"ro":["400 g tofu ferm, presat și tăiat în cuburi de 2 cm","150 g tempeh, tăiat în cuburi de 2 cm","4 ouă mari","300 g cartofi cu coajă crocantă, curățați și tăiați în sferturi","200 g fasole verde, curățată de capete","200 g varză albă, feliată subțire","150 g germeni de soia","1 castravete (~200 g), tăiat în felii semilună","3 linguri ulei vegetal","200 g unt de arahide cremos","200 ml lapte de cocos","2 linguri kecap manis (sos de soia dulce)","2 linguri pastă de tamarind dizolvată în 4 linguri apă caldă","1 linguriță zahăr de palmier sau zahăr brun","2 căței de usturoi, rași fin","1/2 linguriță fulgi de ardei iute","1/2 linguriță sare","chipsuri de creveți (krupuk) și felii de lămâie verde pentru servit"]},"howIsMade":{"hi":"अंडों को हल्के उबलते पानी में 9 मिनट तक कठोर उबालें, बर्फ के पानी में डालें, ठंडे होने पर छीलें और आधा काटें। आलू को अच्छी तरह नमकीन उबलते पानी में 12–15 मिनट तक तब तक पकाएं जब तक कि छेदने पर नरम हो जाएं; छेद वाली चम्मच से निकालें और छान लें, फिर उसी पानी में हरी बीन्स को 3 मिनट के लिए चमकीला हरा और थोड़ी कुरकुरी रहने तक ब्लांच करें। कटी हुई पत्तागोभी को छन्नी में रखकर उबलता पानी डालें, 30 सेकंड गिनें, फिर अतिरिक्त पानी निचोड़ें। नॉन-स्टिक फ्राइंग पैन में मध्यम-तेज आंच पर तेल गरम करें और टोफू के टुकड़ों को हर तरफ से 3–4 मिनट तक सुनहरा और कुरकुरा होने तक तलें; निकालें, फिर उसी पैन में टेम्पे को हर तरफ से 2–3 मिनट तक गहरा सुनहरा होने तक तलें। मूंगफली के मक्खन, नारियल के दूध, कीकैप मानिस, इमली के पानी, ताड़ की चीनी, कसे हुए लहसुन और मिर्च के टुकड़ों को एक छोटे सॉसपैन में मिलाएं; धीमी आंच पर लगातार हिलाते हुए 5–7 मिनट तक पकाएं जब तक यह चिकना और चम्मच की पीठ पर चिपकने के लिए पर्याप्त गाढ़ा न हो जाए। पत्तागोभी, आलू, हरी बीन्स, अंकुरित दालें और खीरे के टुकड़ों को एक बड़ी थाली में सजाएं; ऊपर टोफू, टेम्पे और आधे अंडे रखें। गर्म मूंगफली की चटनी सब पर डालें और झींगा क्रैकर्स और नींबू के टुकड़ों के साथ परोसें।","en":"Hard-boil the eggs in simmering water for 9 minutes, transfer to a bowl of ice water, then peel and halve when cool. Cook the potatoes in well-salted boiling water for 12–15 minutes until just tender when pierced; lift out with a slotted spoon and drain, then blanch the green beans in the same water for 3 minutes until bright green and still with some bite, and drain. Blanch the shredded cabbage by pouring boiling water over it in a colander, count 30 seconds, then press out excess water. Heat the oil in a non-stick frying pan over medium-high heat and fry the tofu cubes for 3–4 minutes per side until golden and crisp; remove, then fry the tempeh in the same pan for 2–3 minutes per side until deep golden. Combine the peanut butter, coconut milk, kecap manis, tamarind water, palm sugar, grated garlic, and chilli flakes in a small saucepan; cook over low heat, stirring constantly, for 5–7 minutes until smooth and thick enough to coat the back of a spoon — thin with a splash of water if needed. Arrange the cabbage, potatoes, green beans, bean sprouts, and cucumber slices on a large platter or individual plates; place the tofu, tempeh, and egg halves on top. Pour the warm peanut sauce over everything, and serve with prawn crackers and lime wedges on the side."}},{"id":93,"origin":{"hi":"स्वीडन","en":"Sweden","ro":"Suedia"},"name":{"hi":"कैनेलबुले","en":"Cinnamon Bun","ro":"Kanelbulle"},"category":{"hi":"मिठाई","en":"Dessert","ro":"Desert"},"servings":12,"tipType":"dessert","pairingsType":"dessert","ingredients":{"hi":["500 ग्राम मैदा, अतिरिक्त बेलने के लिए","250 मिली पूर्ण वसा वाला दूध","7 ग्राम तत्काल सूखा खमीर (1 पैकेट)","10 ग्राम चीनी (आटे के लिए)","1 बड़ा अंडा","100 ग्राम बिना नमक का मक्खन, नरम किया हुआ","1 चम्मच इलायची पाउडर","1/2 चम्मच नमक","75 ग्राम बिना नमक का मक्खन, नरम किया हुआ (भरावन के लिए)","75 ग्राम चीनी (भरावन के लिए)","1 बड़ा चम्मच दालचीनी पाउडर","1 चम्मच इलायची पाउडर (भरावन के लिए)","1 अंडा, फेंटा हुआ (ब्रश करने के लिए)","2 बड़े चम्मच मोती चीनी"],"en":["500 g plain flour, plus extra for dusting","250 ml whole milk","7 g fast-action dried yeast (1 sachet)","10 g caster sugar (for dough)","1 large egg","100 g unsalted butter, softened","1 tsp ground cardamom","1/2 tsp salt","75 g unsalted butter, softened (filling)","75 g caster sugar (filling)","1 tbsp ground cinnamon","1 tsp ground cardamom (filling)","1 egg, beaten (for egg wash)","2 tbsp pearl sugar"],"ro":["500 g făină albă, plus extra pentru presărat","250 ml lapte integral","7 g drojdie uscată instant (1 plic)","10 g zahăr tos (pentru aluat)","1 ou mare","100 g unt nesărat, la temperatura camerei","1 linguriță cardamom măcinat","1/2 linguriță sare","75 g unt nesărat, la temperatura camerei (umplutură)","75 g zahăr tos (umplutură)","1 lingură scorțișoară măcinată","1 linguriță cardamom măcinat (umplutură)","1 ou bătut (pentru uns)","2 linguri zahăr perle"]},"howIsMade":{"hi":"दूध को 37°C तक गरम करें, खमीर और 10 ग्राम चीनी मिलाएं और 5–10 मिनट तक झाग आने तक छोड़ें। एक बड़े कटोरे में आटा, इलायची और नमक मिलाएं; बीच में गड्ढा बनाकर खमीर का मिश्रण और अंडा डालें और एक खुरदरा आटा बनाएं। 100 ग्राम मुलायम मक्खन थोड़ा-थोड़ा करके डालें और हल्का आटे छिड़की हुई सतह पर 8–10 मिनट तक गूंधें जब तक आटा चिकना, लोचदार और हाथ से न चिपके; ढककर गर्म जगह पर 60–90 मिनट तक दोगुना होने तक रखें। 75 ग्राम मक्खन, 75 ग्राम चीनी, दालचीनी और दूसरी चम्मच इलायची मिलाकर भरावन तैयार करें। खमीर उठे आटे को थोड़े आटे से छिड़की हुई सतह पर 40×50 सेमी के आयत में बेलें; भरावन समान रूप से फैलाएं, आटे को लंबाई में तिहाई मोड़ें, फिर बेलें और 12 पट्टियों में काटें। हर पट्टी को मोड़कर एक गांठ में लपेटें और किनारे को नीचे दबाएं; बेकिंग पेपर लगी ट्रे पर दूरी रखकर रखें, ढककर 30–45 मिनट तक स्पष्ट रूप से फूलने तक छोड़ें और ओवन को 200°C (फैन 180°C) पर प्रीहीट करें। पीटे हुए अंडे से ब्रश करें, मोती चीनी छिड़कें और 12–15 मिनट तक गहरे सुनहरे रंग तक बेक करें; वायर रैक पर रखें और किचन टॉवल से ढक दें।","en":"Warm the milk to 37°C, stir in the yeast and the 10 g of caster sugar, and leave for 5–10 minutes until frothy. Combine the flour, cardamom, and salt in a large bowl; make a well, pour in the yeast mixture and beaten egg, then bring together into a rough dough. Add the 100 g of softened butter a piece at a time and knead on a lightly floured surface for 8–10 minutes until the dough is smooth, elastic, and no longer sticks to your hands; cover and leave in a warm place for 60–90 minutes until doubled in size. Beat together the 75 g of butter, 75 g of caster sugar, cinnamon, and the second teaspoon of cardamom until smooth for the filling. Turn the risen dough onto a lightly floured surface and roll into a 40×50 cm rectangle; spread the filling evenly, fold the dough lengthways into thirds, roll again, and cut into 12 strips. Twist each strip and coil into a knot, tucking the end underneath, then space on lined baking trays; cover loosely and prove 30–45 minutes until noticeably puffed, while preheating the oven to 200°C (fan 180°C). Brush with beaten egg, scatter with pearl sugar, and bake for 12–15 minutes until deep golden brown; transfer to a wire rack and cover with a tea towel to keep them soft."}},{"id":94,"origin":{"hi":"मेक्सिको","en":"Mexico","ro":"Mexic"},"name":{"hi":"चिलेस एन नोगाडा","en":"Chiles en nogada","ro":"Chiles en nogada"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"mexican","ingredients":{"hi":["4 बड़े पोब्लानो मिर्च (~700 ग्राम कुल)","400 ग्राम पिसा हुआ सूअर का मांस","2 बड़े चम्मच जैतून का तेल या चरबी","1 मध्यम प्याज (~150 ग्राम), बारीक कटा हुआ","3 लहसुन की कलियाँ, बारीक काटी हुई","2 पके टमाटर (~300 ग्राम), छिलका हटाकर कटे हुए","50 ग्राम किशमिश","50 ग्राम छिले हुए बादाम, मोटे कटे हुए","1 पका आड़ू या नाशपाती (~150 ग्राम), छीलकर छोटे टुकड़ों में","1 चम्मच दालचीनी पाउडर, 1/2 चम्मच लौंग पाउडर, 1 चम्मच नमक, 1/2 चम्मच काली मिर्च","150 ग्राम अखरोट, 30 मिनट गर्म दूध में भिगोकर निथारे हुए","150 ग्राम क्रीम चीज़, नरम किया हुआ","100 मिली खट्टी क्रीम","1 अनार के दाने (~100 ग्राम)","ताज़े चपटे पत्ते वाले अजमोद की एक मुट्ठी"],"en":["4 large poblano chiles (~700 g total)","400 g ground pork","2 tbsp olive oil or lard","1 medium onion (~150 g), finely diced","3 garlic cloves, minced","2 ripe tomatoes (~300 g), peeled and diced","50 g raisins","50 g blanched almonds, roughly chopped","1 ripe peach or pear (~150 g), peeled and diced","1 tsp ground cinnamon, 1/2 tsp ground cloves, 1 tsp salt, 1/2 tsp black pepper","150 g walnut halves, soaked in warm milk 30 minutes then drained","150 g cream cheese, softened","100 ml soured cream","seeds of 1 pomegranate (~100 g)","small handful of fresh flat-leaf parsley leaves"],"ro":["4 ardei poblano mari (~700 g total)","400 g carne de porc tocată","2 linguri ulei de măsline sau untură","1 ceapă medie (~150 g), tăiată mărunt","3 căței de usturoi, tocați","2 roșii coapte (~300 g), curățate de coajă și tocate","50 g stafide","50 g migdale decojite, tocate grosier","1 piersică sau pară coaptă (~150 g), curățată și tăiată cubulețe","1 linguriță scorțișoară, 1/2 linguriță cuișoare, 1 linguriță sare, 1/2 linguriță piper negru","150 g miez de nucă, înmuiat 30 minute în lapte cald și scurs","150 g cremă de brânză, la temperatura camerei","100 ml smântână fermentată","semințele unui rodiu (~100 g)","o mână de frunze de pătrunjel plat proaspăt"]},"howIsMade":{"hi":"पोब्लानो मिर्चों को सीधे गैस की लौ पर या गर्म ग्रिल के नीचे 8–10 मिनट तक चिमटे से पलटते हुए चारों तरफ से पूरी तरह काला होने तक भूनें; ढके हुए कटोरे में 10 मिनट रखें, फिर छिलका रगड़कर उतारें, एक लंबी चीरा लगाएं और छोटे चम्मच से बीज और नसें निकाल दें, मिर्च को पूरा रखें। एक चौड़े फ्राइंग पैन में मध्यम आंच पर तेल गरम करें, प्याज डालें और 5–6 मिनट तक पूरी तरह नरम होने तक भूनें; लहसुन डालें और 1 मिनट और भूनें। पिसा हुआ मांस डालें और 8 मिनट तक तोड़ते हुए गुलाबी रंग समाप्त होने तक भूनें; टमाटर डालें और 5 मिनट तक पानी सूखने तक पकाएं। किशमिश, बादाम, आड़ू, दालचीनी, लौंग, नमक और काली मिर्च मिलाएं; 5 मिनट तक फल नरम होने और मिश्रण सूखने तक पकाएं, फिर आंच से हटाएं और ठंडा होने दें। भिगोए हुए अखरोट को छानें और क्रीम चीज़ और खट्टी क्रीम के साथ पूरी तरह मुलायम होने तक ब्लेंड करें; नमक से स्वाद लें। प्रत्येक मिर्च को ठंडे मांस के भरावन से अच्छी तरह भरें और चीरे को धीरे से बंद करें; अलग-अलग प्लेटों पर रखें। प्रत्येक मिर्च पर अखरोट का सॉस भरपूर डालें, ऊपर अनार के दाने और अजमोद की पत्तियां बिखेरें और कमरे के तापमान पर परोसें।","en":"Char the poblano chiles over an open gas flame or under a hot grill for 8–10 minutes, turning with tongs until the skin is completely blackened on all sides; place in a covered bowl for 10 minutes, then rub off the skin, make a single lengthways slit, and remove the seeds and veins with a small spoon while keeping each chile intact. Heat the oil in a wide frying pan over medium heat, add the onion, and cook for 5–6 minutes until completely soft; add the garlic and cook 1 minute more until fragrant. Add the ground pork and cook, breaking it up with a wooden spoon, for 8 minutes until no pink remains; add the diced tomatoes and cook for 5 minutes until they collapse and the liquid reduces. Stir in the raisins, almonds, peach, cinnamon, cloves, salt, and pepper; cook for 5 minutes until the fruit softens and the mixture is fairly dry, then remove from heat and cool to room temperature. Drain the soaked walnuts and blend with the cream cheese and soured cream until completely smooth; season with a pinch of salt — the nogada should be thick enough to coat a spoon. Stuff each poblano firmly with the cooled meat filling, pressing gently to close the slit; arrange on individual plates or a large serving dish. Spoon the walnut sauce generously over each chile, scatter pomegranate seeds and parsley leaves on top, and serve at room temperature."}},{"id":95,"origin":{"hi":"लेबनान","en":"Lebanon","ro":"Liban"},"name":{"hi":"मसूर का सूप","en":"Lentil Soup","ro":"Supă de linte"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"soup","ingredients":{"hi":["300 ग्राम लाल मसूर, पानी साफ होने तक धोया हुआ","2 बड़े चम्मच जैतून का तेल","1 बड़ा प्याज (~200 ग्राम), बारीक कटा हुआ","2 मध्यम गाजर (~200 ग्राम), छीली और कटी हुई","3 लहसुन की कलियाँ, बारीक कटी हुई","2 चम्मच जीरा पाउडर","1 चम्मच धनिया पाउडर","1/2 चम्मच हल्दी","1/4 चम्मच लाल मिर्च","1.2 लीटर सब्जी या चिकन का शोरबा","1 नींबू का रस","2 बड़े चम्मच बिना नमक का मक्खन (टॉपिंग के लिए)","1 चम्मच मीठी पैपरिका (टॉपिंग के लिए)","नमक और काली मिर्च स्वादानुसार","ताज़ा धनिया या अजमोद और नींबू के टुकड़े परोसने के लिए"],"en":["300 g red lentils, rinsed until water runs clear","2 tbsp olive oil","1 large onion (~200 g), finely diced","2 medium carrots (~200 g), peeled and diced","3 garlic cloves, minced","2 tsp ground cumin","1 tsp ground coriander","1/2 tsp ground turmeric","1/4 tsp cayenne pepper","1.2 litres vegetable or chicken stock","juice of 1 lemon","2 tbsp unsalted butter (for topping)","1 tsp sweet paprika (for topping)","salt and black pepper to taste","fresh coriander or parsley and lemon wedges to serve"],"ro":["300 g linte roșie, clătită până apa devine limpede","2 linguri ulei de măsline","1 ceapă mare (~200 g), tăiată mărunt","2 morcovi medii (~200 g), curățați și tăiați cubulețe","3 căței de usturoi, tocați","2 lingurițe chimen măcinat","1 linguriță coriandru măcinat","1/2 linguriță turmeric","1/4 linguriță ardei cayenne","1,2 litri supă de legume sau pui","sucul de la 1 lămâie","2 linguri unt nesărat (pentru topping)","1 linguriță paprika dulce (pentru topping)","sare și piper negru după gust","coriandru proaspăt sau pătrunjel, felii de lămâie pentru servit"]},"howIsMade":{"hi":"एक बड़े बर्तन में मध्यम आंच पर जैतून का तेल गरम करें, प्याज और गाजर डालें और 8–10 मिनट तक कभी-कभी हिलाते हुए नरम और प्याज पारदर्शी होने तक पकाएं। लहसुन, जीरा, धनिया, हल्दी और लाल मिर्च डालें; 1–2 मिनट तक मसालों की महक आने तक हिलाएं। धोई हुई मसूर और शोरबा डालें, उबाल आने दें, फिर आंच कम करें, आंशिक रूप से ढकें और 20–25 मिनट तक मसूर पूरी तरह नरम होने और घुलने लगने तक पकाएं। हैंड ब्लेंडर से लगभग आधा सूप मलाईदार लेकिन गांठदार बनावट के लिए पीसें — या पूरा पूरी तरह मुलायम करने के लिए; जरूरत हो तो थोड़ा शोरबा डालकर पतला करें। नींबू का रस मिलाएं और नमक और काली मिर्च से भरपूर स्वाद बनाएं। एक छोटी पैन में मध्यम आंच पर मक्खन पिघलाएं, पैपरिका डालें और 30 सेकंड तक महक आने तक पकाएं। गर्म सूप को गर्म कटोरों में डालें, प्रत्येक हिस्से पर पैपरिका मक्खन छिड़कें, ताज़ा धनिया डालें और नींबू के टुकड़ों और कुरकुरी रोटी के साथ परोसें।","en":"Heat the olive oil in a large saucepan over medium heat, add the onion and carrots, and cook for 8–10 minutes, stirring occasionally, until softened and the onion is translucent. Add the garlic, cumin, coriander, turmeric, and cayenne; stir for 1–2 minutes until the spices are fragrant and toasted. Add the rinsed lentils and stock, bring to a boil, then reduce the heat, partially cover, and simmer for 20–25 minutes until the lentils are completely tender and beginning to dissolve into the liquid. Use an immersion blender to puree about half the soup directly in the pot for a creamy yet textured finish — or blend it all smooth if you prefer; thin with a splash of extra stock or water if needed. Stir in the lemon juice and season generously with salt and black pepper. Melt the butter in a small pan over medium heat, add the sweet paprika, and let it sizzle for 30 seconds until fragrant and deep red. Ladle the hot soup into warmed bowls, drizzle the paprika butter over each portion, scatter fresh coriander on top, and serve with lemon wedges and crusty bread."}},{"id":96,"origin":{"hi":"ग्रीस","en":"Greece","ro":"Grecia"},"name":{"hi":"स्पानाकोपिटा","en":"Spanakopita","ro":"Spanakopita"},"category":{"hi":"स्नैक","en":"Snack","ro":"Gustare"},"servings":6,"tipType":"veg","pairingsType":"veg","ingredients":{"hi":["500 ग्राम फ़िलो पेस्ट्री, जमी हुई हो तो पिघलाई गई","1 किलो ताज़ा पालक, धोया हुआ (या 600 ग्राम जमा हुआ, पिघलाकर निचोड़ा हुआ)","300 ग्राम फेटा चीज़, टुकड़ों में","2 मध्यम प्याज़, बारीक कटे","4 हरी प्याज़, बारीक कटी","3 बड़े अंडे, फेंटे हुए","30 ग्राम ताज़ा डिल, कटा हुआ","20 ग्राम ताज़ा अजमोद, कटा हुआ","150 मिली एक्स्ट्रा वर्जिन जैतून का तेल","100 ग्राम कद्दूकस की हुई केफालोतीरी या पेकोरीनो (वैकल्पिक)","1/2 चम्मच ताज़ा कद्दूकस की हुई जायफल","स्वादानुसार नमक और ताज़ा पिसी काली मिर्च"],"en":["500g phyllo pastry, thawed if frozen","1kg fresh spinach, washed (or 600g frozen spinach, thawed and squeezed dry)","300g feta cheese, crumbled","2 medium onions, finely chopped","4 spring onions, finely sliced","3 large eggs, beaten","30g fresh dill, chopped","20g fresh parsley, chopped","150ml extra virgin olive oil","100g grated kefalotyri or pecorino (optional)","1/2 tsp freshly grated nutmeg","salt and freshly ground black pepper to taste"],"ro":["500g foi de plăcintă (phyllo), decongelate dacă sunt din congelator","1kg spanac proaspăt, spălat (sau 600g spanac congelat, decongelat și stors bine)","300g brânză feta, sfărâmată","2 cepe medii, tocate fin","4 cepe verzi, tăiate fin","3 ouă mari, bătute","30g mărar proaspăt, tocat","20g pătrunjel proaspăt, tocat","150ml ulei de măsline extravirgin","100g kefalotyri sau pecorino, ras (opțional)","1/2 linguriță nucșoară proaspăt rasă","sare și piper negru proaspăt măcinat după gust"]},"howIsMade":{"hi":"ओवन को 180°C (फैन 160°C) पर पहले से गरम करें। 1 किलो पालक धोकर बड़े बर्तन में मध्यम आंच पर 4–5 मिनट तक भूनें, जब तक वह सिमट न जाए। छलनी में निकालकर चम्मच के पिछले हिस्से से दबाकर अधिक से अधिक पानी निकालें, फिर मुट्ठीभर पालक को किचन पेपर के बीच रखकर अच्छे से निचोड़ें।. एक पैन में 3 बड़े चम्मच जैतून का तेल गरम करें और कटी हुई प्याज़ को मध्यम आंच पर 8 मिनट तक नरम और पारदर्शी होने तक भूनें। हरी प्याज़ डालकर 2 मिनट और पकाएं।. एक बड़े कटोरे में निचोड़ा हुआ पालक, प्याज़ का मिश्रण, 300 ग्राम टूटा फेटा, इस्तेमाल कर रहे हों तो केफालोतीरी, 3 फेंटे हुए अंडे, डिल, अजमोद, जायफल, नमक और काली मिर्च मिलाएं। हल्के हाथ से मिलाएं — ज़्यादा मिलाने पर पालक फिर से पानी छोड़ता है।. 25×35 सेमी की बेकिंग डिश पर जैतून का तेल लगाएं। एक फ़िलो शीट बिछाएं, तेल लगाएं, ऊपर एक और शीट रखें। ऐसे ही करते जाएं जब तक नीचे 8 परतें न बन जाएं। बची हुई फ़िलो शीट को थोड़े नम कपड़े से ढककर रखें।. भरावन को फ़िलो बेस पर एक समान फैलाएं। ऊपर से 8 और फ़िलो शीट डालें, हर परत पर जैतून का तेल अच्छी मात्रा में लगाएं।. किनारों को अंदर की ओर मोड़ें। तेज़ चाकू से ऊपरी सतह को 6–8 हिस्सों में मार्क करें, सिर्फ ऊपरी परतों को काटें — इससे परोसते समय पाई टूटती नहीं। पेस्ट्री मुड़ने से बचाने के लिए ऊपर पानी की कुछ बूंदें छिड़कें।. 40–45 मिनट तक, जब तक ऊपरी सतह गहरी सुनहरी न हो जाए और हल्के से थपथपाने पर कुरकुरी आवाज न आए, बेक करें। 15 मिनट रेस्ट करने दें, फिर मार्क की हुई लाइनों पर काटें।.","en":"Preheat the oven to 180°C (fan 160°C); wash 1kg of spinach and wilt it in a large pot over medium heat for 4–5 minutes, until just collapsed; tip into a colander and press out as much water as possible, then squeeze handfuls dry between paper towels. Warm 3 tablespoons of olive oil in a pan and cook the chopped onions over medium heat for 8 minutes, until soft and translucent; add the spring onions and cook 2 more minutes. In a large bowl, combine the squeezed spinach, the onion mixture, 300g crumbled feta, the kefalotyri if using, 3 beaten eggs, dill, parsley, nutmeg, salt and pepper; mix gently — do not overwork or the spinach will release more water. Brush a 25×35 cm baking dish with olive oil; lay one sheet of phyllo, brush with olive oil, and top with another sheet; continue until you have 8 layers as the base; keep unused phyllo covered with a slightly damp cloth. Spread the filling evenly over the phyllo base; top with 8 more sheets of phyllo, brushing each layer generously with olive oil. Tuck the edges in; with a sharp knife, score the top into 6–8 portions, cutting only through the top layers — this prevents shattering when serving; sprinkle a few drops of water on top to stop the pastry curling. Bake for 40–45 minutes, until the top is deep golden brown and the pastry sounds crisp when tapped; rest 15 minutes before cutting along the scored lines."},"timeMins":{"total":90,"active":40}},{"id":97,"origin":{"hi":"नाइजीरिया","en":"Nigeria","ro":"Nigeria"},"name":{"hi":"जॉलोफ राइस","en":"Jollof Rice","ro":"Jollof Rice"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"def","ingredients":{"hi":["400 ग्राम लंबे दाने वाले पारबॉइल्ड चावल (या बासमती), पानी साफ निकलने तक धोए हुए","6 पके रोमा टमाटर, मोटे टुकड़ों में कटे (या 400 ग्राम कैन में कटे टमाटर)","2 बड़ी लाल शिमला मिर्च, बीज निकालकर मोटे टुकड़ों में","1 स्कॉच बोनट या लाल मिर्च, बीज निकाली हुई","2 बड़ी प्याज़ (1 मिक्सी के लिए, 1 कटी हुई)","4 लहसुन की कलियां, छिली हुई","30 ग्राम ताज़ा अदरक, छिला हुआ","3 बड़े चम्मच टमाटर पेस्ट","120 मिली वनस्पति तेल (पारंपरिक रूप से मूंगफली का तेल)","750 मिली गर्म चिकन या सब्ज़ी का शोरबा","2 तेज पत्ते","1 छोटा चम्मच करी पाउडर","1 छोटा चम्मच सूखा थाइम","1 छोटा चम्मच धुंआ-छन्न पैपरिका","स्वादानुसार नमक और ताज़ा पिसी काली मिर्च"],"en":["400g long-grain parboiled rice (or basmati), rinsed until water runs clear","6 ripe Roma tomatoes, roughly chopped (or 400g canned chopped tomatoes)","2 large red bell peppers, deseeded and roughly chopped","1 scotch bonnet or red chilli, deseeded","2 large onions (1 blended, 1 sliced)","4 garlic cloves, peeled","30g fresh ginger, peeled","3 tbsp tomato paste","120ml vegetable oil (groundnut oil is traditional)","750ml hot chicken or vegetable stock","2 bay leaves","1 tsp curry powder","1 tsp dried thyme","1 tsp smoked paprika","salt and freshly ground black pepper to taste"],"ro":["400g orez cu bob lung parboiled (sau basmati), spălat până apa rămâne limpede","6 roșii Roma coapte, tăiate grosier (sau 400g roșii din conservă)","2 ardei kapia roșii mari, fără semințe și tăiați grosier","1 ardei scotch bonnet sau ardei iute roșu, fără semințe","2 cepe mari (una mixată, una feliată)","4 căței de usturoi, curățați","30g ghimbir proaspăt, curățat","3 linguri pastă de roșii","120ml ulei vegetal (tradițional, ulei de arahide)","750ml supă fierbinte de pui sau legume","2 foi de dafin","1 linguriță pudră de curry","1 linguriță cimbru uscat","1 linguriță boia afumată","sare și piper negru proaspăt măcinat după gust"]},"howIsMade":{"hi":"400 ग्राम चावल को ठंडे पानी में तब तक धोएं जब तक पानी साफ न निकलने लगे, फिर छान लें — यह कदम अतिरिक्त स्टार्च हटाता है और दानों को अलग रखता है।. ब्लेंडर में टमाटर, लाल शिमला मिर्च, मिर्च, एक प्याज़, लहसुन और अदरक डालकर चिकनी पेस्ट बनाएं।. भारी तले वाले बर्तन में 120 मिली तेल मध्यम आंच पर गरम करें। कटी हुई प्याज़ डालें और 5–6 मिनट तक हल्का सुनहरा होने तक भूनें।. 3 बड़े चम्मच टमाटर पेस्ट डालें और 3 मिनट तक पकाएं जब तक रंग गहरा न हो जाए और कच्ची महक न जाए।. ब्लेंड किया हुआ मिर्च-टमाटर मिश्रण डालें, तेज पत्ते, करी पाउडर, थाइम और धुंआ-छन्न पैपरिका डालें। मध्यम आंच पर बिना ढके 18–20 मिनट तक बार-बार चलाते हुए पकाएं जब तक चटनी गाढ़ी होकर गहरी लाल न हो जाए और तेल ऊपर न आ जाए — यह सबसे महत्वपूर्ण कदम है।. धुले हुए चावल डालें और हर दाने पर चटनी लगने तक चलाएं। 750 मिली गर्म शोरबा डालें, नमक-मिर्च से स्वाद ठीक करें और उबाल लाएं।. आंच एकदम धीमी कर दें, बर्तन को कसकर ढकें (असली स्वाद के लिए ढक्कन से पहले किनारे पर एल्युमिनियम फॉयल लपेटें) और बिना हिलाए 25–30 मिनट तक पकाएं जब तक चावल नरम न हो जाए और सारा पानी सूख न जाए।. आंच बंद करके 10 मिनट और ढका रहने दें। कांटे से धीरे से चलाएं — नीचे की परत में हल्की धुंआदार पपड़ी होनी चाहिए। तले हुए केले, ग्रिल्ड चिकन या साधारण सलाद के साथ परोसें।.","en":"Rinse 400g of rice in cold water until the water runs clear, then drain — this removes excess starch and keeps the grains separate. Blend the tomatoes, red bell peppers, chilli, one onion, garlic and ginger to a smooth paste in a blender. Heat 120ml oil in a heavy-bottomed pot over medium heat; add the sliced onion and fry for 5–6 minutes, until lightly golden. Stir in 3 tablespoons of tomato paste and cook for 3 minutes, until darkened and the raw aroma is gone. Pour in the blended pepper mixture, add the bay leaves, curry powder, thyme and smoked paprika; cook uncovered over medium heat for 18–20 minutes, stirring often, until the sauce reduces, deepens to a dark red and the oil rises to the surface — this is the critical step. Add the rinsed rice and stir until every grain is coated in sauce; pour in 750ml hot stock, season with salt and pepper, and bring back to a boil. Reduce the heat to the lowest setting, cover the pot tightly (seal the rim with foil before placing the lid for an authentic finish), and cook undisturbed for 25–30 minutes, until the rice is tender and the liquid is absorbed. Turn off the heat and leave covered for 10 more minutes; fluff gently with a fork — the bottom layer should have a slight smoky crust; serve with fried plantain, grilled chicken, or a simple salad."}},{"id":98,"origin":{"hi":"सामोआ","en":"Samoa","ro":"Samoa"},"name":{"hi":"ओका इआ","en":"Oka i'a","ro":"Oka i'a"},"category":{"hi":"स्नैक","en":"Snack","ro":"Gustare"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"hi":["500 ग्राम सशिमी-ग्रेड टूना या माही-माही, बिना त्वचा और कांटों के, 1.5 सेमी के क्यूब में कटा हुआ","120 मिली ताज़ा नींबू का रस (लगभग 6 नींबू)","200 मिली पूर्ण वसा वाला नारियल का दूध (नया खुला हुआ या डिब्बाबंद)","1 मध्यम खीरा, छिलकर बीज निकालकर बारीक काटा हुआ","1 छोटा लाल प्याज़, बारीक कटा हुआ","2 पके टमाटर, बीज निकालकर कटे हुए","1 छोटी लाल मिर्च, बारीक कटी (वैकल्पिक)","1 हरी प्याज़, बारीक कटी","1 छोटा चम्मच महीन समुद्री नमक","ताज़ा पिसी काली मिर्च","सजावट के लिए ताज़े धनिये के पत्ते"],"en":["500g sashimi-grade tuna or mahi-mahi, skinned and boned, cut into 1.5 cm cubes","120ml fresh lime juice (about 6 limes)","200ml full-fat coconut milk (freshly opened or canned)","1 medium cucumber, peeled, deseeded, and finely diced","1 small red onion, finely diced","2 ripe tomatoes, deseeded and diced","1 small red chilli, finely chopped (optional)","1 spring onion, finely sliced","1 tsp fine sea salt","freshly ground black pepper","fresh coriander leaves, to garnish"],"ro":["500g ton sau mahi-mahi de calitate sashimi, fără piele și oase, tăiat cuburi de 1,5 cm","120ml suc proaspăt de lime (aproximativ 6 lime)","200ml lapte de cocos integral (proaspăt deschis sau din conservă)","1 castravete mediu, curățat, fără semințe, tăiat cuburi mici","1 ceapă roșie mică, tăiată cuburi mici","2 roșii coapte, fără semințe, tăiate cuburi","1 ardei iute roșu mic, tocat fin (opțional)","1 ceapă verde, tăiată fin","1 linguriță sare fină de mare","piper negru proaspăt măcinat","frunze de coriandru proaspăt, pentru ornat"]},"howIsMade":{"hi":"कटी हुई मछली को नॉन-रिएक्टिव (कांच या सिरेमिक) कटोरे में रखें। ऊपर से 120 मिली ताज़ा नींबू का रस डालें और हर टुकड़े पर लग जाए ऐसे हल्के से चलाएं। 15–20 मिनट के लिए फ्रिज में रखें — सतह अपारदर्शी हो जानी चाहिए जबकि बीच पारदर्शी रहे।. मछली के मैरिनेट होते समय, कटे हुए लाल प्याज़ को ठंडे पानी में 10 मिनट भिगोकर छान लें। यह कच्ची तीखी महक हल्की करता है पर कुरकुरापन बनाए रखता है।. महीन छलनी से मछली का अच्छी तरह पानी निकालें। ज़्यादातर नींबू का रस फेंक दें, लेकिन 2 बड़े चम्मच बचाकर रखें।. मछली को साफ कटोरे में वापस डालें। खीरा, छाना हुआ लाल प्याज़, टमाटर, मिर्च और हरी प्याज़ डालें। मछली टूटे नहीं इसलिए हल्के से मिलाएं।. 200 मिली नारियल का दूध और बचा रखा 2 बड़े चम्मच नींबू का रस डालें। नमक और कुछ बार पीसी काली मिर्च डालें। हल्के हाथ से मिलाएं — नारियल का दूध मछली पर कोट हो जाए लेकिन उसे तोड़े नहीं।. चखकर नमक या नींबू समायोजित करें। तुरंत, बहुत ठंडा, उथले कटोरों में परोसें। ऊपर से ताज़े धनिये के पत्ते छिड़कें।.","en":"Place the cubed fish in a non-reactive (glass or ceramic) bowl; pour over 120ml fresh lime juice and toss until every piece is coated; refrigerate for 15–20 minutes — the surface should turn opaque while the centre stays translucent. While the fish marinates, soak the diced red onion in cold water for 10 minutes, then drain; this softens its raw bite without losing the crunch. Drain the fish thoroughly through a fine sieve; discard most of the lime juice but reserve 2 tablespoons. Return the fish to a clean bowl; add the cucumber, drained red onion, tomatoes, chilli and spring onion; toss gently so the fish stays intact. Pour in 200ml coconut milk and the reserved 2 tbsp lime juice; add the salt and a few grinds of pepper; fold everything together gently — the coconut milk should coat without breaking the fish. Taste and adjust salt or lime; serve immediately, very cold, in shallow bowls; scatter fresh coriander leaves on top."}},{"id":99,"origin":{"hi":"आर्मेनिया","en":"Armenia","ro":"Armenia"},"name":{"hi":"ख़ोरोवाट्स","en":"Khorovats","ro":"Khorovats"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"hi":["800 ग्राम सूअर का कंधा या बीफ टेंडरलॉइन, 4 सेमी क्यूब में कटा हुआ","2 बड़े लाल प्याज़ (1 मैरिनेड के लिए स्लाइस, 1 सींख के लिए कीलियों में)","1 लाल शिमला मिर्च, 4 सेमी टुकड़ों में","1 हरी शिमला मिर्च, 4 सेमी टुकड़ों में","1 मध्यम बैंगन, 3 सेमी मोटाई में गोल कटा","4 पके टमाटर (साबुत ग्रिल करने के लिए)","3 बड़े चम्मच सूरजमुखी का तेल","1 छोटा चम्मच ताज़ा पिसी काली मिर्च","2 छोटे चम्मच मोटा नमक","ताज़ी तुलसी और अजमोद की एक छोटी मुट्ठी, परोसने के लिए","लवाश या कोई और सादा रोटी, परोसने के लिए"],"en":["800g pork shoulder or beef tenderloin, cut into 4 cm cubes","2 large red onions (1 sliced for the marinade, 1 cut into wedges for skewering)","1 red bell pepper, cut into 4 cm pieces","1 green bell pepper, cut into 4 cm pieces","1 medium aubergine, cut into 3 cm rounds","4 ripe tomatoes (to be grilled whole alongside)","3 tbsp sunflower oil","1 tsp freshly ground black pepper","2 tsp coarse salt","a small handful of fresh basil and parsley, to serve","lavash or another flatbread, to serve"],"ro":["800g pulpă de porc sau mușchi de vită, tăiat cuburi de 4 cm","2 cepe roșii mari (una feliată pentru marinadă, una tăiată felii pentru frigărui)","1 ardei gras roșu, tăiat bucăți de 4 cm","1 ardei gras verde, tăiat bucăți de 4 cm","1 vânătă medie, tăiată rondele de 3 cm","4 roșii coapte (pentru grătar întregi)","3 linguri ulei de floarea-soarelui","1 linguriță piper negru proaspăt măcinat","2 lingurițe sare grunjoasă","un mănunchi de busuioc și pătrunjel proaspăt, pentru servit","lavaș sau alt tip de pâine plată"]},"howIsMade":{"hi":"एक प्याज़ को बारीक स्लाइस करें। बड़े कटोरे में 800 ग्राम क्यूब में कटा मांस, स्लाइस प्याज़, 2 छोटा चम्मच नमक, 1 छोटा चम्मच काली मिर्च और 3 बड़े चम्मच सूरजमुखी का तेल मिलाएं। हाथों से अच्छे से मलें और 4–8 घंटे या रातभर फ्रिज में रखें।. कोयले की आग जलाएं और कोयलों को तब तक जलने दें जब तक वे लाल चमकदार न हों और किनारे सफेद न पड़ जाएं — लगभग 30–40 मिनट। ग्रिल को कोयले से 15 सेमी ऊपर रखें।. मैरिनेट किए हुए मांस को धातु की सींख पर चढ़ाएं, प्याज़ के टुकड़ों के साथ बारी-बारी लगाएं, और टुकड़ों के बीच गर्म हवा निकलने के लिए छोटा अंतर रखें।. साबुत मिर्च, बैंगन के टुकड़े और टमाटर को मांस से दूर सीधे ग्रिल पर रखें। बार-बार पलटकर सभी ओर से छिलका काला होने तक भूनें — कुल 12–15 मिनट।. मांस की सींख को कोयले के सबसे गर्म हिस्से के ऊपर रखें। हर 2 मिनट में पलटते हुए 10–14 मिनट तक ग्रिल करें, जब तक मांस बाहर से गहरा कैरामलाइज़्ड और बीच में हल्का गुलाबी न रह जाए — सूअर के लिए भीतरी तापमान 60°C।. ग्रिल की हुई सब्जियों को प्लेट में रखें, फॉयल से 5 मिनट ढकें, फिर जली हुई त्वचा उतार दें। मोटे-मोटे काटें और निकले रस, नमक और कटे हुए अजमोद के साथ मिलाकर एक देहाती चटनी बनाएं।. सींख को गरमागरम सब्जी की चटनी, ताज़ी तुलसी, नींबू के टुकड़े और गरम लवाश के साथ परोसें, लपेटकर खाएं।.","en":"Thinly slice one onion; in a large bowl, combine 800g cubed meat, the sliced onion, 2 tsp salt, 1 tsp black pepper, and 3 tbsp sunflower oil; massage well by hand and refrigerate 4–8 hours, or overnight. Light a charcoal fire and let it burn down to glowing red embers with white edges — about 30–40 minutes; position the grill 15 cm above the coals. Thread the marinated meat onto metal skewers, alternating with wedges of onion and leaving small gaps between pieces so the hot air can circulate. Lay the whole peppers, aubergine slices and tomatoes directly on the grill, away from the meat; char them rotating frequently, until the skins blacken on every side — about 12–15 minutes total. Place the meat skewers over the hottest part of the embers; grill 10–14 minutes, turning every 2 minutes, until the meat is deeply caramelised outside but still pink in the centre — internal temperature 60°C for pork. Transfer the grilled vegetables to a plate, cover with foil for 5 minutes, then strip off the blackened skins; roughly chop and mix with the resting juices, salt, and chopped parsley to make a rustic relish. Serve the skewers hot with the vegetable relish, fresh basil, lemon wedges, and warm lavash for wrapping."}},{"id":100,"origin":{"hi":"एस्टोनिया","en":"Estonia","ro":"Estonia"},"name":{"hi":"वेरिवोर्स्ट","en":"Verivorst","ro":"Verivorst"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"hi":["500 ग्राम सूअर का खून (ताज़ा या पिघलाया हुआ)","200 ग्राम सूअर की चर्बी या चर्बी वाला सूअर का पेट, छोटे क्यूब में कटा","200 ग्राम मोती जौ, पकाया और ठंडा किया हुआ","2 बड़े प्याज़, बारीक कटे","1 छोटा चम्मच सूखी मार्जोरम","1 छोटा चम्मच ऑलस्पाइस पाउडर","1 छोटा चम्मच काली मिर्च पाउडर","2 छोटा चम्मच मोटा नमक","1.5 मीटर साफ की हुई प्राकृतिक सॉसेज केसिंग","2 बड़े चम्मच सूअर का चर्बी (लार्ड), पकाने के लिए","परोसने के लिए लिंगोनबेरी जैम और अचार"],"en":["500g pig's blood (fresh or thawed)","200g pork fat or fatty pork belly, finely diced","200g pearl barley, cooked and cooled","2 large onions, finely chopped","1 tsp dried marjoram","1 tsp ground allspice","1 tsp ground black pepper","2 tsp coarse salt","1.5m cleaned natural sausage casing","2 tbsp pork lard, for cooking","lingonberry jam and pickled cucumbers, to serve"],"ro":["500g sânge de porc (proaspăt sau decongelat)","200g slănină sau piept de porc gras, tăiat cuburi mici","200g orz perlat, fiert și răcit","2 cepe mari, tocate fin","1 linguriță maghiran uscat","1 linguriță ienibahar măcinat","1 linguriță piper negru măcinat","2 lingurițe sare grunjoasă","1,5m maț natural curățat","2 linguri untură de porc, pentru gătit","gem de lingonberry și castraveți murați, pentru servit"]},"howIsMade":{"hi":"एक बड़ी कड़ाही में चर्बी के क्यूब्स को धीमी आंच पर 8–10 मिनट तक भूनें, जब तक अधिकांश चर्बी पिघल न जाए और क्यूब्स सुनहरे हो जाएं। कटी हुई प्याज़ डालें और 6–8 मिनट और पकाएं जब तक वे नरम और पारदर्शी न हो जाएं। पूरी तरह ठंडा होने दें।. एक बड़े कटोरे में पका हुआ जौ, तले हुए प्याज़ और चर्बी (पूरी चर्बी सहित), मार्जोरम, ऑलस्पाइस, नमक और काली मिर्च मिलाएं। अच्छे से मिलाएं।. खून को व्हिस्क से थोड़ी देर फेंटकर कोई थक्के तोड़ें, फिर इसे धीरे-धीरे जौ के मिश्रण में मिलाएं। भरावन चमकदार और बहने योग्य होनी चाहिए, पर बहुत पतली नहीं।. सॉसेज केसिंग को ठंडे बहते पानी में 5 मिनट तक धोएं। एक छोर को रसोई के धागे से बांधें।. केसिंग के खुले छोर को चौड़े फ़नल या सॉसेज स्टफर पर खिसकाएं। मिश्रण को धीरे-धीरे भरें, पकाने के दौरान फैलाव के लिए केसिंग को केवल दो-तिहाई भरा रखें। 12–15 सेमी के सॉसेज में बांधें और हर एक को सुई से कई जगह चुभोएं।. एक बड़े बर्तन में पानी को 80°C तक गरम करें — उबालें नहीं। सॉसेज को धीरे से डालें और 30–40 मिनट तक हल्के से पोच करें, जब तक छूने पर वे ठोस न लगें और चुभोने पर रस साफ न आए।. सॉसेज निकालें और 10 मिनट रखें। ओवन को 200°C पर पहले से गरम करें।. सॉसेज पर पिघली लार्ड लगाएं और ट्रे में रखकर 12–15 मिनट तक भूनें, बीच में एक बार पलटें, जब तक केसिंग कुरकुरी और सुनहरी न हो जाए। गरमागरम लिंगोनबेरी जैम और अचार के साथ परोसें।.","en":"In a large pan, fry the diced pork fat over low heat for 8–10 minutes, until most of its fat has rendered and the cubes are golden; add the chopped onions and cook 6–8 minutes more, until soft and translucent; set aside to cool completely. In a large bowl, combine the cooked pearl barley, the fried onions and pork fat (with all their fat), the marjoram, allspice, salt and pepper; mix well. Whisk the blood briefly to break up any clots, then stir it gradually into the barley mixture; the filling should look glossy and pourable, but not too liquid. Rinse the sausage casing under cold running water for 5 minutes; tie off one end with kitchen twine. Slide the open end of the casing onto a wide funnel or sausage stuffer; pipe the mixture in gradually, leaving the casing two-thirds full to allow expansion during cooking; tie off into 12–15 cm sausages and prick each with a needle in several places. Bring a large pot of water to 80°C — not boiling; slip the sausages in and poach gently for 30–40 minutes, until they feel firm to the touch and the juices run clear when pricked. Lift the sausages out and let them rest 10 minutes; preheat the oven to 200°C. Brush the sausages with melted lard and roast on a tray for 12–15 minutes, turning once, until the skins are crisp and burnished; serve hot with lingonberry jam and pickled cucumbers."}},{"id":102,"origin":{"hi":"दक्षिण कोरिया","en":"South Korea","ro":"Coreea de Sud"},"name":{"hi":"तोकबोक्की","en":"Tteokbokki","ro":"Tteokbokki"},"category":{"hi":"स्नैक","en":"Snack","ro":"Gustare"},"servings":4,"tipType":"def","pairingsType":"korean","ingredients":{"hi":["गेरे-तोक (बेलनाकार चावल के केक) 500 ग्राम, ताज़ा या पिघला हुआ","इओमुक (कोरियाई फिश केक) 150 ग्राम, त्रिकोण में कटा","गोचुजांग (किण्वित लाल मिर्च पेस्ट) 3 बड़े चम्मच","गोचुगारू (कोरियाई लाल मिर्च फ्लेक्स) 1 बड़ा चम्मच","चीनी 1 बड़ा चम्मच","सोया सॉस 1 छोटा चम्मच","एंकोवी स्टॉक 500 मिली (या पानी में दाशी पैकेट)","हरे प्याज़ 2, 5 सेमी टुकड़ों में कटे","2 उबले अंडे, छिले हुए","तिल का तेल 1 छोटा चम्मच","भुने तिल 1 छोटा चम्मच"],"en":["500g cylindrical rice cakes (garae-tteok), fresh or thawed","150g eomuk (Korean fish cake), cut into triangles","3 tbsp gochujang (fermented red chili paste)","1 tbsp gochugaru (Korean red pepper flakes)","1 tbsp sugar","1 tsp soy sauce","500ml anchovy stock (or water with a dashi packet)","2 spring onions, cut into 5 cm pieces","2 hard-boiled eggs, peeled","1 tsp sesame oil","1 tsp toasted sesame seeds"],"ro":["500g tteok cilindric (garae-tteok) proaspăt sau dezghețat","150g eomuk (prăjitură de pește coreeană), tăiat în triunghiuri","3 linguri gochujang (pastă de ardei iute fermentat)","1 lingură gochugaru (fulgi de ardei iute coreean)","1 lingură zahăr","1 linguriță sos de soia","500ml supă de hamsii (sau apă cu dashi)","2 cepe verzi, tăiate în bucăți de 5 cm","2 ouă fierte tari, decojite","1 linguriță ulei de susan","1 linguriță semințe de susan prăjite"]},"howIsMade":{"hi":"यदि तोक सख्त या ठंडे हैं, उन्हें गुनगुने पानी में 20–30 मिनट तक मुलायम होने तक भिगोएं। पानी निकाल दें।. एक चौड़े उथले पैन में 500 मिली एंकोवी स्टॉक को मध्यम-तेज़ आंच पर उबाल लें।. 3 बड़े चम्मच गोचुजांग, 1 बड़ा चम्मच गोचुगारू, 1 बड़ा चम्मच चीनी और 1 छोटा चम्मच सोया सॉस मिलाएं। पेस्ट पूरी तरह घुलने और सॉस चमकदार लाल होने तक व्हिस्क से फेंटें।. छाने हुए तोक डालें। हर टुकड़े पर सॉस लगाने के लिए हल्के से मिलाएं, फिर मध्यम आंच पर 8–10 मिनट तक बार-बार चलाते हुए पकाएं जब तक तोक नरम हो और सॉस गाढ़ा होकर चम्मच के पीछे चिपके।. इओमुक के टुकड़े डालें और 3–4 मिनट और पकाएं जब तक वे सॉस सोख लें और चमकदार लाल हो जाएं।. 2 उबले अंडे डालकर गरम करें। चखकर ज़रूरत हो तो चुटकीभर चीनी या थोड़ा सोया सॉस मिलाएं।. तिल का तेल छिड़कें, हरी प्याज़ और तिल बिखेरें। पैन से सीधे, बहुत गर्म, तुरंत परोसें।.","en":"If the rice cakes are hard or refrigerated, soak them in warm water for 20–30 minutes until pliable; drain. In a wide shallow pan, bring 500ml of anchovy stock to a boil over medium-high heat. Stir in 3 tbsp gochujang, 1 tbsp gochugaru, 1 tbsp sugar and 1 tsp soy sauce; whisk until the paste fully dissolves and the sauce turns glossy red. Add the drained rice cakes; stir gently to coat every piece, then simmer over medium heat for 8–10 minutes, stirring often, until the rice cakes are tender and the sauce has thickened to a syrupy consistency that coats the back of a spoon. Add the eomuk pieces and cook for another 3–4 minutes, until they have absorbed the sauce and turned bright red. Slip in the 2 hard-boiled eggs to warm through; taste and adjust with a pinch of sugar or a splash of soy if needed. Drizzle with sesame oil, sprinkle with the spring onions and sesame seeds; serve immediately, very hot, straight from the pan."}},{"id":103,"origin":{"hi":"इक्वेडोर","en":"Ecuador","ro":"Ecuador"},"name":{"hi":"झींगा सेविचे","en":"Shrimp Ceviche","ro":"Ceviche de camarón"},"category":{"hi":"नाश्ता","en":"Snack","ro":"Gustare"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"hi":["600 ग्राम मध्यम झींगे, छिले और नस निकाले हुए","180 मिली ताज़ा नींबू का रस (लगभग 8 नींबू)","120 मिली ताज़ा संतरे का रस","1 बड़ा लाल प्याज़, बारीक कटा","3 पके टमाटर, बीज निकालकर कटे","1 लाल मिर्च (ají), बारीक कटी (वैकल्पिक)","30 ग्राम ताज़े धनिये के पत्ते, कटे हुए","3 बड़े चम्मच जैतून का तेल","1 छोटा चम्मच महीन समुद्री नमक","ताज़ा पिसी काली मिर्च","चिफ्लेस (प्लांटेन चिप्स) या भुना मकई, परोसने के लिए"],"en":["600g medium shrimp, peeled and deveined","180ml fresh lime juice (about 8 limes)","120ml fresh orange juice","1 large red onion, finely diced","3 ripe tomatoes, deseeded and diced","1 red chili (ají), finely chopped (optional)","30g fresh coriander leaves, chopped","3 tbsp olive oil","1 tsp fine sea salt","freshly ground black pepper","chifles (plantain chips) or toasted corn, to serve"],"ro":["600g creveți medii, decojiți și fără vene","180ml suc proaspăt de lime (aproximativ 8 lime)","120ml suc proaspăt de portocale","1 ceapă roșie mare, tăiată cuburi mici","3 roșii coapte, fără semințe și tăiate cuburi","1 ardei iute roșu (ají), tocat fin (opțional)","30g frunze de coriandru proaspăt, tocate","3 linguri ulei de măsline","1 linguriță sare fină de mare","piper negru proaspăt măcinat","chifles (chipsuri de plantain) sau porumb prăjit, pentru servit"]},"howIsMade":{"hi":"एक बड़े बर्तन में नमकीन पानी उबालें। झींगे डालकर 60–90 सेकंड तक उबालें जब तक वे गुलाबी और अपारदर्शी न हो जाएं। तुरंत छानकर बर्फ के पानी के कटोरे में डालें।. झींगे का पानी निकालें, स्वादानुसार आधे करें या साबुत रखें, और एक नॉन-रिएक्टिव (कांच या सिरेमिक) कटोरे में रखें।. झींगों पर 180 मिली नींबू का रस और 120 मिली संतरे का रस डालें। मिलाएं, ढककर फ्रिज में 15–20 मिनट रखें।. झींगे के मैरिनेट होते समय, कटे हुए लाल प्याज़ को नमकीन बर्फ के पानी में 10 मिनट भिगोएं और छान लें — यह कच्ची तीखेपन को कम करता है पर कुरकुरापन बनाए रखता है।. झींगे के कटोरे में छाना हुआ प्याज़, टमाटर, मिर्च, धनिया, 3 बड़े चम्मच जैतून का तेल और 1 छोटा चम्मच नमक डालें। हल्के से मिलाएं।. चखकर नमक, नींबू या मिर्च समायोजित करें। स्वाद घुलने के लिए 5 मिनट रखें।. उथले कटोरों में बहुत ठंडा परोसें, साथ में कुरकुरापन के लिए चिफ्लेस या भुना मकई।.","en":"Bring a large pot of salted water to a boil; add the shrimp and boil for 60–90 seconds, until pink and opaque; drain immediately and shock in a bowl of ice water. Drain the shrimp, halve them or leave them whole as you prefer, and place in a non-reactive (glass or ceramic) bowl. Pour 180ml lime juice and 120ml orange juice over the shrimp; toss, cover, and refrigerate for 15–20 minutes. While the shrimp marinates, soak the diced red onion in salted ice water for 10 minutes, then drain — this softens the harsh bite without losing crunch. Add the drained onion, tomatoes, chili, coriander, 3 tbsp olive oil and 1 tsp salt to the shrimp bowl; toss gently. Taste and adjust salt, lime, or chili; let rest for 5 minutes so the flavours settle. Serve very cold in shallow bowls, with chifles or toasted corn alongside for crisp contrast."}},{"id":104,"origin":{"hi":"डोमिनिकन गणराज्य","en":"Dominican Republic","ro":"Republica Dominicană"},"name":{"hi":"ला बान्देरा","en":"La Bandera","ro":"La Bandera"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"latin","ingredients":{"hi":["400 ग्राम लंबे दाने वाला सफेद चावल","250 ग्राम सूखे राजमा (या 800 ग्राम पका हुआ/कैन से, छाना हुआ)","600 ग्राम हड्डी वाले चिकन थाई या बीफ चक, 4 सेमी क्यूब में कटा","2 बड़े हरे प्लांटेन, छिले और 1 सेमी मोटे टुकड़ों में","1 मध्यम हरी शिमला मिर्च, बारीक कटी","1 छोटी लाल शिमला मिर्च, बारीक कटी","1 बड़ी प्याज़, बारीक कटी","4 लहसुन की कलियां, कटी हुई","30 ग्राम ताज़ा धनिया, कटा हुआ (या कुलांत्रो)","2 पके टमाटर, कटे हुए (या 200 ग्राम कैन के कटे टमाटर)","2 बड़े चम्मच टमाटर पेस्ट","60 मिली वनस्पति तेल (प्लांटेन तलने के लिए और)","1 छोटा चम्मच सूखा अजवायन","1 नींबू का रस","स्वादानुसार नमक और ताज़ा पिसी काली मिर्च"],"en":["400g long-grain white rice","250g dried red kidney beans (or 800g cooked/canned, drained)","600g bone-in chicken thighs or beef chuck, cut into 4 cm cubes","2 large green plantains, peeled and sliced 1 cm thick","1 medium green bell pepper, finely diced","1 small red bell pepper, finely diced","1 large onion, finely chopped","4 garlic cloves, minced","30g fresh coriander, chopped (or culantro if available)","2 ripe tomatoes, diced (or 200g canned chopped tomatoes)","2 tbsp tomato paste","60ml vegetable oil (plus more for frying plantains)","1 tsp dried oregano","juice of 1 lime","salt and freshly ground black pepper"],"ro":["400g orez cu bob lung alb","250g fasole roșie uscată (sau 800g fasole gătită)","600g pulpe de pui cu os sau pulpă de vită, tăiată cuburi de 4 cm","2 banane plantain verzi mari, decojite, tăiate rondele de 1 cm","1 ardei gras verde mediu, tăiat cuburi mici","1 ardei gras roșu mic, tăiat cuburi mici","1 ceapă mare, tocată fin","4 căței de usturoi, tocați","30g coriandru proaspăt, tocat (sau culantro)","2 roșii coapte, tăiate cuburi (sau 200g roșii din conservă)","2 linguri pastă de roșii","60ml ulei vegetal (plus mai mult pentru prăjit)","1 linguriță oregano uscat","zeamă de la 1 lime","sare și piper negru proaspăt măcinat"]},"howIsMade":{"hi":"यदि सूखे राजमा का उपयोग कर रहे हैं, उन्हें रात भर भिगोएं। छानकर 1 लीटर ताज़े पानी और चुटकीभर नमक से ढकें, 60–75 मिनट तक नरम होने तक पकाएं। 250 मिली पकाने का पानी अलग रखें।. मांस को नमक, काली मिर्च, अजवायन और नींबू के रस से मैरिनेट करें। सोफ्रिटो तैयार करते समय 15 मिनट रखें।. भारी बर्तन में 2 बड़े चम्मच तेल गरम करें। सोफ्रिटो बनाएं: प्याज़ को 5 मिनट भूनें, फिर लहसुन, दोनों शिमला मिर्च और आधा धनिया डालें। 4 मिनट तक नरम होने तक पकाएं।. सोफ्रिटो को एक तरफ कर दें। खाली जगह में मांस डालें और प्रत्येक तरफ 3–4 मिनट तक भूनें। 2 बड़े चम्मच टमाटर पेस्ट और कटे टमाटर डालें, 3 मिनट पकाएं। 500 मिली पानी डालें, ढककर 35–40 मिनट तक पकाएं, जब तक मांस कांटे से नरमी से अलग न हो और सॉस गाढ़ा न हो जाए।. इसी बीच चावल पकाएं: 400 ग्राम चावल को पानी साफ निकलने तक धोएं। चौड़े बर्तन में 1 बड़ा चम्मच तेल और 1 छोटा चम्मच नमक गरम करें, चावल डालें, 700 मिली पानी डालें, उबाल लाएं, सबसे धीमी आंच पर ढककर 18–20 मिनट पकाएं। आंच से उतारकर 10 मिनट रखें।. राजमा पूरा करें: छोटे बर्तन में 1 बड़ा चम्मच तेल और चरण 3 में रखा हुआ एक बड़ा चम्मच सोफ्रिटो गरम करें। छाने हुए राजमा, 250 मिली रखे हुए पानी और 1 छोटा चम्मच नमक डालें। 12–15 मिनट पकाएं, मुट्ठीभर राजमा को बर्तन की दीवार पर दबाकर सॉस की गाढ़ी स्थिरता बनाएं।. एक पैन में 5 सेमी तेल को 175°C तक गरम करें। प्लांटेन के टुकड़ों को 3–4 मिनट सुनहरा होने तक तलें। कागज पर निकालकर तेल छानें, प्रेस या गिलास के तले से दबाकर चपटा करें, 1–2 मिनट और कुरकुरा होने तक तलें। गरम होने पर नमक छिड़कें।. प्लेट लगाएं: आधार के रूप में चावल, बगल में एक करछुल राजमा, सॉस के साथ ब्रेज़्ड मांस का उदार भाग और 4–5 प्लांटेन टुकड़े। बचा हुआ धनिया, नींबू के टुकड़े और साधारण हरी सलाद के साथ खत्म करें।.","en":"Soak the dried beans overnight if using; drain, cover with 1L fresh water and a pinch of salt, and simmer for 60–75 minutes, until fully tender; reserve 250ml of the cooking liquid. Season the meat with salt, pepper, oregano, and lime juice; rest for 15 minutes while you prepare the sofrito. Heat 2 tbsp oil in a heavy pot; make a sofrito: sauté the onion for 5 minutes, then add the garlic, both peppers, and half the coriander; cook 4 minutes until soft. Push the sofrito to one side; add the meat to the empty space and brown for 3–4 minutes per side; stir in 2 tbsp tomato paste and the diced tomatoes, cook for 3 minutes; pour in 500ml water, cover, and simmer for 35–40 minutes, until the meat is fork-tender and the sauce has thickened. Meanwhile cook the rice: rinse 400g of rice until the water runs clear; in a wide pot, heat 1 tbsp oil and 1 tsp salt, add the rice, cover with 700ml water, bring to a boil, then reduce to the lowest heat and steam, covered, for 18–20 minutes; rest 10 minutes off heat. Finish the beans: in a small pot, heat 1 tbsp oil and a spoonful of the sofrito set aside in step 3; add the drained beans plus 250ml reserved cooking liquid and 1 tsp salt; simmer for 12–15 minutes, mashing a handful against the side of the pot to thicken to a saucy consistency. Heat 5 cm of oil in a frying pan to 175°C; fry the plantain slices for 3–4 minutes until golden; drain on paper, flatten with a press or the back of a cup, and refry for 1–2 minutes until crisp; salt while hot. Plate each portion with rice as the base, a ladle of beans alongside, a generous portion of braised meat with its sauce, and 4–5 plantain rounds; finish with the remaining coriander, lime wedges, and a simple green salad."}},{"id":105,"origin":{"hi":"ईरान","en":"Iran","ro":"Iran"},"name":{"hi":"फेसेंजान","en":"Fesenjan","ro":"Fesenjan"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"middle-eastern","ingredients":{"hi":["800 ग्राम बिना हड्डी चिकन थाई, या 1 छोटी बत्तख (1.5 किलो) कटी हुई","300 ग्राम छिले अखरोट, भूनकर बारीक पिसे","120 मिली अनार का शीरा","2 बड़े प्याज़, बारीक कटे","3 बड़े चम्मच वनस्पति तेल","1 छोटा चम्मच हल्दी पाउडर","1 छोटा चम्मच दालचीनी पाउडर","1/2 छोटा चम्मच ताज़ा कद्दूकस की हुई जायफल","1 बड़ा चम्मच ब्राउन शुगर (या स्वादानुसार)","1 लीटर गर्म चिकन शोरबा या पानी","ताज़े अनार के दाने, सजावट के लिए","स्वादानुसार नमक और ताज़ा पिसी काली मिर्च","परोसने के लिए बासमती चावल"],"en":["800g boneless chicken thighs, or 1 small duck (1.5kg) jointed","300g shelled walnuts, toasted and finely ground","120ml pomegranate molasses","2 large onions, finely chopped","3 tbsp vegetable oil","1 tsp ground turmeric","1 tsp ground cinnamon","1/2 tsp freshly grated nutmeg","1 tbsp brown sugar (or to taste)","1 litre hot chicken stock or water","fresh pomegranate seeds, to garnish","salt and freshly ground black pepper","basmati rice, to serve"],"ro":["800g pulpe de pui dezosate, sau 1 rață mică (1,5kg) tăiată","300g miez de nucă, prăjit și măcinat fin","120ml melasă de rodie","2 cepe mari, tocate fin","3 linguri ulei vegetal","1 linguriță turmeric măcinat","1 linguriță scorțișoară măcinată","1/2 linguriță nucșoară proaspăt rasă","1 lingură zahăr brun (sau după gust)","1 litru supă de pui sau apă fierbinte","semințe de rodie proaspete, pentru ornat","sare și piper negru proaspăt măcinat","orez basmati pentru servit"]},"howIsMade":{"hi":"एक सूखी कड़ाही में 300 ग्राम अखरोट को मध्यम आंच पर 4–5 मिनट लगातार हिलाते हुए भूनें, जब तक खुशबू आए और रंग थोड़ा गहरा हो जाए। ठंडा करके फूड प्रोसेसर में जितना संभव हो उतनी बारीक पेस्ट बनाएं।. एक भारी बर्तन में 3 बड़े चम्मच तेल मध्यम आंच पर गरम करें। कटी हुई प्याज़ डालें और 12–15 मिनट तक गहरी सुनहरी और मीठी होने तक भूनें। हल्दी, दालचीनी और जायफल डालकर 1 मिनट पकाएं।. मांस को नमक और काली मिर्च से सीज़न करें। बर्तन में डालें और प्रत्येक तरफ 4–5 मिनट तक केवल रंग के लिए भूनें। प्लेट में निकालें।. अखरोट की पेस्ट बर्तन में डालें और लकड़ी के चम्मच से 3 मिनट चलाएं, जब तक तेल छोड़ने लगे और भुनी हुई महक आए — यह कदम सॉस की गहराई बनाता है।. 1 लीटर गर्म शोरबा डालें, मांस को रस सहित वापस डालें, और धीमी आंच पर बिना ढके 30–40 मिनट पकाएं, अखरोट पेस्ट जलने न पाए इसलिए बार-बार चलाएं।. अनार का शीरा और ब्राउन शुगर डालें। चखें: सॉस खट्टी-मीठी और गहरी स्वादिष्ट होनी चाहिए। धीमी आंच पर 30–40 मिनट और पकाएं जब तक मांस पूरी तरह नरम न हो, सॉस लगभग काला न हो और अखरोट का तेल सतह पर न आ जाए।. नमक, खटास के लिए और शीरा या मिठास संतुलित करने के लिए चीनी से समायोजित करें। गर्म बासमती चावल के ऊपर परोसें, ताज़े अनार के दानों से सजाएं।.","en":"Toast 300g of walnuts in a dry pan over medium heat for 4–5 minutes, tossing constantly, until fragrant and slightly darker; cool, then grind to as fine a paste as possible in a food processor. In a heavy pot, heat 3 tbsp oil over medium heat; add the chopped onions and cook for 12–15 minutes, until deeply golden and sweet; stir in the turmeric, cinnamon, and nutmeg and cook for 1 minute. Season the meat with salt and pepper; add to the pot and brown for 4–5 minutes per side, just for colour; lift onto a plate. Add the walnut paste to the pot and stir with a wooden spoon for 3 minutes, until it starts releasing oil and smells toasted — this is the step that builds the sauce's depth. Pour in 1 litre of hot stock, return the meat with its juices, and simmer uncovered over low heat for 30–40 minutes, stirring often so the nut paste does not scorch. Add the pomegranate molasses and brown sugar; taste: the sauce should be tart-sweet and deeply savoury; continue to simmer over low heat for another 30–40 minutes, until the meat is fully tender, the sauce has darkened to almost black, and walnut oil rises to the surface. Adjust with salt, more molasses (for tartness) or sugar (to round it); serve over warm basmati rice, scattered with fresh pomegranate seeds."}},{"id":106,"origin":{"hi":"फिलीपींस","en":"Philippines","ro":"Filipine"},"name":{"hi":"कारे-कारे","en":"Kare-Kare","ro":"Kare-Kare"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"hi":["1.2 किलो बैल की पूंछ, जोड़ों पर कटी (या हड्डी सहित बीफ शैंक)","200 ग्राम बिना मीठा मूंगफली का मक्खन (या 250 ग्राम भुनी मूंगफली, पिसी हुई)","2 बड़े चम्मच एनाटो (अचुएटे) बीज — या 1 बड़ा चम्मच एनाटो पाउडर","4 बड़े चम्मच कच्चा चावल, सूखी कड़ाही में भूनकर पिसा हुआ","1 बड़ा प्याज़, बारीक कटा","6 लहसुन की कलियां, कटी हुई","1 बड़ा बैंगन, चार टुकड़ों में कटा","200 ग्राम लंबी हरी फलियां (sitaw), 7 सेमी टुकड़ों में","1 बड़ा बोक चॉय या 200 ग्राम पेचाय, लंबाई में आधा कटा","1.5 लीटर पानी (या बीफ शोरबा)","60 मिली वनस्पति तेल","स्वादानुसार नमक","बागूंग (फिलिपिनो किण्वित झींगा पेस्ट), परोसने के लिए","उबले चावल, परोसने के लिए"],"en":["1.2kg oxtail, cut at the joints (or bone-in beef shank)","200g unsweetened peanut butter (or 250g roasted peanuts, ground)","2 tbsp annatto (achuete) seeds — or 1 tbsp annatto powder","4 tbsp raw rice, toasted in a dry pan and ground","1 large onion, finely chopped","6 garlic cloves, minced","1 large eggplant, cut into quarters","200g long green beans (sitaw), cut into 7 cm lengths","1 large bok choy or 200g pechay, halved lengthwise","1.5L water (or beef stock)","60ml vegetable oil","salt to taste","bagoong (Filipino shrimp paste), to serve","steamed rice, to serve"],"ro":["1,2kg coadă de vită, tăiată în bucăți la articulație (sau pulpă de vită cu os)","200g pastă de arahide neîndulcită (sau 250g arahide prăjite, măcinate)","2 linguri semințe de annatto (achiote) — sau 1 lingură pudră de annatto","4 linguri orez crud, prăjit într-o tigaie uscată și măcinat","1 ceapă mare, tocată fin","6 căței de usturoi, tocați","1 vânătă mare, tăiată sferturi","200g fasole verde lungă, tăiată în bucăți de 7 cm","1 bok choy mare sau 200g pak choi, tăiat pe lungime","1,5L apă (sau supă de vită)","60ml ulei vegetal","sare după gust","bagoong (pastă de creveți filipineză) pentru servit","orez fiert, pentru servit"]},"howIsMade":{"hi":"बैल की पूंछ को बड़े बर्तन में 1.5 लीटर पानी के साथ डालें। उबाल लाएं, झाग हटाएं और 5 मिनट उबालें। छानकर मांस को धोएं ताकि साफ शोरबा बने।. मांस को 1.5 लीटर ताज़े पानी (या बीफ शोरबा) के साथ वापस बर्तन में डालें और 2.5–3 घंटे धीमी आंच पर पकाएं जब तक मांस हड्डी से लगभग अलग न होने लगे। मांस निकालकर 1 लीटर शोरबा बचाकर रखें।. एनाटो बीजों को 3 बड़े चम्मच गरम पानी में 10 मिनट भिगोएं, फिर छानकर गहरा लाल-नारंगी तरल प्राप्त करें (या एनाटो पाउडर सीधे घोल लें)।. एक साफ बर्तन में 60 मिली तेल गरम करें। प्याज़ को 5 मिनट भूनें, लहसुन डालें और 1 मिनट और पकाएं।. मूंगफली का मक्खन, एनाटो तरल और बचाया हुआ 1 लीटर शोरबा डालें। चिकना रखने के लिए व्हिस्क से फेंटें। 5 मिनट पकाएं, फिर भुना पिसा चावल डालें — चटनी स्पष्ट रूप से गाढ़ी होने लगेगी।. मांस को चटनी में वापस डालें और धीमी आंच पर 10–15 मिनट पकाएं, बहुत गाढ़ा हो तो शोरबे से पतला करें। नमक सावधानी से डालें — मेज पर परोसा गया बागूंग बहुत नमकीन है।. बैंगन के टुकड़े और हरी फलियां डालें, 5 मिनट पकाएं। ऊपर बोक चॉय रखें, ढककर 3 मिनट और पकाएं जब तक सब्जियां नरम लेकिन रंगीन रहें।. गहरे कटोरे में उबले चावल पर परोसें, बगल में एक छोटे कटोरे में बागूंग रखें — हर डिनर अपनी पसंद के अनुसार मिलाता है।.","en":"Put the oxtail in a large pot with 1.5L water; bring to a boil, skim the foam, and boil for 5 minutes; drain and rinse the meat for a clear broth. Return the meat to the pot with 1.5L fresh water (or beef stock) and simmer gently for 2.5–3 hours, until the meat falls almost off the bone; lift out the meat and reserve 1L of the broth. Steep the annatto seeds in 3 tbsp hot water for 10 minutes, then strain to a deep red-orange liquid (or dissolve the annatto powder directly). In a clean pot, heat 60ml oil; sauté the onion for 5 minutes, add the garlic and cook 1 minute more. Stir in the peanut butter, annatto liquid, and 1L of the reserved broth; whisk to keep it smooth; simmer 5 minutes, then add the toasted ground rice — the sauce will begin to thicken visibly. Return the meat to the sauce and simmer over low heat for 10–15 minutes, loosening with more broth if it becomes too thick; season with salt (sparingly — the bagoong at the table is very salty). Add the eggplant quarters and long beans, simmer 5 minutes; lay the bok choy on top, cover, and cook for another 3 minutes, until the vegetables are tender but still vibrant. Serve in deep bowls over steamed rice, with bagoong in a small bowl alongside — each diner stirs in as much as they like."}},{"id":107,"origin":{"hi":"पुर्तगाल","en":"Portugal","ro":"Portugalia"},"name":{"hi":"फ्रांसेज़िन्हा","en":"Francesinha","ro":"Francesinha"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"hi":["8 मोटी सफेद ब्रेड स्लाइस (सैंडविच लोफ)","400 ग्राम रिब-आई या सिरलोइन स्टेक, 4 पतले स्लाइस में काटा हुआ","4 लिंगुइसा या स्मोक्ड सॉसेज, लंबाई में आधे कटे","8 पकी हुई हैम स्लाइस","8 मसालेदार सलामी या चोरिज़ो स्लाइस","12 स्लाइस चेडर या गौडा (पिघलने वाला)","4 अंडे, ऊपर रखने के लिए","30 ग्राम मक्खन","अंडे तलने के लिए तेल","सॉस के लिए:","400 मिली लागर बीयर","200 मिली बीफ शोरबा","200 ग्राम टमाटर पेस्ट","60 मिली व्हिस्की या ब्रांडी","1 छोटा प्याज़, बारीक कटा","2 लहसुन की कलियां, कटी हुई","1 तेज पत्ता","1/2 छोटा चम्मच मिर्च फ्लेक्स (या piri-piri)","1 बड़ा चम्मच मैदा","स्वादानुसार नमक, काली मिर्च, चीनी","फ्राइज़, परोसने के लिए"],"en":["8 thick slices white bread (sandwich loaf)","400g rib-eye or sirloin steak, cut into 4 thin slices","4 linguiça or smoked sausage links, halved lengthwise","8 slices cooked ham","8 slices spicy salami or chouriço","12 slices Cheddar or Gouda, melting type","4 eggs, for topping","30g butter","oil for frying eggs","For the sauce:","400ml lager beer","200ml beef stock","200g tomato paste","60ml whisky or brandy","1 small onion, finely chopped","2 garlic cloves, minced","1 bay leaf","1/2 tsp chili flakes (or piri-piri)","1 tbsp flour","salt, pepper, sugar to taste","fries, to serve"],"ro":["8 felii groase de pâine albă (tip toast)","400g antricot sau mușchi de vită, în 4 felii subțiri","4 cârnați linguiça (sau cabanos afumat), tăiați pe lungime","8 felii de șuncă (presunto) fiartă","8 felii salami picant (chouriço)","12 felii brânză cheddar sau Gouda topit","4 ouă (pentru deasupra)","30g unt","ulei pentru prăjit ouăle","Pentru sos:","400ml bere blondă","200ml bulion de vită","200g pastă de roșii","60ml whisky sau brandy","1 ceapă mică, tocată","2 căței de usturoi, tocați","1 frunză de dafin","1/2 linguriță fulgi de chili (sau piri-piri)","1 lingură făină","sare, piper, zahăr după gust","cartofi prăjiți, pentru servit"]},"howIsMade":{"hi":"पहले सॉस बनाएं: एक सॉसपैन में 1 बड़ा चम्मच मक्खन गरम करें, प्याज़ को 5 मिनट भूनें, लहसुन और 1 बड़ा चम्मच मैदा डालकर 1 मिनट पकाएं। टमाटर पेस्ट डालें और 2 मिनट पकाएं।. बीयर और व्हिस्की डालें, अल्कोहल जलने के लिए 2 मिनट उबालें। शोरबा, तेज पत्ता, मिर्च फ्लेक्स, एक चुटकी नमक और चीनी डालें। धीमी आंच पर 25–30 मिनट तक पकाएं जब तक सॉस गाढ़ी और चमकदार न हो जाए। चिकनी फिनिश के लिए छानें।. स्टेक स्लाइस पर नमक और काली मिर्च लगाएं। बची मक्खन एक पैन में पिघलाएं और स्टेक को प्रत्येक तरफ 1.5 मिनट तक भूनकर निकालें।. उसी पैन में लिंगुइसा के आधे टुकड़ों को प्रत्येक तरफ 2–3 मिनट तक सेंकें।. हर सैंडविच के लिए 2 ब्रेड स्लाइस को मक्खन या तेल में दोनों तरफ 1 मिनट तक टोस्ट करें। परत बनाएं: 1 ब्रेड, 2 हैम स्लाइस, 1 स्टेक, 2 सलामी स्लाइस, 2 लिंगुइसा आधे, फिर दूसरी ब्रेड स्लाइस। हल्के से दबाएं।. सैंडविच को ग्रीस्ड बेकिंग डिश में रखें। हर एक पर 3 चीज़ स्लाइस ढकें और 220°C ग्रिल के नीचे 3–4 मिनट रखें जब तक चीज़ पिघले, बुलबुले उठें और जगह-जगह सुनहरा हो जाए।. हर सैंडविच के लिए 1 अंडा तेल में फ्राई करें, जर्दी बहती हुई रखें।. हर सैंडविच को गहरी प्लेट में रखें, चीज़ के ऊपर तला अंडा रखें, और सॉस को सैंडविच के चारों ओर उदारता से डालें — प्लेट के तल में जमा होना चाहिए। तुरंत फ्राइज़ के साथ परोसें।.","en":"Make the sauce first: heat 1 tbsp of the butter in a saucepan, sauté the onion for 5 minutes, add the garlic and 1 tbsp flour, cook for 1 minute; stir in the tomato paste and cook for 2 minutes. Pour in the beer and whisky, simmer 2 minutes to burn off the alcohol; add the beef stock, bay leaf, chili flakes, a pinch each of salt and sugar; simmer over low heat for 25–30 minutes, until the sauce is thick and glossy; strain for a smooth finish. Season the steak slices with salt and pepper; melt the remaining butter in a frying pan and sear the steak for 1.5 minutes per side, until browned; lift out. In the same pan, fry the linguiça halves for 2–3 minutes per side, until coloured. For each sandwich, toast 2 slices of bread in butter or oil on both sides (1 minute per side); layer: 1 slice bread, 2 slices ham, 1 slice steak, 2 slices salami, 2 linguiça halves, top with second slice of bread; press gently. Place the sandwiches in a greased baking dish; cover each with 3 slices of cheese and slide under a grill at 220°C for 3–4 minutes, until the cheese melts, bubbles and browns in spots. Fry 1 egg per sandwich in oil, leaving the yolk runny. Set each sandwich in a deep plate, place a fried egg on top of the cheese, and pour the hot sauce generously around the sandwich — it should pool at the base of the plate; serve immediately with fries on the side."}},{"id":109,"origin":{"hi":"पेरू","en":"Peru","ro":"Peru"},"name":{"hi":"अरोस चाउफ़ा","en":"Arroz Chaufa","ro":"Arroz Chaufa"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"latin","ingredients":{"hi":["500 ग्राम लंबे दाने वाला चावल, पका और ठंडा (एक दिन पुराना हो तो बेहतर)","300 ग्राम चिकन ब्रेस्ट या पोर्क लॉइन, 1.5 सेमी क्यूब में कटा","3 बड़े अंडे, फेंटे हुए","1 लाल शिमला मिर्च, बारीक कटी","6 हरे प्याज़, सफेद भाग बारीक कटे, हरा भाग अलग रखा","3 लहसुन की कलियां, कटी हुई","20 ग्राम ताज़ा अदरक, बारीक कटा","60 मिली सोया सॉस","1 बड़ा चम्मच ऑयस्टर सॉस","1 बड़ा चम्मच भुना तिल का तेल","60 मिली तटस्थ वनस्पति तेल","1 छोटा चम्मच आहि अमारियो पेस्ट (या 1/2 छोटा चम्मच मिर्च पाउडर)","स्वादानुसार नमक और सफेद मिर्च"],"en":["500g long-grain rice, cooked and cooled (preferably day-old)","300g chicken breast or pork loin, cut into 1.5 cm cubes","3 large eggs, beaten","1 red bell pepper, finely diced","6 spring onions, white parts finely sliced, green parts reserved","3 garlic cloves, minced","20g fresh ginger, finely minced","60ml soy sauce","1 tbsp oyster sauce","1 tbsp toasted sesame oil","60ml neutral vegetable oil","1 tsp ají amarillo paste (or 1/2 tsp chili powder)","salt and white pepper to taste"],"ro":["500g orez cu bob lung fiert și răcit (preferabil de o zi)","300g piept de pui sau pulpă de porc, tăiat cuburi de 1,5 cm","3 ouă mari, bătute","1 ardei kapia roșu, tăiat cuburi mici","6 cepe verzi, partea albă tăiată fin, verdele păstrat","3 căței de usturoi, tocați","20g ghimbir proaspăt, tocat fin","60ml sos de soia","1 lingură sos de stridii","1 lingură ulei de susan","60ml ulei vegetal neutru","1 linguriță aji amarillo pastă (sau 1/2 linguriță pudră de chili)","sare și piper alb după gust"]},"howIsMade":{"hi":"अंडे को एक चुटकी नमक के साथ फेंटें। एक वोक में 1 बड़ा चम्मच वनस्पति तेल मध्यम आंच पर गरम करें, अंडे डालकर तेजी से चलाते हुए पतला ऑमलेट बनाएं। प्लेट में निकालकर छोटे टुकड़ों में काटें। अलग रखें।. वोक बहुत गरम होने पर एक और 1 बड़ा चम्मच तेल डालें। मांस को एक चुटकी नमक के साथ 3–4 मिनट तक भूनें जब तक किनारे सुनहरे हों और अंदर पक जाए। ऑमलेट की प्लेट में निकालें।. बचा हुआ वनस्पति तेल वोक में डालें और हल्का धुआं उठने तक गरम करें। लहसुन, अदरक और शिमला मिर्च डालकर 30 सेकंड तक खुशबू आने तक भूनें।. हरे प्याज़ का सफेद भाग और आहि अमारियो पेस्ट डालें। 30 सेकंड और भूनें जिससे स्वाद तेल में मिल जाए।. ठंडे चावल डालें। स्पैचुला से छोटे टुकड़ों में तोड़ें, 3–4 मिनट तक बीच-बीच में वोक के तले पर दबाएं और पलटें जब तक हर दाना अलग हो और हल्की चटचटाहट सुनाई दे।. चावल पर सोया सॉस और ऑयस्टर सॉस डालें, 1 मिनट तक चलाएं जब तक रंग समान रूप से बंट जाए। मांस और अंडे वापस वोक में डालें।. आंच बंद करें। तिल का तेल छिड़कें और हरे प्याज़ का हरा भाग डालें। सफेद मिर्च से सीज़न करें। तुरंत वोक से सीधे गरम परोसें।.","en":"Beat the eggs with a pinch of salt; heat 1 tbsp of vegetable oil in a wok over medium heat, pour in the eggs, and quickly make a thin omelette by stirring; tip onto a plate and cut into small cubes; set aside. With the wok very hot, add another 1 tbsp oil; stir-fry the meat with a pinch of salt for 3–4 minutes, until browned at the edges and cooked through; move to the plate with the eggs. Pour the remaining vegetable oil into the wok and heat until it just begins to smoke; add the garlic, ginger, and bell pepper, and stir-fry for 30 seconds, until fragrant. Add the white parts of the spring onions and the ají amarillo paste; stir-fry for 30 seconds, letting the flavours infuse the oil. Add the cold rice; use a spatula to break it into small pieces, pressing it against the bottom of the wok between tosses for 3–4 minutes, until every grain is separate and you hear a slight sizzle. Pour the soy sauce and oyster sauce over the rice, tossing for 1 minute to distribute evenly and pick up colour; return the meat and egg to the wok. Turn off the heat; drizzle with the sesame oil and add the green parts of the spring onions; season with white pepper; serve immediately, hot, straight from the wok."}},{"id":110,"origin":{"hi":"सिंगापुर","en":"Singapore","ro":"Singapore"},"name":{"hi":"चिली केकड़ा","en":"Chili Crab","ro":"Chili Crab"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"hi":["2 जीवित मड क्रैब (कुल 1.5 किलो), साफ कर के जोड़ों पर आधे काटे हुए","4 बड़े चम्मच टमाटर पेस्ट","3 बड़े चम्मच साम्बल ओलेक (या मिर्च पेस्ट)","2 बड़े चम्मच मीठी मिर्च सॉस","60 मिली केचप","30 ग्राम ताज़ा अदरक, कद्दूकस की हुई","6 लहसुन की कलियां, कटी हुई","2 बड़े अंडे, फेंटे हुए","3 हरी प्याज़, कटी हुई","1 बड़ा चम्मच चावल का सिरका","2 छोटे चम्मच चीनी","1 छोटा चम्मच नमक","500 मिली चिकन शोरबा (या पानी)","60 मिली वनस्पति तेल","1 बड़ा चम्मच कॉर्न स्टार्च, 2 बड़े चम्मच पानी में घोला हुआ","तले हुए मंटू (चीनी बन), परोसने के लिए"],"en":["2 live mud crabs (1.5kg total), cleaned and halved at the joints","4 tbsp tomato paste","3 tbsp sambal oelek (or chili paste)","2 tbsp sweet chili sauce","60ml ketchup","30g fresh ginger, grated","6 garlic cloves, minced","2 large eggs, beaten","3 spring onions, chopped","1 tbsp rice vinegar","2 tsp sugar","1 tsp salt","500ml chicken stock (or water)","60ml vegetable oil","1 tbsp cornstarch mixed with 2 tbsp water","fried mantou (Chinese buns), to serve"],"ro":["2 crabi de noroi vii (1,5kg în total), curățați și tăiați în jumătăți la articulații","4 linguri pastă de roșii","3 linguri sos sambal oelek (sau pastă de chili)","2 linguri sos dulce de chili","60ml ketchup","30g ghimbir proaspăt, ras","6 căței de usturoi, tocați","2 ouă mari, bătute","3 cepe verzi, tocate","1 lingură oțet de orez","2 lingurițe zahăr","1 linguriță sare","500ml supă de pui (sau apă)","60ml ulei vegetal","1 lingură amidon de porumb amestecat cu 2 linguri apă","mantou prăjit (chifle chinezești), pentru servit"]},"howIsMade":{"hi":"केकड़ों को 30 मिनट के लिए फ्रीज़र में रखें जिससे वे कोमलता से बेहोश हो जाएं। उन्हें साफ करें, ऊपरी कवच हटाएं, अंदर के नरम अंग निकालें, और जोड़ों पर हर केकड़े को दो हिस्सों में काटें। चाकू के पीछे से चिमटे तोड़ें जिससे स्वाद अंदर तक पहुंचे।. एक छोटे कटोरे में अंडे फेंटें। दूसरे कटोरे में टमाटर पेस्ट, साम्बल, मीठी मिर्च सॉस, केचप, सिरका, चीनी और नमक मिलाएं — यह सॉस का आधार है।. एक बड़े वोक या गहरे बर्तन में 60 मिली तेल तेज़ आंच पर गरम करें। केकड़े के टुकड़े डालें और 3–4 मिनट तक पलटते हुए तलें जब तक कवच लाल न हो जाए। प्लेट में निकालें।. उसी तेल में कद्दूकस की हुई अदरक और लहसुन 30 सेकंड तक भूनें जब तक तेज़ खुशबू न आए।. टमाटर मिश्रण और 500 मिली चिकन शोरबा डालें। उबाल लाएं, अधिक तीखेपन के लिए अधिक साम्बल डालें।. केकड़े के टुकड़े वापस डालें, वोक ढककर 8–10 मिनट तक पकाएं, बीच में एक बार पलटें, जब तक मांस पूरी तरह पकाकर नरम न हो जाए।. कॉर्न स्टार्च मिश्रण को पतली धार में डालें और चलाते हुए सॉस को गाढ़ा और चमकदार बनाएं। फेंटे हुए अंडे को बिना चलाए वोक के चारों ओर गोलाकार में डालें — वे रेशमी रिबन की तरह जम जाएंगे। 30 सेकंड रुकें, फिर एक बार मोड़ें।. कटी हुई हरी प्याज़ छिड़कें। तुरंत एक बड़ी थाली में परोसें, साथ में तले हुए मंटू रखें जिनसे सॉस को पोंछा जा सके।.","en":"Place the crabs in the freezer for 30 minutes to humanely stun them; clean them, lift off the top shell, remove the soft inner organs, and chop the crab in half at the joints; crack the claws with the back of a knife so the flavour penetrates. Beat the eggs in a small bowl; in another bowl, stir together the tomato paste, sambal, sweet chili sauce, ketchup, vinegar, sugar and salt — this is the sauce base. Heat 60ml of oil in a large wok or deep pot over high heat; add the crab pieces and stir-fry for 3–4 minutes, turning, until the shells turn red; lift onto a plate. In the same oil, sauté the grated ginger and garlic for 30 seconds, until very fragrant. Pour in the tomato-paste mixture and 500ml chicken stock; bring to a boil, adjust with more sambal for more heat. Return the crab pieces, cover the wok and simmer for 8–10 minutes, turning once halfway, until the meat is fully cooked and tender. Stir the cornstarch slurry into the sauce in a thin stream so the sauce thickens to a glossy coat; pour the beaten eggs around the wok in a spiral without stirring — they will set as silky ribbons; wait 30 seconds, then fold once. Scatter with the chopped spring onions; serve immediately on a large platter with fried mantou alongside to soak up the sauce."}},{"id":111,"origin":{"hi":"मेक्सिको","en":"Mexico","ro":"Mexic"},"name":{"hi":"तामाले","en":"Tamale","ro":"Tamale"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"mexican","ingredients":{"hi":["20–24 सूखी मक्के की पत्तियां","500 ग्राम मासा हरीना (निक्स्तामलाइज़्ड मक्का आटा)","250 ग्राम सूअर का चर्बी (लार्ड), कमरे के तापमान पर","500 मिली गर्म चिकन शोरबा","1 बड़ा चम्मच बेकिंग पाउडर","2 छोटे चम्मच नमक","भरावन के लिए:","500 ग्राम बिना हड्डी सूअर का कंधा, उबला और कतरा हुआ","4 सूखी गुआहियो मिर्च, डंठल और बीज निकाले हुए","2 सूखी अंचो मिर्च, डंठल और बीज निकाले हुए","1 छोटा प्याज़, चार टुकड़ों में","3 लहसुन की कलियां","1 छोटा चम्मच पिसा जीरा","1 छोटा चम्मच मेक्सिकन अजवायन","2 बड़े चम्मच वनस्पति तेल","स्वादानुसार नमक","लाल या हरी साल्सा, परोसने के लिए"],"en":["20–24 dried corn husks","500g masa harina (nixtamalized corn flour)","250g pork lard, at room temperature","500ml warm chicken stock","1 tbsp baking powder","2 tsp salt","For the filling:","500g boneless pork shoulder, simmered and shredded","4 dried guajillo chilies, stems and seeds removed","2 dried ancho chilies, stems and seeds removed","1 small onion, quartered","3 garlic cloves","1 tsp ground cumin","1 tsp Mexican oregano","2 tbsp vegetable oil","salt to taste","red or green salsa, to serve"],"ro":["20–24 foi de porumb uscate (chiote)","500g masa harina (făină de porumb nixtamalizată)","250g untură de porc, la temperatura camerei","500ml supă de pui caldă","1 lingură praf de copt","2 lingurițe sare","Pentru umplutură:","500g pulpă de porc dezosată, fiartă și mărunțită","4 ardei iuți guajillo uscați, fără semințe","2 ardei iuți ancho uscați, fără semințe","1 ceapă mică, tăiată sferturi","3 căței de usturoi","1 linguriță chimion măcinat","1 linguriță oregano mexican","2 linguri ulei vegetal","sare după gust","salsă roșie sau verde, pentru servit"]},"howIsMade":{"hi":"मक्के की पत्तियों को गुनगुने पानी में 30 मिनट तक भिगोएं जब तक वे लचीली न हो जाएं। प्लेट से दबाकर डूबा रखें।. सॉस तैयार करें: सूखी कड़ाही में गुआहियो और अंचो मिर्च हर तरफ 1 मिनट तक भूनें जब तक खुशबू न आए। गर्म पानी में 15 मिनट डुबोएं। भिगोई हुई मिर्च, प्याज़, लहसुन, जीरा, अजवायन और 250 मिली भिगोने का पानी ब्लेंडर में डालकर पीसें। छानें।. एक पैन में 2 बड़े चम्मच तेल गरम करें, मिर्च सॉस डालें और 8–10 मिनट गाढ़ा होने तक पकाएं। कतरा हुआ सूअर का मांस डालें, नमक से सीज़न करें, 5 मिनट और पकाएं। ठंडा होने दें।. लार्ड को मिक्सर से 3 मिनट तक हल्का और सफेद होने तक फेंटें। बेकिंग पाउडर और नमक डालें, 30 सेकंड और मिलाएं।. गर्म चिकन शोरबा और मासा हरीना बारी-बारी से डालते हुए लगातार फेंटें। आटा हल्का, फूला हुआ और स्पैचुला से चिपका रहना चाहिए। एक छोटा गोला ठंडे पानी में डालें — तैरना चाहिए।. पत्तियों का पानी निकालें। हर तामाले के लिए 3 बड़े चम्मच आटे को पत्ती पर पतली परत में फैलाएं, किनारों पर 2 सेमी और ऊपर 5 सेमी छोड़ें। बीच में 2 बड़े चम्मच भरावन रखें।. पत्ती के किनारों को भरावन के ऊपर मोड़ें, फिर पतले सिरे को ऊपर मोड़ें, शीर्ष को खुला छोड़ें। तामालों को स्टीमर बास्केट में सीधा रखें, खुला सिरा ऊपर।. 60–75 मिनट तक भाप में पकाएं जब तक एक खोलकर देखने पर आटा पत्ती से साफ अलग न हो जाए। 10 मिनट विश्राम दें। गर्म लाल या हरी साल्सा के साथ परोसें।.","en":"Soak the corn husks in warm water for 30 minutes, until pliable; weight them down with a plate so they stay submerged. Make the sauce: toast the guajillo and ancho chilies in a dry pan for 1 minute per side, until fragrant; cover with hot water for 15 minutes; blend the rehydrated chilies with the onion, garlic, cumin, oregano and 250ml of the soaking liquid; strain the sauce. Heat 2 tbsp oil in a pan, pour in the chili sauce and simmer for 8–10 minutes, until thickened; add the shredded pork, season with salt and cook another 5 minutes; let it cool. Beat the lard with a mixer for 3 minutes, until fluffy and pale; add the baking powder and salt, mix 30 seconds more. Add the masa harina alternately with warm chicken stock, beating continuously; the dough should be light, fluffy, and cling to the spatula; test by dropping a small ball into cold water — it should float. Drain the corn husks; for each tamale, spread 3 tbsp of dough in a thin layer on a husk, leaving a 2 cm border on the sides and 5 cm at the top; place 2 tbsp filling down the centre. Fold the sides of the husk over the filling, then fold the narrow end up, leaving the top open; stand the tamales vertically in a steamer basket, open ends up. Steam for 60–75 minutes, until the dough peels cleanly away from the husk when you open one; let them rest 10 minutes before serving; serve warm with red or green salsa alongside."}},{"id":112,"origin":{"hi":"थाईलैंड","en":"Thailand","ro":"Thailanda"},"name":{"hi":"टॉम यम","en":"Tom Yum","ro":"Tom Yum"},"category":{"en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"thai","ingredients":{"hi":["चिकन या सीफ़ूड स्टॉक 1 लीटर","कच्चे झींगे 300 ग्राम, छिले और नस हटाए","लेमनग्रास 2 डंठल, 3 सेमी में काटे और कुचले","गैलंगल (या अदरक) 30 ग्राम, पतले कटे","काफ़िर लाइम पत्ते 6","थाई लाल मिर्च 3–4, आधे कटे","ऑयस्टर या बटन मशरूम 200 ग्राम, कटे","मछली सॉस 3 बड़े चम्मच","ताज़ा नींबू का रस 2 बड़े चम्मच","पाम चीनी 1 बड़ा चम्मच","टॉम यम पेस्ट 2 बड़े चम्मच (वैकल्पिक)","हरा प्याज़ 1 डंठल, सजावट के लिए","ताज़ा धनिया परोसने के लिए"],"en":["1L chicken or seafood stock","300g raw prawns, peeled and deveined","2 stalks lemongrass, cut into 3cm pieces and bruised","30g galangal (or ginger), thinly sliced","6 kaffir lime leaves","3–4 Thai red chillies, halved","200g oyster or button mushrooms, sliced","3 tbsp fish sauce","2 tbsp fresh lime juice","1 tbsp palm sugar","2 tbsp tom yum paste (optional)","1 spring onion stalk, to garnish","Fresh coriander to serve"],"ro":["1 L supă de pui sau stoc de fructe de mare","300g creveți cruzi, curățați","2 tulpini lemongrass, secționate în bucăți de 3 cm și zdrobite","30g galangal (sau ghimbir), felii subțiri","6 frunze de kaffir lime","3–4 ardei iuți roșii thailandezi, tăiați pe jumătate","200g ciuperci pleurotus sau champignon, feliate","3 linguri sos de pește","2 linguri suc proaspăt de lime","1 lingură zahăr de palmier","2 linguri pastă tom yum (opțional)","1 tulpină ceapă verde, pentru servire","Coriandru proaspăt, pentru servire"]},"howIsMade":{"hi":"एक बड़े बर्तन में 1 लीटर शोरबा को धीमी आंच पर उबाल लें।. कुचले लेमनग्रास, गैलंगल के स्लाइस और काफ़िर लाइम पत्ते डालें। सुगंध को शोरबे में मिलाने के लिए 10 मिनट तक धीमी आंच पर पकाएं।. टॉम यम पेस्ट (यदि उपयोग कर रहे हैं), आधे कटे मिर्च और कटे मशरूम डालें। मशरूम के थोड़ा नरम होने तक 3–4 मिनट पकाएं।. झींगे डालें और ठीक 2–3 मिनट पकाएं — वे गुलाबी हो जाएंगे और मुड़ जाएंगे। ज़्यादा न पकाएं वरना रबरी हो जाएंगे।. बर्तन को आंच से हटा दें। 3 बड़े चम्मच मछली सॉस, 2 बड़े चम्मच ताज़ा नींबू का रस और 1 बड़ा चम्मच पाम चीनी डालें।. चखें और संतुलन समायोजित करें: सूप एक साथ खट्टा, नमकीन, मसालेदार और हल्का मीठा होना चाहिए। खटास के लिए अधिक नींबू, नमक के लिए अधिक मछली सॉस।. गहरे कटोरे में तुरंत परोसें, हरी प्याज़ और ताज़ा धनिया छिड़कें। लेमनग्रास, गैलंगल और लाइम पत्ते सुगंधित सामग्री हैं और खाए नहीं जाते।.","en":"Bring 1L of stock to a gentle simmer in a large pot. Add the bruised lemongrass stalks, sliced galangal, and kaffir lime leaves; simmer for 10 minutes to infuse the aromatics and turn the broth deeply fragrant. Stir in the tom yum paste (if using), halved chillies, and sliced mushrooms; cook for 3–4 minutes, until the mushrooms soften slightly. Add the prawns and cook for exactly 2–3 minutes — they should turn pink and curl; do not overcook or they will become rubbery. Take the pot off the heat; stir in 3 tbsp fish sauce, 2 tbsp fresh lime juice, and 1 tbsp palm sugar. Taste and adjust the balance: the soup should be sour, salty, spicy, and lightly sweet all at once; add more lime for sharpness or more fish sauce for salt. Serve immediately in deep bowls, scattered with spring onion and fresh coriander; the lemongrass, galangal, and lime leaves are aromatics and are not meant to be eaten."}},{"id":113,"origin":{"hi":"अर्जेंटीना","en":"Argentina","ro":"Argentina"},"name":{"hi":"मिलानेसा","en":"Milanesa","ro":"Milanesa"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"latin","ingredients":{"hi":["4 पतले बीफ स्टीक (टॉप राउंड या सिरलोइन), लगभग 150 ग्राम प्रत्येक","2 बड़े अंडे","2 लहसुन की कलियां, बारीक कटी","20 ग्राम ताज़ा अजमोद, बारीक कटा","150 ग्राम सूखे ब्रेडक्रम्ब्स (हल्की परत के लिए पैंको)","100 ग्राम साधारण आटा","1 छोटा चम्मच नमक","1/2 छोटा चम्मच ताज़ा पिसी काली मिर्च","500 मिली वनस्पति तेल, तलने के लिए","1 नींबू, टुकड़ों में, परोसने के लिए"],"en":["4 thin beef steaks (top round or sirloin), about 150g each","2 large eggs","2 garlic cloves, finely minced","20g fresh parsley, finely chopped","150g dried breadcrumbs (panko works for a lighter crust)","100g plain flour","1 tsp salt","1/2 tsp freshly ground black pepper","500ml vegetable oil, for frying","1 lemon, cut into wedges, to serve"],"ro":["4 felii subțiri de vită (vrăbioară sau pulpă), aproximativ 150g fiecare","2 ouă mari","2 căței de usturoi, tocați fin","20g pătrunjel proaspăt, tocat","150g pesmet uscat (eventual panko pentru o crustă mai aerată)","100g făină simplă","1 linguriță sare","1/2 linguriță piper negru proaspăt măcinat","500ml ulei vegetal, pentru prăjit","1 lămâie, tăiată felii, pentru servit"]},"howIsMade":{"hi":"बीफ स्लाइस को दो प्लास्टिक रैप के बीच रखें। मीट हथौड़े से 5 मिमी मोटा होने तक पीटें। दोनों तरफ आधा नमक और काली मिर्च लगाएं।. एक चौड़े उथले कटोरे में अंडे, कटा लहसुन, अजमोद और बचा हुआ नमक-मिर्च फेंटें।. दो उथली प्लेट तैयार करें: एक में आटा, दूसरी में ब्रेडक्रम्ब्स। ब्रेडिंग क्रम: आटा → फेंटा अंडा → ब्रेडक्रम्ब्स।. हर स्लाइस को आटे में डुबाकर अतिरिक्त झाड़ें, फिर अंडे के मिश्रण में (2 सेकंड टपकने दें), फिर दोनों तरफ ब्रेडक्रम्ब्स में दबाएं। ब्रेडक्रम्ब्स को मांस को पूरी तरह ढकना चाहिए।. ब्रेडेड स्लाइसों को तार रैक पर 10 मिनट आराम दें — ब्रेडिंग बेहतर चिपकती है।. एक बड़े पैन में 1 सेमी तेल को 175°C तक गरम करें (थर्मामीटर से या ब्रेड क्यूब टेस्ट से — 30 सेकंड में सुनहरा होना चाहिए)।. एक या दो स्लाइस को प्रत्येक तरफ 2 मिनट तक तलें जब तक परत गहरी सुनहरी और मांस नरम न हो जाए। ट्रे पर तार रैक पर निकालें (कागज पर नहीं — परत नरम हो जाती है)।. खाने से ठीक पहले परत पर निचोड़ने के लिए नींबू के टुकड़ों के साथ तुरंत परोसें।.","en":"Place the beef slices between two sheets of cling film; pound with a meat mallet until 5 mm thick; season with half the salt and pepper on both sides. Beat the eggs in a wide shallow bowl with the minced garlic, parsley, and the remaining salt and pepper. Set up two shallow plates: one with the flour, one with the breadcrumbs; breading line: flour → beaten egg → breadcrumbs. Dip each slice in flour, shaking off the excess, then in the egg mixture (let it drip for 2 seconds), then press into the breadcrumbs on both sides; the crumbs should fully coat the meat. Let the breaded slices rest on a wire rack for 10 minutes — the breading adheres better this way. Heat 1 cm of oil in a large frying pan to 175°C (use a thermometer or test with a bread cube — it should brown in 30 seconds). Fry the slices one or two at a time for 2 minutes per side, until the crust is deep golden and the meat is tender; drain on a rack over a tray (not on paper — it steams the crust). Serve immediately with lemon wedges to squeeze over the crust just before eating."}},{"id":114,"origin":{"hi":"कंबोडिया","en":"Cambodia","ro":"Cambodgia"},"name":{"hi":"लोक लाक","en":"Lok Lak","ro":"Lok Lak"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","pairingsType":"vietnamese","ingredients":{"hi":["600 ग्राम बीफ टेंडरलॉइन या सिरलोइन, 2.5 सेमी क्यूब में कटा","3 बड़े चम्मच ऑयस्टर सॉस","2 बड़े चम्मच सोया सॉस","1 बड़ा चम्मच पाम चीनी (या ब्राउन शुगर)","1 बड़ा चम्मच टमाटर पेस्ट","6 लहसुन की कलियां, कटी हुई","2 छोटे चम्मच ताज़ा पिसी काली मिर्च (उदारता से)","3 बड़े चम्मच वनस्पति तेल","1 बड़ा प्याज़, पतला कटा","4 अंडे (तलने के लिए)","1 छोटा सलाद (iceberg या romaine), पत्ते अलग","2 टमाटर, कटे हुए","1 खीरा, कटा हुआ","डिप के लिए:","2 नींबू का रस","1 छोटा चम्मच मोटा नमक","1/2 छोटा चम्मच ताज़ा पिसी काली मिर्च","उबले चावल, परोसने के लिए"],"en":["600g beef tenderloin or sirloin, cut into 2.5 cm cubes","3 tbsp oyster sauce","2 tbsp soy sauce","1 tbsp palm sugar (or brown sugar)","1 tbsp tomato paste","6 garlic cloves, minced","2 tsp freshly ground black pepper (generous)","3 tbsp vegetable oil","1 large onion, thinly sliced","4 eggs (for frying)","1 small head of lettuce (iceberg or romaine), leaves separated","2 tomatoes, sliced","1 cucumber, sliced","For the dipping sauce:","juice of 2 limes","1 tsp coarse salt","1/2 tsp freshly ground black pepper","steamed rice, to serve"],"ro":["600g vrăbioară sau mușchi de vită, tăiată cuburi de 2,5 cm","3 linguri sos de stridii","2 linguri sos de soia","1 lingură zahăr de palmier (sau zahăr brun)","1 lingură pastă de roșii","6 căței de usturoi, tocați","2 lingurițe piper negru proaspăt măcinat (din belșug)","3 linguri ulei vegetal","1 ceapă mare, tăiată felii subțiri","4 ouă (pentru ochiuri)","1 cap mic de salată verde (iceberg sau romană), frunzele separate","2 roșii, feliate","1 castravete, feliat","Pentru sos:","zeama de la 2 lime","1 linguriță sare grunjoasă","1/2 linguriță piper negru proaspăt măcinat","orez fiert, pentru servit"]},"howIsMade":{"hi":"एक कटोरे में बीफ को ऑयस्टर सॉस, सोया सॉस, पाम चीनी, टमाटर पेस्ट, आधा लहसुन और 1 छोटा चम्मच काली मिर्च के साथ मिलाएं। कमरे के तापमान पर 30 मिनट तक मैरिनेट करें।. डिप तैयार करें: एक छोटे कटोरे में नींबू का रस, मोटा नमक और बची हुई काली मिर्च मिलाएं।. परोसने की प्लेट तैयार करें: बड़ी प्लेट पर सलाद के पत्ते, टमाटर के स्लाइस और खीरे के स्लाइस सजाएं।. एक पैन में थोड़ा तेल डालकर 4 अंडे को इस तरह तलें कि जर्दी बहती रहे। गर्म प्लेट पर अलग रख दें।. एक बड़े वोक में 3 बड़े चम्मच तेल बहुत तेज़ आंच पर हल्के धुएं तक गरम करें।. कटा प्याज़ और बचा हुआ लहसुन डालें, 30 सेकंड तक खुशबू आने तक भूनें।. मैरिनेट किया हुआ बीफ एक परत में डालें। 1 मिनट तक बिना छुए सीयरिंग होने दें, फिर 2 मिनट तेज़ी से चलाएं। बीफ बाहर से कुरकुरा और बीच में गुलाबी होना चाहिए — अधिक न पकाएं।. गर्म बीफ को सलाद की प्लेट पर डालें, हर हिस्से पर एक तला अंडा रखें। नींबू डिप और हर डाइनर के लिए उबले चावल के साथ तुरंत परोसें।.","en":"In a bowl, combine the beef with oyster sauce, soy sauce, palm sugar, tomato paste, half the garlic, and 1 tsp black pepper; let it marinate at room temperature for 30 minutes. Make the dipping sauce: stir lime juice, coarse salt, and the remaining pepper in a small bowl; set aside. Arrange the serving platter: lettuce leaves, tomato slices, and cucumber slices laid out on a large platter. Fry 4 eggs in a pan with a little oil, leaving the yolks runny; set them aside on a warm plate. Heat 3 tbsp oil in a large wok over very high heat until it just begins to smoke. Add the sliced onion and remaining garlic, stir-fry for 30 seconds, until fragrant. Add the marinated beef in a single layer; leave it untouched for 1 minute to sear, then stir-fry vigorously for 2 more minutes; the beef should be charred outside and pink inside — do not overcook. Spoon the hot beef over the salad platter, place a fried egg on each portion; serve immediately with the lime dipping sauce alongside and steamed rice for each diner."}},{"id":115,"origin":{"hi":"उज़्बेकिस्तान","en":"Uzbekistan","ro":"Uzbekistan"},"name":{"hi":"मंटी","en":"Manti","ro":"Manti"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"hi":["आटे के लिए:","500 ग्राम मैदा","250 मिली गुनगुना पानी","1 अंडा","1 छोटा चम्मच नमक","भरावन के लिए:","600 ग्राम मोटे कटे गोमांस या भेड़ का मांस (मशीन से नहीं)","3 बड़े प्याज़, बारीक कटे (मांस:प्याज़ अनुपात 1:1 आयतन से — आवश्यक)","1 छोटा चम्मच पिसा जीरा","1 छोटा चम्मच ताज़ा पिसी काली मिर्च","2 छोटे चम्मच नमक","100 ग्राम भेड़ की पूंछ की चर्बी या लार्ड बहुत छोटे क्यूब में (वैकल्पिक, परंपरागत)","परोसने के लिए:","100 ग्राम मक्खन","200 ग्राम पूर्ण वसा वाला दही (या खट्टी क्रीम)","1 बड़ा चम्मच मीठी पैपरिका","ताज़ा धनिया या अजमोद, कटा हुआ"],"en":["For the dough:","500g all-purpose flour","250ml warm water","1 egg","1 tsp salt","For the filling:","600g coarsely chopped beef or lamb (knife-cut, not ground)","3 large onions, finely chopped (use a 1:1 onion-to-meat ratio by volume — essential)","1 tsp ground cumin","1 tsp freshly ground black pepper","2 tsp salt","100g lamb-tail fat or pork lardons in tiny cubes (optional, traditional)","To serve:","100g butter","200g full-fat yogurt (or sour cream)","1 tbsp sweet paprika","fresh coriander or parsley leaves, chopped"],"ro":["Pentru aluat:","500g făină","250ml apă caldă","1 ou","1 linguriță sare","Pentru umplutură:","600g carne tocată grosier de vită sau miel","3 cepe mari, tăiate fin (foarte importantă proporția 1:1 cu carnea după volum)","1 linguriță chimion măcinat","1 linguriță piper negru proaspăt măcinat","2 lingurițe sare","100g grăsime de coadă de oaie sau slănină tăiată cuburi mici (opțional, dar tradițional)","Pentru servit:","100g unt","200g iaurt gras (sau smântână)","1 lingură boia dulce","frunze de coriandru sau pătrunjel proaspăt, tocate"]},"howIsMade":{"hi":"आटा तैयार करें: एक बड़े कटोरे में मैदा और नमक मिलाएं। अंडे को गुनगुने पानी के साथ फेंटें और मैदा में डालें। 10 मिनट तक चिकना और लचीला आटा बनने तक गूंधें। प्लास्टिक रैप से ढककर 30 मिनट विश्राम दें।. भरावन तैयार करें: चाकू से कटा मांस, प्याज़, जीरा, नमक, काली मिर्च और भेड़ की पूंछ की चर्बी (यदि उपयोग कर रहे हैं) मिलाएं। हाथ से एक समान होने तक मिलाएं। प्याज़ से रस निकलेगा — उसे भरावन में रहने दें।. आटे को 4 भागों में बांटें। हर भाग को जितना संभव हो उतना पतला (1–2 मिमी) बेलें। 10x10 सेमी के चौकोर काटें।. हर चौकोर के बीच में एक उदार चम्मच भरावन रखें। आटे के चारों कोनों को भरावन के ऊपर उठाकर शीर्ष पर एक साथ चिपकाएं, फिर चारों किनारों को बंद करके सीलबंद पैकेट बनाएं।. स्टीमर टोकरी पर तेल लगाएं। मंटी को एक परत में, बिना छुए, रखें (पकाने पर फूल जाते हैं)।. मध्यम आंच पर 35–40 मिनट तक भाप में पकाएं जबकि पानी लगातार उबलता रहे। आटा पारदर्शी और थोड़ा चमकदार हो जाने पर तैयार।. एक छोटे बर्तन में मक्खन पिघलाएं, मीठी पैपरिका मिलाएं। आंच से उतारकर 1 मिनट रखें।. मंटी को बड़ी थाली में सजाएं, कटे अजमोद छिड़कें, और ऊपर से पैपरिका मक्खन डालें। साथ में छोटे कटोरे में दही परोसें।.","en":"Make the dough: in a large bowl, combine the flour with salt; beat the egg with warm water and pour over the flour; knead for 10 minutes until smooth and elastic; cover with cling film and rest for 30 minutes. Make the filling: combine the knife-cut meat, onions, cumin, salt, pepper, and lamb-tail fat (if using); mix by hand until uniform; the onions will release liquid — keep it in. Divide the dough into 4 pieces; roll each as thin as possible (1–2 mm); cut into 10x10 cm squares. Place a generous tablespoon of filling in the centre of each square; lift the four corners of the dough up over the filling and pinch them together at the top, then pinch the four side edges closed to form a sealed parcel. Brush a steamer basket with oil; arrange the manti in a single layer, not touching (they will swell as they cook). Steam for 35–40 minutes over medium heat with the water at a steady boil; the dough should become translucent and slightly glossy when done. Melt the butter in a small saucepan, stir in the sweet paprika; let it rest 1 minute off the heat. Arrange the manti on a large platter, scatter with chopped parsley, and spoon the paprika butter over the top; serve with yogurt in a small bowl alongside."}},{"id":116,"origin":{"hi":"जॉर्जिया","en":"Georgia","ro":"Georgia"},"name":{"hi":"चाखोखबिली","en":"Chakhokhbili","ro":"Chakhokhbili"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"hi":["1.2 किलो हड्डी वाली चिकन थाई और ड्रमस्टिक","4 बड़े प्याज़ (लगभग 600 ग्राम), पतले कटे — परंपरागत रूप से प्याज़ और मुर्गी का वजन अनुपात 1:1","6 पके टमाटर (लगभग 700 ग्राम), छिले और मोटे कटे","1 लाल शिमला मिर्च, बीज निकालकर कटी हुई","6 लहसुन की कलियां, कटी हुई","2 बड़े चम्मच टमाटर पेस्ट","1 छोटा चम्मच ख्मेली-सुनेली (जॉर्जियाई मसाला मिश्रण)","1/2 छोटा चम्मच पिसी नीली मेथी (उत्सखो-सुनेली)","1 छोटा चम्मच सूखी सेवरी या मार्जोरम","30 ग्राम ताज़ा धनिया, पत्तियां और तने अलग, दोनों कटे हुए","20 ग्राम ताज़ा अजमोद, कटा हुआ","1 छोटा चम्मच नमक","ताज़ा पिसी काली मिर्च","1 बड़ा चम्मच सफेद वाइन सिरका (वैकल्पिक, ताज़गी के लिए)","जॉर्जियाई फ्लैटब्रेड या कोई देहाती रोटी, परोसने के लिए"],"en":["1.2kg bone-in chicken thighs and drumsticks","4 large onions (about 600g), thinly sliced — a 1:1 onion-to-chicken ratio by weight is traditional","6 ripe tomatoes (about 700g), peeled and roughly chopped","1 red bell pepper, deseeded and diced","6 garlic cloves, minced","2 tbsp tomato paste","1 tsp khmeli-suneli (Georgian spice blend)","1/2 tsp ground blue fenugreek (utskho suneli)","1 tsp dried savory or marjoram","30g fresh coriander, leaves and stems separated, both chopped","20g fresh parsley, chopped","1 tsp salt","freshly ground black pepper","1 tbsp white wine vinegar (optional, for brightness)","Georgian flatbread or any sturdy bread, to serve"],"ro":["1,2kg pulpe de pui cu os (pulpe superioare și ciocănele)","4 cepe mari (aproximativ 600g), feliate subțire — raportul 1:1 ceapă:pui după greutate este tradițional","6 roșii coapte (aproximativ 700g), decojite și tăiate grosier","1 ardei kapia roșu, fără semințe, tăiat cuburi","6 căței de usturoi, tocați","2 linguri pastă de roșii","1 linguriță khmeli-suneli (amestec de condimente georgian)","1/2 linguriță schinduf albastru măcinat (utskho suneli)","1 linguriță cimbru de iarnă uscat (sau maghiran)","30g coriandru proaspăt, frunze și tulpini separate, ambele tocate","20g pătrunjel proaspăt, tocat","1 linguriță sare","piper negru proaspăt măcinat","1 lingură oțet de vin alb (opțional, pentru prospețime)","pâine georgiană sau alt tip de pâine rustică, pentru servit"]},"howIsMade":{"hi":"एक भारी बर्तन को मध्यम-तेज़ आंच पर बिना तेल के सूखा गरम करें। चिकन के टुकड़ों को त्वचा वाली ओर नीचे रखकर हर तरफ 6–8 मिनट तक गहरा सुनहरा होने तक भूनें। चिकन अपनी चर्बी छोड़ता है — यही चाखोखबिली को परिभाषित करने वाला सूखा भूनने का चरण है।. चिकन को एक प्लेट में निकाल लें। बर्तन में 3–4 बड़े चम्मच चर्बी रहनी चाहिए — उसे रखें।. कटी हुई प्याज़ को इस चर्बी में डालें। मध्यम आंच पर 12–15 मिनट, बार-बार चलाते हुए, गहरी सुनहरी और नरम होने तक भूनें।. शिमला मिर्च, आधा लहसुन, कटे धनिये के तने, ख्मेली-सुनेली, नीली मेथी और सेवरी डालें। खुशबू आने तक 2 मिनट पकाएं।. टमाटर पेस्ट डालें और 2 मिनट और पकाएं जब तक रंग गहरा न हो जाए। कटे टमाटर डालें और चिकन को उसके रस के साथ बर्तन में वापस डालें।. आंच धीमी करें, ढककर 35–45 मिनट तक पकाएं, बीच में चिकन को एक बार पलटें। चिकन हड्डी से लगभग अलग होने वाला होना चाहिए और टमाटर एक गाढ़ी, चमकदार चटनी में पिघल जाएं।. ढक्कन हटाएं और यदि चटनी को और गाढ़ा करना हो तो 5 मिनट और बिना ढके पकाएं। बचा हुआ लहसुन, सिरका (यदि उपयोग कर रहे हैं) और कटे धनिये और अजमोद का बड़ा हिस्सा मिलाएं।. चखें, नमक और काली मिर्च समायोजित करें। उथले कटोरों में गर्मागर्म परोसें, साथ में जॉर्जियाई फ्लैटब्रेड (या कोई देहाती रोटी) रखें जिससे चटनी पोंछी जा सके। बची हुई जड़ी-बूटियां ऊपर से छिड़कें।.","en":"Heat a heavy dry pot over medium-high heat — no oil; lay the chicken pieces skin-side down and cook for 6–8 minutes per side, until deeply golden; the chicken renders its own fat — this is the dry-brown step that defines chakhokhbili. Lift the chicken onto a plate; the pot should hold 3–4 tbsp of rendered fat — keep it. Add the sliced onions to the rendered fat; cook over medium heat for 12–15 minutes, stirring often, until deeply golden and soft. Stir in the bell pepper, half the garlic, the chopped coriander stems, khmeli-suneli, blue fenugreek, and savory; cook 2 minutes, until fragrant. Add the tomato paste and cook 2 more minutes, until it darkens; add the chopped tomatoes and return the chicken with its juices to the pot. Reduce the heat to low, cover, and braise for 35–45 minutes, turning the chicken once halfway; the chicken should be falling off the bone and the tomatoes broken down into a thick, glossy sauce. Lift the lid and simmer uncovered 5 more minutes to thicken the sauce if needed; stir in the remaining garlic, the vinegar (if using), and most of the chopped coriander leaves and parsley. Taste, adjust salt and pepper; serve hot in shallow bowls with Georgian flatbread (or any sturdy bread) to mop up the sauce; scatter the remaining herbs on top."}},{"id":117,"origin":{"hi":"पेरू","en":"Peru","ro":"Peru"},"name":{"hi":"लोमो सालताडो","en":"Lomo Saltado","ro":"Lomo Saltado"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"latin","ingredients":{"hi":["600 ग्राम बीफ सिरलोइन या टेंडरलॉइन, 1 सेमी मोटी पट्टियों में कटा","3 बड़े आलू (लगभग 700 ग्राम), मोटे फ्राइज़ में कटे","1 बड़ा लाल प्याज़, 1 सेमी मोटे टुकड़ों में","2 मध्यम रोमा टमाटर, टुकड़ों में (या मोटे स्लाइस)","1 पीली आहि अमारियो मिर्च (या 1 लाल शिमला मिर्च + 1 छोटा चम्मच आहि अमारियो पेस्ट)","4 लहसुन की कलियां, कटी हुई","2 बड़े चम्मच ताज़ा अदरक, कद्दूकस की हुई","3 बड़े चम्मच सोया सॉस","2 बड़े चम्मच रेड वाइन सिरका","30 ग्राम ताज़ा धनिया, मोटे कटे","3 बड़े चम्मच वनस्पति तेल (आलू तलने के लिए 500 मिली अतिरिक्त)","1 छोटा चम्मच नमक","1/2 छोटा चम्मच ताज़ा पिसी काली मिर्च","400 ग्राम सफेद बासमती चावल, पका हुआ","1 नींबू, टुकड़ों में (वैकल्पिक)"],"en":["600g beef sirloin or tenderloin, cut into 1 cm strips","3 large potatoes (about 700g), cut into thick fries","1 large red onion, cut into 1 cm-thick wedges","2 medium Roma tomatoes, cut into wedges (or thick slices)","1 yellow ají amarillo pepper (or 1 red bell pepper + 1 tsp ají amarillo paste)","4 garlic cloves, minced","2 tbsp fresh ginger, grated","3 tbsp soy sauce","2 tbsp red wine vinegar","30g fresh coriander, roughly chopped","3 tbsp vegetable oil (plus 500ml for frying potatoes)","1 tsp salt","1/2 tsp freshly ground black pepper","400g white basmati rice, cooked","1 lime, cut into wedges (optional)"],"ro":["600g vrăbioară sau mușchi de vită, tăiată fâșii de 1 cm grosime","3 cartofi mari (aproximativ 700g), tăiați cartofi prăjiți groși","1 ceapă roșie mare, feliată în pene groase de 1 cm","2 roșii Roma medii, tăiate sferturi (sau felii groase)","1 ardei aji amarillo galben (sau 1 ardei kapia + 1 linguriță pastă aji amarillo)","4 căței de usturoi, tocați","2 linguri ghimbir proaspăt, ras","3 linguri sos de soia","2 linguri oțet de vin roșu","30g coriandru proaspăt, tocat grosier","3 linguri ulei vegetal (plus 500ml pentru cartofi)","1 linguriță sare","1/2 linguriță piper negru proaspăt măcinat","400g orez basmati alb, gătit","1 lime, tăiat felii (opțional)"]},"howIsMade":{"hi":"बीफ की पट्टियों को नमक और काली मिर्च से सीज़न करें। कमरे के तापमान पर 10 मिनट विश्राम दें — तेज़ आंच पर बेहतर सीयरिंग होगी।. एक गहरे पैन में 500 मिली तेल को 175°C तक गरम करें। आलू को 6–7 मिनट तक सुनहरा कुरकुरा होने तक तलें। तार रैक पर निकालकर तेल छानें और गर्म होने पर हल्का नमक छिड़कें।. एक बड़े वोक या लोहे की कड़ाही को बहुत तेज़ आंच पर 2 बड़े चम्मच वनस्पति तेल के साथ गरम करें — तेल हल्के से धुआं उठने लगे। यह सबसे महत्वपूर्ण कदम है: पेरूवियन \"wok hei\" प्रभाव के लिए पैन बहुत गरम होना चाहिए।. बीफ को एक परत में डालें। 30 सेकंड बिना छुए सीयरिंग होने दें, फिर 90 सेकंड तेज़ी से चलाएं — बीफ बाहर से ब्राउन और बीच में गुलाबी होना चाहिए। प्लेट में निकालें।. उसी वोक में 1 और बड़ा चम्मच तेल डालें। प्याज़ के टुकड़े और आहि अमारियो को 90 सेकंड तक भूनें — प्याज़ कुरकुरा रहना चाहिए, नर्म नहीं।. लहसुन और अदरक डालें, 30 सेकंड तक खुशबू आने तक भूनें। टमाटर डालें और 1 मिनट पकाएं — थोड़े नर्म हों पर टूटें नहीं।. पैन के किनारे पर सोया सॉस और रेड वाइन सिरका डालें (ये भाप बनकर सुगंधित धुआं देंगे)। बीफ को रस सहित और तले आलू वापस डालें। 30 सेकंड तेज़ी से चलाएं जब तक सब कुछ कोट न हो जाए।. आंच बंद करें, कटा धनिया छिड़कें और एक बार मिलाएं। गर्म बासमती चावल पर तुरंत परोसें, साथ में नींबू के टुकड़े रखें।.","en":"Season the beef strips with salt and pepper; let them rest for 10 minutes at room temperature — they will sear better at high heat. Heat 500ml of oil in a deep pan to 175°C; fry the potatoes for 6–7 minutes until golden and crisp; drain on a rack and salt lightly while hot. Heat a large wok or cast-iron pan over very high heat with 2 tbsp of vegetable oil — the oil should just begin to smoke; this is the critical step: the pan must be very hot for the Peruvian \"wok hei\" effect. Add the beef in a single layer; leave untouched for 30 seconds to sear, then stir-fry vigorously for 90 seconds — the beef should be browned outside but still pink in the centre; lift onto a plate. In the same wok, add 1 tbsp more oil; stir-fry the onion wedges and ají amarillo for 90 seconds — the onion should stay crisp, not soft. Add the garlic and ginger, stir-fry for 30 seconds until fragrant; add the tomatoes and cook for 1 minute — they should soften slightly but not break down. Pour the soy sauce and red wine vinegar around the edge of the pan (they will steam and create aromatic smoke); return the beef with its juices and add the fries; toss vigorously for 30 seconds, until everything is coated. Turn off the heat, scatter the chopped coriander, and toss once; serve immediately over warm basmati rice with lime wedges on the side."}},{"id":118,"origin":{"hi":"मोरक्को","en":"Morocco","ro":"Maroc"},"name":{"hi":"चिकन तजीन","en":"Chicken Tagine","ro":"Chicken Tagine"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"middle-eastern","ingredients":{"hi":["1.2 किग्रा हड्डी और छिलके सहित चिकन थाई (लगभग 8 टुकड़े), अतिरिक्त छिलका हटाया हुआ","2 बड़े पीले प्याज़ (~400 ग्राम), एक मैरिनेड के लिए बारीक कद्दूकस किया, एक स्ट्यू बेस के लिए पतले स्लाइस","6 लहसुन की कलियाँ, बारीक कटी","4 सेमी ताज़ा अदरक, बारीक कद्दूकस की","1 छोटा चम्मच जीरा + 1 छोटा चम्मच सोंठ + 1 छोटा चम्मच धनिया पाउडर + 1/2 छोटा चम्मच हल्दी + 1/2 छोटा चम्मच मीठी पैप्रिका + 1/2 छोटा चम्मच सफ़ेद मिर्च + एक उदार चुटकी केसर के धागे (8-10 धागे, 2 बड़े चम्मच गर्म पानी में भिगोए)","ताज़ा हरा धनिया का छोटा गुच्छा ~25 ग्राम, बारीक कटा (आधा मैरिनेड में, आधा सजावट में)","चौड़ी पत्ती वाला अजमोद का छोटा गुच्छा ~25 ग्राम, बारीक कटा (आधा मैरिनेड में, आधा सजावट में)","1.5 छोटा चम्मच नमक + 1/2 छोटा चम्मच ताज़ी पिसी काली मिर्च","3 बड़े चम्मच जैतून का तेल + 1 बड़ा चम्मच अनसाल्टेड मक्खन (या सबसे पारंपरिक स्वाद के लिए smen)","2 अचारी नींबू, धोए हुए, गूदा निकालकर छिलका पतली पट्टियों में काटा (कुल लगभग 80 ग्राम छिलका)","150 ग्राम हरे मोरक्कन जैतून (या Castelvetrano), धोए हुए, बड़े हों तो बीज निकाल दें","400 मिली गर्म पानी या कम-नमक चिकन शोरबा","आधे ताज़े नींबू का रस (अंत में डालें, ताज़गी के लिए)","परोसने के लिए: रसे को सोखने के लिए गर्म मोरक्कन फ्लैटब्रेड khobz, या भाप में पका कूसकूस"],"en":["1.2 kg bone-in skin-on chicken thighs (about 8 pieces), trimmed of excess skin","2 large yellow onions (~400 g), one finely grated for the marinade, one thinly sliced for the stew base","6 garlic cloves, minced","4 cm fresh ginger, finely grated","1 tsp ground cumin + 1 tsp ground ginger + 1 tsp ground coriander + 0.5 tsp ground turmeric + 0.5 tsp sweet paprika + 0.5 tsp ground white pepper + a generous pinch of saffron threads (8-10 strands, bloomed in 2 tbsp hot water)","1 small bunch fresh coriander (cilantro), about 25 g, finely chopped (half for the marinade, half for garnish)","1 small bunch flat-leaf parsley, about 25 g, finely chopped (half for the marinade, half for garnish)","1.5 tsp salt + 0.5 tsp freshly ground black pepper","3 tbsp olive oil + 1 tbsp unsalted butter (or smen for the most traditional flavour)","2 preserved lemons, rinsed, flesh discarded, peel cut into thin strips (about 80 g of peel total)","150 g green Moroccan olives (or Castelvetrano), rinsed, pitted if large","400 ml hot water or low-salt chicken stock","Juice of half a fresh lemon (added at the end, to brighten)","To serve: warm khobz flatbread to mop up the sauce, or steamed couscous"],"ro":["1.2 kg pulpe de pui cu os și piele (aproximativ 8 bucăți), curățate de pielea în exces","2 cepe galbene mari (~400 g), una rasă fin pentru marinadă, una tăiată felii subțiri pentru baza tocăniței","6 căței de usturoi, tocați","4 cm ghimbir proaspăt, ras fin","1 linguriță chimion măcinat + 1 linguriță ghimbir măcinat + 1 linguriță coriandru măcinat + 0.5 linguriță turmeric + 0.5 linguriță boia dulce + 0.5 linguriță piper alb măcinat + un vârf generos de șofran (8-10 fire, înflorite în 2 linguri apă fierbinte)","1 legătură mică de coriandru proaspăt (cilantro), ~25 g, tocat fin (jumătate pentru marinadă, jumătate pentru garnitură)","1 legătură mică de pătrunjel cu frunza lată, ~25 g, tocat fin (jumătate pentru marinadă, jumătate pentru garnitură)","1.5 linguriță sare + 0.5 linguriță piper negru proaspăt măcinat","3 linguri ulei de măsline + 1 lingură unt nesărat (sau smen pentru aroma cea mai tradițională)","2 lămâi conservate, clătite, pulpa îndepărtată, coaja tăiată fâșii subțiri (aproximativ 80 g de coajă)","150 g măsline verzi marocane (sau Castelvetrano), clătite, fără sâmburi dacă sunt mari","400 ml apă fierbinte sau supă de pui cu puțină sare","Zeama de la jumătate de lămâie proaspătă (adăugată la final, pentru prospețime)","Pentru servit: pâine plată khobz caldă pentru a culege sosul, sau couscous aburit"]},"howIsMade":{"hi":"चिकन को मैरिनेट करें: एक बड़े बर्तन में कद्दूकस की प्याज़, लहसुन, अदरक, सभी सूखे मसाले, भिगोया हुआ केसर अपने पानी सहित, आधा कटा हरा धनिया, आधा अजमोद, 1.5 छोटा चम्मच नमक, 1/2 छोटा चम्मच काली मिर्च और 1.5 बड़े चम्मच जैतून का तेल मिलाएं। चिकन थाई डालकर मैरिनेड को छिलके के नीचे और ऊपर अच्छी तरह मसाज करें। ढककर कम से कम 1 घंटे फ्रिज में रखें; 4 घंटे काफ़ी बेहतर, रात भर सबसे अच्छा।\n\nभूनें और बेस तैयार करें: तजिन या मोटे तले वाले बर्तन में बाकी 1.5 बड़े चम्मच तेल और मक्खन को मध्यम आंच पर गरम करें। कटी प्याज़ डालकर 8 मिनट तक चलाते हुए नरम और हल्की सुनहरी होने तक भूनें। प्याज़ को एक ओर खिसकाएं, चिकन को छिलके वाली ओर नीचे रखें और 3-4 मिनट तक छिलका गहरा सुनहरा होने तक भूनें, फिर पलटें।\n\nधीमी आंच पर पकाएं: बर्तन में बची हर बूंद मैरिनेड को कड़ाही में डालें। 400 मिली गर्म पानी या शोरबा डालें। हल्का उबाल आने पर ढक्कन लगाकर आंच एकदम धीमी कर दें। 30 मिनट पकाएं — शंक्वाकार ढक्कन भाप को रोके रखता है जो तजिन की पहचान है।\n\nअचारी नींबू और जैतून डालें: ढक्कन हटाएं, अचारी नींबू के छिलके की पट्टियाँ और हरे जैतून चिकन के चारों ओर (ऊपर नहीं) रखें — दोनों नमकीन पानी छोड़ते हैं, इसलिए ज़ोर से न हिलाएं। फिर से ढककर 10-15 मिनट और पकाएं, जब तक चिकन के सबसे मोटे हिस्से में 75 °C न हो और सॉस चमकदार, हल्की गाढ़ी होकर चम्मच की पीठ पर कोट हो जाए।\n\nखत्म करें और परोसें: ढक्कन हटाएं, आधे ताज़े नींबू का रस ऊपर निचोड़ें और बचा धनिया और अजमोद छिड़कें। नमक डालने से पहले चखें — अचारी नींबू और जैतून दोनों नमक देते हैं। सीधे तजिन से ही, सॉस सोखने के लिए गर्म मोरक्कन khobz फ्लैटब्रेड के साथ, या भाप में पकाए कूसकूस के साथ परोसें।","en":"MARINATE THE CHICKEN: in a large bowl combine the grated onion, garlic, ginger, all the dry spices, the bloomed saffron with its water, half the chopped coriander, half the parsley, 1.5 tsp salt, 0.5 tsp black pepper and 1.5 tbsp olive oil. Add the chicken thighs and massage the marinade thoroughly into and under the skin. Cover and refrigerate at least 1 hour; 4 hours is markedly better, overnight is best.\n\nSEAR AND BUILD THE BASE: heat the remaining 1.5 tbsp olive oil and the butter in a tagine vessel or wide heavy-bottomed pot over medium heat. Add the sliced onion and cook 8 minutes, stirring, until soft and lightly golden. Push the onions to one side, lay the marinated chicken skin-side down and sear 3-4 minutes until the skin is deep golden, then flip.\n\nSIMMER: scrape every drop of marinade from the bowl into the pot. Pour in the 400 ml hot water or stock. Bring to a gentle simmer, then cover and reduce the heat to its lowest setting. Cook 30 minutes — the conical lid traps the steam that defines a tagine.\n\nADD PRESERVED LEMON AND OLIVES: lift the lid, tuck the preserved-lemon strips and green olives around (not on top of) the chicken — both release brine, so resist the urge to stir vigorously. Re-cover and cook 10-15 minutes more, until the chicken reads 75 °C / 170 °F at the thickest part and the sauce has reduced to a glossy, brothy consistency that coats the back of a spoon.\n\nFINISH AND SERVE: uncover, squeeze the half-lemon juice over the dish, and scatter the reserved coriander and parsley on top. Taste before salting — preserved lemons and olives both contribute salt, so the dish often needs nothing more. Serve straight from the tagine with warm khobz flatbread to mop up the sauce, or alongside steamed couscous."}},{"id":120,"origin":{"hi":"वेनेज़ुएला","en":"Venezuela","ro":"Venezuela"},"name":{"hi":"अरेपा","en":"Arepa","ro":"Arepa"},"category":{"hi":"नाश्ता","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"veg","pairingsType":"latin","ingredients":{"hi":["आटे के लिए:","400 ग्राम harina P.A.N. (पूर्व-पकाया सफेद मक्के का आटा)","500 मिली गुनगुना पानी","1 छोटा चम्मच नमक","2 बड़े चम्मच वनस्पति तेल","रेइना पेपियादा (क्लासिक चिकन-एवोकाडो भरावन) के लिए:","2 चिकन ब्रेस्ट (लगभग 500 ग्राम), उबाले और कतरे हुए","1 पका एवोकाडो, क्यूब में कटा","3 बड़े चम्मच मेयोनेज़","1 बड़ा चम्मच नींबू का रस","1 हरी प्याज़, बारीक कटी","10 ग्राम ताज़ा धनिया, कटा","नमक और काली मिर्च","अन्य लोकप्रिय भरावन:","200 ग्राम ताज़ा सफेद चीज़ (queso fresco), स्लाइस","100 ग्राम कतरा बीफ (carne mechada)","तवे के लिए वनस्पति तेल"],"en":["For the dough:","400g harina P.A.N. (pre-cooked white corn flour)","500ml warm water","1 tsp salt","2 tbsp vegetable oil","For reina pepiada (classic chicken-avocado filling):","2 chicken breasts (about 500g), poached and shredded","1 ripe avocado, diced","3 tbsp mayonnaise","1 tbsp lime juice","1 spring onion, finely sliced","10g fresh coriander, chopped","salt and pepper","Other popular fillings:","200g fresh white cheese (queso fresco), sliced","100g shredded beef (carne mechada)","vegetable oil for griddle"],"ro":["Pentru aluat:","400g harina P.A.N. (făină de porumb pre-fiartă)","500ml apă caldă","1 linguriță sare","2 linguri ulei vegetal","Pentru reina pepiada (umplutura clasică):","2 piepți de pui (aproximativ 500g), fierți și mărunțiți","1 avocado copt, tăiat cuburi","3 linguri maioneză","1 lingură zeamă de lime","1 ceapă verde, tăiată fin","10g coriandru proaspăt, tocat","sare și piper","Alte umpluturi populare:","200g brânză albă proaspătă (queso fresco), feliată","100g carne de vită mărunțită (carne mechada)","ulei vegetal pentru prăjit pe plită"]},"howIsMade":{"hi":"एक बड़े कटोरे में 500 मिली गुनगुना पानी, नमक और तेल मिलाएं। 400 ग्राम harina P.A.N; धीरे-धीरे डालकर हाथ या स्पैचुला से मिलाएं।. 3–4 मिनट तक चिकना और लचीला आटा बनने तक गूंधें। कपड़े से ढककर 5 मिनट विश्राम दें — आटा पानी सोखकर आकार देने में आसान हो जाता है।. आटा परीक्षण करें: हल्का चिपचिपा हो पर कच्चा नहीं। आकार देते समय फटे तो 1 बड़ा चम्मच और पानी डालें।. 8 बराबर गेंदों में बांटें (प्रत्येक लगभग 100 ग्राम)। हर एक को हथेलियों के बीच 8 सेमी चौड़ा और 1.5 सेमी मोटा डिस्क बनाएं, गीली उंगलियों से किनारे चिकने करें।. भारी पैन या ग्रिडल को मध्यम आंच पर थोड़े तेल के साथ गरम करें। अरेपा डालकर हर तरफ 4–5 मिनट तक भूनें जब तक गहरे धब्बों वाली सुनहरी परत न बने।. बेकिंग ट्रे पर रखकर 180°C पर पहले से गरम ओवन में 10–15 मिनट तक पकाएं जब तक हल्के थपथपाने पर खोखला आवाज न आए। यही पकने की परीक्षा है।. अरेपा के विश्राम के दौरान reina pepiada तैयार करें: कतरा हुआ चिकन, एवोकाडो, मेयोनेज़, नींबू का रस, हरी प्याज़, धनिया, नमक और काली मिर्च मिलाएं।. तेज़ चाकू से हर अरेपा को क्षैतिज रूप से (पीता पॉकेट की तरह) काटें, पूरी तरह अलग न करें। reina pepiada (या चुना भरावन) से भरें। अरेपा गर्म और बाहर से कुरकुरी हो तब तुरंत परोसें।.","en":"In a large bowl, combine 500ml warm water with salt and oil; gradually add 400g harina P.A.N., mixing with your hand or a spatula. Knead for 3–4 minutes until the dough is smooth and pliable; cover with a cloth and let it rest for 5 minutes — the flour absorbs the water and the dough becomes easier to shape. Test the dough: it should be slightly sticky but not raw; if it cracks while shaping, add a tablespoon more water. Divide into 8 equal balls (about 100g each); flatten each between your palms into a 8 cm wide, 1.5 cm thick disc, smoothing the edges with damp fingers. Heat a heavy pan or griddle over medium heat with a little oil; add the arepas and cook for 4–5 minutes per side, until a golden crust with darker spots forms. Transfer to a baking tray and finish in a preheated 180°C oven for 10–15 minutes, until they sound hollow when tapped lightly; this is the doneness test. While the arepas rest, make the reina pepiada: mix the shredded chicken with avocado, mayonnaise, lime juice, spring onion, coriander, salt, and pepper. Slice each arepa horizontally with a sharp knife (like a pita pocket), without cutting all the way through; stuff with reina pepiada (or your chosen filling); serve immediately while the arepa is warm and crisp on the outside."}},{"id":121,"origin":{"hi":"फ़िनलैंड","en":"Finland","ro":"Finlanda"},"name":{"hi":"करेलियन पाई","en":"Karelian Pie","ro":"Karjalanpiirakka"},"category":{"hi":"नाश्ता","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"hi":["आटे के लिए:","150 ग्राम राई का आटा","100 ग्राम सादा सफेद आटा","150 मिली ठंडा पानी","1/2 छोटा चम्मच नमक","1 बड़ा चम्मच वनस्पति तेल","चावल खिचड़ी भरावन के लिए:","200 ग्राम छोटे दाने वाला चावल (पुडिंग चावल)","1 लीटर पूर्ण वसा वाला दूध","1/2 छोटा चम्मच नमक","20 ग्राम मक्खन","मूना वोई (अंडे का मक्खन, क्लासिक टॉपिंग) के लिए:","100 ग्राम नरम बिना नमक का मक्खन","2 उबले अंडे, छिले और बारीक कटे","1/4 छोटा चम्मच नमक","1/4 छोटा चम्मच सफेद मिर्च"],"en":["For the dough:","150g rye flour","100g plain white flour","150ml cold water","1/2 tsp salt","1 tbsp vegetable oil","For the rice porridge filling:","200g short-grain rice (pudding rice)","1 litre whole milk","1/2 tsp salt","20g butter","For muna voi (egg butter, classic topping):","100g soft unsalted butter","2 hard-boiled eggs, peeled and finely chopped","1/4 tsp salt","1/4 tsp white pepper"],"ro":["Pentru aluat:","150g făină de secară","100g făină albă","150ml apă rece","1/2 linguriță sare","1 lingură ulei vegetal","Pentru umplutura de orez:","200g orez cu bob rotund (orez pudding)","1 litru lapte integral","1/2 linguriță sare","20g unt","Pentru muna voi (untul de ouă pentru servire):","100g unt moale","2 ouă fierte tari, decojite și tocate fin","1/4 linguriță sare","1/4 linguriță piper alb"]},"howIsMade":{"hi":"चावल खिचड़ी तैयार करें (एक दिन पहले बनाई जा सकती है): एक बर्तन में 200 ग्राम चावल और 250 मिली गर्म पानी मिलाएं। मध्यम आंच पर 8 मिनट तक पानी सोखने तक पकाएं।. 1 लीटर दूध और 1/2 छोटा चम्मच नमक डालें। धीमी आंच पर बार-बार चलाते हुए 35–45 मिनट तक खिचड़ी बहुत क्रीमी और गाढ़ी होने तक पकाएं। 20 ग्राम मक्खन मिलाएं और पूरी तरह ठंडा करें।. आटे के लिए: कटोरे में राई का आटा, सफेद आटा और नमक मिलाएं। ठंडा पानी और तेल डालें, 5 मिनट तक मजबूत पर लचीला आटा गूंधें।. आटे को 16 बराबर टुकड़ों में बांटकर गेंदें बनाएं। राई का आटा बिखरी सतह पर हर गेंद को बहुत पतले अंडाकार में बेलें (1 मिमी मोटी, 12 सेमी लंबी)।. हर अंडाकार के बीच में 1–2 बड़े चम्मच ठंडी खिचड़ी रखें, 2 सेमी किनारा छोड़ें।. आटे को दोनों लंबे किनारों से भरावन के ऊपर उठाएं, बीच खुला छोड़ें। उंगलियों से आटा दबाकर विशिष्ट ज़िगज़ैग सिलवटें बनाएं — यह पारंपरिक करेलियन मुहर है।. पाई को बेकिंग पेपर बिछी ट्रे पर रखें। पहले से 250°C तक गरम ओवन में 15–20 मिनट तक किनारे सुनहरे होने तक बेक करें।. बेक होते समय मूना वोई तैयार करें: नरम मक्खन को कटे अंडे, नमक और सफेद मिर्च के साथ मसलकर मिलाएं। पाई को गुनगुना, खुले चावल वाली सतह पर मूना वोई उदारता से लगाकर परोसें।.","en":"Make the rice porridge (can be made a day ahead): combine 200g rice with 250ml hot water in a pot; cook 8 minutes over medium heat, until the water is absorbed. Add 1 litre milk and 1/2 tsp salt; simmer over low heat, stirring often, for 35–45 minutes, until the porridge is very creamy and thick; stir in 20g butter and cool completely. For the dough: combine rye flour, white flour, and salt in a bowl; add cold water and oil, knead for 5 minutes until firm but elastic. Divide the dough into 16 equal pieces and roll into balls; on a rye-floured surface, roll each ball into a very thin oval (1 mm thick, 12 cm long). Spoon 1–2 tbsp cold rice porridge into the centre of each oval, leaving a 2 cm border. Lift the dough over the filling on both long sides, leaving the centre exposed; pinch the dough with your fingers to create the characteristic zigzag pleats — this is the traditional Karelian seal. Arrange the pies on a lined baking tray; bake in a preheated 250°C oven for 15–20 minutes, until the edges are golden brown. While the pies bake, make muna voi: mash the soft butter with the chopped eggs, salt, and white pepper; serve the pies warm, generously spread with muna voi over the exposed rice surface."}},{"id":123,"origin":{"hi":"इटली","en":"Italy","ro":"Italia"},"name":{"hi":"पास्ता ए फाजोली","en":"Pasta e fagioli","ro":"Pasta e fagioli"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"pasta","pairingsType":"italian","ingredients":{"hi":["200 ग्राम छोटा पास्ता (ditalini, tubetti, या orecchiette)","400 ग्राम कैन में बोर्लोटी या कैनेलिनी राजमा, छाने हुए (या 200 ग्राम सूखे, रात भर भिगो कर पकाए)","1 बड़ा प्याज़, बारीक कटा","2 गाजर, बारीक क्यूब में","2 अजवाइन डंठल, बारीक क्यूब में","3 लहसुन की कलियां, कटी हुई","100 ग्राम पैंचेटा या बेकन, क्यूब में (वैकल्पिक)","400 ग्राम कैन कटे टमाटर","2 बड़े चम्मच टमाटर पेस्ट","1 तेज पत्ता","1 ताज़ा रोज़मेरी टहनी","1 ताज़ा थाइम टहनी","1.2 लीटर गर्म चिकन या सब्ज़ी का शोरबा","4 बड़े चम्मच एक्स्ट्रा वर्जिन जैतून का तेल","1 परमेज़ान छिलका टुकड़ा (वैकल्पिक, स्वाद के लिए)","स्वादानुसार नमक और ताज़ा पिसी काली मिर्च","परोसने के लिए कद्दूकस परमेज़ान और एक्स्ट्रा वर्जिन जैतून का तेल"],"en":["200g short pasta (ditalini, tubetti, or orecchiette)","400g canned borlotti or cannellini beans, drained (or 200g dried, soaked overnight and cooked)","1 large onion, finely chopped","2 carrots, finely diced","2 celery stalks, finely diced","3 garlic cloves, minced","100g pancetta or bacon, diced (optional)","400g canned chopped tomatoes","2 tbsp tomato paste","1 bay leaf","1 sprig fresh rosemary","1 sprig fresh thyme","1.2L hot chicken or vegetable stock","4 tbsp extra-virgin olive oil","1 piece Parmigiano rind (optional, for flavour)","salt and freshly ground black pepper","grated Parmigiano and extra-virgin olive oil, to serve"],"ro":["200g paste scurte (ditalini, tubetti sau orecchiette)","400g fasole borlotti sau cannellini din conservă, scurse (sau 200g fasole uscată înmuiată peste noapte și fiartă)","1 ceapă mare, tocată fin","2 morcovi, tăiați cuburi mici","2 tulpini de țelină, tăiate cuburi mici","3 căței de usturoi, tocați","100g pancetta sau bacon, tăiat cuburi (opțional)","400g roșii sfărâmate din conservă","2 linguri pastă de roșii","1 frunză de dafin","1 crenguță de rozmarin proaspăt","1 crenguță de cimbru proaspăt","1,2 litri supă de pui sau legume fierbinte","4 linguri ulei de măsline extravirgin","1 bucată coajă de Parmigiano (opțional, pentru aromă)","sare și piper negru proaspăt măcinat","Parmigiano ras și ulei de măsline extravirgin, pentru servit"]},"howIsMade":{"hi":"एक बड़े भारी तले वाले बर्तन में 3 बड़े चम्मच जैतून का तेल मध्यम आंच पर गरम करें। पैंचेटा क्यूब्स (यदि उपयोग कर रहे हैं) डालकर 5 मिनट तक भूनें जब तक भूरा हो और चर्बी निकल जाए।. प्याज़, गाजर, अजवाइन और एक चुटकी नमक डालें। 10–12 मिनट तक नरम और हल्का कैरमलाइज़्ड होने तक भूनें — यह सोफ्रिटो है, सुगंधित आधार।. लहसुन, टमाटर पेस्ट, रोज़मेरी और थाइम मिलाएं। टमाटर पेस्ट का रंग गहरा होने तक 2 मिनट पकाएं।. कटे टमाटर, तेज पत्ता और परमेज़ान छिलका (यदि उपयोग कर रहे हैं) डालें। मध्यम आंच पर 5 मिनट पकाएं।. आधे राजमा साबुत और बाकी आधे को कांटे या हैंड व्हिस्क से मसलकर डालें (पारंपरिक बनावट दोनों मांगती है)। 1.2 लीटर गर्म शोरबा डालें। उबाल लाएं।. पास्ता डालें और मध्यम आंच पर 8–10 मिनट तक बार-बार चलाते हुए अल डेंटे होने तक पकाएं। पास्ता स्टार्च छोड़ेगा जिससे तरल गाढ़ा होगा।. चखें और नमक समायोजित करें। परमेज़ान छिलका, रोज़मेरी और थाइम निकालें। सूप को 5 मिनट विश्राम दें — और गाढ़ा होकर सघन, क्रीमी स्टू बन जाएगा।. गहरे कटोरे में गर्म परोसें। उदारता से ताज़ा पिसी काली मिर्च, ढेर सारा कद्दूकस परमेज़ान और अंत में एक्स्ट्रा वर्जिन जैतून का तेल डालकर परिपूर्ण करें।.","en":"In a large heavy-bottomed pot, heat 3 tbsp olive oil over medium heat; add the diced pancetta (if using) and cook for 5 minutes, until browned and the fat has rendered. Add the onion, carrots, celery and a pinch of salt; sauté for 10–12 minutes, until soft and lightly caramelised — this is the soffritto, the aromatic foundation. Stir in the garlic, tomato paste, rosemary, and thyme; cook for 2 minutes, until the paste darkens. Add the chopped tomatoes, bay leaf, and Parmigiano rind (if using); simmer for 5 minutes over medium heat. Add half the beans whole and the other half mashed with a fork or hand whisk (the traditional texture calls for both); pour in 1.2L hot stock; bring to a boil. Add the pasta and cook for 8–10 minutes over medium heat, stirring often, until al dente; the liquid will thicken as the pasta releases starch. Taste and adjust salt; remove the Parmigiano rind, rosemary, and thyme stems; let the soup rest 5 minutes — it will thicken further into a dense, creamy stew. Serve hot in deep bowls; crown with generous fresh black pepper, a heavy drift of grated Parmigiano, and a final drizzle of extra-virgin olive oil."}},{"id":124,"origin":{"hi":"श्रीलंका","en":"Sri Lanka","ro":"Sri Lanka"},"name":{"hi":"कोट्टू","en":"Kottu","ro":"Kottu"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"indian","ingredients":{"hi":["8 गोदम्बा रोटी या पराठा (कुल लगभग 640 ग्राम), 1 सेमी चौड़ी पतली पट्टियों में काटी हुई","600 ग्राम हड्डी और चमड़ी रहित चिकन थाई, 1.5 सेमी टुकड़ों में कटी हुई","5 बड़े अंडे, चुटकी भर नमक के साथ हल्के से फेंटे हुए","2 मध्यम लाल प्याज़ (लगभग 240 ग्राम), पतले स्लाइस","1 बड़ा लीक (लगभग 200 ग्राम), छाँटा, पतले स्लाइस और धुला हुआ","2 छोटी गाजर (लगभग 140 ग्राम), जुलियेन कटी","3 ताज़ी हरी मिर्च, पतली स्लाइस (कम तीखेपन के लिए बीज निकाली हुई)","2 बड़े चम्मच ताज़ा अदरक, बारीक कद्दूकस की हुई","5 लहसुन की कलियाँ, बारीक कटी","2 छोटे चम्मच श्रीलंकन करी पाउडर","1 छोटा चम्मच पिसी हल्दी","2 छोटे चम्मच कश्मीरी मिर्च पाउडर या मीठी पैपरिका","15 ताज़ी करी पत्ते","400 मिली गरम चिकन या नारियल करी सॉस","3 बड़े चम्मच सोया सॉस","4 बड़े चम्मच नारियल या वनस्पति तेल","1.5 छोटे चम्मच नमक, स्वादानुसार और","2 बड़े चम्मच नींबू (लाइम) का रस, अंत में डालने के लिए"],"en":["8 godhamba roti or paratha (about 640 g total), thinly sliced into 1 cm-wide strips","600 g boneless, skinless chicken thigh, cut into 1.5 cm pieces","5 large eggs, lightly beaten with a pinch of salt","2 medium red onions (about 240 g), thinly sliced","1 large leek (about 200 g), trimmed, thinly sliced, and washed","2 small carrots (about 140 g), julienned","3 fresh green chillies, finely sliced (seeded for a milder finish)","2 tbsp finely grated fresh ginger","5 garlic cloves, finely chopped","2 tsp Sri Lankan curry powder","1 tsp ground turmeric","2 tsp Kashmiri chilli powder or sweet paprika","15 fresh curry leaves","400 ml warm chicken or coconut curry sauce","3 tbsp soy sauce","4 tbsp coconut or vegetable oil","1.5 tsp salt, plus more to taste","2 tbsp lime juice, to finish"],"ro":["8 lipii godhamba sau paratha (aproximativ 640 g în total), tăiate în fâșii subțiri de 1 cm lățime","600 g pulpă de pui dezosată, fără piele, tăiată în bucăți de 1,5 cm","5 ouă mari, bătute ușor cu un praf de sare","2 cepe roșii medii (aproximativ 240 g), feliate subțire","1 praz mare (aproximativ 200 g), curățat, feliat subțire și spălat","2 morcovi mici (aproximativ 140 g), tăiați julienne","3 ardei iuți verzi proaspeți, feliați subțire (fără semințe pentru un gust mai blând)","2 linguri ghimbir proaspăt, ras fin","5 căței de usturoi, tocați fin","2 lingurițe pudră de curry srilankez","1 linguriță turmeric măcinat","2 lingurițe pudră de ardei iute Kashmiri sau boia dulce","15 frunze de curry proaspete","400 ml sos de curry de pui sau de cocos, cald","3 linguri sos de soia","4 linguri ulei de cocos sau vegetal","1,5 lingurițe sare, plus după gust","2 linguri suc de lime, pentru finisare"]},"howIsMade":{"hi":"एक बड़े स्किलेट या वोक में 1 बड़ा चम्मच तेल मध्यम-तेज़ आंच पर गरम करें। चिकन को 0.5 छोटे चम्मच नमक और चुटकी भर करी पाउडर से सीज़न करें। बीच-बीच में चलाते हुए 7–8 मिनट पकाएं, जब तक यह हल्का सुनहरा और बस पक जाए (बीच में गुलाबी न रहे)। एक प्लेट में निकाल लें।. उसी पैन में बचा हुआ 3 बड़े चम्मच तेल डालें। तेल चमकने लगे तो करी पत्ते डालें — वे 5–10 सेकंड चटकेंगे। कटे लाल प्याज़ डालें और 3–4 मिनट पकाएं, जब तक वे नर्म हो जाएं और किनारे पारदर्शी दिखें लेकिन फिर भी मज़बूत रहें।. लीक, गाजर और हरी मिर्च डालें और 2–3 मिनट चलाएं — सब्ज़ियों को कुरकुरा-नर्म रहना चाहिए, गुदा नहीं।. सब्ज़ियों को पैन के एक तरफ़ धकेल दें। खाली जगह में अदरक और लहसुन डालें और 30 सेकंड पकाएं, जब तक खुशबू आ जाए पर भूरे न पड़ें। बचा हुआ करी पाउडर, हल्दी और कश्मीरी मिर्च पाउडर मिलाएं; 20–30 सेकंड तब तक भूनें जब तक सुगंध उठे।. फेंटे हुए अंडे पैन के बीच में डालें और 60–90 सेकंड तक हल्के हाथ से चलाते रहें, जब तक सेट हो जाएं पर चमकदार बने रहें — स्पैचुला से उन्हें छोटे टुकड़ों में तोड़ लें।. चिकन को कटी रोटी के साथ पैन में वापस डालें। सब कुछ 1–2 मिनट मिलाएं ताकि रोटी पर मसालों और चिकन के रस का रंग चढ़ जाए।. पैन के किनारे पर सोया सॉस और गरम करी सॉस डालें। दो धातु के स्पैचुला (या भारी लकड़ी के चम्मच की पीठ) से मिश्रण को 3–4 मिनट तेज़ी से काटते-मिलाते रहें — ढेर में कटाई जारी रखें ताकि रोटी की पट्टियाँ छोटे-छोटे टुकड़ों में टूटें और सॉस सोख लें। मिश्रण चमकदार और एकजुट दिखना चाहिए, सूप जैसा नहीं।. चखें और ज़रूरत हो तो और नमक डालें। नींबू का रस निचोड़ें, एक बार और मिलाएं, और जब कोट्टू अभी भी भाप छोड़ रहा हो, तुरंत साथ में करी सॉस का एक करछुल और रखकर परोसें।.","en":"Heat 1 tbsp of the oil in a large skillet or wok over medium-high heat; season the chicken with 0.5 tsp of the salt and a pinch of the curry powder; cook for 7–8 minutes, stirring occasionally, until lightly golden and just cooked through (no pink in the centre); transfer to a plate. Add the remaining 3 tbsp of oil to the same pan; when shimmering, add the curry leaves — they will crackle for 5–10 seconds; add the sliced red onions and cook for 3–4 minutes until softened and translucent at the edges but still firm. Add the leek, carrots, and green chillies and stir-fry for 2–3 minutes — the vegetables should remain crisp-tender, not soft. Push the vegetables to one side of the pan; add the ginger and garlic to the open space and cook for 30 seconds, until fragrant but not browned; stir in the remaining curry powder, the turmeric, and the Kashmiri chilli powder; toast for 20–30 seconds until aromatic. Pour the beaten eggs into the centre of the pan and gently scramble for 60–90 seconds until set but still glossy — break the curd into small pieces with the spatula. Return the chicken to the pan along with the sliced roti; toss everything together for 1–2 minutes so the roti picks up colour from the spices and chicken juices. Pour the soy sauce and warm curry sauce around the edge of the pan; use two metal spatulas (or the back of a heavy wooden spoon) and chop-and-toss the mixture vigorously for 3–4 minutes — keep cutting through the pile so the roti strips break down into small irregular pieces and soak up the sauce; the mixture should look glossy and unified, not soupy. Taste and add more salt if needed; squeeze over the lime juice, toss once more, and serve immediately while the kottu still steams, with an extra ladle of curry sauce on the side."}},{"id":125,"origin":{"hi":"लातविया","en":"Latvia","ro":"Letonia"},"name":{"hi":"पिरागी","en":"Piragi","ro":"Piragi"},"category":{"hi":"नाश्ता","en":"Snack","ro":"Gustare"},"servings":8,"tipType":"meat","pairingsType":"meat","ingredients":{"hi":["500 ग्राम स्ट्रॉन्ग व्हाइट ब्रेड आटा, बेलने के लिए अतिरिक्त","250 मिली फुल-फैट दूध, 38°C तक हल्का गर्म","7 ग्राम पैकेट (2 छोटे चम्मच) इंस्टैंट ड्राई यीस्ट","50 ग्राम कास्टर शक्कर","1 छोटा चम्मच बारीक समुद्री नमक","70 ग्राम अनसाल्टेड मक्खन, पिघलाकर थोड़ा ठंडा","1 बड़ा अंडा, हल्के से फेंटा हुआ","350 ग्राम स्मोक्ड स्ट्रीकी बेकन (या स्मोक्ड स्पेक), 5 मिमी छोटे टुकड़ों में","1 बड़ा प्याज़ (लगभग 180 ग्राम), बहुत बारीक कटा","1 बड़ा चम्मच न्यूट्रल तेल (केवल अगर बेकन बहुत दुबला हो)","0.5 छोटा चम्मच ताज़ी पिसी काली मिर्च","चुटकी भर कैरावे बीज, हल्के से कुटे हुए (वैकल्पिक)","1 बड़ी अंडे की जर्दी, 1 बड़े चम्मच दूध के साथ फेंटी हुई, ग्लेज़ के लिए","फ्लेकी समुद्री नमक, छिड़कने के लिए (वैकल्पिक)"],"en":["500 g strong white bread flour, plus extra for dusting","250 ml whole milk, gently warmed to 38°C","7 g sachet (2 tsp) instant dry yeast","50 g caster sugar","1 tsp fine sea salt","70 g unsalted butter, melted and slightly cooled","1 large egg, lightly beaten","350 g smoked streaky bacon (or smoked speck), in small 5 mm dice","1 large onion (about 180 g), very finely diced","1 tbsp neutral oil (only if the bacon is very lean)","0.5 tsp freshly ground black pepper","Pinch of caraway seeds, lightly crushed (optional)","1 large egg yolk beaten with 1 tbsp milk, for glazing","Flaky sea salt, for sprinkling (optional)"],"ro":["500 g făină albă de pâine, plus pentru tăvălit","250 ml lapte integral, încălzit ușor la 38°C","1 plic de 7 g (2 lingurițe) drojdie instant uscată","50 g zahăr tos","1 linguriță sare fină de mare","70 g unt nesărat, topit și ușor răcit","1 ou mare, bătut ușor","350 g bacon afumat (sau speck afumat), tăiat cuburi mici de 5 mm","1 ceapă mare (aproximativ 180 g), tocată foarte fin","1 lingură ulei neutru (doar dacă baconul este foarte slab)","0,5 linguriță piper negru proaspăt măcinat","Un vârf de semințe de chimen, ușor zdrobite (opțional)","1 gălbenuș mare bătut cu 1 lingură de lapte, pentru glazură","Fulgi de sare de mare, pentru presărat (opțional)"]},"howIsMade":{"hi":"गुनगुने दूध को एक बड़े बाउल में डालें, ऊपर से यीस्ट और शक्कर छिड़कें और हल्के से चलाएं। 5–10 मिनट छोड़ें जब तक सतह पर झाग न आ जाए — यह पुष्टि करता है कि यीस्ट सक्रिय है।. दूध में पिघला मक्खन, फेंटा अंडा और नमक मिलाएं। आटा डालें और लकड़ी के चम्मच से तब तक चलाएं जब तक एक खुरदुरा आटा न बन जाए। हल्के आटे वाली सतह पर पलटें और 8–10 मिनट गूँधें, जब तक यह चिकना, लचीला और छूने पर हल्का चिपचिपा भर हो।. आटे को गोले का आकार दें, हल्के तेल लगे बाउल में रखें, गीले कपड़े से ढकें और गर्म जगह पर 1 घंटे से 1 घंटे 15 मिनट तक, दोगुना होने तक उठने दें।. इसी बीच भरावन तैयार करें। कटे बेकन को सूखे फ्राइंग पैन में मध्यम आंच पर 5–6 मिनट तक, बार-बार चलाते हुए पकाएं — चर्बी निकल जाए और किनारे बस रंग पकड़ें पर बेकन कुरकुरा न हो। प्याज़ (और ज़रूरत हो तो तेल) डालें और 4–5 मिनट और पकाएं, जब तक प्याज़ पारदर्शी हो जाए पर भूरा न हो। काली मिर्च और कैरावे से सीज़न करें। पूरी तरह ठंडा करें।. फूले आटे की हवा निकालें और 24 बराबर टुकड़ों में बाँटें (हर एक लगभग 35 ग्राम)। हर टुकड़े को चिकने गोले में बेलें, फिर बेलन से 4 मिमी मोटे, 8 सेमी अंडाकार आकार में बेल लें।. हर अंडाकार के एक आधे हिस्से पर 1 छोटा चम्मच ठंडी भरावन रखें, आटे को मोड़कर भरावन ढक दें और किनारों को कसकर दबाकर सील करें। सील किए सिरों को धीरे से एक-दूसरे की ओर खींचें ताकि क्लासिक अर्धचंद्राकार आकार बने, और सीवन ट्रे पर नीचे की ओर हो।. पिरागी को दो बेकिंग पेपर वाली ट्रे पर 3 सेमी की दूरी पर रखें। हल्के से ढकें और 20–25 मिनट और उठने दें, जब तक स्पष्ट रूप से फूल जाएं। इस बीच ओवन को 220°C (425°F / फैन 200°C) तक प्रीहीट करें।. ऊपर अंडे की जर्दी का ग्लेज़ ब्रश करें, चाहें तो फ्लेकी नमक छिड़कें और 12–15 मिनट बेक करें — तैयार होने पर ऊपर गहरा सुनहरा भूरा होगा, सीवन कसकर बंद रहेंगे और नीचे थपथपाने पर खोखली आवाज़ आएगी। रैक पर 5 मिनट ठंडा करें और गुनगुना परोसें।.","en":"Pour the warm milk into a large bowl, scatter the yeast and sugar over it, and stir lightly; let stand 5–10 minutes until foamy on the surface — this confirms the yeast is alive. Add the melted butter, beaten egg, and salt to the milk; pour in the flour and stir with a wooden spoon until a shaggy dough forms; tip onto a lightly floured surface and knead for 8–10 minutes, until smooth, elastic, and only slightly tacky to the touch. Shape the dough into a ball, place it in a lightly oiled bowl, cover with a damp cloth, and leave to rise in a warm spot for 1 hour to 1 hour 15 minutes, until doubled. Meanwhile, prepare the filling; cook the diced bacon in a dry frying pan over medium heat for 5–6 minutes, stirring often, until the fat has rendered and the edges just begin to colour but the bacon is not crisp; add the onion (and the oil if needed) and cook for another 4–5 minutes, until the onion is translucent but not browned; season with the pepper and caraway; cool completely. Knock back the risen dough and divide it into 24 equal pieces (about 35 g each); roll each piece into a smooth ball, then flatten with a rolling pin into an 8 cm oval, about 4 mm thick. Spoon 1 tsp of cold filling onto one half of each oval, fold the dough over to enclose, and pinch the edges firmly to seal; pull the sealed ends gently toward each other to form the classic crescent shape, with the seam facing down on the tray. Arrange the piragi on two parchment-lined trays, leaving 3 cm between them; cover lightly and let rise for another 20–25 minutes, until visibly puffy; meanwhile heat the oven to 220°C (425°F / fan 200°C). Brush the tops with the egg-yolk glaze, sprinkle with flaky salt if using, and bake for 12–15 minutes — they are ready when the tops are deep golden brown, the seams hold tight, and the bottoms sound hollow when tapped; cool on a rack for 5 minutes and serve warm."}},{"id":126,"origin":{"hi":"वियतनाम","en":"Vietnam","ro":"Vietnam"},"name":{"hi":"बान्ह ज़ेओ","en":"Banh Xeo","ro":"Bánh xèo"},"category":{"hi":"नाश्ता","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"fish","pairingsType":"vietnamese","ingredients":{"hi":["250 ग्राम चावल का आटा","30 ग्राम कॉर्नफ्लोर (कॉर्न स्टार्च)","1 छोटा चम्मच पिसी हल्दी","0.5 छोटा चम्मच बारीक समुद्री नमक, सूअर के लिए अतिरिक्त","1 छोटा चम्मच कास्टर शक्कर","400 मिली फुल-फैट नारियल का दूध","350 मिली ठंडा सोडा वाटर (या ठंडा सादा पानी)","4 हरे प्याज़, हरे हिस्से पतले कटे (लगभग 30 ग्राम)","300 ग्राम सूअर का पेट (बेली) या कंधे का मांस, 5 मिमी मोटी पट्टियों में","300 ग्राम कच्चे छिले हुए झींगे (लगभग 24 मध्यम), नस निकाली हुई","200 ग्राम ताज़े मूँग दाल के अंकुर","1 मध्यम प्याज़ (लगभग 120 ग्राम), पतले कटे","60 मिली न्यूट्रल तेल (मूँगफली या वनस्पति), तलने के लिए","1 बड़ा चम्मच फिश सॉस, नुओक चाम के लिए 3 बड़े चम्मच अतिरिक्त","3 बड़े चम्मच ताज़ा नींबू (लाइम) का रस","2 बड़े चम्मच कास्टर शक्कर (नुओक चाम के लिए)","1 लहसुन की कली बारीक कटी और 1 छोटी लाल मिर्च पतली कटी (नुओक चाम के लिए)","1 बटर लेट्यूस या रोमेन सलाद का सिर, पत्ते अलग किए हुए, साथ में ताज़े जड़ी-बूटियों का एक बड़ा गुच्छा (पुदीना, पेरिला, धनिया, थाई तुलसी) और 1 खीरा जुलियेन कटा, परोसने के लिए"],"en":["250 g rice flour","30 g cornflour (cornstarch)","1 tsp ground turmeric","0.5 tsp fine sea salt, plus more for the pork","1 tsp caster sugar","400 ml full-fat coconut milk","350 ml cold sparkling water (or cold still water)","4 spring onions, green tops finely sliced (about 30 g)","300 g pork belly or shoulder, cut into 5 mm-thick strips","300 g raw peeled prawns (about 24 medium), deveined","200 g fresh mung bean sprouts","1 medium onion (about 120 g), thinly sliced","60 ml neutral oil (peanut or vegetable), for frying","1 tbsp fish sauce, plus 3 tbsp for the nuoc cham","3 tbsp fresh lime juice","2 tbsp caster sugar (for the nuoc cham)","1 garlic clove, finely minced, and 1 small red chilli, finely sliced (for the nuoc cham)","1 head butter lettuce or romaine, leaves separated, plus a large bunch of fresh herbs (mint, perilla, coriander, Thai basil) and 1 cucumber, julienned, to serve"],"ro":["250 g făină de orez","30 g amidon de porumb","1 linguriță turmeric măcinat","0,5 linguriță sare fină de mare, plus în plus pentru carnea de porc","1 linguriță zahăr tos","400 ml lapte de cocos integral","350 ml apă minerală rece (sau apă plată rece)","4 cepe verzi, părțile verzi feliate subțire (aproximativ 30 g)","300 g piept sau pulpă de porc, tăiat fâșii de 5 mm grosime","300 g creveți cruzi decojiți (aproximativ 24 medii), curățați de venă","200 g germeni proaspeți de fasole mung","1 ceapă medie (aproximativ 120 g), feliată subțire","60 ml ulei neutru (de arahide sau vegetal), pentru prăjit","1 lingură sos de pește, plus 3 linguri pentru nuoc cham","3 linguri suc de lime proaspăt","2 linguri zahăr tos (pentru nuoc cham)","1 cățel de usturoi tocat fin și 1 ardei iute roșu mic feliat subțire (pentru nuoc cham)","1 căpățână de salată verde de unt sau romană, frunze separate, plus o legătură mare de ierburi proaspete (mentă, perilla, coriandru, busuioc thailandez) și 1 castravete tăiat julienne, pentru servit"]},"howIsMade":{"hi":"बैटर कम-से-कम 30 मिनट पहले बनाएं। एक बड़े बाउल में चावल का आटा, कॉर्नफ्लोर, हल्दी, 0.5 छोटा चम्मच नमक और 1 छोटा चम्मच शक्कर अच्छी तरह फेंट लें। नारियल का दूध और सोडा वाटर डालकर चिकना होने तक फेंटें। हरे प्याज़ के हरे हिस्से मिलाएं। ढककर फ्रिज में कम-से-कम 30 मिनट (अधिकतम 4 घंटे) रखें — आराम देने से आटा अच्छी तरह हाइड्रेट होकर अधिक कुरकुरी क्रेप बनेगी।. बैटर के आराम के दौरान नुओक चाम बनाएं। एक बाउल में 3 बड़े चम्मच फिश सॉस, 3 बड़े चम्मच नींबू का रस, 2 बड़े चम्मच शक्कर और 4 बड़े चम्मच गुनगुना पानी मिलाकर शक्कर घुलने तक चलाएं। कटी लहसुन और मिर्च डालें। एक ओर रख दें।. सूअर की पट्टियों को 1 बड़े चम्मच फिश सॉस और 0.5 छोटे चम्मच काली मिर्च के साथ मिलाएं। झींगों को धोकर थपथपा कर सुखा लें। अंकुर धोकर पानी झटक दें। सलाद, जड़ी-बूटियाँ और खीरा परोसने की प्लेट में सजाएं।. 24 सेमी नॉन-स्टिक पैन को मध्यम-तेज़ आंच पर गरम करें। 1 छोटा चम्मच तेल डालकर पूरे पैन में फैलाएं, फिर 2–3 झींगे और एक मुट्ठी सूअर की पट्टियाँ डालें। 60–90 सेकंड चलाते हुए भूनें — झींगे गुलाबी होकर मुड़ जाएं और सूअर के किनारे सुनहरे हो जाएं पर पूरी तरह से न पकें।. बैटर चलाएं, फिर लगभग 100 मिली कलछी से पैन में डालें और तुरंत पैन घुमाकर बैटर को पतली परत में बेस पर फैलाएं और किनारों पर आधी ऊँचाई तक चढ़ाएं। क्रेप के एक आधे हिस्से पर कटे प्याज़ की एक छोटी मुट्ठी छिड़कें।. ढक्कन से 60 सेकंड ढकें — भाप ऊपर पकाने में मदद करती है। ढक्कन हटाएं, किनारे पर 1 छोटा चम्मच तेल डालें और 2–3 मिनट और पकाएं — किनारे गहरे सुनहरे हो जाएं और पतले स्पैचुला से साफ-साफ निकलने लगें।. सूअर और झींगे वाले आधे हिस्से पर एक मुट्ठी अंकुर रखें। खाली आधा हिस्सा ऊपर मोड़कर अर्धचंद्र आकार दें और गर्म प्लेट पर सरकाएं। बचे हुए बैटर, झींगे, सूअर और अंकुरों के साथ दोहराएं; आपको 4–5 क्रेप मिलने चाहिए।. क्रेप जब तक ज़ोर से कुरकुरा शोर कर रही हो, तभी तुरंत परोसें। खाने का तरीका: एक टुकड़ा फाड़ें, सलाद के पत्ते में जड़ी-बूटियों और खीरे के साथ लपेटें और नुओक चाम में डुबोएं। क्रेप को मोड़ते समय स्पष्ट कुरकुरी आवाज़ आनी चाहिए — अगर नर्म हो जाए तो अगली बार पैन अधिक गरम और बैटर थोड़ा पतला डालें।.","en":"Make the batter at least 30 minutes ahead; whisk together the rice flour, cornflour, turmeric, 0.5 tsp salt, and 1 tsp sugar in a large bowl; pour in the coconut milk and sparkling water and whisk until smooth; stir in the sliced spring-onion greens; cover and rest in the fridge for at least 30 minutes (up to 4 hours) — the resting hydrates the flour for a crisper crepe. While the batter rests, mix the nuoc cham; stir 3 tbsp fish sauce, 3 tbsp lime juice, 2 tbsp sugar, and 4 tbsp warm water in a bowl until the sugar dissolves; add the minced garlic and sliced chilli; set aside. Toss the pork strips with 1 tbsp fish sauce and 0.5 tsp pepper; rinse and pat dry the prawns; wash the bean sprouts and shake dry; arrange the lettuce, herbs, and cucumber on a serving platter. Heat a 24 cm non-stick pan over medium-high heat; add 1 tsp oil, swirl to coat, then add 2–3 prawns and a handful of pork strips; stir-fry for 60–90 seconds until the prawns curl pink and the pork edges are golden but not fully cooked through. Stir the batter, then ladle about 100 ml into the pan, immediately swirling so the batter coats the base in a thin layer and reaches halfway up the sides; drop a small handful of sliced onion over one half of the crepe. Cover with a lid for 60 seconds — the steam helps cook the top; then uncover, drizzle 1 tsp oil around the edge, and cook for a further 2–3 minutes, until the edges turn deep golden and lift cleanly from the pan with a thin spatula. Pile a handful of bean sprouts onto the half topped with pork and prawns; fold the empty half over to form a half-moon, then slide onto a warmed plate; repeat with the remaining batter, prawns, pork, and bean sprouts; you should get 4–5 crepes. Serve immediately, while the crepes are still loud-crispy; to eat: tear a piece, wrap it in lettuce with herbs and cucumber, and dip into the nuoc cham; the crepe should crackle audibly as it bends — if it goes soft, the next one needs a hotter pan and a slightly thinner pour."}},{"id":127,"origin":{"hi":"पेरू","en":"Peru","ro":"Peru"},"name":{"hi":"काउसा लिमेन्या","en":"Causa Limeña","ro":"Causa Limeña"},"category":{"hi":"ऐपेटाइज़र","en":"Appetizer","ro":"Aperitiv"},"servings":4,"tipType":"fish","pairingsType":"latin","ingredients":{"hi":["1 किलो पीले पेरूवियन आलू (या Yukon Gold या अन्य वैक्सी पीले आलू), छिले और बड़े टुकड़ों में कटे","60 मिली ताज़ा नींबू (लाइम) का रस (लगभग 2 नींबू)","60 मिली न्यूट्रल तेल (सूरजमुखी या जैतून)","2 बड़े चम्मच आहि अमारियो पेस्ट (या 1 बड़ा चम्मच आहि अमारियो + 1 छोटा चम्मच कोरियाई गोचुजांग विकल्प के रूप में)","1.5 छोटे चम्मच बारीक समुद्री नमक, स्वादानुसार और","0.5 छोटा चम्मच ताज़ी पिसी सफेद मिर्च","2 × 160 ग्राम जैतून तेल में उच्च गुणवत्ता वाले टूना के डिब्बे, छाने हुए (या 320 ग्राम पका और चीरा मुर्गी का सीना)","120 ग्राम अच्छी मेयोनेज़","2 हरे प्याज़, बहुत बारीक कटे (लगभग 20 ग्राम)","1 छोटी अजवाइन की डंडी, बारीक कटी (लगभग 30 ग्राम, वैकल्पिक)","0.5 छोटा चम्मच बारीक समुद्री नमक","1 बड़ा पका एवोकैडो (लगभग 200 ग्राम), 5 मिमी मोटे स्लाइस और 1 छोटे चम्मच नींबू रस के साथ टॉस किए हुए","12 काले जैतून (botija या Kalamata), आधे काटे और बीज निकाले हुए","2 कड़े उबले अंडे, आधे या चौथाई में कटे","ताज़े धनिया या पार्सले की डंडियाँ"],"en":["1 kg yellow Peruvian potatoes (or Yukon Gold or other waxy yellow potatoes), peeled and cut into chunks","60 ml fresh lime juice (about 2 limes)","60 ml neutral oil (sunflower or olive)","2 tbsp ají amarillo paste (or 1 tbsp ají amarillo + 1 tsp Korean gochujang as substitute)","1.5 tsp fine sea salt, plus more to taste","0.5 tsp freshly ground white pepper","2 × 160 g tins of high-quality tuna in olive oil, drained (or 320 g cooked shredded chicken breast)","120 g good mayonnaise","2 spring onions, very finely sliced (about 20 g)","1 small celery stalk, finely diced (about 30 g, optional)","0.5 tsp fine sea salt","1 large ripe avocado (about 200 g), sliced 5 mm thick and tossed with 1 tsp lime juice","12 black olives (botija or kalamata), halved and pitted","2 hard-boiled eggs, halved or quartered","Sprigs of fresh coriander or parsley"],"ro":["1 kg cartofi galbeni peruvieni (sau Yukon Gold ori alți cartofi galbeni cu pastă fermă), curățați și tăiați în bucăți","60 ml suc proaspăt de lime (aproximativ 2 lime)","60 ml ulei neutru (de floarea-soarelui sau de măsline)","2 linguri pastă de ají amarillo (sau 1 lingură ají amarillo + 1 linguriță gochujang ca substitut)","1,5 lingurițe sare fină de mare, plus după gust","0,5 linguriță piper alb proaspăt măcinat","2 conserve de 160 g de ton de calitate în ulei de măsline, scurse (sau 320 g piept de pui fiert și mărunțit)","120 g maioneză bună","2 cepe verzi, feliate foarte fin (aproximativ 20 g)","1 tulpină mică de țelină, tocată fin (aproximativ 30 g, opțional)","0,5 linguriță sare fină de mare","1 avocado mare copt (aproximativ 200 g), feliat la 5 mm și amestecat cu 1 linguriță suc de lime","12 măsline negre (botija sau Kalamata), tăiate în două și fără sâmburi","2 ouă fierte tare, tăiate în jumătăți sau sferturi","Crenguțe de coriandru sau pătrunjel proaspăt"]},"howIsMade":{"hi":"आलू को अच्छी तरह नमक वाले पानी (हर लीटर के लिए लगभग 1 बड़ा चम्मच नमक) में 18–20 मिनट उबालें, जब तक चाकू बिना किसी रुकावट के अंदर जाए लेकिन आलू टूटें नहीं। पानी निथार कर रैक पर 5 मिनट भाप उड़ने दें।. गुनगुने रहते ही आलू को राइसर या बारीक छलनी से चौड़े बाउल में पास करें। आहि अमारियो पेस्ट, नींबू का रस, तेल, 1.5 छोटा चम्मच नमक और सफेद मिर्च डालें। हाथों से 2–3 मिनट हल्के से गूंथें — मैश चिकना, रेशमी और थोड़ा लचीला होना चाहिए, दबाने पर अपना आकार बनाए रखे।. चखें और ज़रूरत हो तो और नमक या नींबू डालें। ढककर कमरे के तापमान पर ठंडा होने दें, फिर 20 मिनट फ्रिज में रख कर थोड़ा सख्त करें।. भरावन तैयार करें। छाने हुए टूना (या मुर्गी) को एक बाउल में टुकड़ों में कर लें। मेयोनेज़, हरे प्याज़, अजवाइन (अगर डाल रहे हैं) और 0.5 छोटा चम्मच नमक डालें। हल्के से मिलाएं — मछली के दिखाई देने वाले टुकड़े बने रहें, पूरी प्यूरी न बनाएं। उपयोग तक फ्रिज में रखें।. 22 × 12 सेमी के लोफ टिन (या 18 सेमी गोल केक रिंग) को क्लिंग फ़िल्म से लाइन करें, ज़्यादा बाहर निकलने के लिए छोड़ें। आलू मैश का एक-तिहाई हिस्सा बेस में 1.5 सेमी की एकसमान परत में दबाएं, गीले चम्मच की पीठ से चिकना करें।. टूना या मुर्गी की भरावन का आधा हिस्सा आलू पर 1 सेमी की परत में फैलाएं, किनारे पर 5 मिमी छोड़ें। एवोकैडो स्लाइस को एक तंग ओवरलैपिंग सिंगल लेयर में सजाएं। दूसरा एक-तिहाई आलू एवोकैडो पर दबाएं, फिर बची हुई भरावन और आखिरी आलू की परत डालें।. क्लिंग फ़िल्म को ऊपर मोड़ें और हथेली या छोटे बोर्ड से मज़बूती से दबाकर टेरीन को संकुचित करें। कम-से-कम 1 घंटा (अधिकतम 6 घंटे) फ्रिज में रखें ताकि परतें सेट हो जाएं।. क्लिंग फ़िल्म से टेरीन को उठाएं, फ़िल्म हटाएं और गर्म गीले चाकू से 8 बड़े टुकड़ों में काटें (हर कट के बाद ब्लेड को धोएं)। हर टुकड़े के ऊपर आधा जैतून, उबले अंडे का एक टुकड़ा और धनिए की डंडी रखें। काटने के 2 घंटे के भीतर ठंडा परोसें।.","en":"Boil the potatoes in well-salted water (about 1 tbsp salt per litre) for 18–20 minutes, until a knife slides in with no resistance but the potatoes are not falling apart; drain and leave to steam-dry on a rack for 5 minutes. While still warm, pass the potatoes through a ricer or fine sieve into a wide bowl; add the ají amarillo paste, lime juice, oil, 1.5 tsp salt, and white pepper; knead gently with your hands for 2–3 minutes — the mash should be smooth, silky, and slightly elastic, holding its shape when pinched. Taste and adjust with more salt or lime; cover and let cool to room temperature, then chill for 20 minutes to firm slightly. Make the filling; flake the drained tuna (or shred the chicken) into a bowl; add the mayonnaise, spring onions, celery (if using), and 0.5 tsp salt; fold gently — keep visible flakes of fish rather than a smooth purée; chill until needed. Line a 22 × 12 cm loaf tin (or a round 18 cm cake ring) with cling film, leaving a generous overhang; press one-third of the potato mash into the base in an even 1.5 cm layer, using the back of a damp spoon to smooth. Spread half the tuna or chicken filling over the potato in a 1 cm layer, leaving a 5 mm border; arrange the avocado slices on top in a tight overlapping single layer; press a second third of potato over the avocado, then top with the remaining filling and a final layer of potato. Fold the cling film over the top and press firmly with the flat of your hand or a small board to compact the terrine; refrigerate for at least 1 hour (or up to 6 hours) to set the layers. Lift the terrine out using the cling film, peel back, and slice into 8 generous portions with a hot wet knife (rinse the blade between cuts); top each slice with an olive half, a wedge of hard-boiled egg, and a sprig of coriander; serve cold, within 2 hours of slicing."}},{"id":129,"origin":{"hi":"किर्गिज़स्तान","en":"Kyrgyzstan","ro":"Kârgâzstan"},"name":{"hi":"बेशबर्माक","en":"Beshbarmak","ro":"Beshbarmak"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"hi":["1.2 किलो हड्डी सहित मेमने का कंधा या गोमांस का ब्रिस्केट (या मिश्रण), 4 बड़े टुकड़ों में कटा","3 लीटर ठंडा पानी","1 बड़ा चम्मच बारीक समुद्री नमक, स्वादानुसार और","1 प्याज़, आधा कटा (शोरबे के लिए)","1 गाजर, आधी कटी (शोरबे के लिए)","2 तेजपत्ते","10 साबुत काली मिर्च के दाने","400 ग्राम साधारण मैदा, बेलने के लिए अतिरिक्त","2 बड़े अंडे","150 मिली गुनगुना पानी","1 छोटा चम्मच बारीक समुद्री नमक","2 बड़े प्याज़ (लगभग 350 ग्राम), आधे काटकर पतले अर्धचंद्राकार में कटे","0.5 छोटा चम्मच ताज़ी पिसी काली मिर्च","चुटकी भर शक्कर","ताज़ा डिल या पार्सले, मोटा कटा"],"en":["1.2 kg bone-in lamb shoulder or beef brisket (or a mix), cut into 4 large pieces","3 litres cold water","1 tbsp fine sea salt, plus more to taste","1 onion, halved (for the broth)","1 carrot, halved (for the broth)","2 bay leaves","10 whole black peppercorns","400 g plain (all-purpose) flour, plus extra for dusting","2 large eggs","150 ml warm water","1 tsp fine sea salt","2 large onions (about 350 g), halved and thinly sliced into half-moons","0.5 tsp freshly ground black pepper","Pinch of sugar","Fresh dill or parsley, roughly chopped"],"ro":["1,2 kg umăr de miel sau piept de vită cu os (sau un amestec), tăiat în 4 bucăți mari","3 litri apă rece","1 lingură sare fină de mare, plus după gust","1 ceapă, tăiată în două (pentru bulion)","1 morcov, tăiat în două (pentru bulion)","2 frunze de dafin","10 boabe de piper negru întregi","400 g făină albă obișnuită, plus pentru tăvălit","2 ouă mari","150 ml apă caldă","1 linguriță sare fină de mare","2 cepe mari (aproximativ 350 g), tăiate în două și feliate subțire în semilune","0,5 linguriță piper negru proaspăt măcinat","Un vârf de zahăr","Mărar sau pătrunjel proaspăt, tocat grosier"]},"howIsMade":{"hi":"एक बड़े स्टॉकपॉट में मांस रखें, ठंडे पानी से ढकें और मध्यम आंच पर धीरे-धीरे उबाल लाएं — धीरे गरम करने से शोरबा में अधिकतम स्वाद आता है। पहले 10 मिनट ध्यान से सतह से ग्रे झाग हटाएं जब तक सतह साफ न हो जाए।. 1 बड़ा चम्मच नमक, आधी कटी प्याज़, गाजर, तेजपत्ते और काली मिर्च के दाने डालें। आंच इतनी कम करें कि सतह बमुश्किल हिले और बिना ढके 2–2.5 घंटे पकाएं, जब तक मांस कांटे से आसानी से अलग हो और हड्डी से छूट जाए।. मांस पकते समय आटा बनाएं। एक चौड़े बाउल में मैदा और 1 छोटा चम्मच नमक मिलाएं, बीच में जगह बनाएं और अंडे व गुनगुना पानी डालें। कांटे से मिलाएं, फिर आटा वाली सतह पर 8–10 मिनट तब तक गूँधें जब तक यह सख्त, चिकना और लचीला न हो जाए। क्लिंग फ़िल्म से ढककर कमरे के तापमान पर 30 मिनट विश्राम दें।. आराम किया हुआ आटा 4 भागों में बाँटें। एक बार में एक हिस्से पर काम करें, बाकी ढके रखें, और आटा वाली सतह पर जितना संभव हो उतना पतला बेलें — लगभग 1 मिमी मोटा। मोटे तौर पर 8 × 8 सेमी वर्गों (या 10 × 5 सेमी हीरे) में काटें। आटा अच्छी तरह छिड़कें और चिपकने न दें — ट्रे पर सपाट रखें।. मांस को शोरबे से बोर्ड पर निकालें, हल्के से एल्युमिनियम फ़ॉइल से ढककर विश्राम दें। शोरबे को बारीक छलनी से छानकर साफ बर्तन में डालें और उबली सब्ज़ियाँ हटा दें। शोरबा हल्का उबलता हुआ रखें।. 500 मिली गरम शोरबा अलग छोटी कड़ाही में डालें। पतले कटे प्याज़ और चुटकी भर शक्कर डालकर 5–6 मिनट उबालें — प्याज़ पारदर्शी और बस मुलायम रहे, टूट कर बिखरे नहीं। 0.5 छोटा चम्मच काली मिर्च मिलाएं।. छाने हुए शोरबे को फिर तेज़ी से उबालें। आटे के टुकड़ों को थोड़े-थोड़े करके डालें, चिपकने से बचाने के लिए हल्के से चलाएं, और हर बैच को 3–4 मिनट तब तक पकाएं जब तक तैरने लगें और दाँत में मीठा कुरकुरापन रहे। छन्नी कलछी से गरम सर्विंग प्लेट पर निकालें।. मांस को रेशे के विपरीत मोटी फाँकों में काटें और नूडल्स के ऊपर सजाएं। प्याज़ और उसका शोरबा खुले हाथ से मांस के ऊपर डालें। कटा हुआ डिल छिड़कें, और हर खाने वाले को साथ में गरम साफ शोरबा का एक कप दें ताकि वे बीच-बीच में पी सकें। सब कुछ धुआँ छोड़ता रहे, तभी तुरंत परोसें।.","en":"Place the meat in a large stockpot, cover with the cold water, and bring slowly to the boil over medium heat — slow heating draws maximum flavour into the broth; skim the grey foam carefully for the first 10 minutes until the surface runs clear. Add the 1 tbsp salt, halved onion, carrot, bay leaves, and peppercorns; reduce the heat to a bare simmer (the surface should barely move) and cook uncovered for 2–2.5 hours, until the meat is fork-tender and falling from the bone. While the meat simmers, make the dough; whisk the flour and 1 tsp salt in a wide bowl, make a well, and add the eggs and warm water; stir with a fork, then knead on a floured surface for 8–10 minutes until firm, smooth, and elastic; cover with cling film and rest at room temperature for 30 minutes. Divide the rested dough into 4 pieces; working with one piece at a time and keeping the rest covered, roll out as thinly as possible on a floured surface — about 1 mm thick; cut into rough 8 × 8 cm squares (or 10 × 5 cm diamonds); dust generously with flour and lay flat on a tray so they do not stick. Lift the meat out of the broth onto a board, cover loosely with foil, and rest; strain the broth into a clean pot through a fine sieve and discard the boiling vegetables; keep the broth at a gentle simmer. Ladle 500 ml of the hot broth into a separate small pot; add the thinly sliced onions and a pinch of sugar and simmer for 5–6 minutes — the onions should stay translucent and just tender, not collapsed; stir in 0.5 tsp black pepper. Bring the strained broth back to a vigorous boil; drop the dough squares in batches, stir gently to prevent sticking, and cook 3–4 minutes per batch until they float and are al dente; lift out with a slotted spoon onto a warmed serving platter. Slice the meat thickly against the grain and arrange over the noodles; spoon the onions and their broth liberally over the meat; scatter with chopped dill, then ladle a cup of the hot clear broth on the side for each diner to sip between bites; serve immediately while everything is steaming hot."}},{"id":130,"origin":{"hi":"थाईलैंड","en":"Thailand","ro":"Thailanda"},"name":{"hi":"नारियल चावल","en":"Coconut Rice","ro":"Orez cu lapte de cocos"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"hi":["400 ग्राम लंबे दाने वाला चावल (थाई जैस्मिन या बासमती)","400 मिली फुल-फैट नारियल का दूध (1 मानक डिब्बा)","250 मिली ठंडा पानी","1 छोटा चम्मच बारीक समुद्री नमक","1 छोटा चम्मच कास्टर शक्कर","2 ताज़े पैंडन (पंडानस) पत्ते, गांठ बाँधे (या 1 छोटा चम्मच पैंडन एसेंस — वैकल्पिक पर परंपरागत)","1 छोटा शैलट (लगभग 30 ग्राम), पतला कटा","1 लेमनग्रास डंडी, हल्के से कुटी (वैकल्पिक, दक्षिण-पूर्व एशियाई सुगंध के लिए)","3 सेमी नींबू (लाइम) के छिलके की पट्टी (वैकल्पिक, ताज़गी के लिए)","1 बड़ा चम्मच नारियल तेल या न्यूट्रल तेल","30 ग्राम बिना मीठा सूखा नारियल कद्दूकस, हल्का भुना (सजावट के लिए)","एक छोटी मुट्ठी ताज़े हरे धनिए के पत्ते (सजावट के लिए)"],"en":["400 g long-grain rice (Thai jasmine or basmati)","400 ml full-fat coconut milk (1 standard tin)","250 ml cold water","1 tsp fine sea salt","1 tsp caster sugar","2 fresh pandan leaves, tied into a knot (or 1 tsp pandan extract — optional but traditional)","1 small shallot (about 30 g), finely sliced","1 stalk lemongrass, lightly bruised (optional, for Southeast Asian aroma)","3 cm strip lime zest (optional, for brightness)","1 tbsp coconut oil or neutral oil","30 g unsweetened desiccated coconut, lightly toasted (for garnish)","Small handful fresh coriander leaves (for garnish)"],"ro":["400 g orez cu bob lung (jasmine thailandez sau basmati)","400 ml lapte de cocos integral (1 conservă standard)","250 ml apă rece","1 linguriță sare fină de mare","1 linguriță zahăr tos","2 frunze de pandan proaspete, legate în nod (sau 1 linguriță extract de pandan — opțional, dar tradițional)","1 eșalotă mică (aproximativ 30 g), feliată fin","1 tulpină de lemongrass, ușor zdrobită (opțional, pentru aroma sud-est asiatică)","Coajă de lime de 3 cm, fâșie subțire (opțional, pentru prospețime)","1 lingură ulei de cocos sau ulei neutru","30 g cocos rasă neîndulcită, ușor prăjită (pentru garnitură)","Un pumn mic de frunze de coriandru proaspete (pentru garnitură)"]},"howIsMade":{"hi":"चावल को छलनी में रखकर ठंडे बहते पानी के नीचे लगभग 1 मिनट तक हाथ से चलाते हुए धोएं, जब तक पानी लगभग साफ न निकले। अच्छी तरह छानें। यह सतह का स्टार्च हटाता है और अंत में दाने अलग-अलग बने रहते हैं।. 2-लीटर का मोटे तले वाला बर्तन मध्यम आंच पर रखें और नारियल का तेल गरम करें। कटे शैलट डालें और 90 सेकंड–2 मिनट तक चलाते हुए भूनें, जब तक नर्म हो जाएं और किनारे हल्के सुनहरे हों, पर भूरे न पड़ें।. छाने हुए चावल बर्तन में डालें और 30 सेकंड तक चलाएं ताकि हर दाना तेल में लिपट जाए। नारियल का दूध और पानी डालें, फिर नमक, शक्कर, गांठ बँधे पैंडन पत्ते, कुटी लेमनग्रास और नींबू का छिलका मिलाएं।. नमक घुलने के लिए एक बार चलाएं और मध्यम-तेज़ आंच पर हल्का उबाल लाएं — लगभग 2 मिनट हल्के हाथ से चलाते रहें ताकि नारियल का दूध तले में न चिपके।. आंच एकदम धीमी कर दें, कसा हुआ ढक्कन लगाएं और बिना खोले 12 मिनट पकाएं। ढक्कन न उठाएं — अंदर बँधी भाप ही चावल को एकसमान पकाती है।. आंच बंद करें (ढक्कन लगा रहने दें) और चावल को 10 मिनट विश्राम दें — यह अंतिम भाप दानों को सुखाती है और चिपकने से रोकती है।. ढक्कन हटाएं, पैंडन, लेमनग्रास और नींबू का छिलका निकालकर हटा दें। कांटे से चावल को हल्के से फुलाएं, ऊपर भुना सूखा नारियल और हरे धनिए के पत्ते छिड़कें और तुरंत करी, सम्बोल या ग्रिल्ड मछली के साथ परोसें।.","en":"Rinse the rice thoroughly in a sieve under cold running water for about 1 minute, swirling with your hand, until the water runs almost clear; drain well; this removes surface starch and keeps the grains separate at the end. Heat the coconut oil in a heavy-based 2-litre pan over medium heat; add the sliced shallot and stir-fry for 90 seconds–2 minutes, until softened and lightly golden at the edges but not browned. Add the drained rice to the pan and stir for 30 seconds to coat each grain in oil; pour in the coconut milk and water, then add the salt, sugar, knotted pandan leaves, bruised lemongrass, and lime zest. Stir once to dissolve the salt and bring to a gentle boil over medium-high heat — keep stirring gently for about 2 minutes so the coconut milk does not catch on the base. Lower the heat to the lowest possible setting, cover with a tight-fitting lid, and cook undisturbed for 12 minutes; do not lift the lid — the trapped steam is what cooks the rice evenly. Turn off the heat (leave the pan covered) and rest the rice for 10 minutes — this finishing steam dries the grains and stops them clumping. Lift the lid, remove and discard the pandan, lemongrass, and lime zest; fluff the rice gently with a fork, scatter the toasted desiccated coconut and coriander leaves over the top, and serve immediately alongside curry, sambols, or grilled fish."}},{"id":131,"origin":{"hi":"मलेशिया","en":"Malaysia","ro":"Malaezia"},"name":{"hi":"नासी लेमक","en":"Nasi lemak","ro":"Nasi lemak"},"category":{"hi":"नाश्ता","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"hi":["400 ग्राम लंबे दाने का जैस्मिन चावल","400 मिली फुल-फैट नारियल का दूध","200 मिली ठंडा पानी","1 छोटा चम्मच बारीक समुद्री नमक","2 ताज़े पैंडन (पंडानस) पत्ते गांठ बँधे, साथ में 1 कुटी लेमनग्रास डंडी और 3 ताज़ा अदरक के पतले स्लाइस (चावल के लिए)","60 ग्राम बिना छिलके वाली कच्ची मूँगफली","60 ग्राम इकान बिलिस (मलेशियाई सूखी एंकोवी)","4 बड़े अंडे","1 मध्यम खीरा (लगभग 200 ग्राम), 5 मिमी मोटी गोल फाँकों में कटा","10 सूखी लाल मिर्चें, गरम पानी में 15 मिनट भिगोकर छानी हुई","4 ताज़ी लाल मिर्चें (नर्म)","2 बड़े शैलट (लगभग 120 ग्राम) छिले, साथ में 3 लहसुन की कलियाँ और अंगूठे जितनी ताज़ा अदरक (15 ग्राम)","1 बड़ा चम्मच बेलाचान (भुना झींगा पेस्ट) या विकल्प में 1.5 छोटे चम्मच फिश सॉस","2 बड़े चम्मच इमली का गूदा 4 बड़े चम्मच गुनगुने पानी में घुला (या 3 बड़े चम्मच नींबू/लाइम का रस)","2 बड़े चम्मच पाम शक्कर या गहरी ब्राउन शक्कर","1 मध्यम लाल प्याज़ (लगभग 120 ग्राम), पतले छल्लों में कटा","60 मिली और 250 मिली न्यूट्रल तेल (60 मिली sambal के लिए; बाकी एंकोवी और मूँगफली तलने के लिए)","0.5 छोटा चम्मच बारीक समुद्री नमक sambal के लिए"],"en":["400 g long-grain jasmine rice","400 ml full-fat coconut milk","200 ml cold water","1 tsp fine sea salt","2 fresh pandan leaves tied into a knot, plus 1 bruised stalk of lemongrass and 3 thin slices of fresh ginger (for the rice)","60 g raw skinless peanuts","60 g ikan bilis (dried Malaysian anchovies)","4 large eggs","1 medium cucumber (about 200 g), sliced into 5 mm rounds","10 dried red chillies, soaked in hot water for 15 minutes and drained","4 fresh red chillies (mild)","2 large shallots (about 120 g), peeled, plus 3 garlic cloves and 1 thumb-sized piece of fresh ginger (15 g)","1 tbsp belacan (toasted shrimp paste), or 1.5 tsp fish sauce as a substitute","2 tbsp tamarind paste mixed with 4 tbsp warm water (or 3 tbsp lime juice)","2 tbsp palm sugar or dark brown sugar","1 medium red onion (about 120 g), sliced into thin rings","60 ml plus 250 ml neutral oil (split: 60 ml for the sambal, the rest for frying anchovies and peanuts)","0.5 tsp fine sea salt for the sambal"],"ro":["400 g orez jasmine cu bob lung","400 ml lapte de cocos integral","200 ml apă rece","1 linguriță sare fină de mare","2 frunze de pandan proaspete, legate în nod, plus 1 tulpină de lemongrass zdrobită și 3 felii subțiri de ghimbir proaspăt (pentru orez)","60 g arahide crude fără pieliță","60 g ikan bilis (anșoa malaezieni uscați)","4 ouă mari","1 castravete mediu (aproximativ 200 g), tăiat rondele de 5 mm","10 ardei iuți roșii uscați, înmuiați în apă fierbinte 15 minute și scurși","4 ardei iuți roșii proaspeți (blânzi)","2 eșalote mari (aproximativ 120 g), decojite, plus 3 căței de usturoi și o bucată de ghimbir cât degetul mare (15 g)","1 lingură belacan (pastă de creveți prăjită) sau 1,5 linguriță sos de pește ca substitut","2 linguri pastă de tamarin amestecată cu 4 linguri apă caldă (sau 3 linguri suc de lime)","2 linguri zahăr de palmier sau zahăr brun închis","1 ceapă roșie medie (aproximativ 120 g), feliată inele subțiri","60 ml plus 250 ml ulei neutru (împărțit: 60 ml pentru sambal, restul pentru prăjit anșoa și arahide)","0,5 linguriță sare fină de mare pentru sambal"]},"howIsMade":{"hi":"चावल को छलनी में रखकर ठंडे बहते पानी के नीचे 1 मिनट तक धोएं जब तक पानी लगभग साफ न निकले, फिर अच्छी तरह छानें। 2-लीटर मोटे तले के बर्तन में चावल, नारियल का दूध, पानी, 1 छोटा चम्मच नमक, पैंडन, लेमनग्रास और अदरक डालें। मध्यम-तेज़ आंच पर हल्के उबाल पर लाएं, एक बार चलाएं। आंच एकदम धीमी कर दें, कसा हुआ ढक्कन लगाएं और बिना खोले 12 मिनट पकाएं। आंच बंद करें और ढका हुआ 10 मिनट और विश्राम दें — अंदर बँधी भाप पकाव पूरा करती है और दाने सुखाती है। परोसने से पहले पैंडन, लेमनग्रास और अदरक हटा दें।. चावल पकते समय मूँगफली तलें। एक छोटे पैन में 250 मिली तेल को 160°C तक गर्म करें। मूँगफली को 3–4 मिनट तक हल्के सुनहरे होने तक तलें (ठंडी होते ही और गहरी होंगी), फिर छन्नी कलछी से किचन पेपर पर निकालें। हल्का नमक छिड़कें।. इकान बिलिस को पेपर से पोंछकर सुखाएं। उसी तेल में दो बैच में 60–90 सेकंड प्रति बैच, एक बार चलाते हुए, कुरकुरी और गहरी सुनहरी होने तक तलें। अलग पेपर पर निकालें और तेल बचाकर रखें।. कड़े उबले अंडे बनाएं: हल्के उबलते पानी में डालकर ठोस ज़र्दी के लिए ठीक 8 मिनट (या हल्की क्रीमी ज़र्दी के लिए 7 मिनट) पकाएं। तुरंत बर्फ़ के पानी में 3 मिनट डालें, फिर छीलकर आधे काटें।. सम्बल पेस्ट बनाएं। भीगी छनी सूखी मिर्चें, ताज़ी मिर्चें, शैलट, लहसुन, 15 ग्राम अदरक का टुकड़ा और बेलाचान को ब्लेंडर या ओखली में बचाए हुए तेल के 2 बड़े चम्मच के साथ डालकर मोटा पेस्ट बनाएं।. वोक या चौड़े पैन में 60 मिली ताज़ा तेल मध्यम आंच पर गर्म करें। सम्बल पेस्ट डालें और लगातार चलाते हुए 12–15 मिनट तक तब तक भूनें जब तक तेल किनारों से अलग न हो जाए और पेस्ट का रंग गहरा ईंट लाल न हो जाए। यह लंबा भूनना सामग्री का कच्चा स्वाद हटाता है।. लाल प्याज़ के छल्ले, इमली का पानी, पाम शक्कर और 0.5 छोटा चम्मच नमक डालें। 6–8 मिनट और धीमी आंच पर पकाएं जब तक प्याज़ नर्म न हो जाए और सम्बल चमकदार, जैम जैसी बनावट का हो जाए जो पैन में चम्मच फेरने पर साफ रेखा छोड़े। चखें और संतुलन बनाएं — तीखा, मीठा, खट्टा और नमकीन लगभग बराबर अनुपात में हो।. परोसने के लिए: हर प्लेट के बीच चावल का एक ढेर रखें। चारों ओर आधा उबला अंडा, एक उदार चम्मच सम्बल, मूँगफली का छोटा ढेर, कुरकुरी इकान बिलिस का छोटा ढेर और खीरे की पंखुड़ी रखें। हर निवाले में हर ढेर से थोड़ा-थोड़ा मिलाकर खाएं।.","en":"Rinse the rice in a sieve under cold running water for 1 minute, until the water runs almost clear, then drain well; put it in a heavy 2-litre pan with the coconut milk, water, 1 tsp salt, pandan, lemongrass, and ginger; bring to a gentle boil over medium-high heat, stirring once; lower the heat to the lowest setting, cover with a tight lid, and cook undisturbed for 12 minutes; turn off the heat and rest, covered, for another 10 minutes — the trapped steam finishes cooking and dries the grains; discard the aromatics before serving. While the rice cooks, fry the peanuts; heat the 250 ml oil in a small pan to 160°C; fry the peanuts for 3–4 minutes until pale gold (they will darken as they cool), then lift onto paper towels with a slotted spoon; salt lightly. Pat the ikan bilis dry; in the same oil, fry them in two batches for 60–90 seconds per batch, stirring once, until crisp and deep gold; lift onto a separate sheet of paper; reserve the oil. Hard-boil the eggs: lower them into gently simmering water and cook for exactly 8 minutes for set yolks (or 7 minutes for slightly jammy); transfer immediately to iced water for 3 minutes, then peel and halve. Make the sambal paste; combine the drained dried chillies, fresh chillies, shallots, garlic, the 15 g ginger piece, and belacan in a blender or mortar with 2 tbsp of the reserved oil and process to a coarse paste. Heat 60 ml fresh oil in a wok or wide pan over medium heat; add the sambal paste and fry, stirring continuously, for 12–15 minutes, until the oil splits out around the edges and the paste turns deep brick-red; this long fry is what kills the raw bite of the aromatics. Stir in the red onion rings, tamarind water, palm sugar, and 0.5 tsp salt; simmer for 6–8 minutes more, until the onions are softened and the sambal has a glossy, jammy texture that holds a clean line when you drag a spoon across the pan; taste and balance — it should be hot, sweet, sour, and savoury in roughly equal measure. To serve: mound a portion of rice on each plate; surround with a hard-boiled egg half, a generous spoonful of sambal, a small heap of peanuts, a small heap of crispy anchovies, and a fan of cucumber slices; eat by mixing small amounts from each pile into each bite."}},{"id":132,"origin":{"hi":"स्विट्ज़रलैंड","en":"Switzerland","ro":"Elveția"},"name":{"hi":"रॉश्ती","en":"Rösti","ro":"Rösti"},"category":{"hi":"नाश्ता","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"hi":["1 किलो वैक्सी आलू (Yukon Gold, Charlotte या समान किस्म), बिना छिले","60 ग्राम अनसाल्टेड मक्खन, 30-30 ग्राम के दो भागों में","2 बड़े चम्मच न्यूट्रल तेल (सूरजमुखी या अंगूर के बीज), 1-1 बड़े चम्मच के दो भागों में","1 छोटा चम्मच बारीक समुद्री नमक, स्वादानुसार और","0.5 छोटा चम्मच ताज़ी पिसी काली मिर्च","चुटकी भर कद्दूकस की हुई जायफल (वैकल्पिक, बर्न संस्करण में परंपरागत)","1 छोटा प्याज़ (लगभग 80 ग्राम), बहुत बारीक कटा (वैकल्पिक, सामान्य प्रकार)","60 ग्राम पुराना ग्रुयेर पनीर, मोटा कद्दूकस (वैकल्पिक, अधिक भरपूर समापन के लिए)","1 बड़ा चम्मच बारीक कटा ताज़ा चाइव्स, सजावट के लिए"],"en":["1 kg waxy potatoes (Yukon Gold, Charlotte, or similar), unpeeled","60 g unsalted butter, in two 30 g portions","2 tbsp neutral oil (sunflower or grapeseed), in two 1 tbsp portions","1 tsp fine sea salt, plus more to taste","0.5 tsp freshly ground black pepper","Pinch of grated nutmeg (optional, traditional in Bernese versions)","1 small onion (about 80 g), very finely diced (optional, common variation)","60 g aged gruyère, coarsely grated (optional, for a richer finish)","1 tbsp finely chopped fresh chives, to garnish"],"ro":["1 kg cartofi cu pastă fermă (Yukon Gold, Charlotte sau similari), necurățați","60 g unt nesărat, împărțit în două porții de 30 g","2 linguri ulei neutru (de floarea-soarelui sau de struguri), împărțit în două porții de 1 lingură","1 linguriță sare fină de mare, plus după gust","0,5 linguriță piper negru proaspăt măcinat","Un vârf de nucșoară rasă (opțional, tradițional în versiunea berneză)","1 ceapă mică (aproximativ 80 g), tăiată foarte fin (opțional, variantă obișnuită)","60 g gruyère maturat, ras grosier (opțional, pentru finisare mai bogată)","1 lingură arpagic proaspăt tocat fin, pentru garnitură"]},"howIsMade":{"hi":"एक दिन पहले, साबुत बिना छिले आलू को अच्छी तरह नमक वाले पानी (हर लीटर के लिए 1 बड़ा चम्मच नमक) में 8–10 मिनट तक उबालें — चाकू थोड़े विरोध से अंदर जाए, बीच कच्चा रहे। पानी निथार कर पूरी तरह ठंडा करें। बिना ढके रातभर फ्रिज में रखें ताकि सतह सूख जाए और स्टार्च जम जाए।. अगले दिन, ठंडे आलू को छीलें — छिलका आसानी से उतर जाना चाहिए। बॉक्स कद्दूकस के बड़े छेद वाले हिस्से से लंबे, समान धागों में कद्दूकस करें, गर्म होने से बचाने के लिए जल्दी काम करें।. एक बाउल में कद्दूकस किए आलू को नमक, काली मिर्च और जायफल से सीज़न करें और उंगलियों की पोरों से हल्के से मिलाएं — दबाएं नहीं, ताकि धागे लंबे बने रहें।. 24 सेमी नॉन-स्टिक या अच्छी तरह सीज़न किए लोहे के पैन में 1 बड़ा चम्मच तेल और 30 ग्राम मक्खन मध्यम आंच पर तब तक गरम करें जब तक मक्खन झाग बना कर हेज़लनट रंग का न हो जाए। प्याज़ का बारीक कटा हिस्सा (अगर डाल रहे हैं) डालें और 90 सेकंड–2 मिनट तक नर्म और हल्के सुनहरे होने तक भूनें।. सीज़न किए आलू को पैन में एक समान परत में फैलाएं, स्पैचुला की पीठ से हल्के से दबाकर 1.5 सेमी मोटी और लगभग 22 सेमी व्यास की पैटी बनाएं — कसकर न दबाएं, हवा के अंतराल अंदर को कुरकुरा बनाते हैं। बिना छुए 8–10 मिनट पकाएं जब तक नीचे की तरफ गहरा सुनहरा भूरा न हो जाए और स्पैचुला को नीचे डालते ही साफ-साफ अलग न हो जाए।. एक सपाट प्लेट पैन के ऊपर रखें, rösti को प्लेट में पलटें, फिर पकी सतह ऊपर रखते हुए वापस पैन में सरकाएं। बचा हुआ 30 ग्राम मक्खन और 1 बड़ा चम्मच तेल किनारों पर डालें ताकि वे पैटी के नीचे फैल जाएं। 7–9 मिनट और पकाएं जब तक दूसरी तरफ भी उतनी ही गहरी सुनहरी हो जाए और बीच गरम और नर्म हो (बीच में पतला चाकू डालने पर कोई रुकावट न मिले)।. rösti को बोर्ड पर सरकाएं, अगर ग्रुयेर डाल रहे हैं तो ऊपर से छिड़कें (बची हुई गर्मी से हल्का पिघलेगा), कटे चाइव्स से सजाएं और 4 टुकड़ों में काटें। ऊपर तले अंडे के साथ, स्मोक्ड हैम के साथ या Bratwurst के साथ तुरंत परोसें।.","en":"The day before, parboil the potatoes whole and unpeeled in well-salted water (1 tbsp salt per litre) for 8–10 minutes — a knife should meet some resistance, the centre should still be raw; drain and cool completely; refrigerate uncovered overnight so the surface dries and the starches firm up. The next day, peel the cold potatoes — the skins should slip off easily; grate them on the large holes of a box grater into long, even shreds, working briskly so they do not warm. In a bowl, season the grated potatoes with the salt, pepper, and nutmeg, and toss gently to distribute — use your fingertips, not a heavy hand, so the strands stay long. Heat 1 tbsp oil and 30 g of the butter in a 24 cm non-stick or well-seasoned cast-iron pan over medium heat until the butter foams and just turns nut-brown; add the diced onion (if using) and cook for 90 seconds–2 minutes, until soft and lightly golden. Add the seasoned potato to the pan in one even layer, lightly pressing with the back of a spatula to form a 1.5 cm cake about 22 cm across — do not pack it down hard, the air gaps are what crisp the inside; cook undisturbed for 8–10 minutes, until the underside is deep golden brown and pulls cleanly from the pan when you slide a spatula under it. Hold a flat plate over the pan, invert the rösti onto it, then slide it back into the pan with the cooked side up; add the remaining 30 g butter and 1 tbsp oil around the edges so they run under the cake; cook for a further 7–9 minutes, until the second side is equally deep golden and the centre is hot and tender (a paring knife pushed into the middle should meet no resistance). Slide the rösti onto a board, scatter with the grated gruyère if using (the residual heat will melt it lightly), top with chopped chives, and cut into 4 wedges; serve immediately with a fried egg on top, smoked ham, or Bratwurst."}},{"id":133,"origin":{"hi":"रोमानिया","en":"Romania","ro":"România"},"name":{"hi":"सॉसेज के साथ बीन्स","en":"Beans with Sausages","ro":"Fasole cu cârnați"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"hi":["500 ग्राम सूखी सफेद बीन्स (cannellini, navy या यूनानी विशाल बीन्स), रातभर ठंडे पानी में भिगोई हुई","4 स्मोक्ड पोर्क सॉसेज (लगभग 500 ग्राम; उदा. cârnați Pleșcoi या स्मोक्ड पोलिश सॉसेज)","150 ग्राम स्मोक्ड बेकन (कैसर) या स्मोक्ड पोर्क रिब्स, 2 सेमी टुकड़ों में कटे (वैकल्पिक, अधिक गहराई के लिए)","2 बड़े प्याज़ (लगभग 350 ग्राम), बारीक कटे","2 मध्यम गाजर (लगभग 200 ग्राम), बारीक कटी","1 मध्यम लाल शिमला मिर्च, बारीक कटी","4 लहसुन की कलियाँ, बारीक कटी","3 बड़े चम्मच टमाटर पेस्ट","200 ग्राम डिब्बाबंद कुटे टमाटर (या 2 ताज़े टमाटर कद्दूकस किए)","3 तेजपत्ते","1 छोटा चम्मच मीठी पैपरिका","0.5 छोटा चम्मच सूखी थाइम (या 1 ताज़ी डंडी)","0.5 छोटा चम्मच ताज़ी पिसी काली मिर्च","1.5 छोटे चम्मच बारीक समुद्री नमक, स्वादानुसार और","60 मिली सूरजमुखी का तेल (या 30 ग्राम चरबी)","1.5–2 लीटर पानी (या ज़्यादा गहरे स्वाद के लिए बिना नमक का चिकन स्टॉक)","2 बड़े चम्मच ताज़ा डिल या पार्सले बारीक कटा, अंत में डालने के लिए","1 बड़ा चम्मच सफेद वाइन सिरका (वैकल्पिक, अंत में संतुलन के लिए)"],"en":["500 g dried white beans (cannellini, navy, or Greek elephant), soaked overnight in cold water","4 smoked pork sausages (about 500 g; e.g. cârnați Pleșcoi or smoked Polish sausage)","150 g smoked bacon (kaiser) or smoked pork ribs, cut into 2 cm pieces (optional, for extra depth)","2 large onions (about 350 g), finely diced","2 medium carrots (about 200 g), finely diced","1 medium red bell pepper, finely diced","4 garlic cloves, finely chopped","3 tbsp tomato paste","200 g canned crushed tomatoes (or 2 fresh tomatoes, grated)","3 bay leaves","1 tsp sweet paprika","0.5 tsp dried thyme (or 1 sprig fresh)","0.5 tsp freshly ground black pepper","1.5 tsp fine sea salt, plus more to taste","60 ml sunflower oil (or 30 g lard)","1.5–2 litres water (or unsalted chicken stock for richer flavour)","2 tbsp finely chopped fresh dill or parsley, to finish","1 tbsp white wine vinegar (optional, to balance at the end)"],"ro":["500 g fasole albă uscată (cannellini, navy sau fasole gigant grecească), înmuiată peste noapte în apă rece","4 cârnați afumați de porc (aproximativ 500 g, ex. cârnați Pleșcoi sau cârnați polonezi afumați)","150 g kaiser afumat sau coaste de porc afumate, tăiate bucăți de 2 cm (opțional, pentru profunzime)","2 cepe mari (aproximativ 350 g), tocate fin","2 morcovi medii (aproximativ 200 g), tocați mărunt","1 ardei kapia roșu mediu, tocat fin","4 căței de usturoi, tocați fin","3 linguri bulion (pastă de roșii)","200 g roșii sfărâmate din conservă (sau 2 roșii proaspete, date pe răzătoare)","3 foi de dafin","1 linguriță boia dulce","0,5 linguriță cimbru uscat (sau 1 crenguță proaspătă)","0,5 linguriță piper negru proaspăt măcinat","1,5 lingurițe sare fină de mare, plus după gust","60 ml ulei de floarea-soarelui (sau 30 g untură)","1,5–2 litri apă (sau supă neagră de pui pentru o aromă mai bogată)","2 linguri mărar sau pătrunjel proaspăt tocat fin, pentru finisare","1 lingură oțet de vin alb (opțional, pentru echilibru la final)"]},"howIsMade":{"hi":"एक रात पहले, सूखी बीन्स को बड़े बाउल में रखें, कम-से-कम 2 लीटर ठंडे पानी से ढकें और 8–12 घंटे भिगोएं। बीन्स लगभग दोगुनी हो जाएंगी और गैस बनाने वाली शक्करों का बड़ा हिस्सा निकल जाएगा।. अगले दिन बीन्स को छानकर धोएं। एक मोटे तले के बर्तन में डालकर ताज़ा पानी 5 सेमी ऊपर तक डालें, उबाल लाएं और बिना ढके 10 मिनट पकाएं। फिर से छान लें — यह पहली तेज़ उबाल बीन्स को सौम्य बनाती है और अंत में पकने का समय कम करती है।. बीन्स को 1.5 लीटर ताज़ा पानी (या स्टॉक), (अगर डाल रहे हैं तो) स्मोक्ड बेकन और 2 तेजपत्तों के साथ बर्तन में वापस डालें। हल्के उबाल पर लाएं और आधा ढककर 50–60 मिनट पकाएं — बीन्स बस नर्म हों, टूटें नहीं। अभी नमक न डालें (इस चरण में नमक छिलकों को सख्त कर देता है)।. बीन्स पकते समय एक चौड़े गहरे पैन में तेल मध्यम आंच पर गरम करें। कटा प्याज़ और एक उदार चुटकी नमक डालें और 8–10 मिनट तक बार-बार चलाते हुए नर्म और किनारे सुनहरे होने तक भूनें। गाजर और लाल शिमला मिर्च डालें और 5–6 मिनट और भूनें जब तक नर्म न हो जाएं।. सब्ज़ियों को एक तरफ़ धकेलें, खाली जगह में लहसुन डालकर 30 सेकंड पकाएं, फिर पैपरिका और थाइम डालें — 20–30 सेकंड तक खुशबू आने तक भूनें। टमाटर पेस्ट और कुटे टमाटर डालें और 3–4 मिनट तक चलाते हुए पकाएं जब तक टमाटर गहरा लाल न हो जाए और तेल किनारों से अलग न दिखे।. 2 सॉसेज को 2 सेमी के गोले में काटें; अन्य 2 को ऊपर रखने के लिए साबुत रखें। कटी सॉसेज को टमाटर बेस में डालें और 2–3 मिनट पकाएं ताकि कुछ चर्बी निकले।. बीन्स के बर्तन को उसके पानी सहित टमाटर बेस में पलट दें, बचा तेजपत्ता, 1.5 छोटे चम्मच नमक और काली मिर्च डालें। साबुत सॉसेज को स्टू में दबा दें। बिना ढके 35–45 मिनट पकाएं, बीच-बीच में चलाते हुए, जब तक बीन्स नर्म हो जाएं और शोरबा एक पतली ग्रेवी जैसा गाढ़ा हो जाए जो चम्मच की पीठ पर लिपटे। अगर बहुत गाढ़ा हो जाए तो थोड़ा पानी डालें।. चखें, नमक से सेट करें, अगर डाल रहे हैं तो सफेद वाइन सिरका डालें (हल्की खटास स्मोक्ड स्वाद को निखारती है)। साबुत सॉसेज निकालें और तिरछा काटें। बीन्स को गहरे कटोरों में परोसें, हर एक के ऊपर सॉसेज की पंखुड़ी बनाएं, कटी डिल छिड़कें और अचार और देशी पाव या पोलेंटा के साथ परोसें।.","en":"The night before, place the dried beans in a large bowl, cover with at least 2 litres of cold water, and leave to soak for 8–12 hours; they will roughly double in size and lose much of the gas-producing sugars. The next day, drain and rinse the beans; put them in a heavy pot with fresh water to cover by 5 cm, bring to a boil, and cook uncovered for 10 minutes; drain again — this first quick boil mellows the beans and shortens the final cooking time. Return the beans to the pot with 1.5 litres of fresh water (or stock), the smoked bacon (if using), and 2 of the bay leaves; bring to a gentle simmer and cook partially covered for 50–60 minutes — the beans should be just tender but not falling apart; do not salt yet (salt at this stage toughens the skins). While the beans simmer, heat the oil in a wide deep pan over medium heat; add the diced onions and a generous pinch of salt and cook for 8–10 minutes, stirring often, until soft and golden brown at the edges; add the carrots and red bell pepper and cook for another 5–6 minutes, until softened. Push the vegetables to one side, add the garlic to the empty space and cook for 30 seconds, then stir in the paprika and thyme — toast for 20–30 seconds until fragrant; add the tomato paste and crushed tomatoes and cook, stirring, for 3–4 minutes, until the tomato is deeper red and the oil splits out around the edges. Slice 2 of the smoked sausages into 2 cm rounds; keep the other 2 whole for the top; add the sliced sausage to the tomato base and cook for 2–3 minutes to render some fat. Tip the bean pot and its liquid into the tomato base, add the remaining bay leaf, the 1.5 tsp salt, and the black pepper; bury the whole sausages in the stew; simmer uncovered for 35–45 minutes, stirring occasionally, until the beans are soft and the liquid has thickened to a thin gravy that coats the back of a spoon; add a splash of water if it tightens too much. Taste, adjust with salt, and add the white wine vinegar if using (a touch of acid brightens the smoke); lift out the whole sausages and slice on the diagonal; ladle the beans into deep bowls, top each with a fan of sausage slices, scatter with chopped dill, and serve with pickles and crusty bread or polenta."}},{"id":134,"origin":{"hi":"हंगरी","en":"Hungary","ro":"Ungaria"},"name":{"hi":"चिकन पप्रिकाश","en":"Chicken Paprikash","ro":"Chicken Paprikash"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"hi":["हड्डी और छिलके सहित चिकन की जांघें और टंगड़ी 1.5 किलो (लगभग 8 टुकड़े)","2 बड़े प्याज़ (लगभग 400 ग्राम), बारीक कटे","3 बड़े चम्मच हंगेरियन मीठी पैपरिका (Édesnemes, अधिमानतः Kalocsa या Szeged से), साथ में 0.5 छोटा चम्मच हंगेरियन तीखी पैपरिका (वैकल्पिक)","3 लहसुन की कलियाँ, बारीक कटी","1 मध्यम लाल शिमला मिर्च, बारीक कटी","1 मध्यम टमाटर (लगभग 100 ग्राम), छिलका हटाकर बारीक कटा (या 2 बड़े चम्मच टमाटर पेस्ट)","60 ग्राम चरबी (या 4 बड़े चम्मच न्यूट्रल तेल)","500 मिली बिना नमक का गरम चिकन स्टॉक या पानी","200 ग्राम फुल-फैट खट्टी क्रीम (कम-से-कम 20% फैट — लाइट क्रीम न लें, फट जाएगी)","1 बड़ा चम्मच मैदा","1.5 छोटे चम्मच बारीक समुद्री नमक, स्वादानुसार और","0.5 छोटा चम्मच ताज़ी पिसी काली मिर्च","1 छोटा चम्मच कैरावे बीज (वैकल्पिक, कुछ क्षेत्रों में परंपरागत)","ताज़ा डिल या पार्सले कटा, सजावट के लिए"],"en":["1.5 kg bone-in, skin-on chicken thighs and drumsticks (about 8 pieces)","2 large onions (about 400 g), finely diced","3 tbsp sweet Hungarian paprika (Édesnemes, preferably from Kalocsa or Szeged), plus 0.5 tsp hot Hungarian paprika (optional)","3 garlic cloves, finely chopped","1 medium red bell pepper, finely diced","1 medium tomato (about 100 g), peeled and finely diced (or 2 tbsp tomato paste)","60 g lard (or 4 tbsp neutral oil)","500 ml hot unsalted chicken stock or water","200 g full-fat sour cream (at least 20% fat — do NOT use light sour cream, it will split)","1 tbsp plain (all-purpose) flour","1.5 tsp fine sea salt, plus more to taste","0.5 tsp freshly ground black pepper","1 tsp caraway seeds (optional, traditional in some regions)","Fresh dill or parsley, chopped, to garnish"],"ro":["1,5 kg pulpe și copane de pui cu os și piele (aproximativ 8 bucăți)","2 cepe mari (aproximativ 400 g), tocate fin","3 linguri paprika dulce maghiară (Édesnemes, de preferință din Kalocsa sau Szeged), plus 0,5 linguriță paprika iute maghiară (opțional)","3 căței de usturoi, tocați fin","1 ardei gras roșu mediu, tăiat cuburi mici","1 roșie medie (aproximativ 100 g), curățată și tăiată cuburi mici (sau 2 linguri pastă de roșii)","60 g untură (sau 4 linguri ulei neutru)","500 ml supă de pui fierbinte nesărată sau apă","200 g smântână grasă (cel puțin 20% grăsime — NU smântână ușoară, se taie)","1 lingură făină albă","1,5 lingurițe sare fină de mare, plus după gust","0,5 linguriță piper negru proaspăt măcinat","1 linguriță semințe de chimen (opțional, tradițional în unele regiuni)","Mărar sau pătrunjel proaspăt tocat, pentru garnitură"]},"howIsMade":{"hi":"चिकन को किचन पेपर से थपथपा कर सुखाएं और दोनों तरफ़ 1 छोटा चम्मच नमक और काली मिर्च लगाकर सीज़न करें। 15 मिनट कमरे के तापमान पर रखें।. 28 सेमी भारी डच ओवन या चौड़े गहरे पैन में चरबी मध्यम-तेज़ आंच पर पिघलाएं। दो बैच में चिकन को चमड़ी की तरफ़ नीचे रखकर 4–5 मिनट, फिर दूसरी तरफ़ 3 मिनट सेक करें जब तक चमड़ी गहरी सुनहरी न हो — पैन को न भरें। प्लेट में निकालें।. आंच मध्यम कर दें और लगभग 3 बड़े चम्मच चर्बी छोड़कर बाकी निकाल दें। प्याज़ और एक चुटकी नमक डालें और 12–15 मिनट बार-बार चलाते हुए नर्म, चमकदार और पूरी तरह सुनहरे होने तक भूनें — यह धीमी भूनाई पैपरिकाश के स्वाद की नींव है।. लहसुन, लाल शिमला मिर्च और (अगर डाल रहे हैं तो) कैरावे बीज डालें और 2–3 मिनट और पकाएं जब तक शिमला मिर्च बस नर्म न हो जाए।. पैन को पूरी तरह आंच से उतारें। मीठी पैपरिका (और तीखी पैपरिका अगर डाल रहे हैं) मिलाएं — पैपरिका सीधी आंच पर जलकर कड़वी हो जाती है, इसलिए पैन उस समय आंच से हटा होना चाहिए। 30 सेकंड चलाएं जब तक प्याज़ गहरे ईंट लाल रंग में रंग जाए और मसाले की खुशबू गर्म और मीठी हो जाए।. पैन को मध्यम आंच पर वापस रखें। कटा टमाटर (या टमाटर पेस्ट) डालें और 1 मिनट चलाएं। गरम स्टॉक और बची 0.5 छोटी चम्मच नमक डालें, फिर चिकन को चमड़ी ऊपर रखकर सॉस में वापस सेट करें। हल्के उबाल पर लाएं।. ढककर सबसे धीमी आंच पर 35–45 मिनट तक तब तक पकाएं जब तक चिकन हड्डी से आसानी से अलग हो जाए और भीतर का तापमान 75°C तक पहुँच जाए। चिकन को गर्म प्लेट पर निकालें और सॉस तैयार करते समय एल्युमिनियम फ़ॉइल से ढक दें।. खट्टी क्रीम में मैदा डालकर चिकना होने तक फेंटें, फिर तापमान संतुलित करने के लिए एक करछुल गरम सॉस फेंटते हुए मिलाएं। आंच बंद कर के टेम्पर की हुई क्रीम को सॉस में डालें और रेशमी होने तक चलाएं। चिकन को सिर्फ़ गर्म करने के लिए सॉस में वापस डालें, चखें और नमक सेट करें, फिर nokedli, ताज़े पास्ता या बटर नूडल्स पर परोसें और ऊपर कटा डिल डालें।.","en":"Pat the chicken dry with paper towels and season both sides with 1 tsp of the salt and the black pepper; rest at room temperature for 15 minutes. Melt the lard in a heavy 28 cm Dutch oven or wide deep pan over medium-high heat; working in two batches, sear the chicken skin-side down for 4–5 minutes, then 3 minutes on the other side, until the skin is deep golden — do not crowd the pan; lift onto a plate. Reduce the heat to medium and pour off all but about 3 tbsp of the rendered fat; add the onions and a pinch of salt and cook for 12–15 minutes, stirring often, until soft, glossy, and fully golden — this slow sweat is the foundation of paprikash flavour. Add the garlic, red bell pepper, and caraway seeds (if using) and cook for another 2–3 minutes, until the pepper is just softened. Take the pan off the heat completely; stir in the sweet paprika (and hot paprika if using) — paprika scorches and turns bitter on direct heat, so the pan must be off when it goes in; stir for 30 seconds until the onions are stained a deep brick red and the spice smells warm and sweet. Return the pan to medium heat; add the diced tomato (or tomato paste) and stir for 1 minute; pour in the hot stock and the remaining 0.5 tsp salt, then nestle the chicken back into the sauce, skin-side up; bring to a gentle simmer. Cover and braise on the lowest heat for 35–45 minutes, until the chicken pulls easily from the bone and the internal temperature reads 75°C; lift the chicken onto a warm plate and tent with foil while you finish the sauce. Whisk the flour into the sour cream until smooth, then whisk in a ladle of the hot pan sauce to temper; off the heat, pour the tempered cream back into the pan and stir until silky; return the chicken to the sauce just to warm through, taste and adjust salt, then serve over nokedli, fresh pasta, or buttered noodles with chopped dill on top."}},{"id":135,"origin":{"hi":"इटली","en":"Italy","ro":"Italia"},"name":{"hi":"पास्ता अला नोर्मा","en":"Pasta alla Norma","ro":"Pasta alla Norma"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"pasta","pairingsType":"italian","ingredients":{"hi":["2 मध्यम बैंगन (कुल लगभग 700 ग्राम), बिना छिले, 2 सेमी क्यूब्स में कटे","बैंगन को नमकीन करने के लिए 1.5 छोटे चम्मच बारीक समुद्री नमक, साथ ही पास्ता पानी के लिए अतिरिक्त","बैंगन को उथला तलने के लिए 300 मिली एक्स्ट्रा वर्जिन जैतून का तेल","400 ग्राम रिगाटोनी, पेन्ने रिगाटे या मैकरोनी","सॉस के लिए 3 बड़े चम्मच एक्स्ट्रा वर्जिन जैतून का तेल","3 लहसुन की कलियाँ, पतले स्लाइस की हुई","0.5 छोटा चम्मच सूखी चिली फ्लेक्स (वैकल्पिक)","800 ग्राम साबुत छिले डिब्बाबंद टमाटर (हो सके तो San Marzano), हाथ से कुचले, या 700 ग्राम passata","1 छोटा चम्मच कास्टर शक्कर (केवल अगर टमाटर खट्टे हों)","0.5 छोटा चम्मच ताज़ी पिसी काली मिर्च","1 बड़ा गुच्छा ताज़ी तुलसी (लगभग 30 ग्राम), पत्ते अलग करके फाड़े हुए","120 ग्राम ricotta salata, बारीक कद्दूकस, परोसने के लिए और","पास्ता पानी के लिए 1 बड़ा चम्मच मोटा समुद्री नमक"],"en":["2 medium aubergines (about 700 g total), unpeeled, cut into 2 cm cubes","1.5 tsp fine sea salt for salting the aubergine, plus more for the pasta water","300 ml extra-virgin olive oil for shallow-frying the aubergine","400 g rigatoni, penne rigate, or maccheroni","3 tbsp extra-virgin olive oil for the sauce","3 garlic cloves, sliced thin","0.5 tsp dried chilli flakes (optional)","800 g whole peeled tomatoes (San Marzano if available), crushed by hand, or 700 g passata","1 tsp caster sugar (only if the tomatoes are sharp)","0.5 tsp freshly ground black pepper","1 large bunch fresh basil (about 30 g), leaves picked and torn","120 g ricotta salata, finely grated, plus more to serve","1 tbsp coarse sea salt for the pasta water"],"ro":["2 vinete medii (aproximativ 700 g în total), necurățate, tăiate cuburi de 2 cm","1,5 lingurițe sare fină de mare pentru asezonarea vinetelor, plus mai multă pentru apa pastelor","300 ml ulei de măsline extravirgin pentru prăjit vinetele","400 g rigatoni, penne rigate sau maccheroni","3 linguri ulei de măsline extravirgin pentru sos","3 căței de usturoi, feliați subțire","0,5 linguriță fulgi de ardei iute uscat (opțional)","800 g roșii întregi, decojite (San Marzano dacă e posibil), zdrobite cu mâna, sau 700 g pasată","1 linguriță zahăr tos (doar dacă roșiile sunt acrișoare)","0,5 linguriță piper negru proaspăt măcinat","1 legătură mare de busuioc proaspăt (aproximativ 30 g), frunzele rupte","120 g ricotta salata, rasă fin, plus în plus pentru servit","1 lingură sare grunjoasă de mare pentru apa pastelor"]},"howIsMade":{"hi":"बैंगन के क्यूब्स को 1.5 छोटे चम्मच बारीक नमक के साथ छलनी में मिलाएं और एक बाउल के ऊपर 30 मिनट तक छानें — इससे कड़वा पानी निकलता है और बैंगन तलते समय ज़्यादा तेल नहीं चूसता। पेपर टॉवल से हल्के से दबाकर सुखाएं।. एक चौड़े गहरे पैन में 300 मिली जैतून का तेल 170°C तक गरम करें। एक बैंगन के टुकड़े से जाँच — चटकदार आवाज़ आनी चाहिए। बैंगन को तीन बैच में, हर बैच 3–4 मिनट, बार-बार पलटते हुए तब तक तलें जब तक हर तरफ़ गहरा सुनहरा हो और अंदर से नर्म (चाकू आसानी से पार हो)। छन्नी कलछी से पेपर टॉवल पर निकालें। अलग रखें।. बैंगन तलते समय एक बड़े बर्तन में 4 लीटर पानी और 1 बड़ा चम्मच मोटा नमक तेज़ उबाल लाएं।. एक चौड़े सॉते पैन में 3 बड़े चम्मच जैतून तेल मध्यम आंच पर गरम करें। कटे लहसुन और (अगर डाल रहे हैं) चिली फ्लेक्स डालें और 60–90 सेकंड पकाएं — लहसुन किनारों पर हल्का सुनहरा हो, भूरा कभी न करें।. कुटे टमाटर, (अगर डाल रहे हैं) शक्कर, 0.5 छोटा चम्मच नमक और काली मिर्च डालें। चलाकर हल्के उबाल पर लाएं। 12–15 मिनट तक बीच-बीच में चलाते हुए पकाएं जब तक सॉस थोड़ा गाढ़ा न हो जाए और तेल ऊपर न आ जाए। अंतिम मिनट में फाड़ी हुई आधी तुलसी डालें।. पास्ता को उबलते पानी में डालें और पैकेट के समय से 1 मिनट कम पकाएं ताकि al dente हो। 250 मिली स्टार्च वाला पास्ता पानी अलग रखें और पास्ता छान लें।. तले बैंगन को टमाटर सॉस में मिलाएं, फिर छाने पास्ता डालें। मध्यम आंच पर 1–2 मिनट तेज़ी से टॉस करें, ज़रूरत हो तो पास्ता पानी डालें, जब तक सॉस हर टुकड़े पर चमकदार रूप से लिपट न जाए — पैन झुकाने पर बहना चाहिए पर पानीदार न हो।. आंच से हटाकर आधा कद्दूकस ricotta salata और बची हुई अधिकांश तुलसी छिड़ककर एक बार टॉस करें। चार गर्म कटोरों में बाँटें, हर एक के ऊपर और ricotta salata, बची तुलसी के पत्ते और कच्चे जैतून तेल की धार डालकर तुरंत परोसें।.","en":"Toss the aubergine cubes with the 1.5 tsp fine salt in a colander and leave to drain over a bowl for 30 minutes — this draws out bitter water and stops the aubergine from drinking too much oil during frying; press lightly with a paper towel and pat dry. Heat the 300 ml olive oil in a wide deep frying pan to 170°C; test with a single aubergine cube — it should sizzle briskly; fry the aubergine in three batches for 3–4 minutes per batch, turning often, until deeply golden on all sides and tender inside (a knife should pass through easily); lift onto paper towels with a slotted spoon to drain; reserve. While the aubergine fries, bring a large pot with 4 litres of water and 1 tbsp coarse salt to a rolling boil. In a wide sauté pan, heat the 3 tbsp olive oil over medium heat; add the sliced garlic and chilli flakes (if using) and cook for 60–90 seconds — the garlic should just turn pale gold around the edges, never brown. Add the crushed tomatoes, the sugar (if using), 0.5 tsp salt, and the black pepper; stir and bring to a simmer; cook for 12–15 minutes, stirring occasionally, until the sauce has thickened slightly and the oil rises to the surface; tear in half of the basil for the last minute. Drop the pasta into the boiling water and cook 1 minute less than the package says for al dente; reserve 250 ml of starchy pasta water, then drain. Fold the fried aubergine into the tomato sauce, then add the drained pasta; toss vigorously over medium heat for 1–2 minutes, adding splashes of pasta water as needed, until the sauce clings glossy to every piece — it should be loose enough to flow when you tilt the pan but not watery. Off the heat, scatter half the grated ricotta salata and most of the remaining basil and toss once; divide between four warmed bowls, finish each with more ricotta salata, the last basil leaves, and a drizzle of raw olive oil; serve immediately."}},{"id":137,"origin":{"hi":"तुर्कमेनिस्तान","en":"Turkmenistan","ro":"Turkmenistan"},"name":{"hi":"इचलेक्ली","en":"Ichlekli","ro":"Ichlekli"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"hi":["500 ग्राम साधारण मैदा, बेलने के लिए अतिरिक्त","1 छोटा चम्मच बारीक समुद्री नमक","240 मिली गुनगुना पानी","1 बड़ा चम्मच न्यूट्रल तेल (सूरजमुखी या अंगूर के बीज)","500 ग्राम मेमने का कंधा या गोमांस का चक, बारीक कीमा (या बड़े टुकड़ों में काटकर प्रोसेसर में पल्स करें)","100 ग्राम मेमने की पूँछ की चर्बी या गोमांस सूट, बारीक कटी (या विकल्प में 30 ग्राम अनसाल्टेड मक्खन)","2 बड़े प्याज़ (लगभग 350 ग्राम), बारीक कटे","200 ग्राम वैक्सी आलू, छिलकर 5 मिमी क्यूब्स में कटे (वैकल्पिक पर परंपरागत)","1.5 छोटे चम्मच बारीक समुद्री नमक","1 छोटा चम्मच ताज़ी पिसी काली मिर्च","1 छोटा चम्मच पिसा जीरा","0.5 छोटा चम्मच पिसा धनिया","0.5 छोटा चम्मच सूखी लाल मिर्च के फ्लेक्स (वैकल्पिक)","1 बड़े अंडे की जर्दी, 1 बड़े चम्मच दूध के साथ फेंटी हुई, ब्रश करने के लिए"],"en":["500 g plain (all-purpose) flour, plus extra for rolling","1 tsp fine sea salt","240 ml warm water","1 tbsp neutral oil (sunflower or grapeseed)","500 g lamb shoulder or beef chuck, finely minced (or coarsely diced and pulsed in a processor)","100 g lamb-tail fat or beef suet, finely diced (or 30 g unsalted butter as substitute)","2 large onions (about 350 g), finely diced","200 g waxy potatoes, peeled and diced into 5 mm cubes (optional but traditional)","1.5 tsp fine sea salt","1 tsp freshly ground black pepper","1 tsp ground cumin","0.5 tsp ground coriander","0.5 tsp dried red pepper flakes (optional)","1 large egg yolk, beaten with 1 tbsp milk, for brushing"],"ro":["500 g făină albă obișnuită, plus pentru întins","1 linguriță sare fină de mare","240 ml apă caldă","1 lingură ulei neutru (de floarea-soarelui sau de struguri)","500 g umăr de miel sau pulpă de vită, tocate fin (sau cuburi mărunte pulsate într-un robot)","100 g grăsime de coadă de miel sau seu de vită, tăiate fin (sau 30 g unt nesărat ca substitut)","2 cepe mari (aproximativ 350 g), tocate fin","200 g cartofi cu pastă fermă, curățați și tăiați cuburi de 5 mm (opțional, dar tradițional)","1,5 lingurițe sare fină de mare","1 linguriță piper negru proaspăt măcinat","1 linguriță chimion măcinat","0,5 linguriță coriandru măcinat","0,5 linguriță fulgi de ardei iute uscat (opțional)","1 gălbenuș mare bătut cu 1 lingură de lapte, pentru uns"]},"howIsMade":{"hi":"आटा बनाएं। चौड़े बाउल में मैदा और नमक फेंटें। बीच में जगह बनाकर गुनगुना पानी और तेल डालें और लकड़ी के चम्मच से चलाकर खुरदुरा आटा बनाएं। हल्के आटे वाली सतह पर 6–8 मिनट गूँधें जब तक चिकना, सख्त और लचीला न हो जाए — ब्रेड के आटे से थोड़ा कड़ा। क्लिंग फ़िल्म में लपेटकर कमरे के तापमान पर 30 मिनट विश्राम दें, इसी बीच भरावन तैयार करें।. एक बड़े बाउल में कीमा, चर्बी, प्याज़, (अगर डाल रहे हैं तो) आलू के क्यूब्स, नमक, काली मिर्च, जीरा, धनिया पाउडर और मिर्च फ्लेक्स मिलाएं। हाथों से 1 मिनट तक मिलाएं जब तक मिश्रण चिपचिपा और अच्छी तरह बंध न जाए। पहले से न पकाएं — भरावन आटे के अंदर पकेगा।. ओवन को 220°C (425°F / फैन 200°C) तक प्रीहीट करें और एक भारी बेकिंग ट्रे को उल्टा करके या पिज़्ज़ा स्टोन को मध्य रैक पर रखें ताकि कम-से-कम 20 मिनट तक गर्म हो जाए। यह गर्म सतह बेस को कुरकुरा बनाती है।. आराम किए आटे को दो बराबर भागों में बाँटें। हल्के आटे वाली सतह पर एक भाग को 32 सेमी व्यास, लगभग 2 मिमी मोटी डिस्क में बेलें — किनारों को बीच से पतला रखें ताकि सील ज़्यादा मोटी न हो।. डिस्क को बेकिंग पेपर पर सरकाएं। भरावन को डिस्क पर समान रूप से फैलाएं, 2 सेमी का किनारा छोड़ते हुए, और हल्के से दबाकर 1.5 सेमी की परत बनाएं।. दूसरे आटे को भी 32 सेमी की डिस्क में बेलकर ऊपर रखें। किनारे पर दोनों परतों को मज़बूती से दबाएं, फिर किनारे को अंदर की ओर रोल कर के उँगलियों से दबाएं ताकि एक तंग रस्सी जैसा किनारा बने और रस बाहर न निकले।. ऊपर अंडे की जर्दी का ग्लेज़ ब्रश करें और भाप निकलने के लिए बीच में कांटे से 6–8 जगह छेद करें। पाई को बेकिंग पेपर सहित ओवन की गर्म ट्रे पर सरकाएं। 30–35 मिनट तक बेक करें जब तक ऊपर गहरा सुनहरा भूरा न हो जाए और नीचे थपथपाने पर खोखली आवाज़ न आए।. पाई को बोर्ड पर 5 मिनट विश्राम दें (भाप शांत होती है और भरावन सेट होता है), फिर तेज़ चाकू से 8 टुकड़ों में काटें। हरी चाय, सादे दही या खट्टे दूध के साथ गरम परोसें।.","en":"Make the dough; whisk the flour and salt in a wide bowl; make a well, pour in the warm water and oil, and stir with a wooden spoon until a shaggy dough forms; knead on a lightly floured surface for 6–8 minutes until smooth, firm, and elastic — slightly stiffer than bread dough; wrap in cling film and rest at room temperature for 30 minutes while you prepare the filling. In a large bowl, combine the minced lamb, fat, onions, potato cubes (if using), salt, pepper, cumin, coriander, and pepper flakes; mix with your hands for 1 minute until the mixture is sticky and well bound; do not pre-cook — the filling cooks inside the dough. Heat the oven to 220°C (425°F / fan 200°C) and place an upturned heavy baking tray or pizza stone on the middle rack to heat through for at least 20 minutes; the hot surface is what crisps the bottom. Divide the rested dough into two equal pieces; on a lightly floured surface, roll one piece into a 32 cm round, about 2 mm thick — work the edges thinner than the centre so the seal will not be too thick. Slide the round onto a sheet of baking parchment; spread the filling evenly over the disc, leaving a 2 cm border, and press it down lightly into a 1.5 cm layer. Roll out the second piece of dough to the same 32 cm round and lay it on top; press the two layers together firmly around the edge, then roll and pinch the rim inward into a tight rope-like border so no juice can escape. Brush the top with the egg-yolk glaze and prick the centre in 6–8 places with a fork to let steam vent; slide the pie, on its parchment, onto the hot tray in the oven; bake for 30–35 minutes, until the top is deep golden brown and the bottom sounds hollow when you tap it. Rest the pie on a board for 5 minutes (the steam settles and the filling firms up), then cut into 8 wedges with a sharp knife; serve hot with green tea, plain yoghurt, or soured milk."}},{"id":138,"origin":{"hi":"यूक्रेन","en":"Ukraine","ro":"Ucraina"},"name":{"hi":"चिकन कीव","en":"Chicken Kiev","ro":"Pui Kiev"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"hi":["100 ग्राम अनसाल्टेड मक्खन, कमरे के तापमान पर नर्म","3 लहसुन की कलियाँ, बहुत बारीक कटी (या 1 बड़ा चम्मच लहसुन पेस्ट)","30 ग्राम सपाट पत्ती वाली अजमोद, बहुत बारीक कटी","1 बड़ा चम्मच नींबू का रस","0.5 छोटा चम्मच बारीक समुद्री नमक","0.25 छोटा चम्मच ताज़ी पिसी काली मिर्च","4 बड़े बिना छिलके वाले चिकन ब्रेस्ट (हर एक लगभग 200 ग्राम)","ब्रेस्ट के लिए 1 छोटा चम्मच बारीक समुद्री नमक","ब्रेस्ट के लिए 0.5 छोटा चम्मच ताज़ी पिसी काली मिर्च","80 ग्राम साधारण मैदा","2 बड़े अंडे, 1 बड़े चम्मच ठंडे पानी के साथ फेंटे हुए","150 ग्राम panko या बारीक सूखे ब्रेड क्रम्ब्स","750 मिली न्यूट्रल तेल (सूरजमुखी या रेपसीड), डीप फ्राई के लिए","1 बड़ा चम्मच अनसाल्टेड मक्खन, तेल को सुगंधित करने के लिए (वैकल्पिक, अधिक मेवेदार क्रस्ट के लिए)","नींबू के टुकड़े और थोड़ी अजमोद, परोसने के लिए"],"en":["100 g unsalted butter, softened to room temperature","3 garlic cloves, very finely minced (or 1 tbsp garlic paste)","30 g flat-leaf parsley, very finely chopped","1 tbsp lemon juice","0.5 tsp fine sea salt","0.25 tsp freshly ground black pepper","4 large skinless chicken breasts (about 200 g each)","1 tsp fine sea salt for the breasts","0.5 tsp freshly ground black pepper for the breasts","80 g plain (all-purpose) flour","2 large eggs, beaten with 1 tbsp cold water","150 g panko or fine dry breadcrumbs","750 ml neutral oil (sunflower or rapeseed), for deep-frying","1 tbsp unsalted butter, for finishing the oil (optional, for a nuttier crust)","Lemon wedges and a small bunch of parsley, to serve"],"ro":["100 g unt nesărat, înmuiat la temperatura camerei","3 căței de usturoi, tocați foarte fin (sau 1 lingură pastă de usturoi)","30 g pătrunjel cu frunze plate, tocat foarte fin","1 lingură suc de lămâie","0,5 linguriță sare fină de mare","0,25 linguriță piper negru proaspăt măcinat","4 piepți mari de pui dezosați și fără piele (aproximativ 200 g fiecare)","1 linguriță sare fină de mare pentru piepți","0,5 linguriță piper negru proaspăt măcinat pentru piepți","80 g făină albă obișnuită","2 ouă mari, bătute cu 1 lingură apă rece","150 g panko sau pesmet fin uscat","750 ml ulei neutru (de floarea-soarelui sau de rapiță), pentru prăjire adâncă","1 lingură unt nesărat, pentru aromatizarea uleiului (opțional, pentru o crustă cu unt prăjit)","Felii de lămâie și o legătură mică de pătrunjel, pentru servit"]},"howIsMade":{"hi":"हर्ब बटर बनाएं। नर्म मक्खन को बाउल में डालकर बारीक कटी लहसुन, अजमोद, नींबू का रस, 0.5 छोटा चम्मच नमक और 0.25 छोटा चम्मच काली मिर्च के साथ अच्छी तरह फेंटें जब तक सब एकसार न हो जाए। क्लिंग फ़िल्म पर निकालें, 12 सेमी लंबा और 2 सेमी मोटा बेलनाकार आकार दें, कसकर लपेटें और कम-से-कम 1 घंटे फ्रीज़ करें ताकि काटा जा सके इतना सख्त हो जाए।. ठंडे बटर लॉग को 4 बराबर बेलनों में काटें। चिकन तैयार करते समय इन्हें फिर से फ्रीज़र में रखें — बटर बहुत ठंडा होना चाहिए, वरना तलते समय लीक होगा।. तेज़ चाकू से हर चिकन ब्रेस्ट के मोटे साइड में एक गहरा क्षैतिज पॉकेट काटें, विपरीत किनारे से लगभग 1 सेमी पहले रुकें — पूरा न काटें। ब्रेस्ट को किताब की तरह खोलें, दो क्लिंग फ़िल्म के बीच रखें और मीट हथौड़े से बीच से किनारों की ओर हल्के से ठोकें ताकि एकसमान 5 मिमी मोटाई हो जाए। अंदर 1 छोटा चम्मच नमक और 0.5 छोटा चम्मच काली मिर्च से सीज़न करें।. हर पीटे हुए ब्रेस्ट के बीच में एक ठंडा बटर बेलन रखें। बटर के ऊपर दो लंबे किनारे मोड़ें, फिर ब्रेस्ट को कसकर बंद बेलन की तरह रोल करें, हवा निकालने के लिए दबाएं। ढीले फ्लैप नीचे दबा दें। हर पैकेट को क्लिंग फ़िल्म में लपेटकर 30 मिनट फ्रिज में रखें।. तीन उथले कटोरे तैयार करें: एक में मैदा, एक में फेंटे अंडे + पानी, एक में ब्रेड क्रम्ब्स। एक पैकेट लें, मैदे में डुबोएं और अतिरिक्त झाड़ दें, फिर अंडे में डुबोकर अच्छी तरह छानें, फिर ब्रेड क्रम्ब्स में — हर तरफ़ मज़बूती से दबाएं। दूसरी परत के लिए अंडे और क्रम्ब्स में फिर से डुबोएं: यह डबल कोटिंग तलने के समय बटर फटने से रोकती है। बाकी तीन के साथ दोहराएं।. एक गहरे बर्तन में तेल को 170°C तक गरम करें। एक ब्रेड क्रम्ब से जाँच करें — 20 सेकंड में हल्का सुनहरा और चटकदार होना चाहिए। दो Kiev सावधानी से डालें और 6–7 मिनट तक एक बार पलटते हुए तलें जब तक चारों ओर गहरा सुनहरा भूरा क्रस्ट न बन जाए। ट्रे पर रखे रैक पर निकालें। बाकी दो के लिए दोहराएं।. ज़रूरत हो तो ओवन में पूरा करें। तले हुए Kiev को ट्रे पर रखे रैक पर रखें और 180°C (350°F) पर 8–10 मिनट बेक करें, जब तक टेम्परेचर प्रोब को मांस (बटर में नहीं) में डालने पर 70°C आ जाए। इससे क्रस्ट जले बिना चिकन पूरी तरह पक जाता है।. रैक पर 2 मिनट विश्राम दें, फिर प्लेट में रखें। मेज़ पर हर Kiev का ऊपरी हिस्सा छेदें — पिघला हर्ब बटर सुनहरी धारा में बाहर निकलेगा। नींबू के टुकड़े और अजमोद के साथ तुरंत मैश्ड पटैटो या बटर राइस के साथ परोसें।.","en":"Make the herb butter; beat the softened butter in a bowl with the minced garlic, chopped parsley, lemon juice, 0.5 tsp salt, and 0.25 tsp pepper until evenly combined; scrape onto cling film, shape into a 12 cm long, 2 cm thick log, wrap tightly, and freeze for at least 1 hour, until firm enough to slice. Slice the chilled butter log into 4 equal cylinders; return them to the freezer while you prepare the chicken — the butter must be very cold or it will leak out during frying. With a sharp knife, cut a deep horizontal pocket into the thick side of each chicken breast, stopping about 1 cm before the opposite edge — do not cut through; open the breast like a book, lay it between two sheets of cling film, and pound gently with a meat mallet to an even 5 mm thickness, working from the centre outwards; season the inside with 1 tsp salt and 0.5 tsp pepper. Place one cold butter cylinder along the centre of each pounded breast; fold the two long sides over the butter, then roll the breast tightly into a sealed cylinder, pressing to expel air; tuck any loose flaps underneath; wrap each parcel in cling film and refrigerate for 30 minutes. Set up three shallow bowls: one with the flour, one with the beaten eggs and water, one with the breadcrumbs; take a parcel, dip in flour and pat off excess, then egg, draining well, then breadcrumbs — press firmly on all sides; dip the egg and breadcrumbs again for a second coat: this double coat is what stops the butter from blowing out during frying; repeat with the other three. Heat the oil in a deep pan to 170°C; test with a breadcrumb — it should sizzle and turn pale gold in 20 seconds; lower two Kievs in carefully and fry for 6–7 minutes, turning once, until the crust is deeply golden brown all over; lift onto a wire rack set over a tray; repeat with the other two. Finish in the oven if needed; place the fried Kievs on a rack over a baking tray and bake at 180°C (350°F) for 8–10 minutes, until a temperature probe pushed into the chicken (not the butter) reads 70°C; this ensures the chicken is cooked through without overcooking the crust. Rest for 2 minutes on the rack, then plate; pierce the top of each Kiev at the table — the molten herb butter will spill out in a golden stream; serve immediately with lemon wedges and parsley, alongside mashed potatoes or buttered rice."}},{"id":139,"origin":{"hi":"लिथुआनिया","en":"Lithuania","ro":"Lituania"},"name":{"hi":"त्सेपेलिनाई","en":"Cepelinai","ro":"Cepelinai"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"hi":["1.5 किलो कच्चे वैक्सी आलू (Yukon Gold या समान), छीलकर वज़न लिया हुआ","500 ग्राम आटा-वाले (फ्लोरी) आलू (Russet या King Edward), छीलकर वज़न लिया हुआ","1 बड़ा चम्मच नींबू का रस या 1 छोटा चम्मच सिट्रिक एसिड (कच्चे कद्दूकस आलू को सलेटी होने से रोकने के लिए)","आटे के लिए 1 छोटा चम्मच बारीक समुद्री नमक","2 बड़े चम्मच कॉर्नफ्लोर — केवल अगर कच्चा आलू बहुत गीला हो","मोटे कीमे किए सूअर के कंधे का 500 ग्राम (या 50% सूअर + 50% गोमांस)","1 मध्यम प्याज़ (लगभग 150 ग्राम), बहुत बारीक कटा","भरावन के लिए 1 छोटा चम्मच बारीक समुद्री नमक","0.5 छोटा चम्मच ताज़ी पिसी काली मिर्च","1 छोटा चम्मच सूखी मार्जोरम या सूखी सेवरी","भरावन के लिए 60 मिली ठंडा पानी","200 ग्राम स्मोक्ड स्ट्रीकी बेकन, क्यूब्स में कटा","1 बड़ा प्याज़ (लगभग 200 ग्राम), पतले स्लाइस","200 ग्राम फुल-फैट खट्टी क्रीम","ताज़ा डिल या पार्सले, बारीक कटा, सजावट के लिए","उबालने के पानी के लिए 1 बड़ा चम्मच मोटा समुद्री नमक"],"en":["1.5 kg raw waxy potatoes (Yukon Gold or similar), peeled and weighed","500 g floury potatoes (Russet or King Edward), peeled and weighed","1 tbsp lemon juice or 1 tsp citric acid (to prevent the raw grated potato from greying)","1 tsp fine sea salt for the dough","2 tbsp cornflour (cornstarch) — only if the raw potato is very wet","500 g coarsely minced pork shoulder (or 50% pork + 50% beef)","1 medium onion (about 150 g), very finely diced","1 tsp fine sea salt for the filling","0.5 tsp freshly ground black pepper","1 tsp dried marjoram or dried savory","60 ml cold water for the filling","200 g smoked streaky bacon, cubed","1 large onion (about 200 g), finely sliced","200 g full-fat sour cream","Dill or parsley, finely chopped, to garnish","1 tbsp coarse sea salt for the cooking water"],"ro":["1,5 kg cartofi cu pastă fermă (Yukon Gold sau similari), curățați și cântăriți după curățare","500 g cartofi făinoși (Russet sau King Edward), curățați și cântăriți după curățare","1 lingură suc de lămâie sau 1 linguriță acid citric (pentru a împiedica înnegrirea cartofului ras crud)","1 linguriță sare fină de mare pentru aluat","2 linguri amidon de porumb — doar dacă aluatul rămâne prea umed","500 g carne de porc tocată grosier (sau 50% porc + 50% vită)","1 ceapă medie (aproximativ 150 g), tocată foarte fin","1 linguriță sare fină de mare pentru umplutură","0,5 linguriță piper negru proaspăt măcinat","1 linguriță maghiran uscat sau cimbru de munte uscat","60 ml apă rece pentru umplutură","200 g bacon afumat striat, tăiat cuburi","1 ceapă mare (aproximativ 200 g), feliată fin","200 g smântână grasă","Mărar sau pătrunjel, tocat fin, pentru garnitură","1 lingură sare grunjoasă de mare pentru apa de fierbere"]},"howIsMade":{"hi":"पहले भरावन बनाएं ताकि स्वाद घुलकर बैठ जाएँ। एक बाउल में सूअर का कीमा, बारीक कटी प्याज़, 1 छोटा चम्मच नमक, काली मिर्च, मार्जोरम और 60 मिली ठंडा पानी डालें और हाथ से 1–2 मिनट तब तक मिलाएं जब तक मिश्रण चिपचिपा और अच्छी तरह बंध न जाए। ढककर फ्रिज में रखें, इसी बीच आलू का आटा तैयार करें।. 500 ग्राम आटा-वाले आलू को साबुत, बिना छिले, नमक के पानी में 25–30 मिनट तक नरम होने तक उबालें। पानी निथार कर गर्म में ही छील लें और राइसर से पीस लें या बारीक मैश कर लें। एक ट्रे पर फैलाकर कमरे के तापमान तक ठंडा करें — गर्म मैश अगले चरण में कच्चा आलू पका देगा।. एक बड़े बाउल में साफ़ रसोई के कपड़े पर 1.5 किलो कच्चे आलू को बॉक्स कद्दूकस के बारीक हिस्से से कद्दूकस करें। कपड़े को इकट्ठा करके दूसरे बाउल के ऊपर ज़ोर से निचोड़ें ताकि अधिक-से-अधिक रस निकल जाए। आपको लगभग 250 मिली रस मिलेगा; 5 मिनट के लिए छोड़ दें।. ध्यान से रस वाले बाउल का साफ़ पानी निकाल दें और तले में बैठा सफेद स्टार्च छोड़ दें। इस स्टार्च को निचोड़े आलू में वापस खुरचकर डालें — यह वही प्राकृतिक बाइंडर है जो cepelinai को जोड़े रखता है। ठंडा किया हुआ मैश, नींबू का रस और 1 छोटा चम्मच नमक मिलाएं। हाथ से 2–3 मिनट ज़ोर से गूँथें ताकि चिपचिपा और लचीला आटा बने। अगर आटा अभी भी बहुत गीला हो तभी कॉर्नफ्लोर डालें।. गीले हाथों से आटे को 8 बराबर भागों में बाँटें (हर एक लगभग 220 ग्राम)। एक टुकड़े को गीली हथेली पर 12 × 8 सेमी अंडाकार में चपटा करें, बीच में लगभग 60 ग्राम ठंडी भरावन रखें, फिर आटे को ऊपर लाकर भरावन के चारों ओर लपेटें और किनारों को कसकर सील करें। 12 सेमी की ज़ेपलिन आकृति में बनाएं, जिसमें कोई दरार न हो जहाँ से भाप या पानी अंदर जा सके।. एक चौड़े गहरे बर्तन में 4 लीटर पानी और 1 बड़ा चम्मच मोटा नमक डालकर हल्के उबाल पर लाएं (तेज़ खौलते पानी से cepelinai टूट जाएंगे)। 2 बैच में cepelinai डालें, बेस से चिपकने से बचाने के लिए हल्के से एक बार चलाएं और सबसे हल्के उबाल पर 25–30 मिनट पकाएं, जब तक सतह मैट से पारदर्शी न हो जाए और cepelinai ऊपर तैरने लगें।. पकते समय सॉस बनाएं। बेकन के क्यूब्स को सूखी फ्राइंग पैन में मध्यम आंच पर 6–8 मिनट तब तक भूनें जब तक चर्बी निकल जाए और क्यूब्स कुरकुरे हों। कटा प्याज़ डालें और 5–6 मिनट और पकाएं जब तक नर्म और हल्का सुनहरा न हो जाए। आंच बंद करें, मिलाएं और गरम रखें।. पके cepelinai को छन्नी कलछी से गर्म प्लेटों में निकालें — हर व्यक्ति के लिए 2। बेकन-प्याज़ मिश्रण और उसकी चर्बी से उदारता से छिड़कें, ठंडी खट्टी क्रीम की बड़ी चम्मच ऊपर रखें और कटा डिल छिड़ककर खत्म करें। जब तक सब कुछ गरम है और अंदर रसीला है, तुरंत परोसें।.","en":"Make the filling first so the flavours marry; mix the minced pork, finely diced onion, 1 tsp salt, pepper, marjoram, and 60 ml cold water in a bowl with your hand for 1–2 minutes, until the mixture is sticky and well bound; cover and chill while you prepare the potato dough. Boil the 500 g floury potatoes whole and unpeeled in salted water for 25–30 minutes, until very tender; drain, peel while hot, and pass through a ricer or mash smoothly; spread out on a tray to cool to room temperature — hot mash would cook the raw potato in the next step. Grate the 1.5 kg waxy potatoes on the fine side of a box grater into a large bowl lined with a clean kitchen towel; gather the towel and squeeze hard over a second bowl to extract as much liquid as possible; you should end up with about 250 ml of liquid; leave it to settle for 5 minutes. Carefully pour off the clear water from the bowl of squeezed liquid, leaving the white starch settled at the bottom; scrape this starch back into the squeezed grated potato — it is the natural binder that holds the dumplings together; add the cooled mashed potato, the lemon juice, and 1 tsp salt; mix vigorously by hand for 2–3 minutes, until you have a sticky, elastic dough; add the cornflour only if the dough still feels wet. With wet hands, divide the dough into 8 equal pieces (about 220 g each); flatten one piece on a wet palm into a 12 × 8 cm oval, place about 60 g of the chilled filling in the centre, then wrap the dough up and around the filling, pinching to seal completely; smooth into a 12 cm zeppelin shape, with no cracks where steam or water could enter. Bring a wide deep pan with 4 litres of water and 1 tbsp coarse salt to a gentle simmer (not a rolling boil — vigorous water can break the dumplings); lower the cepelinai in 2 batches, stir gently once to keep them off the base, and cook for 25–30 minutes at the gentlest simmer, until the surface goes from matte to translucent and the dumplings float high. While they cook, make the sauce; cook the cubed bacon in a dry frying pan over medium heat for 6–8 minutes until the fat renders and the cubes are crisp; add the sliced onion and cook for another 5–6 minutes until soft and lightly golden; stir off the heat and keep warm. Lift the cooked cepelinai out with a slotted spoon onto warmed plates — 2 per person; scatter generously with the bacon-onion mixture and its fat, top with a heap of cold sour cream, and finish with chopped dill; serve immediately while everything is hot and the centres are juicy."}},{"id":140,"origin":{"hi":"फ़्रांस","en":"France","ro":"Franța"},"name":{"hi":"चिकन फ्रिकासी","en":"Chicken Fricassée","ro":"Fricassée de Poulet"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"french","ingredients":{"hi":["1.5 किलो हड्डी और चमड़ी सहित चिकन की जांघें और टांगें (लगभग 8 टुकड़े), या 1.5 किलो पूरा चिकन 8 भागों में कटा हुआ","1 छोटा चम्मच बारीक समुद्री नमक + 0.5 छोटा चम्मच ताज़ी पिसी सफ़ेद मिर्च (काली मिर्च चल जाएगी पर सॉस में दाने दिखेंगे)","60 ग्राम अनसाल्टेड मक्खन, 30 ग्राम + 30 ग्राम में बाँटा हुआ","2 बड़े चम्मच न्यूट्रल तेल","250 ग्राम पर्ल प्याज़ या छोटे शैलट, छीले हुए (या 1 मध्यम प्याज़ बारीक कटा)","200 ग्राम सफ़ेद या भूरे मशरूम, बड़े हों तो आधे या चौथाई काटे","2 मध्यम गाजर (लगभग 200 ग्राम), छीलकर 5 सेमी बैटन में कटी","2 लहसुन की कलियाँ, बारीक कटी","30 ग्राम साधारण मैदा","150 मिली ड्राई सफ़ेद वाइन (Riesling या Sauvignon Blanc)","500 मिली बिना नमक का गर्म चिकन स्टॉक","1 छोटा बूके गारनी (1 तेजपत्ता + 4 थाइम की डंडी + 4 पार्सले के डंठल, धागे से बँधे)","200 मिली डबल क्रीम (35% फ़ैट या ज़्यादा), अधिक रिच लिएज़ोन के लिए वैकल्पिक 2 अंडे की जर्दी","1 बड़ा चम्मच ताज़ा नींबू का रस","2 बड़े चम्मच बारीक कटा ताज़ा फ्लैट-लीफ पार्सले, सजावट के लिए"],"en":["1.5 kg bone-in skin-on chicken thighs and drumsticks (about 8 pieces), or a 1.5 kg whole chicken jointed into 8","1 tsp fine sea salt + 0.5 tsp freshly ground white pepper (black pepper works but speckles the sauce)","60 g unsalted butter, divided into 30 g + 30 g","2 tbsp neutral oil","250 g pearl onions or small shallots, peeled (or 1 medium onion finely diced)","200 g chestnut or button mushrooms, halved or quartered if large","2 medium carrots (about 200 g), peeled and cut into 5 cm batons","2 garlic cloves, finely minced","30 g plain (all-purpose) flour","150 ml dry white wine (Riesling or Sauvignon Blanc)","500 ml hot unsalted chicken stock","1 small bouquet garni (1 bay leaf + 4 thyme sprigs + 4 parsley stalks tied with string)","200 ml double cream (heavy cream, 35% fat or higher), plus 2 optional egg yolks for a richer liaison","1 tbsp fresh lemon juice","2 tbsp finely chopped fresh flat-leaf parsley, to garnish"],"ro":["1,5 kg pulpe și copane de pui cu os și piele (aproximativ 8 bucăți) sau 1,5 kg pui întreg dezasamblat în 8 bucăți","1 linguriță sare fină de mare + 0,5 linguriță piper alb proaspăt măcinat (piperul negru funcționează dar pătează sosul)","60 g unt nesărat, împărțit în două porții de 30 g","2 linguri ulei neutru","250 g cepe de primăvară sau eșalote mici, decojite (sau 1 ceapă medie tocată fin)","200 g ciuperci champignon (albe sau brune), tăiate în jumătăți sau sferturi dacă sunt mari","2 morcovi medii (aproximativ 200 g), curățați și tăiați bastonașe de 5 cm","2 căței de usturoi, tocați fin","30 g făină albă obișnuită","150 ml vin alb sec (Riesling sau Sauvignon Blanc)","500 ml supă de pui fierbinte nesărată","1 bouquet garni mic (1 foaie de dafin + 4 crenguțe de cimbru + 4 cozi de pătrunjel legate cu sfoară)","200 ml smântână grasă (cel puțin 35% grăsime), plus 2 gălbenușuri opționale pentru o legătură mai bogată","1 lingură suc de lămâie proaspăt","2 linguri pătrunjel proaspăt cu frunze plate, tocat fin, pentru garnitură"]},"howIsMade":{"hi":"चिकन के टुकड़ों को किचन पेपर से थपथपा कर सुखाएं और दोनों तरफ़ 1 छोटा चम्मच नमक और सफेद मिर्च लगाकर सीज़न करें। 15 मिनट कमरे के तापमान पर रखें।. 28 सेमी भारी सॉटे पैन या डच ओवन में 30 ग्राम मक्खन और 2 बड़े चम्मच तेल मध्यम आंच पर पिघलाएं। मक्खन झाग देने लगे तो चिकन को चमड़ी की तरफ़ नीचे रखकर एक परत में (ज़रूरत हो तो बैच में) रखें और दोनों तरफ़ से 5–6 मिनट सेकें — सतह हल्के सुनहरे रंग की होनी चाहिए, भूरी नहीं। भूरी क्रस्ट सॉस को गंदा कर देगी। प्लेट में निकालें।. आंच मध्यम-कम कर दें। उसी पैन में पर्ल प्याज़ डालें और 5–6 मिनट चलाते हुए तब तक भूनें जब तक हल्के सुनहरे हों पर अभी भी हल्के रंग के दिखें। चिकन वाली प्लेट में निकालें।. पैन में गाजर और मशरूम डालें और 4–5 मिनट पकाएं — मशरूम पहले पानी छोड़ेंगे फिर वही पानी खींच लेंगे। लहसुन डालकर 30 सेकंड चलाएं।. सब्ज़ियों पर मैदा छिड़कें और 2 मिनट लगातार चलाएं ताकि कच्चे आटे का स्वाद खत्म हो जाए — सब्ज़ियों के चारों तरफ़ हल्का रू बनेगा। सफ़ेद वाइन डालें और तेज़ी से उबाल पर लाएं, नीचे की चिपकी हुई कोटिंग खुरचते हुए, और आधा रहने तक (1–2 मिनट) रिड्यूस करें।. चिकन और पर्ल प्याज़ को एक परत में वापस पैन में रखें। गर्म स्टॉक लगभग ढकने तक डालें, बूके गारनी डालें और सबसे हल्के उबाल पर लाएं। ढककर जांघों के लिए 30–35 मिनट (या पहले निकाले गए ब्रेस्ट के लिए 25 मिनट) पकाएं, जब तक मांस हड्डी से आसानी से अलग न हो और भीतर का तापमान 75°C न हो जाए।. चिकन और सब्ज़ियों को गर्म डिश में निकालें और एल्युमिनियम फ़ॉइल से ढकें। बूके गारनी निकाल कर फेंक दें। मध्यम आंच पर सॉस को तेज़ी से उबालें और 3–5 मिनट तक रिड्यूस करें जब तक यह चम्मच की पीठ को कोट करे (लगभग 350 मिली)।. लिएज़ोन बनाएं। छोटे बाउल में क्रीम और अंडे की जर्दी को फेंट लें। एक करछुल गरम सॉस मिलाकर तापमान संतुलित करें, फिर आंच बंद करके टेम्पर किए मिश्रण को सॉस में वापस डालें। धीरे से मिलाएं — उबालें नहीं, वरना ज़र्दी फट जाएगी। नींबू का रस डालें, चखकर नमक सेट करें। चिकन के ऊपर डालें, कटा पार्सले छिड़कें और चावल, बटर नूडल्स या स्टीम्ड आलू के साथ तुरंत परोसें।.","en":"Pat the chicken pieces dry with paper towels and season both sides with 1 tsp salt and the white pepper; rest at room temperature for 15 minutes. Heat 30 g of the butter and 2 tbsp oil in a wide 28 cm heavy-based sauté pan or Dutch oven over medium heat; when the butter foams, add the chicken skin-side down in one layer (work in batches if needed) and cook 5–6 minutes per side — the surface should turn pale gold and gilded, NOT brown; a brown crust would muddy the sauce; lift onto a plate. Reduce the heat to medium-low; add the pearl onions to the same pan and cook for 5–6 minutes, stirring, until lightly gilded but still pale; lift onto the plate with the chicken. Add the carrots and mushrooms to the pan and cook for 4–5 minutes — the mushrooms will release their water and reabsorb it; add the garlic and stir for 30 seconds. Sprinkle the flour over the vegetables and stir constantly for 2 minutes to cook out the raw taste — a pale roux will form around the vegetables; pour in the wine and bring to a brisk simmer, scraping up any sediment from the pan base, until reduced by half (1–2 minutes). Return the chicken and pearl onions to the pan in a single layer; pour in the hot stock to nearly cover, tuck in the bouquet garni, and bring to the gentlest simmer; cover and cook for 30–35 minutes for thighs (or 25 minutes for breasts removed earlier), until the meat pulls easily from the bone and the internal temperature reads 75°C. Lift the chicken and vegetables to a warmed dish and cover with foil; discard the bouquet garni; bring the sauce to a brisk simmer over medium heat and reduce for 3–5 minutes, until it coats the back of a spoon (about 350 ml). Make the liaison; whisk the cream and egg yolks together in a small bowl; whisk in a ladle of hot sauce to temper, then pour the tempered mixture back into the pan off the heat; stir gently — DO NOT BOIL, or the yolks will scramble; add the lemon juice, taste and adjust the salt; pour over the chicken, scatter with chopped parsley, and serve immediately with rice, buttered noodles, or steamed potatoes."}},{"id":141,"origin":{"hi":"कुवैत","en":"Kuwait","ro":"Kuweit"},"name":{"hi":"मचबूस","en":"Machboos","ro":"Machboos"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"middle-eastern","ingredients":{"hi":["1.5 किलो हड्डी और चमड़ी सहित चिकन की जांघें और टांगें (या 1.2 किलो हड्डी सहित मेमने का कंधा 6 सेमी टुकड़ों में कटा)","400 ग्राम बासमती चावल, धोकर ठंडे पानी में 30 मिनट भिगोकर छाने हुए","60 मिली न्यूट्रल तेल (या 30 ग्राम घी + 2 बड़े चम्मच तेल, अधिक भरपूर स्वाद के लिए)","3 बड़े प्याज़ (लगभग 600 ग्राम), पतले कटे — परोसने के लिए थोड़ा कच्चा रख लें","6 लहसुन की कलियाँ, बारीक कटी","अंगूठे के आकार का ताज़ा अदरक (लगभग 30 ग्राम), बारीक कद्दूकस","3 मध्यम टमाटर (लगभग 300 ग्राम), कद्दूकस किए (या 200 ग्राम डिब्बाबंद कुटे टमाटर)","2 बड़े चम्मच टमाटर पेस्ट","2 सूखे नींबू (loomi), चाकू से 3 जगह छेद किए (या कम पारंपरिक विकल्प के रूप में 2 बड़े चम्मच ताज़ा नींबू/लाइम का रस)","1 बड़ा चम्मच बहारात मसाला (या 1 छोटा चम्मच पिसी दालचीनी + 1 छोटा चम्मच पिसा जीरा + 1 छोटा चम्मच पिसा धनिया + 0.5 छोटा चम्मच पिसी इलायची + 0.5 छोटा चम्मच पिसी काली मिर्च)","0.5 छोटा चम्मच पिसी हल्दी","4 साबुत हरी इलायची की फलियाँ, हल्की चटकाई हुई + 1 दालचीनी का टुकड़ा (5 सेमी) + 4 साबुत लौंग + 2 तेजपत्ते","1 छोटा गुच्छा ताज़ा हरा धनिया (लगभग 30 ग्राम), तने बारीक कटकर बर्तन में, पत्ते सजावट के लिए सुरक्षित","2 ताज़ी हरी मिर्चें, लंबाई में चीरी हुई","1.2 लीटर गरम पानी (या अधिक गहरे स्वाद के लिए बिना नमक का चिकन स्टॉक)","1.5 छोटे चम्मच बारीक समुद्री नमक, स्वादानुसार और","60 ग्राम बादाम स्लाइस और 40 ग्राम सुनहरी किशमिश, 1 छोटे चम्मच घी में हल्के भुने (ऊपर से छिड़कने के लिए)","0.5 छोटा चम्मच केसर के रेशे, 2 बड़े चम्मच गुनगुने पानी में भिगोए (वैकल्पिक, चावल को सजाने के लिए)"],"en":["1.5 kg bone-in skin-on chicken thighs and drumsticks (or 1.2 kg bone-in lamb shoulder cut into 6 cm chunks)","400 g basmati rice, rinsed and soaked in cold water for 30 minutes, then drained","60 ml neutral oil (or 30 g ghee + 2 tbsp oil for a richer flavour)","3 large onions (about 600 g), finely sliced — reserve a small handful raw for serving","6 garlic cloves, finely chopped","1 thumb-sized piece of fresh ginger (about 30 g), finely grated","3 medium tomatoes (about 300 g), grated (or 200 g canned chopped tomatoes)","2 tbsp tomato paste","2 dried limes (loomi), pierced with a knife in 3 places (or 2 tbsp fresh lime juice as a less-traditional substitute)","1 tbsp baharat (or 1 tsp ground cinnamon + 1 tsp ground cumin + 1 tsp ground coriander + 0.5 tsp ground cardamom + 0.5 tsp ground black pepper)","0.5 tsp ground turmeric","4 whole green cardamom pods, lightly cracked + 1 cinnamon stick (5 cm) + 4 whole cloves + 2 bay leaves","1 small bunch fresh coriander (about 30 g), stems chopped fine for the pot, leaves reserved for garnish","2 fresh green chillies, slit lengthwise","1.2 litres hot water (or unsalted chicken stock for more depth)","1.5 tsp fine sea salt, plus more to taste","60 g flaked almonds and 40 g sultanas, lightly toasted in 1 tsp ghee (to scatter on top)","0.5 tsp saffron threads soaked in 2 tbsp warm water (optional, for finishing the rice)"],"ro":["1,5 kg pulpe și copane de pui cu os și piele (sau 1,2 kg umăr de miel cu os tăiat bucăți de 6 cm)","400 g orez basmati, clătit și înmuiat în apă rece 30 de minute, apoi scurs","60 ml ulei neutru (sau 30 g ghee + 2 linguri ulei pentru aromă mai bogată)","3 cepe mari (aproximativ 600 g), feliate fin — păstrează o mică parte crudă pentru servit","6 căței de usturoi, tocați fin","O bucată de ghimbir proaspăt cât degetul mare (aproximativ 30 g), ras fin","3 roșii medii (aproximativ 300 g), date pe răzătoare (sau 200 g roșii sfărâmate din conservă)","2 linguri pastă de roșii","2 lămâi uscate (loomi), înțepate cu cuțitul în 3 locuri (sau 2 linguri suc proaspăt de lime ca substitut mai puțin tradițional)","1 lingură baharat (sau 1 linguriță scorțișoară măcinată + 1 linguriță chimion măcinat + 1 linguriță coriandru măcinat + 0,5 linguriță cardamom măcinat + 0,5 linguriță piper negru măcinat)","0,5 linguriță turmeric măcinat","4 capsule întregi de cardamom verde, ușor crăpate + 1 baton de scorțișoară (5 cm) + 4 cuișoare + 2 foi de dafin","1 legătură mică de coriandru proaspăt (aproximativ 30 g), tijele tocate fin pentru oală, frunzele păstrate pentru garnitură","2 ardei iuți verzi proaspeți, crestați pe lungime","1,2 litri apă fierbinte (sau supă de pui nesărată pentru profunzime)","1,5 lingurițe sare fină de mare, plus după gust","60 g migdale feliate și 40 g stafide blonde, ușor prăjite în 1 linguriță ghee (pentru deasupra)","0,5 linguriță fire de șofran înmuiate în 2 linguri apă caldă (opțional, pentru finisarea orezului)"]},"howIsMade":{"hi":"बासमती चावल को ठंडे बहते पानी के नीचे तब तक धोएं जब तक पानी लगभग साफ़ न निकले, फिर ताज़ा ठंडे पानी में 30 मिनट भिगो दें। इससे अतिरिक्त स्टार्च निकलता है और अंतिम पकाने का समय कम हो जाता है। उपयोग से ठीक पहले छान लें।. चिकन के टुकड़े सुखाएं और 0.5 छोटा चम्मच नमक से सीज़न करें। 28 सेमी भारी बर्तन में तेल (या घी + तेल) को मध्यम-तेज़ आंच पर गरम करें। तेल चमकने लगे तो चिकन को चमड़ी की तरफ़ नीचे करके रखें और हर तरफ़ 4–5 मिनट तक गहरा सुनहरा होने तक सीयरिंग करें। प्लेट में निकालें।. आंच मध्यम कर दें। उसी बर्तन में कटी प्याज़ और एक चुटकी नमक डालें और 12–15 मिनट तक बार-बार चलाते हुए तब तक भूनें जब तक गहरी सुनहरी और बहुत नर्म न हो जाए। लहसुन और अदरक डालें और 1 मिनट खुशबू आने तक भूनें।. इलायची की फलियाँ, दालचीनी का टुकड़ा, लौंग, तेजपत्ते, बहारात और हल्दी डालें। 30 सेकंड भूनें — मसाले खुशबूदार हो जाएँगे और रंग गहरा करेंगे। टमाटर पेस्ट और कद्दूकस किए टमाटर डालें और 4–5 मिनट चलाते हुए पकाएं जब तक मिश्रण गहरा लाल न हो और तेल किनारों से अलग न हो जाए।. चिकन को एक परत में बर्तन में वापस डालें। गरम पानी (या स्टॉक) डालें, सूखे नींबू, चीरी हुई मिर्चें, कटे हरे धनिए के तने और बचा नमक डालें। हल्के उबाल पर लाएं, ढक्कन लगाएं, सबसे धीमी आंच कर दें और चिकन के लिए 35–40 मिनट (या मेमने के लिए 1 घंटा 30 मिनट) तक पकाएं जब तक मांस आसानी से हड्डी से अलग न हो और शोरबा गहरा सुगंधित न हो जाए।. चिकन को प्लेट में निकालें और गर्म रखने के लिए हल्के से एल्युमिनियम फ़ॉइल से ढक दें। शोरबे की ऊपर की अतिरिक्त चर्बी हटा दें।. छाने हुए चावल को बर्तन में डालें, हल्के से दबाकर शोरबा बस ढक जाए (ज़रूरत हो तो गरम पानी डालें — चावल के ऊपर लगभग 2.5 सेमी तरल रहना चाहिए)। फिर हल्के उबाल पर लाएं, कसकर ढकें, सबसे धीमी आंच कर दें और बिना छुए 18 मिनट पकाएं।. आंच बंद करें। केसर वाला पानी (अगर उपयोग कर रहे हैं) चावल के ऊपर छिड़कें, चिकन के टुकड़े ऊपर रखें, ढक्कन वापस लगाएं और 10 मिनट विश्राम दें — भाप चिकन को पूरी तरह पका देती है और चावल के दाने अलग हो जाते हैं। चावल को कांटे से हल्के से फुलाएं, चौड़ी प्लेट पर पलटें, चिकन ऊपर रखें और भुने बादाम, किशमिश, कच्ची प्याज़ के टुकड़े और ताज़े धनिए के पत्ते छिड़कें। deeba (इमली की चटनी) या दही के साथ परोसें।.","en":"Rinse the basmati rice under cold running water until the water runs almost clear, then soak in fresh cold water for 30 minutes; this removes excess starch and shortens the final cooking step; drain just before use. Pat the chicken pieces dry and season with 0.5 tsp of the salt; heat the oil (or ghee + oil) in a heavy 28 cm pot over medium-high heat; when shimmering, add the chicken skin-side down and sear for 4–5 minutes per side until deep golden; lift onto a plate. Reduce the heat to medium; add the sliced onions and a pinch of salt to the same pot and cook for 12–15 minutes, stirring often, until deeply golden and very soft; add the garlic and ginger and cook for 1 minute until fragrant. Stir in the cardamom pods, cinnamon stick, cloves, bay leaves, baharat, and turmeric; toast for 30 seconds — the spices should turn aromatic and deepen in colour; add the tomato paste and grated tomatoes and cook, stirring, for 4–5 minutes, until the mixture darkens to a rich red and the oil splits out around the edges. Return the chicken to the pot in a single layer; pour in the hot water (or stock), add the dried limes, slit chillies, chopped coriander stems, and remaining salt; bring to a gentle boil, then cover, reduce to the lowest simmer, and cook for 35–40 minutes (chicken) or 1 h 30 min (lamb), until the meat is fork-tender and the broth is deeply flavoured. Lift the chicken onto a plate and cover loosely with foil to keep warm; skim any excess fat from the broth. Add the drained rice to the pot, gently pushing it down so it is just covered by the broth (top up with hot water if needed — you want about 2.5 cm of liquid above the rice); bring back to a gentle boil, then cover with a tight lid, reduce to the lowest possible heat, and cook undisturbed for 18 minutes. Turn off the heat; drizzle the saffron water (if using) over the rice, place the chicken pieces on top, replace the lid, and rest for 10 minutes — the steam finishes cooking the chicken and the rice grains separate; fluff the rice with a fork, transfer to a wide platter with the chicken on top, and scatter with toasted almonds, sultanas, raw onion slices, and fresh coriander leaves; serve with deeba (tamarind sauce) or yoghurt on the side."}},{"id":142,"origin":{"hi":"कांगो गणराज्य","en":"Republic of the Congo","ro":"Republica Congo"},"name":{"hi":"मोअम्बे चिकन","en":"Moambe chicken","ro":"Pui Moambe"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"hi":["1.5 किलो हड्डी और चमड़ी सहित चिकन की जांघें और टांगें (लगभग 8 टुकड़े)","चिकन के लिए 1 छोटा चम्मच बारीक समुद्री नमक + 0.5 छोटा चम्मच ताज़ी पिसी काली मिर्च","60 मिली लाल पाम तेल (या स्वाद बहुत तेज़ हो तो 30 मिली पाम तेल + 2 बड़े चम्मच न्यूट्रल तेल)","2 बड़े प्याज़ (लगभग 400 ग्राम), बारीक कटे","6 लहसुन की कलियाँ, बारीक कटी","अंगूठे के आकार का ताज़ा अदरक (लगभग 20 ग्राम), बारीक कद्दूकस","400 ग्राम पके टमाटर, कद्दूकस किए हुए, या 1 × 400 ग्राम डिब्बाबंद कुटे टमाटर","2 बड़े चम्मच टमाटर पेस्ट","100 ग्राम बिना मीठा चिकना पीनट बटर (या उपलब्ध हो तो 200 ग्राम डिब्बाबंद moambe पाम पेस्ट)","2 ताज़ी scotch bonnet या habanero मिर्चें, लंबाई में चीरी हुई (या 1 छोटा चम्मच सूखी मिर्च के फ्लेक्स; स्वादानुसार समायोजित करें — moambe तीखा होता है)","2 तेजपत्ते","500 मिली बिना नमक का गरम चिकन स्टॉक या पानी","1.5 छोटे चम्मच बारीक समुद्री नमक, स्वादानुसार और","2 बड़े चम्मच बारीक कटी फ्लैट-लीफ पार्सले (या 2 बड़े चम्मच लेमन बेसिल), सजावट के लिए","भापी सफ़ेद चावल, fufu, या उबली plantain, परोसने के लिए"],"en":["1.5 kg bone-in skin-on chicken thighs and drumsticks (about 8 pieces)","1 tsp fine sea salt + 0.5 tsp freshly ground black pepper for the chicken","60 ml red palm oil (or 30 ml palm + 2 tbsp neutral oil if the flavour is too strong)","2 large onions (about 400 g), finely diced","6 garlic cloves, finely chopped","1 thumb-sized piece of fresh ginger (about 20 g), finely grated","400 g ripe tomatoes, grated, or 1 × 400 g can chopped tomatoes","2 tbsp tomato paste","100 g unsweetened smooth peanut butter (or 200 g canned moambe palm paste when available)","2 fresh scotch bonnet or habanero chillies, slit lengthwise (or 1 tsp dried chilli flakes; adjust to taste — moambe is hot)","2 bay leaves","500 ml hot unsalted chicken stock or water","1.5 tsp fine sea salt, plus more to taste","2 tbsp finely chopped flat-leaf parsley (or 2 tbsp lemon basil), to garnish","Steamed white rice, fufu, or boiled plantains, to serve"],"ro":["1,5 kg pulpe și copane de pui cu os și piele (aproximativ 8 bucăți)","1 linguriță sare fină de mare + 0,5 linguriță piper negru proaspăt măcinat pentru pui","60 ml ulei de palmier roșu (sau 30 ml palmier + 2 linguri ulei neutru dacă aroma e prea puternică)","2 cepe mari (aproximativ 400 g), tocate fin","6 căței de usturoi, tocați fin","O bucată de ghimbir proaspăt cât degetul mare (aproximativ 20 g), ras fin","400 g roșii coapte, date pe răzătoare (sau 1 × 400 g conservă de roșii tocate)","2 linguri pastă de roșii","100 g unt de arahide neîndulcit, fin (sau 200 g pastă de moambe la conservă, când e disponibilă)","2 ardei iuți proaspeți scotch bonnet sau habanero, crestați pe lungime (sau 1 linguriță fulgi de ardei iute; ajustează după gust — muambe este picant)","2 foi de dafin","500 ml supă de pui fierbinte nesărată sau apă","1,5 lingurițe sare fină de mare, plus după gust","2 linguri pătrunjel cu frunze plate tocat fin (sau 2 linguri busuioc de lămâie), pentru garnitură","Orez alb fiert, fufu sau banane plantain fierte, pentru servit"]},"howIsMade":{"hi":"चिकन के टुकड़े सुखाएं और दोनों तरफ़ 1 छोटा चम्मच नमक और 0.5 छोटा चम्मच काली मिर्च लगाएं। 15 मिनट कमरे के तापमान पर रखें।. 28 सेमी भारी बर्तन में पाम तेल मध्यम-तेज़ आंच पर गरम करें — पाम तेल गहरे नारंगी-लाल तरल में पिघलता है। तेल चमकने लगे तो चिकन को चमड़ी की तरफ़ नीचे करके एक परत में रखें (ज़रूरत हो तो दो बैच में) और हर तरफ़ 4–5 मिनट तक तब तक सीयरिंग करें जब तक चमड़ी गहरी सुनहरी न हो जाए। प्लेट में निकालें।. आंच मध्यम कर दें। उसी बर्तन में कटी प्याज़ और एक चुटकी नमक डालें और 8–10 मिनट तक बार-बार चलाते हुए तब तक भूनें जब तक नर्म, चमकदार और हल्की सुनहरी न हो जाएं (भूरी न पड़ें)।. लहसुन और अदरक डालें और 1 मिनट खुशबू आने तक भूनें। टमाटर पेस्ट और कद्दूकस किए टमाटर डालें और 5–6 मिनट चलाते हुए पकाएं जब तक मिश्रण गहरा ईंट-लाल न हो जाए और पाम तेल किनारों से अलग होने लगे — यह तेल अलगाव moambe की पहचान है।. एक छोटे बाउल में पीनट बटर को 200 मिली गरम स्टॉक के साथ चिकना होने तक फेंट लें, फिर बर्तन में डालकर मिलाएं। बचा हुआ 300 मिली स्टॉक, तेजपत्ते, चीरी मिर्चें और बची 0.5 छोटी चम्मच नमक डालें।. चिकन को एक परत में बर्तन में वापस रखें, टुकड़ों को सॉस में बैठाएं और चमड़ी ऊपर रखें ताकि वह तरल के ऊपर रहे। हल्के उबाल पर लाएं।. ढक्कन को थोड़ा खुला रखकर ढक दें और सबसे धीमी आंच पर 35–40 मिनट पकाएं, बीच में एक बार चलाएं, जब तक चिकन हड्डी से आसानी से अलग न हो और भीतर का तापमान 75°C न हो जाए। सॉस coral-orange रंग की और इतनी गाढ़ी होनी चाहिए कि चम्मच की पीठ पर लिपटे — ज़्यादा गाढ़ी हो जाए तो थोड़े गरम पानी से पतला करें।. चखें और ज़रूरत हो तो नमक या और मिर्च डालें। चिकन को गर्म प्लेट में निकालें, ऊपर से सॉस ख़ूब डालें, कटा पार्सले छिड़कें और तुरंत भापी चावल, fufu या उबली plantain के साथ परोसें ताकि सॉस को सोखा जा सके।.","en":"Pat the chicken pieces dry and season both sides with 1 tsp salt and 0.5 tsp pepper; rest at room temperature for 15 minutes. Heat the palm oil in a heavy 28 cm pot over medium-high heat — palm oil melts into a deep orange-red liquid; when shimmering, add the chicken pieces skin-side down in one layer (work in two batches if needed) and sear for 4–5 minutes per side until the skin is deep golden; lift onto a plate. Reduce the heat to medium; add the diced onions and a pinch of salt to the same pot and cook for 8–10 minutes, stirring often, until soft, glossy, and lightly golden but not browned. Add the garlic and ginger and cook for 1 minute until fragrant; stir in the tomato paste and grated tomatoes and cook for 5–6 minutes, stirring, until the mixture darkens to a rich brick-red and the palm oil starts to separate around the edges — this oil split is the signature look of moambe. Whisk the peanut butter with 200 ml of the hot stock in a small bowl until smooth, then pour into the pot and stir to combine; add the remaining 300 ml stock, the bay leaves, slit chillies, and the remaining 0.5 tsp salt. Return the chicken to the pot in a single layer, nestling the pieces into the sauce skin-side up so the skin stays above the liquid; bring to a gentle simmer. Cover with a lid set slightly ajar and cook on the lowest heat for 35–40 minutes, stirring once at the halfway mark, until the chicken pulls easily from the bone and the internal temperature reads 75°C; the sauce should be coral-orange and thick enough to coat the back of a spoon — if it tightens too much, loosen with a splash of hot water. Taste and adjust with salt or extra chilli; lift the chicken into a warmed serving dish, spoon the sauce generously over the top, scatter with chopped parsley, and serve immediately with steamed rice, fufu, or boiled plantain to soak up the sauce."}},{"id":143,"origin":{"hi":"फ़्रांस","en":"France","ro":"Franța"},"name":{"hi":"कैसुले","en":"Cassoulet","ro":"Cassoulet"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":6,"tipType":"meat","pairingsType":"meat","ingredients":{"hi":["500 ग्राम सूखी सफ़ेद बीन्स (haricot tarbais या cannellini), रातभर ठंडे पानी में भिगोई हुई","4 कोनफिट बत्तख की टांगें (cuisses de canard confites), कमरे के तापमान पर, चर्बी अलग रखी हुई","400 ग्राम सूअर के कंधे का मांस, 4 सेमी टुकड़ों में कटा","300 ग्राम छिलके सहित सूअर का पेट (बेली), 3 सेमी टुकड़ों में कटा","4 तुलूज़ सॉसेज (लगभग 500 ग्राम) — या विकल्प में स्मोक्ड सूअर सॉसेज","1 बड़ी गाजर (लगभग 150 ग्राम), छीली और 2 सेमी टुकड़ों में कटी","1 बड़ा प्याज़ (लगभग 200 ग्राम), छिला और उसमें 4 साबुत लौंग गाड़ी हुई","1 लहसुन की पूरी (लगभग 60 ग्राम), क्षैतिज रूप से दो भागों में कटी","1 बूके गारनी (1 तेजपत्ता + 4 थाइम की डंडी + 4 पार्सले के डंठल + एक टुकड़ा सूखी नारंगी छिलका, धागे से बँधे)","1 सूअर का खुर हड्डी या हैम हॉक (लगभग 400 ग्राम, वैकल्पिक पर परंपरागत)","200 ग्राम डिब्बाबंद कुटे टमाटर (या 2 पके टमाटर, छिले और कटे हुए)","2 बड़े चम्मच टमाटर पेस्ट","1.5 लीटर बिना नमक का चिकन या सूअर का स्टॉक (या पानी)","60 ग्राम मोटे सफ़ेद ब्रेड क्रम्ब्स","1.5 छोटे चम्मच बारीक समुद्री नमक, स्वादानुसार और","1 छोटा चम्मच ताज़ी पिसी काली मिर्च","2 बड़े चम्मच फ्लैट-लीफ पार्सले बारीक कटा, सजावट के लिए","2 बड़े चम्मच बत्तख की चर्बी (confit से), मांस सीयरिंग के लिए"],"en":["500 g dried white beans (haricot tarbais or cannellini), soaked in cold water overnight","4 confit duck legs (cuisses de canard confites), at room temperature, fat reserved","400 g pork shoulder, cut into 4 cm pieces","300 g pork belly with rind, cut into 3 cm pieces","4 Toulouse sausages (about 500 g) — or smoked pork sausages as a substitute","1 large carrot (about 150 g), peeled and cut into 2 cm chunks","1 large onion (about 200 g), peeled and studded with 4 whole cloves","1 head of garlic (about 60 g), halved horizontally","1 bouquet garni (1 bay leaf + 4 thyme sprigs + 4 parsley stalks + a piece of dried orange peel, tied)","1 pork knuckle bone or ham hock (about 400 g, optional but traditional)","200 g canned chopped tomatoes (or 2 ripe tomatoes, peeled and chopped)","2 tbsp tomato paste","1.5 litres unsalted chicken or pork stock (or water)","60 g coarse white breadcrumbs","1.5 tsp fine sea salt, plus more to taste","1 tsp freshly ground black pepper","2 tbsp finely chopped fresh flat-leaf parsley, to garnish","2 tbsp duck fat (from the confit), for browning the meats"],"ro":["500 g fasole albă uscată (haricot tarbais sau cannellini), înmuiată în apă rece peste noapte","4 pulpe de rață confit (cuisses de canard confites), la temperatura camerei, grăsimea păstrată","400 g umăr de porc, tăiat bucăți de 4 cm","300 g piept de porc cu șorici, tăiat bucăți de 3 cm","4 cârnați de Toulouse (aproximativ 500 g) — sau cârnați afumați de porc ca substitut","1 morcov mare (aproximativ 150 g), curățat și tăiat bucăți de 2 cm","1 ceapă mare (aproximativ 200 g), curățată și înfiptă cu 4 cuișoare întregi","1 căpățână de usturoi (aproximativ 60 g), tăiată orizontal","1 bouquet garni (1 foaie de dafin + 4 crenguțe de cimbru + 4 cozi de pătrunjel + o bucată de coajă uscată de portocală, legate)","1 os de jambon afumat sau o ciolan de porc (aproximativ 400 g, opțional dar tradițional)","200 g roșii sfărâmate din conservă (sau 2 roșii coapte, decojite și tocate)","2 linguri pastă de roșii","1,5 litri supă de pui sau de porc nesărată (sau apă)","60 g pesmet alb grosier","1,5 lingurițe sare fină de mare, plus după gust","1 linguriță piper negru proaspăt măcinat","2 linguri pătrunjel proaspăt cu frunze plate, tocat fin, pentru garnitură","2 linguri grăsime de rață (din confit), pentru rumenirea cărnurilor"]},"howIsMade":{"hi":"एक रात पहले बीन्स को बड़े बाउल में रखें, कम-से-कम 2 लीटर ठंडे पानी से ढकें और 10–12 घंटे भिगोएं। ये लगभग दोगुनी हो जाएंगी। अगले दिन छानकर धो लें।. बीन्स का स्टॉक बनाएं। छाने हुए बीन्स को 5-लीटर भारी बर्तन में डालें, सूअर के घुटने (अगर डाल रहे हैं) के साथ, 4 लौंग वाली प्याज़, आधी कटी लहसुन की पूरी, गाजर के टुकड़े, बूके गारनी और 1.5 लीटर ठंडा स्टॉक डालें। हल्के उबाल पर लाएं और बिना ढके 50–60 मिनट तक तब तक पकाएं जब तक बीन्स बस नर्म हों, टूटे नहीं। अभी नमक न डालें।. इसी बीच मांस को सीयरिंग करें। चौड़े पैन में 2 बड़े चम्मच बत्तख की चर्बी मध्यम-तेज़ आंच पर गरम करें। सूअर के कंधे और बेली को थपथपा कर सुखाएं और बैच में हर तरफ़ 4–5 मिनट सीयरिंग करें जब तक गहरे सुनहरे न हो जाएं। प्लेट में निकालें। उसी चर्बी में तुलूज़ सॉसेज को हर तरफ़ 2–3 मिनट सिर्फ़ छिलके पर रंग आने तक भूनें। प्लेट में रखें।. ओवन को 160°C (320°F / फैन 140°C) तक प्रीहीट करें। बीन्स के बर्तन से सूअर का घुटना, प्याज़, लहसुन, गाजर और बूके गारनी निकालें और सुगंधित चीज़ें फेंक दें। घुटने की हड्डी से मांस छुड़ाकर मोटा फाड़ें और रखें। टमाटर पेस्ट और कटे टमाटर बीन्स के पानी में मिलाएं, चखें और 1.5 छोटे चम्मच नमक व काली मिर्च डालें।. 26 सेमी चौड़े cassole (या कोई भी चौड़ा ओवन-योग्य बर्तन) में cassoulet को सजाएं। नीचे एक-तिहाई बीन्स फैलाएं, ऊपर सीयरिंग किए सूअर कंधा, बेली, घुटने का मांस और ठंडे confit बत्तख की टांगें रखें। एक और एक-तिहाई बीन्स से ढकें, सीयरिंग किए सॉसेज ऊपर रखें, फिर बची बीन्स से समाप्त करें। ऊपरी बीन्स की परत बस ढकने जितना बीन्स का पानी डालें — बाकी बाद में डालने के लिए गर्म रखें।. ब्रेड क्रम्ब्स को समान रूप से छिड़कें। cassole को बिना ढके ओवन में रखें और 1 घंटा पकाएं। ब्रेड क्रम्ब्स सुनहरे होकर भूरी क्रस्ट बना लेंगे।. 1 घंटे बाद, लकड़ी के चम्मच की पीठ से क्रस्ट को cassoulet में दबा कर तोड़ें — चलाएं नहीं। अगर सूखा लगे तो रखे हुए बीन्स के पानी का एक करछुल डालें। ओवन में वापस रखें और 1 घंटे और पकाएं, 30 मिनट बाद फिर से क्रस्ट तोड़ें, जब तक नई क्रस्ट न बने और cassoulet किनारों पर गहरे बुलबुलाने लगे।. एक बार और दोहराएं: क्रस्ट तोड़ें, तरल भरें और आख़िरी 30–40 मिनट बेक करें। कुल ओवन समय लगभग 2 घंटे 30 मिनट — कुल तीन क्रस्ट। ओवन से निकालकर cassoulet को 10 मिनट विश्राम दें ताकि बीन्स तरल वापस सोख लें। कटा पार्सले छिड़कें और cassole से सीधे, क्रस्टी पाव और हरे सलाद के साथ परोसें।.","en":"The night before, place the beans in a large bowl, cover with at least 2 litres of cold water, and soak for 10–12 hours; they will roughly double in size; drain and rinse the next day. Make the bean stock; put the drained beans in a heavy 5-litre pot with the pork knuckle (if using), the studded onion, the halved garlic head, the carrot chunks, the bouquet garni, and 1.5 litres of cold stock; bring to a gentle simmer and cook uncovered for 50–60 minutes, until the beans are just tender but not falling apart; do not salt yet. Meanwhile, brown the meats; heat 2 tbsp duck fat in a wide skillet over medium-high heat; pat the pork shoulder and pork belly dry and brown in batches for 4–5 minutes per side until deep golden; lift onto a plate; in the same fat, brown the Toulouse sausages for 2–3 minutes per side just to colour the casings; add to the plate. Heat the oven to 160°C (320°F / fan 140°C); lift the cooked knuckle, onion, garlic, carrot, and bouquet garni out of the bean pot and discard the aromatics; pull any meat from the knuckle bone, shred coarsely, and reserve; stir the tomato paste and chopped tomatoes into the bean liquid, then taste and add 1.5 tsp salt and the pepper. Assemble the cassoulet in a wide 26 cm cassole (or any wide oven-safe pot); spread one-third of the beans on the bottom, then arrange the browned pork shoulder, pork belly, knuckle meat, and the cold confit duck legs on top; cover with another third of the beans, lay the browned sausages on top, then finish with the remaining beans; pour over enough bean liquid to just cover the top layer of beans — keep the rest warm for topping up. Sprinkle the breadcrumbs evenly over the top; place the cassole in the oven, uncovered, and cook for 1 hour; the breadcrumbs will gild and form a brown crust. After 1 hour, break the crust by pressing it down into the cassoulet with the back of a wooden spoon — do not stir; top up with a ladle of reserved bean liquid if it looks dry; return to the oven and cook for another hour, breaking the crust again after 30 minutes, until a fresh crust has formed and the cassoulet is bubbling deeply around the edges. Repeat once more: break the crust, top up the liquid, and bake a final 30–40 minutes; the total oven time is about 2 h 30 m — three crusts in all; rest the cassoulet for 10 minutes out of the oven so the beans drink back the liquid; scatter with chopped parsley and serve straight from the pot, with crusty bread and a green salad."},"timeMins":{"total":240,"active":45}},{"id":144,"origin":{"hi":"क्रोएशिया","en":"Croatia","ro":"Croația"},"name":{"hi":"पाश्तित्साडा","en":"Pasticada","ro":"Pašticada"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"hi":["1.2 किलो बीफ रंप या टॉपसाइड, एक टुकड़े में","100 ग्राम सूअर की पीठ की चर्बी या pancetta, 5 मिमी × 5 सेमी पट्टियों में कटी हुई, larding के लिए","2 मध्यम गाजर (लगभग 200 ग्राम): 1 माचिस की तीली के आकार में larding के लिए, 1 बारीक कटी हुई सॉस के लिए","10 साबुत लौंग (5 larding के लिए, 5 मैरीनेड के लिए) + 0.5 छोटा चम्मच पिसी लौंग सॉस के लिए","6 लहसुन की कलियाँ, छिली हुई — 3 मैरीनेड के लिए कुटी, 3 सॉस के लिए बारीक कटी","200 मिली सफ़ेद वाइन सिरका + 200 मिली ठंडा पानी + 3 तेजपत्ते + 1 छोटा चम्मच साबुत काली मिर्च + 4 जूनिपर बेरीज़ (मैरीनेड के लिए)","2 बड़े प्याज़ (लगभग 400 ग्राम), बारीक कटे","200 ग्राम बीज रहित सूखे आलूबुखारे (prunes)","100 मिली मीठी वाइन prošek (या मीठी Marsala या 1 बड़ा चम्मच ब्राउन शक्कर + 80 मिली port)","500 मिली ड्राई लाल वाइन (Plavac Mali, Merlot या कोई भी मज़बूत ड्राई रेड)","300 मिली बिना नमक का बीफ स्टॉक","2 बड़े चम्मच टमाटर पेस्ट + 200 ग्राम डिब्बाबंद कुटे टमाटर","1 छोटा चम्मच पिसी दालचीनी + 0.5 छोटा चम्मच ताज़ी कद्दूकस की जायफल","50 ग्राम चरबी (या 3 बड़े चम्मच जैतून का तेल), सीयरिंग के लिए","1.5 छोटे चम्मच बारीक समुद्री नमक, स्वादानुसार और","0.5 छोटा चम्मच ताज़ी पिसी काली मिर्च, अंत में डालने के लिए","ताज़ा बारीक कटा पार्सले, सजावट के लिए","Gnocchi या ताज़ा पास्ता (लगभग 500 ग्राम), परोसने के लिए"],"en":["1.2 kg beef rump or topside, in one piece","100 g pork fat back or pancetta, cut into 5 mm × 5 cm strips for larding","2 medium carrots (about 200 g): 1 cut into matchsticks for larding, 1 finely diced for the sauce","10 whole cloves (5 for larding, 5 for the marinade) + 0.5 tsp ground cloves for the sauce","6 garlic cloves, peeled — 3 crushed for the marinade, 3 finely chopped for the sauce","200 ml white wine vinegar + 200 ml cold water + 3 bay leaves + 1 tsp black peppercorns + 4 juniper berries (for the marinade)","2 large onions (about 400 g), finely diced","200 g pitted prunes (dried plums)","100 ml prošek dessert wine (or sweet Marsala or 1 tbsp brown sugar + 80 ml port)","500 ml dry red wine (Plavac Mali, Merlot, or any robust dry red)","300 ml unsalted beef stock","2 tbsp tomato paste + 200 g canned chopped tomatoes","1 tsp ground cinnamon + 0.5 tsp freshly grated nutmeg","50 g lard (or 3 tbsp olive oil), for browning","1.5 tsp fine sea salt, plus more to taste","0.5 tsp freshly ground black pepper, for finishing","Fresh parsley, finely chopped, to garnish","Gnocchi or fresh pasta (about 500 g), to serve"],"ro":["1,2 kg vrăbioară sau pulpă de vită, într-o singură bucată","100 g slană de porc sau pancetta, tăiată fâșii de 5 mm × 5 cm pentru împănat","2 morcovi medii (aproximativ 200 g): 1 tăiat fâșii subțiri pentru împănat, 1 tăiat cuburi mici pentru sos","10 cuișoare întregi (5 pentru împănat, 5 pentru marinadă) + 0,5 linguriță cuișoare măcinate pentru sos","6 căței de usturoi decojiți — 3 zdrobiți pentru marinadă, 3 tocați fin pentru sos","200 ml oțet de vin alb + 200 ml apă rece + 3 foi de dafin + 1 linguriță boabe de piper negru + 4 boabe de ienupăr (pentru marinadă)","2 cepe mari (aproximativ 400 g), tocate fin","200 g prune uscate fără sâmburi","100 ml vin dulce prošek (sau Marsala dulce, sau 1 lingură zahăr brun + 80 ml porto)","500 ml vin roșu sec (Plavac Mali, Merlot sau orice vin sec robust)","300 ml supă de vită nesărată","2 linguri pastă de roșii + 200 g roșii sfărâmate din conservă","1 linguriță scorțișoară măcinată + 0,5 linguriță nucșoară proaspăt rasă","50 g untură (sau 3 linguri ulei de măsline), pentru rumenire","1,5 lingurițe sare fină de mare, plus după gust","0,5 linguriță piper negru proaspăt măcinat, pentru finisare","Pătrunjel proaspăt tocat fin, pentru garnitură","Gnocchi sau paste proaspete (aproximativ 500 g), pentru servit"]},"howIsMade":{"hi":"पहला दिन, मांस को larding करें। तेज़ चाकू से बीफ टुकड़े की सतह पर 16 गहरी कतरें बनाएं। हर कतर में सूअर की चर्बी की एक पट्टी, गाजर की एक माचिस की तीली, और (एक के बाद एक कतरों में) आधी साबुत लौंग डालें। चर्बी अंदर से मांस को सींचती है, गाजर सॉस को मीठा करती है, लौंग मांस को सुगंध देती है।. मैरीनेड बनाएं। ऐसे न-प्रतिक्रियात्मक बर्तन में जो मांस को बस समाए, 200 मिली वाइन सिरका, 200 मिली ठंडा पानी, मैरीनेड के लिए 3 कुटी लहसुन की कलियाँ, 3 तेजपत्ते, साबुत काली मिर्च, जूनिपर बेरीज़, और बची 5 साबुत लौंगें मिलाएं। मांस को डुबोएं, ढककर फ्रिज में 24 घंटे (अधिकतम 48) रखें, बीच में दो बार पलटें।. दूसरा दिन, मांस निकालें, चिपकी मसाले खुरचकर हटाएं और अच्छी तरह सुखाएं — गीला मांस सिअर नहीं होगा। मैरीनेड फेंक दें। मांस को 1 छोटा चम्मच नमक और 0.5 छोटा चम्मच काली मिर्च से सीज़न करें।. 28 सेमी भारी डच ओवन या braiser में चरबी मध्यम-तेज़ आंच पर पिघलाएं। मांस को हर तरफ़ 3–4 मिनट, कुल 12–15 मिनट तक तब तक सीयरिंग करें जब तक चारों ओर एकसमान महोगनी रंग न आ जाए। प्लेट में निकालें।. आंच मध्यम कर दें। पिघली चर्बी में कटी प्याज़ और एक चुटकी नमक डालें और 10–12 मिनट बार-बार चलाते हुए तब तक भूनें जब तक गहरा सुनहरा भूरा न हो जाए — यह धीमा कैरामेलाइज़ेशन सॉस की नींव है। कटी गाजर और कटा लहसुन डालें और 3–4 मिनट और भूनें। टमाटर पेस्ट, पिसी लौंग, दालचीनी और जायफल मिलाएं और 1 मिनट भूनें।. prošek डालें और तले को खुरचते हुए 1 मिनट चलाएं। लाल वाइन डालें, आंच बढ़ाएं और आधे रहने तक रिड्यूस करें (लगभग 6–8 मिनट)। कटे टमाटर, बीफ स्टॉक, prunes और बची 0.5 छोटी चम्मच नमक डालें। मांस को बर्तन में वापस रखें और तरल में डुबाएं — सॉस मांस की लगभग तीन-चौथाई ऊँचाई तक आना चाहिए।. कसकर ढककर सबसे धीमी आंच पर (या 150°C ओवन में) 2 घंटे 30 मिनट – 3 घंटे braise करें, हर 45 मिनट में मांस पलटें, जब तक चाकू बीच में बिना रुकावट के अंदर न जाए। मांस को बोर्ड पर निकालें और एल्युमिनियम फ़ॉइल से ढककर 15 मिनट विश्राम दें।. सॉस पूरा करें। prunes निकालें और सजावट के लिए एक मुट्ठी रखें; बाकी को सॉस के साथ हैंड ब्लेंडर से गाढ़े, चमकदार ग्रेवी बनाएं (या बारीक छन्नी से छानें)। ज़रूरत हो तो खुले में 5–8 मिनट और गाढ़ा करें — सॉस चम्मच की पीठ कोट करे और गहरे मीठे-खट्टे-मसालेदार स्वाद का हो। आराम किए मांस को रेशे के विपरीत 1 सेमी मोटी फाँकों में काटें, गर्म gnocchi या ताज़ा पास्ता पर पंखे के आकार में रखें, सॉस उदार रूप से डालें, बचे prunes और कटा पार्सले छिड़कें और तुरंत परोसें।.","en":"Day 1, lard the beef; using a sharp paring knife, make 16 deep slits across the surface of the beef joint; slide a strip of pork fat, a carrot matchstick, and (in alternate slits) half of a whole clove into each slit; the fat will baste the meat from the inside, the carrot will sweeten the sauce, and the cloves perfume the meat. Make the marinade; in a non-reactive bowl just large enough to hold the beef, combine 200 ml wine vinegar, 200 ml cold water, the 3 crushed marinade garlic cloves, 3 bay leaves, peppercorns, juniper berries, and the remaining 5 whole cloves; submerge the beef, cover, and refrigerate 24 hours (up to 48 hours), turning twice. Day 2, lift the beef out, scrape off any clinging spices, and pat thoroughly dry — wet meat will not brown; discard the marinade; season the meat with 1 tsp salt and 0.5 tsp pepper. Heat the lard in a heavy Dutch oven or braiser (28 cm) over medium-high heat; sear the beef on all sides for 3–4 minutes per side, about 12–15 minutes total, until evenly mahogany brown all over; lift onto a plate. Reduce the heat to medium; add the diced onion and a pinch of salt to the rendered fat and cook for 10–12 minutes, stirring often, until deeply golden brown — this slow caramelisation builds the sauce; add the diced carrot and chopped garlic and cook for another 3–4 minutes; stir in the tomato paste, ground cloves, cinnamon, and nutmeg and toast for 1 minute. Pour in the prošek and stir for 1 minute, scraping the base; add the red wine, raise the heat, and reduce by half (about 6–8 minutes); add the chopped tomatoes, beef stock, prunes, and the remaining 0.5 tsp salt; return the beef to the pot, settling it into the liquid — the sauce should come about three-quarters of the way up the meat. Cover with a tight lid and braise on the lowest hob heat (or in a 150°C oven) for 2 h 30 m – 3 h, turning the beef every 45 minutes, until a knife slides into the centre with no resistance; lift the beef onto a board and rest, tented with foil, for 15 minutes. Finish the sauce; lift out the prunes and reserve a handful for garnish; blend the rest with the sauce using a stick blender to a thick, glossy gravy (or push through a sieve for a finer finish); reduce uncovered for 5–8 minutes if it needs thickening — it should coat the back of a spoon and taste deeply sweet-sour-spiced; slice the rested beef across the grain into 1 cm slices, fan over warm gnocchi or fresh pasta, spoon the sauce generously, scatter with reserved prunes and chopped parsley, and serve immediately."}},{"id":145,"origin":{"hi":"साइप्रस","en":"Cyprus","ro":"Cipru"},"name":{"hi":"शेफ्टालिया","en":"Sheftalia","ro":"Sheftalia"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"mediterranean","ingredients":{"hi":["400 ग्राम मोटे कीमे वाला सूअर का कंधा (15–20% चर्बी)","300 ग्राम मोटे कीमे वाला मेमने का कंधा (या मेमना न मिले तो 700 ग्राम सूअर ही)","300 ग्राम कॉल फैट (मेमने या सूअर का), हल्के नमक वाले ठंडे पानी में 30 मिनट भिगोकर छाना हुआ — लगभग 30 × 30 सेमी की शीट","1 बड़ा प्याज़ (लगभग 200 ग्राम), कद्दूकस करके अतिरिक्त रस निचोड़ा हुआ","30 ग्राम फ्लैट-लीफ पार्सले, बारीक कटा","20 ग्राम ताज़ा पुदीना (साइप्रस का dyosmos), बारीक कटा (वैकल्पिक पर परंपरागत)","4 लहसुन की कलियाँ, बारीक कटी","1.5 छोटे चम्मच बारीक समुद्री नमक","1 छोटा चम्मच ताज़ी पिसी काली मिर्च","1 छोटा चम्मच पिसा जीरा","0.5 छोटा चम्मच पिसी दालचीनी","60 मिली ड्राई सफ़ेद वाइन या 2 बड़े चम्मच रेड वाइन सिरका (बाँधने और नर्म करने के लिए)","मांस मिश्रण के लिए 1 बड़ा चम्मच जैतून का तेल","ग्रिल पर ब्रश करने के लिए 1 बड़ा चम्मच जैतून का तेल","नींबू के टुकड़े, लाल प्याज़ के स्लाइस, टमाटर के स्लाइस और गर्म पीटा या साइप्रस का लेमोनी ब्रेड, परोसने के लिए","Tzatziki या hummus, परोसने के लिए"],"en":["400 g coarsely minced pork shoulder (15–20% fat)","300 g coarsely minced lamb shoulder (or 700 g all pork if lamb is unavailable)","300 g caul fat (lamb or pork), soaked in cold lightly-salted water for 30 minutes then drained — about a 30 × 30 cm sheet","1 large onion (about 200 g), grated and squeezed of excess liquid","30 g flat-leaf parsley, finely chopped","20 g fresh mint (Cypriot dyosmos), finely chopped (optional but traditional)","4 garlic cloves, finely minced","1.5 tsp fine sea salt","1 tsp freshly ground black pepper","1 tsp ground cumin","0.5 tsp ground cinnamon","60 ml dry white wine or 2 tbsp red wine vinegar (to bind and tenderise)","1 tbsp olive oil for the meat mixture","1 tbsp olive oil for brushing the grill","Lemon wedges, sliced red onion, sliced tomato, and warm pitta or Cypriot lemoni-bread, to serve","Tzatziki or hummus, to serve"],"ro":["400 g umăr de porc tocat grosier (15–20% grăsime)","300 g umăr de miel tocat grosier (sau 700 g doar porc, dacă mielul nu este disponibil)","300 g prapure (de porc sau miel), înmuiat în apă rece ușor sărată 30 de minute, apoi scurs — o foaie de aproximativ 30 × 30 cm","1 ceapă mare (aproximativ 200 g), dată pe răzătoare și stoarsă de lichidul în exces","30 g pătrunjel cu frunze plate, tocat fin","20 g mentă proaspătă (dyosmos cipriot), tocată fin (opțional, dar tradițional)","4 căței de usturoi, tocați fin","1,5 lingurițe sare fină de mare","1 linguriță piper negru proaspăt măcinat","1 linguriță chimion măcinat","0,5 linguriță scorțișoară măcinată","60 ml vin alb sec sau 2 linguri oțet de vin roșu (pentru a lega și a frăgezi)","1 lingură ulei de măsline pentru compoziție","1 lingură ulei de măsline pentru uns grătarul","Felii de lămâie, ceapă roșie feliată, roșii feliate și pita caldă sau pâine cipriotă de lămâie (lemoni), pentru servit","Tzatziki sau hummus, pentru servit"]},"howIsMade":{"hi":"मांस मिश्रण बनाएं। एक चौड़े बाउल में सूअर का कीमा, मेमने का कीमा, कद्दूकस की प्याज़, पार्सले, पुदीना (अगर डाल रहे हैं), लहसुन, नमक, काली मिर्च, जीरा, दालचीनी, वाइन (या सिरका) और 1 बड़ा चम्मच जैतून तेल मिलाएं। हाथ से 2–3 मिनट तब तक गूँधें जब तक चिपचिपा और एकसमान न हो जाए। ढककर फ्रिज में कम-से-कम 1 घंटा (अधिकतम 12 घंटे) रखें ताकि स्वाद घुलें।. कॉल फैट तैयार करें। भिगोकर छाने हुए कॉल फैट को साफ़ बोर्ड पर सावधानी से फैलाएं — यह बहुत आसानी से फट जाता है। कैंची से लगभग 12 × 12 सेमी के 12 चौकोर टुकड़ों में काटें। छेद हों तो टुकड़ों को ओवरलैप करके ढक दें।. sheftalia बनाएं। एक बड़े चम्मच आकार का मांस (लगभग 50–60 ग्राम) लें और 7–8 सेमी लंबा थोड़ा संकीर्ण होने वाला बेलन बनाएं। एक चौकोर कॉल फैट के किनारे पर रखें। दोनों किनारे मांस के ऊपर मोड़ें, फिर सॉसेज जैसी आकृति में कसकर रोल करें, सीवन नीचे की ओर रखें। अगर मेटल skewer हो तो उसमें पिरो दें — वरना लपेटा हुआ सीवन पकड़ लेगा। बाकी सामग्री से दोहराएं: कुल 12 sheftalia मिलेंगे, हर व्यक्ति के लिए 3।. लिपटे सॉसेज को ट्रे पर रखें और कम-से-कम 15 मिनट (अधिकतम 4 घंटे) फ्रिज में रखें ताकि कॉल फैट सख्त हो जाए — ग्रिल पर बेहतर टिकेगा।. चारकोल ग्रिल या भारी रिज्ड griddle पैन को मध्यम-तेज़ आंच पर गरम करें (सतह लगभग 200°C)। 1 बड़े चम्मच जैतून तेल से हल्का ब्रश करें। sheftalia ग्रिल छूते ही सिज़ करनी चाहिए पर आक्रामक लपटें न उठें — बहुत ज़्यादा गर्मी से कॉल फैट जल जाएगा अंदर मांस पकने से पहले।. sheftalia को कुल 12–15 मिनट तक ग्रिल करें, हर 3–4 मिनट में चारों में से अगली side पर पलटें, जब तक कॉल फैट पतली लेस जैसी क्रस्ट बन जाए और मांस का बीच 70°C पर पहुँच जाए। ये गहरे सुनहरे-भूरे होने चाहिए, ठोस पर सख़्त नहीं।. sheftalia को बोर्ड पर निकालें और एल्युमिनियम फ़ॉइल से हल्के से ढककर 5 मिनट विश्राम दें। रस बैठ जाते हैं और बची हुई गर्मी से मांस पूरा पक जाता है।. पीटा या लेमोनी ब्रेड को ग्रिल पर हर तरफ़ 30 सेकंड गर्म करें। हर प्लेट पर 3 sheftalia प्रति व्यक्ति, गर्म ब्रेड, नींबू के टुकड़े, लाल प्याज़ और टमाटर के स्लाइस रखें। साथ में tzatziki या hummus। sheftalia के टुकड़ों को पीटा में सलाद और सॉस के साथ डालकर खाएं।.","en":"Make the meat mixture; in a wide bowl combine the minced pork, minced lamb, grated onion, parsley, mint (if using), garlic, salt, pepper, cumin, cinnamon, wine (or vinegar), and 1 tbsp olive oil; knead with your hand for 2–3 minutes until sticky and homogeneous; cover and chill in the fridge for at least 1 hour (up to 12 hours) so the seasoning matures. Prepare the caul fat; spread the soaked and drained caul fat carefully on a clean board — it tears very easily; use scissors to cut it into 12 squares of about 12 × 12 cm; patch holes by overlapping pieces. Shape the sheftalia; take a tablespoon-sized portion of meat (about 50–60 g) and shape into a slightly tapered cylinder 7–8 cm long; place at the edge of one caul-fat square; fold the sides over the meat, then roll up tightly into a sausage shape, finishing with the seam underneath; pierce onto a metal skewer if you have one — otherwise the wrapped seam will hold; repeat with the remaining meat and caul fat: you should get 12 sheftalia, 3 per person. Rest the wrapped sausages on a tray and chill for at least 15 minutes (up to 4 hours) so the caul fat firms — they hold together better on the grill. Heat a charcoal grill or a heavy ridged griddle pan to medium-high (about 200°C / 390°F surface); brush lightly with 1 tbsp olive oil; the sheftalia should hiss when they touch the grill but not flare aggressively — too high and the caul fat will burn before the meat cooks through. Grill the sheftalia for 12–15 minutes total, turning every 3–4 minutes onto each of their four sides, until the caul fat has rendered down into a thin lacy crust and the meat reaches 70°C in the centre; they should be deep golden brown and feel firm but not hard. Lift the sheftalia onto a board and rest, loosely tented with foil, for 5 minutes; the juices settle and the meat finishes cooking from residual heat. Warm the pitta or Cypriot lemoni-bread on the grill for 30 seconds per side; pile 3 sheftalia per person on each plate with the warm bread, lemon wedges, sliced red onion, and tomato; spoon tzatziki or hummus to the side; eat by tearing pieces of sheftalia into the pitta with the salad and dip."}},{"id":146,"origin":{"hi":"बोस्निया और हर्जेगोविना","en":"Bosnia and Herzegovina","ro":"Bosnia și Herțegovina"},"name":{"hi":"चेवापी","en":"Cevapi","ro":"Cevapi"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"hi":["500 ग्राम मोटे कीमे वाला बीफ चक (लगभग 15% चर्बी)","300 ग्राम मोटे कीमे वाला मेमने का कंधा (या मेमना न मिले तो 800 ग्राम सिर्फ़ बीफ)","4 लहसुन की कलियाँ, 0.5 छोटा चम्मच नमक के साथ बारीक पेस्ट में कूटी हुई","60 मिली ठंडा सोडा वाटर","1 छोटा चम्मच बेकिंग सोडा — स्प्रिंगी टेक्सचर की कुंजी","1.5 छोटे चम्मच बारीक समुद्री नमक","1 छोटा चम्मच ताज़ी पिसी काली मिर्च","1 छोटा चम्मच मीठी हंगेरियन पैपरिका","0.5 छोटा चम्मच सूखी मार्जोरम या ओरिगानो (वैकल्पिक पर परंपरागत)","ब्रश करने के लिए 1 बड़ा चम्मच न्यूट्रल तेल","4 somun फ्लैटब्रेड (या 4 पीटा), हर एक लगभग 18 सेमी, परोसने के लिए","1 बड़ा लाल प्याज़ (लगभग 200 ग्राम), बहुत बारीक कटा","200 ग्राम ajvar (भुनी लाल मिर्च की चटनी)","100 ग्राम kajmak (बाल्कन गाढ़ी क्लॉटेड क्रीम) या गाढ़ी crème fraîche विकल्प के रूप में","1 छोटा गुच्छा फ्लैट-लीफ पार्सले, पत्ते अलग किए, छिड़कने के लिए"],"en":["500 g coarsely minced beef chuck (about 15% fat)","300 g coarsely minced lamb shoulder (or 800 g all beef if lamb is unavailable)","4 garlic cloves, crushed with 0.5 tsp salt to a fine paste","60 ml chilled sparkling water","1 tsp baking soda (sodium bicarbonate) — the key to the springy texture","1.5 tsp fine sea salt","1 tsp freshly ground black pepper","1 tsp sweet Hungarian paprika","0.5 tsp dried marjoram or oregano (optional but traditional)","1 tbsp neutral oil for brushing","4 somun flatbreads (or 4 pittas), about 18 cm across each, to serve","1 large red onion (about 200 g), very finely diced","200 g ajvar (roasted red-pepper relish)","100 g kajmak (Balkan clotted cream) or thick crème fraîche, as a substitute","1 small bunch flat-leaf parsley, leaves picked, to scatter"],"ro":["500 g pulpă de vită tocată grosier (15% grăsime)","300 g umăr de miel tocat grosier (sau 800 g doar vită, dacă nu există miel)","4 căței de usturoi, zdrobiți cu 0,5 linguriță sare într-o pastă fină","60 ml apă minerală rece (carbogazoasă)","1 linguriță bicarbonat de sodiu — cheia texturii elastice","1,5 lingurițe sare fină de mare","1 linguriță piper negru proaspăt măcinat","1 linguriță boia dulce maghiară","0,5 linguriță maghiran sau oregano uscat (opțional, dar tradițional)","1 lingură ulei neutru pentru uns","4 lipii somun (sau 4 pita) de aproximativ 18 cm fiecare, pentru servit","1 ceapă roșie mare (aproximativ 200 g), tocată foarte fin","200 g ajvar (pastă de ardei copți)","100 g kajmak (smântână groasă balcanică) sau crème fraîche groasă ca substitut","1 legătură mică de pătrunjel cu frunze plate, frunzele păstrate, pentru servit"]},"howIsMade":{"hi":"मांस मिश्रण बनाएं। एक चौड़े बाउल में बीफ कीमा, मेमने का कीमा, लहसुन-नमक पेस्ट, ठंडा सोडा वाटर, बेकिंग सोडा, नमक, काली मिर्च, पैपरिका और मार्जोरम मिलाएं। हाथ से 4–5 मिनट तक ज़ोर से गूँधें — मिश्रण साफ़-साफ़ चिपचिपा और अच्छी तरह बंधा हुआ हो जाए। यह लंबा गूँधना और बेकिंग सोडा cevapi को विशिष्ट स्प्रिंगी बाउंस देता है।. बाउल को क्लिंग फ़िल्म से ढककर फ्रिज में कम-से-कम 4 घंटे, आदर्श रूप से 12–24 घंटे रखें। स्वाद घुलते हैं और प्रोटीन आराम करते हैं।. हाथ ठंडे पानी से गीले करें। एक बड़े चम्मच आकार की मांस मात्रा (लगभग 35–40 ग्राम) लें और हथेलियों के बीच 7–8 सेमी लंबा, 2 सेमी मोटा उंगली-आकार का बेलन बनाएं। बाकी मांस के साथ दोहराएं और लगभग 24 cevapi (हर व्यक्ति के लिए 6) बनाएं। बनाते-बनाते ट्रे पर रखें।. आकार दिए cevapi को कम-से-कम 20 मिनट (अधिकतम 4 घंटे) फ्रिज में रखें ताकि वे सख्त हों — ग्रिल पर बेहतर आकार बनाए रखेंगे।. चारकोल ग्रिल या भारी रिज्ड griddle पैन को मध्यम-तेज़ आंच पर गरम करें (सतह लगभग 220°C)। cevapi को बहुत हल्का तेल लगाएं — बस एक झलक। ग्रिल पर रखते ही सिज़ करना चाहिए पर तेज़ धुआँ नहीं उठना चाहिए।. cevapi को कुल 8–10 मिनट तक ग्रिल करें, हर 2 मिनट में चारों में से अगली side पर पलटें, जब तक सतह महोगनी रंग की और किनारे कुरकुरे न हो जाएं और बीच 65°C तक न पहुँच जाए (वे प्लेट में पकना जारी रखेंगे)। दबाएं नहीं; लक्ष्य है रसीला और स्प्रिंगी अंदर।. cevapi 2 मिनट विश्राम लेते समय, somun (या पीटा) को ग्रिल पर हर तरफ़ 30 सेकंड गर्म करें जब तक हल्का फूले और हल्का जल जाए। हर एक को सीवन के साथ चीरकर पॉकेट बनाएं।. हर गर्म फ्लैटब्रेड में 6 cevapi भरें (या हर प्लेट पर ब्रेड के बगल में 6 रखें)। एक तरफ़ 1–2 बड़े चम्मच ajvar रखें, उदार चम्मच kajmak (या crème fraîche) और बारीक कटी कच्ची लाल प्याज़ का छोटा ढेर डालें। पार्सले के पत्ते छिड़कें और तुरंत परोसें — cevapi का रस somun में सोखना चाहिए।.","en":"Make the meat mixture; in a wide bowl combine the minced beef, minced lamb, garlic-salt paste, chilled sparkling water, baking soda, salt, pepper, paprika, and marjoram; knead vigorously with your hand for 4–5 minutes — the mixture should become noticeably sticky and start to pull together; this long knead and the bicarbonate are what give cevapi their characteristic springy bounce. Cover the bowl with cling film and rest the mixture in the fridge for at least 4 hours, ideally 12–24 hours; the flavour matures and the proteins relax. Wet your hands with cold water; take a tablespoon-sized portion of meat (about 35–40 g) and roll it between your palms into a finger-shaped cylinder about 7–8 cm long and 2 cm thick; repeat with the remaining meat to make about 24 cevapi (6 per person); arrange on a tray as you go. Chill the shaped cevapi for at least 20 minutes (up to 4 hours) to firm — they hold their shape better on the grill. Heat a charcoal grill or a heavy ridged griddle pan to medium-high (about 220°C surface); brush the cevapi very lightly with oil — barely a glaze; the grill should hiss but not smoke aggressively. Grill the cevapi for 8–10 minutes total, turning every 2 minutes onto all four sides, until the surface is mahogany brown with crisp edges and the centre reaches 65°C (they continue cooking on the plate); do not press them down; the goal is juicy, springy interiors. While the cevapi rest for 2 minutes, warm the somun (or pittas) on the grill 30 seconds per side until just puffed and lightly charred; split each one open along the seam to make a pocket. Pile 6 cevapi inside each warm flatbread (or arrange 6 on each plate beside the bread); spoon 1–2 tablespoons of ajvar to one side, add a generous knob of kajmak (or crème fraîche), and a small mound of diced raw red onion; scatter parsley leaves and serve immediately — the cevapi juices should soak into the somun."}},{"id":147,"origin":{"hi":"घाना","en":"Ghana","ro":"Ghana"},"name":{"hi":"फुफु","en":"Fufu","ro":"Fufu"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"hi":["700 ग्राम ताज़ा कसावा जड़, छिलकर 5 सेमी टुकड़ों में काटी हुई (या 500 ग्राम पहले से छिले फ्रोज़न कसावा टुकड़े, पिघलाए हुए)","500 ग्राम अर्ध-पके प्लैंटेन, लगभग 3 बड़े, छिलकर 5 सेमी टुकड़ों में (पीले छिलके पर काले निशान वाले प्लैंटेन मीठेपन और स्टार्च का सही संतुलन देते हैं)","उबालने वाले पानी के लिए 1 बड़ा चम्मच बारीक समुद्री नमक","उबालने के लिए 2 लीटर ठंडा पानी","बर्तन से अलग रखा गया लगभग 150 मिली गर्म उबला पानी, जग में गुनगुना रखा हुआ","हाथों और परोसने वाले कटोरे को चिकना करने के लिए 1 बड़ा चम्मच न्यूट्रल तेल (पाम तेल या सूरजमुखी)","गर्म पश्चिमी अफ्रीकी सूप (600 मिली–1 लीटर light soup, palmnut, मूँगफली या egusi) का एक बड़ा बर्तन, परोसने के लिए","अधिक तीखेपन के लिए ताज़ा scotch bonnet मिर्च की स्लाइसें","सूप के ऊपर छिड़कने के लिए भुनी या कुटी हुई मूँगफली (वैकल्पिक)"],"en":["700 g fresh cassava root, peeled and cut into 5 cm chunks (or 500 g pre-peeled frozen cassava chunks, thawed)","500 g semi-ripe plantains, about 3 large, peeled and cut into 5 cm chunks (yellow skin streaked with black gives the right balance of sweet and starchy)","1 tbsp fine sea salt for the cooking water","2 litres cold water for boiling","About 150 ml hot cooking water reserved from the pot, kept warm in a jug","1 tbsp neutral oil (palm or sunflower), for oiling hands and the serving bowl","1 large pot of hot West African soup (600 ml–1 L of light soup, palmnut, groundnut, or egusi), for serving","Sliced fresh scotch bonnet chilli, for those who want extra heat","Roasted peanuts or crushed groundnuts, to scatter over the soup (optional)"],"ro":["700 g manioc proaspăt, curățat și tăiat bucăți de 5 cm (sau 500 g cassava decongelată, deja curățată)","500 g banane plantain semi-coapte, aproximativ 3 mari, decojite și tăiate bucăți de 5 cm (coaja galbenă cu pete negre dă echilibrul potrivit între dulce și amidonos)","1 lingură sare fină de mare pentru apa de fierbere","2 litri apă rece pentru fierbere","Aproximativ 150 ml apă fierbinte de fierbere păstrată separat, ținută caldă într-un vas","1 lingură ulei neutru (palmier sau floarea-soarelui), pentru a unge mâinile și bolul de servit","O cratiță mare cu supă vest-africană caldă (600 ml–1 L de light soup, palmnut, groundnut sau egusi), pentru servit","Ardei iute scotch bonnet feliat, pentru cei care vor mai mult picant","Arahide prăjite sau pisate, pentru presărat peste supă (opțional)"]},"howIsMade":{"hi":"कसावा तैयार करें। कसावा के टुकड़ों को ठंडे पानी में धोकर लगी मिट्टी निकालें। तेज़ चाकू से मोटे भूरे छिलके पर लंबाई में चीरा लगाएं और गुलाबी अंदरूनी परत के साथ छिलका हटा दें ताकि सफ़ेद गूदा दिखे। हर टुकड़े के बीच का रेशेदार धागा काटकर फेंक दें।. 5 लीटर भारी बर्तन में छिले कसावा, प्लैंटेन के टुकड़े, 1 बड़ा चम्मच नमक और 2 लीटर ठंडा पानी डालें। मध्यम-तेज़ आंच पर हल्का उबाल आने दें, फिर मध्यम-धीमी कर 30–40 मिनट पकाएं जब तक दोनों कांटे से आसानी से छिद जाएं — कसावा उबले आलू जैसा होना चाहिए।. छन्नी में छानें पर कम-से-कम 250 मिली गर्म पकाने वाला पानी जग में बाद के लिए रखें। दिखने वाले रेशे या तंतु निकालकर फेंक दें।. fufu को कूटें। पारंपरिक तरीका: गर्म कसावा-प्लैंटेन मिश्रण को कुछ बूँद तेल से चिकनाई किए भारी लकड़ी के मूसल बर्तन में बैच में डालें। लंबे लकड़ी के मूसल से लय में कूटें जबकि दूसरा व्यक्ति (हल्के तेल लगे हाथों से) हर वार के बीच मिश्रण को घुमाए और इकट्ठा करे। हर बैच पर 8–10 मिनट काम करें जब तक पेस्ट घना, बिल्कुल चिकना और स्पष्ट लचीला न हो जाए — कोई गांठ न रहे।. बिना मूसल: गर्म कसावा और प्लैंटेन को मज़बूत स्टैंड मिक्सर में dough hook के साथ डालें। 1 मिनट कम गति पर चलाकर टुकड़े तोड़ें, फिर मध्यम पर 6–8 मिनट, हर 2 मिनट कटोरा खुरचें, जब तक मिश्रण हुक के चारों ओर एक लचीला आटा न बना ले। बहुत सूखा हो तो हर बार 1 बड़ा चम्मच गर्म पकाने का पानी डालें — लक्ष्य चमकदार और लचीला हो, गीला नहीं।. बनावट जाँचें। एक छोटा टुकड़ा (लगभग 50 ग्राम) लेकर हल्के तेल लगे हाथों में चिकनी गेंद बनाएं। सतह चमकदार और बिना सीवन होनी चाहिए, और गेंद प्लेट पर बिना ढहे या फटे आकार बनाए रखे। फट जाए तो एक और चम्मच गर्म पानी मिलाएं; ढह जाए तो 2 मिनट और गूँधें।. हल्के तेल लगे हाथों से सर्विंग पोर्शन बनाएं: लगभग 250 ग्राम की 4 बड़ी गेंदें (या पारंपरिक व्यक्तिगत सर्विंग के लिए 8 छोटी)। हर गेंद को हल्के तेल लगे चौड़े कटोरे में रखें ताकि चिपके नहीं। परोसने तक गीले कपड़े से ढक दें — हवा में fufu जल्दी सख्त हो जाता है।. तुरंत परोसें। हर fufu गेंद के चारों ओर एक चौड़े कटोरे में गर्म पश्चिमी अफ्रीकी सूप (light soup, palmnut, मूँगफली या egusi) डालें। खाने का तरीका: दाहिने हाथ से fufu का छोटा टुकड़ा तोड़ें, अंगूठे से दबाकर कप का आकार दें और सूप उठाएं — fufu को चबाएं नहीं, पूरा निगल लें ताकि सूप का स्वाद उसे ले जाए। कटी scotch bonnet मिर्च और भुनी मूँगफली स्वादानुसार छिड़कें।.","en":"Prepare the cassava; wash the cassava chunks under cold water to remove any clinging grit; with a paring knife slit the thick brown skin lengthwise, then peel it away (along with the pink underlayer) to expose the white core; cut out the fibrous central string from each piece and discard. In a heavy 5-litre pot, combine the peeled cassava chunks, the plantain chunks, the 1 tbsp salt, and the 2 litres cold water; bring to a gentle boil over medium-high heat, then reduce to medium-low and cook for 30–40 minutes, until both cassava and plantain are fork-tender — the cassava should feel like a cooked potato when pierced. Drain into a colander but reserve at least 250 ml of the hot cooking liquid in a jug for later; pick out and discard any visible fibres or strings. Pound the fufu; traditional method: transfer the hot cassava-plantain mixture in batches to a heavy wooden mortar lubricated with a few drops of oil; with a long wooden pestle, pound rhythmically while a second person (lightly oiled hands) turns and gathers the mass between strokes; work for 8–10 minutes per batch until the paste is dense, perfectly smooth, and noticeably elastic — no lumps remain. Mortar-free method: place the hot cassava and plantain together in a sturdy stand mixer with the dough-hook attachment; run at low speed for 1 minute to break down the chunks, then increase to medium and beat for 6–8 minutes, scraping the bowl every 2 minutes, until the mass forms a single elastic dough around the hook; add a tablespoon of reserved hot cooking water at a time if it is too dry — the goal is glossy and elastic without being wet. Test the texture; pinch off a small piece (about 50 g) and roll it in lightly oiled palms into a smooth ball; the surface should be glossy and seamless, and the ball should hold its shape on a plate without sagging or cracking; if it cracks, work in another spoonful of hot water; if it slumps, knead for another 2 minutes. Shape the serving portions with lightly oiled hands: form 4 large balls of about 250 g each (or 8 smaller balls for traditional individual servings); place each ball in a slightly oiled wide bowl so it does not stick; cover with a damp cloth until ready to serve — fufu hardens quickly when exposed to air. Serve immediately; ladle hot West African soup (light soup, palmnut, groundnut, or egusi) into a wide soup bowl around each fufu ball; eat by pinching off a small piece of fufu with the right hand, pressing a depression into it with the thumb to form a cup, and using it to scoop up the soup — do not chew the fufu, swallow it whole so the flavour of the soup carries it down; scatter chopped scotch bonnet and roasted peanuts to taste."}},{"id":148,"origin":{"hi":"जॉर्जिया","en":"Georgia","ro":"Georgia"},"name":{"hi":"खिंकाली","en":"Khinkali","ro":"Khinkali"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"hi":["500 ग्राम साधारण मैदा, बेलने के लिए अतिरिक्त","250 मिली ठंडा पानी","1 बड़ा अंडा, हल्के से फेंटा हुआ (वैकल्पिक — कुछ जॉर्जियाई परिवार नरम आटे के लिए अंडा डालते हैं)","आटे के लिए 1 छोटा चम्मच बारीक समुद्री नमक","आटे के लिए 1 बड़ा चम्मच न्यूट्रल तेल","500 ग्राम मोटे कीमे वाला बीफ (लगभग 15% चर्बी)","200 ग्राम मोटे कीमे वाला सूअर का कंधा (या अधिक दुबले परिणाम के लिए 700 ग्राम सिर्फ़ बीफ)","1 बड़ा प्याज़ (लगभग 200 ग्राम), बहुत बारीक कटा — कद्दूकस न करें, बनावट महत्वपूर्ण है","3 लहसुन की कलियाँ, बारीक कटी","20 ग्राम ताज़ा हरा धनिया, बारीक कटा — डंडी और पत्ते","1 छोटा चम्मच पिसा जीरा + 1 छोटा चम्मच ताज़ी पिसी काली मिर्च + 0.5 छोटा चम्मच khmeli suneli (या विकल्प के रूप में 0.25 छोटा चम्मच कैरावे + 0.25 छोटा चम्मच पिसा मेथीदाना)","भरावन के लिए 1.5 छोटे चम्मच बारीक समुद्री नमक","200 मिली बर्फ़ ठंडा बीफ स्टॉक या ठंडा पानी (उबालने के समय धीरे-धीरे भाप छोड़ता है — मशहूर शोरबा पॉकेट का राज़)","उबालने वाले पानी के लिए 1 बड़ा चम्मच मोटा समुद्री नमक","टेबल पर छिड़कने के लिए ख़ूब ताज़ी पिसी काली मिर्च"],"en":["500 g plain (all-purpose) flour, plus extra for rolling","250 ml cold water","1 large egg, lightly beaten (optional — some Georgian families use an egg for a softer dough)","1 tsp fine sea salt for the dough","1 tbsp neutral oil for the dough","500 g coarsely minced beef (around 15% fat)","200 g coarsely minced pork shoulder (or 700 g all beef for a leaner result)","1 large onion (about 200 g), very finely diced — do NOT grate, the texture matters","3 garlic cloves, finely minced","20 g fresh coriander, finely chopped — stems and leaves","1 tsp ground cumin + 1 tsp freshly ground black pepper + 0.5 tsp khmeli suneli (or 0.25 tsp caraway + 0.25 tsp ground fenugreek as substitute)","1.5 tsp fine sea salt for the filling","200 ml ice-cold beef stock or cold water (releases steam slowly during boiling — this is what creates the famous broth pocket)","1 tbsp coarse sea salt for the cooking water","Plenty of freshly cracked black pepper, to scatter at the table"],"ro":["500 g făină albă obișnuită, plus pentru întins","250 ml apă rece","1 ou mare, bătut ușor (opțional — unele familii georgiene folosesc un ou pentru un aluat mai moale)","1 linguriță sare fină de mare pentru aluat","1 lingură ulei neutru pentru aluat","500 g vită tocată grosier (în jur de 15% grăsime)","200 g umăr de porc tocat grosier (sau 700 g doar vită pentru un rezultat mai slab)","1 ceapă mare (aproximativ 200 g), tocată foarte fin — NU rasă, textura contează","3 căței de usturoi, tocați fin","20 g coriandru proaspăt, tocat fin — tulpini și frunze","1 linguriță chimion măcinat + 1 linguriță piper negru proaspăt măcinat + 0,5 linguriță khmeli suneli (sau 0,25 linguriță chimion negru + 0,25 linguriță schinduf măcinat ca substitut)","1,5 lingurițe sare fină de mare pentru umplutură","200 ml supă de vită rece ca gheața sau apă rece (eliberează aburi încet în timpul fierberii — acesta este secretul pungii de bulion)","1 lingură sare grunjoasă de mare pentru apa de fierbere","Mult piper negru proaspăt măcinat, pentru presărat la masă"]},"howIsMade":{"hi":"आटा: एक बड़े बर्तन में 500 ग्राम मैदा और 1 छोटा चम्मच नमक मिलाएं। धीरे-धीरे 250 मिली ठंडा पानी डालें (और वैकल्पिक रूप से 1 फेंटा हुआ अंडा + 1 बड़ा चम्मच तेल), कांटे से चलाएं, फिर 8–10 मिनट तक गूंथें जब तक आटा चिकना, सख़्त और लचीला न हो जाए — पतला बेलने पर न फटे इतना दृढ़ होना चाहिए। फिल्म से ढककर कमरे के तापमान पर 30 मिनट विश्राम दें।. भरावन: एक बर्तन में 500 ग्राम बीफ + 200 ग्राम पोर्क मोटा कीमा, 200 ग्राम बहुत बारीक कटा प्याज़, 3 लहसुन की कलियाँ, 20 ग्राम कटा धनिया, 1 छोटा चम्मच जीरा, 1 छोटा चम्मच काली मिर्च, 0.5 छोटा चम्मच khmeli suneli और 1.5 छोटे चम्मच नमक हाथ से मिलाएं। 200 मिली बर्फ़ ठंडा स्टॉक 50 मिली डालकर हर बार के बाद मिलाते हुए धीरे-धीरे डालें — भरावन ढीला और गीला होना चाहिए लेकिन तरल नहीं। ढककर 30 मिनट फ्रिज में रखें।. बेलना: आटे को 4 भागों में बांटें। एक बार में एक भाग पर काम करें (बाकी ढके रखें)। हल्के मैदे वाले सतह पर 2 मिमी पतला बेलें। तश्तरी या बड़े गिलास से 12–14 सेमी व्यास के गोल काटें। कतरे जमा करके हल्का गूंथें और फिर बेलें।. आकार देना: एक गोल हथेली पर रखें, बीच में लगभग 30 मिली (2 बड़े चम्मच) भरावन रखें। दूसरे हाथ से भरावन के चारों ओर 18–20 चुन्नटें बनाएं, हर चुन्नट को अंगूठे और तर्जनी के बीच दबाकर हल्के से केंद्र की ओर मोड़ें। अंत में सभी चुन्नटें ऊपर इकट्ठा करें और सिरे — पूंछ — को मरोड़कर बंद करें। खिंकाली को मैदे वाले सतह पर रखें।. उबालने का पानी: बड़े बर्तन में 4 लीटर पानी तेज़ उबाल पर लाएं और 1 बड़ा चम्मच मोटा नमक डालें।. उबालना: एक बार में 5–6 खिंकाली उबलते पानी में डालें (भीड़ न लगाएं)। जैसे ही वे सतह पर तैरें (2–3 मिनट बाद) टाइमर शुरू करें: और 8–10 मिनट उबालें। कुल 12–14 मिनट। चुन्नटें पारदर्शी हो जाएं और अंदर शोरबा हिलता दिखे — तभी तैयार।. निकालना: छेद वाले चम्मच से निकालें, थोड़ा निथारें और गर्म प्लेट पर रखें। तुरंत ऊपर से ख़ूब ताज़ी पिसी काली मिर्च छिड़कें। कोई सॉस नहीं — खिंकाली सादे ही खाई जाती है।. कैसे खाएं: उंगलियों से खिंकाली की पूंछ पकड़ें, थोड़ा झुकाएं और सिलाई के पास छोटा छेद कुतरें, फिर अंदर का गर्म शोरबा गिरने से पहले पहले चूस लें। बाकी हिस्सा खाएं, मरोड़ी पूंछ प्लेट पर छोड़ दें। बची पूंछों की संख्या = आपने कितनी खाईं।.","en":"DOUGH: mix 500 g flour with 1 tsp salt in a large bowl; gradually pour in 250 ml cold water (and optionally 1 beaten egg + 1 tbsp oil), stirring with a fork, then knead on the bench 8–10 minutes until the dough is smooth, firm and elastic — it needs to be tough enough to roll thin without tearing; cover with film and rest 30 minutes at room temperature. FILLING: in a bowl, mix by hand 500 g beef + 200 g pork coarse-mince with 200 g very finely diced onion, 3 garlic cloves, 20 g chopped coriander, 1 tsp cumin, 1 tsp black pepper, 0.5 tsp khmeli suneli and 1.5 tsp salt; slowly pour in 200 ml ice-cold stock, 50 ml at a time, mixing after each addition — the filling should be loose and wet but not soupy; cover and chill 30 minutes. ROLLING: divide the dough into 4 pieces; work one piece at a time (keep the rest covered); roll out to a 2 mm thin sheet on a lightly floured surface; cut 12–14 cm diameter circles with a saucer or large glass; gather scraps, knead briefly and roll again. SHAPING: place a circle in your palm, put about 30 ml (2 tbsp) of filling in the centre; with the other hand, form 18–20 pleats around the filling, pinching each pleat between thumb and forefinger and twisting it gently toward the centre; at the end, gather all pleats at the top and twist the tip — the tail — to seal; set the khinkali on a floured surface. COOKING WATER: bring 4 litres of water to a vigorous rolling boil in a large pot and add 1 tbsp coarse salt. BOILING: drop 5–6 khinkali at a time into the boiling water (do not crowd); the moment they float to the surface (after 2–3 minutes), start your timer: boil another 8–10 minutes; total 12–14 minutes; they are done when the pleats turn translucent and you can see the broth moving inside. REMOVING: lift them out with a slotted spoon, let drain briefly and arrange on a warm plate; immediately scatter plenty of freshly cracked black pepper over the top; no sauce — khinkali are eaten plain. HOW TO EAT: hold the khinkali by the tail with your fingers, tilt slightly and bite a small hole near the seam, then sip the hot broth from inside first before it spills; then eat the rest of the dumpling, leaving the twisted tail on the plate; the number of tails left = how many you ate."}},{"id":149,"origin":{"hi":"मेक्सिको","en":"Mexico","ro":"Mexic"},"name":{"hi":"पोज़ोले","en":"Pozole","ro":"Pozole"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"servings":6,"tipType":"meat","pairingsType":"mexican","ingredients":{"hi":["1.2 किलो हड्डी रहित पोर्क कंधा, 4 सेमी क्यूब में कटा","500 ग्राम पोर्क गर्दन या पूंछ की हड्डियाँ (अधिक समृद्ध शोरबे के लिए)","1 बड़ा सफ़ेद प्याज़ छिलके सहित दो भागों में कटा (रंग के लिए) + परोसने के लिए 1 छोटा प्याज़ बारीक कटा","8 लहसुन की कलियाँ (6 शोरबे के लिए, 2 मिर्च की चटनी के लिए)","3 तेज पत्ते","शोरबे के लिए 1 बड़ा चम्मच मोटा नमक + स्वादानुसार नमक","शोरबे के लिए 4 लीटर ठंडा पानी","800 ग्राम कैन्ड होमिनी मकई, छाना और धोया (या 250 ग्राम सूखी होमिनी रात भर भिगोकर अलग से उबाली हुई)","6 सूखी गुआहीलो मिर्च, डंडी और बीज निकाली हुई","4 सूखी अंचो मिर्च, डंडी और बीज निकाली हुई","2 सूखी अर्बोल मिर्च (वैकल्पिक, तीखेपन के लिए)","1 छोटा चम्मच पिसा जीरा","1 छोटा चम्मच सूखा मैक्सिकन ओरेगानो","परोसने के लिए 200 ग्राम हरी पत्तागोभी बारीक कटी","150 ग्राम लाल मूली पतली कटी","4–6 नींबू टुकड़ों में कटे","12 टोस्टाडास (कुरकुरे मक्के की टॉर्टिया)","टेबल पर छिड़कने के लिए ताज़ा या सूखा ओरेगानो"],"en":["1.2 kg boneless pork shoulder, cut into 4 cm cubes","500 g pork neck bones or pork tail (for a richer broth)","1 large white onion halved, skin on (for color) + 1 small onion finely diced for serving","8 garlic cloves (6 for the broth, 2 for the chili sauce)","3 bay leaves","1 tbsp coarse salt for the broth + salt to taste","4 litres cold water for the broth","800 g canned hominy, drained and rinsed (or 250 g dried hominy soaked overnight and boiled separately)","6 dried guajillo chilies, stemmed and deseeded","4 dried ancho chilies, stemmed and deseeded","2 dried árbol chilies (optional, for heat)","1 tsp ground cumin","1 tsp dried Mexican oregano","200 g green cabbage, finely shredded for serving","150 g red radishes, thinly sliced","4–6 limes cut into wedges","12 tostadas (crisp corn tortillas)","Fresh or dried oregano to scatter at the table"],"ro":["1,2 kg umăr de porc dezosat, tăiat în cuburi de 4 cm","500 g oase de porc cu carne (gât sau coadă) pentru un bulion mai bogat","1 ceapă albă mare tăiată în jumătăți (cu coajă, pentru culoare) + 1 ceapă mică tocată fin pentru servire","8 căței de usturoi (6 pentru bulion, 2 pentru sosul de ardei)","3 frunze de dafin","1 lingură sare grunjoasă pentru bulion + sare după gust","4 litri apă rece pentru bulion","800 g hominy din conservă, scurs și clătit (sau 250 g hominy uscat înmuiat peste noapte și fiert separat)","6 ardei guajillo uscați, decotorați și fără semințe","4 ardei ancho uscați, decotorați și fără semințe","2 ardei de árbol uscați (opțional, pentru iuțeală)","1 linguriță chimion măcinat","1 linguriță oregano mexican uscat","200 g varză verde tocată mărunt, pentru servire","150 g ridichi roșii feliate subțire","4–6 lime tăiate în sferturi","12 tostadas (lipii de porumb crocante)","Oregano proaspăt sau uscat de presărat la masă"]},"howIsMade":{"hi":"शोरबे का आधार: एक बड़े बर्तन में 1.2 किलो क्यूब किया हुआ पोर्क कंधा + 500 ग्राम पोर्क हड्डियाँ, 1 दो भागों में कटा प्याज़ (छिलके सहित), 6 लहसुन की कलियाँ, 3 तेज पत्ते और 1 बड़ा चम्मच नमक डालें। 4 लीटर ठंडा पानी डालकर ढकें। उबाल लाएं, पहले 5 मिनट तक झाग निकालें, फिर हल्की आँच पर धीमा करें।. पोर्क उबालना: बिना ढक्कन के 1.5–2 घंटे उबालें जब तक मांस कांटे से अलग न हो जाए। मांस और हड्डियाँ निकालें, दो कांटों से मोटा-मोटा फाड़ें, अलग रखें। शोरबा (~3.5 लीटर) छानें, बाकी छोड़ दें।. मिर्च भूनना: एक सूखी कड़ाही को मध्यम आँच पर गर्म करें। 6 गुआहीलो + 4 अंचो + 2 अर्बोल (वैकल्पिक) मिर्च को कलछी से दबाते हुए हर तरफ 30 सेकंड भूनें जब तक सुगंधित और हल्के फूले हुए न हो जाएं — जलने न दें वरना शोरबा कड़वा हो जाएगा। एक कटोरे में डालें, उबलते पानी से ढकें और 15 मिनट तक भिगोएं जब तक नर्म न हो जाएं।. मिर्च सॉस: भीगी मिर्च को 2 लहसुन की कलियाँ, 1 छोटा चम्मच जीरा, 1 छोटा चम्मच ओरेगानो और 500 मिली गर्म शोरबे के साथ ब्लेंडर में डालें। तेज़ गति पर 2–3 मिनट तक पूरी तरह चिकना होने तक पीसें। पेस्ट को बारीक छलनी से कटोरे में छानें, गूदा छलनी से दबाकर निकालें — बचे छिलके के टुकड़े छोड़ दें।. मिलाना: छानी हुई मिर्च सॉस को वापस शोरबे के बर्तन में डालें। फाड़ा हुआ मांस और 800 ग्राम सूखा हुआ होमिनी डालें। उबाल लाएं और बिना ढक्कन के 30–40 मिनट तक बीच-बीच में हिलाते हुए पकाएं जब तक शोरबा थोड़ा गाढ़ा न हो जाए और स्वाद मिल जाएं। चखें और नमक समायोजित करें — गहरा स्वादिष्ट होना चाहिए।. गार्निश तैयार करें: जबकि पोज़ोले उबल रहा है, 200 ग्राम पत्तागोभी बारीक काटें, 150 ग्राम मूली पतली काटें, 1 प्याज़ बारीक काटें, 4–6 नींबू टुकड़ों में काटें, ओरेगानो तैयार करें। हर एक को टेबल पर छोटे कटोरों में रखें।. टोस्टाडास: 12 टोस्टाडास को सूखी कड़ाही में हर तरफ 30 सेकंड गर्म करें जब तक कुरकुरे और हल्के सुनहरे न हो जाएं। टेबल की टोकरी में रखें।. परोसें: पोज़ोले को गहरी कटोरियों में डालें। हर मेहमान अपनी कटोरी सजाता है: एक मुठ्ठी पत्तागोभी, मूली का बिखराव, प्याज़ और ओरेगानो की चुटकी, नींबू का रस। टोस्टाडास साथ में खाई जाती हैं — शोरबे में तोड़कर या चम्मच की तरह इस्तेमाल करके। तुरंत, बहुत गर्म खाएं।.","en":"BROTH BASE: place 1.2 kg cubed pork shoulder + 500 g pork bones, 1 halved onion (skin on), 6 garlic cloves, 3 bay leaves and 1 tbsp salt in a large stockpot; cover with 4 litres of cold water; bring to a boil, skim the foam for the first 5 minutes, then reduce to a gentle simmer. SIMMER THE PORK: simmer uncovered 1.5–2 hours until the pork is fork-tender; lift out meat and bones, shred the meat coarsely with two forks, set aside; strain the broth (~3.5 L) and discard the solids. TOAST THE CHILIES: heat a dry skillet over medium heat; toast 6 guajillo + 4 ancho + 2 árbol chilies (optional), pressing them down with a spatula, 30 seconds per side until fragrant and lightly blistered — do not burn or the broth will turn bitter; transfer to a bowl, cover with boiling water, and soak 15 minutes until softened. CHILI SAUCE: transfer the soaked chilies to a blender with 2 garlic cloves, 1 tsp cumin, 1 tsp oregano and 500 ml of the warm broth; blend on high 2–3 minutes until completely smooth; strain the puree through a fine sieve into a bowl, pressing the pulp through — discard the skin bits left behind. COMBINE: pour the strained chili sauce back into the broth pot; add the shredded pork and 800 g drained hominy; bring to a simmer and cook uncovered 30–40 minutes, stirring occasionally, until the broth thickens slightly and the flavours meld; taste and adjust salt — it should be deeply savoury. PREP THE GARNISHES: while the pozole simmers, finely shred 200 g cabbage, thinly slice 150 g radishes, finely dice 1 onion, cut 4–6 limes into wedges, prepare oregano; arrange each in small bowls on the table. TOSTADAS: warm 12 tostadas in a dry skillet 30 seconds per side until crisp and lightly toasted; place in a basket for the table. SERVE: ladle the pozole into deep bowls; each guest customises their bowl: a handful of cabbage, scattering of radish, pinch of onion and oregano, squeeze of lime; tostadas eaten alongside — broken into the broth or used to scoop; eaten immediately while piping hot."}},{"id":150,"origin":{"hi":"ग्वाटेमाला","en":"Guatemala","ro":"Guatemala"},"name":{"hi":"पेपियान","en":"Pepian","ro":"Pepian"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"mexican","ingredients":{"hi":["1.2 किलो हड्डी वाले चिकन के थाई और ड्रमस्टिक (लगभग 8 टुकड़े)","चिकन उबालने के लिए 1.5 लीटर ठंडा पानी + 1 छोटा चम्मच नमक","100 ग्राम कच्चे छिले हुए कद्दू के बीज (पेपिटास)","50 ग्राम तिल के बीज","4 सूखी गुआहीलो मिर्च, डंडी और बीज निकाली हुई","2 सूखी अंचो या पासिया मिर्च, डंडी और बीज निकाली हुई","1 सूखी चिपोटले मिर्च (वैकल्पिक, धुएँदार स्वाद के लिए)","4 मध्यम टमाटर (~500 ग्राम), दो भागों में कटे","4 टोमाटिलोस (~200 ग्राम), छिलका हटाकर दो भागों में कटे","1 मध्यम प्याज़ (~150 ग्राम), चार भागों में कटा","5 बिना छिले लहसुन की कलियाँ","1 सीलोन दालचीनी की छड़ी (~5 सेमी)","2 साबुत लौंग","1 छोटा चम्मच पिसी काली मिर्च + 0.5 छोटा चम्मच पिसा ऑलस्पाइस","1 मक्के की टॉर्टिया, टुकड़ों में फटी (गाढ़ा करने के लिए)","200 ग्राम ग्विस्किल (चायोटे स्क्वैश) या तोरई विकल्प, छिली और 2 सेमी क्यूब में कटी","300 ग्राम आलू, छिले और 2 सेमी क्यूब में कटे","पेस्ट पकाने के लिए 2 बड़े चम्मच वनस्पति तेल","सजाने के लिए 2 बड़े चम्मच बारीक कटा ताज़ा हरा धनिया","स्वादानुसार नमक","परोसने के लिए 500 ग्राम पका हुआ सफ़ेद चावल + गर्म टॉर्टिया"],"en":["1.2 kg bone-in chicken thighs and drumsticks (about 8 pieces)","1.5 L cold water + 1 tsp salt for poaching","100 g raw hulled pumpkin seeds (pepitas)","50 g sesame seeds","4 dried guajillo chilies, stemmed and deseeded","2 dried ancho or pasilla chilies, stemmed and deseeded","1 dried chipotle chili (optional, for smokiness)","4 medium tomatoes (~500 g), halved","4 tomatillos (~200 g), husked and halved","1 medium onion (~150 g), quartered","5 unpeeled garlic cloves","1 Ceylon cinnamon stick (~5 cm)","2 whole cloves","1 tsp ground black pepper + 0.5 tsp ground allspice","1 corn tortilla, torn into pieces (for thickening)","200 g güisquil (chayote squash) or zucchini, peeled and cubed 2 cm","300 g potatoes, peeled and cubed 2 cm","2 tbsp vegetable oil for cooking the paste","2 tbsp fresh cilantro, finely chopped, to garnish","Salt to taste","500 g cooked white rice + warm tortillas to serve"],"ro":["1,2 kg pulpe și pulpe inferioare de pui cu os (aproximativ 8 bucăți)","1,5 L apă rece + 1 linguriță sare pentru fierberea puiului","100 g semințe crude de dovleac decojite (pepitas)","50 g semințe de susan","4 ardei guajillo uscați, decotorați și fără semințe","2 ardei ancho sau pasilla uscați, decotorați și fără semințe","1 ardei chipotle (opțional, pentru afumare)","4 roșii medii (~500 g), tăiate în jumătăți","4 tomatillos (~200 g), curățați de coajă și tăiați în jumătăți","1 ceapă medie (~150 g), tăiată în sferturi","5 căței de usturoi, necurățați","1 batjoc de scorțișoară Ceylon (~5 cm)","2 cuișoare întregi","1 linguriță piper negru măcinat + 0,5 linguriță ienibahar măcinat","1 tortilla de porumb, ruptă în bucăți (pentru îngroșare)","200 g chayote (sau dovlecel ca substitut), curățat și tăiat cuburi de 2 cm","300 g cartofi, curățați și tăiați cuburi de 2 cm","2 linguri ulei vegetal pentru sotare","2 linguri coriandru proaspăt, tocat fin, pentru ornare","Sare după gust","500 g orez alb gătit + tortillas calde pentru servire"]},"howIsMade":{"hi":"चिकन उबालना: एक बड़े बर्तन में 1.2 किलो चिकन को 1.5 लीटर ठंडे पानी और 1 छोटा चम्मच नमक के साथ डालें। उबाल लाएं, झाग निकालें, फिर हल्की आँच पर धीमा करें। 25–30 मिनट तक पकाएं जब तक चिकन ठीक से पक जाए (रस साफ़ निकले)। चिकन को थाली में निकालें और शोरबा (~1.2 लीटर) रखें।. बीज भूनना: एक सूखी कड़ाही में मध्यम आँच पर 100 ग्राम कद्दू के बीज को लगातार चलाते हुए 3–4 मिनट तक भूनें जब तक वे फूलकर सुनहरे-भूरे हो जाएं — जलने न दें। एक कटोरे में निकालें। उसी कड़ाही में 50 ग्राम तिल को लगातार चलाते हुए 1–2 मिनट सुनहरा और सुगंधित होने तक भूनें। उसी कटोरे में डालें।. सब्जियाँ झुलसाना: मध्यम-तेज़ आँच पर सूखी कड़ाही या कोमाल में 4 दो भागों में कटे टमाटर (पहले कटी सतह नीचे), 4 दो भागों में कटे टोमाटिलोस, 1 चार भागों में कटा प्याज़ और 5 बिना छिले लहसुन की कलियों को झुलसाएं। 8–10 मिनट बीच-बीच में पलटते रहें जब तक छिलके जगह-जगह काले न पड़ें और सब्जियाँ नर्म न हो जाएं। ठंडा होने पर लहसुन छीलें।. मिर्च और मसाले भूनना: उसी कड़ाही में 4 गुआहीलो + 2 अंचो + 1 चिपोटले (वैकल्पिक) मिर्च को कलछी से दबाते हुए हर तरफ 20–30 सेकंड भूनें जब तक सुगंधित न हो जाएं — जलने न दें। एक कटोरे में निकालें, उबलते पानी से ढकें और 15 मिनट तक भिगोएं। उसी कड़ाही में 1 दालचीनी, 2 लौंग, 1 छोटा चम्मच काली मिर्च और 0.5 छोटा चम्मच ऑलस्पाइस को 30 सेकंड भूनें। फटी टॉर्टिया के टुकड़ों को हर तरफ 30 सेकंड कुरकुरा होने तक भूनें।. पेस्ट पीसना: एक ब्लेंडर में निथारी मिर्च, झुलसी सब्जियाँ, छीला लहसुन, भुने बीज, टॉर्टिया के टुकड़े और 500 मिली चिकन शोरबा डालें। तेज़ गति पर 3–4 मिनट तक पूरी तरह चिकना होने तक पीसें — रेशमी बनावट के लिए बारीक छलनी से छानें।. सॉस पकाना: बर्तन में 2 बड़े चम्मच तेल मध्यम आँच पर गर्म करें। पिसी हुई पेस्ट डालें — सावधान, यह छिटकेगी। 10 मिनट तक लकड़ी के चम्मच से लगातार चलाते हुए पकाएं जब तक सॉस गहरा न हो जाए और कच्चापन न जाए। सॉस चम्मच के पिछले हिस्से पर चिपकनी चाहिए।. चिकन उबालना: चिकन के टुकड़ों को बर्तन में वापस डालें, फिर बचा 700 मिली शोरबा + 200 ग्राम चायोटे + 300 ग्राम आलू के क्यूब डालें। आंशिक रूप से ढककर हल्की आँच पर 25–30 मिनट पकाएं जब तक आलू और चायोटे मुलायम न हो जाएं और चिकन में सॉस पूरी तरह से समा जाए। बीच-बीच में चलाएं। नमक समायोजित करें।. परोसें: भाप वाले सफ़ेद चावल के बिस्तर पर गहरी प्लेटों में पेपियान डालें। हर परोसी पर ताज़ा हरा धनिया छिड़कें और नींबू निचोड़ें (वैकल्पिक)। सॉस को उठाने के लिए साथ में गर्म मक्के की टॉर्टिया परोसें।.","en":"POACH THE CHICKEN: place 1.2 kg chicken pieces in 1.5 L cold water with 1 tsp salt in a large pot; bring to a boil, skim the foam, then reduce to a gentle simmer; cook 25–30 minutes until the chicken is just cooked through (juices run clear); remove the chicken to a plate and reserve the broth (~1.2 L). TOAST THE SEEDS: in a dry skillet over medium heat, toast 100 g pumpkin seeds, stirring constantly, 3–4 minutes until they puff up and turn golden brown — do not burn; transfer to a bowl; in the same skillet, toast 50 g sesame seeds 1–2 minutes until golden and fragrant, stirring constantly; add to the same bowl. CHAR THE VEGETABLES: in a dry skillet or comal over medium-high heat, char 4 halved tomatoes (cut side down first), 4 halved tomatillos, 1 quartered onion, and 5 unpeeled garlic cloves; turn occasionally for 8–10 minutes until the skins are blackened in spots and the vegetables soften; peel the garlic after they cool. TOAST THE CHILIES AND SPICES: in the same skillet, briefly toast 4 guajillo + 2 ancho + 1 chipotle (optional) chilies, pressing them flat with a spatula, 20–30 seconds per side until fragrant — do not burn; transfer to a bowl and cover with boiling water; soak 15 minutes; in the same skillet, briefly toast 1 cinnamon stick, 2 cloves, 1 tsp pepper, and 0.5 tsp allspice for 30 seconds; toast the torn tortilla pieces 30 seconds per side until crisp. BLEND THE PASTE: in a blender, combine the drained chilies, the charred vegetables, peeled garlic, toasted seeds, toasted tortilla pieces, and 500 ml of the chicken broth; blend on high 3–4 minutes until the paste is completely smooth — strain through a fine sieve if you want it silky. COOK THE SAUCE: heat 2 tablespoons of oil in the pot over medium heat; pour in the blended paste — be careful, it will splutter; simmer 10 minutes, stirring frequently with a wooden spoon, until the sauce darkens and the rawness cooks off; the sauce should coat the back of the spoon. STEW THE CHICKEN: return the chicken pieces to the pot, then pour in the remaining 700 ml broth + 200 g chayote + 300 g potato cubes; simmer gently, partially covered, 25–30 minutes until the potatoes and chayote are fork-tender and the chicken is fully infused with the sauce; stir occasionally to prevent sticking; adjust salt to taste — the sauce should taste deeply spiced and slightly sweet. SERVE: spoon the pepian into deep plates over a bed of steamed white rice; top each serving with a sprinkle of fresh cilantro and a squeeze of lime (optional); serve with warm corn tortillas on the side for scooping up the sauce."}},{"id":151,"origin":{"hi":"रूस","en":"Russia","ro":"Rusia"},"name":{"hi":"ओक्रोश्का","en":"Okroshka","ro":"Okroshka"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"soup","ingredients":{"hi":["1 लीटर सादा केफिर (3.2% वसा), अच्छी तरह ठंडा","500 मिली ठंडा बिना गैस वाला मिनरल पानी (या ठंडा उबला पानी), ठंडा","500 ग्राम मध्यम स्टार्ची आलू (4 टुकड़े), छिलके सहित उबाले फिर छीलकर 1 सेमी क्यूब में कटे","4 बड़े सख्त उबले अंडे, छीलकर 1 सेमी क्यूब में कटे","400 ग्राम खीरा (3 मध्यम), छिले, बड़े बीज हटाए और 0.5 सेमी क्यूब में कटे","300 ग्राम पकी डोक्टोरस्काया सॉसेज या उबला हैम, 0.5 सेमी क्यूब में कटा","150 ग्राम लाल मूली, साफ़ करके 0.5 सेमी क्यूब में कटी","6 हरा प्याज़ (सफ़ेद और हरे भाग अलग), पतला कटा","30 ग्राम ताज़ा डिल, बारीक कटा (सजावट के लिए 1 बड़ा चम्मच अतिरिक्त)","1 बड़ा चम्मच डिजॉन सरसों (वैकल्पिक लेकिन पारंपरिक)","1.5 छोटे चम्मच बारीक नमक + 0.5 छोटा चम्मच ताज़ी पिसी काली मिर्च","1 छोटा चम्मच चीनी (केफिर के खटाई को संतुलित करता है)","1 छोटा चम्मच नींबू का रस या सफ़ेद वाइन सिरका","परोसने के लिए खट्टी क्रीम (स्मेताना)","परोसने के लिए बर्फ़ के टुकड़े और ताज़ी राई की रोटी"],"en":["1 L plain kefir (3.2% fat), well chilled","500 ml cold still mineral water (or cold boiled water), chilled","500 g medium starchy potatoes (4 pieces), boiled in skins then peeled and diced 1 cm","4 large hard-boiled eggs, peeled and diced 1 cm","400 g cucumbers (3 medium), peeled, large seeds scooped out, diced 0.5 cm","300 g cooked doktorskaya sausage or boiled ham, diced 0.5 cm","150 g red radishes, trimmed and diced 0.5 cm","6 spring onions (whites and greens kept separate), thinly sliced","30 g fresh dill, finely chopped (plus 1 tbsp to garnish)","1 tbsp Dijon-style mustard (optional but traditional)","1.5 tsp fine salt + 0.5 tsp freshly ground black pepper","1 tsp sugar (balances the kefir tang)","1 tsp lemon juice or white-wine vinegar","Sour cream (smetana) to drizzle when serving","Ice cubes and fresh dark rye bread for serving"],"ro":["1 L chefir simplu 3,2% grăsime, bine răcit","500 ml apă minerală plată rece sau apă fiartă rece, răcită","500 g cartofi medii (4 bucăți) fierți în coajă, decojiți și tăiați cuburi de 1 cm","4 ouă mari fierte tari, decojite și tăiate cuburi de 1 cm","400 g castraveți (3 bucăți medii), decojiți, fără sâmburi mari și tăiați cuburi de 0,5 cm","300 g cârnați doktorskaya sau șuncă fiartă, tăiată cuburi de 0,5 cm","150 g ridichi roșii, tăiate cuburi de 0,5 cm","6 cepe verzi (cu părți albe și verzi separate), feliate subțire","30 g mărar proaspăt, tocat fin (plus 1 lingură pentru ornare)","1 lingură muștar Dijon (opțional, dar tradițional)","1,5 lingurițe sare fină + 0,5 linguriță piper negru proaspăt măcinat","1 linguriță zahăr (echilibrează aciditatea chefirului)","1 linguriță suc de lămâie sau oțet de vin alb","Smântână (smetana) pentru servire","Cuburi de gheață și pâine neagră proaspătă pentru servire"]},"howIsMade":{"hi":"आलू और अंडे उबालें: ठंडे नमकीन पानी के बर्तन में, 500 ग्राम पूरे आलू (छिलके सहित, रगड़े हुए) को 20–25 मिनट तक उबालें जब तक कांटे से नर्म न हो जाएं। दूसरे बर्तन में 4 अंडे ठंडे पानी में डालकर उबाल लाएं, फिर 9 मिनट तक उबालें (सख्त के लिए)। दोनों को छानें, आलू पर आसानी से छिलने के लिए ठंडा पानी डालें, अंडों को बर्फ़ वाले पानी में 5 मिनट डुबाएं। दोनों को छीलकर 1 सेमी क्यूब में काटें; एक ट्रे पर फैलाएं और 30 मिनट के लिए फ्रिज में रखें — मिलाने से पहले सब कुछ ठंडा होना चाहिए।. खीरे काटें: 400 ग्राम खीरे को छीलें, लंबाई में आधे काटें, चम्मच से बड़े पानी वाले बीज निकालें, फिर 0.5 सेमी क्यूब में काटें — छोटे एकसमान क्यूब आवश्यक हैं, बड़े टुकड़े डूब जाते हैं और सूप ख़राब करते हैं। पेपर टॉवल से पानी सोखें।. प्रोटीन काटें: 300 ग्राम पकी सॉसेज या उबला हैम को 0.5 सेमी क्यूब में काटें — खीरे के समान आकार ताकि हर चम्मच संतुलित हो।. मूली और प्याज़ काटें: 150 ग्राम मूली को साफ़ करके 0.5 सेमी क्यूब में काटें। 6 हरे प्याज़ को काटें (सफ़ेद और हरे भाग अलग रखें)। 30 ग्राम डिल बारीक काटें, सजावट के लिए 1 बड़ा चम्मच रखें। एक छोटे कटोरे में 2 बड़े चम्मच प्याज़ के सफ़ेद हिस्से को एक चुटकी नमक के साथ चम्मच की पीठ से मसलें — सूप में सुगंध छोड़ता है।. ड्रेसिंग: एक बड़े मिक्सिंग बाउल में 1 लीटर ठंडा केफिर + 500 मिली ठंडा पानी + 1 बड़ा चम्मच सरसों + 1 छोटा चम्मच नींबू रस + 1.5 छोटे चम्मच नमक + 0.5 छोटा चम्मच काली मिर्च + 1 छोटा चम्मच चीनी को व्हिस्क करें। 30 सेकंड चिकना होने तक फेंटें, फिर चखें — आधार खट्टा और हल्का मीठा होना चाहिए, ख़ूब मसालेदार क्योंकि कटी हुई सामग्री इसे पतला करेगी।. जोड़ें: सभी कटी हुई सामग्री (आलू, अंडे, खीरे, सॉसेज, मूली, हरा प्याज़ हरा हिस्सा, मसले सफ़ेद, डिल) को केफिर बेस में डालें। बिना कुचले समान रूप से बांटने के लिए कलछी से धीरे से मिलाएं।. ठंडा करें: ओक्रोश्का को ढककर कम से कम 30 मिनट (आदर्श रूप से 1 घंटा) फ्रिज में रखें ताकि स्वाद मिल जाएं और सूप बर्फीला हो जाए। 3 घंटे से ज़्यादा न रखें — खीरे पानी छोड़ने लगेंगे और सूप पतला हो जाएगा।. परोसें: परोसने से पहले धीरे से चलाएं। अच्छी तरह से ठंडे गहरे कटोरों में डालें। हर कटोरी पर 1 बड़ा चम्मच खट्टी क्रीम, कुछ अतिरिक्त डिल डालें, गर्मियों में हर कटोरी में 2 बर्फ़ के टुकड़े। ताज़ी राई की रोटी के साथ तुरंत परोसें; जो ज़्यादा तीखा चाहते हैं उनके लिए मेज़ पर सरसों।.","en":"BOIL THE POTATOES AND EGGS: in a pot of cold salted water, boil 500 g whole potatoes (skins on, scrubbed) 20–25 min until fork-tender; in a second pot, place 4 eggs in cold water, bring to a boil, then simmer 9 min for hard-boiled; drain both, cover potatoes with cold water to peel easily, plunge eggs into ice water 5 min; peel and dice both 1 cm; spread on a tray and chill 30 min in the fridge — everything must be cold before mixing. DICE THE CUCUMBERS: peel 400 g cucumbers, halve lengthwise, scoop out any large watery seeds with a spoon, then dice 0.5 cm — the small even cube is essential, larger pieces sink and ruin the soup; pat with paper towel to remove excess water. DICE THE PROTEIN: dice 300 g cooked sausage or boiled ham into 0.5 cm cubes — the same size as the cucumbers so each spoonful balances. DICE RADISH AND ONIONS: trim and dice 150 g radishes 0.5 cm; slice 6 spring onions (whites and greens kept separate); finely chop 30 g dill, reserve 1 tbsp for garnish; in a small bowl, mash 2 tbsp of the spring-onion whites with a pinch of salt using the back of a spoon — this releases their aroma into the soup. THE DRESSING: in a large mixing bowl, whisk together 1 L cold kefir + 500 ml cold water + 1 tbsp mustard + 1 tsp lemon juice + 1.5 tsp salt + 0.5 tsp pepper + 1 tsp sugar; whisk 30 seconds until smooth, then taste — the base should be tangy and slightly sweet, generously seasoned because the diced ingredients will dilute it. ASSEMBLE: add all diced ingredients (potatoes, eggs, cucumbers, sausage, radish, spring-onion greens and mashed whites, dill) to the kefir base; stir gently with a ladle to distribute evenly without crushing anything. CHILL: cover and refrigerate the okroshka 30 minutes minimum (ideally 1 hour) so the flavours mingle and the soup becomes ice-cold; do not chill longer than 3 hours — the cucumbers will start to release water and the soup turns thin. SERVE: stir gently before serving; ladle into deep, well-chilled bowls; top each bowl with 1 tablespoon sour cream, a few extra dill fronds, and 2 ice cubes per bowl in summer heat; serve immediately with fresh dark rye bread on the side; mustard on the table for those who like it sharper."}},{"id":152,"origin":{"hi":"उज़्बेकिस्तान","en":"Uzbekistan","ro":"Uzbekistan"},"name":{"hi":"पलोव","en":"Plov","ro":"Plov"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":6,"tipType":"meat","pairingsType":"meat","ingredients":{"hi":["कुछ चर्बी सहित 600 ग्राम मेमने का कंधा या बीफ चक, 3 सेमी क्यूब में कटा","प्रामाणिक स्वाद के लिए 100 ग्राम भेड़ की पूंछ की चर्बी (कुर्द्यक) — या विकल्प के रूप में 150 मिली न्यूट्रल सूरजमुखी तेल","500 ग्राम देवज़ीरा या लंबे दाने का बासमती चावल","500 ग्राम पीली गाजर (या 600 ग्राम नारंगी गाजर), 0.5 × 0.5 × 5 सेमी माचिस की तीली के आकार में जूलियन कटी — कद्दूकस न करें","2 बड़े पीले प्याज़ (~300 ग्राम), पतले कटे","2 साबुत लहसुन के सिर (बाहरी छिलके हटाए लेकिन सिर पूरे)","1 बड़ा चम्मच साबुत जीरा (पिसा नहीं)","1 बड़ा चम्मच सूखे बारबरी बेर (ज़ीरा/बारबारिस) — वैकल्पिक लेकिन पारंपरिक","0.5 छोटा चम्मच पिसी हल्दी (रंग के लिए)","1 साबुत सूखा तीखा लाल मिर्च (वैकल्पिक)","1 छोटा चम्मच पिसी काली मिर्च","1.5 बड़े चम्मच बारीक नमक + स्वादानुसार अतिरिक्त नमक","1.2 लीटर उबलता पानी (आरक्षित)","100 ग्राम चना, रात भर भिगोया (वैकल्पिक, पारंपरिक ताशकंद शैली)","परोसने के लिए: सिरके के साथ पतला कटा लाल प्याज़, टमाटर-खीरा अचिचुक सलाद, चपटी रोटी (नॉन)"],"en":["600 g lamb shoulder or beef chuck with some fat, cut into 3 cm cubes","100 g lamb-tail fat (kurdyuk) for authentic flavour — OR 150 ml neutral sunflower oil as a substitute","500 g devzira or long-grain basmati rice","500 g yellow carrots (or 600 g orange carrots), cut into julienne matchsticks 0.5 × 0.5 × 5 cm — do NOT grate","2 large yellow onions (~300 g), thinly sliced","2 whole heads of garlic (papery outer skins removed but heads intact)","1 tbsp whole cumin seeds (not ground)","1 tbsp dried barberries (zira/barbaris) — optional but traditional","0.5 tsp ground turmeric (for colour)","1 dried whole hot red chili (optional)","1 tsp ground black pepper","1.5 tbsp fine salt + extra to season","1.2 L boiling water (reserve)","100 g chickpeas, soaked overnight (optional, traditional Tashkent style)","To serve: thinly sliced red onion with vinegar, achichuk tomato-cucumber salad, flatbread (non)"],"ro":["600 g umăr de miel sau gulaș de vită cu puțină grăsime, tăiat cuburi de 3 cm","100 g grăsime de coadă de oaie (kurdyuk) — opțional pentru aromă autentică — SAU 150 ml ulei neutru de floarea-soarelui ca substitut","500 g orez devzira sau basmati cu bob lung","500 g morcovi galbeni (sau 600 g morcovi portocalii), tăiați julien în bețișoare de 0,5 × 0,5 × 5 cm — NU dați prin răzătoare","2 cepe galbene mari (~300 g), feliate subțire","2 căpățâni de usturoi întregi (cu coaja exterioară curățată, dar capul păstrat întreg)","1 lingură semințe de chimion întregi (nu măcinate)","1 lingură fructe uscate de cătină (zira/barbaris) — opțional, tradițional","0,5 linguriță turmeric măcinat (pentru culoare)","1 ardei roșu iute uscat întreg (opțional)","1 linguriță piper negru măcinat","1,5 linguri sare fină + sare după gust","1,2 L apă clocotită (rezerve)","100 g năut, înmuiat peste noapte (opțional, tradițional Tashkent)","Pentru servire: ceapă roșie feliată subțire cu oțet, salată de roșii cu castraveți (achichuk), pâine plată non"]},"howIsMade":{"hi":"चावल भिगोएं: 500 ग्राम चावल को ठंडे पानी में 4–5 बार धोएं जब तक पानी साफ़ न हो जाए, फिर गुनगुने नमकीन पानी (प्रति लीटर 1 छोटा चम्मच नमक) में 1 घंटे के लिए भिगोएं। यह कदम पलोव के लिए अनिवार्य है — दाने अलग रहते हैं और शोरबा को समान रूप से सोखते हैं। बर्तन में डालने से ठीक पहले छानें।. चर्बी पिघलाएं: एक भारी कास्ट-आयरन कज़ान या डच ओवन में मध्यम आँच पर, 100 ग्राम भेड़ की पूंछ की चर्बी को पिघलाएं जब तक कुरकुरे टुकड़े सुनहरे-भूरे न हो जाएं (लगभग 8 मिनट), फिर उन्हें छेद वाले चम्मच से निकालें। तेल का उपयोग करने पर: 150 मिली तेल को चमकने और हल्के से धुआँ निकलने तक गर्म करें (तेज़ आँच पर लगभग 3 मिनट) — कच्चे स्वाद को निष्क्रिय करने के लिए आवश्यक।. मांस को सीयर करें: आँच को तेज़ करें और 600 ग्राम मांस के क्यूब्स को गर्म चर्बी में एक परत में डालें। बिना हिलाए हर तरफ 2–3 मिनट, कुल 8–10 मिनट, सभी तरफ गहरे भूरे होने तक सीयर करें। मांस को प्लेट में निकालें।. प्याज़ + गाजर: बची हुई चर्बी में 300 ग्राम कटा प्याज़ डालें और हिलाते हुए 5–6 मिनट सुनहरे-भूरे होने तक भूनें। मांस को वापस डालें और 500 ग्राम जूलियन गाजर को ऊपर एक परत में डालें — पहले 5 मिनट तक न हिलाएं (गाजर को भाप से पकने दें)। फिर धीरे से हिलाएं और 8–10 मिनट और पकाएं जब तक गाजर मुरझाई, सुनहरी और कैरमलाइज़ होने लगे।. ज़िरवक (शोरबा बेस): 1.2 लीटर उबलता पानी डालें (मांस और गाजर को 1 सेमी तक ढकना चाहिए)। 1 बड़ा चम्मच साबुत जीरा (पहले हथेलियों में रगड़कर तेल निकालें), 1 बड़ा चम्मच बारबरी, 0.5 छोटा चम्मच हल्दी, 1 सूखी मिर्च, 1 छोटा चम्मच काली मिर्च, 100 ग्राम चना, 1.5 बड़े चम्मच नमक और 2 साबुत लहसुन के सिरों को केंद्र में दबाएं। उबाल लाएं, आँच कम करें और बिना ढक्कन 30 मिनट तक उबालें — यह ज़िरवक है। शोरबा थोड़ा ज़्यादा मसालेदार लगना चाहिए; चावल इसे संतुलित करेगा।. चावल डालें: भीगे चावल को सावधानी से छानें और ज़िरवक के ऊपर समान रूप से फैलाएं (मिलाएं नहीं)। चावल बस डूबा होना चाहिए — यदि नहीं, तो सावधानी से उबलता पानी डालें। आँच को तेज़ करें और बिना ढक्कन के 10–12 मिनट तक पकाएं जब तक दिखाई देने वाला पानी चावल की सतह तक न पहुँचे (छड़ी से जाँचें)। चावल को छेद वाले चम्मच से समतल करें लेकिन नीचे की मांस की परत से कभी न मिलाएं।. ढकें + भाप दें: जब सतह का पानी वाष्पित हो जाए और चावल की सतह पर छोटे भाप के छेद दिखाई दें, चावल को गुम्बद आकार में बनाएं, लकड़ी के चम्मच के हैंडल से नीचे तक 4–5 गहरे छेद बनाएं (भाप निकलने के लिए), आँच को न्यूनतम करें, बर्तन को तंग ढक्कन से ढकें (वाष्प सोखने के लिए ढक्कन के नीचे साफ़ रसोई का तौलिया रखें) और 25 मिनट पकाएं। फिर आँच से हटाकर ढके हुए 15 मिनट विश्राम दें — ढक्कन न उठाएं।. परोसें: ढक्कन हटाएं और लहसुन के सिर और मिर्च निकालें। एक चम्मच से धीरे से खुदाई करें, चावल को ऊपर उठाते हुए और मांस और गाजर को तले से ऊपर लाते हुए, बड़ी सामुदायिक प्लेट पर स्थानांतरित करते समय मिलाएं। मांस और लहसुन को केंद्र में रखें, चावल से घेरा हुआ। तुरंत सिरके वाले पतले कटे लाल प्याज़, ताज़े टमाटर के सलाद और किनारे पर चपटी रोटी के साथ परोसें।.","en":"SOAK THE RICE: wash 500 g rice in cold water 4–5 times until the water runs clear, then soak it in warm salted water (1 tsp salt per litre) for 1 hour; this step is non-negotiable for plov — the grains stay separate and absorb the broth evenly; drain just before adding to the pot. RENDER THE FAT: in a heavy cast-iron kazan or Dutch oven over medium heat, melt 100 g lamb-tail fat until the cracklings are golden brown (about 8 minutes), then remove them with a slotted spoon; if using oil: heat 150 ml oil until it shimmers and faintly smokes (about 3 minutes at high heat) — essential to neutralize the raw taste. SEAR THE MEAT: raise heat to high and add 600 g cubed meat in a single layer to the hot fat; sear undisturbed 2–3 minutes per side, total 8–10 minutes, until deeply browned on all sides; lift the meat out to a plate. ONION + CARROT: in the remaining fat, add 300 g sliced onion and fry, stirring, 5–6 minutes until golden brown; return the meat and add 500 g julienned carrots in a single layer on top — do NOT stir for the first 5 minutes (this lets the carrots steam); then stir gently and cook another 8–10 minutes until the carrots are wilted, golden, and just starting to caramelize. ZIRVAK (BROTH BASE): pour in 1.2 L boiling water (it should cover the meat and carrots by 1 cm); add 1 tbsp cumin seeds (first rubbed briefly between your palms to release the oils), 1 tbsp barberries, 0.5 tsp turmeric, 1 dried chili, 1 tsp black pepper, 100 g chickpeas, 1.5 tbsp salt, and the 2 whole garlic heads pushed into the centre; bring to a boil, reduce heat to low and simmer uncovered 30 minutes — this is the zirvak; the broth must taste slightly over-seasoned; the rice will tame it. ADD THE RICE: drain the soaked rice carefully and spread it evenly over the zirvak (do not stir it in); the rice should just be submerged — if not, add boiling water carefully; raise heat to high and cook uncovered 10–12 minutes until the visible water has reduced to the surface of the rice (poke with a chopstick to check); tap the rice flat with a slotted spoon but never mix it with the meat layer below. COVER + STEAM: once the surface water has evaporated and small steam holes appear on the rice surface, mound the rice into a dome, poke 4–5 deep holes through to the bottom with the handle of a wooden spoon (for steam to escape), reduce heat to the lowest setting, cover the pot with a tight lid (place a clean kitchen towel under the lid to absorb condensation), and cook 25 minutes; then remove from heat and let rest, covered, 15 minutes — do not lift the lid. SERVE: uncover and lift out the garlic heads and chili; gently dig down with a spoon, lifting the rice and bringing the meat and carrots from the bottom to the top, mixing as you transfer to a large communal platter; arrange the meat and garlic on top in the centre, surrounded by rice; serve immediately with sliced red onion sprinkled with vinegar, fresh tomato salad, and flatbread on the side."}},{"id":153,"servings":8,"tipType":"dessert","pairingsType":"dessert","origin":{"hi":"स्लोवेनिया","en":"Slovenia","ro":"Slovenia"},"name":{"hi":"पोटिका","en":"Potica","ro":"Potica"},"category":{"hi":"मिठाई","en":"Dessert","ro":"Desert"},"ingredients":{"hi":["आटे के लिए: 500 ग्राम ब्रेड आटा (या मज़बूत मैदा), गूंथने के लिए अतिरिक्त","7 ग्राम इंस्टेंट सूखा खमीर या 21 ग्राम ताज़ा खमीर","50 ग्राम बारीक चीनी (1 छोटा चम्मच खमीर को खिलाने के लिए, बाकी आटे में)","5 ग्राम बारीक नमक","250 मिली गुनगुना पूर्ण क्रीम दूध (38 °C)","100 ग्राम बिना नमक की मक्खन, पिघलाई और गुनगुनी ठंडी की","आटे के लिए 2 बड़े अंडे की जर्दी + 1 साबुत अंडा","1 बड़ा चम्मच डार्क रम (वैकल्पिक, पारंपरिक)","1 अनुपचारित नींबू का बारीक कद्दूकस किया छिलका","अखरोट भरावन के लिए: 400 ग्राम छिलके वाले अखरोट, बारीक पिसे (ताज़े पिसे — पहले से पिसे काम नहीं करेंगे)","200 मिली गर्म पूर्ण क्रीम दूध","150 ग्राम बबूल शहद (या हल्का फूल शहद)","भरावन के लिए 100 ग्राम बिना नमक की मक्खन, पिघलाई","भरावन के लिए 100 ग्राम बारीक चीनी","2 जर्दी + 2 सफ़ेद अंडे (अलग-अलग कड़े फेंट तक फेंटे)","1 बड़ा चम्मच डार्क रम, 1 छोटा चम्मच पिसी दालचीनी, 0.5 छोटा चम्मच पिसी लौंग, 1 बड़ा चम्मच ताज़ा ब्रेडक्रम्ब","अंत के लिए: 1 अंडा 1 बड़े चम्मच दूध के साथ फेंटा (अंडा लेप), बेक करने के बाद छिड़कने के लिए शक्कर पाउडर"],"en":["For the dough: 500 g bread flour (or strong all-purpose), plus extra for kneading","7 g instant dry yeast OR 21 g fresh yeast","50 g caster sugar (1 tsp to feed the yeast, the rest in the dough)","5 g fine salt","250 ml warm whole milk (38 °C)","100 g unsalted butter, melted and cooled to lukewarm","2 large egg yolks + 1 whole egg for the dough","1 tbsp dark rum (optional, traditional)","Finely grated zest of 1 unwaxed lemon","For the walnut filling: 400 g finely ground shelled walnuts (freshly ground — pre-ground will not work)","200 ml hot whole milk","150 g acacia honey (or mild floral honey)","100 g unsalted butter, melted, for the filling","100 g caster sugar for the filling","2 large egg yolks + 2 egg whites (whipped to stiff peaks separately)","1 tbsp dark rum, 1 tsp ground cinnamon, 0.5 tsp ground cloves, 1 tbsp fresh breadcrumbs","For finishing: 1 egg beaten with 1 tbsp milk (egg wash), icing sugar to dust after baking"],"ro":["Pentru aluat: 500 g făină pentru pâine (T550), plus pentru frământare","7 g drojdie uscată instant SAU 21 g drojdie proaspătă","50 g zahăr fin (1 linguriță pentru a hrăni drojdia, restul în aluat)","5 g sare fină","250 ml lapte integral cald (38 °C)","100 g unt nesărat topit și răcit la călduț","2 gălbenușuri mari + 1 ou întreg pentru aluat","1 lingură rom întunecat (opțional, tradițional)","Coaja rasă fin de la 1 lămâie netratată","Pentru umplutură: 400 g miez de nucă măcinat fin (proaspăt măcinat, nu pre-măcinat — esențial)","200 ml lapte integral fierbinte","150 g miere de salcâm (sau miere florală blândă)","100 g unt nesărat topit pentru umplutură","100 g zahăr fin pentru umplutură","2 gălbenușuri + 2 albușuri (bătute spumă tare separat)","1 lingură rom întunecat, 1 linguriță scorțișoară măcinată, 0,5 linguriță cuișoare măcinate, 1 lingură pesmet proaspăt","Pentru finisare: 1 ou bătut cu 1 lingură lapte (spălătură), zahăr pudră pentru presărat după coacere"]},"howIsMade":{"hi":"खमीर सक्रिय करें: एक छोटे कटोरे में, 7 ग्राम इंस्टेंट सूखे खमीर (या 21 ग्राम ताज़ा) को 250 मिली गुनगुने दूध (~38 °C) में 1 छोटा चम्मच चीनी के साथ घोलें। 10 मिनट तक रहने दें जब तक ऊपर मलाईदार झाग न आ जाए — यदि झाग नहीं बनता तो खमीर मरा हुआ है, फिर से शुरू करें।. आटा: डो हुक वाली स्टैंड मिक्सर में (या हाथ से), 500 ग्राम आटे को बाकी 47 ग्राम चीनी, 5 ग्राम नमक और नींबू के छिलके के साथ मिलाएं। झागदार खमीर-दूध, 2 जर्दी + 1 साबुत अंडा, 100 ग्राम पिघलाई-और-ठंडी की मक्खन और 1 बड़ा चम्मच रम डालें। मध्यम गति पर 10 मिनट (या हाथ से 15 मिनट) तक गूंथें जब तक आटा चिकना, लचीला और कटोरे से साफ़ अलग होने न लगे — नरम लेकिन चिपचिपा नहीं होना चाहिए। फिल्म से ढककर गर्म जगह में 1.5–2 घंटे तक उठने दें जब तक दोगुना न हो जाए।. अखरोट भरावन: 400 ग्राम ताज़े पिसे अखरोट को बड़े कटोरे में डालें। ऊपर से 200 मिली गर्म दूध, 100 ग्राम पिघलाई मक्खन, 150 ग्राम शहद और 100 ग्राम चीनी डालें। अखरोट को पकाने और चीनी घोलने के लिए अच्छी तरह मिलाएं। 10 मिनट ठंडा करें, फिर 2 जर्दी, 1 बड़ा चम्मच रम, 1 छोटा चम्मच दालचीनी, 0.5 छोटा चम्मच लौंग, 1 बड़ा चम्मच ब्रेडक्रम्ब और एक चुटकी नमक मिलाएं। एक अलग कटोरे में 2 सफ़ेद अंडे कड़ी झाग तक फेंटें और 3 भागों में अखरोट मिश्रण में हल्के से मिलाएं — भरावन हवादार और फैलाने योग्य होना चाहिए।. आटा बेलें: एक साफ़ कपड़े पर हल्का आटा छिड़कें और उठा हुआ आटा उस पर पलट दें। धीरे से हवा निकालें, फिर 60 × 40 सेमी, 4–5 मिमी मोटाई के पतले आयत में बेलें — केंद्र से बाहर की ओर काम करें, उठाते और घुमाते हुए चिपकने से रोकें। आटा इतना पतला होना चाहिए कि बेक करने के बाद सर्पिल दिखाई दे, लेकिन इतना मोटा हो कि भरावन को संभाल सके।. भरावन फैलाएं: अखरोट भरावन को आटे पर समान रूप से फैलाएं, लंबे किनारों पर 2 सेमी सीमा छोड़ें। स्पैचुला से धीरे से दबाएं — अधिक न भरें, भरावन 5–6 मिमी मोटा होना चाहिए। यदि कोई जगह पतली हो तो अतिरिक्त पिसे अखरोट छिड़कें।. रोल करें: कपड़े की मदद से आटे को लंबी तरफ़ से कसकर रोल करें, एक लंबा लट्ठा बनाएं। कसकर रोल करें लेकिन इतना कसा नहीं कि भरावन दब जाए। सीवन को बंद करने के लिए दबाएं और सिरों को अंदर भरें। लट्ठा लगभग 60 सेमी लंबा होना चाहिए।. साँचे में + दूसरा उठाव: ट्यूबलर पोटिका साँचे (या 24 सेमी बंट पैन या कुगेलहोफ साँचे) को मक्खन से अच्छी तरह से चिकना करें और आटा छिड़कें। लट्ठे को साँचे में सीवन नीचे रखें, सिरों को बंद रिंग बनाने के लिए जोड़ें (एक साथ चुटकी से दबाएं)। ढीला ढकें और गर्म जगह में 45–60 मिनट उठने दें जब तक आटा स्पष्ट रूप से उठ कर साँचे को लगभग भर न ले। इस बीच ओवन को 175 °C पर पहले से गर्म करें।. बेक करें: ऊपर अंडे का लेप लगाएं। 175 °C ओवन के मध्य रैक पर 45–55 मिनट तक बेक करें — यदि 30 मिनट के बाद ऊपर बहुत जल्दी भूरा हो रहा है तो ढीला फ़ॉयल से ढकें। पोटिका तब तैयार है जब एक सींक साफ़ निकले और आंतरिक तापमान 92–95 °C तक पहुँचे। साँचे में 15 मिनट विश्राम दें, फिर सावधानी से एक तार रैक पर पलटें ताकि पूरी तरह से ठंडा हो जाए। काटने से पहले उदारता से शक्कर पाउडर छिड़कें। मज़बूत कॉफ़ी या चाय के साथ कमरे के तापमान पर परोसें।.","en":"ACTIVATE THE YEAST: in a small bowl, dissolve 7 g instant dry yeast (or 21 g fresh yeast) into 250 ml warm milk (~38 °C) with 1 tsp sugar; let stand 10 minutes until a creamy foam appears on top — if it doesn't foam, the yeast is dead, start over. THE DOUGH: in a stand mixer with dough hook (or by hand), combine 500 g flour with the remaining 47 g sugar, 5 g salt, and lemon zest; pour in the foamed yeast-milk, 2 egg yolks + 1 whole egg, 100 g melted-and-cooled butter, and 1 tbsp rum; knead on medium speed 10 minutes (or 15 by hand) until the dough is smooth, elastic, and pulls cleanly from the bowl — it should be soft but not sticky; cover with film and proof in a warm place 1.5–2 hours until doubled. THE WALNUT FILLING: place 400 g freshly ground walnuts in a large bowl; pour over 200 ml hot milk, 100 g melted butter, 150 g honey, and 100 g sugar; stir well to scald the walnuts and dissolve the sugars; cool 10 minutes, then mix in 2 egg yolks, 1 tbsp rum, 1 tsp cinnamon, 0.5 tsp cloves, 1 tbsp breadcrumbs, and a pinch of salt; in a separate bowl, whip 2 egg whites to stiff peaks, then fold them gently into the walnut mixture in 3 additions — the filling should be airy and spreadable. ROLL THE DOUGH: lightly flour a clean tea towel and turn the proofed dough out onto it; punch down gently, then roll out into a thin rectangle 60 × 40 cm and 4–5 mm thick — work from the centre outward, lifting and rotating to prevent sticking; the dough must be thin enough that the spiral is visible after baking, but thick enough to hold the filling. SPREAD THE FILLING: spread the walnut filling evenly over the rolled dough, leaving a 2 cm border along the long edges; pat it gently with a spatula — do not overload, the filling should be 5–6 mm thick; sprinkle a few extra ground walnuts if any spot oozes thin. ROLL UP: using the tea towel to help, roll up the dough tightly from the long side, forming a long log; roll snug but not so tight you compress the filling; pinch the seam closed and tuck in the ends; the log should be about 60 cm long. SHAPE IN MOLD + SECOND PROOF: grease a tubular potica mold (or a 24 cm Bundt pan or a kugelhopf form) thoroughly with butter and dust with flour; lay the log in the mold, seam side down, joining the ends to form a closed ring (pinch them together); cover loosely and proof again in a warm place 45–60 minutes until the dough has risen visibly to almost fill the mold; meanwhile, preheat the oven to 175 °C. BAKE: brush the top with the egg wash; bake on the middle rack of the 175 °C oven 45–55 minutes — cover loosely with foil after 30 min if the top is browning too fast; the potica is done when a skewer comes out clean and the internal temperature reaches 92–95 °C; let it rest 15 minutes in the mold, then carefully invert onto a wire rack to cool completely; dust generously with icing sugar before slicing; serve at room temperature with strong coffee or tea."}},{"id":154,"servings":4,"tipType":"def","pairingsType":"soup","origin":{"hi":"नाइजीरिया","en":"Nigeria","ro":"Nigeria"},"name":{"hi":"एगुसी सूप","en":"Egusi soup","ro":"Egusi soup"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["250 ग्राम कच्चे एगुसी बीज, बारीक पिसे (या 200 ग्राम पहले से पिसा एगुसी)","हड्डी सहित 600 ग्राम बकरी का मांस या बीफ चक, 4 सेमी टुकड़ों में कटा","200 ग्राम धुएँदार मछली (मैकेरल या कैटफिश) — साफ़, बिना कांटे, टुकड़ों में टूटी (वैकल्पिक, पारंपरिक)","100 ग्राम सूखे झींगे या स्टॉकफिश, 30 मिनट भिगोई और छोटे टुकड़ों में फटी (वैकल्पिक)","1 मध्यम प्याज़ (~150 ग्राम), मोटे कटे","2 स्कॉच बोनेट मिर्च (या 3 हबानेरो) — तीखेपन के अनुसार समायोजित","2 लाल शिमला मिर्च (~300 ग्राम), बीज निकाले","100 मिली लाल ताड़ का तेल","3 बड़े ताज़े टमाटर (~400 ग्राम) या 200 ग्राम टमाटर पेस्ट 200 मिली पानी में मिलाया","4 लहसुन की कलियाँ, बारीक कटी","5 सेमी ताज़ा अदरक, छीला और कद्दूकस किया","2 स्टॉक क्यूब (मैगी या समान, 10 ग्राम)","1 बड़ा चम्मच पिसा क्रेफ़िश (प्रामाणिक स्वाद के लिए आवश्यक) — विकल्प: 1 बड़ा चम्मच पिसा सूखा झींगा","1 तेज पत्ता (या 1 छोटा चम्मच पिसा)","200 ग्राम ताज़ा पालक या उगु कद्दू के पत्ते, धुले और मोटे कटे","1.5 छोटे चम्मच नमक + स्वादानुसार अधिक","1 बड़ा चम्मच इरु/दावादावा (लोकस्ट बीन्स) — वैकल्पिक, पारंपरिक योरूबा","परोसने के लिए: कूटा हुआ यम, फुफू, एबा (गारी), या उबला सफ़ेद चावल"],"en":["250 g raw egusi seeds, finely ground (or 200 g pre-ground egusi)","600 g goat meat or beef chuck on the bone, cut into 4 cm pieces","200 g smoked fish (mackerel or catfish) — cleaned, boned, broken into chunks (optional, traditional)","100 g dried prawns or stockfish (panla), soaked 30 min and torn small (optional)","1 medium onion (~150 g), roughly chopped","2 Scotch bonnet peppers (or 3 habaneros) — adjust to heat tolerance","2 red bell peppers (~300 g), seeded","100 ml red palm oil","3 large fresh tomatoes (~400 g) OR 200 g tomato paste blended with 200 ml water","4 garlic cloves, finely minced","5 cm fresh ginger, peeled and grated","2 stock cubes (Maggi or similar, 10 g)","1 tbsp ground crayfish (essential for authentic flavour) — substitute: 1 tbsp ground dried shrimp","1 bay leaf (or 1 tsp ground bay)","200 g fresh spinach or ugu pumpkin leaves, washed and roughly chopped","1.5 tsp salt + more to taste","1 tbsp locust beans (iru/dawadawa) — optional, traditional Yoruba addition","To serve: pounded yam, fufu, eba (gari), or boiled white rice"],"ro":["250 g semințe egusi brute, măcinate fin (sau 200 g egusi pre-măcinat)","600 g carne de capră sau gulaș de vită cu os, tăiată în bucăți de 4 cm","200 g pește afumat (macrou sau somn) — curățat, dezosat, rupt în bucăți (opțional, tradițional)","100 g creveți uscați sau stockfish, înmuiat 30 minute și rupt mic (opțional)","1 ceapă medie (~150 g), tocată grosier","2 ardei iuți Scotch bonnet (sau 3 habanero) — ajustează după toleranța la iuțeală","2 ardei roșii grași (~300 g), fără semințe","100 ml ulei roșu de palmier","3 roșii mari proaspete (~400 g) sau 200 g pastă de roșii amestecată cu 200 ml apă","4 căței de usturoi, tocați fin","5 cm rădăcină de ghimbir proaspăt, curățată și rasă","2 cuburi Maggi sau pentru condimentare (10 g)","1 lingură crayfish măcinat (esențial pentru aroma autentică) — substitut: 1 lingură creveți uscați măcinați","1 frunză de dafin (sau 1 linguriță dafin măcinat)","200 g spanac proaspăt sau frunze de ugu (pumpkin leaves), spălate și tocate","1,5 lingurițe sare + sare după gust","1 lingură semințe de locust (iru/dawadawa) — opțional, tradițional Yoruba","Pentru servire: igname pisată, fufu, eba (gari) sau orez fiert"]},"howIsMade":{"hi":"एगुसी पेस्ट: 250 ग्राम एगुसी बीज को मसाला ग्राइंडर या फ़ूड प्रोसेसर में 30 सेकंड पल्स करें जब तक बारीक पिसे लेकिन अभी पेस्ट न बने। एक छोटे कटोरे में 200 मिली गुनगुने पानी के साथ हुम्मस जैसा गाढ़ा पेस्ट बनाएं। पूरी तरह से हाइड्रेट होने के लिए 10 मिनट बैठने दें — यही सिग्नेचर बनावट का राज़ है: बाहर दानेदार, अंदर मलाईदार।. मांस पकाएं: एक भारी बर्तन में 600 ग्राम कटा मांस, 1 कटा प्याज़, 4 कटी लहसुन की कलियाँ, कद्दूकस की अदरक, 2 स्टॉक क्यूब, 1 छोटा चम्मच नमक और 1 लीटर पानी मिलाएं। उबाल लाएं, फिर ढककर 40–50 मिनट (बकरी हो तो अधिक) पकाएं जब तक मांस नरम हो लेकिन टूटे नहीं। छानें और 800 मिली शोरबा बचाएं। मांस अलग रखें।. मिर्च बेस ब्लेंड करें: ब्लेंडर में 2 लाल शिमला मिर्च, 2 स्कॉच बोनेट और 3 ताज़े टमाटर (या पेस्ट और पानी) मिलाएं। पूरी तरह से चिकना होने तक 1–2 मिनट ब्लेंड करें। चौड़े पैन में डालें और मध्यम आँच पर 15 मिनट उबालें — मिश्रण आधा हो जाना चाहिए और रंग गहरा ईंट-लाल। यह सघनता आवश्यक है वरना सूप पतला होगा।. ताड़ के तेल में बेस भूनें: अपने सूप बर्तन में मध्यम आँच पर 100 मिली ताड़ का तेल 2 मिनट गर्म करें जब तक चमकने लगे (धुआँ न निकालें — ज़्यादा गर्म करना स्वाद नष्ट करता है)। सघन मिर्च-टमाटर बेस डालें और 8–10 मिनट हिलाते हुए भूनें जब तक तेल सतह पर तैरे और मिश्रण थोड़ा गहरा हो जाए। इसे \"बेस भूनना\" कहते हैं।. एगुसी डालें: हाइड्रेट एगुसी पेस्ट को बड़े चम्मच से लें और उबलते मिर्च बेस में डम्पलिंग-स्टाइल में गिराएं — हिलाएं नहीं। डम्पलिंग को 5 मिनट बिना छुए पकने दें, फिर धीरे से मिलाएं। कुछ अपना आकार बनाए रखेंगे (गांठें) जबकि अन्य टूटकर सॉस को गाढ़ा करेंगे — यह वांछित बनावट है।. शोरबा + मांस + मछली: बचाया 800 मिली शोरबा डालें। पका मांस, 200 ग्राम धुएँदार मछली (टुकड़ों में), 100 ग्राम भिगोए सूखे झींगे/स्टॉकफिश (वैकल्पिक), 1 बड़ा चम्मच पिसा क्रेफ़िश, 1 बड़ा चम्मच लोकस्ट बीन्स (वैकल्पिक), और 1 तेज पत्ता डालें। धीरे से चलाएं, उबाल लाएं और बिना ढक्कन 15–20 मिनट पकाएं जब तक सूप पुडिंग जैसी गाढ़ी संगति में सिकुड़ जाए — चम्मच पर ढेर बननी चाहिए, शोरबे की तरह न बहे।. हरी पत्तेदार सब्जियाँ डालें: उबलते सूप में 200 ग्राम कटा पालक (या उगु/कद्दू के पत्ते) मिलाएं। बिना ढक्कन 5–7 मिनट पकाएं जब तक पत्तियाँ मुरझा जाएं लेकिन चमकीली हरी रहें। चखें और नमक तथा तीखापन समायोजित करें। सूप गहरा स्वादिष्ट, हल्का अखरोटी (एगुसी से), साफ़ ताड़ के तेल का स्वाद और बढ़ती मिर्च की गर्मी होनी चाहिए।. आराम और परोसें: आँच बंद करें और सूप को 5 मिनट आराम दें — इस छोटी राहत में स्वाद नाटकीय रूप से मिल जाते हैं। गहरे कटोरों में परोसें, चुने हुए \"निगलने\" (कूटा यम, फुफू, एबा या अमाला) को बगल में रखें। दाहिने हाथ से खाएं: एक छोटा टुकड़ा लें, सूप में डुबोएं और बिना चबाए निगलें। उबला सफ़ेद चावल हल्का विकल्प है।.","en":"EGUSI PASTE: pulse 250 g egusi seeds in a spice grinder or food processor 30 seconds until finely ground but not yet pasty; in a small bowl, mix with 200 ml warm water into a thick, hummus-like paste; let it sit 10 minutes to hydrate fully — this is the secret to the signature lumpy-creamy texture. COOK THE MEAT: in a heavy pot, combine 600 g cut meat with 1 chopped onion, 4 minced garlic, grated ginger, 2 stock cubes, 1 tsp salt and 1 L water; bring to boil, then simmer covered 40–50 minutes (longer if using goat) until the meat is tender enough to bite easily but not falling apart; strain and reserve 800 ml of the broth; set the meat aside. BLEND THE PEPPER BASE: in a blender, combine 2 red bell peppers, 2 Scotch bonnet peppers, and 3 fresh tomatoes (or paste-and-water mix); blend 1–2 minutes until completely smooth; pour into a wide pan and simmer over medium heat 15 minutes — the mix should reduce by half and the colour deepen to a rich brick-red; this concentration is essential or the soup will be watery. FRY THE PALM-OIL BASE: in your soup pot over medium heat, warm 100 ml palm oil 2 minutes until it just shimmers (do NOT smoke it — over-smoking destroys the flavour); add the reduced pepper-tomato base and fry, stirring, 8–10 minutes until the oil floats to the surface and the mixture darkens slightly; this is called \"frying the base\". ADD THE EGUSI: take the hydrated egusi paste by tablespoons and drop dumpling-style into the simmering pepper base — do NOT stir; let the dumplings cook undisturbed 5 minutes, then gently fold them in; some will hold their shape (the lumps) while others break apart and thicken the sauce — this is the desired texture. ADD STOCK + MEAT + FISH: pour in 800 ml reserved meat broth; add the cooked meat, 200 g smoked fish (broken into chunks), 100 g soaked dried prawns/stockfish (optional), 1 tbsp ground crayfish, 1 tbsp locust beans (optional), and 1 bay leaf; stir gently, bring to a simmer and cook uncovered 15–20 minutes until the soup has reduced and thickened to a pudding-like consistency — it should mound on a spoon, not pour like broth. ADD GREENS: stir in 200 g chopped spinach (or ugu/pumpkin leaves) into the simmering soup; cook 5–7 minutes uncovered until the greens are wilted but still bright green; taste and adjust salt and heat; the soup should taste deeply savoury, slightly nutty (from the egusi), with a clean palm-oil finish and a building chili heat. REST AND SERVE: turn off the heat and let the soup rest 5 minutes — the flavours meld dramatically in this short rest; serve in deep bowls with the swallow of choice (pounded yam, fufu, eba, or amala) on the side; eat with the right hand: take a small lump of swallow, dip into the soup, and swallow without chewing; boiled white rice is a milder option."}},{"id":155,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"hi":"पोलैंड","en":"Poland","ro":"Polonia"},"name":{"hi":"कोटलेट स्हाबोवी","en":"Kotlet schabowy","ro":"Kotlet schabowy"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["हड्डी रहित 4 पोर्क लोइन चॉप (~180–200 ग्राम प्रत्येक, ~1.5–2 सेमी मोटाई) — कुल लगभग 800 ग्राम","पोर्क के लिए 1 छोटा चम्मच बारीक नमक","0.5 छोटा चम्मच ताज़ी पिसी सफ़ेद मिर्च","नर्म करने वाली भिगाई के लिए 200 मिली पूर्ण क्रीम दूध (पोलिश तरकीब)","ब्रेडिंग के लिए 80 ग्राम साधारण मैदा","1 बड़े चम्मच दूध और एक चुटकी नमक के साथ फेंटे 3 बड़े अंडे","200 ग्राम ताज़ा बारीक ब्रेडक्रम्ब (एक दिन पुरानी ब्रेड से घर का बना सबसे अच्छा) या पंको","तलने के लिए 80 ग्राम लार्ड (पारंपरिक) या 100 मिली न्यूट्रल सूरजमुखी तेल","अंतिम बेस्टिंग के लिए 30 ग्राम बिना नमक की मक्खन","1 नींबू टुकड़ों में कटा (आधुनिक सजावट)","डिल आलू के लिए: छिले 800 ग्राम स्टार्ची आलू + 30 ग्राम मक्खन + 1 छोटा गुच्छा कटा डिल + उबालने के पानी के लिए नमक","भुने सॉरक्राउट के लिए: छाना 400 ग्राम सॉरक्राउट + 1 छोटा बारीक कटा प्याज़ + 1 बड़ा चम्मच लार्ड + 100 मिली पानी"],"en":["4 boneless pork loin chops (~180–200 g each, ~1.5–2 cm thick) — about 800 g total","1 tsp fine salt for the pork","0.5 tsp freshly ground white pepper","200 ml whole milk for the tenderizing soak (the Polish trick)","80 g all-purpose flour for breading","3 large eggs beaten with 1 tbsp milk and a pinch of salt","200 g fine fresh breadcrumbs (homemade from day-old bread is best) or panko","80 g lard (traditional) OR 100 ml neutral sunflower oil for frying","30 g unsalted butter for the finishing baste","1 lemon, cut into wedges (modern garnish)","For dill potatoes: 800 g floury potatoes peeled + 30 g butter + 1 small bunch chopped dill + salt for the cooking water","For sautéed sauerkraut: 400 g drained sauerkraut + 1 small onion finely chopped + 1 tbsp lard + 100 ml water"],"ro":["4 cotlete de porc din mușchi (~180–200 g fiecare, ~1,5–2 cm grosime) — aproximativ 800 g total","1 linguriță sare fină pentru carne","0,5 linguriță piper alb proaspăt măcinat","200 ml lapte integral pentru marinada de tendierare","80 g făină pentru panare","3 ouă mari bătute cu 1 lingură lapte și un vârf de sare","200 g pesmet fin proaspăt (de casă, din pâine de o zi) sau panko","80 g untură (tradițional) SAU 100 ml ulei neutru de floarea-soarelui pentru prăjit","30 g unt nesărat pentru finisare","1 lămâie tăiată în sferturi (garnitură modernă)","Pentru cartofi cu mărar: 800 g cartofi făinoși decojiți + 30 g unt + 1 bunch mic de mărar tocat + sare pentru apa de fierbere","Pentru varza murată: 400 g varză murată scursă + 1 ceapă mică tocată + 1 lingură untură + 100 ml apă"]},"howIsMade":{"hi":"पोर्क को कूटें: हर पोर्क चॉप को दो प्लास्टिक रैप शीटों के बीच रखें और चपटे मीट हथौड़े से केंद्र से बाहर की ओर हर तरफ 30 सेकंड कूटें जब तक चॉप 6–7 मिमी मोटी और लगभग दोगुनी न हो जाएं — एक समान पकाने के लिए मोटाई समान होनी चाहिए। चर्बी की किनारी पर 3–4 कट लगाएं ताकि वह सिकुड़े नहीं।. दूध में भिगोएं: कूटे चॉप को सूखाएं और हर तरफ नमक और सफ़ेद मिर्च रगड़ें। उथली डिश में रखें, 200 मिली दूध डालें ताकि चॉप लगभग डूब जाएं, ढककर 30 मिनट (अधिकतम 2 घंटे) फ्रिज में रखें — लैक्टिक एसिड स्वाद बदले बिना मांस को नर्म करेगा।. ब्रेडिंग स्टेशन सेटअप: एक पंक्ति में तीन उथली प्लेट: प्लेट 1 में 80 ग्राम मैदा; प्लेट 2 में 3 फेंटे अंडे + 1 बड़ा चम्मच दूध + एक चुटकी नमक; प्लेट 3 में 200 ग्राम बारीक ब्रेडक्रम्ब। क्रम मायने रखता है: हर चॉप को मैदा → अंडा → ब्रेडक्रम्ब के क्रम में जाना चाहिए, कदम छोड़े बिना।. चॉप पर ब्रेडिंग करें: एक चॉप दूध से निकालें, अतिरिक्त को टपकने दें, और मैदे में डुबोएं, अतिरिक्त को झाड़ें — मैदा पतला और एकसमान कवर करना चाहिए वरना अंडा नहीं चिपकेगा। फिर अंडे में डुबोएं, 2 सेकंड टपकने दें, फिर ब्रेडक्रम्ब में दोनों तरफ़ मज़बूती से दबाएं, थपथपाकर चिपकाएं। एक प्लेट पर रखें। चारों के लिए दोहराएं। 5 मिनट विश्राम दें — ब्रेडिंग हाइड्रेट होती है और बंधती है।. आलू उबालें: इस बीच 800 ग्राम आलू छीलें और 4 सेमी क्यूब में काटें। ठंडे नमकीन पानी में डालें, उबाल लाएं और 15–18 मिनट तक उबालें जब तक कांटे से नर्म न हो जाएं। छानें, बिना आँच के 2 मिनट बर्तन में वापस डालें ताकि सूख जाएं, फिर 30 ग्राम मक्खन और कटा डिल मिलाएं।. सॉरक्राउट भूनें: एक अलग पैन में मध्यम आँच पर 1 बड़ा चम्मच लार्ड पिघलाएं। 1 बारीक कटा प्याज़ डालें, 5 मिनट सुनहरा होने तक भूनें। 400 ग्राम छाना सॉरक्राउट और 100 मिली पानी डालें; ढककर 15 मिनट पकाएं, फिर ढक्कन हटाकर 5 मिनट और पकाएं जब तक अधिकांश तरल वाष्पीकृत न हो जाए। काली मिर्च के एक चुटकी से सीज़न करें।. श्निट्ज़ल तलें: एक बड़े भारी पैन में मध्यम-तेज़ आँच पर 80 ग्राम लार्ड (या 100 मिली तेल) चमकने तक गर्म करें (175 °C, या ब्रेडक्रम्ब का टुकड़ा संपर्क में आते ही चटकता है)। चॉप को एक बार में 2 तलें ताकि पैन भीड़ न हो, हर तरफ 3–4 मिनट बिना छुए तब तक तलें जब तक गहरे सुनहरे और कुरकुरे न हो जाएं; आंतरिक तापमान 70 °C तक पहुँचना चाहिए। अंतिम 30 सेकंड में पैन में 15 ग्राम मक्खन डालें और श्निट्ज़ल पर डालने के लिए पैन झुकाएं — मक्खन भूरा झाग बनाता है और ब्रेडिंग को पोलिश रविवार की प्रतिष्ठित सुगंध देता है। पेपर टॉवल बिछी रैक पर निकालें (प्लेट पर नहीं, जो नीचे को नर्म कर देगी)।. तुरंत परोसें: हर श्निट्ज़ल को डिल आलू और सॉरक्राउट के ढेर के साथ प्लेट करें। अगर पसंद हो तो नींबू का टुकड़ा सजावट के लिए डालें (निचोड़ चर्बी को हल्का करता है)। चाकू और कांटे से खाएं — कभी सिर्फ़ कांटे से नहीं, यह क्लासिक्स का सम्मान करने वाला व्यंजन है। अधिकतम कुरकुरेपन के लिए तलने के 5 मिनट के भीतर श्निट्ज़ल खा लेना चाहिए।.","en":"POUND THE PORK: place each pork chop between two sheets of cling film and pound with a flat meat mallet from the centre outward, 30 seconds per side, until the chops are 6–7 mm thick and almost doubled in size — they must be even thickness for uniform cooking; score the fatty rim 3–4 times to prevent curling. MILK SOAK: pat the pounded chops dry and rub each side with salt and white pepper; place in a shallow dish, pour over 200 ml milk so the chops are mostly submerged, cover and refrigerate 30 minutes (up to 2 hours) — the lactic acid tenderizes the meat without altering the flavour. SET UP THE BREADING STATION: three shallow plates in a row: plate 1 with 80 g flour; plate 2 with 3 beaten eggs + 1 tbsp milk + a pinch of salt; plate 3 with 200 g fine breadcrumbs; the line-up matters: every chop must travel flour → egg → breadcrumbs without skipping. BREAD THE CHOPS: lift one chop from the milk, let the excess drip off, and dredge in flour, shaking off the excess — the flour must coat thinly and evenly or the egg won't stick; then dip into the egg, letting it drip 2 seconds, then press firmly into the breadcrumbs on both sides, patting them on so they adhere; set on a plate; repeat for all 4 chops; let them rest 5 minutes — the breading hydrates and binds. BOIL THE POTATOES: meanwhile, peel 800 g potatoes and cut into 4 cm chunks; place in cold salted water, bring to boil, and simmer 15–18 minutes until fork-tender; drain, return to the pot off heat for 2 minutes to dry, then toss with 30 g butter and chopped dill. SAUTÉ THE SAUERKRAUT: in a separate pan, melt 1 tbsp lard over medium heat; add 1 finely chopped onion, fry 5 minutes until golden; add 400 g drained sauerkraut and 100 ml water; simmer covered 15 minutes, then uncover and cook 5 minutes more until most of the liquid has evaporated and the kraut is tender; season with a twist of pepper. FRY THE SCHNITZELS: heat 80 g lard (or 100 ml oil) in a large heavy skillet over medium-high heat until shimmering (175 °C, or a breadcrumb sizzles immediately on contact); fry the chops 2 at a time so the pan isn't crowded, 3–4 minutes per side undisturbed until deeply golden brown and crisp; the internal temperature should reach 70 °C; in the last 30 seconds, add 15 g butter to the pan and tilt to baste the schnitzels — the butter foams brown and gives the breading its iconic Polish-Sunday aroma; transfer to a rack lined with paper towels to drain (NOT a plate, which would steam the bottom soggy). SERVE IMMEDIATELY: plate each schnitzel alongside a mound of dill potatoes and a heap of sauerkraut; garnish with a lemon wedge if you like (the squeeze brightens the fat); eat with a knife and fork — never just a fork, this is a respect-the-classics dish; the schnitzel should be eaten within 5 minutes of frying for maximum crunch."}},{"id":156,"origin":{"hi":"दक्षिण कोरिया","en":"South Korea","ro":"Coreea de Sud"},"name":{"hi":"किम्बाप","en":"Kimbap","ro":"Kimbap"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"korean","ingredients":{"hi":["360 ग्राम (2 कप) छोटे दाने का सफ़ेद चावल, बिना पका — ~4 रोल के लिए","चावल पकाने के लिए 540 मिली (2¼ कप) ठंडा पानी","भुनी नोरी 4 शीट (gim, 20 × 18 सेमी)","दानमुजी (पीली मूली का अचार) की 4 पट्टियाँ, नोरी की लंबाई में, ~1 सेमी मोटी","बेबी पालक 100 ग्राम (या 1 छोटा गुच्छा साधारण पालक)","मध्यम गाजर 2 (~150 ग्राम), 0.5 × 0.5 × 8 सेमी जूलियन","बड़े अंडे 3","नकली केकड़ा स्टिक 200 ग्राम (या पका हुआ हैम, या मेयो के साथ मिक्स्ड कैन्ड टूना)","खीरा 100 ग्राम (1 छोटा कोरियाई या 1/3 इंग्लिश), बीज निकाला और लंबा कटा","भुना तिल का तेल 3 बड़े चम्मच (चावल के लिए 1.5 बड़ा चम्मच, पालक के लिए 0.5 छोटा चम्मच, बाकी बाहरी रब के लिए)","बारीक नमक 1.5 छोटे चम्मच (चावल के लिए 1 छोटा चम्मच, सब्ज़ियों और अंडों के लिए चुटकी)","भुने तिल 2 छोटे चम्मच","अंडे और गाजर पकाने के लिए न्यूट्रल तेल 1 बड़ा चम्मच","पिसी सफ़ेद मिर्च 0.5 छोटा चम्मच","बांस की चटाई (गिम्बल) + प्लास्टिक रैप"],"en":["360 g (2 cups) short-grain white rice, uncooked — makes ~4 rolls","540 ml (2¼ cups) cold water for cooking the rice","4 sheets toasted nori (gim, 20 × 18 cm)","4 strips danmuji (yellow pickled radish), cut to nori length, ~1 cm thick","100 g baby spinach (or 1 small bunch regular spinach)","2 medium carrots (~150 g), julienned 0.5 × 0.5 × 8 cm matchsticks","3 large eggs","200 g imitation crab sticks (or cooked ham, or tuna mixed with mayo)","100 g cucumber (1 small Korean cucumber or 1/3 English cucumber), seeded and cut into long batons","3 tbsp toasted sesame oil (1.5 tbsp for the rice, 0.5 tsp for spinach, the rest for the outer rub)","1.5 tsp fine salt (1 tsp for the rice, pinches for veg and eggs)","2 tsp toasted sesame seeds","1 tbsp neutral oil for cooking the eggs and carrots","0.5 tsp ground white pepper","Bamboo rolling mat (gimbal) + plastic wrap"],"ro":["360 g (2 căni) orez cu bob scurt necopt, pentru ~4 rulouri","540 ml (2¼ căni) apă rece pentru fierberea orezului","4 foi de nori prăjit (gim, 20 × 18 cm)","4 fâșii de danmuji (ridiche galbenă murată), tăiate la lungimea norii, grosime ~1 cm","100 g spanac baby (sau 1 mănunchi mic de spanac obișnuit)","2 morcovi medii (~150 g), tăiați julien 0,5 × 0,5 × 8 cm","3 ouă mari, bătute","200 g bețe de crab imitație (sau șuncă fiartă sau ton conservat amestecat cu maioneză)","100 g castraveți (1 mic castravete coreean sau 1/3 castravete englezesc), fără sâmburi, tăiat fâșii lungi","3 linguri ulei de susan prăjit (1,5 lingură pentru orez, 0,5 linguriță pentru spanac, restul pentru exterior)","1,5 linguriță sare fină (1 linguriță pentru orez, restul pentru legume)","2 lingurițe semințe de susan prăjite","1 lingură ulei neutru pentru gătit ouăle și sotat morcovii","0,5 linguriță piper alb măcinat","Covoraș de bambus (kimbal) + folie alimentară"]},"howIsMade":{"hi":"चावल: 360 ग्राम चावल को ठंडे पानी में 3–4 बार धोएं जब तक पानी साफ़ न हो। अच्छी तरह छानें, फिर एक भारी बर्तन में 540 मिली ताज़ा ठंडे पानी के साथ डालें। मध्यम-तेज़ आँच पर बिना ढक्कन के उबाल लाएं (3–4 मिनट), फिर ढक्कन लगाएं, सबसे कम आँच पर करें और 12 मिनट पकाएं — ढक्कन न उठाएं। आँच से हटाएं और ढके हुए 10 मिनट विश्राम दें। चावल नर्म, थोड़ा चिपचिपा, अलग दानों वाला होना चाहिए. चावल को मसाला दें: गर्म रहते हुए एक चौड़े कटोरे में ट्रांसफ़र करें। ऊपर 1.5 बड़ा चम्मच तिल का तेल, 1 छोटा चम्मच नमक और 2 छोटे चम्मच भुना तिल छिड़कें। चावल कलछी से काटने की गति में धीरे से मिलाएं — कभी भी ज़ोर से न हिलाएं, दाने टूट जाएंगे और गुदगुदे हो जाएंगे। नम कपड़े से ढककर गुनगुना होने तक ठंडा करें (10–15 मिनट). पालक: एक छोटे बर्तन में नमकीन पानी उबालें। 100 ग्राम पालक को 30 सेकंड के लिए सिर्फ़ मुरझाने तक उबालें। तुरंत ठंडे पानी में डालकर पकाव रोकें और चमकीला हरा रंग बनाए रखें। मुठ्ठी से जितना हो सके कस कर निचोड़ें ताकि सारा पानी निकल जाए — गीला पालक रोल बिगाड़ देगा। 0.5 छोटा चम्मच तिल का तेल और एक चुटकी नमक से सीज़न करें. गाजर: एक छोटे पैन में 1 छोटा चम्मच न्यूट्रल तेल मध्यम आँच पर गरम करें। 150 ग्राम जूलियन गाजर और एक चुटकी नमक डालें, 2 मिनट तले जब तक थोड़ी नर्म हो लेकिन कुरकुरी रहे। ठंडा होने के लिए प्लेट में निकालें — मुरझाई तेलयुक्त गाजर रोल को तोड़ देगी. अंडे: 3 अंडे को एक चुटकी नमक और 0.5 छोटा चम्मच सफ़ेद मिर्च के साथ फेंटें। नॉन-स्टिक पैन में 1 छोटा चम्मच न्यूट्रल तेल मध्यम-धीमी आँच पर गरम करें, अंडे डालें और पैन झुकाकर 25 × 20 सेमी पतली समान शीट बनाएं। ऊपर सेट होने तक 2 मिनट पकाएं, पलटें नहीं। बोर्ड पर स्लाइड करें, 2 मिनट ठंडा करें और नोरी की चौड़ाई की 4 लंबी पट्टियों में काटें. भराई तैयार करें: 100 ग्राम खीरे को लंबाई में 8 लंबे टुकड़ों में काटें, चम्मच से बीज वाले बीच को निकाल दें। 200 ग्राम केकड़े की स्टिक को लंबाई में आधा करें। दानमुजी की 4 पट्टियाँ नोरी की लंबाई में काटें। उस क्रम में ट्रे पर रखें जिसमें आप उन्हें रखेंगे: पालक → गाजर → खीरा → केकड़ा → अंडा → दानमुजी. हर किम्बाप रोल करें: बांस की चटाई की लकड़ियों को क्षैतिज रूप से रखें; नोरी की चमकदार तरफ़ नीचे की ओर रखें। गीले अंगुलियों से ~150 ग्राम चावल को नोरी के निचले 3/4 भाग में पतली एकसमान परत में फैलाएं, दूर की किनारी पर 4 सेमी खाली छोड़ दें। पास की किनारी से 3 सेमी अंदर एक तंग बंडल में पंक्तिबद्ध करें: पालक, गाजर, खीरा, केकड़ा, अंडा और दानमुजी। चटाई की पास वाली किनारी उठाएं और मज़बूती से आगे रोल करें, पहली घुमावदार से भराई को चावल के नीचे छिपाते हुए, फिर दूर की किनारी तक कसकर रोल करते रहें। सीवन के साथ दबाकर सील करें. काटें और परोसें: हर रोल के बाहर 0.5 छोटा चम्मच तिल का तेल हल्के से ब्रश करें ताकि नोरी चमकदार हो और चाकू से न चिपके। हर कट के बीच में तेज़ चाकू को नम कपड़े से पोंछें। हर रोल को एक निर्णायक धक्के से 8 बराबर गोलाई में काटें (आरी न चलाएं) — कुल 32 टुकड़े। प्लेट पर सजाएं, तिल छिड़कें। रोल करने के 4 घंटे के भीतर खाएं; किम्बाप को कभी फ्रिज में न रखें (दोबारा गर्म करने पर चावल सख्त हो जाते हैं और नोरी नम हो जाती है).","en":"Rinse 360 g rice in cold water 3–4 times until the water runs clear, drain well, then put in a heavy pot with 540 ml fresh cold water, bring to a boil uncovered over medium-high heat (3–4 min), cover, reduce to the lowest possible heat and cook 12 minutes without lifting the lid, then remove from heat and rest covered 10 minutes until the rice is tender, slightly sticky, with separate grains. While the rice is still hot, transfer it to a wide bowl, drizzle 1.5 tbsp sesame oil, 1 tsp salt and 2 tsp toasted sesame seeds over the top and fold gently with a rice paddle in cutting motions — never stir aggressively or the grains break and turn mushy — then cover with a damp cloth and let cool to lukewarm (10–15 min). Bring a small pot of salted water to a boil and blanch 100 g spinach for 30 seconds until just wilted, then drain and rinse under cold water immediately to stop the cooking and preserve the bright green colour, squeeze in your fist as hard as possible to remove all water (wet spinach ruins the roll) and season with 0.5 tsp sesame oil and a pinch of salt. Heat 1 tsp neutral oil in a small pan over medium heat, add 150 g julienned carrot and a pinch of salt and stir-fry 2 minutes until just softened but still crisp, then tip onto a plate to cool — limp, oily carrots will break the roll. Beat 3 eggs with a pinch of salt and 0.5 tsp white pepper, heat 1 tsp neutral oil in a non-stick pan over medium-low heat, pour in the eggs and tilt the pan to form a thin even sheet 25 × 20 cm, cook 2 minutes until set on top without flipping, then slide onto a board, let cool 2 minutes and cut into 4 long strips the width of the nori. Cut 100 g cucumber lengthwise into 8 long batons and scrape the seedy core out with a teaspoon, split 200 g crab sticks in half lengthwise and cut 4 strips of danmuji to nori length, then arrange everything on a tray in the order you'll lay them: spinach, carrot, cucumber, crab, egg, danmuji. Place the bamboo mat with the slats running horizontally and lay a sheet of nori shiny-side down, then with wet fingers spread ~150 g rice in a thin even layer over the bottom 3/4 of the nori while leaving a clean 4 cm strip at the far edge, and about 3 cm in from the near edge line up one strip each of spinach, carrot, cucumber, crab, egg and danmuji in a tight bundle, then lift the near edge of the mat and roll firmly forward, tucking the fillings under the rice with the first roll and continuing to roll tightly to the far edge, then press along the seam to seal. Brush the outside of each roll lightly with 0.5 tsp sesame oil to make the nori glossy and prevent it from sticking to the knife, wipe a sharp knife with a damp cloth between cuts, then slice each roll into 8 even rounds with one decisive push (no sawing) for 32 pieces total, arrange on a plate and sprinkle with sesame seeds — eat within 4 hours of rolling and never refrigerate kimbap."},"timeMins":{"total":60,"active":50}},{"id":157,"servings":6,"tipType":"meat","pairingsType":"latin","origin":{"hi":"चिली","en":"Chile","ro":"Chile"},"name":{"hi":"पास्टेल दे चोक्लो","en":"Pastel de Choclo","ro":"Pastel de Choclo"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["पीनो (मांस भराई) के लिए: 600 ग्राम बीफ कीमा (चक या सर्लोइन, 20% चर्बी)","2 बड़े प्याज़ (~400 ग्राम), बारीक कटे","4 लहसुन की कलियाँ, बारीक कटी","भूनने के लिए 2 बड़े चम्मच न्यूट्रल तेल","पीनो के लिए 1.5 छोटे चम्मच नमक + 1 छोटा चम्मच ताज़ी पिसी काली मिर्च","पिसा जीरा 1 छोटा चम्मच + मीठा पपरिका 1 छोटा चम्मच + सूखा ओरेगानो 1 छोटा चम्मच + ají color 1 छोटा चम्मच (या धुएँदार पिमेंटन विकल्प)","बीफ शोरबा या पानी 60 मिली","काली किशमिश 80 ग्राम, 100 मिली गुनगुने पानी में 15 मिनट भिगो कर छाने","हड्डी सहित त्वचा सहित चिकन थाई 4 (~600 ग्राम) — उबाले और हाथ से फाड़े (पारंपरिक जोड़)","चिकन उबालने के लिए 1 तेज पत्ता + 800 मिली पानी","उबले अंडे 6, छिले और आधे काटे (प्रति परोसी 1)","बीज निकाले काले जैतून 18–24 (कलामाता शैली)","मकई पेस्ट (choclo) के लिए: ताज़ी सफ़ेद मकई के दाने 1.2 किलो (~6–8 भुट्टे) या पिघलाई जमी मकई 1 किलो","पूर्ण क्रीम दूध 80 मिली","बिना नमक की मक्खन 60 ग्राम","ताज़ी तुलसी की पत्तियाँ 1 बड़ा चम्मच, बारीक कटी (चिली की पहचान)","मकई पेस्ट के लिए बारीक नमक 1 छोटा चम्मच + ग्रैन्युलेटेड शक्कर 1 बड़ा चम्मच","बेक करने से पहले ऊपर छिड़कने के लिए ग्रैन्युलेटेड शक्कर 2 बड़े चम्मच (प्रतिष्ठित कैरमलाइज़्ड क्रस्ट के लिए)"],"en":["For the pino (meat filling): 600 g ground beef (chuck or sirloin, 20% fat)","2 large onions (~400 g), finely diced","4 garlic cloves, finely minced","2 tbsp neutral oil for sautéing","1.5 tsp salt + 1 tsp freshly ground black pepper for the pino","1 tsp ground cumin + 1 tsp sweet paprika + 1 tsp dried oregano + 1 tsp aji color (or pimentón as substitute)","60 ml beef stock or water","80 g dark raisins, soaked 15 min in 100 ml warm water, then drained","4 bone-in skin-on chicken thighs (~600 g) — poached and pulled (traditional addition)","1 bay leaf + 800 ml water to poach the chicken","6 hard-boiled eggs, peeled and halved (1 per portion)","18–24 pitted black olives (kalamata-style)","For the corn paste (choclo): 1.2 kg fresh white corn kernels (~6–8 ears) OR 1 kg thawed frozen corn","80 ml whole milk","60 g unsalted butter","1 tbsp fresh basil leaves, finely chopped (the Chilean signature)","1 tsp fine salt + 1 tbsp granulated sugar for the corn paste","2 tbsp granulated sugar to sprinkle over the top before baking (for the iconic caramelized crust)"],"ro":["Pentru pino: 600 g vită tocată (gulaș sau pulpă, 20% grăsime)","2 cepe mari (~400 g), tăiate fin","4 căței de usturoi, tocați fin","2 linguri ulei neutru pentru sotat","1,5 lingurițe sare + 1 linguriță piper negru proaspăt măcinat (pentru pino)","1 linguriță chimion măcinat + 1 linguriță boia dulce + 1 linguriță oregano uscat + 1 linguriță aji color (sau pimentón pentru substitut)","60 ml supă de vită sau apă","80 g stafide negre, înmuiate 15 minute în 100 ml apă caldă, apoi scurse","4 pulpe de pui cu os și piele (~600 g) — fierte și destrămate (tradițional)","1 frunză de dafin + 800 ml apă pentru fiertul puiului","6 ouă tari, decojite și tăiate în jumătăți (1 per porție)","18–24 măsline negre cu sâmbure scos (stil kalamata)","Pentru pasta de porumb: 1,2 kg boabe proaspete de porumb alb (~6–8 știuleți) SAU 1 kg porumb congelat dezghețat","80 ml lapte integral","60 g unt nesărat","1 lingură busuioc proaspăt, tocat fin (semnătura chiliană)","1 linguriță sare fină + 1 lingură zahăr granulat pentru pasta de porumb","2 linguri zahăr granulat pentru presărat pe suprafață înainte de coacere (crusta caramelizată iconică)"]},"howIsMade":{"hi":"प्याज़ कैरमलाइज़ करें: एक भारी पैन में मध्यम आँच पर 2 बड़े चम्मच तेल गरम करें और 400 ग्राम बारीक कटा प्याज़ 0.5 छोटे चम्मच नमक के साथ डालें। बार-बार चलाते हुए 12–15 मिनट तक भूनें जब तक गहरा सुनहरा और पारदर्शी न हो जाए — इस चरण को जल्दी न करें, कैरमलाइज़्ड प्याज़ पीनो स्वाद की नींव है। 4 कटी लहसुन की कलियाँ डालें और 1 मिनट और सुगंधित होने तक पकाएं।. बीफ को भूरा करें: आँच मध्यम-तेज़ कर दें। प्याज़ में 600 ग्राम बीफ कीमा डालें, लकड़ी के चम्मच से तोड़ते हुए। 6–8 मिनट पकाएं जब तक मांस गुलाबी न रहे और सारा तरल वाष्पित न हो जाए। 1 छोटा चम्मच जीरा, 1 छोटा चम्मच पपरिका, 1 छोटा चम्मच ओरेगानो, 1 छोटा चम्मच ají color (यदि उपयोग कर रहे हों), बचा 1 छोटा चम्मच नमक और 1 छोटा चम्मच काली मिर्च डालें। मसालों के स्वाद को खिलने के लिए 1 मिनट चलाएं।. पीनो को पूरा करें: 60 मिली शोरबा और छानी हुई किशमिश डालें। 3–4 मिनट पकाएं जब तक मिश्रण नम हो लेकिन सूप जैसा न हो — पीनो चमकदार होना चाहिए और चम्मच पर अपना आकार बनाए रखना चाहिए। आँच से हटाएं और 15 मिनट ठंडा करें — विश्राम स्वाद को गहरा करता है और मकई टॉपिंग को फिसलने से रोकता है।. चिकन उबालें: जब पीनो विश्राम कर रहा हो, 4 चिकन थाई को 800 मिली हल्के नमकीन पानी में 1 तेज पत्ते के साथ 25 मिनट तक उबालें जब तक पक न जाए। छानें, थोड़ा ठंडा करें, फिर हड्डियों से मांस को बड़े टुकड़ों में निकालें (त्वचा फेंक दें)। पास्टेल के साथ परोसने के लिए शोरबा बचाएं।. मकई पेस्ट: एक फूड प्रोसेसर या ब्लेंडर में 1.2 किलो मकई के दाने, 80 मिली दूध और 1 छोटा चम्मच नमक के साथ 30 सेकंड पल्स करें जब तक मोटा पेस्ट न बने — बनावट बनाए रखें, चिकनी क्रीम में ब्लेंड न करें। 60 ग्राम मक्खन के साथ भारी सॉसपैन में मध्यम आँच पर ट्रांसफ़र करें। 10–15 मिनट लकड़ी के चम्मच से लगातार चलाते हुए पकाएं जब तक पेस्ट पैन के किनारों से अलग होने वाली पोलेंटा जैसी संगति में गाढ़ा न हो जाए। 1 बड़ा चम्मच कटी तुलसी डालें और आँच से हटाएं।. इकट्ठा करें: ओवन को 200 °C पर पहले से गरम करें, ऊपरी एक तिहाई में रैक रखें। पीनो को 6 व्यक्तिगत मिट्टी के पाइला (या एक 28 सेमी बेकिंग डिश) में बांटें। प्रत्येक हिस्से पर उबले चिकन के टुकड़े, 1 उबले अंडे का आधा, 3–4 जैतून और किशमिश का छोटा ढेर सजावटी रूप से रखें। ऊपर गर्म मकई पेस्ट को समान 2 सेमी परत में चम्मच से डालें, किनारों तक सील करने के लिए चम्मच की पीठ से चिकना करें।. शक्कर की परत: मकई टॉपिंग पर 2 बड़े चम्मच ग्रैन्युलेटेड शक्कर समान रूप से छिड़कें। यह कदम परक्राम्य नहीं है — बेकिंग के दौरान शक्कर कैरमलाइज़ हो जाएगी और प्रतिष्ठित गहरी, लगभग जली हुई सुनहरी परत बन जाएगी जो पास्टेल दे चोक्लो को किसी भी अन्य शेपर्ड पाई से अलग करती है।. बेक करें: पास्टेल्स को 200 °C ओवन के ऊपरी रैक पर रखें और 25–30 मिनट बेक करें जब तक मकई टॉपिंग सुनहरी भूरी हो जाए और शक्कर सतह पर गहरे धब्बों में कैरमलाइज़ हो जाए। कोने बुलबुले बना सकते हैं — यह सही है। परोसने से पहले 10 मिनट विश्राम दें (भराई को बैठना है)। पाइला से सीधे पेब्रे सॉस और एक गिलास चिली कारमेनेर के साथ परोसें।.","en":"CARAMELIZE THE ONIONS: in a heavy skillet over medium heat, warm 2 tbsp oil and add 400 g finely diced onion with 0.5 tsp salt; sauté 12–15 minutes, stirring often, until deeply golden and translucent — DO NOT rush this step, the caramelized onion is the foundation of pino flavour; add 4 minced garlic cloves and cook 1 minute more until fragrant. BROWN THE BEEF: raise the heat to medium-high; add 600 g ground beef to the onions, breaking it apart with a wooden spoon; cook 6–8 minutes until the meat is no longer pink and any liquid has evaporated; add 1 tsp cumin, 1 tsp paprika, 1 tsp oregano, 1 tsp aji color (if using), the remaining 1 tsp salt and 1 tsp pepper; stir 1 minute to bloom the spices. FINISH THE PINO: pour in 60 ml beef stock and the drained raisins; simmer 3–4 minutes until the mixture is moist but not soupy — the pino should be glossy and able to hold its shape on a spoon; remove from heat and let cool 15 minutes — letting it rest deepens the flavour and prevents the corn topping from sliding off. POACH THE CHICKEN: while the pino rests, simmer 4 chicken thighs in 800 ml lightly salted water with 1 bay leaf for 25 minutes until cooked through; drain, cool slightly, then pull the meat from the bones in large chunks (skin discarded); reserve the stock for serving alongside the pastel. CORN PASTE: in a food processor or blender, pulse 1.2 kg fresh corn kernels with 80 ml milk and 1 tsp salt 30 seconds until coarsely pureed — keep some texture, do not blend to a smooth cream; transfer to a heavy saucepan with 60 g butter over medium heat; cook 10–15 minutes, stirring constantly with a wooden spoon, until the puree thickens to a polenta-like consistency that pulls away from the sides of the pan; stir in 1 tbsp chopped basil and remove from heat. ASSEMBLE: preheat oven to 200 °C with a rack in the upper third; divide the pino between 6 individual earthenware pailas (or one 28 cm baking dish); top each portion with chunks of poached chicken, 1 hard-boiled egg half, 3–4 olives, and a small pile of raisins arranged decoratively; spoon the warm corn paste over the top in an even 2 cm layer, smoothing with the back of a spoon to seal all the way to the edges. SUGAR CRUST: sprinkle 2 tbsp granulated sugar evenly over the corn topping; this is non-negotiable — the sugar caramelizes during baking into the iconic dark, almost-burnt golden crust that distinguishes pastel de choclo from any other shepherd's pie. BAKE: place the pastels on the upper rack of the 200 °C oven and bake 25–30 minutes until the corn topping is golden brown and the sugar has caramelized into dark spots across the surface; the corners may bubble — that's correct; let rest 10 minutes before serving (the filling needs to set); serve straight from the paila with a side of pebre salsa and a glass of Chilean Carmenère."}},{"id":158,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"hi":"सर्बिया","en":"Serbia","ro":"Serbia"},"name":{"hi":"प्लजेस्काविका","en":"Pljeskavica","ro":"Pljeskavica"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["मोटा कीमा बीफ चक 500 ग्राम (~20% चर्बी)","मोटा कीमा मेमने का कंधा 300 ग्राम (या हल्के संस्करण के लिए सूअर का कंधा)","1 बड़ा प्याज़ (~200 ग्राम), बारीक कद्दूकस और पानी निचोड़ा (रसीली पैटी का राज़)","4 लहसुन की कलियाँ, 0.5 छोटे चम्मच नमक के साथ कुटी पेस्ट में","1 बड़ा चम्मच मीठा हंगेरियन पपरिका","1 छोटा चम्मच तीखी पपरिका (धुएँदार या कश्मीरी, वैकल्पिक)","1.5 छोटे चम्मच बारीक नमक","1 छोटा चम्मच ताज़ी पिसी काली मिर्च","1 छोटा चम्मच बेकिंग सोडा (बाल्कन तरकीब — पैटी को रसीली और मुलायम रखती है)","100 मिली बर्फ़ ठंडा कार्बोनेटेड पानी (फूले लचीले बनावट के लिए)","0.5 छोटा चम्मच सूखा मरजोरम या ओरेगानो","ग्रिल या पैन के लिए 1 बड़ा चम्मच वनस्पति तेल","परोसने के लिए: 4 सोमुन या पीटा ब्रेड (~18 सेमी), 1 मध्यम लाल प्याज़ (~150 ग्राम) पतला कटा, अजवार 200 ग्राम, कायमक या खट्टी क्रीम 100 ग्राम, ताज़ा अजमोद, नींबू के टुकड़े (वैकल्पिक)"],"en":["500 g coarsely ground beef chuck (~20% fat)","300 g coarsely ground lamb shoulder (or pork shoulder for a milder version)","1 large onion (~200 g), finely grated and water squeezed out (the secret to juicy patties)","4 garlic cloves, crushed with 0.5 tsp salt into a paste","1 tbsp sweet Hungarian paprika","1 tsp hot paprika (smoked or Kashmiri, optional)","1.5 tsp fine salt","1 tsp freshly ground black pepper","1 tsp baking soda (the Balkan trick — helps keep them juicy and tender)","100 ml ice-cold sparkling water (for the fluffy springy texture)","0.5 tsp dried marjoram or oregano","1 tbsp vegetable oil for the grill or pan","To serve: 4 somun or pita breads (~18 cm rounds), 1 medium red onion (~150 g) thinly sliced, 200 g ajvar red-pepper relish, 100 g kajmak or sour cream, fresh parsley, lemon wedges (optional)"],"ro":["500 g vită tocată grosier (ceafă, ~20% grăsime)","300 g umăr de miel tocat grosier (sau umăr de porc pentru o versiune mai blândă)","1 ceapă mare (~200 g), rasă fin și stoarsă bine (secretul cărnurilor suculente)","4 căței de usturoi, zdrobiți cu 0,5 linguriță sare într-o pastă","1 lingură boia ungurească dulce","1 linguriță boia iute (afumată sau Kashmir, opțional)","1,5 lingurițe sare fină","1 linguriță piper negru proaspăt măcinat","1 linguriță bicarbonat de sodiu (trucul balcanic — păstrează carnea suculentă și frageda)","100 ml apă minerală carbogazoasă rece ca gheața (pentru textura pufoasă)","0,5 linguriță maghiran uscat sau oregano","1 lingură ulei vegetal pentru grătar sau tigaie","Pentru servire: 4 chifle somun sau pita (~18 cm), 1 ceapă roșie medie (~150 g) tăiată subțire, 200 g ajvar, 100 g kajmak sau smântână, pătrunjel proaspăt, lămâie (opțional)"]},"howIsMade":{"hi":"प्याज़ की तैयारी: 200 ग्राम प्याज़ को कद्दूकस की बारीक तरफ़ से कद्दूकस करें। एक साफ़ कपड़े में डालकर सिंक के ऊपर ज़ोर से निचोड़ें ताकि जितना संभव हो उतना तरल निकल जाए — कम से कम 80 मिली रस निकलना चाहिए। गीला प्याज़ पैटी को ग्रिल पर बिखेर देता है। निचोड़े गूदे के 2 बड़े चम्मच मांस के लिए बचाएं।. मांस मिलाएं: एक बड़े कटोरे में 500 ग्राम बीफ + 300 ग्राम मेमने (या सूअर) को मिलाएं। 2 बड़े चम्मच निचोड़ा प्याज़ का गूदा, 0.5 छोटे चम्मच नमक के साथ कुटी 4 लहसुन की कलियाँ, 1 बड़ा चम्मच मीठा पपरिका, 1 छोटा चम्मच तीखी पपरिका (यदि उपयोग कर रहे हों), 1 छोटा चम्मच नमक, 1 छोटा चम्मच काली मिर्च, 0.5 छोटा चम्मच मरजोरम और 1 छोटा चम्मच बेकिंग सोडा डालें। हाथ से 4–5 मिनट तक ज़ोर से गूंथें — मिश्रण चिपचिपा और स्पष्ट रूप से कसा हुआ हो जाना चाहिए, जो प्लजेस्काविका को उसकी प्रतिष्ठित उछाल देता है।. कार्बोनेटेड पानी डालें: गूंथना जारी रखते हुए 100 मिली बर्फ़ ठंडे कार्बोनेटेड पानी को धीरे-धीरे 25 मिली के 4 हिस्सों में डालें। पानी कीमे में हवा भरता है और बेकिंग सोडा के साथ मिलकर पैटी को रसीली और मुलायम रखता है। फिल्म से ढककर कम से कम 4 घंटे, आदर्श रूप से रात भर फ्रिज में रखें — स्वाद विकास और बंधन के लिए विश्राम परक्राम्य नहीं है।. पैटी का आकार: विश्राम किए हुए मांस को ~225 ग्राम प्रत्येक के 4 बराबर हिस्सों में बांटें। गीले हाथों से (चिपकने से रोकने के लिए) हर हिस्से को गेंद में रोल करें, फिर 18–20 सेमी व्यास और 8 मिमी मोटाई के सपाट डिस्क में चपटा करें। डिस्क का व्यास उस ब्रेड के बराबर होना चाहिए जिसमें परोसा जाएगा। अंगूठे से बीच में हल्के से दबाएं ताकि एक डिम्पल बन जाए — यह पैटी को ग्रिल पर गुंबदाकार होने से रोकता है।. दूसरा ठंडा करना: बने पैटी को बेकिंग पेपर बिछी ट्रे पर रखें। ढीला ढककर 20 मिनट फ्रिज में रखें ताकि सख्त हो जाएं। इस बीच चारकोल ग्रिल को मध्यम-तेज़ आँच (200 °C) पर जलाएं या 1 बड़ा चम्मच तेल के साथ भारी रिज्ड ग्रिडल पैन को बस धुआँ निकलने तक गरम करें।. ग्रिल करें: पैटी को हल्के से तेल से ब्रश करें। हर तरफ 4–5 मिनट बिना हिलाए ग्रिल करें — केवल एक बार पलटें। पैटी तब तैयार है जब आंतरिक तापमान 65 °C (मध्यम) तक पहुँचे और दोनों तरफ गहरी महोगनी क्रस्ट बने, ग्रिल के निशान दिखाई दें। उन्हें दबाने से बचें — आप सारा रस खो देंगे और चरण 3 का काम बेकार हो जाएगा।. ब्रेड को गरम करें: ग्रिलिंग के आखिरी मिनट में 4 सोमुन या पीटा को ग्रिल पर हर तरफ 30 सेकंड रखें जब तक गर्म और हल्के से टोस्ट न हो जाएं। हर पीटा को एक किनारे से काटकर पैटी के लिए पर्याप्त बड़ी जेब बनाएं।. परोसें: हर गर्म पीटा जेब में एक पैटी रखें। ऊपर से 1 बड़ा चम्मच अजवार, कायमक का एक टुकड़ा, कटे कच्चे लाल प्याज़ का उदार ढेर, अजमोद की एक चुटकी और चाहें तो नींबू निचोड़ें डालें। ब्रेड गर्म रहते हुए हाथों से तुरंत खाएं — गर्म रसीले मांस, ठंडे कायमक और धुएँदार अजवार का विपरीत बाल्कन स्ट्रीट फ़ूड की आत्मा है।.","en":"ONION PREP: grate 200 g onion on the fine side of a box grater; transfer to a clean tea towel and squeeze HARD over the sink to remove as much liquid as possible — at least 80 ml of juice should come out; wet onion makes the patties fall apart on the grill; reserve 2 tbsp of the squeezed pulp for the meat. MIX THE MEAT: in a large bowl, combine 500 g beef + 300 g lamb (or pork); add 2 tbsp squeezed onion pulp, 4 garlic cloves crushed with 0.5 tsp salt, 1 tbsp sweet paprika, 1 tsp hot paprika (if using), 1 tsp salt, 1 tsp pepper, 0.5 tsp marjoram and 1 tsp baking soda; knead vigorously by hand 4–5 minutes — the mixture should become sticky and noticeably tightened, which gives pljeskavica its signature springy bounce. ADD SPARKLING WATER: slowly drizzle in 100 ml ice-cold sparkling water while continuing to knead, in 4 additions of 25 ml each; the water aerates the mince and combines with the baking soda to keep the patties juicy and tender; cover with film and refrigerate at least 4 hours, ideally overnight — the rest is non-negotiable for flavour development and binding. SHAPE THE PATTIES: divide the rested meat into 4 equal portions of ~225 g each; with wet hands (to prevent sticking), roll each portion into a ball, then flatten into a flat disc 18–20 cm in diameter and 8 mm thick; the disc must be the same diameter as the bread it will be served in; press the centre slightly with your thumb to create a dimple — this prevents the patty from doming up on the grill. SECOND CHILL: place the shaped patties on a parchment-lined tray; cover loosely and refrigerate 20 minutes to firm up; meanwhile, fire up a charcoal grill to medium-high (200 °C) or heat a heavy ridged griddle pan with 1 tbsp oil until just smoking. GRILL: brush the patties lightly with oil; grill 4–5 minutes per side without moving — turn ONCE only; the patties are done when the internal temperature reaches 65 °C (medium) and a deep mahogany crust has formed on both sides with visible grill marks; resist pressing them — you'll lose all the juice and undo the work you did in step 3. WARM THE BREAD: during the last minute of grilling, place 4 somun or pita on the grill for 30 seconds per side until warmed and lightly toasted; split each pita open at one edge to make a pocket large enough for the patty. SERVE: slip one patty into each warm pita pocket; top with 1 tbsp ajvar, a knob of kajmak, a generous mound of sliced raw red onion, a sprinkle of parsley, and a squeeze of lemon if you like; eat immediately with your hands while the bread is warm — the contrast of hot juicy meat, cool kajmak, and smoky ajvar is the soul of Balkan street food."}},{"id":159,"servings":4,"tipType":"dessert","pairingsType":"dessert","origin":{"hi":"नीदरलैंड","en":"Netherlands","ro":"Olanda"},"name":{"hi":"पॉफर्चेस","en":"Poffertjes","ro":"Poffertjes"},"category":{"hi":"मिठाई","en":"Dessert","ro":"Desert"},"ingredients":{"hi":["कुट्टू का आटा 250 ग्राम (पारंपरिक, सिग्नेचर स्वाद देता है) — या 100 ग्राम कुट्टू + 150 ग्राम साधारण मैदा हल्के विकल्प के रूप में","इंस्टेंट सूखा खमीर 7 ग्राम (या 21 ग्राम ताज़ा खमीर)","1 बड़ा चम्मच ग्रैन्युलेटेड शक्कर (1 छोटा चम्मच खमीर खिलाने के लिए, बाकी बैटर में)","बारीक नमक 0.5 छोटा चम्मच","गुनगुना पूर्ण क्रीम दूध 350 मिली (38 °C)","बड़े अंडे 2","बैटर के लिए पिघलाई गुनगुनी बिना नमक की मक्खन 30 ग्राम","पैन और अंतिम सजावट के लिए अतिरिक्त बिना नमक की मक्खन 50 ग्राम","1 बड़ा चम्मच डार्क रम या वेनिला अर्क (वैकल्पिक, पारंपरिक)","परोसने के लिए: ऊपर रखने के लिए 30 ग्राम ठंडी बिना नमक की मक्खन के क्यूब, छिड़कने के लिए 60 ग्राम शक्कर पाउडर, स्ट्रोपवॉफल या मेपल सिरप (वैकल्पिक), ताज़ी बेरी (वैकल्पिक)","उपकरण: 24–30 गड्ढों वाला कास्ट-आयरन poffertjespan पैन (या एब्लेस्किवर पैन); पलटने के लिए छोटी लकड़ी की कटार"],"en":["250 g buckwheat flour (traditional, gives the signature flavour) — OR 100 g buckwheat + 150 g all-purpose flour as a milder substitute","7 g instant dry yeast (or 21 g fresh yeast)","1 tbsp granulated sugar (1 tsp to feed the yeast, the rest in the batter)","0.5 tsp fine salt","350 ml warm whole milk (38 °C)","2 large eggs","30 g unsalted butter, melted and cooled to lukewarm for the batter","50 g additional unsalted butter for the pan + finishing","1 tbsp dark rum or vanilla extract (optional, traditional)","To serve: 30 g cold unsalted butter cubes for topping, 60 g icing sugar to dust, stroopwafel syrup or maple syrup (optional), fresh berries (optional)","Equipment: poffertjespan cast-iron pan with 24–30 dimples (or aebleskiver pan); small wooden skewer or chopstick for flipping"],"ro":["250 g făină de hrișcă (tradițional, dă aroma signature) — SAU 100 g hrișcă + 150 g făină albă ca substitut mai blând","7 g drojdie uscată instant (sau 21 g drojdie proaspătă)","1 lingură zahăr (1 linguriță pentru drojdie, restul în aluat)","0,5 linguriță sare fină","350 ml lapte integral cald (38 °C)","2 ouă mari","30 g unt nesărat topit și răcit la călduț pentru aluat","50 g unt nesărat suplimentar pentru tigaie și finisare","1 lingură rom întunecat sau extract de vanilie (opțional, tradițional)","Pentru servire: 30 g unt rece în cuburi pentru a pune deasupra, 60 g zahăr pudră pentru presărat, sirop stroopwafel sau de arțar (opțional), fructe de pădure proaspete (opțional)","Echipament: tigaie poffertjespan din fontă cu 24–30 adâncituri (sau tigaie aebleskiver); bețișoară de lemn pentru întors"]},"howIsMade":{"hi":"खमीर सक्रिय करें: एक सॉसपैन में 350 मिली दूध को लगभग 38 °C तक गरम करें (गुनगुना — कलाई पर आरामदायक)। एक बड़े कटोरे में डालें, सतह पर 7 ग्राम इंस्टेंट सूखा खमीर और 1 छोटा चम्मच चीनी छिड़कें, और 10 मिनट के लिए छोड़ दें जब तक ऊपर मलाईदार झाग न आ जाए। यदि झाग नहीं बनता है, तो खमीर मर चुका है — ताज़ा खमीर के साथ फिर से शुरू करें।. बैटर बनाएं: फेंटे खमीर वाले दूध में 2 अंडे फेंटकर चिकना करें। एक अलग कटोरे में 250 ग्राम कुट्टू का आटा (या कुट्टू+मैदा मिक्स), बची हुई 2 छोटे चम्मच चीनी और 0.5 छोटा चम्मच नमक छानें। सूखी सामग्री को गीली में दो हिस्सों में डालें, हर बार चिकना होने तक फेंटें — गांठें न हों। 30 ग्राम पिघलाई ठंडी मक्खन और 1 बड़ा चम्मच रम (यदि उपयोग कर रहे हों) फेंटें। बैटर पतली क्रीम की संगति का होना चाहिए जो व्हिस्क से रिबन की तरह गिरे।. पहला उठाव: कटोरे को साफ़ कपड़े से ढककर गर्म जगह में 60 मिनट के लिए उठने दें, जब तक सतह बुलबुलों से ढक न जाए और बैटर स्पष्ट रूप से उठ न जाए (~1.5× आयतन)। खमीर असली पॉफर्चेस की प्रतिष्ठित हवादार, थोड़ी खट्टी स्वाद विकसित करता है।. हिलाएं और विश्राम दें: उठे बैटर को धीरे से हिलाकर बड़े बुलबुले निकालें। एक स्क्वीज़ बोतल, जग या पाइपिंग बैग में ट्रांसफ़र करें — छोटे गड्ढों में सटीक रूप से बांटने का सबसे आसान तरीका। पैन गरम होने के दौरान 10 मिनट विश्राम दें।. पॉफर्चेसपैन को गरम करें: 24 या 30 गड्ढों वाले कास्ट-आयरन पॉफर्चेसपैन को मध्यम-धीमी आँच पर 3 मिनट के लिए रखें जब तक समान रूप से गरम न हो जाए (पानी की एक बूंद से जाँचें — यह 2 सेकंड में चटकनी चाहिए और वाष्पीकृत होनी चाहिए)। हर गड्ढे को उदारता से चिकना करने के लिए पिघलाई मक्खन में डूबा हुआ मुड़ा हुआ रसोई का तौलिया उपयोग करें — हर गड्ढा कवर होना चाहिए या पॉफर्चेस चिपक जाएगा।. गड्ढे भरें: तेज़ी से काम करते हुए, हर गड्ढे में 3/4 (प्रति गड्ढा लगभग 1 बड़ा चम्मच) तक बैटर निचोड़ें या डालें। 60–90 सेकंड प्रतीक्षा करें जब तक किनारे जम न जाएं और प्रत्येक के चारों ओर एक सुनहरा वलय न बन जाए, सतह पर बुलबुले बनें।. हर एक को पलटें: लकड़ी की कटार का उपयोग करके, हर अर्ध-जमे पॉफर्चे को उसके गड्ढे के किनारे से ऊपर खींचें और उल्टा पलटें — ऊपरी अनपका बैटर गड्ढे में बहेगा, एक गोल गेंद बनाएगा। दूसरी तरफ गहरा सुनहरा भूरा होने तक 60–90 सेकंड और पकाएं। हर पॉफर्चे एक फूली हुई गोल गेंद होनी चाहिए, दोनों तरफ सुनहरी, लगभग 3 सेमी चौड़ी।. तुरंत परोसें: हर गर्म प्लेट पर 8–10 पॉफर्चेस स्लाइड करें। ऊपर ठंडी मक्खन का एक छोटा टुकड़ा रखें (यह पिघलकर सोख लेगा) और बारीक छलनी के माध्यम से शक्कर पाउडर की उदार धूल छिड़कें। तुरंत परोसें — पॉफर्चेस बनने के 5 मिनट के भीतर रबरी हो जाते हैं। वैकल्पिक: स्ट्रोपवॉफल सिरप टपकाएं या ताज़ी बेरी छिड़कें।.","en":"ACTIVATE THE YEAST: warm 350 ml milk in a saucepan to about 38 °C (lukewarm — comfortable on your wrist); pour into a large bowl, sprinkle 7 g instant dry yeast and 1 tsp sugar over the surface, and let stand 10 minutes until a creamy foam appears on top; if no foam, the yeast is dead — start over with fresh yeast. MAKE THE BATTER: whisk 2 eggs into the foamed yeast-milk until smooth; in a separate bowl, sift together 250 g buckwheat flour (or the buckwheat+all-purpose mix), the remaining 2 tsp sugar and 0.5 tsp salt; add the dry to the wet in two additions, whisking each time until smooth — no lumps; whisk in 30 g melted cooled butter and 1 tbsp rum (if using); the batter should be the consistency of thin cream that ribbons off the whisk. FIRST PROOF: cover the bowl with a clean cloth and let rise in a warm spot for 60 minutes, until the surface is covered with bubbles and the batter has risen noticeably (about 1.5× volume); the yeast develops the signature airy, slightly sour flavour of true poffertjes. STIR DOWN AND REST: gently stir the risen batter to deflate large bubbles; transfer to a squeeze bottle, jug or piping bag — the easiest way to portion accurately into the small dimples; let rest 10 minutes while the pan heats. HEAT THE POFFERTJESPAN: place a 24- or 30-dimple cast-iron poffertjespan over medium-low heat for 3 minutes until evenly hot (test with a drop of water — it should sizzle and evaporate in 2 seconds); use a folded paper towel dipped in melted butter to grease each dimple generously — every dimple must be coated or the poffertjes will stick. FILL THE DIMPLES: working fast, squeeze or pour batter into each dimple until 3/4 full (about 1 tbsp per dimple); wait 60–90 seconds until the edges are set and a golden ring forms around each one, with bubbles forming on the surface. FLIP EACH ONE: using a wooden skewer, pull each half-set poffertje up the side of its dimple and flip it upside down — the uncooked top batter will flow into the dimple, filling out a round ball; cook another 60–90 seconds until the second side is deep golden brown; each poffertje should be a fluffy round ball, golden on both sides, about 3 cm wide. SERVE IMMEDIATELY: slide 8–10 poffertjes onto each warm plate; top with a small knob of cold butter (it will melt and soak in) and a generous dust of icing sugar through a fine sieve; serve immediately — poffertjes turn rubbery within 5 minutes of being made; optional: drizzle stroopwafel syrup or scatter fresh berries."}},{"id":160,"origin":{"hi":"जापान","en":"Japan","ro":"Japonia"},"name":{"hi":"जापानी करी चावल","en":"Japanese Curry Rice","ro":"Curry japonez"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"japanese","ingredients":{"hi":["छोटे दाने के चावल 2 कप (कच्चे)","हड्डी रहित चिकन थाई 400ग्रा (या बीफ), 3 सेमी टुकड़े","बड़े प्याज़ 2, मध्यम कटे","मध्यम आलू 2, 3 सेमी टुकड़े","मध्यम गाजर 2, 1.5 सेमी स्लाइस","वनस्पति तेल 1 बड़ा चम्मच","पानी 800 मिली","जापानी करी रूक्स ब्लॉक 1 पैक (जैसे S&B गोल्डन करी)","वॉर्सेस्टरशायर सॉस 1 छोटा चम्मच","केचप 1 छोटा चम्मच (वैकल्पिक)","नमक और काली मिर्च स्वादानुसार"],"en":["2 cups short-grain rice (uncooked)","400g boneless skinless chicken thighs (or beef chuck), cut into 3 cm pieces","2 large onions, cut into medium dice","2 medium potatoes, cut into 3 cm cubes","2 medium carrots, cut into 1.5 cm rounds","1 tbsp vegetable oil","800ml water","1 pack Japanese curry roux blocks (e.g. S&B Golden Curry, medium, approx. 100g)","1 tsp Worcestershire sauce","1 tsp ketchup (optional, for depth)","salt and black pepper to taste"],"ro":["2 căni orez cu bob scurt (nepreparare)","400g pulpe de pui dezosate fără piele (sau vită pentru friptură), tăiate cuburi de 3 cm","2 cepe mari, tăiate cuburi medii","2 cartofi medii, tăiați cuburi de 3 cm","2 morcovi medii, tăiați rondele de 1,5 cm","1 lingură ulei vegetal","800ml apă","1 pachet blocuri de roux curry japonez (ex. S&B Golden Curry, mediu picant, aprox. 100g)","1 linguriță sos Worcestershire","1 linguriță ketchup (opțional, pentru rotunjimea gustului)","sare și piper negru după gust"]},"howIsMade":{"hi":"चावल: 360 ग्राम (2 कप) छोटे दाने का चावल ठंडे पानी से 3–4 बार धोएं जब तक पानी साफ़ न हो जाए। 540 मिली (2½ कप) ठंडे पानी के साथ बर्तन में डालें। बिना ढक्कन उबाल लाएं, ढककर सबसे कम आँच पर 13 मिनट पकाएं। आँच से हटाकर ढके हुए 10 मिनट विश्राम दें। ढक्कन न उठाएं।. प्याज़ को कैरमलाइज़ करें: एक बड़े बर्तन में 1 बड़ा चम्मच तेल मध्यम आँच पर गरम करें। 2 मध्यम कटे प्याज़ डालकर अक्सर हिलाते हुए 15–20 मिनट तक नर्म और सुनहरा होने तक भूनें — यह कदम न छोड़ें; कैरमलाइज़्ड प्याज़ स्वाद की रीढ़ है।. मांस को ब्राउन करें: 3 सेमी टुकड़ों में कटे 400 ग्राम चिकन थाई या बीफ चक डालें, नमक और काली मिर्च से सीज़न करें, सभी तरफ 3–4 मिनट ब्राउन करें। मांस पर गहरी सुनहरी परत होनी चाहिए — अतिरिक्त स्वाद।. सब्ज़ियाँ: 1.5 सेमी रोंडल में कटी 2 गाजर और 3 सेमी क्यूब में कटे 2 आलू डालें। तेल में सब्ज़ियों को कोट करने के लिए 1 मिनट हिलाएं।. बेस उबालें: 800 मिली पानी डालें, उबाल लाएं, धीमी आँच पर बिना ढक्कन के 15 मिनट या जब तक आलू बस नर्म न हो जाए (कटार से जाँचें) तक पकाएं।. रूक्स डालें: बर्तन को आँच से हटाएं। 100 ग्राम जापानी करी रूक्स ब्लॉक्स को छोटे टुकड़ों में तोड़कर पूरी तरह घुलने तक मिलाएं — आँच से हटाकर डालने से गांठें नहीं बनतीं।. सॉस गाढ़ा करें: बर्तन को धीमी आँच पर वापस रखें और 10 मिनट तक अक्सर हिलाते हुए पकाएं जब तक सॉस गाढ़ा और चमकदार न हो जाए — चम्मच के पिछले हिस्से पर चिपकनी चाहिए। गहराई के लिए 1 छोटा चम्मच वुस्टरशायर सॉस और 1 छोटा चम्मच केचप मिलाएं, चखें और नमक समायोजित करें।. परोसें: गहरी प्लेट में गर्म चावल के ऊपर करी की उदार मात्रा डालें। पारंपरिक संगत: कात्सु श्निट्ज़ल, कटी पत्तागोभी, अचारी लाल मूली (फुकुजिनज़ुके)। एक ही प्लेट में बिना मिलाए चावल और करी दोनों होते हैं — टेबल पर चम्मच से एक साथ मिलाते हैं।.","en":"THE RICE: rinse 360 g (2 cups) short-grain rice in cold water 3–4 times until the water runs clear; place in a pot with 540 ml (2½ cups) cold water; bring to a boil uncovered, cover, reduce to lowest heat and cook 13 minutes; remove from heat and rest covered 10 minutes; do not lift the lid. CARAMELIZE THE ONIONS: in a large pot, heat 1 tbsp oil over medium heat; add 2 medium-diced onions and cook, stirring often, for 15–20 minutes until soft and golden — DO NOT skip this step; the caramelized onions are the backbone of flavour. BROWN THE MEAT: add 400 g boneless chicken thighs or beef chuck cut in 3 cm pieces, season with salt and pepper, sear on all sides 3–4 minutes; the meat must have a deep golden crust — extra flavour. VEGETABLES: add 2 carrots cut in 1.5 cm rounds and 2 potatoes cut in 3 cm cubes; stir 1 minute to coat the vegetables in the oil. SIMMER THE BASE: pour in 800 ml water, bring to a boil, reduce to a gentle simmer uncovered for 15 minutes, or until the potato is just tender (check with a skewer). ADD THE ROUX: remove the pot from the heat; break 100 g Japanese curry roux blocks into small pieces and stir into the pot until fully dissolved — adding off heat prevents lumps. THICKEN THE SAUCE: return the pot to low heat and simmer, stirring frequently, for 10 minutes until the sauce is thick and glossy — it should coat the back of a spoon; stir in 1 tsp Worcestershire sauce and 1 tsp ketchup for depth, taste and adjust salt. SERVE: spoon a generous portion of curry over hot rice in deep plates; traditional accompaniments: katsu schnitzel, shredded cabbage, pickled red radishes (fukujinzuke); a single plate holds both rice and curry without mixing them — you spoon them together at the table."}},{"id":161,"servings":4,"tipType":"def","pairingsType":"mediterranean","origin":{"hi":"यूनान","en":"Greece","ro":"Grecia"},"name":{"hi":"फासोलाडा","en":"Fasolada","ro":"Fasolada"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"ingredients":{"hi":["सूखी सफ़ेद बीन्स 400 ग्राम (कैनेलिनी, नेवी या ग्रीक बड़ी गिगांटेस), ठंडे पानी में रात भर भिगोई हुई","मध्यम गाजर 2 (~200 ग्राम), छिली और 1 सेमी क्यूब में कटी","अजवाइन के डंठल 2 (~150 ग्राम), 1 सेमी क्यूब में कटे + अजवाइन की पत्तियाँ 30 ग्राम कटी (वैकल्पिक, पारंपरिक)","बड़ा प्याज़ 1 (~200 ग्राम), बारीक कटा","लहसुन की कलियाँ 4, बारीक कटी","पके टमाटर 400 ग्राम (4 मध्यम) — छीले और कद्दूकस किए या 1 कैन × 400 ग्राम क्रश्ड टमाटर","टमाटर पेस्ट 1 बड़ा चम्मच","सोफ्रिटो के लिए 100 मिली एक्स्ट्रा वर्जिन जैतून का तेल + अंत के लिए 60 मिली अतिरिक्त","तेज पत्ते 2","सूखा ओरेगानो 1 छोटा चम्मच","नमक 1.5 छोटे चम्मच + स्वादानुसार और","ताज़ी पिसी काली मिर्च 0.5 छोटा चम्मच","रेड वाइन सिरका 1 बड़ा चम्मच (वैकल्पिक, अंत में चमकाता है)","पानी 1.5 लीटर (या सब्जी स्टॉक)","परोसने के लिए: कुरकुरी देहाती ब्रेड, कलामाता जैतून, टुकड़ों में किया फेटा पनीर, ताज़ा अजमोद"],"en":["400 g dried white beans (cannellini, navy, or large Greek gigantes), soaked overnight in cold water","2 medium carrots (~200 g), peeled and diced 1 cm","2 celery stalks (~150 g), diced 1 cm + 30 g celery leaves chopped (optional, traditional)","1 large onion (~200 g), finely diced","4 garlic cloves, finely minced","400 g ripe tomatoes (4 medium) — peeled and grated OR 1 × 400 g can crushed tomatoes","1 tbsp tomato paste","100 ml extra-virgin olive oil for the soffritto + 60 ml more for finishing","2 bay leaves","1 tsp dried oregano","1.5 tsp salt + more to taste","0.5 tsp freshly ground black pepper","1 tbsp red wine vinegar (optional, brightens at the end)","1.5 L water (or vegetable stock)","To serve: crusty country bread, Kalamata olives, crumbled feta cheese, fresh parsley"],"ro":["400 g fasole albă uscată (cannellini, navy sau gigantes grecești), înmuiate peste noapte în apă rece","2 morcovi medii (~200 g), curățați și tăiați cuburi de 1 cm","2 tulpini de țelină (~150 g), tăiate cuburi de 1 cm + 30 g frunze de țelină tocate (opțional, tradițional)","1 ceapă mare (~200 g), tăiată fin","4 căței de usturoi, tocați fin","400 g roșii coapte (4 medii) — decojite și rase SAU 1 conservă × 400 g de roșii zdrobite","1 lingură pastă de roșii","100 ml ulei de măsline extravirgin pentru sotat + 60 ml suplimentar pentru finisare","2 frunze de dafin","1 linguriță oregano uscat","1,5 lingurițe sare + sare după gust","0,5 linguriță piper negru proaspăt măcinat","1 lingură oțet de vin roșu (opțional, dă luminozitate la final)","1,5 L apă (sau supă de legume)","Pentru servire: pâine de țară crocantă, măsline Kalamata, brânză feta sfărâmată, pătrunjel proaspăt"]},"howIsMade":{"hi":"बीन्स भिगोएं: 400 ग्राम सूखी सफ़ेद बीन्स को एक बड़े कटोरे में रखें, 5 सेमी ऊपर ठंडे पानी से ढक दें और 8 घंटे या रात भर भिगोएं। छानें और धोएं — भिगोने से पकाने का समय कम होता है और बीन्स साबुत समान रूप से पकती हैं।. बीन्स को आधा उबालें: छानी हुई बीन्स को बड़े बर्तन में रखें, 3 सेमी ऊपर ठंडे पानी से ढकें और उबाल लाएं। तेज़ 10 मिनट उबालें, फिर छानें — यह कदम पाचन में कठिनाई पैदा करने वाले गैस के कारक यौगिकों को हटाता है और साफ़ स्वाद वाला शोरबा देता है।. सोफ्रिटो: 5 लीटर के भारी बर्तन में 100 मिली जैतून का तेल मध्यम आँच पर गरम करें। 200 ग्राम कटा प्याज़ + 200 ग्राम कटी गाजर + 150 ग्राम कटी अजवाइन डालें और बार-बार चलाते हुए 12–15 मिनट तक बहुत नर्म और सुनहरा होने तक भूनें — यह धीमी सब्जी आधार फासोलाडा की गहराई का आधार है। 4 कटी लहसुन की कलियाँ डालें और 1 मिनट और सुगंधित होने तक पकाएं।. टमाटर खिलाएं: 1 बड़ा चम्मच टमाटर पेस्ट डालें और 2 मिनट चलाते हुए गहरा होने तक पकाएं। 400 ग्राम कद्दूकस किया टमाटर (या कैन का क्रश्ड) डालें और 5 मिनट पकाएं जब तक कच्ची खट्टास खत्म न हो जाए और मिश्रण गहरा लाल हो जाए।. बीन्स और पानी डालें: आधी उबली बीन्स बर्तन में वापस डालें। 1.5 लीटर पानी (या सब्जी स्टॉक), 2 तेज पत्ते, 1 छोटा चम्मच ओरेगानो, 1.5 छोटे चम्मच नमक और 0.5 छोटा चम्मच काली मिर्च डालें। उबाल लाएं और हल्की आँच पर करें।. धीरे-धीरे पकाएं: 60–90 मिनट बिना ढक्कन के बीच-बीच में हिलाते हुए पकाएं जब तक बीन्स पूरी तरह से नर्म और केंद्र में मलाईदार हो जाएं लेकिन अपना आकार बनाए रखें — 1 घंटे के बाद हर 15 मिनट में एक बीन चखें। शोरबा लगभग आधा हो जाना चाहिए और सूप की संगति में गाढ़ा हो जाना चाहिए। यदि बहुत तेज़ी से सूखे तो पानी डालें।. अंत: तेज पत्ते निकालें। 30 ग्राम कटी अजवाइन की पत्तियाँ (यदि उपयोग कर रहे हों) और 1 बड़ा चम्मच रेड वाइन सिरका चमकाने के लिए मिलाएं। चखें और नमक समायोजित करें। आँच से हटाकर सतह पर 60 मिली ताज़ा एक्स्ट्रा वर्जिन जैतून का तेल डालें — यह वह फिनिशिंग तेल है जो सूप को चमकदार और सुगंधित बनाता है। स्वाद को व्यवस्थित होने के लिए 10 मिनट विश्राम दें।. परोसें: गहरे कटोरों में डालें, हर परोसी पर एक और छोटा चम्मच जैतून के तेल की धार दें, और ऊपर ताज़ी काली मिर्च पीस लें। टेबल पर कुरकुरी देहाती रोटी, कलामाता जैतून का छोटा कटोरा, टुकड़ों में किया फेटा और कटा ताज़ा अजमोद के साथ परोसें। अगले दिन और भी अच्छा।.","en":"SOAK THE BEANS: place 400 g dried white beans in a large bowl, cover with cold water by 5 cm, and soak 8 hours or overnight; drain and rinse — the soak shortens the cooking time and helps even, intact beans. PARBOIL THE BEANS: place the drained beans in a large pot, cover with cold water by 3 cm, and bring to a boil; boil hard 10 minutes, then drain — this removes the indigestible compounds that cause gas and gives a cleaner-tasting broth. SOFFRITTO: in a heavy 5 L pot, heat 100 ml olive oil over medium heat; add 200 g diced onion + 200 g diced carrot + 150 g diced celery and cook, stirring often, 12–15 minutes until very soft and starting to gold — this slow vegetable base is the foundation of fasolada's depth; add 4 minced garlic cloves and cook 1 more minute until fragrant. BLOOM THE TOMATO: add 1 tbsp tomato paste and cook stirring 2 minutes until darkened; add 400 g grated tomato (or canned crushed) and simmer 5 minutes until the raw acidity cooks off and the mixture turns deep red. ADD BEANS AND WATER: return the parboiled beans to the pot; add 1.5 L water (or vegetable stock), 2 bay leaves, 1 tsp oregano, 1.5 tsp salt and 0.5 tsp pepper; bring to a boil, reduce to a gentle simmer. SLOW SIMMER: cook uncovered 60–90 minutes, stirring occasionally, until the beans are completely tender and creamy at the centre but still hold their shape — taste a bean every 15 minutes after the 1 hour mark; the broth should reduce by about half and thicken to a soupy consistency; add more water if it dries out too fast. FINISH: discard the bay leaves; stir in 30 g chopped celery leaves (if using) and 1 tbsp red wine vinegar for brightness; taste and adjust salt; off the heat, drizzle 60 ml fresh extra-virgin olive oil over the surface — this is the finishing oil that makes the soup glossy and aromatic; let rest 10 minutes for flavours to settle. SERVE: ladle into deep bowls, drizzle each portion with another teaspoon of olive oil, and grind fresh black pepper over the top; serve with crusty country bread, a small bowl of Kalamata olives, crumbled feta, and chopped fresh parsley on the table; even better the next day."}},{"id":162,"servings":4,"tipType":"meat","pairingsType":"mexican","origin":{"hi":"मेक्सिको","en":"Mexico","ro":"Mexic"},"name":{"hi":"त्लायुदास","en":"Tlayudas","ro":"Tlayudas"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["त्लायुदा टॉर्टिला 4 (~30 सेमी, अर्ध-सूखी) या विकल्प के रूप में 4 बड़ी गेहूं की टॉर्टिला","सूखी काली बीन्स 250 ग्राम, रात भर भिगोई हुई (या 1 × 400 ग्राम कैन)","बीन्स तलने और पकाने के लिए लार्ड 100 ग्राम या वनस्पति तेल 100 मिली","बड़ा प्याज़ 1 (~200 ग्राम): आधा बीन्स के लिए चार भागों में, दूसरा आधा परोसने के लिए बारीक कटा","लहसुन की कलियाँ 4 (2 बीन्स के लिए, 2 मांस के लिए)","बीन्स के लिए: पिसा जीरा 1 छोटा चम्मच + सूखा ओरेगानो 1 छोटा चम्मच + नमक 1 छोटा चम्मच","फ्लैंक या स्कर्ट स्टीक 500 ग्राम, बहुत पतला रेशे के विपरीत कटा (तासाहो शैली)","ताज़ा मैक्सिकन चोरिज़ो 200 ग्राम (या स्पेनिश), केसिंग से निकाला","क्वेसिल्लो (ओआहाका चीज़) 300 ग्राम या कम नमी वाली मोज़ेरेला, कद्दूकस की","कटा आइसबर्ग सलाद 200 ग्राम","पके एवोकाडो 2 (~300 ग्राम), कटे","पके टमाटर 4 (~400 ग्राम), कटे","साल्सा रोहा या वर्दे 200 ग्राम (घर का बना या स्टोर से)","नींबू 1 टुकड़ों में कटा + परोसने के लिए ताज़ा हरा धनिया"],"en":["4 tlayuda tortillas (~30 cm, semi-dried) or 4 large flour tortillas as substitute","250 g dried black beans soaked overnight (or 1 × 400 g can)","100 g lard or 100 ml vegetable oil for frying beans + cooking","1 large onion (~200 g): half quartered for the beans, the other half finely diced for serving","4 garlic cloves (2 for beans, 2 for meat)","1 tsp ground cumin + 1 tsp dried oregano + 1 tsp salt for the beans","500 g flank or skirt steak, sliced very thinly across the grain (tasajo-style)","200 g fresh Mexican chorizo (or Spanish), removed from casing","300 g quesillo (Oaxaca string cheese) or low-moisture mozzarella, shredded","200 g shredded iceberg lettuce","2 ripe avocados (~300 g), sliced","4 ripe tomatoes (~400 g), sliced","200 g salsa roja or salsa verde (homemade or store-bought)","1 lime cut into wedges + fresh cilantro for serving"],"ro":["4 tortillas tlayuda (~30 cm, semi-uscate) sau 4 tortillas mari de făină","250 g fasole neagră uscată înmuiată peste noapte (sau 1 conservă × 400 g)","100 g untură sau 100 ml ulei vegetal pentru prăjit fasolea + sotat","1 ceapă mare (~200 g): jumătate tăiată sferturi pentru fasole, cealaltă jumătate tocată fin pentru servire","4 căței de usturoi (2 pentru fasole, 2 pentru carne)","1 linguriță chimion măcinat + 1 linguriță oregano uscat + 1 linguriță sare pentru fasole","500 g flank steak sau skirt steak, feliat foarte subțire în diagonală (stil tasajo)","200 g chorizo proaspăt mexican (sau spaniol), scos din maț","300 g quesillo (brânză Oaxaca) sau mozzarella low-moisture, rasă","200 g salată iceberg, tocată","2 avocado coapte (~300 g), feliate","4 roșii coapte (~400 g), feliate","200 g salsa roja sau verde (de casă sau de la magazin)","1 lime tăiată sferturi + coriandru proaspăt pentru servire"]},"howIsMade":{"hi":"बीन्स: 250 ग्राम भिगोई काली बीन्स छानें। 1.5 लीटर पानी, आधा प्याज़ चार भागों में, 2 साबुत लहसुन की कलियाँ, 1 छोटा चम्मच जीरा, 1 छोटा चम्मच ओरेगानो और 1 छोटा चम्मच नमक के साथ 60–90 मिनट तक उबालें जब तक बहुत नर्म न हो जाएं। 200 मिली पकाने का तरल बचाकर छानें।. बीन्स फिर से तलें (frijoles refritos): एक पैन में 50 ग्राम लार्ड मध्यम आँच पर गरम करें। पकी बीन्स डालें और आलू मैशर या स्पैचुला से मसलें, धीरे-धीरे बचाया तरल मिलाते हुए जब तक गाढ़ा क्रीमी पेस्ट न बन जाए। 5–7 मिनट चलाते हुए पकाएं जब तक हल्का काला न पड़े और धुएँदार सुगंध न आ जाए।. स्टीक भूनें: एक बड़े पैन में 1 बड़ा चम्मच तेल मध्यम-तेज़ आँच पर गरम करें। 500 ग्राम बीफ को नमक और काली मिर्च से सीज़न करें, एक परत में हर तरफ 2 मिनट सेंकें (पैन को भीड़भाड़ न करें, बैच में काम करें)। फ़ॉयल से ढकी प्लेट में रखें।. चोरिज़ो भूनें: उसी पैन में केसिंग से निकाला 200 ग्राम चोरिज़ो डालें, लकड़ी के चम्मच से तोड़ें और मध्यम आँच पर 5–7 मिनट तक भूनें जब तक लाल तेल निकले और मांस पूरी तरह पक जाए। तेल के साथ पैन में छोड़ें।. टॉपिंग तैयार करें: 2 एवोकाडो, 4 टमाटर और बचा आधा प्याज़ (बारीक कटा) काटें। 200 ग्राम सलाद पत्ते को काटें। तेज़ी से इकट्ठा करने के लिए हर एक को अलग कटोरे में रखें।. त्लायुदा को इकट्ठा करें: एक प्लांचा या बड़ी ग्रिडल पैन को मध्यम-तेज़ आँच पर पहले से गरम करें। सूखे सतह पर एक त्लायुदा टॉर्टिला रखें और रिफ्राइड बीन्स की उदार परत किनारों से 1 सेमी तक फैलाएं। बीन्स पर 75 ग्राम कद्दूकस की चीज़ छिड़कें। एक हिस्सा भुना हुआ स्टीक और चोरिज़ो डालें।. इसे कुरकुरा करें: प्लांचा पर बिना पलटे 5–7 मिनट पकाएं — टॉर्टिला का तला सुनहरा भूरा, कुरकुरा होना चाहिए और हल्के झुलसने के निशान दिखने चाहिए। चीज़ पूरी तरह से पिघलनी चाहिए। पिघलने को तेज़ करने के लिए अंतिम 2 मिनट ढक्कन से ढकें।. परोसें: चौड़े स्पैचुला से त्लायुदा को प्लेट पर स्लाइड करें। ऊपर सलाद पत्ता, टमाटर के टुकड़े, एवोकाडो, कटा प्याज़, साल्सा डालें। नींबू निचोड़ें और हरा धनिया छिड़कें। आधा मोड़ें या हाथ से खुली खाएं। बचे 3 त्लायुदा के लिए दोहराएं। तुरंत परोसें — रुकने पर रबर जैसा हो जाता है।.","en":"THE BEANS: drain 250 g soaked black beans; boil in 1.5 L water with half an onion in quarters, 2 whole garlic cloves, 1 tsp cumin, 1 tsp oregano and 1 tsp salt for 60–90 minutes until very tender; drain, reserving 200 ml of the cooking liquid. REFRY THE BEANS (frijoles refritos): in a skillet, heat 50 g lard over medium heat; add the cooked beans and mash with a potato masher or spatula, adding the reserved liquid gradually until you have a thick creamy paste; cook 5–7 minutes, stirring, until slightly blackened and smoky. SEAR THE STEAK: heat 1 tbsp oil in a large skillet over medium-high; season 500 g beef with salt and pepper, sear 2 minutes per side in a single layer (do not crowd the pan, work in batches); rest the meat on a foil-tented plate. FRY THE CHORIZO: in the same skillet, add 200 g chorizo from its casing, break it up with a wooden spoon, and fry 5–7 minutes over medium heat until the red oil is released and the meat is fully cooked; leave it in the pan with its oil. PREP THE TOPPINGS: slice 2 avocados, 4 tomatoes and the remaining onion half (finely diced); shred 200 g lettuce; place each in a separate bowl for fast assembly. ASSEMBLE THE TLAYUDA: preheat a plancha or large griddle over medium-high heat; place a tlayuda tortilla on the dry surface and spread it with a generous layer of refried beans to within 1 cm of the edges; scatter 75 g shredded cheese over the beans; add a portion of seared steak and chorizo. CRISP IT UP: cook on the plancha over medium heat 5–7 minutes without flipping — the bottom of the tortilla must turn golden brown, crunchy, and show light scorch marks; the cheese must melt completely; cover with a lid for the last 2 minutes to speed melting. SERVE: slide the tlayuda onto a plate with a wide spatula; top with lettuce, tomato slices, avocado, diced onion, salsa; squeeze lime and scatter cilantro; fold in half or eat open with your hands; repeat for the remaining 3 tlayudas; serve immediately — it gets chewy if it sits."}},{"id":163,"servings":4,"tipType":"meat","pairingsType":"latin","origin":{"hi":"कोलम्बिया","en":"Colombia","ro":"Columbia"},"name":{"hi":"बान्देहा पायसा","en":"Bandeja Paisa","ro":"Bandeja Paisa"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"ingredients":{"hi":["फ्रिहोलेस अंतीयोकेन्योस के लिए: सूखी लाल किडनी या कारगामांटो बीन्स 400 ग्राम, रात भर भिगोई हुई","मध्यम गाजर 1 (~100 ग्राम) कद्दूकस + मध्यम टमाटर 2 (~250 ग्राम) कद्दूकस + प्याज़ 1 (~150 ग्राम) बारीक कटा + लहसुन की 4 कलियाँ होगाओ के लिए","बीन्स के लिए: तेल 2 बड़े चम्मच + टमाटर पेस्ट 1 बड़ा चम्मच + जीरा 1 छोटा चम्मच + नमक 1 छोटा चम्मच","बीन्स के लिए पका हुआ प्लांटेन 1 (~150 ग्राम) क्यूब में कटा","अरोस ब्लांको के लिए: मध्यम दाने का चावल 360 ग्राम (2 कप) + पानी 540 मिली + नमक 0.5 छोटा चम्मच","कार्ने मोलिडा के लिए: कीमा बीफ 500 ग्राम + बारीक कटा प्याज़ 1 + लहसुन की 4 कलियाँ + कद्दूकस के 2 टमाटर + तेल 2 बड़े चम्मच + जीरा 1 छोटा चम्मच + नमक 1 छोटा चम्मच + काली मिर्च 0.5 छोटा चम्मच + बीफ स्टॉक 50 मिली","चिचारोन के लिए: छिलके सहित पोर्क बेली 800 ग्राम 8 स्ट्रिप्स ~10 सेमी में कटी + नमक 1 छोटा चम्मच","4 कच्चे कोलंबियाई चोरिज़ो (~80 ग्राम प्रत्येक)","4 मोर्सिया (खून सॉसेज, ~80 ग्राम प्रत्येक)","4 छोटे अरेपास के लिए: पहले से पकाया सफ़ेद मक्का आटा (Harina P.A.N.) 200 ग्राम + गुनगुना पानी 240 मिली + नमक 0.5 छोटा चम्मच + ग्रिडल के लिए तेल 1 बड़ा चम्मच","मादुरो के लिए: बहुत पका प्लांटेन 2 (बहुत काले छिलके वाला) + तेल 2 बड़े चम्मच","सनी साइड अप के लिए 4 बड़े अंडे + तेल 1 बड़ा चम्मच + नमक और काली मिर्च","पके एवोकाडो 2, आधे काटे और बीज निकाला","कुरकुरी सफ़ेद ब्रेड के 4 स्लाइस + नींबू के 4 टुकड़े + परोसने के लिए नमक"],"en":["For frijoles antioqueños: 400 g dried red kidney or cargamanto beans, soaked overnight","1 medium carrot (~100 g) grated + 2 medium tomatoes (~250 g) grated + 1 onion (~150 g) finely diced + 4 garlic cloves for the hogao","2 tbsp oil + 1 tbsp tomato paste + 1 tsp ground cumin + 1 tsp salt for the beans","1 ripe plantain (~150 g) diced for the beans","For arroz blanco: 360 g (2 cups) medium-grain white rice + 540 ml water + 0.5 tsp salt","For carne molida: 500 g ground beef + 1 onion finely diced + 4 garlic cloves + 2 grated tomatoes + 2 tbsp oil + 1 tsp cumin + 1 tsp salt + 0.5 tsp pepper + 50 ml beef stock","For chicharrón: 800 g pork belly skin-on cut into 8 strips of ~10 cm + 1 tsp salt","4 raw Colombian chorizos (~80 g each)","4 morcillas (blood sausages, ~80 g each)","For 4 small arepas: 200 g precooked white corn flour (Harina P.A.N.) + 240 ml warm water + 0.5 tsp salt + 1 tbsp oil for the griddle","For maduro: 2 very ripe plantains (deep black skin) + 2 tbsp oil","4 large eggs for sunny-side up + 1 tbsp oil + salt and pepper","2 ripe avocados, halved and pitted","4 slices of crusty white bread + 4 lime wedges + salt to serve"],"ro":["Pentru frijoles antioqueños: 400 g fasole roșie uscată (cargamanto sau kidney) înmuiată peste noapte","1 morcov mediu (~100 g) ras + 2 roșii medii (~250 g) rase + 1 ceapă (~150 g) tocată fin + 4 căței usturoi pentru hogao","2 linguri ulei + 1 lingură pastă de roșii + 1 linguriță chimion + 1 linguriță sare pentru fasole","1 banană plantain coaptă (~150 g) tocată în cuburi pentru fasole","Pentru arroz blanco: 360 g (2 căni) orez cu bob mediu + 540 ml apă + 0,5 linguriță sare","Pentru carne molida: 500 g vită tocată + 1 ceapă tocată + 4 căței usturoi + 2 roșii rase + 2 linguri ulei + 1 linguriță chimion + 1 linguriță sare + 0,5 linguriță piper + 50 ml supă de vită","Pentru chicharrón: 800 g costiță de porc cu coajă tăiată în 8 fâșii lungi de 10 cm + 1 linguriță sare","4 chorizos columbieni cruzi (~80 g fiecare)","4 morcillas (cârnați de sânge, ~80 g fiecare)","Pentru arepas (4 mici): 200 g făină de porumb precoaptă (Harina P.A.N.) + 240 ml apă caldă + 0,5 linguriță sare + 1 lingură ulei pentru tigaie","Pentru maduro: 2 banane plantain foarte coapte (coaja neagră) + 2 linguri ulei","4 ouă mari pentru ochiuri + 1 lingură ulei + sare și piper","2 avocado coapte, jumătățite și fără sâmbure","4 felii pâine albă crocantă + 4 felii de lime + sare pentru servire"]},"howIsMade":{"hi":"भिगोएं और योजना: 400 ग्राम लाल बीन्स को रात भर भिगोएं। बान्देहा पायसा 6 समानांतर घटकों की मांग करता है — शुरू करने से पहले सभी सामग्री और उपकरण इकट्ठा करें, साथ ही 3 बर्तन और 2 पैन।. बीन्स: बीन्स को छानें, 1.5 लीटर पानी में कद्दूकस गाजर + 1 कद्दूकस टमाटर + प्याज़ + 2 लहसुन की कलियाँ + 1 छोटा चम्मच जीरा + 1 छोटा चम्मच नमक के साथ 60–90 मिनट तक नरम होने तक उबालें। अंतिम 15 मिनट में होगाओ बनाएं: 2 बड़े चम्मच तेल में बचा प्याज़ + 2 लहसुन + 1 कद्दूकस टमाटर + 1 बड़ा चम्मच टमाटर पेस्ट 5 मिनट भूनें। बीन्स में क्यूब किया प्लांटेन के साथ डालें और 10 मिनट और पकाएं।. चावल: 360 ग्राम चावल को ठंडे पानी में 3 बार धोएं। 540 मिली पानी और 0.5 छोटा चम्मच नमक के साथ रखें। उबाल लाएं, ढककर सबसे कम आँच पर 12 मिनट, ढके हुए 10 मिनट विश्राम दें।. कार्ने मोलिडा: एक पैन में 2 बड़े चम्मच तेल मध्यम-तेज़ आँच पर गरम करें। प्याज़ और लहसुन को 5 मिनट तक नरम होने तक भूनें। 500 ग्राम कीमा बीफ डालें, चम्मच से तोड़ें और 8 मिनट भूनें। 2 कद्दूकस टमाटर, 1 छोटा चम्मच जीरा, 1 छोटा चम्मच नमक और 0.5 छोटा चम्मच काली मिर्च डालें, 5 मिनट पकाएं। 50 मिली स्टॉक से डेग्लेज़ करें।. चिचारोन: छिलके सहित पोर्क बेली के 8 स्ट्रिप्स को बर्तन में 200 मिली ठंडे पानी और 1 छोटा चम्मच नमक के साथ डालें। उबाल लाएं, ढककर 30 मिनट पकाएं। पूरी तरह से छानें। उसी बर्तन में पोर्क को अपनी ही चर्बी में मध्यम-तेज़ आँच पर 8–10 मिनट अक्सर पलटते हुए तलें जब तक छिलका सुनहरा और कुरकुरा न हो जाए। (विकल्प: 200 °C ओवन में रैक पर 40 मिनट।). अरेपा: एक कटोरे में 200 ग्राम मक्के का आटा, 240 मिली गुनगुना पानी और 0.5 छोटा चम्मच नमक मिलाएं जब तक नम आटा न बने। 5 मिनट विश्राम दें। 10 सेमी व्यास और 1 सेमी मोटाई की 4 पैटी बनाएं। एक गर्म पैन में 1 बड़ा चम्मच तेल के साथ मध्यम आँच पर हर तरफ 4–5 मिनट तब तक पकाएं जब तक सुनहरा गहरे धब्बों के साथ न हो जाए।. मादुरो + अंडे + सॉसेज: 2 काले प्लांटेन को 1 सेमी मोटे टुकड़ों में काटें। 2 बड़े चम्मच तेल में मध्यम आँच पर हर तरफ 2 मिनट कैरमलाइज़ होने तक तलें। दूसरे पैन में 4 कच्चे चोरिज़ो को हर तरफ 5 मिनट और 4 मोर्सिया को हर तरफ 3 मिनट तलें। फिर 1 छोटा चम्मच तेल में 4 अंडे 2 मिनट तब तक तलें जब तक सफ़ेद भाग सेट हो जाए लेकिन ज़र्दी बहती रहे।. इकट्ठा करें: 4 बड़ी प्लेटों पर इस क्रम में रखें: चावल का एक ढेर, बीन्स की उदार चम्मच, कार्ने मोलिडा का एक हिस्सा, 2 चिचारोन के टुकड़े, 1 चोरिज़ो, 1 मोर्सिया, मांस के ऊपर 1 तला अंडा, 2 मादुरो स्लाइस, 1/2 एवोकाडो, 1 अरेपा, 1 ब्रेड स्लाइस, 1 नींबू का टुकड़ा। तुरंत परोसें — बान्देहा पायसा को चाकू और कांटे से खाया जाता है, हर निवाला कई घटकों का संयोजन।.","en":"SOAK & PLAN: soak 400 g red beans overnight; bandeja paisa runs 6 parallel components — gather all ingredients and tools before starting, plus 3 pots and 2 skillets. THE BEANS: drain the beans, simmer in 1.5 L water with grated carrot + 1 grated tomato + onion + 2 garlic cloves + 1 tsp cumin + 1 tsp salt 60–90 minutes until tender; in the final 15 minutes make the hogao: sauté in 2 tbsp oil the remaining onion + 2 garlic + 1 grated tomato + 1 tbsp tomato paste 5 minutes; stir into the beans with the diced plantain and cook 10 more minutes. THE RICE: rinse 360 g rice in cold water 3 times; place with 540 ml water and 0.5 tsp salt; bring to a boil, cover, reduce to lowest heat 12 minutes, rest covered 10 minutes. CARNE MOLIDA: heat 2 tbsp oil in a skillet over medium-high; sauté onion and garlic 5 minutes until soft; add 500 g ground beef, break up with the spoon and brown 8 minutes; add 2 grated tomatoes, 1 tsp cumin, 1 tsp salt and 0.5 tsp pepper, cook 5 minutes; deglaze with 50 ml stock. CHICHARRÓN: place 8 strips of pork belly skin-on in a pot with 200 ml cold water and 1 tsp salt; bring to a boil, cover and simmer 30 minutes; drain completely; in the same pot, fry the pork in its own fat over medium-high heat 8–10 minutes turning often until the skin is golden and crackling; (Alternative: 200 °C oven 40 minutes on a rack.). AREPAS: mix 200 g corn flour with 240 ml warm water and 0.5 tsp salt in a bowl until a damp dough forms; rest 5 minutes; shape into 4 patties of 10 cm diameter and 1 cm thick; griddle in a hot pan with 1 tbsp oil over medium heat 4–5 minutes per side until golden with dark spots. MADURO + EGGS + SAUSAGES: slice 2 black plantains into 1 cm rounds; fry in 2 tbsp oil over medium heat 2 minutes per side until caramelized; in another skillet, fry 4 raw chorizos 5 minutes per side and 4 morcillas 3 minutes per side; then fry 4 eggs in 1 tsp oil 2 minutes until whites set but yolks runny. ASSEMBLY: on 4 large platters arrange in this order: a mound of rice, a generous ladle of beans, a portion of carne molida, 2 chicharrón pieces, 1 chorizo, 1 morcilla, 1 fried egg on top of the meat, 2 maduro slices, 1/2 avocado, 1 arepa, 1 bread slice, 1 lime wedge; serve immediately — bandeja paisa is eaten with knife and fork, each bite in combination with others."}},{"id":164,"servings":4,"tipType":"def","pairingsType":"def","origin":{"hi":"हंगरी","en":"Hungary","ro":"Ungaria"},"name":{"hi":"लांगोश","en":"Lángos","ro":"Lángos"},"category":{"hi":"नाश्ता","en":"Snack","ro":"Gustare"},"ingredients":{"hi":["सर्व-उपयोगी या T550 ब्रेड आटा 500 ग्राम","इंस्टेंट सूखी खमीर 7 ग्राम (या ताज़ी खमीर 21 ग्राम)","दानेदार चीनी 1 छोटा चम्मच (खमीर खिलाने के लिए)","आटे के लिए महीन नमक 1.5 छोटे चम्मच","38 °C पर गुनगुना पूर्ण वसा वाला दूध 300 मिली (या पानी, पारंपरिक)","उबला और मैश किया आलू 100 ग्राम (फूली बनावट का राज़)","आटे के लिए तटस्थ तेल 2 बड़े चम्मच","गहरे तलने के लिए सूरजमुखी या तटस्थ तेल 1 लीटर","लहसुन की लेप के लिए: 4 लहसुन की कलियाँ 1 छोटे चम्मच नमक + 1 बड़े चम्मच पानी के साथ पेस्ट में कुचली","हंगेरियन खट्टी क्रीम (tejföl) 200 ग्राम","तीखी कद्दूकस की चीज़ 200 ग्राम (चेडर/गौडा/एडम शैली)","ताज़े चाइव्स का छोटा गुच्छा, बारीक कटा (वैकल्पिक)","अंत के लिए नमक","उपकरण: तलने के लिए चौड़ा भारी बर्तन + छेद वाला चम्मच + तार रैक"],"en":["500 g all-purpose or T550 bread flour","7 g instant dry yeast (or 21 g fresh yeast)","1 tsp granulated sugar (to feed yeast)","1.5 tsp fine salt for the dough","300 ml warm whole milk (or water, traditional) at 38 °C","100 g boiled mashed potato (the secret to the fluffy texture)","2 tbsp neutral oil for the dough","1 L sunflower or neutral oil for deep-frying","For garlic rub: 4 garlic cloves crushed with 1 tsp salt + 1 tbsp water into a paste","200 g Hungarian sour cream (tejföl)","200 g sharp grated cheese (cheddar/gouda/edam-style)","1 small bunch fresh chives, finely chopped (optional)","Salt for finishing","Equipment: wide heavy pot for frying + slotted spoon + wire rack"],"ro":["500 g făină universală sau de pâine T550","7 g drojdie uscată instant (sau 21 g drojdie proaspătă)","1 linguriță zahăr granulat (pentru hrănirea drojdiei)","1,5 lingurițe sare fină pentru aluat","300 ml lapte integral cald (sau apă, tradițional) la 38 °C","100 g cartof fiert și pasat (secretul texturii pufoase)","2 linguri ulei neutru pentru aluat","1 L ulei de floarea-soarelui sau neutru pentru prăjit","Pentru ungerea cu usturoi: 4 căței de usturoi zdrobiți cu 1 linguriță sare + 1 lingură apă în pastă","200 g smântână ungurească (tejföl)","200 g brânză tare rasă (cheddar/gouda/edam)","1 legăturică mică de ceapă verde proaspătă (arpagic), tocată fin (opțional)","Sare pentru finisare","Echipament: oală grea și lată pentru prăjit + lingură cu fante + grătar de sârmă"]},"howIsMade":{"hi":"खमीर सक्रिय करें: 100 मिली दूध को 38 °C तक गरम करें, 7 ग्राम खमीर और 1 छोटा चम्मच चीनी डालें, हिलाएं और 10 मिनट तक झाग आने तक रखें। कोई झाग नहीं = मरी हुई खमीर, फिर से शुरू करें।. आटा गूंदें: एक बड़े कटोरे में 500 ग्राम आटा 1.5 छोटे चम्मच नमक के साथ मिलाएं। एक गड्ढा बनाएं, झाग वाला खमीर दूध, बचा हुआ 200 मिली गुनगुना दूध, 100 ग्राम चिकना मसला आलू (बिना गांठ) और 2 बड़े चम्मच तेल डालें। हाथ या स्टैंड मिक्सर से 10 मिनट तक गूंदें जब तक चिकना, मुलायम और थोड़ा चिपचिपा न हो जाए — ब्रेड के आटे से नरम।. पहली खमीरीकरण: साफ़ तौलिए से ढकें और गर्म स्थान पर 1.5–2 घंटे दोगुना होने तक रखें।. आकार दें: हाथों और कार्य सतह पर हल्का तेल लगाएं। 4 बराबर हिस्सों में बांटें (~225 ग्राम प्रत्येक)। गेंदों में बेल लें, ढककर 10 मिनट विश्राम दें। तेल लगे हाथों से प्रत्येक गेंद को 25 सेमी की डिस्क में लगभग 1 सेमी मोटी फैलाएं, किनारों पर थोड़ा पतला।. दूसरी खमीरीकरण: आकार दी डिस्क को तेल लगी ट्रे पर रखें, ढीली ढकें और 20 मिनट फूलने तक रहने दें।. तेल गरम करें: 1 लीटर तेल को चौड़े भारी बर्तन में 5 सेमी गहराई तक डालें। 175 °C (मध्यम-तेज़ आँच) तक गरम करें — आटे का एक छोटा टुकड़ा 5 सेकंड के भीतर चटकना और ऊपर उठना चाहिए।. लांगोश तलें: एक लांगोश को सावधानी से गर्म तेल में स्लाइड करें। 30 सेकंड बाद छेद वाले चम्मच से धीरे से तेल के नीचे दबाएं — यह नाटकीय रूप से फूलता है। गहरा सुनहरा भूरा होने तक प्रत्येक तरफ 60–90 सेकंड तलें। तार रैक पर निकालें (किचन टॉवल नहीं जो भाप से तल नरम करता है)।. टॉपिंग और परोसें: अभी भी गरम ऊपरी हिस्से पर लहसुन पेस्ट (4 कलियाँ 1 छोटे चम्मच नमक + 1 बड़े चम्मच पानी के साथ कुचली) ब्रश करें। 50 ग्राम खट्टी क्रीम फैलाएं, 50 ग्राम कद्दूकस चीज़ बिखेरें, कटी चाइव्स और एक चुटकी नमक छिड़कें। हाथ में या प्लेट पर परोसें, 5 मिनट के भीतर खाएं जब रोटी बाहर से कुरकुरी और अंदर से नरम हो।.","en":"PROOF THE YEAST: warm 100 ml of the milk to 38 °C, add 7 g yeast and 1 tsp sugar, stir and let stand 10 minutes until foamy; no foam = dead yeast, start over. MAKE THE DOUGH: in a large bowl combine 500 g flour with 1.5 tsp salt; make a well, add the foamed yeast-milk, the remaining 200 ml warm milk, 100 g smooth mashed potato (no lumps), and 2 tbsp oil; knead by hand or stand mixer 10 minutes until smooth, soft and slightly sticky — softer than bread dough. FIRST PROOF: cover with a clean towel and rise in a warm place 1.5–2 hours until doubled. SHAPE: lightly oil hands and work surface; divide into 4 equal portions (~225 g each); roll into balls, rest 10 minutes covered; with oiled hands stretch each ball into a 25 cm disc about 1 cm thick, slightly thinner at the edges. SECOND PROOF: place shaped discs on an oiled tray, cover loosely and let rise 20 minutes until puffy. HEAT THE OIL: pour 1 L oil into a wide heavy pot to a 5 cm depth; heat to 175 °C (medium-high) — a small piece of dough should sizzle and rise within 5 seconds. FRY THE LÁNGOS: carefully slide one lángos into the hot oil; after 30 seconds, gently push under with a slotted spoon — it puffs dramatically; fry 60–90 seconds per side until deeply golden brown; drain on a wire rack (NOT paper towels which steam the base soft). TOPPING & SERVE: brush the still-hot top with garlic paste (4 garlic crushed with 1 tsp salt + 1 tbsp water); smear with 50 g sour cream, scatter 50 g grated cheese, sprinkle chopped chives and a pinch of salt; serve in hand or on a plate, eaten within 5 minutes while bread is crisp outside and pillowy inside."}},{"id":165,"servings":4,"tipType":"veg","pairingsType":"indian","origin":{"hi":"भारत","en":"India","ro":"India"},"name":{"hi":"राजमा","en":"Rajma","ro":"Rajma"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["सूखी राजमा 350 ग्राम, 8–12 घंटे ठंडे पानी में भिगोई (या शॉर्टकट के तौर पर 2 × 400 ग्राम राजमा के डिब्बे छाने हुए)","राजमा उबालने के लिए 1.2 लीटर पानी + 1 छोटा चम्मच नमक + 2 तेज पत्ते + 4 बड़ी इलायची की फलियाँ (प्रेशर कुकर के लिए)","मसाला के लिए 3 बड़े चम्मच घी या तटस्थ तेल","साबुत जीरा 1 छोटा चम्मच","बहुत बारीक कटे 2 मध्यम पीले प्याज़ (~300 ग्राम)","6 लहसुन की कलियाँ + 4 सेमी ताज़ा अदरक — 1 बड़े चम्मच पानी के साथ पेस्ट में पीसें","1 हरी मिर्च (या स्वादानुसार), बारीक कटी","4 मध्यम पके टमाटर (~400 ग्राम), ब्लेंडर में चिकनी पल्प तक पीसे","टमाटर पेस्ट 1 बड़ा चम्मच (गाढ़ापन के लिए)","मसाला के लिए धनिया पाउडर 1 छोटा चम्मच + पिसा जीरा 1 छोटा चम्मच + हल्दी 0.5 छोटा चम्मच + कश्मीरी लाल मिर्च पाउडर 1 छोटा चम्मच + नमक 1 छोटा चम्मच","गरम मसाला 1 छोटा चम्मच (अंत में डालें, उबालें नहीं)","कसूरी मेथी 1 छोटा चम्मच, हथेली में मसली (अंत में डालें)","30 ग्राम मक्खन क्यूब्स में (रेस्तरां शैली का अंतिम स्पर्श)","1 बड़ा चम्मच सिंगल क्रीम या 2 बड़े चम्मच फुल फैट दही (वैकल्पिक, क्रीमी बनावट के लिए)","गार्निश के लिए ताज़े धनिया (सिलैंट्रो) पत्ते + 1 नींबू वेजेज में; परोसने के लिए: 540 मिली पानी में 0.5 छोटा चम्मच नमक के साथ पका 360 ग्राम (2 कप) बासमती चावल, और नान या जीरा राइस यदि पसंद हो"],"en":["350 g dried red kidney beans (rajma) soaked 8–12 h in cold water (OR 2 × 400 g cans drained as a shortcut)","1.2 L cooking water for the beans + 1 tsp salt + 2 bay leaves + 4 black cardamom pods (for pressure-cooking the beans)","3 tbsp ghee or neutral oil for the masala","1 tsp whole cumin seeds (jeera)","2 medium yellow onions (~300 g) very finely diced","6 garlic cloves + 4 cm fresh ginger — grated into a paste with 1 tbsp water","1 green chili (or to taste), finely chopped","4 medium ripe tomatoes (~400 g), pureed in a blender to a smooth pulp","1 tbsp tomato paste (for body)","1 tsp ground coriander (dhania) + 1 tsp ground cumin (jeera) + 0.5 tsp turmeric (haldi) + 1 tsp Kashmiri red chili powder + 1 tsp salt for the masala","1 tsp garam masala (added at end, not boiled)","1 tsp kasuri methi (dried fenugreek leaves), crushed in palm (added at end)","30 g butter cubed (the restaurant-style finish)","1 tbsp single cream or 2 tbsp full-fat yogurt (optional, for creaminess)","Fresh coriander (cilantro) leaves to garnish + 1 lime in wedges; to serve: 360 g (2 cups) basmati rice cooked in 540 ml water with 0.5 tsp salt, and naan or jeera rice if preferred"],"ro":["350 g fasole roșie uscată (rajma) înmuiată 8–12 h în apă rece (SAU 2 × 400 g cutii de fasole roșie scursă ca scurtătură)","1,2 L apă de fierbere pentru fasole + 1 linguriță sare + 2 foi de dafin + 4 păstăi de cardamom negru (pentru fierberea sub presiune)","3 linguri ghee sau ulei neutru pentru masala","1 linguriță semințe întregi de chimion (jeera)","2 cepe galbene medii (~300 g) tocate foarte fin","6 căței de usturoi + 4 cm de ghimbir proaspăt — răzuite în pastă cu 1 lingură de apă","1 ardei iute verde (sau după gust), tocat fin","4 roșii medii coapte (~400 g), pasate la blender până la o pulpă fină","1 lingură pastă de roșii (pentru corp)","1 linguriță coriandru măcinat (dhania) + 1 linguriță chimion măcinat (jeera) + 0,5 linguriță turmeric (haldi) + 1 linguriță Kashmiri chili pudră + 1 linguriță sare pentru masala","1 linguriță garam masala (adăugat la final, nu fiert)","1 linguriță kasuri methi (frunze uscate de schinduf), zdrobite în palmă (adăugat la final)","30 g unt cubulețe (finisajul în stil restaurant)","1 lingură smântână dulce single sau 2 linguri iaurt gras (opțional, pentru cremozitate)","Frunze proaspete de coriandru (cilantro) pentru garnitură + 1 lămâie verde feliată; pentru servire: 360 g (2 căni) orez basmati fiert în 540 ml apă cu 0,5 linguriță sare, plus naan sau jeera rice dacă preferi"]},"howIsMade":{"hi":"राजमा भिगोएँ: 350 ग्राम राजमा को ठंडे पानी में 2–3 बार धोएँ। ठंडे पानी से 5 सेमी ऊपर तक ढककर 8–12 घंटे (या रातभर) भिगोएँ। छानकर धोएँ। भिगोना छोड़ने से बीच कच्चे रह जाते हैं और गैस वाली बनावट बनती है।. प्रेशर कुकर में राजमा पकाएँ: भीगी राजमा को प्रेशर कुकर में 1.2 लीटर पानी + 1 छोटा चम्मच नमक + 2 तेज पत्ते + 4 बड़ी इलायची के साथ डालें। तेज आँच पर 4–5 सीटी के लिए प्रेशर पकाएँ, फिर धीमी आँच पर 25 मिनट पकाएँ। प्रेशर को स्वाभाविक रूप से निकलने दें। राजमा पूरी तरह से नरम होना चाहिए — एक दाना अंगूठे और तर्जनी के बीच दबाएँ; हल्के दबाव से मसल जाना चाहिए। (विकल्प: खुले बर्तन में 1.5–2 घंटे उबालें।) 500 मिली पानी बचाते हुए छानें।. भुनाओ — तड़का: एक भारी कढ़ाई या गहरे पैन में मध्यम आँच पर 3 बड़े चम्मच घी पिघलाएँ। जब चमकने लगे, 1 छोटा चम्मच जीरा डालें — 5 सेकंड में चटकेगा और फटेगा। काला होने न दें।. प्याज़: 300 ग्राम बहुत बारीक कटा प्याज़ डालें। बार-बार चलाते हुए 12–15 मिनट तक गहरा सुनहरा भूरा — लगभग कैरेमलाइज़्ड — होने तक पकाएँ। यह लंबा, धीमा प्याज़ का भुनाओ रेस्तरां की राजमा को शौकिया प्रयासों से अलग करता है। जल्दबाज़ी न करें।. अदरक-लहसुन-हरी मिर्च: अदरक-लहसुन का पेस्ट और हरी मिर्च डालें। 1–2 मिनट चलाएँ जब तक कच्ची गंध न चली जाए।. टमाटर बेस: पिसा हुआ टमाटर पल्प + 1 बड़ा चम्मच टमाटर पेस्ट + 1 छोटा चम्मच धनिया पाउडर + 1 छोटा चम्मच पिसा जीरा + 0.5 छोटा चम्मच हल्दी + 1 छोटा चम्मच कश्मीरी मिर्च + 1 छोटा चम्मच नमक डालें। बार-बार चलाते हुए 8–10 मिनट पकाएँ जब तक तेल कढ़ाई के किनारों पर मसाले से अलग न हो जाए — यह दृश्य संकेत है कि भुनाओ पूर्ण हो गया और कच्चा टमाटर पक गया है।. राजमा के साथ पकाएँ: छनी हुई राजमा और 500 मिली बचाया हुआ पानी डालें। धीरे से चलाएँ। उबाल आने दें और बिना ढके 20–25 मिनट पकाएँ, ग्रेवी को गाढ़ा करने के लिए कुछ राजमा को चम्मच से कढ़ाई के किनारे पर आंशिक रूप से मसलें। ग्रेवी कम होनी चाहिए और राजमा पर लिपटनी चाहिए — न ज़्यादा पतली न सूखी, चम्मच पर टिकने वाले गाढ़े स्टू की तरह।. फिनिश और परोसें: 1 छोटा चम्मच गरम मसाला + 1 छोटा चम्मच मसली कसूरी मेथी + 30 ग्राम क्यूब्स में मक्खन + 1 बड़ा चम्मच क्रीम (वैकल्पिक) मिलाएँ। मक्खन पिघलने तक चलाएँ। ढककर आँच से उतार 5 मिनट छोड़ दें ताकि स्वाद बैठ जाएँ। उबले बासमती चावल (या जीरा राइस या नान) के ऊपर गर्मागर्म परोसें, कटी ताज़ी धनिया और नींबू निचोड़ कर। अगले दिन और बेहतर।.","en":"SOAK THE BEANS: rinse 350 g rajma in cold water 2–3 times; cover with cold water by 5 cm and soak 8–12 hours (or overnight); drain and rinse; skipping the soak gives undercooked centers and gassy texture. PRESSURE-COOK THE BEANS: place soaked rajma in a pressure cooker with 1.2 L water + 1 tsp salt + 2 bay leaves + 4 black cardamom pods; pressure-cook on high heat 4–5 whistles, then reduce to low and cook 25 minutes; let the pressure release naturally; beans should be completely tender — press one between thumb and forefinger; it should mash with light pressure; (Alternative: open pot 1.5–2 h simmer.) Drain reserving 500 ml bean cooking liquid. BHUNAO — TEMPER: in a heavy kadhai or deep pan over medium heat, melt 3 tbsp ghee; when shimmering, add 1 tsp cumin seeds — they will sizzle and pop within 5 seconds; do not let them blacken. ONIONS: add 300 g very finely diced onion; cook stirring often 12–15 minutes until deeply golden brown — almost caramelized; this long, slow onion bhunao is what separates restaurant rajma from amateur attempts; do not rush. GINGER-GARLIC-CHILI: add the ginger-garlic paste and green chili; stir 1–2 minutes until the raw smell disappears. TOMATO BASE: add the pureed tomato pulp + 1 tbsp tomato paste + 1 tsp ground coriander + 1 tsp ground cumin + 0.5 tsp turmeric + 1 tsp Kashmiri chili powder + 1 tsp salt; cook stirring frequently 8–10 minutes until the oil separates from the masala on the edges of the pan — this is the visual sign the bhunao is complete and the raw tomato has cooked off. SIMMER WITH BEANS: tip in the drained rajma and 500 ml of reserved bean liquid; stir gently; bring to a simmer and cook uncovered 20–25 minutes, partially mashing some beans against the side of the pan with a spoon to thicken the gravy; the gravy should reduce and coat the beans — neither soupy nor dry, like a thick stew that holds on a spoon. FINISH AND SERVE: stir in 1 tsp garam masala + 1 tsp crushed kasuri methi + 30 g butter cubed + 1 tbsp cream (optional); stir until butter melts; cover and let rest off heat 5 minutes for flavors to settle; serve hot over steamed basmati rice (or jeera rice or naan), topped with chopped fresh coriander and a squeeze of lime; better the next day."}},{"id":166,"servings":4,"tipType":"meat","pairingsType":"latin","origin":{"hi":"क्यूबा","en":"Cuba","ro":"Cuba"},"name":{"hi":"पिकाडिलो","en":"Picadillo","ro":"Picadillo"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["बीफ़ कीमा 600 ग्राम (चक, ~20% वसा)","सोफ्रिटो के लिए 2 बड़े चम्मच जैतून का तेल","1 बड़ा पीला प्याज़ (~200 ग्राम), बारीक कटा","1 बड़ी हरी शिमला मिर्च (~200 ग्राम), बारीक कटी","6 लहसुन की कलियाँ, बारीक कटी","1 छोटा चम्मच पिसा जीरा (कॉमिनो) + 1 छोटा चम्मच सूखा ऑरगैनो + 0.5 छोटा चम्मच मीठी स्मोक्ड पपरिका (पिमेंतोन) + 1 तेज पत्ता","400 ग्राम कुचला टमाटर डिब्बाबंद (या 4 ताज़े टमाटर छीलकर कद्दूकस किए) + 2 बड़े चम्मच टमाटर पेस्ट","100 मिली ड्राई व्हाइट वाइन या 50 मिली ड्राई शेरी (क्यूबन परंपरागत — कच्चे मांस की गंध जलाता है)","बीज रहित हरे जैतून (मैनज़ानिला) 100 ग्राम, आधे कटे","सुनहरी या काली किशमिश 60 ग्राम, 100 मिली गर्म पानी में 10 मिनट भिगोकर फिर छानी","जमी हरी मटर 100 ग्राम, पिघलाई","1 बड़ा चम्मच केपर, छाने (वैकल्पिक, परंपरागत)","1.5 छोटा चम्मच नमक + 0.5 छोटा चम्मच ताज़ी पिसी काली मिर्च","गार्निश के लिए ताज़ा फ्लैट-लीफ पार्सले","परोसने के लिए: 540 मिली पानी में 0.5 छोटा चम्मच नमक के साथ पका 360 ग्राम (2 कप) सफ़ेद चावल + 240 ग्राम पकी काली फलियाँ + 2 पके प्लांटेन कटे और तले + नींबू वेजेज"],"en":["600 g ground beef (chuck, ~20% fat)","2 tbsp olive oil for the sofrito","1 large yellow onion (~200 g), finely diced","1 large green bell pepper (~200 g), finely diced","6 garlic cloves, minced","1 tsp ground cumin (comino) + 1 tsp dried oregano + 0.5 tsp sweet smoked paprika (pimentón) + 1 bay leaf","400 g can crushed tomatoes (or 4 fresh tomatoes peeled and grated) + 2 tbsp tomato paste","100 ml dry white wine OR 50 ml dry sherry (Cuban traditional — burns off raw-meat smell)","100 g pitted green olives (manzanilla), halved","60 g golden or dark raisins, soaked 10 min in 100 ml hot water then drained","100 g frozen green peas, thawed","1 tbsp capers, drained (optional, traditional)","1.5 tsp salt + 0.5 tsp freshly ground black pepper","Fresh flat-leaf parsley to garnish","To serve: 360 g (2 cups) white rice cooked in 540 ml water with 0.5 tsp salt + 240 g cooked black beans + 2 ripe plantains sliced and fried + lime wedges"],"ro":["600 g carne tocată de vită (gât/cap de piept, ~20% grăsime)","2 linguri ulei de măsline pentru sofrito","1 ceapă galbenă mare (~200 g), tăiată cubulețe fine","1 ardei gras verde mare (~200 g), tăiat cubulețe fine","6 căței de usturoi, tocați mărunt","1 linguriță chimion măcinat (comino) + 1 linguriță oregano uscat + 0,5 linguriță boia dulce afumată (pimentón) + 1 foaie de dafin","400 g roșii zdrobite la conservă (sau 4 roșii proaspete decojite și răzuite) + 2 linguri pastă de roșii","100 ml vin alb sec SAU 50 ml sherry sec (tradițional cubanez — arde mirosul de carne crudă)","100 g măsline verzi fără sâmburi (manzanilla), tăiate în jumătăți","60 g stafide aurii sau negre, înmuiate 10 minute în 100 ml apă caldă, apoi scurse","100 g mazăre verde congelată, dezghețată","1 lingură capere, scurse (opțional, tradițional)","1,5 linguriță sare + 0,5 linguriță piper negru proaspăt măcinat","Pătrunjel verde proaspăt cu frunza lată pentru garnitură","Pentru servire: 360 g (2 căni) orez alb fiert în 540 ml apă cu 0,5 linguriță sare + 240 g fasole neagră fiartă + 2 banane plantain coapte feliate și prăjite + felii de lămâie verde"]},"howIsMade":{"hi":"सोफ्रिटो बेस: एक भारी 5 लीटर बर्तन में मध्यम आँच पर 2 बड़े चम्मच जैतून का तेल गरम करें। 200 ग्राम कटा प्याज़ + 200 ग्राम कटी हरी शिमला मिर्च और एक चुटकी नमक डालें। बार-बार चलाते हुए 8–10 मिनट तक पकाएँ जब तक नर्म और सुनहरा होने न लगे — सोफ्रिटो क्यूबन व्यंजनों की आत्मा है। 6 कटी लहसुन की कलियाँ डालें और 1 मिनट और पकाएँ जब तक खुशबू न आ जाए।. मसाले खिलाएँ: 1 छोटा चम्मच जीरा, 1 छोटा चम्मच ऑरगैनो, 0.5 छोटा चम्मच स्मोक्ड पपरिका और 1 तेज पत्ता गरम तेल-सब्ज़ी बेस में डालें। 30 सेकंड चलाएँ जब तक मसाले अपनी खुशबू न छोड़ें — जलने न दें।. बीफ़ भूनें: आँच को मध्यम-तेज़ पर बढ़ाएँ। 600 ग्राम बीफ़ कीमा एक परत में डालें और 2–3 मिनट बिना छेड़े रहने दें ताकि क्रस्ट बन जाए। फिर लकड़ी के चम्मच से तोड़ें और 6–8 मिनट और भूनें जब तक गुलाबी न रहे और कोई निकला हुआ तरल वाष्पित न हो जाए।. डीग्लेज़: 100 मिली ड्राई व्हाइट वाइन (या 50 मिली शेरी) डालें और बर्तन के तले में चिपके भूरे टुकड़े खुरचें। 2–3 मिनट उबालें जब तक शराब की गंध न चली जाए।. टमाटर + निर्माण: कुचले टमाटर का डिब्बा + 2 बड़े चम्मच टमाटर पेस्ट मिलाएँ। 5 मिनट पकाएँ जब तक मिश्रण गहरा न हो और सतह पर तेल न दिखने लगे — टमाटर पूरी तरह पका, बिना कच्ची खटास।. जैतून, किशमिश और मसाला डालें: 100 ग्राम आधे कटे हरे जैतून + 60 ग्राम छानी किशमिश + 1 बड़ा चम्मच केपर (यदि उपयोग कर रहे हों) + 1.5 छोटा चम्मच नमक + 0.5 छोटा चम्मच काली मिर्च मिलाएँ। मीठा-नमकीन विरोधाभास अनोखा क्यूबन हस्ताक्षर है।. धीमी आँच पर पकाएँ: आँच को धीमा करें, आंशिक रूप से ढककर 20–25 मिनट पकाएँ, हर कुछ मिनट चलाते रहें। मिश्रण एक सॉसी हैश में गाढ़ा होना चाहिए — न सूखा न पतला, चम्मच पर टिकने वाला। बहुत सूख जाए तो 60 मिली पानी डालें।. मटर और परोसें: आख़िरी 3 मिनट में 100 ग्राम पिघली मटर मिलाएँ — बस गर्म करने के लिए, उनकी चमकीली हरी रंगत बनाए रखें। तेज पत्ता निकालें। आँच से उतार कटा पार्सले छिड़कें। उबले सफ़ेद चावल पर काली फलियों के साथ, तले प्लांटेन और नींबू वेजेज के साथ परोसें — क्लासिक क्यूबन comida criolla थाली।.","en":"SOFRITO BASE: in a heavy 5 L pot, heat 2 tbsp olive oil over medium heat; add 200 g diced onion + 200 g diced green pepper with a pinch of salt; cook stirring often 8–10 minutes until soft and beginning to gold — the sofrito is the soul of Cuban cooking; add 6 minced garlic cloves and cook 1 minute more until fragrant. BLOOM THE SPICES: add 1 tsp cumin, 1 tsp oregano, 0.5 tsp smoked paprika and 1 bay leaf to the hot oil-and-vegetable base; stir 30 seconds until the spices release their aroma — do not burn. BROWN THE BEEF: raise heat to medium-high; add 600 g ground beef in a single layer and let it sit undisturbed 2–3 minutes to develop a crust; then break it up with a wooden spoon and brown another 6–8 minutes until no pink remains and any released liquid has evaporated. DEGLAZE: pour in 100 ml dry white wine (or 50 ml sherry) and scrape any browned bits stuck to the bottom of the pot; simmer 2–3 minutes until the alcohol smell disappears. TOMATO + BUILD: stir in the can of crushed tomatoes + 2 tbsp tomato paste; cook 5 minutes until the mixture darkens and oil starts to appear on the surface — tomato fully cooked, no raw acidity. ADD OLIVES, RAISINS & SEASON: stir in 100 g halved green olives + 60 g drained raisins + 1 tbsp capers (if using) + 1.5 tsp salt + 0.5 tsp pepper; the sweet-salty contrast is the unique Cuban signature. SIMMER: reduce heat to low, cover partially, and simmer 20–25 minutes, stirring every few minutes; the mixture should thicken into a saucy hash — neither dry nor soupy, holding together on a spoon; add 60 ml water if it gets too dry. PEAS & SERVE: in the last 3 minutes, stir in 100 g thawed peas — just to warm through, keeping them bright green; remove the bay leaf; off the heat, scatter chopped parsley; serve over steamed white rice with black beans on the side, fried plantains, and lime wedges — the classic Cuban comida criolla plate."}},{"id":167,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"hi":"मोरक्को","en":"Morocco","ro":"Maroc"},"name":{"hi":"मेमने का टैगीन","en":"Lamb Tagine","ro":"Tagine cu miel"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["1 किलो हड्डी रहित मेमने का कंधा, 4 सेमी क्यूब में कटा (समृद्धि के लिए थोड़ी चर्बी सहित)","2 बड़े पीले प्याज़ (~400 ग्राम), एक बेस के लिए बारीक कटा और दूसरा स्टू के लिए मोटे टुकड़ों में कटा","6 लहसुन की कलियाँ, बारीक कटी","4 सेमी ताज़ा अदरक, कद्दूकस की","3 बड़े चम्मच जैतून का तेल (या 2 बड़े चम्मच तेल + पारंपरिक समृद्धि के लिए 1 बड़ा चम्मच मक्खन)","1 छोटा चम्मच पिसा जीरा + 1 छोटा चम्मच पिसा धनिया + 1 छोटा चम्मच पिसी दालचीनी + 0.5 छोटा चम्मच पिसी हल्दी + 0.5 छोटा चम्मच मीठी पपरिका + 0.5 छोटा चम्मच पिसा अदरक + एक चुटकी केसर के धागे (5–6 धागे, 2 बड़े चम्मच गर्म पानी में भिगोए)","1.5 छोटा चम्मच रास अल हनुत (मोरक्कन मसाला मिश्रण)","1.5 छोटा चम्मच नमक + 0.5 छोटा चम्मच ताज़ी पिसी काली मिर्च","2 बड़े चम्मच टमाटर पेस्ट","400 ग्राम पके टमाटर (4 मध्यम), छीलकर कद्दूकस किए, या 1 × 400 ग्राम का डिब्बा","200 ग्राम सूखी खुबानी, आधी कटी (तुर्की या कैलिफोर्निया — बहुत मीठी नहीं)","60 ग्राम बीज रहित सूखे आलूबुखारे या किशमिश (वैकल्पिक, गहराई के लिए)","600 मिली गर्म पानी या कम नमक वाला चिकन स्टॉक","1 दालचीनी की डंडी + 1 तेज पत्ता","80 ग्राम साबुत छिली बादाम (या छिलके सहित, भुनी)","1 बड़ा चम्मच शहद (मिठास संतुलित करने के लिए अंत में मिलाएँ)","ताज़ा हरा धनिया + फ्लैट-लीफ पार्सले + 1 बड़ा चम्मच हल्के भुने तिल गार्निश के लिए","परोसने के लिए: 400 मिली पानी + 1 बड़ा चम्मच मक्खन + 0.5 छोटा चम्मच नमक के साथ भाप में पकाया 400 ग्राम कुसकुस, या गर्म ख़ोबज़ फ्लैटब्रेड"],"en":["1 kg boneless lamb shoulder, cut into 4 cm cubes (with some fat on for richness)","2 large yellow onions (~400 g), one finely diced for the base and one cut into thick wedges for the stew","6 garlic cloves, minced","4 cm fresh ginger, grated","3 tbsp olive oil (or 2 tbsp oil + 1 tbsp butter for traditional richness)","1 tsp ground cumin + 1 tsp ground coriander + 1 tsp ground cinnamon + 0.5 tsp ground turmeric + 0.5 tsp sweet paprika + 0.5 tsp ground ginger + a pinch of saffron threads (5–6 strands, bloomed in 2 tbsp hot water)","1.5 tsp ras el hanout (Moroccan spice blend)","1.5 tsp salt + 0.5 tsp freshly ground black pepper","2 tbsp tomato paste","400 g ripe tomatoes (4 medium), peeled and grated, or 1 × 400 g can","200 g dried apricots, halved (use Turkish or California — not too sweet)","60 g pitted dried prunes or raisins (optional, for depth)","600 ml hot water or low-salt chicken stock","1 cinnamon stick + 1 bay leaf","80 g whole blanched almonds (or skin-on, toasted)","1 tbsp honey (added at the end to balance sweetness)","Fresh coriander + flat-leaf parsley + 1 tbsp lightly toasted sesame seeds to garnish","To serve: 400 g couscous steamed with 400 ml water + 1 tbsp butter + 0.5 tsp salt, OR warm khobz flatbread"],"ro":["1 kg pulpă de miel dezosată (spată), tăiată cuburi de 4 cm (cu puțină grăsime pentru bogăție)","2 cepe galbene mari (~400 g), una tăiată cubulețe fine pentru bază și una tăiată în felii groase pentru tocăniță","6 căței de usturoi, tocați mărunt","4 cm ghimbir proaspăt, ras","3 linguri ulei de măsline (sau 2 linguri ulei + 1 lingură unt pentru bogăție tradițională)","1 linguriță chimion măcinat + 1 linguriță coriandru măcinat + 1 linguriță scorțișoară măcinată + 0,5 linguriță turmeric măcinat + 0,5 linguriță boia dulce + 0,5 linguriță ghimbir măcinat + un vârf de șofran (5–6 fire, înflorit în 2 linguri apă caldă)","1,5 linguriță ras el hanout (amestec marocan de condimente)","1,5 linguriță sare + 0,5 linguriță piper negru proaspăt măcinat","2 linguri pastă de roșii","400 g roșii coapte (4 medii), decojite și răzuite, sau 1 cutie × 400 g","200 g caise uscate, tăiate în jumătăți (turcești sau californiene — nu prea dulci)","60 g prune uscate fără sâmburi sau stafide (opțional, pentru profunzime)","600 ml apă fierbinte sau supă de pui cu puțină sare","1 baton de scorțișoară + 1 foaie de dafin","80 g migdale întregi blanșate (sau cu coajă, prăjite)","1 lingură miere (adăugată la final pentru a echilibra dulceața)","Coriandru proaspăt + pătrunjel cu frunza lată + 1 lingură semințe de susan ușor prăjite pentru garnitură","Pentru servire: 400 g couscous aburit cu 400 ml apă + 1 lingură unt + 0,5 linguriță sare, SAU pâine plată khobz caldă"]},"howIsMade":{"hi":"मेमने को मैरीनेट करें: एक बड़े बर्तन में 1 किलो मेमने के क्यूब के साथ 1 छोटा चम्मच जीरा + 1 छोटा चम्मच धनिया + 1 छोटा चम्मच दालचीनी + 0.5 छोटा चम्मच हल्दी + 0.5 छोटा चम्मच पपरिका + 0.5 छोटा चम्मच अदरक + 1.5 छोटा चम्मच रास अल हनुत + 1.5 छोटा चम्मच नमक + 0.5 छोटा चम्मच काली मिर्च + 3 कटी लहसुन की कलियाँ और 1 बड़ा चम्मच जैतून का तेल मिलाएँ। हाथों से मसालों को मांस में अच्छी तरह रगड़ें। ढककर कमरे के तापमान पर 30 मिनट (या फ्रिज में 24 घंटे तक) रखें ताकि मसाले अच्छे से समा जाएँ।. केसर खिलाएँ: 5–6 केसर के धागे 2 बड़े चम्मच गर्म पानी में डालकर 10 मिनट भिगोएँ — इससे स्वाद और रंग निकलता है। अलग रख दें।. बेस बनाएँ: एक भारी तले वाले टैगीन या डच ओवन में बची 2 बड़े चम्मच तेल (और उपयोग कर रहे हों तो 1 बड़ा चम्मच मक्खन) मध्यम आँच पर गरम करें। 200 ग्राम बारीक कटा प्याज़ डालें और बार-बार चलाते हुए 8–10 मिनट तक नर्म और पारदर्शी होने तक पकाएँ। बची 3 कटी लहसुन की कलियाँ + कद्दूकस की अदरक डालें और 1 मिनट चलाएँ।. मेमने को सीयर करें: आँच को मध्यम-तेज़ करें। प्याज़ को बर्तन के किनारों की ओर धकेलें और मैरीनेट किए मेमने को एक परत में डालें (ज़रूरत हो तो 2 बैच में करें)। बिना हिलाए हर तरफ 3–4 मिनट सीयर करें जब तक सभी तरफ गहरा भूरा न हो जाए — क्रस्ट स्टू के समृद्ध स्वाद के लिए आवश्यक है। मेमना भूरा होने के बाद सब कुछ एक साथ मिलाएँ।. टमाटर + तरल: 2 बड़े चम्मच टमाटर पेस्ट मिलाएँ और 1 मिनट गहरा होने तक पकाएँ। 400 ग्राम कद्दूकस किया टमाटर, केसर का पानी, 1 दालचीनी की डंडी और 1 तेज पत्ता डालें। 600 मिली गर्म पानी (या स्टॉक) डालें — तरल को मांस के लगभग आधे तक आना चाहिए, उसे ढकना नहीं चाहिए। हल्के से उबाल पर लाएँ।. धीमी आँच पर पकाएँ: आँच को धीमा करें, टैगीन के ढक्कन (या डच ओवन के सख्त ढक्कन) से ढकें और 1.5–2 घंटे पकाएँ, हर 30 मिनट जाँचते और धीरे से चलाते रहें। जब काँटा आसानी से घुस जाए तो मेमना तैयार है। अगर सॉस बहुत तेज़ी से कम हो जाए तो थोड़ा गर्म पानी डालें।. खुबानी + प्याज़ डालें: 200 ग्राम आधी कटी सूखी खुबानी + 60 ग्राम आलूबुखारा (यदि उपयोग कर रहे हों) + 200 ग्राम प्याज़ के टुकड़े मिलाएँ। ढककर 25–30 मिनट और पकाएँ जब तक फल फूल जाए और प्याज़ के टुकड़े नर्म हों लेकिन अपना आकार बनाए रखें। सॉस चमकदार होना चाहिए, चम्मच के पिछले हिस्से को ढकता हुआ। 1 बड़ा चम्मच शहद से समाप्त करें, चखें, नमक समायोजित करें।. समाप्त करें और परोसें: जब टैगीन आँच से दूर 5 मिनट विश्राम करे, 80 ग्राम साबुत बादाम सूखे पैन में मध्यम आँच पर 3–4 मिनट सुनहरे होने तक भूनें — ध्यान से देखें, ये जल्दी जल जाते हैं। मेमने का टैगीन गर्म कुसकुस के ऊपर (या ख़ोबज़ के साथ) परोसें, ऊपर भुने बादाम, तिल और ताज़ा हरा धनिया और पार्सले छिड़कें। सॉस सोखने के लिए रोटी के साथ खाएँ।.","en":"MARINATE THE LAMB: in a large bowl combine 1 kg lamb cubes with 1 tsp cumin + 1 tsp coriander + 1 tsp cinnamon + 0.5 tsp turmeric + 0.5 tsp paprika + 0.5 tsp ginger + 1.5 tsp ras el hanout + 1.5 tsp salt + 0.5 tsp pepper + 3 of the minced garlic cloves and 1 tbsp olive oil; rub the spices into the meat with your hands; cover and rest 30 minutes at room temperature (or up to 24 h in the fridge) so the spices penetrate. BLOOM SAFFRON: place 5–6 saffron threads in 2 tbsp hot water and let steep 10 minutes — this releases the flavour and colour; set aside. BUILD THE BASE: heat the remaining 2 tbsp oil (and 1 tbsp butter if using) in a heavy-bottomed tagine or Dutch oven over medium heat; add 200 g finely diced onion and cook stirring often 8–10 minutes until soft and translucent; add the remaining 3 minced garlic + grated ginger and stir 1 minute. SEAR THE LAMB: raise heat to medium-high; push the onions to the sides of the pot and add the marinated lamb in a single layer (work in 2 batches if needed); sear 3–4 minutes per side without moving until deeply browned on all sides — the crust is essential for the rich stew flavour; stir everything together once the lamb is browned. TOMATO + LIQUID: stir in 2 tbsp tomato paste and cook 1 minute until darkened; add the 400 g grated tomatoes, the saffron-water, 1 cinnamon stick and 1 bay leaf; pour in 600 ml hot water (or stock) — the liquid should come about halfway up the meat, not cover it; bring to a gentle simmer. SLOW COOK: reduce heat to low, cover with the tagine lid (or a tight Dutch-oven lid), and simmer 1.5–2 hours, checking every 30 minutes and stirring gently; the lamb is ready when a fork sinks in easily; add a splash of hot water if the sauce reduces too quickly. ADD APRICOTS + ONIONS: stir in 200 g halved dried apricots + 60 g prunes (if using) + the 200 g onion wedges; cover and simmer 25–30 minutes more until the fruit is plump and the onion wedges are tender but still holding shape; the sauce should be glossy, coating the back of a spoon; finish with 1 tbsp honey, taste, adjust salt. FINISH AND SERVE: while the tagine rests off the heat for 5 minutes, toast 80 g whole almonds in a dry pan over medium heat 3–4 minutes until golden — watch carefully, they burn fast; spoon the lamb tagine over warm couscous (or serve with khobz), top with toasted almonds, sesame seeds, and a scatter of fresh coriander and parsley; eat with bread to mop up the sauce."}},{"id":168,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"hi":"यूनाइटेड किंगडम","en":"United Kingdom","ro":"Marea Britanie"},"name":{"hi":"शेफर्ड्स पाई","en":"Shepherd's Pie","ro":"Plăcintă a ciobanului"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"ingredients":{"hi":["600 ग्राम मेमने का कीमा (~15% वसा — सामान्य गोमांस कीमा की तुलना में कम वसा वाला लेकिन नमी के लिए पर्याप्त वसा सहित)","1 बड़ा प्याज़ (~200 ग्राम), बारीक कटा","2 मध्यम गाजर (~200 ग्राम), 0.5 सेमी बारीक कटी (छोटे टुकड़े — उन्हें भरावन में गायब हो जाना चाहिए)","4 लहसुन की कलियाँ, बारीक कटी","1 बड़ा चम्मच टमाटर पेस्ट","1 बड़ा चम्मच वर्सेस्टरशायर सॉस (गुप्त गहराई — गैर-समझौता योग्य)","1 छोटा चम्मच सूखा थाइम (या 2 ताज़ी टहनियाँ)","1 छोटा चम्मच सूखा रोज़मेरी, बारीक कटा","2 बड़े चम्मच साधारण आटा (ग्रेवी को गाढ़ा करने के लिए)","300 मिली गर्म मेमने या गोमांस का स्टॉक (घर का बना या कम नमक वाला)","150 ग्राम जमी हुई मटर","1 बड़ा चम्मच तटस्थ तेल","1 छोटा चम्मच नमक + 0.5 छोटा चम्मच ताज़ी पिसी काली मिर्च भरावन के लिए","मसले आलू की टॉपिंग के लिए: 1 किलो मैली आलू (Maris Piper, King Edward, या Yukon Gold), छीलकर 4 सेमी के टुकड़ों में काटे","60 ग्राम बिना नमक का मक्खन + 100 मिली गर्म पूरा दूध + 2 बड़े अंडे की जर्दी (जर्दी प्रतिष्ठित सुनहरा कुरकुरा शीर्ष देती है) + 30 ग्राम कद्दूकस किया परिपक्व चेडर (वैकल्पिक लेकिन पारंपरिक)","0.5 छोटा चम्मच सफेद मिर्च + 0.5 छोटा चम्मच नमक मसले आलू के लिए"],"en":["600 g minced lamb (~15% fat — leaner than usual ground beef but with enough fat for moisture)","1 large onion (~200 g), finely diced","2 medium carrots (~200 g), finely diced 0.5 cm (small dice — they should disappear into the filling)","4 garlic cloves, minced","1 tbsp tomato paste","1 tbsp Worcestershire sauce (the secret depth — non-negotiable)","1 tsp dried thyme (or 2 sprigs fresh)","1 tsp dried rosemary, finely chopped","2 tbsp plain flour (to thicken the gravy)","300 ml hot lamb or beef stock (homemade or low-salt)","150 g frozen peas","1 tbsp neutral oil","1 tsp salt + 0.5 tsp freshly ground black pepper for the filling","For the mash topping: 1 kg floury potatoes (Maris Piper, King Edward, or Yukon Gold), peeled and cut into 4 cm chunks","60 g unsalted butter + 100 ml warm whole milk + 2 large egg yolks (the yolks give the iconic golden crisp top) + 30 g grated mature cheddar (optional but traditional)","0.5 tsp white pepper + 0.5 tsp salt for the mash"],"ro":["600 g carne tocată de miel (~15% grăsime — mai slabă decât vita tocată obișnuită, dar cu suficientă grăsime pentru umiditate)","1 ceapă mare (~200 g), tăiată cubulețe fine","2 morcovi medii (~200 g), tăiați cubulețe fine de 0,5 cm (cubulețe mici — trebuie să dispară în umplutură)","4 căței de usturoi, tocați","1 lingură pastă de roșii","1 lingură sos Worcestershire (profunzimea secretă — nenegociabil)","1 linguriță cimbru uscat (sau 2 crenguțe proaspete)","1 linguriță rozmarin uscat, tocat fin","2 linguri făină albă (pentru a îngroșa sosul)","300 ml supă fierbinte de miel sau vită (de casă sau cu sare redusă)","150 g mazăre congelată","1 lingură ulei neutru","1 linguriță sare + 0,5 linguriță piper negru proaspăt măcinat pentru umplutură","Pentru piureul de deasupra: 1 kg cartofi făinoși (Maris Piper, King Edward sau Yukon Gold), curățați și tăiați bucăți de 4 cm","60 g unt nesărat + 100 ml lapte integral cald + 2 gălbenușuri mari (gălbenușurile dau crusta aurie iconică) + 30 g cheddar maturat ras (opțional dar tradițional)","0,5 linguriță piper alb + 0,5 linguriță sare pentru piure"]},"howIsMade":{"hi":"आलू उबालें: 1 किलो छिले और क्यूब किए आलू को एक बड़े बर्तन में ठंडे नमकीन पानी (2 लीटर पर 1 बड़ा चम्मच नमक) में डालें। उबाल पर लाएँ, स्थिर सिमर पर कम करें, और 15–18 मिनट तक पकाएँ जब तक चाकू बिना प्रतिरोध के फिसले। छानें और आँच से दूर बर्तन में 2 मिनट के लिए वापस रखें ताकि भाप निकले — गीले आलू गीला मैश बनाते हैं। 2. मैश बनाएँ: सूखे आलू को राइसर (फूले मैश के लिए सबसे अच्छा) से गुज़ारें या हाथ के मैशर से मसलें। जब अभी गर्म हो तो 60 ग्राम मक्खन मिलाकर फेंटें, फिर 100 मिली गर्म दूध को 3 बार में डालें, प्रत्येक के बीच फेंटते रहें। आँच से दूर 2 जर्दी, 0.5 छोटा चम्मच सफेद मिर्च, 0.5 छोटा चम्मच नमक फेंटें। मैश चमकदार, चिकना और पर्याप्त सख्त होना चाहिए कि कटक रख सके — यदि बहुत ढीला है तो टॉपिंग डूब जाएगी। गर्म रखने के लिए फॉयल से ढकें। 3. सब्ज़ियाँ पकाएँ: एक बड़े भारी पैन में मध्यम आँच पर 1 बड़ा चम्मच तेल गरम करें। 200 ग्राम कटी प्याज़ + 200 ग्राम कटी गाजर एक चुटकी नमक के साथ डालें। बार-बार चलाते हुए 8–10 मिनट पकाएँ जब तक बहुत नर्म न हो जाए और गाजर ने अपनी कुरकुराहट खो दी हो — मांस के साथ मिलाने के बाद ये और नर्म नहीं होंगी। 4 कटी लहसुन की कलियाँ + थाइम + रोज़मेरी डालें, 1 मिनट और पकाएँ। 4. मेमने को भूनें: आँच को मध्यम-तेज़ करें। 600 ग्राम मेमने का कीमा डालें और इसे लकड़ी के चम्मच से तोड़ें। 8–10 मिनट पकाएँ जब तक मेमना गुलाबी न रहे और निकली हुई चर्बी पैन के तल पर छोटे टुकड़ों को कुरकुरा करना शुरू न कर दे — यह मेलार्ड भूरा रंग ग्रेवी का आधार है। 1 बड़े चम्मच से अधिक जमी चर्बी को चम्मच से निकालें (मेमना बहुत छोड़ता है — बहुत ज़्यादा पाई को चिकना बनाता है)। 5. ग्रेवी बनाएँ: 1 बड़ा चम्मच टमाटर पेस्ट मेमने में मिलाएँ और 1 मिनट तक गहरा होने तक पकाएँ। ऊपर से 2 बड़े चम्मच आटा छिड़कें और कच्चे स्वाद को पकाने के लिए 1–2 मिनट चलाएँ। 300 मिली गर्म स्टॉक + 1 बड़ा चम्मच वर्सेस्टरशायर सॉस + 1 छोटा चम्मच नमक + 0.5 छोटा चम्मच मिर्च डालें, भूरे हुए टुकड़ों को उठाने के लिए पैन के तल को खुरचें। 6. सिमर + मटर: आँच को धीमा करें और बिना ढके 15 मिनट सिमर करें, कभी-कभी चलाते हुए, जब तक ग्रेवी मांस को कोट करने वाली गाढ़ी और चमकदार स्थिरता तक न गाढ़ी हो जाए — यह बहती हुई नहीं होनी चाहिए, अन्यथा मैश डूब जाएगी। 150 ग्राम जमी मटर मिलाएँ (वे ओवन में गर्म हो जाएँगी)। चखें और मसाला समायोजित करें। 7. एसेंबल करें: ओवन को 200 °C पर प्रीहीट करें। मेमने की भरावन को 23 × 30 सेमी की बेकिंग डिश में स्थानांतरित करें (लगभग 2 लीटर क्षमता)। ऊपर मैश को डॉलप में रखें, फिर किनारों तक सील करते हुए स्पैचुला से सावधानी से फैलाएँ। सतह पर लंबी रेखाओं में काँटे के दाँतों को खींचें — ये कटक ओवन में सुंदर रूप से कुरकुरे हो जाते हैं। यदि उपयोग कर रहे हों तो ऊपर 30 ग्राम कद्दूकस किया चेडर छिड़कें। 8. बेक करें और विश्राम करें: डिश को बेकिंग शीट पर रखें (कोई भी उबलती बूँदें पकड़ता है)। बीच के रैक पर 25–30 मिनट बेक करें जब तक ऊपर गहरा सुनहरा न हो जाए, कटक कुरकुरे न हो जाएँ और ग्रेवी किनारों पर स्पष्ट रूप से बुदबुदाती न हो। परोसने से पहले 10 मिनट विश्राम करें — भरावन जम जाती है और काटना साफ होता है। डिश से सीधे एक हरी सलाद या मक्खन वाली पत्ता गोभी के साथ परोसें। अगले दिन और भी बेहतर, बहुत गर्म होने तक फिर से गर्म किया।.","en":"1. BOIL THE POTATOES: place 1 kg peeled and cubed potatoes in a large pot of cold salted water (1 tbsp salt per 2 L), bring to a boil, then reduce to a steady simmer and cook 15–18 minutes until a knife slides through with no resistance; drain and return to the pot off the heat for 2 minutes to steam off, since wet potatoes make wet mash. 2. MAKE THE MASH: pass the dry potatoes through a ricer (best for fluffy mash) or mash with a hand masher, then beat in 60 g butter while still hot followed by 100 ml warm milk added in 3 stages, beating between each, and off the heat beat in 2 yolks, 0.5 tsp white pepper and 0.5 tsp salt until the mash is glossy, smooth and stiff enough to hold ridges (if it's too loose the topping will sink); cover with foil to keep warm. 3. SWEAT THE VEGETABLES: heat 1 tbsp oil in a large heavy skillet over medium heat, add 200 g diced onion and 200 g diced carrot with a pinch of salt, and cook, stirring often, 8–10 minutes until very soft and the carrots have lost their crunch (they will not soften further once mixed with meat), then stir in 4 minced garlic cloves, thyme and rosemary and cook 1 minute more. 4. BROWN THE LAMB: raise the heat to medium-high, add 600 g minced lamb and break it apart with a wooden spoon, then cook 8–10 minutes until the lamb is no longer pink and the released fat has begun to crisp small bits at the bottom of the pan (this Maillard browning is the foundation of the gravy), and spoon off any pooled fat over 1 tbsp, since lamb sheds a lot and too much makes the pie greasy. 5. BUILD THE GRAVY: stir 1 tbsp tomato paste into the lamb and cook 1 minute until darkened, sprinkle 2 tbsp flour over and stir 1–2 minutes to cook the raw taste out, then pour in 300 ml hot stock, 1 tbsp Worcestershire sauce, 1 tsp salt and 0.5 tsp pepper, scraping the bottom of the pan to lift the browned bits. 6. SIMMER + PEAS: reduce heat to low and simmer uncovered 15 minutes, stirring occasionally, until the gravy has thickened to a thick, glossy consistency that coats the meat (it should not be runny, or the mash will sink), then stir in 150 g frozen peas (they will warm through in the oven) and taste and adjust seasoning. 7. ASSEMBLE: preheat the oven to 200 °C and transfer the lamb filling to a 23 × 30 cm baking dish (about 2 L capacity), spoon the mash on top in dollops and spread carefully with a spatula sealing all the way to the edges, then drag the tines of a fork in long lines across the surface (these ridges crisp up beautifully in the oven) and scatter 30 g grated cheddar over the top if using. 8. BAKE & REST: place the dish on a baking sheet to catch any bubbling drips and bake on the middle rack 25–30 minutes until the top is deeply golden, the ridges are crisp, and the gravy is visibly bubbling around the edges, then rest 10 minutes before serving so the filling sets and slicing is cleaner, and serve straight from the dish with a green salad or buttered cabbage on the side (even better the next day, reheated until piping hot)."}},{"id":169,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"hi":"चीन","en":"China","ro":"China"},"name":{"hi":"माओ टोफू","en":"Mapo Tofu","ro":"Mapo Tofu"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["600 ग्राम नरम (सिल्केन या मध्यम-नरम) टोफू, 2 सेमी क्यूब्स में कटा — बनावट व्यंजन का हिस्सा है, सख्त टोफू का उपयोग न करें","200 ग्राम सूअर का कीमा (~20% वसा — छोटी मात्रा हावी हुए बिना उमामी जोड़ती है)","3 बड़े चम्मच तटस्थ तेल (सरसों या मूँगफली)","3 बड़े चम्मच पिक्सियन दौबानजियांग (सिचुआन चौड़ी सेम-मिर्च पेस्ट) — व्यंजन की आत्मा, छोड़ें या प्रतिस्थापित न करें","1 बड़ा चम्मच दौची (किण्वित काली सेम), धोई और मोटे कटी","2 छोटे चम्मच सिचुआन मिर्च सेम पेस्ट (la doubanjiang) या प्रतिस्थापन के रूप में 1 छोटा चम्मच कोरियाई गोचुजांग","4 लहसुन की कलियाँ, बारीक कटी","4 सेमी ताज़ी अदरक, छीली और कद्दूकस की","6 हरे प्याज़: सफेद भाग पकाने के लिए बारीक कटे + हरे ऊपरी भाग गार्निश के लिए तिरछे कटे (अलग रखें)","1.5 बड़े चम्मच गाढ़ा सोया सॉस (laochou)","1 छोटा चम्मच दानेदार चीनी","300 मिली गर्म बिना नमक का चिकन स्टॉक या पानी","2 छोटे चम्मच सिचुआन काली मिर्च (huajiao), सूखे पैन में 60 सेकंड भूनी और ओखली में कुटी","अंतिम स्लरी के लिए 1.5 बड़े चम्मच कॉर्नस्टार्च (cornflour) को 3 बड़े चम्मच ठंडे पानी के साथ मिलाया","फिनिशिंग के लिए 2 छोटे चम्मच मिर्च तेल (la yu)","अंतिम बूँद के लिए 1 छोटा चम्मच भुना तिल का तेल","परोसने के लिए: 320 ग्राम (1.6 कप सूखा) पका जैस्मीन चावल या छोटे दाने वाला चावल"],"en":["600 g soft (silken or medium-soft) tofu, cut into 2 cm cubes — the texture is part of the dish, do not use firm tofu","200 g ground pork (~20% fat — the small amount adds umami without dominating)","3 tbsp neutral oil (rapeseed or peanut)","3 tbsp Pixian doubanjiang (Sichuan broad-bean chili paste) — the SOUL of the dish, do not skip or substitute","1 tbsp douchi (fermented black beans), rinsed and roughly chopped","2 tsp Sichuan chili bean paste (la doubanjiang) OR 1 tsp Korean gochujang as substitute","4 garlic cloves, finely minced","4 cm fresh ginger, peeled and grated","6 spring onions: the white parts finely chopped for cooking + the green tops cut diagonally for garnish (keep separate)","1.5 tbsp dark soy sauce (laochou)","1 tsp granulated sugar","300 ml hot unsalted chicken stock or water","2 tsp Sichuan peppercorns (huajiao), toasted in a dry pan 60 sec and crushed in a mortar","1.5 tbsp cornstarch (cornflour) mixed with 3 tbsp cold water for the final slurry","2 tsp chili oil (la yu) for finishing","1 tsp toasted sesame oil for the last drizzle","To serve: 320 g (1.6 cups dry) cooked jasmine rice or short-grain rice"],"ro":["600 g tofu moale (mătăsos sau mediu-moale), tăiat în cuburi de 2 cm — textura face parte din preparat, nu folosi tofu ferm","200 g carne tocată de porc (~20% grăsime — cantitatea mică adaugă umami fără a domina)","3 linguri ulei neutru (rapiță sau arahide)","3 linguri doubanjiang Pixian (pastă de fasole-chili din Sichuan) — SUFLETUL preparatului, nu omite și nu substitui","1 lingură douchi (fasole neagră fermentată), clătită și tocată grosier","2 lingurițe pastă de fasole-chili Sichuan (la doubanjiang) SAU 1 linguriță gochujang coreean ca substitut","4 căței de usturoi, tocați fin","4 cm ghimbir proaspăt, curățat și ras","6 cepe verzi: părțile albe tocate fin pentru gătit + vârfurile verzi tăiate oblic pentru ornament (păstrează separat)","1,5 linguri sos de soia închis (laochou)","1 linguriță zahăr granulat","300 ml supă fierbinte de pui nesărată sau apă","2 lingurițe boabe de piper sichuan (huajiao), prăjite într-o tigaie uscată 60 sec și zdrobite în mojar","1,5 linguri amidon de porumb (cornflour) amestecat cu 3 linguri apă rece pentru slurry-ul final","2 lingurițe ulei de chili (la yu) pentru finisare","1 linguriță ulei de susan prăjit pentru ultima stropire","Pentru servire: 320 g (1,6 căni uscat) orez jasmine fiert sau orez cu bob scurt"]},"howIsMade":{"hi":"टोफू तैयार करें: 1 छोटा चम्मच नमक के साथ पानी का एक छोटा बर्तन हल्के सिमर पर लाएँ (उबाल नहीं)। 2 सेमी टोफू क्यूब्स को सावधानी से सरकाएँ और उन्हें 2 मिनट तक गर्म होने दें — यह सतह को सख्त करता है ताकि वे सॉस में अपना आकार बनाए रखें। धीरे से छानें और आँच से दूर गर्म बर्तन में अलग रखें।. सिचुआन काली मिर्च भूनें: मध्यम आँच पर एक सूखे पैन में, 2 छोटे चम्मच सिचुआन काली मिर्च 60 सेकंड तक भूनें जब तक तीव्र सुगंधित न हो जाए। ओखली में डालें और मोटे रूप से कूटें। अलग रखें।. सूअर का मांस पकाएँ: एक वोक या भारी कड़ाही में मध्यम-तेज़ आँच पर 2 बड़े चम्मच तटस्थ तेल गरम करें। 200 ग्राम सूअर का कीमा डालें और एक स्पैचुला से तोड़ें। 4–5 मिनट तक भूनें जब तक सूअर का मांस गुलाबी न रहे और छोटे टुकड़े कुरकुरे और सुनहरे भूरे न हो जाएँ — कुरकुरे सूअर और नरम टोफू के बीच बनावट का अंतर आवश्यक है।. दौबानजियांग को खिलाएँ: सूअर के मांस को पैन के एक तरफ धकेलें और खाली जगह में 1 और बड़ा चम्मच तेल डालें। तेल में 3 बड़े चम्मच दौबानजियांग डालें और 60–90 सेकंड तक चलाएँ जब तक तेल गहरा लाल न हो जाए — यह तेल-तलना पेस्ट के रंग और उमामी को छोड़ता है। सूअर के मांस के साथ मिलाएँ। कटा दौची + कटी लहसुन + कद्दूकस अदरक + 2 छोटे चम्मच la doubanjiang (या गोचुजांग) डालें और 60 सेकंड तक भूनें जब तक तीव्र सुगंधित न हो जाए।. द्रव: 300 मिली गर्म स्टॉक + 1.5 बड़े चम्मच गाढ़ा सोया सॉस + 1 छोटा चम्मच चीनी डालें। सिमर पर लाएँ।. टोफू डालें: गर्म टोफू क्यूब्स को धीरे से सिमरिंग सॉस में सरकाएँ। मत चलाएँ — उन्हें नीचे धकेलने के लिए कलछी के पीछे का उपयोग करें, फिर पैन को धीरे से हिलाएँ ताकि वे बैठ जाएँ। 4–5 मिनट तक सिमर करें, कभी-कभी टोफू के ऊपर सॉस छिड़कें, ताकि क्यूब्स बिना टूटे स्वाद सोखें।. गाढ़ा करें: कॉर्नस्टार्च स्लरी को एक बार और चलाएँ और सॉस में आधा डालें, फिर पैन को हिलाएँ और इसे 30 सेकंड तक सिमर होने दें। सॉस चमकदार हो जाएगी और टोफू को कोट करना शुरू कर देगी। यदि अभी भी पतला है, तो बाकी स्लरी डालें। तैयार सॉस को टोफू से हल्के से चिपकना चाहिए, सूप जैसा नहीं होना चाहिए।. खत्म करें और परोसें: आँच से दूर, सतह पर 2 छोटे चम्मच मिर्च तेल + 1 छोटा चम्मच भुना तिल का तेल डालें और हरे प्याज़ के ऊपरी हिस्से + कुटी सिचुआन काली मिर्च छिड़कें। मत चलाएँ — काली मिर्च के दानों को मा (सुन्न) सनसनी के लिए जीभ पर बिना घुले लगना चाहिए। गर्म जैस्मीन चावल के साथ तुरंत परोसें। हर निवाला: चावल + टोफू + सॉस + काली मिर्च = पूर्ण मा-ला अनुभव।.","en":"PREP THE TOFU: bring a small pot of water with 1 tsp salt to a gentle simmer (not boil); slip the 2 cm tofu cubes in carefully and let them warm 2 minutes — this firms the surface so they hold their shape in the sauce; drain gently and set aside in the warm pot off the heat. TOAST SICHUAN PEPPERCORNS: in a dry pan over medium heat, toast 2 tsp Sichuan peppercorns 60 seconds until intensely fragrant; tip into a mortar and crush coarsely; set aside. RENDER THE PORK: heat 2 tbsp neutral oil in a wok or heavy skillet over medium-high heat; add 200 g ground pork and break it apart with a spatula; stir-fry 4–5 minutes until the pork is no longer pink and the small bits are crispy and golden brown — the texture difference between crisp pork and soft tofu is essential. BLOOM THE DOUBANJIANG: push the pork to the side of the pan and add 1 tbsp more oil to the empty space; add 3 tbsp doubanjiang to the oil and stir 60–90 seconds until the oil turns deep red — this oil-frying releases the colour and umami of the paste; stir into the pork; add chopped douchi + minced garlic + grated ginger + 2 tsp la doubanjiang (or gochujang) and stir-fry 60 seconds until intensely aromatic. LIQUID: pour in 300 ml hot stock + 1.5 tbsp dark soy sauce + 1 tsp sugar; bring to a simmer. ADD THE TOFU: slide the warm tofu cubes gently into the simmering sauce; do NOT stir — use the back of a ladle to push them under, then shake the pan gently to settle; simmer 4–5 minutes, basting the tops of the tofu with sauce occasionally, so the cubes absorb flavour without breaking. THICKEN: stir the cornstarch slurry one more time and pour HALF into the sauce, then shake the pan and let it simmer 30 seconds; the sauce will turn glossy and start to coat the tofu; if still thin, add the rest of the slurry; the finished sauce should cling lightly to the tofu, not be soupy. FINISH AND SERVE: off the heat, drizzle 2 tsp chili oil + 1 tsp toasted sesame oil over the surface and scatter the green spring-onion tops + crushed Sichuan peppercorns; do NOT stir — the peppercorns must hit your tongue undiluted for the ma (numbing) sensation; serve immediately with hot jasmine rice; each bite: rice + tofu + sauce + peppercorn = the full ma-la experience."}},{"id":170,"servings":2,"tipType":"veg","pairingsType":"veg","origin":{"hi":"तुर्की","en":"Turkey","ro":"Turcia"},"name":{"hi":"मेनेमेन","en":"Menemen","ro":"Menemen"},"category":{"hi":"सुबह का नाश्ता","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"hi":["6 बड़े अंडे, कमरे के तापमान पर","3 बड़े चम्मच तुर्की या एक्स्ट्रा वर्जिन जैतून का तेल","2 सिवरी बिबर (लंबी हरी तुर्की मिर्च, हल्की तीखी) या प्रतिस्थापन के रूप में 1 हरी शिमला मिर्च + 1 जलापीनो (~कुल 150 ग्राम), बीज निकालकर बारीक कटी","4 पकी टमाटर (~500 ग्राम), छिले और बॉक्स कद्दूकस पर मोटे कद्दूकस किए (छिलका पीछे रहता है, केवल गूदा कद्दूकस से गुजरता है — यह तुर्की तकनीक है)","1 बड़ा चम्मच टमाटर पेस्ट (salça) — वैकल्पिक, लाल रंग को गहरा करता है","1 छोटा चम्मच पुल बिबर (तुर्की लाल मिर्च के फ्लेक्स, अलेप्पो या मराश शैली) — कठोर तीखेपन के बिना गर्माहट जोड़ता है","0.5 छोटा चम्मच सूखी ओरेगानो","0.5 छोटा चम्मच नमक + ताज़ी पिसी काली मिर्च","30 ग्राम फेटा शैली का बेयाज़ पेनिर, टुकड़े किया (वैकल्पिक, क्षेत्रीय एजियन जोड़)","1 छोटी मुट्ठी चपटे पत्ते का अजमोद, बारीक कटा, अंतिम स्पर्श के लिए","1 छोटा गुच्छा चाइव्स या हरी प्याज़ का हरा भाग, बारीक कटा (वैकल्पिक)","परोसने के लिए: 4 मोटे टुकड़े ताज़ा एकमेक (देहाती रोटी) या 2 सिमित (तुर्की तिल बैगल्स), तेज़ बनी तुर्की काली चाय (çay)","क्षेत्रीय बहस पर नोट: यह संस्करण बिना प्याज़ का है (इस्तांबुल शैली); यदि एजियन-शैली बना रहे हैं, तो 1 छोटी प्याज़ बारीक काटें और मिर्च से 4 मिनट पहले पकाएं"],"en":["6 large eggs, at room temperature","3 tbsp Turkish or extra-virgin olive oil","2 sivri biber (long green Turkish peppers, mildly hot) OR 1 green bell pepper + 1 jalapeño as substitute (~150 g total), seeds removed and finely diced","4 ripe tomatoes (~500 g), peeled and roughly grated on a box grater (the skin holds back, only the pulp grates through — this is the Turkish technique)","1 tbsp tomato paste (salça) — optional, deepens the red","1 tsp pul biber (Turkish red pepper flakes, Aleppo or Maraş-style) — adds warmth without harsh heat","0.5 tsp dried oregano","0.5 tsp salt + freshly ground black pepper","30 g feta-style beyaz peynir, crumbled (optional, regional Aegean addition)","1 small handful flat-leaf parsley, finely chopped, to finish","1 small bunch chives or spring onion green, finely chopped (optional)","To serve: 4 thick slices of fresh ekmek country bread OR 2 simit (Turkish sesame bagels), Turkish black tea (çay) brewed strong","Note on regional debate: this version is WITHOUT onion (Istanbul-style); if making the Aegean-style, add 1 small onion finely diced and cook 4 min before the peppers"],"ro":["6 ouă mari, la temperatura camerei","3 linguri ulei de măsline turcesc sau extravirgin","2 sivri biber (ardei lungi verzi turcești, ușor iuți) SAU 1 ardei gras verde + 1 jalapeño ca substitut (~150 g total), fără semințe și tocați fin","4 roșii coapte (~500 g), opărite și răzuite grosier pe răzătoarea cu găuri mari (coaja rămâne în mână, doar pulpa trece prin răzătoare — aceasta este tehnica turcească)","1 lingură pastă de roșii (salça) — opțional, adâncește roșul","1 linguriță pul biber (fulgi de ardei roșu turcesc, stil Aleppo sau Maraș) — adaugă căldură fără iuțeală agresivă","0,5 linguriță oregano uscat","0,5 linguriță sare + piper negru proaspăt măcinat","30 g beyaz peynir tip feta, fărâmițat (opțional, adaos regional egeean)","1 mână mică de pătrunjel cu frunza lată, tocat fin, pentru finisare","1 legătură mică de arpagic sau partea verde a cepei verzi, tocată fin (opțional)","Pentru servire: 4 felii groase de ekmek proaspăt (pâine de țară) SAU 2 simit (covrigi turcești cu susan), ceai negru turcesc (çay) preparat tare","Notă despre dezbaterea regională: această versiune este FĂRĂ ceapă (stil Istanbul); dacă faci versiunea egeeană, adaugă 1 ceapă mică tocată fin și gătește 4 minute înainte de ardei"]},"howIsMade":{"hi":"टमाटर छीलें और कद्दूकस करें: 4 पकी टमाटरों में से प्रत्येक के तले में एक उथला क्रॉस काटें। उबलते पानी में 30 सेकंड के लिए डालें, फिर बर्फ के पानी में स्थानांतरित करें। छिलके आसानी से उतर जाते हैं। प्रत्येक टमाटर को क्षैतिज रूप से आधा करें और कटोरे के ऊपर रखे बॉक्स कद्दूकस की मोटी ओर के विरुद्ध कटी हुई पक्षों को रगड़ें — गूदा कद्दूकस से गुजरता है और खाली छिलका आपके हाथ में रहता है। यह तुर्की तकनीक छिलके के टुकड़ों के बिना एक गूदेदार, रसदार टमाटर का आधार देती है।. मिर्च पकाएँ: 24 सेमी की भारी कड़ाही में (कास्ट आयरन या मिट्टी का सहन पारंपरिक है) मध्यम आँच पर 3 बड़े चम्मच जैतून का तेल गर्म करें। 150 ग्राम बारीक कटी हरी मिर्च डालें और बार-बार चलाते हुए 5–6 मिनट तक पकाएँ जब तक नरम हो जाएँ और किनारों पर थोड़ी छाले पड़ जाएँ लेकिन फिर भी चमकदार हरी रहें — उन्हें भूरा न होने दें।. टमाटर पेस्ट डालें: 1 बड़ा चम्मच टमाटर पेस्ट मिर्च में मिलाएँ और 30 सेकंड पकाएँ — सालका रंग और उमामी को गहरा करती है। (यदि पेस्ट का उपयोग नहीं कर रहे हैं तो इस चरण को छोड़ दें।). कद्दूकस किए टमाटर डालें: कद्दूकस किया हुआ टमाटर गूदा + 1 छोटा चम्मच पुल बिबर + 0.5 छोटा चम्मच ओरेगानो + 0.5 छोटा चम्मच नमक और काली मिर्च का एक उदार मोड़ डालें। हल्के सिमर पर लाएँ और 6–8 मिनट पकाएँ, कभी-कभी चलाएँ, जब तक टमाटर आधा कम न हो जाए और जैम जैसा न दिखे — स्पैचुला के नीचे को सॉस के माध्यम से एक स्पष्ट रेखा खींचनी चाहिए जो तुरंत न भरे।. अंडे तैयार करें: जब टमाटर पकते हैं, 6 अंडों को एक बार में एक करके एक कटोरे में फोड़ें — उन्हें मत फेंटें। अंडे पैन में पूरे या मुश्किल से टूटे हुए जाते हैं, जर्दी शुरू में बरकरार रहती है।. अंडे डालें: जब टमाटर जैम जैसा हो, आँच को मध्यम-धीमी कर दें। अंडों को धीरे से पैन में सरकाएँ, सतह के चारों ओर अंतराल रखते हुए। उन्हें 30 सेकंड बिना छेड़े रहने दें ताकि वे तले में जम जाएँ।. हल्के से फेंटें: एक लकड़ी के चम्मच से, धीमी आठ-आकार की गति में टमाटर के माध्यम से अंडों को धीरे से धकेलें — जोरदार ढंग से मत हिलाएँ। सफेद हिस्से रिबन में जमने चाहिए और जर्दी टूटनी चाहिए और सुनहरी भँवरों में सॉस के माध्यम से धारियाँ बनानी चाहिए। केवल 90 सेकंड–2 मिनट पकाएँ — मेनेमेन को चमकदार और मुश्किल से जमा रहना चाहिए, स्क्रैम्बल्ड एग की तरह सूखा नहीं। थोड़ा गीला रहते समय आँच से उतार लें — यह गर्म पैन में पकता रहता है।. पैन से परोसें: 30 ग्राम कुटा फेटा + कटा अजमोद (और यदि उपयोग कर रहे हैं तो चाइव्स) छिड़कें। पैन सीधे मेज पर लाएँ — मेनेमेन हमेशा पैन से खाया जाता है, रोटी फाड़कर सॉस में डुबोई जाती है। तेज़ तुर्की काली चाय के साथ परोसें। पकाने के 5 मिनट के भीतर, जब तक गर्म और चमकदार हो, खाना सबसे अच्छा है।.","en":"PEEL AND GRATE THE TOMATOES: cut a shallow cross in the bottom of each of 4 ripe tomatoes; drop into boiling water 30 seconds, then transfer to ice water; the skins peel off easily; halve each tomato horizontally and rub the cut sides against the coarse side of a box grater placed over a bowl — the flesh grates through and the empty skin remains in your hand; this Turkish technique gives a pulpy, juicy tomato base with no skin pieces. COOK THE PEPPERS: heat 3 tbsp olive oil in a heavy 24 cm skillet (cast iron or earthenware sahan is traditional) over medium heat; add 150 g finely diced green peppers and cook stirring often 5–6 minutes until softened and slightly blistered at the edges but still bright green — do not let them brown. ADD TOMATO PASTE: stir 1 tbsp tomato paste into the peppers and cook 30 seconds — the salça deepens the colour and umami; (Skip this step if not using paste.). ADD GRATED TOMATOES: pour in the grated tomato pulp + 1 tsp pul biber + 0.5 tsp oregano + 0.5 tsp salt and a generous twist of black pepper; bring to a simmer and cook 6–8 minutes, stirring occasionally, until the tomato has reduced by half and looks jammy — the bottom of the spatula should drag a clear line through the sauce that does not fill in immediately. PREP THE EGGS: while the tomatoes cook, crack 6 eggs into a bowl one at a time — DO NOT beat them; the eggs go into the pan whole or barely broken, with yolks intact at first. ADD THE EGGS: when the tomato is jammy, lower the heat to medium-low; slip the eggs gently into the pan, spaced around the surface; let them sit 30 seconds undisturbed to set on the bottom. SCRAMBLE LIGHTLY: with a wooden spoon, push the eggs gently through the tomato in slow figure-eight motions — DO NOT vigorously stir; the whites should set into ribbons and the yolks should break and streak through the sauce in golden swirls; cook 90 seconds–2 minutes only — the menemen should remain glossy and barely-set, NOT scrambled-egg-dry; take off the heat while still slightly wet — it continues cooking in the hot pan. SERVE FROM THE PAN: scatter 30 g crumbled feta + chopped parsley (and chives if using); bring the pan straight to the table — menemen is always eaten from the pan with bread torn and dipped into the sauce; serve with strong Turkish black tea; best eaten within 5 minutes of cooking, while warm and glossy."}},{"id":171,"servings":4,"tipType":"meat","pairingsType":"soup","origin":{"hi":"रूस","en":"Russia","ro":"Rusia"},"name":{"hi":"सोल्यंका","en":"Solyanka","ro":"Solyanka"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"ingredients":{"hi":["500 ग्राम बीफ ब्रिसकेट या हड्डी सहित पिंडली (शोरबे के लिए)","शोरबे के लिए 2 लीटर ठंडा पानी + 1 प्याज़ + 1 गाजर + 2 तेज पत्ते + 5 काली मिर्च के दाने + 1 छोटा चम्मच नमक स्टॉक के लिए","200 ग्राम स्मोक्ड किलबासा या क्राकोवस्काया, 5 मिमी मोटी स्लाइस में कटी","150 ग्राम पकाया हुआ हैम, 1 सेमी क्यूब्स में कटा (या उबली जीभ, पारंपरिक)","100 ग्राम सलामी या हंटिंग सॉसेज, पतली स्लाइस में कटा","2 बड़े अचारी खीरे (~250 ग्राम, अर्ध-खट्टे या पूरी तरह खट्टे), पतली तीली के आकार में कटे; अचार के पानी का 100 मिली अलग रखें","1 बड़ा प्याज़ (~200 ग्राम), बारीक कटा","1 बड़ा चम्मच टमाटर पेस्ट","200 ग्राम कद्दूकस किया टमाटर (या 1 × 200 ग्राम डिब्बाबंद, पानी निथरा)","सोफ्रिटो के लिए 2 बड़े चम्मच मक्खन या 30 ग्राम पिघली बीफ चर्बी","बीज रहित काले जैतून 80 ग्राम (कलामाता शैली) + बीज रहित हरे जैतून 80 ग्राम","2 बड़े चम्मच केपर, पानी निथरा","1 नींबू, पतले अर्ध-चंद्राकार स्लाइस में कटा","1 तेज पत्ता + 0.5 छोटा चम्मच पिसी काली मिर्च + 1 छोटा चम्मच पपरिका (वैकल्पिक, रंग के लिए)","ताज़ा सोआ का एक छोटा गुच्छा, बारीक कटा","परोसने के लिए 200 ग्राम स्मेताना (खट्टी क्रीम)","परोसने के लिए: 4 मोटी स्लाइस ताज़ा काली राई की रोटी, वैकल्पिक 1 बड़ा चम्मच सहिजन (khren)"],"en":["500 g beef brisket or shin on the bone (for the broth)","2 L cold water for the broth + 1 onion + 1 carrot + 2 bay leaves + 5 black peppercorns + 1 tsp salt for the stock","200 g smoked kielbasa or krakovskaya, sliced 5 mm thick","150 g cooked ham, cut into 1 cm cubes (or boiled tongue, traditional)","100 g salami or hunting sausage, sliced thin","2 large pickled cucumbers (~250 g, half-sour or fully sour), cut into thin matchsticks; reserve 100 ml of the pickle brine","1 large onion (~200 g), finely diced","1 tbsp tomato paste","200 g grated tomatoes (or 1 × 200 g canned, drained)","2 tbsp butter or 30 g rendered beef fat for the soffritto","80 g pitted black olives (kalamata-style) + 80 g pitted green olives","2 tbsp capers, drained","1 lemon, sliced into thin half-moons","1 bay leaf + 0.5 tsp ground black pepper + 1 tsp paprika (optional, for color)","A small bunch fresh dill, finely chopped","200 g smetana (sour cream) for serving","To serve: 4 thick slices of fresh dark rye bread, optional 1 tbsp horseradish (khren)"],"ro":["500 g piept de vită sau rasol cu os (pentru supă)","2 L apă rece pentru supă + 1 ceapă + 1 morcov + 2 foi de dafin + 5 boabe de piper negru + 1 linguriță sare pentru bulion","200 g kielbasa afumată sau cracovskaya, tăiată felii de 5 mm","150 g șuncă fiartă, tăiată cuburi de 1 cm (sau limbă fiartă, tradițional)","100 g salam sau cârnați de vânătoare, tăiat felii subțiri","2 castraveți murați mari (~250 g, semi-acri sau acri complet), tăiați fâșii subțiri; păstrează 100 ml din zeama de murături","1 ceapă mare (~200 g), tocată fin","1 lingură pastă de roșii","200 g roșii răzuite (sau 1 × 200 g din conservă, scurse)","2 linguri unt sau 30 g grăsime de vită topită pentru sotă","80 g măsline negre fără sâmburi (gen kalamata) + 80 g măsline verzi fără sâmburi","2 linguri capere, scurse","1 lămâie, tăiată felii subțiri în formă de semilună","1 foaie de dafin + 0,5 linguriță piper negru măcinat + 1 linguriță boia (opțional, pentru culoare)","O legăturică mică de mărar proaspăt, tocat fin","200 g smetana (smântână) pentru servire","Pentru servire: 4 felii groase de pâine de secară neagră proaspătă, opțional 1 lingură hrean (khren)"]},"howIsMade":{"hi":"शोरबा: 500 ग्राम बीफ ब्रिसकेट को 2 लीटर ठंडे पानी के साथ एक बड़े बर्तन में रखें। उबाल लाएँ और पहले 5 मिनट तक झाग को अच्छी तरह से उतारें — इससे साफ शोरबा मिलता है। 1 पूरी चार टुकड़ों में काटी प्याज़ + 1 पूरी गाजर + 2 तेज पत्ते + 5 काली मिर्च के दाने + 1 छोटा चम्मच नमक डालें। हल्के सिमर पर लाएँ और 1.5 घंटे ढककर पकाएँ जब तक मांस पूरी तरह से नरम न हो जाए।. छानें और रेशेदार करें: बीफ को उठाएँ और थोड़ा ठंडा होने दें। शोरबे को महीन छलनी से एक साफ बर्तन में छानें — आपके पास लगभग 1.5 लीटर साफ, स्वादिष्ट शोरबा होना चाहिए। बीफ को रेशे के विपरीत एक काटे के आकार के टुकड़ों में काटें, किसी भी कठोर कंडरा को हटा दें।. सोफ्रिटो: एक चौड़ी कड़ाही में मध्यम आँच पर 2 बड़े चम्मच मक्खन पिघलाएँ। 200 ग्राम बारीक कटी प्याज़ डालें और 6–8 मिनट तक भूनें जब तक नरम और पारदर्शी न हो जाए। 1 बड़ा चम्मच टमाटर पेस्ट मिलाएँ और 1 मिनट पकाएँ जब तक रंग गहरा न हो जाए। 200 ग्राम कद्दूकस किया टमाटर डालें और 4–5 मिनट पकाएँ जब तक मिश्रण कम न हो जाए और तेल सतह पर दिखाई देने न लगे।. अचार डालें: खीरे की तीलियों को सोफ्रिटो में मिलाएँ और 3–4 मिनट पकाएँ। अचार गर्म होने चाहिए, ज्यादा नरम नहीं — बनावट के विपरीत के लिए उन्हें थोड़ी कुरकुरी रहनी चाहिए।. सॉसेज तलें: एक अलग सूखी कड़ाही में मध्यम आँच पर, स्मोक्ड किलबासा स्लाइस, हैम क्यूब्स और सलामी स्लाइस को 4–5 मिनट तक तलें जब तक किनारे थोड़े भूरे न हो जाएँ और चर्बी निकल न आए। यह कदम गैर-परक्राम्य है — शोरबे में डालने से पहले मांस को सीयर करना ही सोल्यांका को उसका गहरा, धुएँदार चरित्र देता है।. सूप जोड़ें: सोफ्रिटो को छाने हुए शोरबे में डालें और सीयर्ड सॉसेज, हैम, सलामी और रेशेदार बीफ को मिलाएँ। आरक्षित 100 मिली अचार का पानी + 1 तेज पत्ता + 0.5 छोटा चम्मच पिसी काली मिर्च + 1 छोटा चम्मच पपरिका डालें। हल्के सिमर पर लाएँ।. सिमर: कम आँच पर 15–20 मिनट, आंशिक रूप से ढककर पकाएँ, ताकि स्वाद मिल जाएँ। जैतून + केपर केवल अंतिम 5 मिनटों में डालें — उन्हें गर्म होना चाहिए लेकिन अपना आकार बनाए रखना चाहिए। चखें और नमक को समायोजित करें — अधिकांश नमकीनपन अचार, केपर, जैतून और नमकीन पानी से आता है, इसलिए सावधानी से आगे बढ़ें।. परोसें: गर्म सोल्यांका को गहरे कटोरों में डालें। प्रत्येक कटोरे में 1 पतला नींबू का स्लाइस (छिलके सहित पूरा), स्मेताना का एक उदार चम्मच और कटा हुआ सोआ छिड़कें। स्वादानुसार काली मिर्च। तुरंत ताज़ा गहरी राई की रोटी के मोटे टुकड़ों के साथ परोसें — सोल्यांका एक मुख्य पाठ्यक्रम है, शुरुआती सूप नहीं। रूसी परंपरा में, यह उत्सव के बाद का क्लासिक पुनर्स्थापक है।.","en":"THE BROTH: place 500 g beef brisket in a large pot with 2 L cold water; bring to a boil and skim the foam thoroughly for the first 5 minutes — this gives a clear broth; add 1 whole quartered onion + 1 whole carrot + 2 bay leaves + 5 peppercorns + 1 tsp salt; reduce to a gentle simmer and cook covered 1.5 hours until the meat is fully tender. STRAIN AND SHRED: lift the beef out and let it cool slightly; strain the broth through a fine sieve back into a clean pot — you should have about 1.5 L of clear, savoury broth; cut the beef across the grain into bite-sized strips, discarding any tough sinew. SOFFRITTO: in a wide skillet, melt 2 tbsp butter over medium heat; add 200 g finely diced onion and sauté 6–8 minutes until soft and translucent; stir in 1 tbsp tomato paste and cook 1 minute until darkened; add the 200 g grated tomatoes and cook 4–5 minutes until the mixture has reduced and the oil starts to appear on the surface. ADD PICKLES: stir the cucumber matchsticks into the soffritto and cook 3–4 minutes; the pickles should be warmed through, not over-softened — they need to keep some crunch for texture contrast. FRY THE SAUSAGES: in a separate dry pan over medium heat, fry the smoked kielbasa slices, ham cubes, and salami slices 4–5 minutes until lightly browned at the edges and the fat has rendered; this step is non-negotiable — searing the meats before adding them to the broth is what gives solyanka its deep, smoky character. ASSEMBLE THE SOUP: pour the soffritto into the strained broth and stir in the seared sausages, ham, salami, and shredded beef; add the reserved 100 ml pickle brine + 1 bay leaf + 0.5 tsp ground pepper + 1 tsp paprika; bring to a gentle simmer. SIMMER: cook over low heat 15–20 minutes, partially covered, for the flavours to marry; add the olives + capers in the last 5 minutes only — they should warm through but keep their shape; taste and adjust salt — most of the saltiness comes from the pickles, capers, olives, and brine, so go cautiously. SERVE: ladle the hot solyanka into deep bowls; to each bowl add 1 thin lemon slice (whole, peel on), a generous spoonful of smetana, and a scatter of chopped dill; black pepper to taste; serve immediately with thick slices of fresh dark rye bread on the side — solyanka is a main course, not a starter; in Russian tradition, this is the classic post-celebration restorative."}},{"id":172,"servings":4,"tipType":"fish","pairingsType":"fish","origin":{"hi":"अमेरिका","en":"USA","ro":"SUA"},"name":{"hi":"क्लैम चाउडर","en":"Clam Chowder","ro":"Clam Chowder"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["1.5 किलो ताज़ी littleneck या quahog सीप अपने खोल में (या समुद्र से दूर रसोइयों के लिए विकल्प के रूप में रस में 2 × 200 ग्राम साबुत छोटी सीप के डिब्बे)","500 मिली ताज़ा सीप का रस या मछली स्टॉक (यदि ताज़ी सीप का उपयोग कर रहे हैं तो भाप का सारा तरल बचाकर रखें)","150 ग्राम मोटी कटी स्मोक्ड बेकन, 0.5 सेमी क्यूब्स में कटी","1 बड़ा पीला प्याज़ (~250 ग्राम), बारीक कटा","2 मध्यम अजवाइन के डंठल (~120 ग्राम), बारीक कटे","4 लहसुन की कलियाँ, बारीक कटी (वैकल्पिक — बोस्टन के पारंपरिक लोग नापसंद करते हैं लेकिन अधिकांश आधुनिक रेसिपी में शामिल होती हैं)","30 ग्राम बिना नमक का मक्खन","30 ग्राम मैदा (रू के लिए)","750 ग्राम मैली आलू (Yukon Gold या russet), छिले और 1.5 सेमी क्यूब्स में कटे","250 मिली पूर्ण वसा वाला दूध","250 मिली भारी क्रीम (या हल्के संस्करण के लिए आधा-आधा)","2 तेज पत्ते + 1 छोटा चम्मच सूखा थाइम + 0.5 छोटा चम्मच ताज़ा पिसी काली मिर्च","0.5 छोटा चम्मच नमक (पहले चखें — सीप का रस नमकीन होता है)","एक चुटकी कायेन या 1 बूंद तीखा सॉस (वैकल्पिक)","ताज़ी चाइव्स का एक छोटा गुच्छा, बारीक कटा, और सजावट के लिए 2 बड़े चम्मच ताज़ा सपाट पत्ता अजमोद","परोसने के लिए: खाने योग्य ब्रेड कटोरे के रूप में खोखले 4 छोटे साउरडो रोल्स या ऑयस्टर क्रैकर्स (एक पारंपरिक न्यू इंग्लैंड साइड); 1 नींबू, टुकड़ों में कटा"],"en":["1.5 kg fresh littleneck or quahog clams in shells (or 2 × 200 g cans whole baby clams in juice as substitute for landlocked cooks)","500 ml fresh clam juice or fish stock (reserve all the steaming liquid if using fresh clams)","150 g thick-cut smoked bacon, diced 0.5 cm","1 large yellow onion (~250 g), finely diced","2 medium celery stalks (~120 g), finely diced","4 garlic cloves, minced (optional — Boston purists frown but most modern recipes include)","30 g unsalted butter","30 g all-purpose flour (for the roux)","750 g floury potatoes (Yukon Gold or russet), peeled and cut into 1.5 cm cubes","250 ml whole milk","250 ml heavy cream (or half-and-half for a lighter version)","2 bay leaves + 1 tsp dried thyme + 0.5 tsp freshly ground black pepper","0.5 tsp salt (taste first — clam juice is salty)","A pinch of cayenne or 1 dash hot sauce (optional)","1 small bunch fresh chives, finely chopped, and 2 tbsp fresh flat-leaf parsley to garnish","To serve: 4 small hollowed-out sourdough rolls as edible bread bowls OR oyster crackers (a traditional New England side); 1 lemon, sliced into wedges"],"ro":["1,5 kg scoici proaspete (littleneck sau quahog) în cochilii (sau 2 × 200 g conserve de scoici mici întregi în suc, ca substitut pentru cei departe de mare)","500 ml suc de scoici proaspăt sau fond de pește (rezervă tot lichidul de aburire dacă folosești scoici proaspete)","150 g bacon afumat tăiat gros, cuburi de 0,5 cm","1 ceapă galbenă mare (~250 g), tăiată mărunt","2 tulpini medii de țelină (~120 g), tăiate mărunt","4 căței de usturoi, tocați (opțional — puriștii din Boston dezaprobă, dar majoritatea rețetelor moderne îi includ)","30 g unt nesărat","30 g făină universală (pentru roux)","750 g cartofi făinoși (Yukon Gold sau russet), curățați și tăiați cuburi de 1,5 cm","250 ml lapte integral","250 ml smântână grasă (sau jumătate-jumătate pentru o versiune mai ușoară)","2 foi de dafin + 1 linguriță cimbru uscat + 0,5 linguriță piper negru proaspăt măcinat","0,5 linguriță sare (gustă întâi — sucul de scoici este sărat)","Un vârf de cayenne sau 1 strop de sos iute (opțional)","O legăturică mică de arpagic proaspăt, tocat fin, și 2 linguri de pătrunjel proaspăt cu frunze plate pentru garnitură","Pentru servire: 4 chifle mici de sourdough scobite ca boluri comestibile SAU biscuiți pentru stridii (un acompaniament tradițional al Noii Anglii); 1 lămâie, tăiată felii pentru garnitură"]},"howIsMade":{"hi":"1.5 किलो ताज़ी सीप को ठंडे पानी में 2–3 बार धोएं ताकि रेत निकल जाए; जो खुली हों और थपथपाने पर बंद न हों, उन्हें फेंक दें; उन्हें एक चौड़े बर्तन में 250 मिली पानी के साथ रखें, ढककर तेज आँच पर 4–5 मिनट तक भाप दें जब तक खोल बस खुलें; जो बंद रहीं उन्हें फेंक दें. सीप उठाएँ, भाप का तरल पीछे छोड़ दें; उस तरल को नम चीज़क्लॉथ से ढकी महीन छलनी से एक मापने वाले कप में छानें — आपके पास लगभग 400–500 मिली साफ सीप शोरबा होना चाहिए; खोल से सीप का मांस निकालें, मोटा-मोटा काटें और एक तरफ रखें; (यदि डिब्बाबंद सीप का उपयोग कर रहे हैं, तो रस को बचाते हुए छान लें और 500 मिली मछली स्टॉक + डिब्बे का रस का उपयोग करें. ). मध्यम आँच पर भारी 5 लीटर के बर्तन या डच ओवन में 150 ग्राम कटी बेकन डालें; बार-बार चलाते हुए 6–8 मिनट तक पकाएँ जब तक बेकन गहरा भूरा न हो जाए और अधिकांश चर्बी पिघल न जाए; कुरकुरी बेकन को छेद वाली चम्मच से कागज तौलिये पर निकालें और सजावट के लिए अलग रखें; बर्तन में 3 बड़े चम्मच बेकन की चर्बी छोड़ दें. 250 ग्राम कटी प्याज़ + 120 ग्राम कटी अजवाइन को बेकन की चर्बी में एक चुटकी नमक के साथ डालें; बार-बार चलाते हुए 8–10 मिनट तक पकाएँ जब तक नरम और पारदर्शी न हो जाएँ लेकिन भूरे न हों — चाउडर सफेद होता है, यहाँ रंग नहीं चाहिए; 4 बारीक कटी लहसुन की कलियाँ डालें और 1 मिनट और पकाएँ; 30 ग्राम मक्खन डालें और पिघलने दें. सब्जियों पर 30 ग्राम मैदा छिड़कें और लकड़ी की चम्मच से 2 मिनट तक लगातार चलाएँ, कच्ची मैदा का स्वाद पकाते हुए बिना उसे गहरा होने दिए — यह सफेद रू है; छने हुए सीप शोरबे को धीमी स्थिर धारा में डालें, गांठ बनने से रोकने के लिए लगातार फेंटते रहें; 750 ग्राम आलू के क्यूब्स + 2 तेज पत्ते + 1 छोटा चम्मच थाइम + 0.5 छोटा चम्मच काली मिर्च डालें; हल्के सिमर पर लाएँ. बिना ढके 15–18 मिनट तक पकाएँ, कभी-कभी चलाते हुए, जब तक आलू नरम न हो जाएँ लेकिन अपना आकार बनाए रखें — चाकू से एक छेदें और बिना प्रतिरोध के अंदर सरकना चाहिए; आँच को सबसे कम पर कर दें; 250 मिली पूर्ण वसा वाला दूध और 250 मिली भारी क्रीम मिलाएँ — डेयरी डालने के बाद उबलने न दें, या क्रीम फट जाएगी; 3 मिनट तक गरम करें. कटी सीप का मांस और अधिकांश बेकन मिलाएँ (सजावट के लिए 2 बड़े चम्मच बेकन और सभी चाइव्स बचाएँ); 3 मिनट और सिमर करें जब तक सीप बस गर्म न हो जाएँ — अधिक पकाने से वे कठोर और रबरी हो जाती हैं; तेज पत्ते निकालें; चखें और स्वाद को नमक और चाहें तो एक चुटकी कायेन से समायोजित करें. 4 छोटे साउरडो रोल्स को खोखला करें (या परंपरागत सरल विकल्प के रूप में ऑयस्टर क्रैकर्स का उपयोग करें); गर्म चाउडर को ब्रेड के कटोरों या गहरे सूप के प्लेटों में डालें; प्रत्येक को आरक्षित कुरकुरी बेकन, चाइव्स और अजमोद की उदार छिड़काव, और काली मिर्च के ताज़ा घुमाव से ढकें; तुरंत साथ में नींबू के टुकड़ों के साथ परोसें; एक न्यू इंग्लैंड रेस्तरां आमतौर पर मेज पर ऑयस्टर क्रैकर्स का एक छोटा डिश और तीखे सॉस का एक साइड लाता है.","en":"Rinse 1.5 kg fresh clams in cold water 2-3 times to remove sand and discard any that are open and do not close when tapped, then place them in a wide pot with 250 ml water, cover and steam over high heat for 4-5 minutes until the shells just open, discarding any that stayed shut. Lift the clams out and strain the steaming liquid through a fine sieve lined with damp cheesecloth into a measuring cup, aiming for ~400-500 ml of clean clam broth, then pick the clam meat from the shells, roughly chop it, and set aside (if using canned clams, drain them reserving the juice and use the 500 ml fish stock plus the canned juice). In a heavy 5 L pot or Dutch oven over medium heat, add 150 g diced bacon and cook stirring often for 6-8 minutes until the bacon is deeply browned and most of the fat has rendered, then lift the crispy bacon onto a paper towel and set aside for garnish, leaving 3 tbsp of bacon fat in the pot. Add 250 g diced onion and 120 g diced celery to the bacon fat with a pinch of salt and cook stirring often for 8-10 minutes until soft and translucent but not browned (chowder is white, so you do not want colour here), then add 4 minced garlic cloves and cook 1 minute more. Add 30 g butter and let it melt, then sprinkle 30 g flour over the vegetables and stir constantly with a wooden spoon for 2 minutes, cooking out the raw flour taste without letting it darken to keep a white roux. Pour in the strained clam broth in a slow steady stream while whisking constantly to prevent lumps, add 750 g potato cubes, 2 bay leaves, 1 tsp thyme, and 0.5 tsp black pepper, bring to a gentle simmer, then cook uncovered for 15-18 minutes stirring occasionally until the potatoes are tender but still hold their shape and a knife slides in with no resistance. Lower the heat to its lowest setting and stir in 250 ml whole milk and 250 ml heavy cream, taking care not to let it boil after adding dairy or the cream will curdle, then warm through for 3 minutes before stirring in the chopped clam meat and most of the bacon (saving 2 tbsp of bacon and all the chives for garnish), and simmer 3 more minutes until the clams are just heated through (overcooking turns them tough and rubbery), then remove the bay leaves and taste, adjusting seasoning with salt and a pinch of cayenne if you like. Hollow out 4 small sourdough rolls (or use oyster crackers as a traditional simpler option), ladle the hot chowder into the bread bowls or deep soup plates, top each with the reserved crispy bacon, a generous scatter of chives and parsley, and a fresh twist of black pepper, and serve immediately with lemon wedges on the side, just as a New England restaurant typically brings a small dish of oyster crackers and a side of hot sauce to the table."}},{"id":173,"servings":2,"tipType":"meat","pairingsType":"meat","origin":{"hi":"जर्मनी","en":"Germany","ro":"Germania"},"name":{"hi":"करीवुर्स्ट","en":"Currywurst","ro":"Currywurst"},"category":{"hi":"नाश्ता","en":"Snack","ro":"Gustare"},"ingredients":{"hi":["4 बर्लिन शैली के सूअर के मांस के Bratwurst सॉसेज (~120 ग्राम प्रत्येक, कुल ~480 ग्राम) — ताज़े, पहले से ग्रिल नहीं किए गए; या Bratwurst उपलब्ध न हो तो बारीक Bockwurst या Frankfurter से प्रतिस्थापित करें","सॉसेज तलने के लिए 2 बड़े चम्मच तटस्थ तेल (सूरजमुखी)","करी सॉस के लिए: 200 ग्राम अच्छी गुणवत्ता का टमाटर केचप (Heinz या जर्मन Hela)","100 मिली पासाटा या विकल्प के रूप में 1 बड़ा चम्मच टमाटर पेस्ट + 80 मिली पानी","2 बड़े चम्मच मध्यम-तीखा करी पाउडर (एक पीला Madras-शैली मिश्रण) — Herta Heuwer का मूल एक समान ब्रिटिश औपनिवेशिक करी पाउडर का उपयोग करता था","1 छोटा चम्मच मीठी हंगेरियन पपरिका","0.5 छोटा चम्मच स्मोक्ड पपरिका (वैकल्पिक, गहराई जोड़ता है)","1 बड़ा चम्मच Worcestershire सॉस (Heuwer के मूल का रहस्य — समझौता योग्य नहीं)","1 बड़ा चम्मच सेब साइडर सिरका या सफेद वाइन सिरका","1 बड़ा चम्मच सफेद चीनी (सिरके को संतुलित करने और टमाटर को उभारने में मदद करता है)","0.5 छोटा चम्मच पिसा हुआ ऑलस्पाइस + 0.5 छोटा चम्मच पिसा हुआ अदरक (Heuwer द्वारा जोड़ा गया 'गुप्त' गर्म मसाला मिश्रण)","0.5 छोटा चम्मच नमक + एक चुटकी कायेन या तीखा मिर्च पाउडर","परोसने के लिए: ऊपर छिड़कने के लिए अतिरिक्त करी पाउडर + Pommes Frites की 2 सर्विंग (ओवन या फ्रायर से लगभग 400 ग्राम गर्म कुरकुरे फ्राइज़), या 2 छोटे Brötchen रोल्स; प्रामाणिक बर्लिन अनुभव के लिए 2 छोटे लकड़ी के कांटे (Pommespieker)"],"en":["4 Berliner-style Bratwurst pork sausages (~120 g each, total ~480 g) — fresh, not pre-grilled; or substitute fine Bockwurst or Frankfurter if Bratwurst unavailable","2 tbsp neutral oil (sunflower) for frying the sausages","For the curry sauce: 200 g good-quality tomato ketchup (Heinz or German Hela)","100 ml passata or 1 tbsp tomato paste + 80 ml water as substitute","2 tbsp medium-hot curry powder (a yellow Madras-style blend) — Herta Heuwer's original used a similar British colonial curry powder","1 tsp sweet Hungarian paprika","0.5 tsp smoked paprika (optional, adds depth)","1 tbsp Worcestershire sauce (the secret of Heuwer's original — not negotiable)","1 tbsp apple cider vinegar OR white wine vinegar","1 tbsp white sugar (helps balance the vinegar and brings out the tomato)","0.5 tsp ground allspice + 0.5 tsp ground ginger (the 'secret' warm-spice mix Heuwer added)","0.5 tsp salt + a pinch of cayenne or hot chili powder","To serve: extra curry powder for dusting on top + 2 portions of Pommes Frites (about 400 g hot crispy fries from the oven or fryer), or 2 small Brötchen rolls; 2 small wooden forks (Pommespieker) for the authentic Berlin experience"],"ro":["4 cârnați Bratwurst de Berlin din porc (~120 g fiecare, total ~480 g) — proaspeți, nu pre-grătar; sau substituție cu Bockwurst fin sau Frankfurter dacă Bratwurst nu este disponibil","2 linguri ulei neutru (floarea-soarelui) pentru prăjirea cârnaților","Pentru sosul de curry: 200 g ketchup de tomate de bună calitate (Heinz sau german Hela)","100 ml passata sau 1 lingură pastă de tomate + 80 ml apă ca substitut","2 linguri pudră de curry medie-iute (un amestec galben stil Madras) — originalul Herta Heuwer folosea o pudră de curry similară colonială britanică","1 linguriță paprika dulce maghiară","0,5 linguriță paprika afumată (opțional, adaugă profunzime)","1 lingură sos Worcestershire (secretul originalului Heuwer — nu este negociabil)","1 lingură oțet de cidru de mere SAU oțet de vin alb","1 lingură zahăr alb (ajută la echilibrarea oțetului și scoate în evidență tomatele)","0,5 linguriță piment ienibahar + 0,5 linguriță ghimbir măcinat (amestecul 'secret' de mirodenii calde pe care Heuwer le-a adăugat)","0,5 linguriță sare + un vârf de cayenne sau chili iute","Pentru servire: pudră de curry suplimentară pentru presărare deasupra + 2 porții de Pommes Frites (aproximativ 400 g cartofi prăjiți fierbinți și crocanți din cuptor sau friteuză), sau 2 Brötchen mici; 2 furculițe mici de lemn (Pommespieker) pentru experiența autentică berlineză"]},"howIsMade":{"hi":"सॉसेज में छेद करें: पकाने से 15 मिनट पहले 4 Bratwurst को फ्रिज से निकाल लें ताकि वे कमरे के तापमान के करीब आ जाएँ। प्रत्येक सॉसेज को कांटे से 4–5 बार छेदें — यह त्वचा को पैन में फटने से रोकता है और कुछ चर्बी को बाहर निकलने देता है।. करी सॉस बनाएँ: एक छोटे सॉसपैन में, 200 ग्राम केचप + 100 मिली पासाटा + 2 बड़े चम्मच करी पाउडर + 1 छोटा चम्मच मीठी पपरिका + 0.5 छोटा चम्मच स्मोक्ड पपरिका + 1 बड़ा चम्मच Worcestershire + 1 बड़ा चम्मच सिरका + 1 बड़ा चम्मच चीनी + 0.5 छोटा चम्मच ऑलस्पाइस + 0.5 छोटा चम्मच पिसा अदरक + 0.5 छोटा चम्मच नमक + एक चुटकी कायेन मिलाएँ। मिलाने के लिए फेंटें।. सॉस को सिमर करें: करी सॉस को मध्यम-कम आँच पर हल्के सिमर पर लाएँ। 8–10 मिनट तक पकाएँ, लकड़ी की चम्मच से बार-बार चलाते हुए, जब तक सॉस चमकदार और थोड़ा कम न हो जाए — इसे चम्मच के पीछे को कोट करना चाहिए। चखें और समायोजित करें: यदि बहुत तीखा है, तो एक चुटकी और चीनी डालें; यदि बहुत मीठा है, तो थोड़ा और सिरका। सबसे कम आँच पर गर्म रखें।. सॉसेज तलें: मध्यम आँच पर एक भारी कड़ाही में 2 बड़े चम्मच तेल गरम करें। छेद वाले सॉसेज डालें और 8–10 मिनट तक तलें, हर 2 मिनट में चिमटे से पलटते हुए, जब तक सभी तरफ से गहरे सुनहरे भूरे न हो जाएँ और त्वचा कुरकुरी न हो जाए। आंतरिक तापमान 70 °C तक पहुँचना चाहिए — सॉसेज पूरी तरह से पका होना चाहिए।. 2 मिनट आराम दें: सॉसेज को कागज तौलिये से ढके बोर्ड पर स्थानांतरित करें। उन्हें 2 मिनट आराम करने दें — यह पकाने को समाप्त करता है और रसों को पुनः वितरित होने देता है, ताकि काटते समय वे बाहर न निकलें।. काटें: एक तेज चाकू से, प्रत्येक सॉसेज को तिरछा 1.5 सेमी के 8 टुकड़ों में काटें। तिरछा कट सॉस के चिपकने के लिए अधिक सतह देता है और प्रतिष्ठित बर्लिन प्रस्तुति है।. व्यवस्थित करें: कटे हुए सॉसेज को 2 गहरी कागज की ट्रे प्लेटों या उथले कटोरों (बर्लिन Imbiss शैली) के बीच विभाजित करें। ऊपर से गर्म करी सॉस को उदारता से डालें ताकि वह स्लाइस के चारों ओर इकट्ठा हो जाए। पूरी प्लेट को अतिरिक्त उदार चुटकी करी पाउडर से छिड़कें — धूल भरा शीर्ष ही इसे currywurst बनाता है, न कि केवल सॉस में सॉसेज।. POMMES के साथ परोसें: एक लकड़ी का Pommespieker (छोटा कांटा) स्लाइस में चुभाएँ, ट्रे के किनारे पर सुनहरे Pommes Frites का ढेर और मेयोनेज़ + केचप का एक छोटा सा डलप (जर्मन Pommes rot-weiß) रखें। खड़े होकर खाएँ, आदर्श रूप से बर्लिन की सड़क के किनारे पर। एक ठंडे Pilsner के साथ जोड़ें। 5 मिनट के भीतर खाना सबसे अच्छा है — आनंद कुरकुरी त्वचा, गर्म सॉस, धूल भरी करी और नमकीन फ्राइज़ के विरोधाभास में है।.","en":"PRICK THE SAUSAGES: take 4 Bratwurst out of the fridge 15 minutes before cooking to come closer to room temperature; prick each sausage 4–5 times with a fork — this prevents the skin from bursting open in the pan and lets some fat render out. MAKE THE CURRY SAUCE: in a small saucepan, combine 200 g ketchup + 100 ml passata + 2 tbsp curry powder + 1 tsp sweet paprika + 0.5 tsp smoked paprika + 1 tbsp Worcestershire + 1 tbsp vinegar + 1 tbsp sugar + 0.5 tsp allspice + 0.5 tsp ground ginger + 0.5 tsp salt + a pinch of cayenne; whisk to combine. SIMMER THE SAUCE: bring the curry sauce to a gentle simmer over medium-low heat; cook 8–10 minutes, stirring often with a wooden spoon, until the sauce is glossy and slightly reduced — it should coat the back of a spoon; taste and adjust: if too sharp, add a pinch more sugar; if too sweet, a splash more vinegar; keep warm on the lowest heat. FRY THE SAUSAGES: heat 2 tbsp oil in a heavy skillet over medium heat; add the pricked sausages and fry 8–10 minutes, turning every 2 minutes with tongs, until deeply golden brown on all sides and the skin is crisp; the internal temperature should reach 70 °C — sausages must be fully cooked through. REST 2 MINUTES: transfer the sausages onto a board lined with paper towel; let them rest 2 minutes — this finishes cooking and lets the juices redistribute, so they don't gush out when sliced. SLICE: with a sharp knife, slice each sausage diagonally into 8 pieces of 1.5 cm; the diagonal cut gives more surface for the sauce to cling to and is the iconic Berlin presentation. ASSEMBLE: divide the sliced sausages between 2 deep paper-tray plates or shallow bowls (the Berlin Imbiss style); ladle the hot curry sauce generously over the top so it pools around the slices; dust the whole plate with an extra generous pinch of curry powder — the dusty top is what makes it a currywurst, not just a sausage in sauce. SERVE WITH POMMES: stab a wooden Pommespieker (small fork) into the slices, set on the side of the tray a heap of golden Pommes Frites and a small dollop of mayonnaise + ketchup (the German Pommes rot-weiß); eat standing up, ideally on a Berlin street corner; pair with a cold Pilsner; best eaten within 5 minutes — the joy is in the contrast of crisp skin, hot sauce, dusty curry, and salty fries."}},{"id":174,"servings":4,"tipType":"meat","pairingsType":"thai","origin":{"hi":"थाईलैंड","en":"Thailand","ro":"Thailanda"},"name":{"hi":"टॉम खा गाई","en":"Tom Kha Gai","ro":"Tom Kha Gai"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"ingredients":{"hi":["500 ग्राम हड्डी रहित बिना त्वचा वाली चिकन जांघें (इस नाजुक शोरबे में ब्रेस्ट से अधिक स्वाद), रेशे के विरुद्ध 5 मिमी की पट्टियों में पतला कटा हुआ","400 मिली बिना मीठा फुल-फैट नारियल का दूध (क्रीम परत अलग, चरण 2 देखें)","600 मिली बिना नमक का चिकन स्टॉक (कम-सोडियम घर का बना या खरीदा हुआ)","1 हाथ ताज़ा गलंगल (kha) — ~50 ग्राम, छिलका उतारकर 5 मिमी सिक्के के आकार में कटा हुआ; अदरक से प्रतिस्थापन न करें, स्वाद पूरी तरह से अलग है","3 डंडी ताज़ा लेमनग्रास (takrai) — बाहरी पत्तियाँ हटाई गई, निचले 10 सेमी चाकू की पीठ से कुचले गए और 5 सेमी खंडों में कटे हुए","6 ताज़ा कफीर नींबू पत्ते (bai makrut), नसें निकालकर फाड़ी हुई (कटी नहीं — फाड़ने पर तेल निकलते हैं)","4 छोटी थाई बर्ड'स आई मिर्च (prik kee noo) — पूरी हल्के से कुचली हुई, यदि हल्की तीव्रता चाहिए तो काटी नहीं (तीखी के लिए कटी हुई)","4 लहसुन कलियाँ, हल्के से कुचली हुई","2 छोटे शैलट (~80 ग्राम), पतले कटे हुए","200 ग्राम स्ट्रॉ मशरूम (डिब्बाबंद, सूखाए हुए), आधे में कटे — या प्रतिस्थापन के रूप में ताज़ा ऑयस्टर/शिटाके/बटन मशरूम","4 बड़े चम्मच थाई फिश सॉस (nam pla) — सर्वोत्तम स्वाद के लिए Squid या Tiparos ब्रांड","1 बड़ा चम्मच पाम शुगर (या हल्की भूरी चीनी)","60 मिली ताज़ा नींबू रस (2 नींबू से) — अंत में जोड़ा गया, कभी उबाला नहीं गया","2 बड़े चम्मच सोयाबीन तेल में थाई मिर्च पेस्ट (nam prik pao) — हस्ताक्षर स्मोकी गहराई जोड़ता है (वैकल्पिक लेकिन पारंपरिक)","1 छोटा गुच्छा ताज़ा धनिया (सिलेंट्रो) पत्ते, मोटा कटा हुआ, सजावट के लिए","4 हरे प्याज, तिरछे पतले कटे हुए, सजावट के लिए","परोसने के लिए: 320 ग्राम पकाया हुआ चमेली चावल (प्रति परोसने में 80 ग्राम सूखा) + 1 नींबू टुकड़ों में कटा हुआ"],"en":["500 g boneless skinless chicken thighs (more flavour than breast in this delicate broth), thinly sliced across the grain into 5 mm strips","400 ml unsweetened full-fat coconut milk (the cream layer separated, see step 2)","600 ml unsalted chicken stock (low-sodium homemade or store-bought)","1 hand of fresh galangal (kha) — ~50 g, peeled and cut into 5 mm coin slices; do NOT substitute ginger, the flavour is completely different","3 stalks fresh lemongrass (takrai) — outer leaves removed, lower 10 cm bruised with the back of a knife and cut into 5 cm sections","6 fresh kaffir lime leaves (bai makrut), de-veined and torn (NOT chopped — they release oils when torn)","4 small Thai bird's eye chilies (prik kee noo) — lightly bruised whole, not sliced if you want gentle heat (sliced for hot)","4 garlic cloves, lightly bruised","2 small shallots (~80 g), thinly sliced","200 g straw mushrooms (canned, drained), halved — or fresh oyster/shiitake/button mushrooms as substitute","4 tbsp Thai fish sauce (nam pla) — Squid or Tiparos brand for best flavour","1 tbsp palm sugar (or light brown sugar)","60 ml fresh lime juice (from 2 limes) — added at the END, never boiled","2 tbsp Thai chili paste in soybean oil (nam prik pao) — adds the signature smoky depth (optional but traditional)","1 small bunch fresh cilantro (coriander) leaves, roughly chopped, to garnish","4 spring onions, thinly sliced on the diagonal, to garnish","To serve: 320 g cooked jasmine rice (80 g dry per serving) + 1 lime cut into wedges"],"ro":["500 g pulpe de pui dezosate și fără piele (mai aromate decât pieptul în acest bulion delicat), feliate subțire în benzi de 5 mm contra fibrei","400 ml lapte de cocos integral neîndulcit (cu stratul de smântână separat, vezi pasul 2)","600 ml supă de pui nesărată (de casă sau cumpărată cu conținut scăzut de sodiu)","1 mână de galangal proaspăt (kha) — ~50 g, curățat și tăiat în felii de 5 mm; NU înlocui cu ghimbir, aroma este complet diferită","3 tulpini de lemongrass proaspăt (takrai) — frunzele exterioare îndepărtate, partea inferioară de 10 cm zdrobită cu dosul cuțitului și tăiată în secțiuni de 5 cm","6 frunze de kaffir lime proaspete (bai makrut), cu vinele îndepărtate și rupte (NU tăiate — eliberează uleiurile când sunt rupte)","4 ardei iuți thailandezi mici (prik kee noo) — zdrobiți ușor întregi, nu feliați dacă vrei iuțeală blândă (feliați pentru iute)","4 căței de usturoi, zdrobiți ușor","2 șalote mici (~80 g), feliate subțire","200 g ciuperci de paie (la conservă, scurse), tăiate în jumătăți — sau ciuperci proaspete oyster/shiitake/champignon ca substitut","4 linguri sos de pește thailandez (nam pla) — marca Squid sau Tiparos pentru cea mai bună aromă","1 lingură zahăr de palmier (sau zahăr brun deschis)","60 ml suc de lime proaspăt (din 2 limete) — adăugat la SFÂRȘIT, niciodată fiert","2 linguri pastă thailandeză de ardei iute în ulei de soia (nam prik pao) — adaugă profunzimea afumată caracteristică (opțional dar tradițional)","1 mănunchi mic de coriandru proaspăt (frunze de cilantro), tocat grosier, pentru garnitură","4 cepe verzi, feliate subțire pe diagonală, pentru garnitură","Pentru servire: 320 g orez jasmin fiert (80 g uscat pe porție) + 1 lime tăiat în felii"]},"howIsMade":{"hi":"सुगंधित सामग्री तैयार करें: 50 ग्राम गलंगल को छीलकर 5 मिमी सिक्कों में काटें। 3 लेमनग्रास डंडियों से सख्त बाहरी पत्तियाँ हटाएँ और तेल छोड़ने के लिए भारी चाकू की पीठ से निचले 10 सेमी को कुचलें — फिर 5 सेमी टुकड़ों में काटें। 6 कफीर नींबू पत्तों को तेल छोड़ने के लिए फाड़ें (काटें नहीं)। चाकू की बगल से 4 मिर्च + 4 लहसुन कलियाँ हल्के से कुचलें। ये सुगंधित सामग्री शोरबे की आत्मा हैं — कभी भी पिसे हुए विकल्प का उपयोग न करें।. नारियल दूध अलग करें: 400 मिली नारियल दूध का डिब्बा बिना हिलाए खोलें। मोटी क्रीम आमतौर पर ऊपर बैठती है — लगभग 100 मिली मोटी क्रीम चम्मच से निकालें और अलग रखें (यह आपका hua kati, क्रीम है)। बाकी पतला दूध (hang kati) है।. क्रीम को खिलाएँ: एक मध्यम बर्तन में मध्यम आँच पर, 100 मिली नारियल क्रीम को 3–4 मिनट तक उबालें जब तक यह विभाजित न हो जाए और तेल दिखाई से अलग होना न शुरू हो जाए — यह नारियल की सुगंध को केंद्रित करता है और पारंपरिक थाई शुरुआती चाल है। (यदि आपका नारियल दूध साफ-सुथरे ढंग से अलग नहीं होता है, तो इस चरण को छोड़ दें और बस सब कुछ बर्तन में डालकर शुरू करें।). सुगंधित सामग्री को भिगोएँ: गलंगल स्लाइस, लेमनग्रास टुकड़े, फटे हुए नींबू पत्ते, कुचली हुई मिर्च, लहसुन और 80 ग्राम कटे हुए शैलट गर्म नारियल क्रीम में मिलाएँ। 1 मिनट तक हिलाएँ जब तक यह तीव्र सुगंधित न हो जाए। रसोई में स्पष्ट रूप से थाई गंध होनी चाहिए — चमकीला साइट्रस, मसालेदार गलंगल और मीठा नारियल।. शोरबा बनाएँ: बचे हुए 300 मिली नारियल दूध + 600 मिली चिकन स्टॉक + 2 बड़े चम्मच nam prik pao (यदि उपयोग कर रहे हैं) डालें। हल्के सिमर पर लाएँ (कभी भी तेज उबाल नहीं — नारियल दूध तेज उबालने पर बदसूरत तरीके से अलग हो जाता है)। ढके बिना 8 मिनट सिमर करें, ताकि सुगंधित सामग्री पूरी तरह से मिल जाए और शोरबा गहरा और गोल स्वाद ले।. चिकन डालें: 500 ग्राम कटा हुआ चिकन सिमर हो रहे शोरबे में डालें, टुकड़ों को अलग करने के लिए धीरे से हिलाएँ। 4–5 मिनट तक सिमर करें जब तक चिकन बस पक न जाए और सफेद न हो जाए — अधिक पकाने से यह कठोर हो जाता है। 200 ग्राम आधे कटे हुए स्ट्रॉ मशरूम डालें और 2 मिनट और सिमर करें।. मसाला: आँच बंद करें। 4 बड़े चम्मच फिश सॉस + 1 बड़ा चम्मच पाम शुगर मिलाएँ। चखें — शोरबा नमकीन, थोड़ा मीठा, हल्का तीखा और साइट्रस सुगंध से भरपूर होना चाहिए। यदि आवश्यक हो तो थोड़ा और फिश सॉस या चीनी डालें। यहाँ आँच से उतारना महत्वपूर्ण है।. अंतिम क्षण में नींबू: 60 मिली ताज़ा नींबू रस केवल परोसने से ठीक पहले मिलाएँ — नींबू रस उबालने से यह कड़वा और सुस्त हो जाता है। गहरे कटोरों में परोसें। ताज़ा धनिया + कटे हुए हरे प्याज + अधिक तीखापन पसंद करने वालों के लिए कुछ अतिरिक्त कुचली हुई मिर्च की स्लाइस से सजाएँ। बगल में भाप में पका हुआ चमेली चावल और नींबू टुकड़ों के साथ गर्म परोसें। मेहमानों को बताएँ: गलंगल, लेमनग्रास और नींबू पत्ते सुगंधित हैं, खाने योग्य नहीं हैं — उन्हें कटोरे के किनारे की ओर धकेल दें।.","en":"PREP THE AROMATICS: peel and slice 50 g galangal into 5 mm coins; remove the tough outer leaves from 3 lemongrass stalks and bruise the lower 10 cm with the back of a heavy knife to release the oils — then cut into 5 cm pieces; tear (don't chop) 6 kaffir lime leaves to release their oils; lightly bruise 4 chilies + 4 garlic cloves with the side of the knife; these aromatics are the soul of the broth — never use ground substitutes. SEPARATE THE COCONUT MILK: open a 400 ml can of coconut milk without shaking; the thick cream usually sits on top — spoon off about 100 ml of the thick cream and set aside (this is your hua kati, the cream); the rest is the thinner milk (hang kati). BLOOM THE CREAM: in a medium pot over medium heat, simmer the 100 ml coconut cream 3–4 minutes until it splits and the oil starts to separate visibly — this concentrates the coconut flavor and is the traditional Thai opening move; (If your coconut milk doesn't separate cleanly, skip this step and just start with everything in the pot.). INFUSE THE AROMATICS: add the galangal slices, lemongrass pieces, torn lime leaves, bruised chilies, garlic, and 80 g sliced shallots to the hot coconut cream; stir 1 minute until intensely aromatic; the kitchen should smell distinctly of Thai — bright citrus, peppery galangal, and sweet coconut. BUILD THE BROTH: pour in the remaining 300 ml coconut milk + 600 ml chicken stock + 2 tbsp nam prik pao (if using); bring to a gentle simmer (NEVER a hard boil — coconut milk separates ugly if boiled hard); simmer 8 minutes uncovered, so the aromatics infuse fully and the broth tastes deep and rounded. ADD THE CHICKEN: drop the 500 g sliced chicken into the simmering broth, stirring gently to separate the pieces; simmer 4–5 minutes until the chicken is just cooked through and white — overcooking turns it tough; add 200 g halved straw mushrooms and simmer 2 minutes more. SEASON: turn off the heat; stir in 4 tbsp fish sauce + 1 tbsp palm sugar; taste — the broth should be savoury, slightly sweet, mildly hot, and full of citrus aroma; add a splash more fish sauce or sugar if needed; off heat is critical here. LIME AT THE LAST MOMENT: stir in 60 ml fresh lime juice ONLY just before serving — boiling the lime juice turns it bitter and dull; ladle into deep bowls; top with fresh cilantro + sliced spring onions + a few extra slices of bruised chili for those who like more heat; serve hot with steamed jasmine rice on the side and lime wedges; tell guests: the galangal, lemongrass, and lime leaves are aromatics, not edible — fish them to the side of the bowl."}},{"id":175,"servings":6,"tipType":"meat","pairingsType":"latin","origin":{"hi":"केप वर्डे","en":"Cape Verde","ro":"Capul Verde"},"name":{"hi":"काचुपा","en":"Cachupa","ro":"Cachupa"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["400 ग्राम milho cachupa (सफेद होमिनी मक्का, केप वर्डे की विशिष्ट दरारी सूखी किस्म) — रात भर ढेर सारे ठंडे पानी में भिगोई हुई (अनिवार्य)","200 ग्राम सूखी लाल राजमा — रात भर भिगोई हुई","200 ग्राम सूखी बटर बीन्स (लीमा बीन्स) या छोले — रात भर भिगोई हुई (फलियों का मिश्रण केप वर्डे की पहचान है)","500 ग्राम सूअर का कंधा (cabidela), 3 सेमी क्यूब्स में कटा हुआ","300 ग्राम नमकीन सूअर की पसलियाँ या सूअर की बेली (toucinho), टुकड़ों में कटी हुई — अतिरिक्त नमक हटाने के लिए 1 घंटे ठंडे पानी में भिगोएँ","200 ग्राम linguiça या chouriço portuguesa (पुर्तगाली स्मोक्ड सॉसेज), 1.5 सेमी स्लाइस में कटी हुई","200 ग्राम morcela (पुर्तगाली ब्लड सॉसेज) — वैकल्पिक, पारंपरिक","2 बड़े पीले प्याज (~350 ग्राम), एक refogado के लिए बारीक कटा और एक टुकड़ों में कटा हुआ","6 लहसुन कलियाँ, बारीक कटी हुई","2 मध्यम पके टमाटर (~250 ग्राम), छिले और कद्दूकस किए हुए, या 1 × 200 ग्राम कैन कुचले टमाटर","1 बड़ा चम्मच टमाटर पेस्ट","2 तेज पत्ते + 1 छोटा चम्मच पिसा जीरा + 1 छोटा चम्मच मीठी पपरिका + 0.5 छोटा चम्मच सूखा अजवायन + 1 छोटा चम्मच नमक + 0.5 छोटा चम्मच काली मिर्च","3 बड़े चम्मच लाल पाम तेल या जैतून का तेल (पाम तेल कुछ द्वीपों में अधिक पारंपरिक है)","500 ग्राम कद्दू या बटरनट स्क्वैश, छिला हुआ और 4 सेमी क्यूब्स में कटा हुआ","300 ग्राम शकरकंद या रतालू, छिला हुआ और 4 सेमी क्यूब्स में कटा हुआ","200 ग्राम सेवॉय गोभी, 4 सेमी टुकड़ों में कटी हुई (अंतिम चरण में जोड़ी जाती है)","2 लीटर पानी (या सूअर का शोरबा) + 1 piri-piri या scotch bonnet मिर्च (वैकल्पिक, द्वीपों की हल्की तीव्रता के लिए)","परोसने के लिए: ताज़ी सफेद रोटी के टुकड़े, ग्रिल्ड linguiça की कुछ अतिरिक्त स्लाइस, गर्म piri-piri सॉस, और अगले दिन का 'cachupa guisada' विकल्प — अंडे के साथ पैन में तला हुआ"],"en":["400 g milho cachupa (white hominy corn, the cracked dried Cape Verdean variety) — soaked overnight in plenty of cold water (mandatory)","200 g dried red kidney beans — soaked overnight","200 g dried butter beans (lima beans) or chickpeas — soaked overnight (the mixture of legumes is the Cape Verdean signature)","500 g pork shoulder (cabidela), cut into 3 cm cubes","300 g salted pork ribs or pork belly (toucinho), cut into chunks — soak 1 hour in cold water to remove excess salt","200 g linguiça or chouriço portuguesa (Portuguese smoked sausage), cut into 1.5 cm slices","200 g morcela (Portuguese blood sausage) — optional, traditional","2 large yellow onions (~350 g), one finely diced for the refogado and one cut into wedges","6 garlic cloves, minced","2 medium ripe tomatoes (~250 g), peeled and grated, or 1 × 200 g can crushed tomatoes","1 tbsp tomato paste","2 bay leaves + 1 tsp ground cumin + 1 tsp sweet paprika + 0.5 tsp dried oregano + 1 tsp salt + 0.5 tsp black pepper","3 tbsp red palm oil OR olive oil (palm oil is more traditional in some islands)","500 g pumpkin or butternut squash, peeled and cut into 4 cm cubes","300 g sweet potato or yam, peeled and cut into 4 cm cubes","200 g savoy cabbage, cut into 4 cm wedges (added in the final stage)","2 L water (or pork stock) + 1 piri-piri or scotch bonnet chili (optional, for the islands' light heat)","To serve: chunks of fresh white bread, a few extra slices of grilled linguiça, hot piri-piri sauce, and the next-day pan-fried 'cachupa guisada' with eggs option mentioned"],"ro":["400 g milho cachupa (porumb hominy alb, varietatea crăpată uscată specifică Capului Verde) — înmuiat peste noapte în multă apă rece (obligatoriu)","200 g fasole roșie uscată — înmuiată peste noapte","200 g fasole untoasă uscată (lima) sau năut — înmuiată peste noapte (amestecul de leguminoase este semnătura capverdiană)","500 g spată de porc (cabidela), tăiată în cuburi de 3 cm","300 g coaste de porc sărate sau burtă de porc (toucinho), tăiate în bucăți — înmuiate 1 oră în apă rece pentru a îndepărta excesul de sare","200 g linguiça sau chouriço portuguesa (cârnat afumat portughez), tăiat în felii de 1.5 cm","200 g morcela (cârnat de sânge portughez) — opțional, tradițional","2 cepe galbene mari (~350 g), una tăiată mărunt pentru refogado și una tăiată în felii mari","6 căței de usturoi, tocați mărunt","2 roșii medii coapte (~250 g), decojite și răzuite, sau 1 cutie de 200 g de roșii zdrobite","1 lingură pastă de roșii","2 foi de dafin + 1 linguriță chimion măcinat + 1 linguriță boia dulce + 0.5 linguriță oregano uscat + 1 linguriță sare + 0.5 linguriță piper negru","3 linguri ulei roșu de palmier SAU ulei de măsline (uleiul de palmier este mai tradițional în unele insule)","500 g dovleac sau dovleac plăcintar, curățat și tăiat în cuburi de 4 cm","300 g cartof dulce sau ignamă, curățat și tăiat în cuburi de 4 cm","200 g varză de Milano, tăiată în felii mari de 4 cm (adăugată în etapa finală)","2 L apă (sau supă de porc) + 1 ardei iute piri-piri sau scotch bonnet (opțional, pentru iuțeala ușoară a insulelor)","Pentru servire: bucăți de pâine albă proaspătă, câteva felii suplimentare de linguiça la grătar, sos iute piri-piri și opțiunea 'cachupa guisada' a doua zi (prăjită în tigaie cu ouă)"]},"howIsMade":{"hi":"रात भर भिगोएँ: यह कदम गैर-परक्राम्य है। पकाने से एक रात पहले, 400 ग्राम होमिनी मक्का + 200 ग्राम राजमा + 200 ग्राम बटर बीन्स/छोले प्रत्येक को अलग-अलग कटोरों में 5 सेमी ठंडे पानी से ढककर रखें। न्यूनतम 12 घंटे भिगोएँ। अगली सुबह, छानें और धोएँ। भिगोने को छोड़ने से मक्का ऐसा होगा जो घंटों पकने के बाद भी कुरकुरा रहेगा।. होमिनी को पहले से पकाएँ: छानी हुई होमिनी को एक बड़े बर्तन में 1.5 लीटर ताज़े ठंडे पानी + 1 तेज पत्ता + 1 छोटा चम्मच नमक के साथ रखें। उबाल लाएँ, फिर ढककर 1 घंटा सिमर करें। मक्का आंशिक रूप से नरम होना चाहिए लेकिन केंद्र में अभी भी दृढ़ होना चाहिए — यह स्टू में पकता रहेगा। छानें, 500 मिली पकाने का तरल बचा रखें।. फलियों को पहले से पकाएँ: एक दूसरे बर्तन में, छनी हुई राजमा और बटर बीन्स को 3 सेमी तक ढकने के लिए ताज़े ठंडे पानी के साथ रखें। उबाल लाएँ, 5 मिनट तक झाग निकालें, फिर 45 मिनट तक सिमर करें जब तक वे al dente न हो जाएँ — वे स्टू में पूरे होंगे। छानें।. REFOGADO: एक बड़े भारी 8 लीटर बर्तन में, मध्यम आँच पर 3 बड़े चम्मच पाम या जैतून का तेल गर्म करें। 200 ग्राम बारीक कटा प्याज + 6 कटी हुई लहसुन की कलियाँ डालें और 8–10 मिनट तक पकाएँ जब तक वे नरम और सुनहरे न हो जाएँ। 1 बड़ा चम्मच टमाटर पेस्ट मिलाएँ और 1 मिनट तक पकाएँ जब तक यह काला न हो जाए। 250 ग्राम कद्दूकस किया हुआ टमाटर + 1 छोटा चम्मच पपरिका + 1 छोटा चम्मच जीरा + 0.5 छोटा चम्मच अजवायन डालें और 4–5 मिनट तक पकाएँ जब तक मिश्रण कम न हो जाए और तेल सतह पर अलग न हो जाए।. सूअर को सीयर करें: refogado को एक तरफ धकेलें। आँच को मध्यम-उच्च तक बढ़ाएँ और 500 ग्राम सूअर के कंधे के क्यूब्स को एक ही परत में डालें। प्रत्येक तरफ 3 मिनट तक सुनहरा भूरा होने तक सीयर करें, फिर refogado में मिलाएँ। छनी हुई नमकीन सूअर की पसलियाँ/बेली + 1 छोटा चम्मच नमक + 0.5 छोटा चम्मच काली मिर्च + 1 शेष तेज पत्ता + वैकल्पिक piri-piri मिर्च डालें।. स्टू बनाएँ: आंशिक रूप से पकी होमिनी + छनी हुई फलियाँ + 2 लीटर पानी (या सूअर का शोरबा) + आरक्षित 500 मिली मक्का पकाने का तरल डालें। हल्के सिमर पर लाएँ।. धीमी सिमर: ढके बिना, हर 20–30 मिनट में हिलाते हुए, 2 घंटे सिमर करें। 1 घंटे बाद, 500 ग्राम कद्दू के क्यूब्स + 300 ग्राम शकरकंद के क्यूब्स + linguiça स्लाइस डालें। 1.5 घंटे बाद, 200 ग्राम गोभी के टुकड़े + प्याज के टुकड़े + morcela स्लाइस (यदि उपयोग कर रहे हैं) डालें। स्टू को मोटी, खिचड़ी जैसी स्थिरता तक कम होना चाहिए जहाँ मक्का, फलियाँ, सब्जियाँ और मांस सभी नरम हों। चखें और नमक को समायोजित करें — नमकीन सूअर का मांस और सॉसेज बहुत कुछ जोड़ते हैं।. आराम और परोसना: आँच बंद करें और cachupa को 10 मिनट तक आराम करने दें — यहीं यह सही स्थिरता तक गाढ़ी होती है। सभी रंग दिखाई देने के साथ गहरी कटोरियों में उदारता से परोसें: पीला मक्का, लाल फलियाँ, नारंगी कद्दू, हरी गोभी, सुनहरा सॉसेज और समृद्ध सूअर का मांस। ताज़ी सफेद रोटी के टुकड़ों, मेज़ पर गर्म piri-piri सॉस और एक गिलास केप वर्डियन grogue या बीयर के साथ परोसें। अगले दिन के बचे हुए को ऊपर एक तले हुए अंडे के साथ पैन में 'cachupa guisada' के रूप में तला जाता है — पहले दिन से भी बेहतर माना जाता है।.","en":"SOAK OVERNIGHT: this is non-negotiable; the night before cooking, place 400 g hominy corn + 200 g kidney beans + 200 g butter beans/chickpeas each in separate bowls covered by 5 cm of cold water; soak 12 hours minimum; the next morning, drain and rinse; skipping the soak gives a corn that stays gritty after hours of cooking. PRE-COOK THE HOMINY: place the drained hominy in a large pot with 1.5 L fresh cold water + 1 bay leaf + 1 tsp salt; bring to a boil, then simmer covered 1 hour; the corn should be partially tender but still firm at the centre — it will continue cooking in the stew; drain, reserving 500 ml of the cooking liquid. PRE-COOK THE BEANS: in a second pot, place the drained kidney beans and butter beans together with fresh cold water to cover by 3 cm; bring to a boil, skim foam for 5 min, then simmer 45 min until al dente — they will finish in the stew; drain. THE REFOGADO: in a large heavy 8 L pot, heat 3 tbsp palm or olive oil over medium heat; add 200 g finely diced onion + 6 minced garlic and cook 8–10 minutes until soft and golden; stir in 1 tbsp tomato paste and cook 1 min until darkened; add 250 g grated tomato + 1 tsp paprika + 1 tsp cumin + 0.5 tsp oregano and cook 4–5 min until the mixture reduces and the oil separates on the surface. SEAR THE PORK: push the refogado to the side; raise the heat to medium-high and add the 500 g pork shoulder cubes in a single layer; sear 3 minutes per side until golden brown, then stir into the refogado; add the drained salted pork ribs/belly + 1 tsp salt + 0.5 tsp pepper + 1 remaining bay leaf + the optional piri-piri chili. BUILD THE STEW: add the partially-cooked hominy + the drained beans + 2 L water (or pork stock) + the 500 ml reserved corn-cooking liquid; bring to a gentle simmer. SLOW SIMMER: simmer uncovered, stirring every 20–30 minutes, for 2 hours; after 1 hour, add the 500 g pumpkin cubes + 300 g sweet potato cubes + the linguiça slices; after 1.5 hours, add the 200 g cabbage wedges + the onion wedges + the morcela slices (if using); the stew should reduce to a thick, porridge-like consistency where the corn, beans, vegetables, and meats are all tender; taste and adjust salt — the saltpork and sausages add a lot. REST AND SERVE: turn off the heat and let the cachupa rest 10 minutes — this is when it thickens to the perfect consistency; ladle generously into deep bowls with all the colors visible: yellow corn, red beans, orange pumpkin, green cabbage, golden sausage, and rich pork; serve with chunks of fresh white bread, hot piri-piri sauce on the table, and a glass of Cape Verdean grogue or beer; the leftovers next day are pan-fried with a fried egg on top as 'cachupa guisada' — considered even better than the first day."}},{"id":176,"servings":4,"tipType":"veg","pairingsType":"indian","origin":{"hi":"भारत","en":"India","ro":"India"},"name":{"hi":"पाव भाजी","en":"Pav Bhaji","ro":"Pav Bhaji"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["500 ग्राम मैदा वाले आलू, छिले हुए और 3 सेमी क्यूब्स में कटे हुए","250 ग्राम फूलगोभी के फूल (लगभग 1/2 छोटा सिर)","100 ग्राम हरी मटर (ताज़ी या जमी हुई)","100 ग्राम फ्रेंच बीन्स, 1 सेमी टुकड़ों में कटी हुई","1 मध्यम गाजर (~100 ग्राम), कटी हुई","100 ग्राम बिना नमक का मक्खन (हाँ — इतना सब, ये स्ट्रीट विक्रेताओं की मक्खन की मात्रा हैं) — विभाजित","2 बड़े लाल प्याज़ (~300 ग्राम) — एक भाजी के लिए बारीक कटा, एक कच्चा बारीक कटा गार्निश के लिए","1 बड़ी हरी शिमला मिर्च या कैप्सिकम (~150 ग्राम), बारीक कटी हुई","4 पके टमाटर (~500 ग्राम), ब्लेंडर में प्यूरी किए हुए","1 बड़ा चम्मच अदरक-लहसुन पेस्ट (या 3 सेमी अदरक + 4 लहसुन कलियाँ, एक साथ कद्दूकस की हुई)","2 बड़े चम्मच पाव भाजी मसाला (Everest या MDH ब्रांड) — विशिष्ट मसाला मिश्रण, गरम मसाला से न बदलें","1 छोटा चम्मच कश्मीरी लाल मिर्च पाउडर (प्रतीकात्मक लाल रंग के लिए, हल्की तीव्रता)","0.5 छोटा चम्मच हल्दी + 1.5 छोटा चम्मच नमक + 0.5 छोटा चम्मच पिसी काली मिर्च","1 नींबू, 4 टुकड़ों में कटा + ताज़ी कटी हरी धनिया (cilantro), उदारता से","8 छोटे नरम पाव बन्स (मुंबई स्टाइल लाडी पाव, या ब्रिओश स्लाइडर बन्स से बदलें)","पाव को सेंकने के लिए 50 ग्राम बिना नमक का मक्खन + छिड़कने के लिए अतिरिक्त लाल मिर्च पाउडर","परोसने के लिए: अतिरिक्त कच्चा लाल प्याज़, ताज़ी धनिया, नींबू के टुकड़े, 1 छोटी हरी मिर्च बारीक कटी हुई (वैकल्पिक)"],"en":["500 g floury potatoes, peeled and cut into 3 cm cubes","250 g cauliflower florets (about 1/2 small head)","100 g green peas (fresh or frozen)","100 g French beans, cut into 1 cm pieces","1 medium carrot (~100 g), diced","100 g unsalted butter (yes — that much, this is street-vendor butter quantities) — divided","2 large red onions (~300 g) — one finely diced for the bhaji, one finely diced raw for the garnish","1 large green bell pepper or capsicum (~150 g), finely diced","4 ripe tomatoes (~500 g), pureed in a blender","1 tbsp ginger-garlic paste (or 3 cm ginger + 4 garlic cloves, grated together)","2 tbsp pav bhaji masala (Everest or MDH brand) — the specific spice blend, do not substitute with garam masala","1 tsp Kashmiri red chili powder (for the iconic red color, mild heat)","0.5 tsp turmeric + 1.5 tsp salt + 0.5 tsp ground black pepper","1 lemon, cut into 4 wedges + chopped fresh coriander (cilantro), generously","8 small soft pav buns (Mumbai-style ladi pav, or substitute with brioche slider buns)","50 g unsalted butter for toasting the pav + extra red chili powder for sprinkling","To serve: extra raw red onion, fresh coriander, lemon wedges, 1 small green chili finely chopped (optional)"],"ro":["500 g cartofi făinoși, curățați și tăiați în cuburi de 3 cm","250 g buchețele de conopidă (aproximativ 1/2 căpățână mică)","100 g mazăre verde (proaspătă sau congelată)","100 g fasole verde franceză, tăiată în bucăți de 1 cm","1 morcov mediu (~100 g), tăiat cubulețe","100 g unt nesărat (da — atât de mult, acestea sunt cantitățile de unt ale vânzătorilor de stradă) — împărțit","2 cepe roșii mari (~300 g) — una tăiată mărunt pentru bhaji, una tăiată mărunt crudă pentru garnitură","1 ardei capia verde mare sau capsicum (~150 g), tăiat mărunt","4 roșii coapte (~500 g), pasate în blender","1 lingură pastă de ghimbir-usturoi (sau 3 cm ghimbir + 4 căței usturoi, răzuiți împreună)","2 linguri pav bhaji masala (marca Everest sau MDH) — amestecul specific de condimente, nu înlocuiți cu garam masala","1 linguriță pudră de chili roșu Kashmiri (pentru culoarea roșie iconică, iuțeală blândă)","0.5 linguriță turmeric + 1.5 linguriță sare + 0.5 linguriță piper negru măcinat","1 lămâie, tăiată în 4 sferturi + coriandru proaspăt (cilantro) tocat, generos","8 chifle pav mici și moi (ladi pav stil Mumbai, sau înlocuiți cu chifle brioche slider)","50 g unt nesărat pentru prăjirea pavului + suplimentar pudră de chili roșu pentru presărat","Pentru servire: ceapă roșie crudă suplimentară, coriandru proaspăt, sferturi de lămâie, 1 ardei iute verde mic tocat mărunt (opțional)"]},"howIsMade":{"hi":"प्रेशर कुकर में सब्ज़ियाँ पकाएँ: एक प्रेशर कुकर (या बड़े बर्तन) में 500 ग्राम आलू के क्यूब्स + 250 ग्राम फूलगोभी + 100 ग्राम मटर + 100 ग्राम फ्रेंच बीन्स + 100 ग्राम कटी हुई गाजर + 500 मिली पानी + 1 छोटा चम्मच नमक मिलाएँ। तेज़ आँच पर 3 सीटी प्रेशर कुक करें, फिर बंद करें और प्रेशर को प्राकृतिक रूप से निकलने दें (लगभग 15 मिनट)। अगर सामान्य बर्तन का उपयोग कर रहे हैं, तो ढककर 25–30 मिनट तक तब तक सिमर करें जब तक सब कुछ कांटे से नरम न हो जाए। छानें, 250 मिली पकाने का पानी आरक्षित रखें।. सब्ज़ियों को मसलें: आलू मैशर से बर्तन में सीधे उबली सब्जियों को ज़ोर से मसलें जब तक आपको एक मोटा प्यूरी न मिल जाए — कुछ बनावट बनी रहनी चाहिए, यह एक चिकना सूप नहीं है। एक तरफ रखें।. खुशबूदार सामग्री खिलाएँ: एक बड़े भारी कड़ाही या kadhai में मध्यम आँच पर 50 ग्राम मक्खन को पिघलाकर झाग आने तक गर्म करें। 150 ग्राम बारीक कटा लाल प्याज़ डालें और बार-बार हिलाते हुए 5–6 मिनट तक तब तक पकाएँ जब तक नरम न हो जाए और किनारों से हल्का सुनहरा न हो जाए।. अदरक-लहसुन + शिमला मिर्च: 1 बड़ा चम्मच अदरक-लहसुन पेस्ट डालें और 1 मिनट तक हिलाएँ जब तक कच्ची महक न चली जाए। 150 ग्राम कटी हुई हरी शिमला मिर्च डालें और 3–4 मिनट तक तब तक पकाएँ जब तक यह बस नरम हो जाए लेकिन अभी भी चमकीली हरी हो।. मसाले खिलते हैं: 2 बड़े चम्मच पाव भाजी मसाला + 1 छोटा चम्मच कश्मीरी मिर्च + 0.5 छोटा चम्मच हल्दी डालें। 30 सेकंड तक हिलाएँ जब तक मसाले तेज़ खुशबूदार न हो जाएँ — जलाएँ नहीं, ज़रूरत हो तो आँच को थोड़ा कम करें।. भाजी बनाएँ: प्यूरी किए हुए टमाटर + 0.5 छोटा चम्मच पिसी मिर्च + 0.5 छोटा चम्मच नमक डालें। बार-बार हिलाते हुए 6–8 मिनट तक तब तक पकाएँ जब तक टमाटर कम न हो जाए और मक्खन कड़ाही के किनारों से अलग होने न लगे — यह दृश्य संकेत है कि मसाला तैयार है। आरक्षित 250 मिली सब्ज़ी का पानी + मसली हुई सब्ज़ियाँ डालें। मिलाने के लिए ज़ोर से हिलाएँ।. सिमर + और मसलें: भाजी को 10–12 मिनट तक सिमर करें, बार-बार हिलाते हुए और कड़ाही में सीधे आलू मैशर से और मसलते हुए। भाजी गाढ़ी, गहरे लाल, चमकदार और तेज़ खुशबूदार हो जानी चाहिए। मसाला समायोजित करें — मुंबई के स्ट्रीट विक्रेता इसे नमकीन और तीखा पसंद करते हैं। और 30 ग्राम मक्खन और 1 बड़ा चम्मच कटी हरी धनिया मिलाएँ। आधे नींबू का रस निचोड़ें।. पाव सेकें और परोसें: 8 पाव बन्स को पूरी तरह से काटे बिना क्षैतिज रूप से काटें (किताब शैली)। एक चौड़ी कड़ाही को मध्यम आँच पर गर्म करें। 30 ग्राम मक्खन + एक चुटकी पाव भाजी मसाला + एक चुटकी कश्मीरी मिर्च डालें, घुमाएँ। खुले पाव बन्स को गरम मक्खन में दबाएँ और हर तरफ 30–60 सेकंड तक तब तक सेकें जब तक सुनहरे और खुशबूदार न हो जाएँ। तुरंत प्लेट करें: गर्म भाजी का उदार ढेर जिसके ऊपर मक्खन का टुकड़ा, कटा कच्चा लाल प्याज़, कटी हरी धनिया, नींबू का टुकड़ा और वैकल्पिक कटी हरी मिर्च हो। प्रति व्यक्ति 2 सेके पाव साथ में परोसें। पाव को फाड़ें, भाजी में डुबोएँ, हर निवाले पर नींबू निचोड़ें — घर पर मुंबई स्ट्रीट फूड।.","en":"PRESSURE-COOK THE VEGETABLES: in a pressure cooker (or large pot) combine 500 g potato cubes + 250 g cauliflower + 100 g peas + 100 g French beans + 100 g diced carrot + 500 ml water + 1 tsp salt; pressure cook 3 whistles on high, then turn off and let the pressure release naturally (about 15 min); if using a regular pot, cover and simmer 25–30 minutes until everything is fork-tender; drain, RESERVING 250 ml of the cooking water. MASH THE VEGETABLES: with a potato masher, vigorously mash the boiled vegetables right in the pot until you have a coarse purée — some texture should remain, this is NOT a smooth soup; set aside. BLOOM THE AROMATICS: heat 50 g butter in a large heavy skillet or kadhai over medium heat until melted and foaming; add 150 g finely diced red onion and cook stirring often 5–6 minutes until soft and just turning golden at the edges. GINGER-GARLIC + BELL PEPPER: add 1 tbsp ginger-garlic paste and stir 1 minute until the raw smell disappears; add 150 g diced green bell pepper and cook 3–4 minutes until just softened but still bright green. SPICES BLOOM: add 2 tbsp pav bhaji masala + 1 tsp Kashmiri chili powder + 0.5 tsp turmeric; stir 30 seconds until the spices are intensely fragrant — do not burn, lower the heat slightly if needed. BUILD THE BHAJI: pour in the pureed tomatoes + 0.5 tsp ground pepper + 0.5 tsp salt; cook stirring often 6–8 minutes until the tomato has reduced and the butter starts to separate around the edges of the pan — this is the visual sign that the masala is ready; add the reserved 250 ml vegetable water + the mashed vegetables; stir vigorously to combine. SIMMER + MASH MORE: simmer the bhaji 10–12 minutes, stirring frequently and mashing more with a potato masher right in the pan; the bhaji should become thick, dark red, glossy, and intensely fragrant; adjust seasoning — Mumbai street vendors love it salty and spicy; stir in another 30 g butter and 1 tbsp chopped coriander; squeeze in juice of half a lemon. TOAST THE PAV AND SERVE: slice 8 pav buns horizontally without cutting all the way through (book-style); heat a wide skillet over medium heat; add 30 g butter + a pinch of pav bhaji masala + a pinch of Kashmiri chili powder, swirl; press the open pav buns into the hot butter and toast 30–60 seconds per side until golden and fragrant; plate immediately: a generous mound of hot bhaji topped with a knob of butter, chopped raw red onion, chopped coriander, a lemon wedge, and optional chopped green chili; serve with 2 toasted pav per person on the side; tear the pav, dip into the bhaji, squeeze the lemon over each bite — Mumbai street food at home."}},{"id":177,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"hi":"फ़िनलैंड","en":"Finland","ro":"Finlanda"},"name":{"hi":"कारेलियन स्टू","en":"Karelian stew","ro":"Karjalanpaisti"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["400 ग्राम बीफ चक (chuck), 3 सेमी क्यूब्स में कटा हुआ","400 ग्राम सूअर का कंधा, 3 सेमी क्यूब्स में कटा हुआ","400 ग्राम भेड़ का कंधा, 3 सेमी क्यूब्स में कटा हुआ (या लैपलैंड में रेनडियर)","2 बड़े पीले प्याज (~400 ग्राम), मोटे टुकड़ों में कटे हुए","4 मध्यम गाजर (~400 ग्राम), 3 सेमी टुकड़ों में कटी हुई","1 छोटा चम्मच साबुत काली मिर्च के दाने","4 तेज पत्ते","6 साबुत जुनिपर बेरी (फिनिश पहचान, हल्की पाइनी — गैर-परक्राम्य)","6 साबुत ऑलस्पाइस बेरी","2 छोटे चम्मच नमक","1 लीटर ठंडा पानी (या हल्का बीफ स्टॉक — परंपरागत रूप से पानी)","1 बड़ा चम्मच न्यूट्रल तेल या 50 ग्राम मक्खन वैकल्पिक सीयरिंग चरण के लिए","परोसने के लिए: मक्खन और डिल के साथ उबले हुए 800 ग्राम नए आलू, अचार वाला खीरा, लिंगोनबेरी जैम (puolukkahillo), डार्क राई ब्रेड, और एक गिलास ठंडा दूध या बीयर"],"en":["400 g beef chuck, cubed 3 cm","400 g pork shoulder, cubed 3 cm","400 g lamb shoulder, cubed 3 cm (or reindeer in Lapland)","2 large yellow onions (~400 g), thickly sliced","4 medium carrots (~400 g), cut into 3 cm chunks","1 tsp whole black peppercorns","4 bay leaves","6 whole juniper berries (the Finnish signature, slightly piny — non-negotiable)","6 whole allspice berries","2 tsp salt","1 L cold water (or weak beef stock — traditional is water)","1 tbsp neutral oil OR 50 g butter for the optional searing step","To serve: 800 g boiled new potatoes with butter and dill, pickled cucumber, lingonberry jam (puolukkahillo), dark rye bread, and a glass of cold milk or beer"],"ro":["400 g pulpă de vită (chuck), tăiată în cuburi de 3 cm","400 g spată de porc, tăiată în cuburi de 3 cm","400 g spată de miel, tăiată în cuburi de 3 cm (sau ren în Laponia)","2 cepe galbene mari (~400 g), tăiate în felii groase","4 morcovi medii (~400 g), tăiați în bucăți de 3 cm","1 linguriță boabe întregi de piper negru","4 foi de dafin","6 boabe întregi de ienupăr (semnătura finlandeză, ușor rășinos — non-negociabil)","6 boabe întregi de ienibahar","2 lingurițe sare","1 L apă rece (sau supă slabă de vită — tradițional este apa)","1 lingură ulei neutru SAU 50 g unt pentru pasul opțional de rumenire","Pentru servire: 800 g cartofi noi fierți cu unt și mărar, castravete murat, gem de merișoare lingonberry (puolukkahillo), pâine neagră de secară și un pahar de lapte rece sau bere"]},"howIsMade":{"hi":"ओवन को 125 °C पर पहले से गरम करें — बहुत कम धीमी ओवन Karjalanpaisti की पहचान है, वह व्यंजन जो इसकी पिघलती बनावट को परिभाषित करता है।. काटें और क्यूब करें: 400 ग्राम बीफ + 400 ग्राम सूअर + 400 ग्राम भेड़ के मांस से किसी भी कण्डरा को हटा दें। समान 3 सेमी क्यूब्स में काटें — छोटा न काटें। यह 5 घंटे का पकाना है और बड़े क्यूब्स टिक जाते हैं; छोटे टुकड़े धागों में घुल जाते हैं।. अपनी शैली चुनें — पारंपरिक: ब्राउनिंग छोड़ दें। सब कुछ कच्चा परत करें और ओवन को काम करने दें, जैसा कि करेलियाई दादी-नानी सदियों से करती आ रही हैं। आधुनिक: एक डच ओवन में 1 बड़ा चम्मच तेल तेज आँच पर गरम करें, अतिरिक्त मेलार्ड स्वाद के लिए मांस को 3 बैचों में हर तरफ 2 मिनट तक भूरा करें, फिर निकाल लें। दोनों विधियाँ उत्कृष्ट परिणाम देती हैं।. बर्तन में परत करें: एक बड़े डच ओवन या कास्ट-आयरन कैसरोल में, इस क्रम में बारी-बारी से परतें बनाएँ: नीचे बीफ, कटा हुआ प्याज, सूअर, गाजर के टुकड़े, ऊपर भेड़ का मांस। 4 तेज पत्ते + 6 जुनिपर बेरी + 6 ऑलस्पाइस + 1 छोटा चम्मच काली मिर्च के दाने + 2 छोटे चम्मच नमक को परतों के बीच वितरित करें — कभी सिर्फ ऊपर नहीं।. तरल जोड़ें: 1 लीटर ठंडा पानी (या हल्का बीफ स्टॉक) इस तरह डालें कि यह मांस के आधे ऊपर तक आए — ढकने वाला नहीं। मांस लंबे पकाने के दौरान अपने रस छोड़ता है और सॉस स्वाभाविक रूप से गाढ़ा होता है।. सील करें और धीमी आँच पर पकाएँ: कसकर ढक्कन से ढकें। 125 °C ओवन में 4–5 घंटे के लिए स्थानांतरित करें — हाँ, पाँच घंटे, यही बात है। ढक्कन न खोलें सिवाय हर 1.5 घंटे में एक बार तरल की जाँच करने के लिए; यदि बहुत तेजी से कम हो रहा है, तो थोड़ा गर्म पानी डालें। जब काँटा बिना मेहनत के डूब जाए तो मांस तैयार है।. ओवन में आराम: ओवन बंद करें और karjalanpaisti को बंद गर्म ओवन में और 30 मिनट आराम करने दें — स्वाद गहरे होते हैं और मांस सॉस में आराम पाता है।. परोसें: नरम मांस को गर्म गहरी प्लेटों में उठाएँ। ऊपर शोरबा जैसे गाढ़े रसों को चम्मच से डालें। जुनिपर बेरी और ऑलस्पाइस बहादुरों के लिए अंदर रह सकते हैं, या निकाले जा सकते हैं। मक्खन और डिल के साथ उबले हुए नए आलू, साइड में अचार वाला खीरा, लिंगोनबेरी जैम का एक उदार चम्मच (मीठा-खट्टा प्रतिबिंदु), डार्क राई ब्रेड के स्लाइस, और एक गिलास ठंडा दूध या बीयर के साथ परोसें — पारंपरिक फिनिश डिनर संगत।.","en":"PREHEAT THE OVEN to 125 °C — the very low slow oven is the SIGNATURE of Karjalanpaisti, the dish that defines its melting texture. TRIM AND CUBE: trim 400 g beef + 400 g pork + 400 g lamb of any sinew; cut into uniform 3 cm cubes — DO NOT cut smaller; this is a 5 h cook and larger cubes hold up; smaller pieces dissolve into shreds. CHOOSE YOUR STYLE — TRADITIONAL: skip browning; layer everything raw and let the oven do the work, as Karelian grandmothers have done for centuries; mODERN: heat 1 tbsp oil in a Dutch oven over high heat, brown the meat in 3 batches 2 min per side for added Maillard flavour, then lift out; both methods produce excellent results. LAYER THE POT: in a large Dutch oven or cast-iron casserole, build alternating layers in this order: beef on the bottom, sliced onion, pork, carrot chunks, lamb on top; distribute 4 bay leaves + 6 juniper berries + 6 allspice + 1 tsp peppercorns + 2 tsp salt between the layers — never just on top. ADD LIQUID: pour in 1 L cold water (or weak beef stock) so it comes halfway up the meat — NOT covering; the meats release their own juices during the long cook and the sauce concentrates naturally. SEAL AND SLOW-COOK: cover with a tight-fitting lid; transfer to the 125 °C oven for 4–5 hours — yes, five hours, that is the point; do NOT open the lid except once every 1.5 hours to check the liquid; if reducing too fast, add a splash of hot water; the meat is ready when a fork sinks in effortlessly. REST IN THE OVEN: turn off the oven and let the karjalanpaisti rest in the closed warm oven another 30 minutes — the flavours deepen and the meat relaxes into the sauce. SERVE: lift the tender meat into warm deep plates; spoon over the brothy concentrated juices; the juniper berries and allspice can stay in for the brave, or be fished out; serve with boiled new potatoes tossed in butter and dill, pickled cucumber on the side, a generous dollop of lingonberry jam (the sweet-tart counterpoint), slices of dark rye bread, and a glass of cold milk or beer — the traditional Finnish dinner accompaniment."}},{"id":178,"servings":6,"tipType":"meat","pairingsType":"french","origin":{"hi":"फ्रांस","en":"France","ro":"Franța"},"name":{"hi":"बोफ बुर्गिनियों","en":"Boeuf Bourguignon","ro":"Boeuf Bourguignon"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["1.5 किलो बीफ चक या शिन, 4 सेमी क्यूब्स में कटा हुआ (समृद्धि के लिए कुछ मार्बलिंग के साथ)","200 ग्राम लार्डन (स्मोक्ड पोर्क बेली 1 सेमी × 3 सेमी कटा हुआ) या 200 ग्राम मोटा कटा हुआ बेकन क्यूब्स में","750 मिली फुल-बॉडीड बरगंडी रेड वाइन (पिनो नोयर) — सस्ती वाइन का उपयोग न करें","200 मिली बीफ स्टॉक","2 बड़े चम्मच टमाटर पेस्ट","1 बड़ा प्याज (~250 ग्राम), मेरिनेड और ब्रेज के लिए बारीक कटा हुआ","2 मध्यम गाजर (~250 ग्राम), 2 सेमी टुकड़ों में कटी हुई","4 लहसुन की कलियाँ, बारीक कटी","30 ग्राम अनसाल्टेड मक्खन + 2 बड़े चम्मच जैतून का तेल सीयरिंग के लिए","3 बड़े चम्मच आल-पर्पस आटा","1 बुके गार्नी: 3 थाइम स्प्रिग + 2 तेज पत्ते + 6 अजमोद के तने रसोई की डोरी से बंधे","250 ग्राम पर्ल प्याज (silverskin), छिले हुए","250 ग्राम क्रेमिनी या बटन मशरूम, आधे या चौथाई कटे","मशरूम-और-पर्ल-प्याज गार्निश के लिए 30 ग्राम अतिरिक्त मक्खन","1.5 छोटा चम्मच नमक + 1 छोटा चम्मच ताज़ी पिसी हुई काली मिर्च","2 बड़े चम्मच कॉन्याक या ब्रांडी वैकल्पिक फ्लाम्बे के लिए","ताज़ा फ्लैट-लीफ अजमोद + बैगेट + उबले हुए नए आलू या मक्खन वाले अंडे के नूडल्स परोसने के लिए"],"en":["1.5 kg beef chuck or shin, cubed 4 cm (some marbling for richness)","200 g lardons (smoked pork belly cut 1 cm × 3 cm) OR 200 g thick-cut bacon diced","750 ml full-bodied Burgundy red wine (Pinot Noir) — DO NOT use cheap wine","200 ml beef stock","2 tbsp tomato paste","1 large onion (~250 g), finely diced for the marinade and braise","2 medium carrots (~250 g), cut into 2 cm chunks","4 garlic cloves, minced","30 g unsalted butter + 2 tbsp olive oil for searing","3 tbsp all-purpose flour","1 bouquet garni: 3 thyme sprigs + 2 bay leaves + 6 parsley stems tied with kitchen string","250 g pearl onions (silverskin), peeled","250 g cremini or button mushrooms, halved or quartered","30 g extra butter for the mushroom-and-pearl-onion garnish","1.5 tsp salt + 1 tsp freshly ground black pepper","2 tbsp Cognac OR brandy for optional flambé","Fresh flat-leaf parsley + baguette + boiled new potatoes or buttered egg noodles to serve"],"ro":["1.5 kg pulpă de vită (chuck) sau gambă, tăiată în cuburi de 4 cm (cu ceva marmurare pentru bogăție)","200 g lardoni (piept de porc afumat tăiat 1 cm × 3 cm) SAU 200 g bacon gros tăiat cubulețe","750 ml vin roșu Burgundia robust (Pinot Noir) — NU folosi vin ieftin","200 ml supă de vită","2 linguri pastă de roșii","1 ceapă mare (~250 g), tăiată mărunt pentru marinadă și pentru tocană","2 morcovi medii (~250 g), tăiați în bucăți de 2 cm","4 căței de usturoi, tocați mărunt","30 g unt nesărat + 2 linguri ulei de măsline pentru rumenire","3 linguri făină universală","1 buchet garni: 3 crenguțe cimbru + 2 foi de dafin + 6 cozi de pătrunjel legate cu sfoară de bucătărie","250 g ceapă perlată (silverskin), curățată","250 g ciuperci cremini sau champignon, tăiate în jumătăți sau sferturi","30 g unt suplimentar pentru garnitura de ciuperci și ceapă perlată","1.5 linguriță sare + 1 linguriță piper negru proaspăt măcinat","2 linguri Cognac SAU brandy pentru flambare opțională","Pătrunjel proaspăt cu frunza plată + baghetă + cartofi noi fierți sau tăiței cu unt pentru servire"]},"howIsMade":{"hi":"बीफ को मेरिनेट करें (12-24 घंटे पहले, जूलिया चाइल्ड का गैर-परक्राम्य): 1.5 किलो क्यूब बीफ को एक गैर-प्रतिक्रियाशील कटोरे में 750 मिली रेड बरगंडी + 1 कटा हुआ प्याज + 1 कटी हुई गाजर + 4 लहसुन + बुके गार्नी + 1 छोटा चम्मच काली मिर्च के साथ रखें। ढककर 12-24 घंटे के लिए फ्रिज में रखें। छलनी से छानें, वाइन को बचाकर रखें। बीफ को पेपर तौलिये से बहुत अच्छी तरह सुखाएँ — गीला मांस भाप में पकता है, कभी नहीं भुनता।. लार्डन रेंडर करें: एक भारी डच ओवन में मध्यम आँच पर, 200 ग्राम लार्डन को 6-8 मिनट तक कुरकुरा और सुनहरा होने तक पकाएँ, वसा पूरी तरह से निकल जाए। उन्हें झारी से एक प्लेट में निकालें। बर्तन में 2 बड़े चम्मच वसा छोड़ दें।. बीफ को सीयर करें: आँच को तेज करें। 1 बड़ा चम्मच जैतून का तेल + 15 ग्राम मक्खन डालें। बिना भीड़भाड़ के 3-4 बैचों में काम करते हुए, सूखे बीफ क्यूब्स को हर तरफ 2-3 मिनट तक भूनें जब तक कि सभी तरफ गहरे भूरे न हो जाएँ — प्रति बैच लगभग 8 मिनट। प्रत्येक बैच को एक ट्रे में स्थानांतरित करें। बर्तन के तले से चिपकी हुई गहरे रंग की फॉन्ड स्वाद का आधार है — इसे छोड़ दें।. सोफ्रिटो + फ्लाम्बे: आँच को मध्यम कर दें। बर्तन में 250 ग्राम कटा हुआ प्याज + 250 ग्राम गाजर के टुकड़े डालें। नरम होने लगने तक 5 मिनट पकाएँ। 4 कटे हुए लहसुन + 2 बड़े चम्मच टमाटर पेस्ट हिलाएँ और 1 मिनट पकाएँ। 2 बड़े चम्मच कॉन्याक डालें और सावधानी से प्रज्वलित करें (लपटें 30 सेकंड में मर जाती हैं)। या फ्लाम्बे छोड़ दें और बस कॉन्याक को डीग्लेज़ के रूप में जोड़ें।. ब्रेज़ का निर्माण करें: सब्जियों पर 3 बड़े चम्मच आटा छिड़कें और कच्चे स्वाद को पकाने के लिए 1 मिनट हिलाएँ। बचाई हुई वाइन को हिलाते हुए धीरे-धीरे डालें, फॉन्ड को उठाने के लिए तले को खुरचें। 200 मिली बीफ स्टॉक + बुके गार्नी + 1.5 छोटा चम्मच नमक + 1 छोटा चम्मच काली मिर्च डालें। बीफ + लार्डन को बर्तन में वापस डालें — तरल को सब कुछ मुश्किल से ढकना चाहिए।. धीमी ब्रेज़: हल्की उबाल पर लाएँ। ढक्कन को थोड़ा खुला रखकर ढकें और 160 °C ओवन में 2.5-3 घंटे के लिए स्थानांतरित करें (या स्टोवटॉप पर सबसे कम आँच पर उबालें), हर 45 मिनट में हिलाते हुए, जब तक कि बीफ टूटकर अलग होने वाला नर्म न हो जाए और सॉस चम्मच को ढकने वाली चमकदार समृद्धि में गाढ़ा न हो जाए। बुके गार्नी को त्याग दें।. पर्ल प्याज + मशरूम गार्निश: एक अलग कड़ाही में, मध्यम आँच पर 15 ग्राम मक्खन पिघलाएँ। 250 ग्राम छिले हुए पर्ल प्याज + 1 बड़ा चम्मच पानी + 1 छोटा चम्मच चीनी + एक चुटकी नमक डालें, ढककर 15 मिनट पकाएँ, फिर खोलकर 5 मिनट तक चमकदार और सुनहरा होने तक भूनें। उसी कड़ाही में, और 15 ग्राम मक्खन और 250 ग्राम मशरूम डालें, 2 बैचों में 6-8 मिनट तक गहरे सुनहरे भूरे होने तक भूनें — कड़ाही को कभी न भरें।. इकट्ठा करें और परोसें: पर्ल प्याज + मशरूम को ब्रेज़ में मिला दें। एक साथ 5 मिनट गर्म करें। चखें और नमक समायोजित करें। ब्रेज़ को आँच से उतारकर 10 मिनट के लिए आराम दें — स्वाद नाटकीय रूप से गहरे होते हैं। उबले हुए नए आलू (या मक्खन वाले अंडे के नूडल्स) पर गहरी प्लेटों में उदार हिस्से परोसें, सॉस को पोंछने के लिए कुरकुरे बैगेट के साथ, कटे हुए ताज़े अजमोद के साथ छिड़के। हमेशा अगले दिन बेहतर — स्वाद रातभर शादी कर लेते हैं। उसी बरगंडी की एक बोतल पीएँ जिसके साथ आपने पकाया है।.","en":"Place 1.5 kg cubed beef in a non-reactive bowl with the 750 ml red Burgundy, 1 chopped onion, 1 chopped carrot, 4 garlic cloves, the bouquet garni and 1 tsp pepper, then cover and refrigerate for 12-24 hours; drain through a sieve while reserving the wine, and pat the beef very dry with paper towel so it sears rather than steams. In a heavy Dutch oven over medium heat, cook 200 g lardons for 6-8 minutes until crisp and golden and the fat is fully rendered, then lift them out with a slotted spoon and leave 2 tbsp of rendered fat behind in the pot. Raise the heat to high and add 1 tbsp olive oil plus 15 g butter, then sear the dried beef cubes in 3-4 uncrowded batches for 2-3 minutes per side (about 8 minutes per batch) until deeply browned on all sides; transfer each batch to a tray and leave the dark fond stuck to the pot as your flavour base. Reduce the heat to medium, add 250 g diced onion and 250 g carrot chunks and cook 5 minutes until starting to soften, then stir in 4 minced garlic cloves and 2 tbsp tomato paste and cook 1 minute; pour in 2 tbsp Cognac and ignite carefully (the flames die in 30 seconds), or skip the flambe and simply use the Cognac to deglaze. Sprinkle 3 tbsp flour over the vegetables and stir for 1 minute to cook out the raw taste, then pour in the reserved wine slowly while scraping the bottom to lift the fond, add 200 ml beef stock, the bouquet garni, 1.5 tsp salt and 1 tsp pepper, and return the beef and lardons to the pot so the liquid barely covers everything. Bring to a gentle simmer, cover with the lid slightly ajar and transfer to a 160 °C oven (or simmer on the lowest stovetop heat) for 2.5-3 hours, stirring every 45 minutes until the beef is fall-apart tender and the sauce has thickened to a glossy coats-the-spoon consistency; discard the bouquet garni. In a separate skillet, melt 15 g butter over medium heat, add 250 g peeled pearl onions with 1 tbsp water, 1 tsp sugar and a pinch of salt, cover and cook 15 minutes, then uncover and brown 5 minutes until glossy and golden; in the same skillet add another 15 g butter and 250 g mushrooms and saute 6-8 minutes in 2 batches until deeply golden brown, never crowding the pan. Fold the pearl onions and mushrooms into the braise and warm together 5 minutes, then taste and adjust the salt and let the braise rest 10 minutes off the heat so the flavours deepen; serve generous portions in deep plates over boiled new potatoes (or buttered egg noodles), scatter with chopped fresh flat-leaf parsley and offer crusty baguette to mop up the sauce -- it is always better the next day, and pairs perfectly with a bottle of the same Burgundy you cooked with."}},{"id":179,"servings":2,"tipType":"veg","pairingsType":"middle-eastern","origin":{"hi":"ट्यूनीशिया","en":"Tunisia","ro":"Tunisia"},"name":{"hi":"चक्चूका","en":"Chakchouka","ro":"Chakchouka"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["कमरे के तापमान पर 4 बड़े अंडे","4 बड़े चम्मच एक्स्ट्रा-वर्जिन जैतून का तेल (ट्यूनीशियाई या भूमध्यसागरीय)","1 मध्यम पीला प्याज (~150 ग्राम), बारीक कटा हुआ","2 हल्के लाल शिमला मिर्च (~300 ग्राम), बीज निकाले हुए और 1 सेमी क्यूब्स में कटे हुए","1 छोटी लाल मिर्च बारीक कटी हुई या 1 छोटा चम्मच ट्यूनीशियाई हरीसा पेस्ट (अधिक पारंपरिक विकल्प)","4 लहसुन की कलियाँ, बारीक कटी हुई","1 छोटा चम्मच पिसा हुआ जीरा (kamoun) — गर्म मसाले का आधार","1 छोटा चम्मच पिसी हुई शाह जीरा/अजवायन सादा (karwiya) — ट्यूनीशिया का परिभाषित गर्म मसाला, समान दिखने के बावजूद जीरे जैसा नहीं; उपलब्ध न हो तो सौंफ के बीज से बदलें","1 छोटा चम्मच मीठी पपरिका","0.5 छोटा चम्मच पिसा हुआ धनिया","400 ग्राम कैन कुचले हुए टमाटर (या 4 पके टमाटर छिले और कद्दूकस किए हुए)","गाढ़ापन के लिए 1 बड़ा चम्मच टमाटर पेस्ट","1 छोटा चम्मच नमक + 0.5 छोटा चम्मच ताज़ी पिसी काली मिर्च + अम्लता संतुलित करने के लिए एक चुटकी चीनी","60 ग्राम फेटा-शैली पनीर (ट्यूनीशियाई या बल्गेरियाई शैली, टुकड़ों में, वैकल्पिक) + ताज़ा फ्लैट-लीफ अजमोद + धनिया + नींबू के टुकड़े + परोसने के लिए ताज़ी बैगुएट या ट्यूनीशियाई khobz tabouna"],"en":["4 large eggs at room temperature","4 tbsp extra-virgin olive oil (Tunisian or Mediterranean)","1 medium yellow onion (~150 g), finely diced","2 mild red bell peppers (~300 g), seeded and cut into 1 cm dice","1 small red chili finely chopped OR 1 tsp Tunisian harissa paste (the more traditional choice)","4 garlic cloves, minced","1 tsp ground cumin (kamoun) — the warm spice base","1 tsp ground caraway (karwiya) — Tunisia's DEFINING warm spice, NOT the same as cumin despite looking similar; substitute fennel seed if unavailable","1 tsp sweet paprika","0.5 tsp ground coriander","400 g can crushed tomatoes (or 4 ripe tomatoes peeled and grated)","1 tbsp tomato paste for body","1 tsp salt + 0.5 tsp freshly ground black pepper + a pinch of sugar to balance acidity","60 g feta-style cheese (Tunisian or Bulgarian-style, crumbled, optional) + fresh flat-leaf parsley + cilantro + lemon wedges + fresh baguette or Tunisian khobz tabouna to serve"],"ro":["4 ouă mari la temperatura camerei","4 linguri ulei de măsline extravirgin (tunisian sau mediteranean)","1 ceapă galbenă medie (~150 g), tăiată mărunt","2 ardei graşi roşii blânzi (~300 g), curăţaţi de seminţe şi tăiaţi în cuburi de 1 cm","1 ardei iute roşu mic tocat mărunt SAU 1 linguriţă pastă de harissa tunisiană (alegerea mai tradiţională)","4 căţei de usturoi, tocaţi mărunt","1 linguriţă chimion măcinat (kamoun) — baza de mirodenii calde","1 linguriţă chimen măcinat (karwiya) — mirodenia caldă DEFINITORIE a Tunisiei, NU acelaşi lucru cu chimionul deşi arată asemănător; înlocuieşte cu sămânţă de fenicul dacă nu este disponibil","1 linguriţă boia dulce","0.5 linguriţă coriandru măcinat","400 g roşii zdrobite la cutie (sau 4 roşii coapte decojite şi rase)","1 lingură pastă de roşii pentru corp","1 linguriţă sare + 0.5 linguriţă piper negru proaspăt măcinat + un vârf de zahăr pentru echilibrul acidităţii","60 g brânză tip feta (tunisiană sau bulgărească, sfărâmată, opţional) + pătrunjel proaspăt cu frunza lată + coriandru + felii de lămâie + baghetă proaspătă sau khobz tabouna tunisian pentru servire"]},"howIsMade":{"hi":"सुगंधित सामग्री तैयार करें: chakchouka जल्दी पकती है — mise-en-place गैर-परक्राम्य है। 150 ग्राम प्याज + 300 ग्राम लाल शिमला मिर्च + 1 लाल मिर्च काटें। 4 लहसुन कलियाँ बारीक काटें। मसाला चौकड़ी — जीरा + शाह जीरा + पपरिका + धनिया — एक छोटे कटोरे में मापें। शाह जीरा ही इसे ट्यूनीशियाई बनाता है और इज़राइली या लेवेंटाइन शकशुका नहीं।. तेल गर्म करें: एक भारी 24 सेमी कड़ाही में (कास्ट आयरन आदर्श है — मिट्टी का तेजीन सबसे पारंपरिक ट्यूनीशियाई है) मध्यम आँच पर 4 बड़े चम्मच जैतून का तेल चमकने तक गर्म करें।. SOFFRITTO: एक चुटकी नमक के साथ 150 ग्राम कटा हुआ प्याज डालें और बहुत नरम और पारदर्शी होने तक 6–8 मिनट पकाएँ — भूरा नहीं। ट्यूनीशियाई chakchouka धीरे-धीरे पसीना बहाए प्याज की मिठास चाहती है, कारमेलाइज़ेशन नहीं।. शिमला मिर्च + मिर्च + लहसुन: 300 ग्राम कटी हुई लाल शिमला मिर्च + 1 कटी लाल मिर्च (या 1 छोटा चम्मच हरीसा) डालें। शिमला मिर्च नरम होने तक लेकिन फिर भी चमकीली लाल रहने तक 6–8 मिनट पकाएँ। 4 बारीक कटी हुई लहसुन डालें और सुगंधित होने तक 1 मिनट पकाएँ।. मसालों को खिलाएँ: मसाला मिश्रण (1 छोटा चम्मच जीरा + 1 छोटा चम्मच शाह जीरा + 1 छोटा चम्मच पपरिका + 0.5 छोटा चम्मच धनिया) सीधे गर्म तेल-और-सब्जी के आधार में डालें। 30 सेकंड तक तीव्रता से सुगंधित होने तक हिलाएँ — जलाएँ नहीं, अन्यथा व्यंजन कड़वा हो जाएगा।. सॉस बनाएँ: 1 बड़ा चम्मच टमाटर पेस्ट मिलाएँ और 1 मिनट पकाएँ। 400 ग्राम कुचले टमाटर + 1 छोटा चम्मच नमक + 0.5 छोटा चम्मच काली मिर्च + एक चुटकी चीनी डालें। कभी-कभी हिलाते हुए 8–10 मिनट सिमर करें, जब तक सॉस गाढ़ी न हो जाए — सतह पर खींची गई चम्मच को एक स्पष्ट निशान छोड़ना चाहिए जो तुरंत वापस नहीं भरता।. अंडे डालें: एक चम्मच के पीछे से, सिमर हो रही सॉस में 4 कुएँ बनाएँ। प्रत्येक कुएँ में 1 अंडा फोड़ें — जर्दी को बरकरार रखें। सफेदी पर एक चुटकी नमक और जर्दी पर काली मिर्च का एक मोड़ छिड़कें। कड़ाही को ढक्कन से ढकें और मध्यम-कम आँच पर 4–6 मिनट पकाएँ, जब तक सफेदी बस सेट हो जाए लेकिन जर्दी बहती रहे — ढक्कन से देखें; सफेदी अपारदर्शी होनी चाहिए और जर्दी अभी भी चमकीली नारंगी और कांपती हुई।. खत्म करें और परोसें: ऊपर 60 ग्राम कुचला फेटा + एक उदार मुट्ठी कटा अजमोद और धनिया छिड़कें। पैन को सीधे मेज़ पर लाएँ — chakchouka हमेशा सांप्रदायिक होती है, कड़ाही से खाई जाती है। प्रत्येक भोजनकर्ता ताज़ी बैगुएट या khobz tabouna का एक टुकड़ा फाड़ता है और इसका उपयोग सॉस को पोंछने और एक जर्दी तोड़ने के लिए करता है। अपने हिस्से पर एक नींबू का टुकड़ा निचोड़ें। पकाने के 10 मिनट के भीतर सबसे अच्छा, जब तक जर्दी अभी भी पिघली हुई है।.","en":"PREP THE AROMATICS: chakchouka cooks fast — mise-en-place is non-negotiable; dice 150 g onion + 300 g red bell peppers + 1 red chili; mince 4 garlic; measure the spice quartet — cumin + caraway + paprika + coriander — into a small bowl; the caraway is what makes this Tunisian and not Israeli or Levantine shakshuka. WARM THE OIL: heat 4 tbsp olive oil in a heavy 24 cm skillet (cast iron is ideal — earthenware tagine is the most traditional Tunisian) over medium heat until shimmering. SOFFRITTO: add 150 g diced onion with a pinch of salt and cook 6–8 min until very soft and translucent — NOT browned; tunisian chakchouka wants the sweetness of slowly-sweated onions, not caramelization. PEPPERS + CHILI + GARLIC: add 300 g diced red bell peppers + 1 chopped red chili (or 1 tsp harissa); cook 6–8 min until peppers are softened but still bright red; add 4 minced garlic and cook 1 min until fragrant. BLOOM THE SPICES: add the spice mix (1 tsp cumin + 1 tsp caraway + 1 tsp paprika + 0.5 tsp coriander) directly into the hot oil-and-vegetable base; stir 30 seconds until intensely aromatic — do not burn, or the dish turns bitter. BUILD THE SAUCE: stir in 1 tbsp tomato paste and cook 1 min; pour in 400 g crushed tomatoes + 1 tsp salt + 0.5 tsp pepper + a pinch of sugar; simmer 8–10 min, stirring occasionally, until the sauce has thickened — a spoon dragged through the surface should leave a clear trail that does not immediately fill back in. ADD EGGS: with the back of a spoon, make 4 wells in the simmering sauce; crack 1 egg into each well — keep yolks intact; sprinkle a pinch of salt over the whites and a twist of pepper over the yolks; cover the skillet with a lid and cook over medium-low heat 4–6 min, until the whites are just set but the yolks remain runny — peek through the lid; the whites should be opaque and the yolks still bright orange and trembling. FINISH AND SERVE: scatter 60 g crumbled feta + a generous handful of chopped parsley and cilantro over the top; bring the pan straight to the table — chakchouka is always communal, eaten from the skillet; each diner tears off a piece of fresh baguette or khobz tabouna and uses it to mop up the sauce and break into a yolk; squeeze a lemon wedge over your own portion; best within 10 minutes of cooking, while the yolks are still molten."}},{"id":180,"origin":{"hi":"जापान","en":"Japan","ro":"Japonia"},"name":{"hi":"ओकोनोमियाकी","en":"Okonomiyaki","ro":"Okonomiyaki"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"japanese","ingredients":{"hi":["200 ग्राम मैदा (या केक आटा)","240 मिली ठंडा दाशी स्टॉक (या पानी + 1 छोटी चम्मच दाशी पाउडर)","2 बड़े अंडे","400 ग्राम पत्तागोभी, बारीक कटी हुई","200 ग्राम पतली कटी सूअर की पेट की परत (बुता बारा), 5 सेमी टुकड़ों में","2 बड़े चम्मच तेंकासु (टेम्पुरा के टुकड़े, वैकल्पिक)","½ छोटी चम्मच बेकिंग पाउडर","4 बड़े चम्मच जापानी मेयोनीज़ (क्यूपी)","4 बड़े चम्मच ओकोनोमियाकी सॉस (ओटाफुकु)","1 छोटी चम्मच वॉर्सेस्टरशायर सॉस","काट्सुओबुशी परोसने के लिए","आओनोरी पाउडर परोसने के लिए"],"en":["200g plain flour (or cake flour)","240ml cold dashi stock (or water + 1 tsp dashi powder)","2 large eggs","400g white cabbage, finely shredded","200g thinly sliced pork belly (buta bara), cut into 5 cm pieces","2 tbsp tenkasu (tempura scraps, optional)","½ tsp baking powder","4 tbsp Japanese mayonnaise (Kewpie)","4 tbsp okonomiyaki sauce (e.g. Otafuku brand)","1 tsp Worcestershire sauce","katsuobushi (dried bonito flakes) to serve","aonori (powdered seaweed) to serve"],"ro":["200g făină albă simplă (sau făină pentru prăjituri)","240ml supă dashi (rece; sau apă + 1 linguriță pudră dashi)","2 ouă mari","400g varză albă, tăiată fin","200g burta de porc feliată subțire (buta bara), tăiată în bucăți de 5 cm","2 linguri tenkasu (firimituri de tempura, opțional)","½ linguriță praf de copt","4 linguri maioneză Kewpie (japoneză)","4 linguri sos okonomiyaki (ex. Otafuku)","1 linguriță sos Worcestershire","katsuobushi (fulgi de ton uscat), pentru servire","aonori (alge marine pudră), pentru servire"]},"howIsMade":{"hi":"एक बड़े कटोरे में मैदा, बेकिंग पाउडर, अंडे और ठंडा दाशी स्टॉक मिलाएं — ज़्यादा न फेंटें। कटी पत्तागोभी और तेंकासु को स्पेटुला से धीरे से मिलाएं; बैटर गाढ़ा होना चाहिए। नॉन-स्टिक पैन मध्यम आंच पर गर्म करें, थोड़ा तेल लगाएं। बैटर डालें और 2 सेमी मोटी गोल आकार बनाएं। सूअर की पेट की परत के टुकड़े पूरी सतह पर रखें। मध्यम-धीमी आंच पर 5–6 मिनट पकाएं जब तक किनारे सख्त न हों और नीचे सुनहरा न हो। दो स्पेटुला से सावधानी से पलटें, हल्का दबाएं; 5–6 मिनट और पकाएं जब तक मांस कुरकुरा न हो। मांस वाली तरफ ओकोनोमियाकी सॉस लगाएं, क्यूपी मेयोनीज़ जिग-ज़ैग में डालें, काट्सुओबुशी और आओनोरी छिड़कें।","en":"In a large bowl whisk together flour, baking powder, eggs, and cold dashi until just combined — do not overmix. Fold in shredded cabbage and tenkasu with a spatula; the batter should be thick and mounded with cabbage. Heat a non-stick pan over medium heat, brush with a thin layer of oil. Pour batter into the pan and shape into a disc about 2 cm thick. Lay pork belly slices over the entire top surface. Cook 5–6 minutes on medium-low until the edges look set and the underside is golden-brown. Flip carefully using two spatulas, pressing lightly; cook another 5–6 minutes until pork is crisp and batter is cooked through. Brush the pork side with okonomiyaki sauce, drizzle Kewpie in a zigzag, scatter katsuobushi and aonori. Serve immediately from the pan."}},{"id":181,"servings":2,"tipType":"meat","timeMins":{"total":780,"active":120},"pairingsType":"japanese","origin":{"hi":"जापान","en":"Japan","ro":"Japonia"},"name":{"hi":"टोंकोत्सु रामेन","en":"Tonkotsu Ramen","ro":"Ramen Tonkotsu"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"hi":["1.2 किलो सूअर के मज्जा की हड्डियां, उबाली हुई","300 ग्राम ताज़ा पतले रामेन नूडल्स","3 बड़े चम्मच गहरी सोया सॉस (तारे के लिए)","2 बड़े चम्मच मिरिन","200 ग्राम चाशू सूअर की पेट की परत, 1 सेमी मोटी स्लाइस में कटी","2 नरम उबले रामेन अंडे, आधे कटे","80 ग्राम बांस की कोंपलें (मेन्मा), छानी हुई","2 नोरी की पत्तियां, आधी कटी","2 हरे प्याज़, बारीक कटे","4 लहसुन की कलियां, कुचली हुई","30 ग्राम ताज़ा अदरक, छीला और कटा","1 छोटी चम्मच भुना तिल का तेल"],"en":["1.2kg pork marrow bones, blanched","300g fresh thin ramen noodles","3 tbsp dark soy sauce (for tare)","2 tbsp mirin","200g chashu pork belly, sliced 1cm thick","2 soft-boiled ramen eggs, halved","80g bamboo shoots (menma), drained","2 sheets nori, halved","2 spring onions, thinly sliced","4 cloves garlic, crushed","30g fresh ginger, peeled and sliced","1 tsp toasted sesame oil"],"ro":["1,2 kg oase de porc (măduvă), opărite","300g tăiței ramen proaspeți subțiri","3 linguri sos de soia închis (pentru tare)","2 linguri mirin","200g burtă de porc chashu, feliată la 1 cm grosime","2 ouă ramen fierte moale, tăiate în jumătate","80g lăstari de bambus (menma), scurși","2 foi alge nori, tăiate în jumătate","2 cepe verzi, feliate subțire","4 căței usturoi, zdrobiți","30g ghimbir proaspăt, curățat și feliat","1 linguriță ulei de susan prăjit"]},"howIsMade":{"hi":"सूअर की हड्डियों को उबलते पानी में 10 मिनट उबालें, छानें और ठंडे पानी से धोएं। एक बड़े बर्तन में 3 लीटर ठंडे पानी के साथ डालें, तेज उबाल लाएं और 10–12 घंटे तक उसी तरह उबालते रहें — धीमी आंच पर सफेद शोरबा नहीं बनेगा। पानी कम हो तो और डालें। सूअर की पेट की परत को कसकर रोल करें, डोरी से बांधें, सूखे पैन में सभी तरफ से भूनें, फिर 3 बड़े चम्मच सोया सॉस, 2 बड़े चम्मच मिरिन, 1 बड़ा चम्मच सेक और 100 मिली पानी में धीमी आंच पर 90 मिनट पकाएं। 20 मिनट आराम दें, 1 सेमी मोटी स्लाइस काटें। तारे: 4 बड़े चम्मच सोया सॉस + 2 बड़े चम्मच मिरिन, 3 मिनट उबालें, ठंडा करें। नूडल्स पकाएं, छानें। हर कटोरे में 2 बड़े चम्मच तारे डालें, 400 मिली गर्म शोरबा डालें, फिर चाशू, आधा अंडा, बांस की कोंपलें, नोरी, हरा प्याज़ लगाएं और तिल का तेल छिड़कें।","en":"Blanch pork bones in boiling water for 10 minutes, drain and rinse under cold water. Transfer to a large pot with 3L cold water, bring to a rolling boil and hold it there — not a simmer — for 10 to 12 hours, topping up with water as needed; the hard boil breaks down collagen and turns the broth white. Roll pork belly tightly, tie with kitchen string, sear all sides in a dry pan, then braise in 3 tbsp soy sauce, 2 tbsp mirin, 1 tbsp sake and 100ml water on the lowest heat for 90 minutes; rest 20 minutes, slice 1cm thick. Make tare: 4 tbsp soy sauce + 2 tbsp mirin, simmer 3 minutes, cool. Cook noodles per packet, drain. Spoon 2 tbsp tare into each bowl, ladle 400ml hot broth, then top with chashu slices, halved egg, bamboo shoots, nori and spring onion. Finish with sesame oil."}},{"id":182,"servings":2,"tipType":"meat","timeMins":{"total":360,"active":90},"pairingsType":"japanese","origin":{"hi":"जापान","en":"Japan","ro":"Japonia"},"name":{"hi":"शोयू रामेन","en":"Shoyu Ramen","ro":"Ramen Shoyu"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"hi":["1.5 लीटर चिकन हड्डी का स्टॉक","2 बड़े चम्मच सोया सॉस","1 बड़ा चम्मच मिरिन","1 बड़ा चम्मच सेक","400 ग्राम सूअर की पेट की परत, रोल करके रसोई की डोरी से बंधी","4 बड़े अंडे","300 ग्राम ताज़ा रामेन नूडल्स","100 ग्राम बांस की कोंपलें (मेन्मा), धोई हुई","4 नोरी की पत्तियां","3 हरे प्याज़, बारीक कटे","4 नारूटोमाकी मछली केक की स्लाइस","1 छोटी चम्मच तिल का तेल"],"en":["1.5L chicken bone stock","2 tbsp soy sauce","1 tbsp mirin","1 tbsp sake","400g pork belly, rolled and tied with kitchen string","4 large eggs","300g fresh ramen noodles","100g bamboo shoots (menma), rinsed","4 sheets nori","3 spring onions, thinly sliced","4 slices narutomaki fish cake","1 tsp sesame oil"],"ro":["1,5 L supă de oase de pui","2 linguri sos de soia","1 lingură mirin","1 lingură sake","300g burtă de porc, rulată și legată","4 ouă mari","300g tăiței ramen proaspeți","100g lăstari de bambus (menma), clătiți","4 foi alge nori","3 cepe verzi, feliate subțire","4 felii pastă de pește narutomaki","1 linguriță ulei de susan"]},"howIsMade":{"hi":"चिकन हड्डी के स्टॉक को 5 सेमी अदरक, 3 लहसुन की कलियां और 2 हरे प्याज़ के साथ 3–4 घंटे उबालें, छानें। सोया सॉस, मिरिन और सेक को एक छोटे बर्तन में मिलाएं, 5 मिनट उबालें ताकि अल्कोहल उड़ जाए — यह शोयू तारे है। सूअर की पेट की परत को कसकर रोल करें, डोरी से बांधें, सूखे पैन में सभी तरफ से भूनें, फिर 3 बड़े चम्मच सोया, 2 मिरिन, 1 सेक और 100 मिली पानी में धीमी आंच पर 1.5 घंटे पकाएं; 15 मिनट आराम दें, 1 सेमी मोटी स्लाइस काटें। अंडों को ठीक 6.5 मिनट उबालें, ठंडे पानी में ठंडा करें, छीलें और चाशू के बचे शोरबे में कम से कम 4 घंटे भिगोएं। नूडल्स पकाएं, छानें। हर कटोरे में शोयू तारे 2 बड़े चम्मच डालें, गर्म शोरबा डालें, फिर चाशू, आधा अंडा, बांस की कोंपलें, नोरी, हरा प्याज़, नारूटोमाकी लगाएं और तिल का तेल छिड़कें।","en":"Simmer chicken bone stock with a 5cm piece of ginger, 3 garlic cloves and 2 spring onions for 3–4 hours, strain and discard solids. Mix soy sauce, mirin and sake in a small pan, simmer 5 minutes to cook off the alcohol — this is the shoyu tare. Roll pork belly tightly, tie with kitchen string, sear on all sides in a hot pan, then braise in 3 tbsp soy sauce, 2 tbsp mirin, 1 tbsp sake and 100ml water on low heat for 1.5 hours; rest 15 minutes before slicing into 1cm rounds. Soft-boil eggs exactly 6.5 minutes, cool in cold water, peel and submerge in the remaining chashu braising liquid for at least 4 hours. Cook noodles per packet, drain; ladle hot broth into bowls (2 tbsp shoyu tare per bowl), add noodles and top with sliced chashu, halved egg, bamboo shoots, nori, spring onions, narutomaki and a drizzle of sesame oil."}},{"id":183,"servings":2,"tipType":"def","pairingsType":"japanese","origin":{"hi":"जापान","en":"Japan","ro":"Japonia"},"name":{"hi":"मिसो रामेन","en":"Miso Ramen","ro":"Ramen Miso"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"hi":["1.5 लीटर चिकन या सूअर की हड्डी का शोरबा","3 बड़े चम्मच लाल या सफेद मिसो पेस्ट","300 ग्राम ताज़ा रामेन नूडल्स","150 ग्राम सूअर का क़ीमा","80 ग्राम डिब्बाबंद मकई के दाने, छाने हुए","1 बड़ा चम्मच नमक रहित मक्खन","60 ग्राम बांस की कोंपलें, छानी और कटी हुई","2 नरम उबले मैरिनेड रामेन अंडे, आधे कटे","2 नोरी की पत्तियां, आधी कटी","2 हरे प्याज़, कटे हुए","1 छोटी चम्मच भुने तिल","80 ग्राम ताज़ा अंकुरित दाने, उबाले हुए"],"en":["1.5L chicken or pork bone broth","3 tbsp red or white miso paste","300g fresh ramen noodles","150g ground pork","80g canned corn kernels, drained","1 tbsp unsalted butter","60g bamboo shoots, drained and sliced","2 soft-boiled ramen eggs, halved","2 sheets nori, halved","2 spring onions, sliced","1 tsp toasted sesame seeds","80g fresh bean sprouts, blanched"],"ro":["1,5L supă de oase de pui sau porc","3 linguri pastă miso roșu sau alb","300g tăiței ramen proaspeți","150g carne tocată de porc","80g porumb din conservă, scurs","1 lingură unt nesărat","60g lăstari de bambus, scurși și feliați","2 ouă fierte moale, marinate, tăiate în jumătate","2 foi alge nori, tăiate în jumătate","2 cepe verzi, feliate","1 linguriță semințe de susan prăjit","80g muguri de fasole proaspeți, opăriți"]},"howIsMade":{"hi":"एक वोक में तेज़ आंच पर लहसुन और सूअर के क़ीमे को भूनें, मांस को तोड़ते हुए जब तक कोई गुलाबी रंग न रहे। मिसो पेस्ट डालें और 60 सेकंड तक भूनें जब तक थोड़ा गहरा न हो जाए। गर्म शोरबा डालें और हल्के उबाल पर रखें — मिसो डालने के बाद तेज़ उबाल न आने दें वरना किण्वित स्वाद खो जाएगा। मक्खन डालें और पिघलने तक हिलाएं। नूडल्स अलग से पकाएं, छानें। नूडल्स को दो कटोरों में बांटें, मिसो शोरबा डालें। मकई, अंकुरित दाने, मैरिनेड अंडा, बांस की कोंपलें, नोरी और हरा प्याज़ लगाएं। अंत में तिल छिड़कें।","en":"Sauté garlic and ground pork in a wok over high heat, breaking up the meat as it cooks, until no pink remains. Add miso paste and stir-fry 60 seconds until it darkens slightly. Pour in hot broth and bring to a low simmer — do not boil hard once miso is in or it loses its fermented edge. Add butter and stir until melted. Cook noodles per packet, drain. Divide noodles between two bowls, ladle miso broth over. Top with corn, bean sprouts, halved ramen egg, bamboo shoots, nori and spring onion. Scatter sesame seeds last."}},{"id":184,"servings":4,"tipType":"def","pairingsType":"japanese","nutrition":{"cal":480,"prot":22,"carb":38,"fat":26,"fib":3},"origin":{"hi":"जापान","en":"Japan","ro":"Japonia"},"name":{"hi":"टेम्पुरा","en":"Tempura","ro":"Tempura"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["400 ग्राम बड़े झींगे (8–12 सिर सहित, छिलका उतारा हुआ पर पूंछ बाकी), नस निकालकर पूरी तरह सुखाए","1 छोटा जापानी शकरकंद (~200 ग्राम), छीलकर 5 मिमी मोटे गोल टुकड़े","200 ग्राम कबोचा कद्दू, छिलके सहित 5 मिमी अर्धचंद्राकार","1 जापानी बैंगन, तिरछा 1 सेमी मोटे टुकड़ों में","6 ताज़े शीताके मशरूम, डंठल हटाकर सिर पर X आकार का काट","100 ग्राम शिशितो या पतली हरी मिर्च, हर एक में कांटे से छेद ताकि फट न जाए","बैटर के लिए (तलने से ठीक पहले अंत में मिलाएं): 1 बड़ा अंडा, 250 मिली बर्फीला ठंडा सोडा वाटर, 150 ग्राम छाना हुआ मैदा","बैटर में डुबोने से पहले टुकड़ों पर लगाने के लिए 30 ग्राम अतिरिक्त मैदा","गहरी तलाई के लिए 1.5 लीटर तटस्थ तेल (राइस ब्रान या वनस्पति)","टेन्सूयू डिप के लिए: 200 मिली दाशी, 60 मिली सोया सॉस, 60 मिली मिरिन","30 ग्राम डाइकोन, बारीक कद्दूकस कर हल्का निचोड़ा हुआ","10 ग्राम ताज़ा अदरक, बारीक कद्दूकस","बारीक समुद्री नमक और नींबू के टुकड़े, परोसने के लिए"],"en":["400 g large prawns (8–12 head-on, peeled but tails on), deveined and patted bone-dry","1 small Japanese sweet potato (~200 g), peeled and cut into 5 mm rounds","200 g kabocha squash, cut into 5 mm half-moons (skin left on)","1 Japanese eggplant, cut on the bias into 1 cm slices","6 fresh shiitake mushrooms, stems trimmed, caps scored with an X","100 g shishito or thin green peppers, each pricked with a fork so they don't burst","For the batter (mix LAST, just before frying): 1 large egg, 250 ml ice-cold sparkling water, 150 g plain (cake) flour, sifted","30 g extra plain flour for dusting the pieces before dipping","1.5 L neutral oil for deep-frying (rice bran or vegetable)","For the tentsuyu dipping sauce: 200 ml dashi, 60 ml soy sauce, 60 ml mirin","30 g daikon, finely grated and lightly squeezed","10 g fresh ginger, finely grated","Fine sea salt and lemon wedges, to serve"],"ro":["400 g creveți mari (8–12 bucăți cu cap, decojiți dar cu coadă), curățați de vinișor și șterși bine de umiditate","1 cartof dulce japonez mic (~200 g), curățat și tăiat rondele de 5 mm","200 g dovleac kabocha, tăiat semilune de 5 mm (cu coajă)","1 vânătă japoneză, tăiată oblic în felii de 1 cm","6 ciuperci shiitake proaspete, fără picioare, capul crestat în X","100 g ardei shishito sau ardei verzi subțiri, fiecare înțepat cu furculița ca să nu plesnească","Pentru aluat (se amestecă LA FINAL, chiar înainte de prăjit): 1 ou mare, 250 ml apă minerală foarte rece, 150 g făină simplă cernută","30 g făină simplă suplimentară pentru pudrat bucățile înainte de înmuierea în aluat","1.5 L ulei neutru pentru prăjit (de orez sau vegetal)","Pentru sosul tentsuyu: 200 ml dashi, 60 ml sos de soia, 60 ml mirin","30 g daikon, ras fin și stors ușor","10 g ghimbir proaspăt, ras fin","Sare fină de mare și felii de lămâie, pentru servit"]},"howIsMade":{"hi":"झींगों और सब्ज़ियों को पूरी तरह सुखाएं, फिर हर झींगे की नीचे की तरफ तीन हल्के कट लगाएं और रीढ़ के साथ हल्का दबाएं ताकि वे तलते समय मुड़ने के बजाय सीधे रहें।\n\nटेन्सूयू के लिए दाशी, सोया सॉस और मिरिन को थोड़ी देर उबलने दें ताकि अल्कोहल उड़ जाए, फिर छोटी-छोटी कटोरियों में बांटें और कद्दूकस की डाइकोन और अदरक पास में रखें।\n\nभारी बर्तन में तेल को 175°C तक गरम करें, प्रोब थर्मामीटर से नापते हुए।\n\nतलने से ठीक पहले एक ठंडे कटोरे में अंडे को बर्फीले सोडा वाटर के साथ फेंटें, छाना हुआ मैदा एक बार में डालें और सिर्फ़ पांच से आठ बार चलाएं — बैटर में सूखे मैदे की लकीरें दिखती रहनी चाहिए।\n\nहर टुकड़े पर अतिरिक्त मैदा हल्का सा लगाएं, बैटर में डुबाकर तेल में एक बार में चार-पांच टुकड़े डालें। झींगे और शीताके लगभग 90 सेकंड, बैंगन और कबोचा 2 मिनट, शकरकंद 3 मिनट, शिशितो लगभग 1 मिनट में हो जाते हैं, और परत हाथीदांत-सफ़ेद बनी रहनी चाहिए।\n\nइन्हें कागज़ बिछी जाली पर निकालें और तुरंत परोसें — टेन्सूयू में डाइकोन और अदरक मिलाकर, या सब्ज़ियों पर बारीक नमक और थोड़े नींबू के रस के साथ।","en":"Pat the prawns and vegetables completely dry, then make three shallow cuts on the underside of each prawn and press gently along the spine so they fry straight rather than curling.\n\nFor the tentsuyu, bring the dashi, soy sauce and mirin briefly to a simmer to cook off the alcohol, then divide between small dipping bowls and set the grated daikon and ginger alongside.\n\nHeat the oil in a heavy pot to 175°C, measured with a probe thermometer.\n\nJust before frying, beat the egg into the ice-cold sparkling water in a chilled bowl, tip in the sifted flour all at once and stir only five to eight strokes — the batter should still show streaks of dry flour.\n\nDust each piece lightly with the extra flour, dip into the batter, and slip into the oil four or five at a time; prawns and shiitake take about 90 seconds, eggplant and kabocha 2 minutes, sweet potato 3 minutes, shishito a minute, and the crust should stay pale ivory.\n\nLift onto a wire rack set over paper and serve straight away, with the tentsuyu, daikon and ginger to stir in, or the vegetables with a pinch of fine salt and a squeeze of lemon."}},{"id":185,"servings":4,"tipType":"def","pairingsType":"japanese","nutrition":{"cal":280,"prot":7,"carb":52,"fat":4,"fib":2},"origin":{"hi":"जापान","en":"Japan","ro":"Japonia"},"name":{"hi":"ओनिगिरी","en":"Onigiri","ro":"Onigiri"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"ingredients":{"hi":["500 ग्राम जापानी छोटी-दानेदार चावल (कोशिहिकारी या सुशी चावल)","पकाने के लिए 600 मिली ताज़ा ठंडा पानी (चावल:पानी अनुपात ~1:1.1)","तेज़ू (हाथ के पानी) के लिए: 200 मिली गुनगुना पानी + 1.5 छोटा चम्मच बारीक समुद्री नमक","4 भुने हुए नोरी की पत्तियां, नोरी की लंबाई × लगभग 3 सेमी चौड़ी पट्टियों में कटी","भरावन 1 — टूना मेयो: 80 ग्राम छने हुए डिब्बाबंद टूना, 1.5 बड़े चम्मच जापानी मेयोनेज़, ½ छोटा चम्मच सोया सॉस","भरावन 2 — उमेबोशी: 60 ग्राम बीज रहित नमकीन बेर, कांटे से हल्का मसला हुआ","भरावन 3 — शिओज़ाके (नमकीन ग्रिल्ड सालमन): 100 ग्राम ग्रिल्ड सालमन फ़िलेट, बिना छिलके, टुकड़ों में","भरावन 4 — ओकाका: 8 ग्राम बोनिटो फ्लेक्स + 1 छोटा चम्मच सोया सॉस मिलाकर","बिना भरावन वाले ओनिगिरी के लिए: बाहर लपेटने के लिए 2 बड़े चम्मच फुरिकाके (चावल मसाला)","वैकल्पिक: ऊपर कुछ तिल छिड़कें"],"en":["500 g Japanese short-grain rice (Koshihikari or sushi rice)","600 ml fresh cold water for cooking (rice to water ratio ~1:1.1)","For the tezu (finger water): 200 ml warm water + 1.5 tsp fine sea salt","4 sheets toasted nori, cut into strips about 3 cm wide × the length of the sheet","Filling option 1 — tuna mayo: 80 g canned tuna (drained), 1.5 tbsp Japanese mayonnaise, ½ tsp soy sauce","Filling option 2 — umeboshi: 60 g pitted salted plums, lightly mashed with a fork","Filling option 3 — shiozake (grilled salted salmon): 100 g salmon fillet grilled and flaked, with the skin removed","Filling option 4 — okaka: 8 g bonito flakes mixed with 1 tsp soy sauce","For plain onigiri: 2 tbsp furikake (rice seasoning), to coat the outside","Optional: a few sesame seeds for the surface of plain ones"],"ro":["500 g orez japonez cu bobul scurt (Koshihikari sau orez pentru sushi)","600 ml apă rece proaspătă pentru fiert (raport orez:apă ~1:1.1)","Pentru tezu (apa de mâini): 200 ml apă caldă + 1.5 linguriță sare fină de mare","4 foi de nori prăjit, tăiate fâșii de ~3 cm lățime × lungimea foii","Umplutură opțiunea 1 — ton cu maioneză: 80 g ton la conservă (scurs), 1.5 lingură maioneză japoneză, ½ linguriță sos de soia","Umplutură opțiunea 2 — umeboshi: 60 g prune sărate fără sâmburi, ușor strivite cu furculița","Umplutură opțiunea 3 — shiozake (somon sărat la grătar): 100 g file de somon făcut la grătar, fără piele, fărâmițat","Umplutură opțiunea 4 — okaka: 8 g fulgi de bonito amestecați cu 1 linguriță sos de soia","Pentru onigiri simplu: 2 linguri furikake (condiment pentru orez), pentru exterior","Opțional: câteva semințe de susan pentru exterior"]},"howIsMade":{"hi":"चावल को ठंडे पानी से चार-पांच बार धोएं जब तक पानी लगभग साफ़ न निकले, छन्नी में 20 मिनट छोड़ें, फिर 600 मिली ताज़े पानी के साथ भारी बर्तन या राइस कुकर में पकाएं और पकने के बाद ढक्कन लगा कर 10 मिनट और छोड़ दें।\n\nइस बीच उमेबोशी को कांटे से मसलें, टूना को जापानी मेयोनेज़ के साथ मलाईदार पेस्ट में मिलाएं और ग्रिल्ड सालमन को टुकड़ों में करें — हर ओनिगिरी में लगभग एक बड़ा चम्मच भरावन ही जाती है।\n\nगुनगुने पानी में नमक घोल कर तेज़ू तैयार करें; यह हाथ का पानी है, जो चावल को हथेलियों से चिपकने से रोकता है और बाहरी सतह पर हल्का सा नमक चढ़ाता है।\n\nगरम चावल को एक चौड़ी ट्रे में पलटें, लकड़ी के स्पैचुला से धीरे-धीरे फूलाएं और हाथ से सँभालने भर गरम होने तक ठंडा होने दें।\n\nहथेलियां तेज़ू में भिगोएं, हथेली में लगभग 100 ग्राम चावल लें, बीच में हल्का सा गड्ढा बनाएं, एक बड़ा चम्मच भरावन रखें और चावल को चारों ओर इकट्ठा करें; हाथ को मोड़ कर तीन सपाट सतह वाले त्रिकोण में मज़बूती से दबाएं, पर दबा कर ईंट न बनाएं।\n\nखाने से ठीक पहले हर त्रिकोण के आधार पर एक नोरी की पट्टी लपेटें ताकि शैवाल कुरकुरा रहे; बिना भरावन वाले ओनिगिरी के लिए नोरी की जगह बाहर furikake में लपेटें। कमरे के तापमान पर 4 घंटे के भीतर खाएं।","en":"Rinse the rice in cold water four or five times until the water runs almost clear, drain in a strainer for 20 minutes, then cook with the 600 ml of fresh water in a heavy pot or rice cooker; once cooked, rest off the heat with the lid on for 10 minutes.\n\nWhile the rice rests, mash the umeboshi with a fork, mix the tuna with the Japanese mayonnaise into a creamy paste, and flake the grilled salmon — each onigiri needs only about a tablespoon of filling.\n\nDissolve the salt in the warm water to make the tezu; this is the finger water that keeps the rice from sticking to your palms and lightly salts the outside.\n\nTip the hot rice onto a wide tray, fluff gently with a wooden paddle and let it cool until just warm enough to handle.\n\nWet your palms in the tezu, take about 100 g of rice in your palm, press a hollow in the centre, drop in a tablespoon of filling and gather the rice around it; cup your hand and press into a triangle with three flat faces, firm but not crushed.\n\nWrap a strip of nori around the base of each triangle just before eating so the seaweed stays crisp; for plain onigiri, roll the outside in furikake instead. Eat at room temperature within 4 hours."}},{"id":186,"servings":4,"tipType":"def","pairingsType":"japanese","nutrition":{"cal":360,"prot":36,"carb":8,"fat":18,"fib":1},"origin":{"hi":"जापान","en":"Japan","ro":"Japonia"},"name":{"hi":"याकितोरी","en":"Yakitori","ro":"Yakitori"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["बिना हड्डी, छिलके सहित चिकन थाई 600 ग्राम, 2.5 सेमी क्यूब में कटा","मोटे हरे प्याज़ 6 (या 2 negi), सफ़ेद और हल्के हरे हिस्से 3 सेमी टुकड़ों में (~150 ग्राम)","छोटे बांस के सींक 16 (15 सेमी), ठंडे पानी में 30 मिनट भिगोए","तारे के लिए: 120 मिली डार्क सोया सॉस, 120 मिली मिरिन, 60 मिली साके, 30 ग्राम हल्की भूरी शक्कर","शिओ सींकों के लिए बारीक समुद्री नमक","ग्रिल के लिए तटस्थ तेल 1 छोटा चम्मच","परोसने के लिए शिचिमी तोगाराशी","परोसने के लिए नींबू के टुकड़े"],"en":["600 g boneless, skin-on chicken thighs, cut into 2.5 cm cubes","6 fat spring onions (or 2 negi), white and pale green parts cut into 3 cm pieces (~150 g total)","16 short bamboo skewers (15 cm), soaked in cold water for 30 minutes","For the tare: 120 ml dark soy sauce, 120 ml mirin, 60 ml sake, 30 g light brown sugar","Fine sea salt for the shio skewers","1 tsp neutral oil for the grate","Shichimi togarashi, to serve","Lemon wedges, to serve"],"ro":["600 g pulpe de pui dezosate cu piele, tăiate cuburi de 2.5 cm","6 cepe verzi mari (sau 2 negi), partea albă și verde-deschis tăiată bucățele de 3 cm (~150 g)","16 frigărui scurte de bambus (15 cm), înmuiate în apă rece 30 de minute","Pentru tare: 120 ml sos de soia închis, 120 ml mirin, 60 ml sake, 30 g zahăr brun deschis","Sare fină de mare pentru frigăruile shio","1 linguriță ulei neutru pentru grătar","Shichimi togarashi, pentru servit","Felii de lămâie, pentru servit"]},"howIsMade":{"hi":"चिकन थाई को 2.5 सेमी क्यूब और हरे प्याज़ के सफ़ेद हिस्सों को 3 सेमी टुकड़ों में काटें, फिर बांस के सींकों को 30 मिनट ठंडे पानी में भिगो दें ताकि ग्रिल पर न जलें।\n\nतारे के लिए एक छोटे पैन में सोया सॉस, मिरिन, साके और भूरी शक्कर को लगभग 10 मिनट तक धीमी आंच पर पकाएं जब तक हल्की चाशनी न बन जाए, फिर इसे कमरे के तापमान पर ठंडा होने दें।\n\nसींकें दो शैलियों में लगाएं: नेगिमा में चिकन, प्याज़, चिकन, प्याज़, चिकन एक के बाद एक; मोमो में सिर्फ़ चिकन क्यूब, पास-पास पर दबे हुए नहीं।\n\nएक चारकोल ग्रिल या भारी ग्रिल पैन को तेज़ आंच पर गरम करें और ग्रिल पर हल्का तेल लगाएं।\n\nसींकों को छिलके या ज़्यादा चर्बी वाली तरफ़ नीचे रखें और 3–4 मिनट तक गहरे सुनहरे होने तक ग्रिल करें, फिर पलट कर 2–3 मिनट और पकाएं।\n\nतारे वाली सींकों को ठंडे सॉस में डुबाएं, 30 सेकंड के लिए वापस ग्रिल पर रखें ताकि चमक आ जाए, और एक बार और डुबा कर ग्रिल करें; शिओ सींकों पर आंच से उतरते ही चुटकी भर नमक छिड़कें। तुरंत शिचिमी तोगाराशी और नींबू के साथ परोसें।","en":"Cut the chicken thigh into 2.5 cm cubes and the white parts of the spring onions into 3 cm pieces, then soak the bamboo skewers in cold water for 30 minutes so they don't burn on the grill.\n\nFor the tare, simmer the soy sauce, mirin, sake and brown sugar in a small pan for about 10 minutes until lightly syrupy, then let it cool to room temperature.\n\nThread the skewers in two styles: negima alternates chicken, scallion, chicken, scallion, chicken; momo is just chicken cubes packed close together but not squashed.\n\nHeat a charcoal grill or a heavy grill pan over high heat and lightly oil the grate.\n\nLay the skewers down with the skin or fattiest side first and grill for 3–4 minutes until deep golden, then flip and cook another 2–3 minutes.\n\nFor tare skewers, dip in the cooled sauce, return to the grill for 30 seconds to glaze, then dip and glaze once more; season the shio skewers with a pinch of salt straight off the heat. Serve at once with shichimi togarashi and lemon."}},{"id":187,"servings":4,"tipType":"def","pairingsType":"mexican","nutrition":{"cal":520,"prot":38,"carb":22,"fat":28,"fib":6},"origin":{"hi":"मेक्सिको","en":"Mexico","ro":"Mexic"},"name":{"hi":"मोले पोब्लानो","en":"Mole Poblano","ro":"Mole Poblano"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["मिश्रित सूखी मिर्च 80 ग्राम — 3 अन्चो + 3 मुलाटो + 2 पासिया — डंठल और बीज हटाए हुए","अडोबो में 1 चिपोटले मिर्च और उसकी सॉस 1 बड़ा चम्मच","छिले हुए बादाम 100 ग्राम और कच्ची मूंगफली 80 ग्राम","कच्चे सफ़ेद तिल 30 ग्राम (सजावट के लिए थोड़ा अलग) और किशमिश 60 ग्राम","2 बड़े पके टमाटर, आधे कटे; 1 छोटा सफ़ेद प्याज़, चार टुकड़ों में; बिना छिले लहसुन की 3 कलियाँ","1 दालचीनी का टुकड़ा, 2 लौंग, 1 चक्र फूल और 6 साबुत काली मिर्च","2 मक्के की रोटी (टोर्टिया), टुकड़ों में फाड़ी — पारंपरिक गाढ़ा करने वाला तत्व","मेक्सिकन चॉकलेट 60 ग्राम, टुकड़ों में (या डार्क चॉकलेट 50 ग्राम + दालचीनी 1 छोटा चम्मच + हल्की भूरी शक्कर 1 बड़ा चम्मच)","बिना नमक का चिकन शोरबा 1.2 लीटर, गरम रखा","लार्ड (manteca) 3 बड़े चम्मच या तटस्थ तेल","हड्डी सहित चिकन की 4 जांघें, नमकीन पानी में 25 मिनट पकाकर सुखाई हुई","1 छोटा चम्मच बारीक समुद्री नमक और एक चुटकी शक्कर","परोसने के लिए: पका हुआ सफ़ेद चावल, गरम मक्के की रोटी, ताज़े धनिए के पत्ते"],"en":["80 g mixed dried chiles — 3 ancho + 3 mulato + 2 pasilla — stemmed and seeded","1 chipotle chile in adobo, plus 1 tbsp of its sauce","100 g blanched almonds and 80 g raw peanuts","30 g raw sesame seeds (plus extra to garnish) and 60 g raisins","2 large ripe tomatoes, halved; 1 small white onion, quartered; 3 garlic cloves, unpeeled","1 cinnamon stick, 2 cloves, 1 star anise and 6 black peppercorns","2 corn tortillas, torn into pieces — the traditional thickener","60 g Mexican chocolate, broken up (or 50 g dark chocolate + 1 tsp cinnamon + 1 tbsp light brown sugar)","1.2 L unsalted chicken stock, kept warm","3 tbsp lard (manteca) or neutral oil","4 bone-in chicken thighs, poached in salted water for 25 minutes and patted dry","1 tsp fine sea salt and a small pinch of sugar","To serve: cooked white rice, warm corn tortillas, fresh coriander leaves"],"ro":["80 g de ardei iuți uscați amestecați — 3 ancho + 3 mulato + 2 pasilla — fără codiță și seminţe","1 ardei chipotle în sos adobo, plus 1 lingură din sosul lui","100 g de migdale blanşate și 80 g de arahide crude","30 g de seminţe de susan crude (plus în plus pentru garnitură) și 60 g de stafide","2 roșii mari coapte, tăiate jumătăți; 1 ceapă albă mică, tăiată sferturi; 3 căţei de usturoi, necurăţaţi","1 baton de scorţișoară, 2 cuișoare, 1 stea de anason și 6 boabe de piper negru","2 tortilla de porumb, rupte în bucăţi — îngroșătorul tradiţional","60 g de ciocolată mexicană, fărâmiţată (sau 50 g de ciocolată neagră + 1 linguriţă de scorţișoară + 1 lingură de zahăr brun deschis)","1.2 L de supă de pui nesărată, ţinută caldă","3 linguri de untură (manteca) sau ulei neutru","4 pulpe de pui cu os, fierte în apă sărată 25 de minute și șterse","1 linguriţă de sare fină de mare și un vârf mic de zahăr","Pentru servit: orez alb fiert, tortilla de porumb calde, frunze de coriandru proaspăt"]},"howIsMade":{"hi":"सूखी मिर्चों को एक भारी सूखी कड़ाही में मध्यम आंच पर हर तरफ़ क़रीब 30 सेकंड भूनें जब तक उनकी ख़ुशबू न उठे, फिर एक कटोरे में डालें, गरम पानी से ढक दें और 20 मिनट भीगने दें।\n\nउसी कड़ाही में बादाम, मूंगफली, तिल, किशमिश और साबुत मसालों को छोटे-छोटे हिस्सों में हल्का सुनहरा होने तक भूनें — हर बार लगभग 2 मिनट — और अलग रख लें।\n\nटमाटर के आधे टुकड़े, प्याज़ के टुकड़े और छिलके सहित लहसुन को सीधे आंच पर या तेज़ ब्रॉयलर के नीचे जगह-जगह काला होने तक भूनें, और लहसुन ठंडा होते ही उसका छिलका उतार दें।\n\nमिर्चें छानकर (भिगोने का पानी बचा कर रखें) उन्हें भुनी सब्ज़ियों, चिपोटले और उसकी सॉस, भुने सूखे मेवों और बीजों, किशमिश, मसालों और फटी हुई टोर्टिया के साथ ब्लेंडर में डालें, और लगभग 500 मिली गुनगुना शोरबा मिलाकर एक चिकनी गहरी पेस्ट तैयार करें।\n\nएक भारी बर्तन में लार्ड को मध्यम-तेज़ आंच पर गरम करें, पेस्ट डालें और 10–15 मिनट तक लगातार चलाते रहें; जैसे-जैसे स्वाद आपस में मिलते हैं, mole गहरा, गाढ़ा और चमकदार होता जाता है।\n\nबाकी 700 मिली शोरबा और टूटी हुई चॉकलेट डालें, बार-बार चलाते हुए 30–40 मिनट धीमी आंच पर पकाएं जब तक सॉस चम्मच की पीठ पर अच्छी तरह कोट न करे; नमक और एक छोटी चुटकी शक्कर से स्वाद ठीक करें।\n\nपकी हुई चिकन की जांघें mole में डालें और 10 मिनट और पकाएं ताकि वे सॉस का स्वाद सोख लें।\n\nचिकन को गहरी प्लेटों में रखें, ऊपर भरपूर mole डालें, और बचे हुए तिल, धनिए के पत्ते, सफ़ेद चावल और गरम मक्के की रोटी के साथ परोसें।","en":"Toast the dried chiles in a dry heavy pan over medium heat for about 30 seconds per side until fragrant, then transfer to a bowl, cover with hot water and soak for 20 minutes.\n\nIn the same pan, toast the almonds, peanuts, sesame seeds, raisins and whole spices in small batches until just golden — about 2 minutes each — and set aside.\n\nChar the tomato halves, onion quarters and unpeeled garlic directly over a flame or under a hot broiler until blackened in patches, then peel the garlic once cool enough to handle.\n\nDrain the chiles (keeping the soaking water) and blend them with the charred vegetables, chipotle and its sauce, toasted nuts and seeds, raisins, spices and torn tortillas, adding about 500 ml of warm chicken stock to make a smooth dark paste.\n\nHeat the lard in a heavy pot over medium-high heat, pour in the paste and stir constantly for 10–15 minutes; the mole will darken, thicken and turn glossy as the flavours fry together.\n\nStir in the remaining 700 ml of chicken stock and the broken chocolate, then simmer gently for 30–40 minutes, stirring often, until the sauce coats the back of a spoon; season with the salt and a small pinch of sugar.\n\nSlide the poached chicken thighs into the mole and simmer 10 minutes more so they take on the sauce.\n\nServe the chicken in shallow bowls, ladle generous mole over the top, and finish with the reserved sesame seeds, coriander leaves, white rice and warm corn tortillas on the side."}},{"id":188,"servings":4,"tipType":"def","pairingsType":"mexican","nutrition":{"cal":480,"prot":18,"carb":38,"fat":28,"fib":6},"origin":{"hi":"मेक्सिको","en":"Mexico","ro":"Mexic"},"name":{"hi":"चिलाकीलेस","en":"Chilaquiles","ro":"Chilaquiles"},"category":{"hi":"नाश्ता","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"hi":["एक दिन पुरानी मक्के की रोटियाँ 200 ग्राम, आठ टुकड़ों में कटी (या तैयार totopos)","तलने के लिए तटस्थ तेल 500 मिली (या 4 बड़े चम्मच, कम तेल में तलने के लिए)","साल्सा रोहा के लिए: पके टमाटर 6 (~600 ग्राम), 2 गुआखियो मिर्च + 1 चिले दे अर्बोल (डंठल और बीज हटाए हुए), 1 लहसुन की कली, ½ छोटा सफ़ेद प्याज़","1 छोटा चम्मच बारीक समुद्री नमक और सॉस के लिए 1 बड़ा चम्मच तटस्थ तेल","4 बड़े अंडे, सनी-साइड-अप फ्राई (वैकल्पिक पर पारंपरिक)","100 मिली मेक्सिकन क्रेमा (या दूध से पतला किया खट्टा क्रीम)","ताज़ा क्यूसो फ्रेस्को 80 ग्राम, टुकड़ों में (या नर्म फेटा)","½ छोटा लाल प्याज़, बहुत बारीक कटा","ताज़ा धनिया की एक छोटी मुट्ठी, सिर्फ़ पत्ते","1 पका हुआ एवोकाडो, परोसने से ठीक पहले कटा हुआ","अचारी हलापीन्यो, स्वादानुसार"],"en":["200 g day-old corn tortillas, cut into eighths (or store-bought totopos)","500 ml neutral oil for frying (or 4 tbsp for shallow-frying)","For the salsa roja: 6 ripe tomatoes (~600 g), 2 guajillo chiles + 1 chile de árbol (stemmed and seeded), 1 garlic clove, ½ small white onion","1 tsp fine sea salt and 1 tbsp neutral oil for the salsa","4 large eggs, fried sunny-side-up (optional but classic)","100 ml Mexican crema (or sour cream thinned with milk)","80 g queso fresco, crumbled (or mild feta)","½ small red onion, very thinly sliced","A small handful of fresh coriander, leaves picked","1 ripe avocado, sliced just before serving","Pickled jalapeños, to taste"],"ro":["200 g tortilla de porumb de o zi, tăiate în opt (sau totopos cumpărate)","500 ml ulei neutru pentru prăjit (sau 4 linguri pentru prăjit superficial)","Pentru salsa roja: 6 roșii coapte (~600 g), 2 ardei guajillo + 1 ardei de árbol (fără codiță și semințe), 1 cățel de usturoi, ½ ceapă albă mică","1 linguriță sare fină de mare și 1 lingură ulei neutru pentru salsa","4 ouă mari, ochiuri (opțional dar tradițional)","100 ml crema mexicană (sau smântână subțiată cu lapte)","80 g queso fresco, sfărâmat (sau feta blândă)","½ ceapă roșie mică, tăiată felii foarte subțiri","Un mic mănunchi de coriandru proaspăt, doar frunzele","1 avocado copt, feliat chiar înainte de servit","Jalapeños murați, după gust"]},"howIsMade":{"hi":"एक दिन पुरानी टोर्टिया को आठ टुकड़ों में काटें और 175°C पर सुनहरी और कुरकुरी होने तक तलें — हर बैच लगभग 90 सेकंड — या 4 बड़े चम्मच तेल में हल्की तली करें; जाली पर रखकर तेल छाने और गरम रहते हुए हल्का नमक छिड़कें।\n\nसॉस के लिए गुआखियो और अर्बोल मिर्चों को सूखी कड़ाही में हर तरफ़ 20 सेकंड भूनें जब तक ख़ुशबू न उठे, फिर 10 मिनट गरम पानी में भिगो दें; इस बीच टमाटर, लहसुन और प्याज़ को तेज़ ब्रॉयलर के नीचे या सीधे आंच पर तब तक भूनें जब तक जगह-जगह काले न हो जाएँ।\n\nमिर्चें छानकर भुनी सब्ज़ियों, 1 छोटा चम्मच नमक और थोड़े से भिगोने वाले पानी के साथ चिकनी सॉस बना लें।\n\nचौड़ी कड़ाही में 1 बड़ा चम्मच तेल गरम करें, सॉस डालें और लगभग 5 मिनट तक चलाते हुए पकाएं जब तक रंग गहरा और चमकदार न हो जाए।\n\nकुरकुरी टोर्टिया डालें और मध्यम आंच पर 1–2 मिनट तक सॉस के साथ हल्के हाथों से मिलाएं — उन्हें सॉस सोखनी चाहिए पर थोड़ा करारापन भी बना रहना चाहिए।\n\nतुरंत प्लेट में निकालें, चाहें तो ऊपर सनी-साइड-अप अंडे रखें, क्रेमा डालें और ऊपर से क्यूसो फ्रेस्को, लाल प्याज़, धनिया, एवोकाडो और अचारी हलापीन्यो छिड़कें।","en":"Cut the day-old tortillas into eighths and either deep-fry them at 175°C until golden and crisp, about 90 seconds per batch, or shallow-fry in 4 tablespoons of oil; drain on a rack and salt lightly while still warm.\n\nFor the salsa, toast the guajillo and árbol chiles in a dry pan for 20 seconds per side until fragrant, then soak in hot water for 10 minutes; meanwhile, char the tomatoes, garlic and onion under a hot broiler or directly over a flame until blackened in patches.\n\nDrain the chiles and blend with the charred vegetables, 1 teaspoon of salt and a splash of the chile-soaking water until smooth.\n\nHeat 1 tablespoon of oil in a wide pan, pour in the salsa and simmer for about 5 minutes, stirring, until it deepens in colour and looks glossy.\n\nTip in the crisp tortillas and gently fold them through the salsa over medium heat for a minute or two — they should soak up sauce while keeping some bite.\n\nPlate at once, top with the fried eggs if using, drizzle with crema, and scatter queso fresco, sliced red onion, coriander, avocado and pickled jalapeños over the top."}},{"id":189,"servings":8,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":530,"prot":9,"carb":70,"fat":24,"fib":1},"origin":{"hi":"मेक्सिको","en":"Mexico","ro":"Mexic"},"name":{"hi":"ट्रेस लेचेस केक","en":"Tres Leches Cake","ro":"Tort Tres Leches"},"category":{"hi":"मिठाई","en":"Dessert","ro":"Desert"},"ingredients":{"hi":["5 बड़े अंडे, अलग किए हुए, कमरे के तापमान पर","200 ग्राम बारीक चीनी, फेंटी क्रीम के लिए 30 ग्राम अतिरिक्त","200 ग्राम मैदा और 1 छोटा चम्मच बेकिंग पाउडर, साथ छाने हुए","स्पंज के लिए 1 छोटा चम्मच वनीला एसेंस, क्रीम के लिए ½ छोटा चम्मच","1 कैन (397 ग्राम) मीठा कंडेंस्ड मिल्क","1 कैन (340 ग्राम) इवापोरेटेड मिल्क","200 मिली फुल फैट दूध और 50 मिली क्रीम (तीन-दूध का मिश्रण)","250 मिली ठंडी हेवी क्रीम (फेंटने के लिए), ऊपर छिड़कने के लिए पिसी दालचीनी"],"en":["5 large eggs, separated, at room temperature","200 g caster sugar, plus 30 g for the whipped cream","200 g plain flour and 1 tsp baking powder, sifted together","1 tsp vanilla extract for the sponge, plus ½ tsp for the cream","1 can (397 g) sweetened condensed milk","1 can (340 g) evaporated milk","200 ml whole milk and 50 ml heavy cream (the three-milk soak)","250 ml cold heavy cream for whipping, plus ground cinnamon for dusting"],"ro":["5 ouă mari, separate, la temperatura camerei","200 g zahăr tos, plus 30 g pentru frișcă","200 g făină albă și 1 linguriță praf de copt, cernute împreună","1 linguriță esență de vanilie pentru blat, plus ½ linguriță pentru frișcă","1 cutie (397 g) lapte condensat îndulcit","1 cutie (340 g) lapte evaporat","200 ml lapte integral și 50 ml smântână pentru frișcă (amestec pentru îmbibare)","250 ml smântână rece pentru frișcă (35% grăsime), plus scorțișoară măcinată pentru pudrat"]},"howIsMade":{"hi":"ओवन को 175°C पर पहले से गरम कर लें और 23×33 सेमी की बेकिंग डिश पर मक्खन और मैदा हल्का सा छिड़कें, फिर अंडे की सफ़ेदी में एक चुटकी नमक डालकर हल्के झाग आने तक फेंटें और एक-एक चम्मच करके 100 ग्राम चीनी डालते हुए चमकदार सख़्त चोटी बनने तक फेंटते रहें।\n\nजर्दी, बची 100 ग्राम चीनी और वनीला को 3–4 मिनट तक फेंटें जब तक रंग हलका हो और मात्रा तीन गुनी हो जाए, उसके ऊपर मैदा और बेकिंग पाउडर छानें और स्पैटुला से धीरे से मिलाएँ, फिर मेरंग को तीन हिस्सों में मिलाएँ, हवा को जितना हो सके बचाते हुए।\n\nडिश में डालें, ऊपर समतल करें और 25–30 मिनट तक — रंग गहरा सुनहरा हो जाए और हलके दबाने पर वापस उठ आए — बेक करें, फिर डिश में ही कम से कम 30 मिनट ठंडा होने दें।\n\nएक जग में कंडेंस्ड मिल्क, इवापोरेटेड मिल्क और फुल फैट दूध–क्रीम मिश्रण को एक साथ फेंटें, ठंडे केक को पूरे ऊपर से एक पतले स्किवर से तले तक छेद-छेद कर दें, और तीन-दूध का मिश्रण पूरे सतह पर तीन या चार धीमी बारियों में डालें — पहले तरल बहुत लगेगा, लेकिन स्पंज सब सोख लेगा; ढक कर कम से कम 4 घंटे, बेहतर हो तो रात भर, फ्रिज में रखें।\n\nपरोसने से ठीक पहले ठंडी क्रीम को 30 ग्राम चीनी और बची वनीला के साथ हल्की चोटी बनने तक फेंटें, ठंडे केक पर फैलाएँ और पिसी हुई दालचीनी अच्छी मात्रा में छिड़कें।","en":"Heat the oven to 175°C and butter and flour a 23×33 cm baking dish, then whisk the whites with a pinch of salt to soft peaks, beating in 100 g of the sugar a spoonful at a time until glossy and stiff.\n\nWhip the yolks with the remaining 100 g sugar and the vanilla for 3–4 minutes until pale and tripled, sift the flour and baking powder over them and fold in gently, then fold in the meringue in three additions, keeping as much air as you can.\n\nPour into the dish, level the top and bake 25–30 minutes until deep golden and springy at the centre, then cool in the dish for at least 30 minutes.\n\nWhisk the three milks together in a jug, pierce the cooled cake all over to the base with a thin skewer and pour the mixture across the surface in three or four slow passes — it looks like too much liquid, but the sponge drinks every drop; cover and refrigerate at least 4 hours, ideally overnight.\n\nJust before serving, whip the cold cream with the 30 g sugar and the remaining vanilla to soft peaks, spread it over the chilled cake and dust generously with ground cinnamon."}},{"id":190,"servings":6,"tipType":"fish","pairingsType":"french","nutrition":{"cal":480,"prot":50,"carb":30,"fat":18,"fib":4},"origin":{"hi":"फ़्रांस","en":"France","ro":"Franța"},"name":{"hi":"बूया-बेस","en":"Bouillabaisse","ro":"Bouillabaisse"},"category":{"hi":"मछली","en":"Fish","ro":"Pește"},"ingredients":{"hi":["800 ग्राम भूमध्यसागरीय छोटी पथरीली मछलियाँ (रास्कास, वीवर, रास — स्टॉक के लिए), साफ़ की हुई","1.2 किलो सख़्त भूमध्यसागरीय मछली, टुकड़ों में (रास्कास, मंकफ़िश, जॉन डोरी, कोंगर, गुर्नार्ड — कम से कम चार प्रजातियाँ), छिलके सहित, छिलके उतार कर","1 बड़ा प्याज़, 2 लीक (केवल सफ़ेद हिस्सा), 1 फेनेल बल्ब, 4 पके टमाटर, 6 लहसुन की कलियाँ","बुके गार्नी: थाइम, तेज़पत्ता, पार्सले के डंठल, सूखे संतरे के छिलके की एक पट्टी, 1 छोटा चम्मच फेनेल बीज","1 ग्राम केसर के रेशे (एक भरी चुटकी), अंत में डाली जाने वाली 2 बड़े चम्मच पास्तिस (Pernod)","100 मिली ज़ैतून का तेल, 1 छोटा चम्मच नमक, ताज़ी पिसी काली मिर्च","2 लीटर पानी (या हलका फ़िश स्टॉक)","12–15 स्लाइस बासी बेगेट टोस्ट और रूई (3 लहसुन की कलियाँ, ½ छोटा चम्मच केसर, ¼ छोटा चम्मच कायेन, 1 अंडे की जर्दी, 200 मिली ज़ैतून का तेल, नमक, स्टॉक में भिगोया एक छोटा सा ब्रेड)"],"en":["800 g small Mediterranean rockfish (rascasse, weever, wrasse — for the broth), gutted","1.2 kg firm Mediterranean fish in chunks (rascasse, monkfish, John Dory, conger, gurnard — at least four species), skin on, scaled","1 large onion, 2 leeks (white parts only), 1 fennel bulb, 4 ripe tomatoes, 6 garlic cloves","Bouquet garni: thyme, bay, parsley stalks, a strip of dried orange peel, a teaspoon of fennel seeds","1 g saffron threads (a generous pinch), 2 tbsp pastis (Pernod) stirred in at the end","100 ml olive oil, 1 tsp salt, freshly ground pepper","2 L water (or light fish fumet)","12–15 slices of toasted day-old baguette and rouille (3 garlic cloves, ½ tsp saffron, ¼ tsp cayenne, 1 egg yolk, 200 ml olive oil, salt, a small piece of bread soaked in the broth)"],"ro":["800 g pești mici mediteraneeni de stâncă (rascassa, năsărel, vrana — pentru fond), eviscerați","1,2 kg pește mediteranean ferm tăiat bucăți (rascassa, lotă, Saint-Pierre, congru, grondin — minim patru specii), cu piele, scuamat","1 ceapă mare, 2 praz (doar partea albă), 1 bulb de fenicul, 4 roșii coapte, 6 căței de usturoi","Buchet garni: cimbru, foi de dafin, codițe de pătrunjel, coajă uscată de portocală, o linguriță de semințe de fenicul","1 g șofran (un vârf bun), 2 linguri de pastis (Pernod) adăugat la final","100 ml ulei de măsline, 1 linguriță sare, piper proaspăt măcinat","2 l apă (sau fumet uşor de pește)","12–15 felii de baghetă uscată prăjită și rouille (3 căței usturoi, ½ linguriță șofran, ¼ linguriță cayenne, 1 gălbenuș, 200 ml ulei de măsline, sare, o bucată de pâine înmuiată în fond)"]},"howIsMade":{"hi":"सारी मछलियों के छिलके उतार, अंदर साफ़ कर के धो लें — बड़ी मछलियों को 3 सेमी के टुकड़ों में काटें, सिर और काँटे स्टॉक के लिए अलग रख दें, छोटी पथरीली मछलियाँ साबुत ही बर्तन में जाती हैं।\n\nएक भारी तले वाले बड़े बर्तन में 4 बड़े चम्मच ज़ैतून का तेल मध्यम आँच पर गरम करें और प्याज़, लीक और फेनेल को बिना रंग दिए 10 मिनट तक भूनें, फिर कटे टमाटर और 5 लहसुन की कलियाँ डालें और 5 मिनट और पकाएँ जब तक गूदा न बन जाए।\n\nछोटी मछलियाँ और बड़ी मछलियों के सिर–काँटे डाल दें, 2 लीटर पानी से ढक दें, बुके गार्नी (थाइम, तेज़पत्ता, पार्सले, संतरे का छिलका, फेनेल बीज) डालें और तेज़ आँच पर 30–40 मिनट तक उबालें जब तक छोटी मछलियाँ पूरी तरह घुल न जाएँ, फिर सब कुछ मोटी छलनी या वेजिटेबल मिल से ज़ोर से दबाते हुए छान लें — काँटे, जड़ी-बूटियाँ और गूदा फेंक दिए जाते हैं — छने हुए स्टॉक को फिर तेज़ उबाल पर लाएँ, नमक देखें और केसर डालें।\n\nपहले सख़्त मछली के टुकड़े (मंकफ़िश, कोंगर) डाल कर 5–6 मिनट पकाएँ, फिर नाज़ुक मछलियाँ (रास्कास, जॉन डोरी) डाल कर 3–4 मिनट और पकाएँ — मछली बस अपारदर्शी होनी चाहिए, कभी टूटे नहीं — और आँच से उतार कर पास्तिस मिला दें।\n\nरूई के लिए, बची हुई लहसुन की कली को ओखली में नमक और केसर के साथ कूट लें, स्टॉक में भिगो कर निचोड़ी हुई ब्रेड डालें, फिर अंडे की जर्दी, और अंत में बहुत पतली धार में ज़ैतून का तेल डालते हुए मेयोनेज़ जैसा गाढ़ा होने तक फेंटें, फिर दो हिस्सों में परोसें — पहले स्टॉक को टोस्ट किए बेगेट के टुकड़ों पर डालें और ऊपर एक चम्मच रूई रखें, उसके बाद मछली को अलग प्लेट में परोसें, साथ में और रूई दें।","en":"Scale, gut and rinse all the fish — cut the larger ones into 3 cm chunks and keep the heads and bones for the broth, while the small rockfish go whole into the pot.\n\nIn a large heavy pot, heat 4 tablespoons of olive oil over medium heat and sweat the chopped onion, leeks and fennel without colour for about 10 minutes, then add the chopped tomatoes and 5 garlic cloves and cook another 5 minutes to a pulp.\n\nTip in the small fish and the heads and bones of the larger ones, cover with the 2 L of water, drop in the bouquet garni (thyme, bay, parsley, orange peel, fennel seeds) and simmer hard for 30–40 minutes until the small fish completely break down, then pass everything through a coarse sieve or food mill, pressing hard to extract every drop — bones, herbs and pulp discarded — bring the strained broth back to a rolling boil, taste for salt and stir in the saffron.\n\nSlip the firm fish (monkfish, conger) into the broth first and poach 5–6 minutes, then add the more delicate ones (rascasse, John Dory) for another 3–4 — they should be just opaque, never falling apart — and off the heat, swirl in the pastis.\n\nFor the rouille, pound the last garlic clove with the salt and saffron in a mortar, work in the bread (dipped in broth and squeezed), then the yolk, then olive oil in a thin stream, whisking constantly until thick like mayonnaise, then serve in two courses: the broth first, ladled over toasted baguette with a spoonful of rouille on top; the fish after, on a separate plate, with more rouille alongside."}},{"id":191,"servings":4,"tipType":"meat","pairingsType":"french","nutrition":{"cal":650,"prot":30,"carb":40,"fat":38,"fib":2},"origin":{"hi":"फ़्रांस","en":"France","ro":"Franța"},"name":{"hi":"क्रोक मसियो","en":"Croque Monsieur","ro":"Croque Monsieur"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"ingredients":{"hi":["8 मोटी स्लाइस पैन डे मी (नर्म सफ़ेद सैंडविच ब्रेड), एक दिन पुरानी","80 ग्राम बिना नमक का मक्खन, नरम किया हुआ; बेशामेल के लिए 30 ग्राम और","200 ग्राम ग्रुयेर या कोम्ते चीज़, बारीक कद्दूकस","4 स्लाइस जाम्बों दे पारी हैम (~120 ग्राम कुल)","2 छोटे चम्मच डिजॉन सरसों","30 ग्राम मैदा और 300 मिली फुल फैट दूध (बेशामेल के लिए)","बारीक समुद्री नमक, सफ़ेद मिर्च, थोड़ा कद्दूकस किया हुआ जायफल"],"en":["8 thick slices of pain de mie (soft white sandwich bread), one day old","80 g unsalted butter, softened, plus 30 g for the béchamel","200 g Gruyère or Comté, finely grated","4 slices of jambon de Paris (~120 g total)","2 tsp Dijon mustard","30 g plain flour and 300 ml whole milk (for the béchamel)","Fine sea salt, white pepper, a grating of nutmeg"],"ro":["8 felii groase de pain de mie (pâine albă fină de sandviș), o zi vechi","80 g unt nesărat, înmuiat, plus 30 g pentru béchamel","200 g Gruyère sau Comté, ras fin","4 felii de jambon de Paris (~120 g în total)","2 lingurițe muștar Dijon","30 g făină albă și 300 ml lapte integral (pentru béchamel)","Sare fină, piper alb, un sfert de nucușoară rasă"]},"howIsMade":{"hi":"बेशामेल के लिए 30 ग्राम मक्खन को छोटे पैन में मध्यम आँच पर पिघलाएँ, मैदा डाल कर 1–2 मिनट तक बिना रंग दिए चलाएँ, फिर गरम दूध को लगातार व्हिस्क करते हुए धीरे-धीरे डालें और मद्धम आँच पर 4–5 मिनट तक, बार-बार चलाते हुए, इतना गाढ़ा कर लें कि चम्मच की पीठ पर चोटी टिक जाए — नमक, सफ़ेद मिर्च और जायफल से स्वाद दें और गरम रखें।\n\nओवन के ऊपर वाला ग्रिल (ब्रॉयलर) तेज़ पर पहले से गरम कर लें, हर ब्रेड स्लाइस के दोनों तरफ़ नर्म मक्खन लगाएँ, और हर सैंडविच में एक स्लाइस के अंदर वाले तरफ़ डिजॉन सरसों की पतली परत लगाएँ।\n\nमक्खन वाला तरफ़ नीचे रख कर 4 स्लाइसें पेपर बिछी ट्रे पर रखें, हर एक पर बारीक कद्दूकस की ग्रुयेर की पतली परत (ऊपर के लिए ~60 ग्राम बचा कर रखें), एक स्लाइस हैम, फिर चीज़ की एक और पतली परत; बची 4 स्लाइसों से सरसों अंदर रख कर ढक दें और हल्के से दबाएँ।\n\nहर सैंडविच पर 2 भरी बड़े चम्मच बेशामेल किनारों तक फैलाएँ — ब्रेड पूरी तरह ढक जाए और सॉस थोड़ा सा बगल से बहे — ऊपर बचा हुआ ग्रुयेर छिड़कें और ट्रे को गरम ब्रॉयलर के नीचे 4–6 मिनट के लिए डालें, ध्यान से देखते रहें, जब तक बेशामेल बुलबुले छोड़े और जगह-जगह गहरा भूरा हो जाए और चीज़ पूरी तरह पिघल जाए — ब्रेड नीचे से, पहले से जमे हुए मक्खन के कारण, कुरकुरी हो जाती है।\n\nबाहर निकालें, 30 सेकंड आराम दें — वरना चीज़ उँगलियों से चिपक जाएगी — और तिरछा काटें; क्रोक मदाम के लिए, सैंडविच ब्रॉयलर में रहते हुए थोड़े मक्खन में एक अंडा फ्राई करें और परोसने से ठीक पहले हर सैंडविच के ऊपर रख दें।","en":"Melt the 30 g béchamel butter in a small saucepan over medium heat, whisk in the flour and cook 1–2 minutes without colouring, then pour the warm milk in gradually while whisking constantly and simmer gently 4–5 minutes, stirring often, until thick enough to hold a peak on the spoon — season with salt, white pepper and nutmeg and keep warm.\n\nPreheat the broiler (top grill) to high, butter both sides of every bread slice with the softened butter, then thinly spread Dijon on the inner face of one slice per sandwich.\n\nLay 4 buttered slices on a lined tray, top each with a thin layer of grated Gruyère (hold ~60 g back for the top), a slice of ham and another thin layer of cheese, then close with the remaining 4 slices, mustard side in, and press lightly.\n\nSpoon 2 heaped tablespoons of béchamel over each sandwich right to the edges so the bread is fully covered and the sauce runs a little down the sides, scatter the reserved Gruyère on top and slide the tray under the hot broiler for 4–6 minutes, watching closely, until the béchamel is bubbling and deeply browned in patches and the cheese is molten — the bread crisps from below from the butter already gripped to its underside.\n\nLift out, rest 30 seconds — the cheese would stick to you otherwise — and cut on the diagonal; for a croque madame, fry an egg in a little butter while the sandwiches are under the broiler and slip it on top just before serving."}},{"id":192,"servings":4,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":420,"prot":13,"carb":60,"fat":14,"fib":1},"origin":{"hi":"फ़्रांस","en":"France","ro":"Franța"},"name":{"hi":"क्रेप","en":"Crêpes","ro":"Crêpes"},"category":{"hi":"मिठाई","en":"Dessert","ro":"Desert"},"ingredients":{"hi":["250 ग्राम मैदा (T45 या T55), छाना हुआ","4 बड़े अंडे, कमरे के तापमान पर","500 मिली फुल फैट दूध (या 350 मिली दूध + 150 मिली पानी, हल्के क्रेप के लिए)","50 ग्राम बिना नमक का मक्खन, सुनहरा भूरा होने तक पिघलाया हुआ (बेर नोवाज़ेट / ब्राउन बटर)","30 ग्राम चीनी और एक भरी चुटकी बारीक नमक","1 बड़ा चम्मच डार्क रम या ऑरेंज-फ़्लावर वॉटर (या 1 छोटा चम्मच वनीला एसेंस)","पैन के लिए अतिरिक्त मक्खन (~30 ग्राम, ब्रश पर रख कर)","परोसने के लिए: बारीक चीनी, नींबू के टुकड़े, इच्छानुसार जैम, नुटेला या केले की स्लाइस"],"en":["250 g plain flour (T45 or T55), sifted","4 large eggs, at room temperature","500 ml whole milk (or 350 ml milk + 150 ml water for lighter crêpes)","50 g unsalted butter, melted until it browns to beurre noisette","30 g sugar and a good pinch of fine salt","1 tbsp dark rum or orange-flower water (or 1 tsp vanilla extract)","Extra butter for the pan (~30 g, kept on a brush)","To serve: caster sugar, lemon wedges, optionally jam, Nutella or sliced banana"],"ro":["250 g făină albă (T45 sau T55), cernută","4 ouă mari, la temperatura camerei","500 ml lapte integral (sau 350 ml lapte + 150 ml apă pentru crêpes mai ușoare)","50 g unt nesărat, topit până devine beurre noisette (alunizat)","30 g zahăr și un vârf bun de sare fină","1 lingură de rom închis sau apă de flori de portocal (sau 1 linguriță extract de vanilie)","Unt în plus pentru ungerea tigăii (~30 g, ținut cu o pensulă)","Pentru servit: zahăr tos, felii de lămâie, opțional gem, Nutella sau banane"]},"howIsMade":{"hi":"50 ग्राम मक्खन को छोटे पैन में मध्यम आँच पर पिघलाएँ और तब तक पकाएँ जब तक उसमें मेवों जैसी ख़ुशबू न आ जाए और रंग गहरा सुनहरा न हो जाए, फिर एक छलनी से छान कर बाउल में डालें और गहरे रंग का तलछट पैन में छोड़ दें — यही beurre noisette (ब्राउन बटर) है, पेस्ट्री-स्तर के क्रेप की पहचान।\n\nएक बड़े बाउल में मैदा और नमक छानें, बीच में एक गड्ढा बनाएँ, उसमें अंडे डालें और एक-तिहाई दूध तथा चीनी मिलाएँ, फिर व्हिस्क से बीच से बाहर की ओर मैदा को धीरे-धीरे खींचते हुए, एक गाढ़ी और चिकनी पेस्ट बनाएँ जिसमें गाँठें न हों, बचा हुआ दूध पतली धार में डालें, और अंत में ठंडा हुआ ब्राउन बटर और रम मिलाएँ; तैयार बैटर तरल क्रीम जैसी गाढ़ाई में होना चाहिए।\n\nबाउल को ढक कर फ्रिज में कम से कम 30 मिनट, बेहतर हो तो 1 घंटा रखें — ग्लूटन बैठ जाता है, और क्रेप रबर जैसे नहीं, पतले और लचीले बनते हैं।\n\n22–24 सेमी की नॉन-स्टिक पैन या crêpière को मध्यम-तेज़ आँच पर गरम करें, ब्रश से मक्खन की एक बहुत पतली परत लगाएँ और ~50 मिली बैटर डालें, तुरंत पैन घुमा कर तले को एक पतले डिस्क में फैला दें, फिर 50–60 सेकंड तक — जब तक किनारे उठने न लगें और नीचे की सतह सुनहरी-जालीदार न हो जाए — पकाएँ, पतले स्पैटुला से पलट दें (या हिम्मत हो तो हल्के झटके से पैन से उछाल कर) और 25–30 सेकंड और पकाएँ, एक प्लेट पर खिसका लें और साफ़ कपड़े से ढक दें — हर एक–दो क्रेप के बाद पैन पर थोड़ा मक्खन लगाते हुए बैटर ख़त्म होने तक दोहराएँ।\n\nगरम परोसें — ऊपर बारीक चीनी छिड़कें, नींबू निचोड़ें, और चार में मोड़ दें — पेरिस की स्ट्रीट-स्टैंड के क्लासिक संस्करण हैं sucre, sucre-citron, फलों का जैम, नुटेला, या केला और नुटेला।","en":"Melt the 50 g of butter in a small saucepan over medium heat and keep cooking until it smells nutty and turns deep gold, then strain into a bowl leaving the dark sediment behind — that's beurre noisette, the signature flavour of bakery-grade crêpes.\n\nSift the flour and salt into a large bowl, make a well in the middle, crack in the eggs and add a third of the milk with the sugar, then whisk from the centre outwards drawing in the flour until you have a thick smooth paste with no lumps, thin with the rest of the milk in a slow stream and finally add the cooled brown butter and the rum; the batter should be the consistency of single cream.\n\nCover and rest the batter in the fridge at least 30 minutes, ideally an hour — the gluten settles and the crêpes turn out thin and flexible rather than elastic.\n\nHeat a 22–24 cm non-stick pan or crêpière over medium-high heat, brush with a very thin film of butter and pour in about 50 ml of batter, immediately swirling so it covers the base in a thin disc, then cook 50–60 seconds until the edges lift and the underside is lacy golden, flip with a thin spatula (or a quick toss of the pan) for another 25–30 seconds, slide onto a plate and cover with a clean cloth — carry on, brushing the pan with a little butter every one or two crêpes, until the batter is gone.\n\nServe warm, scattered with caster sugar and a squeeze of lemon, folded into quarters — the Parisian street-stand alternatives are sucre, sucre-citron, fruit jam, Nutella, or banana with Nutella."}},{"id":193,"servings":8,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":530,"prot":5,"carb":65,"fat":28,"fib":3},"origin":{"hi":"फ़्रांस","en":"France","ro":"Franța"},"name":{"hi":"टार्ट टैटैं","en":"Tarte Tatin","ro":"Tarte Tatin"},"category":{"hi":"मिठाई","en":"Dessert","ro":"Desert"},"ingredients":{"hi":["8–10 सख़्त और थोड़े खट्टे सेब (reine de reinette, golden delicious या honeycrisp), छिले, आधे और गुठली निकले — लगभग 1.5 किलो","150 ग्राम बिना नमक का मक्खन, क्यूब्स में, कमरे के तापमान पर","200 ग्राम सफ़ेद चीनी (क्लासिक तातैं में ब्राउन शुगर इस्तेमाल नहीं होती)","1 बड़ा चम्मच ताज़ा निचोड़ा हुआ नींबू रस","पफ़ पेस्ट्री (pâte feuilletée) का एक डिस्क, ~250 ग्राम, 26 सेमी व्यास और 3 मिमी मोटाई में बेला हुआ","एक चुटकी फ़्लूर दे सेल (समुद्री नमक के क्रिस्टल)","परोसने के लिए: 200 मिली crème fraîche, आइसक्रीम नहीं — सोलोन इलाक़े की परंपरा"],"en":["8–10 firm tart apples (reine de reinette, golden delicious or honeycrisp), peeled, halved and cored — about 1.5 kg","150 g unsalted butter, cut into cubes, at room temperature","200 g white granulated sugar (do not use brown sugar for a classic tatin)","1 tbsp fresh lemon juice","1 round of puff pastry (pâte feuilletée), ~250 g, rolled to 26 cm and 3 mm thick","A pinch of fleur de sel","To serve: 200 ml crème fraîche, not ice cream — the Sologne tradition"],"ro":["8–10 mere ferme și ușor acrișoare (reine de reinette, golden delicious sau honeycrisp), curățate, înjumătățite și fără cotor — în jur de 1,5 kg","150 g unt nesărat, tăiat cuburi, la temperatura camerei","200 g zahăr alb tos (nu se folosește zahăr brun pentru un tatin clasic)","1 lingură suc proaspăt de lămâie","Un disc de aluat de foitaj (pâte feuilletée), ~250 g, rulat la 26 cm diametru și 3 mm grosime","Un vârf de fleur de sel","Pentru servit: 200 ml smântână grasă (crème fraîche), nu înghețată — tradiția din Sologne"]},"howIsMade":{"hi":"सेबों को नींबू रस से मिलाएँ ताकि वो काले न पड़ें, 22–24 सेमी की मोटे तले वाली ओवन-सेफ़ पैन (या टार्ट टैटैं डिश) में 50 ग्राम मक्खन मध्यम आँच पर पिघलाएँ, ऊपर से चीनी एक समान परत में फैलाएँ और बिना हिलाए तब तक रहने दें जब तक चीनी पूरी तरह घुल कर गहरे एम्बर रंग की कैरामेल न बन जाए — लगभग 8–10 मिनट — क्योंकि हल्के रंग का कैरामेल ओवन में रंग खो देता है और स्वाद फीका रह जाता है।\n\nपैन को आँच से हटाएँ और बचा 100 ग्राम मक्खन क्यूब्स में कैरामेल पर डालें — ज़ोरदार 'चर्र' की आवाज़ आएगी — पैन को घुमाएँ ताकि मक्खन समान रूप से पिघल कर एक चमकदार कैरामेल-बटर सॉस बन जाए, फिर सेब के टुकड़ों को कटी हुई तरफ़ ऊपर रख कर, बीच से बाहर की ओर सर्पिल आकार में कस कर लगाएँ (आ जाएँगे), फिर से मध्यम आँच पर रखें और बिना ढके 25–30 मिनट पकाएँ — बीच-बीच में पैन को टेढ़ा कर के किनारों से कैरामेल को अंदर ले आएँ — जब तक सेब का नीचे का हिस्सा कैरामेल सोख न ले और हल्का मुलायम होने न लगे।\n\nइस बीच ओवन को 200°C पर पहले से गरम कर लें और पफ़ पेस्ट्री को पैन से थोड़ा बड़ा गोल आकार में बेल लें, सेब के नीचे आँच बंद करें और एक-दो मिनट ठंडा होने दें, फिर पेस्ट्री को सेब पर रखें और बची हुई किनारी को पैन के अंदर, सेबों और दीवार के बीच में दबा दें — पलटते वक़्त परत फलों को पकड़ लेगी — और काँटे से पेस्ट्री पर कुछ छेद कर दें।\n\n25–30 मिनट तक बेक करें जब तक पेस्ट्री पूरी सुनहरी न हो जाए और कैरामेल किनारों पर बुलबुले न मारे, फिर ठीक 10 मिनट आराम दें — इतना समय कि कैरामेल बैठ जाए लेकिन सख़्त न हो।\n\nपैन से बड़ी सर्विंग प्लेट को पेस्ट्री पर ढक दें, मोटे कपड़े से पैन को कस कर पकड़ें, और एक निर्णायक हरकत में पलट दें — अगर कोई सेब पैन में फँसा रह जाए, स्पैटुला से उठा कर टार्ट पर वापस रख दें — ऊपर एक चुटकी फ़्लूर दे सेल छिड़कें और गरम परोसें, हर प्लेट पर एक भरा चम्मच crème fraîche के साथ।","en":"Toss the apples with the lemon juice so they don't brown, melt 50 g of the butter in a heavy 22–24 cm oven-safe pan with an ovenproof handle (or a proper tatin pan), scatter the sugar over it in an even layer and leave on medium heat without stirring until the sugar dissolves and caramelises to a deep amber — about 8–10 minutes — because pale caramel bleeds out in the oven and tastes flat.\n\nTake the pan off the heat and drop the remaining 100 g butter in cubes onto the caramel — it will hiss hard — swirl until the butter melts evenly into a glossy buttery sauce, then pack the apple halves cut-side-up, tight against each other in a spiral from the centre outwards (they will fit), return to medium heat and cook uncovered for 25–30 minutes, tilting the pan now and then to catch the caramel from the edges, until the underside of the apples has drunk the caramel and they just start to soften.\n\nMeanwhile heat the oven to 200°C and roll the puff pastry to a disc a little larger than the pan, cut the heat under the apples and let them settle a minute, then drape the pastry over the top and tuck the edges down inside the pan between the apples and the wall — the crust will grip the fruit when you flip — and prick the pastry a few times with a fork.\n\nBake 25–30 minutes until the pastry is fully golden and the caramel bubbles around the edges, then rest exactly 10 minutes — long enough for the caramel to settle without setting hard.\n\nPlace a serving plate wider than the pan over the pastry, hold the pan with a thick cloth and invert in one decisive motion — if any apple stays stuck to the pan, lift it back onto the tart with a spatula — scatter a pinch of fleur de sel over the top and serve warm with a generous spoonful of crème fraîche on each plate."}},{"id":194,"servings":6,"tipType":"soup","pairingsType":"soup","nutrition":{"cal":320,"prot":28,"carb":28,"fat":10,"fib":1},"origin":{"hi":"ग्रीस","en":"Greece","ro":"Grecia"},"name":{"hi":"अवगोलेमोनो","en":"Avgolemono","ro":"Avgolemono"},"category":{"hi":"सूप","en":"Soup","ro":"Supă"},"ingredients":{"hi":["1.5 किलो साबुत चिकन (या 1 किलो हड्डी सहित चिकन जांघें)","2 गाजर, 1 प्याज़, 2 अजवाइन डंठल (शोरबा के लिए)","1 तेज़पत्ता, मुट्ठीभर पार्सले के डंठल, 8 काली मिर्च के दाने","150 ग्राम लंबे दाने वाला चावल (या ओर्ज़ो अगर पसंद हो)","3 बड़े अंडे, कमरे के तापमान पर","2 नींबू का रस (लगभग 80 मिली)","नमक और सफ़ेद मिर्च","ऊपर डालने के लिए ताज़ा डिल या पार्सले"],"en":["1.5 kg whole chicken (or 1 kg bone-in chicken thighs)","2 carrots, 1 onion, 2 celery stalks (for the broth)","1 bay leaf, a handful of parsley stems, 8 black peppercorns","150 g long-grain rice (or orzo if you prefer)","3 large eggs, at room temperature","Juice of 2 lemons (about 80 ml)","Salt and white pepper","Fresh dill or parsley to finish"],"ro":["1,5 kg pui întreg (sau 1 kg pulpe de pui cu os)","2 morcovi, 1 ceapă, 2 tulpini de țelină (pentru fond)","1 frunză de dafin, un mănunchi de codițe de pătrunjel, 8 boabe de piper negru","150 g orez cu bob lung (sau orzo, dacă preferi)","3 ouă mari, la temperatura camerei","Zeama de la 2 lămâi (aproximativ 80 ml)","Sare și piper alb","Mărar sau pătrunjel proaspăt pentru a încheia"]},"howIsMade":{"hi":"एक भारी बर्तन में चिकन रखें, उसके साथ गाजर, प्याज़, अजवाइन, तेज़पत्ता, पार्सले के डंठल और साबुत काली मिर्च डालें, 2.5 लीटर ठंडे पानी से ढक दें और हल्की उबाल पर लाएँ। झाग चम्मच से उठाते रहें, और बिना ढके लगभग 90 मिनट पकाएँ, जब तक मांस हड्डियों से अलग न होने लगे।\n\nचिकन को निकालें, शोरबा छान कर साफ़ बर्तन में डालें और सब्ज़ियाँ अलग कर दें। हड्डियों से मांस उतार लें, छोटे-छोटे टुकड़े करके वापस शोरबे में डालें, फिर से उबाल पर लाएँ और चावल डालें; 15–18 मिनट, चावल नरम होने तक पकाएँ।\n\nएक कटोरे में अंडों को रंग हल्का होने और झाग बनने तक फेंटें, फिर नींबू का रस मिलाते हुए फेंटें। अंडों को टेम्पर करें: एक कप गरम शोरबा अंडों के ऊपर धीरे-धीरे डालें, बिना रुके फेंटते जाएँ, फिर एक कप और, जब तक कटोरा छूने पर गर्म न लगे।\n\nआँच बंद करके यह टेम्पर किया मिश्रण पतली, स्थिर धार में बर्तन में वापस डालें, लगातार चलाते रहें — इसके बाद सूप उबलना नहीं चाहिए, वरना अंडे फट जाएँगे। नमक और सफ़ेद मिर्च ठीक करें और तुरंत परोसें, ऊपर डिल या पार्सले छिड़क कर।","en":"Simmer the chicken in 2.5 L cold water with the carrots, onion, celery, bay leaf, parsley stems and peppercorns. Skim any foam and cook uncovered for about 90 minutes, until the meat falls from the bones.\n\nLift the chicken out, strain the broth into a clean pot and discard the vegetables. Shred the meat off the bones, return it to the broth, bring back to a simmer and stir in the rice; cook 15–18 minutes until tender.\n\nWhisk the eggs in a bowl until light and foamy, then whisk in the lemon juice. Temper them by slowly ladling a cup of hot broth in while whisking, then another, until the bowl is warm to the touch.\n\nOff the heat, pour the tempered eggs back into the pot in a slow steady stream, stirring continuously — never let the soup boil again. Season with salt and white pepper and serve immediately, finished with dill or parsley."}},{"id":195,"servings":4,"tipType":"meat","pairingsType":"mediterranean","nutrition":{"cal":620,"prot":38,"carb":52,"fat":28,"fib":4},"origin":{"hi":"ग्रीस","en":"Greece","ro":"Grecia"},"name":{"hi":"गायरो","en":"Gyros","ro":"Gyros"},"category":{"hi":"दोपहर का खाना","en":"Lunch","ro":"Prânz"},"ingredients":{"hi":["1 किलो पोर्क कंधा, रेशे के विरुद्ध 1 सेमी मोटी पट्टियों में कटा (या बिना हड्डी की चिकन जांघें)","4 लहसुन कलियाँ, बारीक कटी","2 बड़े चम्मच ग्रीक ज़ैतून का तेल","1 बड़ा चम्मच रेड वाइन सिरका","1 बड़ा चम्मच सूखा ऑरगानो (हो सके तो ग्रीक रिगानी)","1 छोटा चम्मच मीठा पपरिका","1 छोटा चम्मच नमक, ½ छोटा चम्मच काली मिर्च","4 बड़ी मुलायम ग्रीक पीटा (बिना जेब वाली फ्लैटब्रेड, पॉकेट पीटा नहीं)","परोसने के लिए: 200 मिली tzatziki, 1 पका टमाटर कटा, ½ लाल प्याज़ बारीक, ऑरगानो, नींबू के टुकड़े, इच्छानुसार फ़्रेंच फ्राइज़"],"en":["1 kg pork shoulder, sliced into 1 cm thick strips against the grain (or boneless chicken thighs)","4 garlic cloves, minced","2 tbsp Greek olive oil","1 tbsp red wine vinegar","1 tbsp dried oregano (Greek rigani if possible)","1 tsp sweet paprika","1 tsp salt, ½ tsp black pepper","4 large soft Greek pitas (the unfilled flatbread, not pocket pita)","To serve: 200 ml tzatziki, 1 ripe tomato sliced, ½ red onion thinly sliced, oregano, lemon wedges, optional French fries"],"ro":["1 kg ceafă de porc, tăiată în fâșii de 1 cm grosime contra fibrei (sau pulpe de pui dezosate)","4 căței de usturoi, tocați","2 linguri ulei de măsline grecesc","1 lingură oțet de vin roșu","1 lingură oregano uscat (rigani grecesc, dacă ai)","1 linguriță boia dulce","1 linguriță sare, ½ linguriță piper negru","4 lipii grecești mari și moi (turtă plată neumplută, nu pita cu buzunar)","Pentru servit: 200 ml tzatziki, 1 roșie coaptă feliată, ½ ceapă roșie tăiată subțire, oregano, felii de lămâie, opțional cartofi prăjiți"]},"howIsMade":{"hi":"एक बड़े कटोरे में लहसुन, जैतून का तेल, सिरका, ओरिगानो, पैपरिका, नमक और काली मिर्च फेंटें, फिर सूअर के मांस की स्ट्राइप्स डालकर हर टुकड़े पर मसाला अच्छी तरह लगाएँ। ढककर कम से कम 3 घंटे, बेहतर हो रात भर मैरीनेट करें।\n\nएक भारी पैन या ग्रिडल को धुआँ उठने तक तेज़ आँच पर गर्म करें। स्ट्राइप्स को एक ही परत में रखें, ज़रूरत हो तो बैच में, और बिना हिलाए हर तरफ़ 2–3 मिनट सेकें, जब तक किनारे गहरे सुनहरे और बीच मुश्किल से पका हो; पैन को न भरें, वरना मांस कैरामेलाइज़ होने की जगह भाप में पकेगा। पकी हुई स्ट्राइप्स को प्लेट पर रखें और अगली बैच पकाएँ।\n\nपिटा ब्रेड एक-एक करके उसी गरम पैन में हर तरफ़ 20 सेकंड गर्म करें, बस इतना कि नरम हो जाएँ। हर पिटा के बीच में एक बड़ा चम्मच भर tzatziki फैलाएँ, गरम मांस ऊपर रखें, टमाटर के कुछ टुकड़े और लाल प्याज़ के छल्ले डालें — और अगर एथेंस की परंपरा निभानी हो, ऊपर मुठ्ठीभर फ्रेंच फ्राइज़ रखें।\n\nकाग़ज़ में कस कर लपेटें, एक सिरा मरोड़ कर बंद कर दें, और तुरंत परोसें — साथ में अतिरिक्त ओरिगानो, नींबू की एक फाँक और बचा हुआ tzatziki।","en":"Whisk the garlic, olive oil, vinegar, oregano, paprika, salt and pepper in a large bowl, add the pork strips and toss until every piece is coated. Cover and marinate at least 3 hours, ideally overnight.\n\nHeat a large heavy skillet or griddle pan over high heat until smoking. Lay the strips down in a single layer, in batches if needed, and sear without moving for 2–3 minutes per side, until the edges are deeply browned and the centre just cooked through; don't crowd the pan or the meat will steam instead of caramelise. Rest each batch on a plate while you cook the next.\n\nWarm the pitas one at a time on the same hot skillet for 20 seconds per side, just until pliable. Spread a heaped tablespoon of tzatziki down the centre of each, lay the hot pork on top, add a few tomato slices and rings of red onion, and — if you're being faithful to Athens — a small handful of French fries on top.\n\nWrap tightly in paper with one end pinched closed, and serve immediately with extra oregano, a wedge of lemon, and the rest of the tzatziki on the side."}},{"id":196,"servings":8,"tipType":"pasta","pairingsType":"mediterranean","nutrition":{"cal":680,"prot":30,"carb":62,"fat":32,"fib":4},"origin":{"hi":"ग्रीस","en":"Greece","ro":"Grecia"},"name":{"hi":"पास्तित्सियो","en":"Pastitsio","ro":"Pastitsio"},"category":{"hi":"पास्ता","en":"Pasta","ro":"Paste"},"ingredients":{"hi":["500 ग्राम पास्तित्सियो नूडल्स (लंबी, ट्यूबलर #2; bucatini अच्छा विकल्प है)","600 ग्राम बीफ़ कीमा (या आधा बीफ़, आधा भेड़)","1 बड़ा प्याज़, बारीक कटा","3 लहसुन कलियाँ, बारीक कटी","400 ग्राम कटे टमाटर (कैन वाले)","2 बड़े चम्मच टमाटर पेस्ट","150 मिली ड्राई रेड वाइन","1 दालचीनी की डंडी, 4 साबुत लौंग, 1 तेज़पत्ता, 1 छोटा चम्मच सूखा ऑरगानो","100 ग्राम Kefalotyri या Pecorino, बारीक कद्दूकस (न मिले तो Parmesan भी चलेगा)","बेशामेल के लिए: 100 ग्राम मक्खन, 100 ग्राम मैदा, 1 लीटर फुल फैट दूध, 4 अंडे की जर्दी, थोड़ा कद्दूकस किया जायफल","नमक, काली मिर्च, ज़ैतून का तेल"],"en":["500 g pastitsio noodles (long, tubular #2; bucatini is a fair substitute)","600 g beef mince (or half beef, half lamb)","1 large onion, finely chopped","3 garlic cloves, minced","400 g chopped tomatoes (canned)","2 tbsp tomato paste","150 ml dry red wine","1 cinnamon stick, 4 whole cloves, 1 bay leaf, 1 tsp dried oregano","100 g Kefalotyri or Pecorino, finely grated (Parmesan works at a pinch)","For the béchamel: 100 g butter, 100 g flour, 1 L whole milk, 4 egg yolks, a grating of nutmeg","Salt and pepper, olive oil"],"ro":["500 g paste tip pastitsio (lungi, tubulare nr. 2; bucatini este o alternativă bună)","600 g carne tocată de vită (sau jumătate vită, jumătate miel)","1 ceapă mare, tocată mărunt","3 căței de usturoi, tocați","400 g roșii tocate (la conservă)","2 linguri pastă de roșii","150 ml vin roșu sec","1 baton de scorțișoară, 4 cuișoare întregi, 1 frunză de dafin, 1 linguriță oregano uscat","100 g Kefalotyri sau Pecorino, ras fin (Parmezan se poate la nevoie)","Pentru béchamel: 100 g unt, 100 g făină, 1 l lapte integral, 4 gălbenușuri, puțină nucușoară rasă","Sare, piper, ulei de măsline"]},"howIsMade":{"hi":"एक भारी पैन में 3 बड़े चम्मच जैतून का तेल गर्म करें और कटे प्याज़ को 8–10 मिनट भूनें, फिर लहसुन डालकर 30 सेकंड भूनें और कीमा डालें। लकड़ी की चम्मच से तोड़ते जाएँ और लगभग 10 मिनट तक गहरा रंग आने तक भूनें। टमाटर पेस्ट डालें, ईंट जैसा रंग आने तक भूनें, फिर वाइन डालकर आधी रह जाने तक उबालें और टमाटर, दालचीनी स्टिक, लौंग, तेज़पत्ता और ओरिगानो डालें। नमक-मिर्च भरपूर डालें और बिना ढके धीमी आँच पर कम से कम 45 मिनट पकाएँ; जोड़ने से पहले साबुत मसाले निकाल दें।\n\nजब तक मीट पक रहा है, बेशामेल बनाएँ: एक चौड़ी कड़ाही में बटर पिघलाएँ, मैदा डालकर बिना रंग बदले 1–2 मिनट भूनें, गुनगुना दूध पतली धार में फेंटते हुए डालें, फिर 5–7 मिनट तक पकाएँ जब तक यह चम्मच की पीठ पर परत बनाए। आँच से हटाकर अंडे की ज़र्दी एक-एक करके मिलाएँ, जायफल और आधी कद्दूकस की चीज़ डालें और स्वादानुसार नमक मिलाएँ।\n\nपास्ता को अच्छी नमकीन पानी में पैकेट के निर्देश से 2 मिनट कम उबालें — बाक़ी ओवन में पकेगा — छानकर बची हुई चीज़ और एक करछुल मीट सॉस के साथ मिला दें ताकि चिपके नहीं।\n\n25×35 सेमी की बेकिंग डिश में पास्ता का आधा हिस्सा एक ही दिशा में बिछाएँ, मीट सॉस समान रूप से फैलाएँ, फिर बाक़ी पास्ता उसी दिशा में ऊपर रखें। बेशामेल ऊपर डालें, सतह बराबर करें और 180°C पर 45–50 मिनट तक सुनहरा और बुलबुलाता हुआ बेक करें।\n\nकाटने से पहले कम से कम 20 मिनट छोड़ दें — गरम काटा तो परतें ढह जाएँगी।","en":"Heat 3 tablespoons of olive oil in a heavy pan and brown the chopped onion for 8–10 minutes, add the garlic for 30 seconds, then crumble in the mince. Break it up with a wooden spoon and let it brown deeply, about 10 minutes. Stir in the tomato paste, fry until brick-red, deglaze with the wine and let it reduce by half before adding the tomatoes, cinnamon stick, cloves, bay leaf and oregano. Season generously and simmer uncovered on low heat for at least 45 minutes; fish out the whole spices before assembling.\n\nWhile the meat cooks, make the béchamel: melt the butter in a wide saucepan, whisk in the flour for a couple of minutes without colour, pour in the warm milk in a slow stream while whisking, then simmer 5–7 minutes until it coats the back of a spoon. Off the heat, beat in the egg yolks one at a time, add the nutmeg and half the grated cheese, and season.\n\nBoil the pasta in well-salted water 2 minutes less than the package says — it'll finish in the oven — drain and toss with the remaining cheese and a ladle of meat sauce so the noodles don't stick.\n\nIn a 25×35 cm baking dish, lay half the pasta in one direction, spread the meat sauce evenly over it, then top with the rest of the pasta aligned the same way. Pour the béchamel over, smooth it level, and bake at 180°C for 45–50 minutes until golden and bubbling.\n\nLet it rest at least 20 minutes before cutting; sliced too hot, the layers collapse."}},{"id":197,"servings":6,"tipType":"veg","pairingsType":"mediterranean","nutrition":{"cal":280,"prot":5,"carb":35,"fat":14,"fib":3},"origin":{"hi":"ग्रीस","en":"Greece","ro":"Grecia"},"name":{"hi":"डोल्मादेस","en":"Dolmades","ro":"Dolmades"},"category":{"hi":"शुरुआती","en":"Appetizer","ro":"Aperitiv"},"ingredients":{"hi":["1 जार (450 ग्राम) सिरके वाली अंगूर की पत्तियाँ, छानी और धुली (या 60 ताज़ी पत्तियाँ, हलकी उबाली)","200 ग्राम लंबे दाने वाला चावल (arborio भी चलेगा)","1 बड़ा प्याज़, बारीक कटा","6 हरे प्याज़ के डंठल, पतले कटे","एक बड़ी मुट्ठी ताज़ा डिल, कटा","एक छोटी मुट्ठी ताज़ा पुदीना, कटा","एक छोटी मुट्ठी फ्लैट लीफ़ पार्सले, कटा","2 नींबू का रस","150 मिली एक्स्ट्रा वर्जिन ज़ैतून का तेल","1 छोटा चम्मच नमक, ताज़ी पिसी काली मिर्च","वैकल्पिक पर पारंपरिक: 1 कद्दूकस किया टमाटर"],"en":["1 jar (450 g) preserved grape leaves, drained and rinsed (or 60 fresh blanched leaves)","200 g long-grain rice (arborio works)","1 large onion, finely chopped","6 spring onions, thinly sliced","A large bunch of fresh dill, chopped","A small bunch of fresh mint, chopped","A small bunch of flat-leaf parsley, chopped","Juice of 2 lemons","150 ml extra-virgin olive oil","1 tsp salt, freshly ground black pepper","Optional but traditional: 1 grated tomato"],"ro":["1 borcan (450 g) de frunze de viță conservate, scurse și clătite (sau 60 de frunze proaspete opărite)","200 g orez cu bob lung (merge și arborio)","1 ceapă mare, tocată mărunt","6 fire de ceapă verde, tăiate subțire","Un mănunchi mare de mărar proaspăt, tocat","Un mănunchi mic de mentă proaspătă, tocată","Un mănunchi mic de pătrunjel cu frunza plată, tocat","Zeama de la 2 lămâi","150 ml ulei de măsline extravirgin","1 linguriță sare, piper negru proaspăt măcinat","Opțional dar tradițional: 1 roșie rasă"]},"howIsMade":{"hi":"चावल को ठंडे पानी में 15 मिनट भिगोकर छान लें। एक चौड़े पैन में 3 बड़े चम्मच जैतून का तेल गरम करें और कटे प्याज़ को रंग आए बिना 8 मिनट तक धीमे से पकाएँ, जब तक वह पारदर्शी न हो जाए। हरे प्याज़, सारी जड़ी-बूटियाँ, छाना हुआ चावल, आधा नींबू का रस और एक भरपूर चुटकी नमक डालें; एक मिनट तक चलाएँ ताकि ख़ुश्बू उभर आए, फिर भरावन को एक प्लेट पर निकालकर कमरे के तापमान तक ठंडा होने दें।\n\nएक अंगूर का पत्ता काम की जगह पर इस तरह रखें कि नसें ऊपर हों और डंठल आपकी ओर हो। डंठल के पास एक भरा हुआ छोटा चम्मच चावल का मिश्रण रखें, नीचे का किनारा भरावन पर मोड़ें, दोनों किनारों को अंदर मोड़ें और छोटे सिगार जैसा कस कर लपेटें। ज़्यादा न भरें — चावल पकते समय फूलता है और बहुत कसकर बंधा हो तो दोल्मा फट जाता है।\n\nभारी बर्तन की तली में फटे या टूटे पत्ते बिछा दें ताकि कुछ चिपके नहीं। बंधे हुए dolmades को सीवन नीचे रखते हुए संकेंद्रित गोल घेरों में, इतने पास-पास जमाएँ कि एक-दूसरे को सहारा दें। ऊपर से बचा जैतून का तेल और नींबू का रस डालें, ठंडा पानी ठीक dolmades की ऊँचाई तक डालें और गर्मी सह सकने वाली प्लेट सीधे ऊपर रखकर डुबा कर रखें।\n\nधीरे-धीरे हल्की उबाल पर लाएँ, ढक दें और सबसे धीमी आँच पर 50 मिनट से 1 घंटा पकाएँ — जब तक चावल नर्म और तरल लगभग सोख न ले। बर्तन में ही ठंडा होने दें — ये ठंडे या कमरे के तापमान पर परोसे जाते हैं, एक नींबू की फाँक और गाढ़े दही के साथ। एक दिन पहले बनाएँ तो स्वाद कहीं बेहतर हो जाता है।","en":"Soak the rice in cold water for 15 minutes and drain. Heat 3 tablespoons of olive oil in a wide pan and sweat the chopped onion for 8 minutes until translucent, no colour. Add the spring onions, all the herbs, the drained rice, half the lemon juice and a generous pinch of salt; stir for a minute to bloom the aromas, then tip onto a plate to cool to room temperature.\n\nLay a grape leaf on the work surface vein-side up, stem at the bottom. Place a heaped teaspoon of the rice mixture near the stem, fold the bottom edge up and over, fold both sides in, and roll up tightly into a small cigar. Don't overfill — the rice swells as it cooks and packed too tightly the dolma will split.\n\nLine the bottom of a heavy pot with torn or broken leaves to prevent sticking. Pack the rolled dolmades in concentric circles, seam-side down, snug enough to hold each other in place. Pour over the remaining olive oil and lemon juice, add cold water just to the top of the dolmades, and press a heatproof plate directly on the surface to keep them submerged.\n\nBring slowly to a simmer, cover, and cook on the lowest heat for 50 minutes to an hour, until the rice is tender and the liquid mostly absorbed. Leave to cool in the pot — they're served cold or at room temperature, with a wedge of lemon and a bowl of thick yoghurt. Made the day before, they taste markedly better."}},{"id":198,"servings":12,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":380,"prot":7,"carb":48,"fat":18,"fib":1},"origin":{"hi":"ग्रीस","en":"Greece","ro":"Grecia"},"name":{"hi":"गालाक्तोबूरेको","en":"Galaktoboureko","ro":"Galaktoboureko"},"category":{"hi":"मिठाई","en":"Dessert","ro":"Desert"},"ingredients":{"hi":["500 ग्राम फ़िलो पेस्ट्री, पिघलाई हुई","200 ग्राम बिना नमक का मक्खन, पिघला हुआ","1 लीटर फुल फैट दूध","200 ग्राम बारीक चीनी (कस्टर्ड के लिए)","150 ग्राम बारीक सूजी","4 बड़े अंडे","1 छोटा चम्मच वनीला एसेंस","1 नींबू का छिलका, कद्दूकस","चाशनी के लिए: 400 ग्राम चीनी, 250 मिली पानी, आधा नींबू का रस, संतरे के छिलके की एक पट्टी, 1 दालचीनी की डंडी"],"en":["500 g phyllo pastry, thawed","200 g unsalted butter, melted","1 L whole milk","200 g caster sugar (for the custard)","150 g fine semolina","4 large eggs","1 tsp vanilla extract","Zest of 1 lemon","For the syrup: 400 g caster sugar, 250 ml water, juice of half a lemon, a strip of orange peel, 1 stick of cinnamon"],"ro":["500 g foi de plăcintă (phyllo), dezghețate","200 g unt nesărat, topit","1 l lapte integral","200 g zahăr tos (pentru cremă)","150 g griș fin","4 ouă mari","1 linguriță extract de vanilie","Coaja rasă de la 1 lămâie","Pentru sirop: 400 g zahăr, 250 ml apă, zeama de la o jumătate de lămâie, o fâșie de coajă de portocală, 1 baton de scorțișoară"]},"howIsMade":{"hi":"चाशनी बहुत पहले से शुरू करें — गरम पाई जब ओवन से निकले तो वो ठंडी होनी चाहिए — एक छोटे बर्तन में चीनी, पानी, नीबू का रस, संतरे का छिलका और दालचीनी मिलाएँ, उबाल पर लाएँ फिर 4 मिनट तक उबालें, आँच से हटा कर पूरी तरह ठंडा करें। कस्टर्ड के लिए, एक चौड़े बर्तन में दूध, चीनी और नीबू के छिलके का बुरादा डाल कर बस-बस भाप उठने तक गरम करें (उबलने न दें), लगातार फेंटते हुए सूजी को एक पतले, एकसमान धार में डालें, फिर धीमी आँच पर 5–6 मिनट और फेंटते रहें जब तक एक ढीली पुडिंग जैसा गाढ़ापन न आ जाए; आँच से हटा कर अंडे एक-एक करके मिलाएँ (मिश्रण गुनगुना होना चाहिए पर इतना गरम नहीं कि अंडे फटें) और वनीला डालें, फिर ऊपर एक परत न बने इसलिए क्लिंगफ़िल्म को सीधे सतह पर दबाएँ। 22×30 सेमी बेकिंग डिश पर पिघले मक्खन से ब्रश करें, तले पर 7 phyllo शीट बिछाएँ, हर एक पर ख़ूब मक्खन ब्रश करें और किनारों को बग़ल से लटकने दें (ये फ़्लैप्स बाद में ऊपर मोड़े जाएँगे), अभी भी गुनगुना कस्टर्ड डालें, उसे एकसमान करें, लटकते फ़्लैप्स अंदर मोड़ें और मक्खन लगाएँ, फिर 7 और phyllo शीट से ढक दें (हर एक पर फिर से मक्खन ब्रश करते हुए) और किनारों को काटें या अंदर डाल दें ताकि पाई पूरी तरह सीलबंद हो। ऊपर वाले phyllo पर तेज़ चाक़ू से हीरे या चौकोर शेप में निशान लगाएँ — पूरा काटें ताकि चाशनी बाद में अंदर जा सके — सतह को बचे मक्खन से उदारता से ब्रश करें, और 170°C पर 45–55 मिनट तक तब तक बेक करें जब तक ऊपर का हिस्सा गहरा सुनहरा-भूरा न हो जाए। ओवन से निकलते ही ठंडी चाशनी को गरम पाई पर एकसमान डालें — वो छनछनाएगी और भाप उठाएगी — कम से कम 4 घंटे, बेहतर रात भर, बैठने दें, फिर निशान वाली रेखाओं के साथ काटें और कमरे के तापमान पर परोसें।","en":"Start the syrup well in advance — it must be cold when the hot pie comes out of the oven — combine the sugar, water, lemon juice, orange peel and cinnamon in a small saucepan, bring to a boil then simmer 4 minutes, take off the heat and leave to cool completely. For the custard, heat the milk in a wide saucepan with the sugar and lemon zest until just steaming (do not let it boil), sprinkle the semolina in a fine even stream while whisking constantly, then keep whisking on low heat for 5–6 minutes until it thickens to a loose pudding; off the heat, beat in the eggs one at a time (the mixture should be warm but not hot enough to scramble them) and the vanilla, then press clingfilm directly onto the surface to stop a skin forming. Brush a 22×30 cm baking dish with melted butter, lay 7 sheets of phyllo across the bottom brushing each generously with butter and letting the edges hang over the sides (those flaps will fold back over the top later), pour in the still-warm custard, smooth it level, fold the overhanging flaps inward and brush them with butter, then cover with another 7 sheets of phyllo (again buttering each) and trim or tuck the edges so the pie is fully sealed. Score the top phyllo into diamonds or squares with a sharp knife — cut all the way through so the syrup can later penetrate — brush the surface lavishly with the last of the butter, and bake at 170°C for 45–55 minutes until the top is deeply golden brown. The moment it comes out of the oven, pour the cold syrup evenly over the hot pie — it will sizzle and steam — leave to settle at least 4 hours, ideally overnight, before cutting along the score lines and serving at room temperature."}},{"id":199,"servings":4,"tipType":"def","pairingsType":"italian","nutrition":{"cal":740,"prot":28,"carb":88,"fat":30,"fib":4},"origin":{"hi":"इटली","en":"Italy","ro":"Italia"},"name":{"hi":"पिज़्ज़ा मार्गेरिटा","en":"Pizza Margherita","ro":"Pizza Margherita"},"category":{"hi":"पिज़्ज़ा","en":"Pizza","ro":"Pizza"},"ingredients":{"hi":["आटे के लिए (4 पिज़्ज़ा): 500 ग्राम 00 आटा (या ब्रेड फ़्लोर), 325 मिली ठंडा पानी, 10 ग्राम नमक, 1 ग्राम ताज़ा खमीर (या ¼ छोटा चम्मच सूखा)","हर पिज़्ज़ा के लिए: 80 ग्राम San Marzano टमाटर (कैन वाले, हाथ से कुचले), एक चुटकी नमक, थोड़ा ज़ैतून का तेल","हर पिज़्ज़ा पर 100 ग्राम fior di latte मोज़रेला, हाथ से तोड़ी हुई (या भैंस के दूध की मोज़रेला)","हर पिज़्ज़ा पर ताज़े तुलसी के कुछ पत्ते","ऊपर डालने के लिए एक्स्ट्रा वर्जिन ज़ैतून का तेल","गोल बनाने और पील के लिए सूजी या मैदा"],"en":["For the dough (4 pizzas): 500 g 00 flour (or bread flour), 325 ml cold water, 10 g salt, 1 g fresh yeast (or ¼ tsp dried)","For each pizza: 80 g San Marzano tomatoes (canned, hand-crushed), a pinch of salt, a drizzle of olive oil","100 g fior di latte mozzarella per pizza, torn into pieces (or buffalo mozzarella)","A few fresh basil leaves per pizza","Extra-virgin olive oil to finish","Semolina or flour for shaping and the peel"],"ro":["Pentru aluat (4 pizza): 500 g făină 00 (sau pentru pâine), 325 ml apă rece, 10 g sare, 1 g drojdie proaspătă (sau ¼ linguriță uscată)","Pentru fiecare pizza: 80 g roșii San Marzano (la conservă, sfărâmate cu mâna), un praf de sare, un fir de ulei de măsline","100 g mozzarella fior di latte per pizza, ruptă în bucățele (sau mozzarella de bivoliță)","Câteva frunze de busuioc proaspăt pentru fiecare pizza","Ulei de măsline extravirgin pentru finalizare","Griș sau făină pentru modelare și pentru lopată"]},"howIsMade":{"hi":"आटे के लिए, ख़मीर को ठंडे पानी में घोलें, फिर आटा और नमक मिलाएँ जब तक एक रूखी सी गुठली न बने, हाथ से 10 मिनट तक (या स्टैंड मिक्सर के dough hook से 6 मिनट) तब तक गूँधें जब तक चिकना और लचीला न हो जाए, ढक कर कमरे के तापमान पर एक घंटा आराम दें, फिर कम से कम 24 घंटे, बेहतर 48 से 72 घंटे फ्रिज में रखें — यह लंबा ठंडा फ़र्मेंटेशन ही नियापोलिटन आटे को वह बबल वाला, जला हुआ किनारा और हवादार बनावट देता है। बेकिंग से दो घंटे पहले, आटा निकालें, 210 g के चार गोले बनाएँ, आटा छिड़कें, गीले कपड़े से ढक कर कमरे के तापमान तक आने दें, इस बीच ओवन को जितना गरम हो सके (250°C या ऊपर) करें, अंदर पिज़्ज़ा स्टोन या भारी स्टील शीट रख कर कम से कम 45 मिनट गरम करें; पिज़्ज़ा के नीचे गंभीर गर्मी के बिना crust समय पर नहीं जमेगा। एक गोले को अच्छे से आटा छिड़की सतह पर हाथ से फैलाएँ — उँगलियों से बीच को दबाएँ, उठा हुआ किनारा छोड़ें, फिर डिस्क को धीरे से खींच कर लगभग 28 सेमी तक फैलाएँ — कभी बेलन का इस्तेमाल न करें, वह crust की गैस की जेबें कुचल देता है — और आटा छिड़की पैडल पर सरकाएँ। 80 g कुचले टमाटर को बीच में रखें और चम्मच के पीछे से spiral में फैलाएँ, किनारे से 2 सेमी पहले रुकें, टमाटर पर हलका नमक छिड़कें, थोड़ा ओलिव ऑयल डालें, और टुकड़े-टुकड़े मोज़रेला ऊपर बिखेर दें (बहुत ज़्यादा नहीं, वर्ना पिज़्ज़ा डूब जाएगा)। पिज़्ज़ा को स्टोन पर सरकाएँ और तब तक बेक करें जब तक crust फूल जाए और कहीं-कहीं काली पड़ जाए, चीज़ पिघल कर पोखर बना ले और किनारा गहरा सुनहरा हो जाए — घरेलू ओवन में पूरी आँच पर 4 से 6 मिनट, लकड़ी से जलने वाले नियापोलिटन ओवन में 90 सेकंड — निकालें, ऊपर तुलसी के पत्ते तोड़ कर डालें (ओवन में जल जाते), अंत में ओलिव ऑयल की एक धार डालें, और तुरंत खाएँ।","en":"For the dough, dissolve the yeast in the cold water then mix in the flour and salt until you have a shaggy mass, knead by hand for 10 minutes (or 6 minutes with a stand mixer and dough hook) until smooth and elastic, cover and rest at room temperature for an hour, then refrigerate for at least 24 hours and ideally 48 to 72 — the long cold proof is what gives Neapolitan dough its blistered char and airy structure. Two hours before baking, take the dough out, divide into four 210 g balls, dust with flour, cover with a damp cloth and let them come to room temperature, meanwhile heat the oven as hot as it goes (250°C or above) with a pizza stone or heavy steel sheet inside for at least 45 minutes; without serious heat under the pizza, the crust will never set in time. Hand-stretch one ball on a well-floured surface — press the centre flat with your fingertips leaving a raised lip, then gently pull and stretch the disc to about 28 cm across — never use a rolling pin, which collapses the gas pockets in the crust — and slide it onto a floured peel. Spoon 80 g of crushed tomato into the centre and spread it in a spiral with the back of the spoon stopping 2 cm from the edge, salt the tomato lightly, drizzle a little olive oil, and scatter the torn mozzarella over the top (not too much, or the pizza floods). Slide the pizza onto the stone and bake until the crust is puffed and charred in spots, the cheese has melted into pools and the rim is dark gold — 4 to 6 minutes in a domestic oven at full blast, 90 seconds in a wood-fired Neapolitan oven — pull it out, tear over the basil leaves (which would scorch in the oven), drizzle a final thread of olive oil, and eat immediately."}},{"id":200,"servings":6,"tipType":"pasta","pairingsType":"italian","nutrition":{"cal":720,"prot":36,"carb":58,"fat":36,"fib":4},"origin":{"hi":"इटली","en":"Italy","ro":"Italia"},"name":{"hi":"लज़ानिए अल्ला बोलोनीज़े","en":"Lasagne alla Bolognese","ro":"Lasagne alla Bolognese"},"category":{"hi":"पास्ता","en":"Pasta","ro":"Paste"},"ingredients":{"hi":["रागू के लिए: 400 ग्राम बीफ़ कीमा, 200 ग्राम पोर्क कीमा, 80 ग्राम पनचेटा बारीक कटी, 1 प्याज़ + 1 गाजर + 1 अजवाइन डंठल सब बारीक कटा, 200 मिली ड्राई रेड वाइन, 400 ग्राम passata या कटे टमाटर, 250 मिली फुल फैट दूध, 1 तेज़पत्ता, नमक और काली मिर्च, ज़ैतून का तेल","बेशामेल के लिए: 80 ग्राम मक्खन, 80 ग्राम मैदा, 1 लीटर फुल फैट दूध, नमक, थोड़ा कद्दूकस जायफल","300 ग्राम ताज़ी अंडे वाली लज़ानिए शीट्स (या 250 ग्राम सूखी, हलकी उबाली हुई)","150 ग्राम Parmigiano Reggiano, बारीक कद्दूकस","डिश पर लगाने के लिए मक्खन"],"en":["For the ragù: 400 g beef mince, 200 g pork mince, 80 g pancetta finely diced, 1 onion + 1 carrot + 1 celery stalk all finely diced, 200 ml dry red wine, 400 g passata or chopped tomatoes, 250 ml whole milk, 1 bay leaf, salt and pepper, olive oil","For the béchamel: 80 g butter, 80 g flour, 1 L whole milk, salt, a grating of nutmeg","300 g fresh egg lasagne sheets (or 250 g dried, blanched)","150 g Parmigiano Reggiano, finely grated","Butter for the dish"],"ro":["Pentru ragù: 400 g vită tocată, 200 g porc tocat, 80 g pancetta tăiată cubulețe, 1 ceapă + 1 morcov + 1 țelină — toate tocate mărunt, 200 ml vin roșu sec, 400 g passata sau roșii tocate, 250 ml lapte integral, 1 frunză de dafin, sare și piper, ulei de măsline","Pentru béchamel: 80 g unt, 80 g făină, 1 l lapte integral, sare, puțină nucușoară rasă","300 g foi proaspete de lasagne cu ou (sau 250 g uscate, opărite)","150 g Parmigiano Reggiano, ras fin","Unt pentru vasul de copt"]},"howIsMade":{"hi":"पैनसेटा को एक भारी बर्तन में ओलिव ऑयल की एक छिड़काव के साथ मध्यम-धीमी आँच पर 5 मिनट तक धीरे-धीरे रेंडर करें जब तक चर्बी साफ़ निकलने न लगे, कटा soffritto (प्याज़, गाजर, अजवाइन डंठल) डालें और 10 मिनट तक तब तक पकाएँ जब तक नर्म हो जाए और किनारे ज़रा सुनहरे हो जाएँ, फिर दोनों कीमे को कुचल कर डालें और अच्छी तरह भूनें — धैर्य: पहले 3 मिनट तक न चलाएँ, फिर तोड़ें और 10 मिनट और पकाएँ जब तक पैन का तला गहराई से कैरेमलाइज़ न हो जाए। शराब डालें, लकड़ी के चम्मच से तले की पपड़ी खुरचें और आधी तक रिड्यूस करें, फिर टमाटर, दूध (बोलोनीज़ की पहचान — यह खटास को गोल करता है और बनावट को कसता है), तेज़पत्ता और 1 छोटा चम्मच नमक डालें; बेहद हलकी उबाल पर लाएँ, आधी ढक कर, और सबसे संभव धीमी आँच पर कम से कम 2 घंटे, बेहतर 3 घंटे पकाएँ, बीच-बीच में चलाते रहें और अगर सूखने का खतरा हो तो थोड़ा पानी डालें — तैयार ragù चमकदार, गहरे भूरे-लाल और लगभग पेस्ट जैसा होना चाहिए, कभी सूप जैसा नहीं। ragù ख़त्म होते-होते béchamel बनाएँ: मक्खन पिघलाएँ, आटे को 2 मिनट तक बिना रंग के फेंटें, गरम दूध को एक धीमी धारा में डालते हुए फेंटें और 5 मिनट तक तब तक उबालें जब तक गाढ़ा न हो जाए, फिर नमक और एक उदार जायफल कद्दूकस से सीज़न करें। अगर सूखी lasagne शीट इस्तेमाल कर रहे हैं तो नमकीन उबलते पानी में 1 मिनट blanch करें और नम कपड़ों पर रखें — ताज़ी शीट कच्ची ही जाती हैं — ओवन को 180°C तक गरम करें और 25×35 सेमी बेकिंग डिश पर मक्खन लगाएँ, फिर तले पर béchamel की एक पतली परत, फिर पास्ता की एक परत, फिर ragù, फिर béchamel, फिर Parmigiano की बर्फ़-जैसी छिड़काव, और तब तक दोहराते रहें जब तक सब ख़त्म न हो जाए (छह-सात परतें बोलोनीज़ का लक्ष्य है), अंत में béchamel और Parmigiano की एक भारी बौछार। 35–40 मिनट तक तब तक बेक करें जब तक ऊपरी भाग कांस्य रंग का और बुलबुलाता हुआ न हो जाए, फिर काटने से पहले 20 मिनट आराम दें — गरम-गरम काटी लसैन्या बिखर जाती है, आराम दी हुई अपनी परतें संभाले रखती है।","en":"Render the pancetta gently in a heavy pot with a splash of olive oil over medium-low heat for 5 minutes until the fat runs clear, add the chopped soffritto (onion, carrot, celery) and cook 10 minutes until soft and just gilded at the edges, then crumble in both meats and brown them properly — patience: do not stir for the first 3 minutes, then break them up and cook 10 more minutes until the pan bottom is deeply caramelised. Pour in the wine, scrape the fond from the pan with a wooden spoon and reduce by half, then add the tomatoes, the milk (the Bolognese signature — it rounds the acid and tightens the texture), the bay leaf and a teaspoon of salt; bring to a bare simmer, partially cover, and cook on the lowest possible heat for at least 2 hours and ideally 3, stirring occasionally and adding a splash of water if it threatens to dry — the finished ragù should be glossy, deep brown-red and almost a paste, never a soup. While the ragù finishes, make the béchamel: melt the butter, whisk in the flour for 2 minutes without colour, pour in the warm milk in a slow stream while whisking and simmer 5 minutes until thick, then season with salt and a generous grating of nutmeg. If using dried lasagne sheets blanch them in salted boiling water for a minute and lay on damp tea towels — fresh sheets go in raw — heat the oven to 180°C and butter a 25×35 cm baking dish, then spread a thin layer of béchamel on the bottom, then a layer of pasta, then ragù, then béchamel, then a snowy dusting of Parmigiano, and repeat until you have used everything (six to seven layers is the Bolognese target), finishing with béchamel and a heavier shower of Parmigiano. Bake 35–40 minutes until the top is bronzed and bubbling, then rest 20 minutes before cutting — lasagne sliced hot slides apart, lasagne rested holds its layers."}},{"id":201,"servings":4,"tipType":"meat","pairingsType":"italian","nutrition":{"cal":580,"prot":42,"carb":18,"fat":32,"fib":3},"origin":{"hi":"इटली","en":"Italy","ro":"Italia"},"name":{"hi":"ओसो बूको अल्ला मिलानेज़े","en":"Osso Buco alla Milanese","ro":"Osso Buco alla Milanese"},"category":{"hi":"मुख्य व्यंजन","en":"Main","ro":"Fel principal"},"ingredients":{"hi":["4 मोटे कटे वील शैंक (3–4 सेमी मोटे, हर एक लगभग 350 ग्राम), घेरे के चारों ओर रसोई के धागे से बंधे","नमक और ताज़ी पिसी काली मिर्च","लपेटने के लिए मैदा","4 बड़े चम्मच बिना नमक का मक्खन, 2 बड़े चम्मच ज़ैतून का तेल","1 प्याज़ + 1 गाजर + 1 अजवाइन डंठल, सभी बारीक कटे","200 मिली ड्राई व्हाइट वाइन","400 ग्राम कटे टमाटर","500 मिली वील या चिकन स्टॉक","1 तेज़पत्ता, थाइम की कुछ टहनियाँ","ग्रेमोलाटा के लिए: 1 नींबू का छिलका, 2 लहसुन कलियाँ बहुत बारीक कटी, एक छोटी मुट्ठी फ्लैट लीफ़ पार्सले बारीक कटी"],"en":["4 thick-cut veal shanks (3–4 cm thick, about 350 g each), tied around the circumference with kitchen string","Salt and freshly ground black pepper","Plain flour for dusting","4 tbsp unsalted butter, 2 tbsp olive oil","1 onion + 1 carrot + 1 celery stalk, all finely diced","200 ml dry white wine","400 g chopped tomatoes","500 ml veal or chicken stock","1 bay leaf, a few sprigs of thyme","For the gremolata: zest of 1 lemon, 2 garlic cloves finely minced, a small bunch of flat-leaf parsley finely chopped"],"ro":["4 rasoluri groase de vițel (3–4 cm grosime, aproximativ 350 g fiecare), legate cu sfoară de bucătărie pe circumferință","Sare și piper negru proaspăt măcinat","Făină albă pentru tăvălit","4 linguri unt nesărat, 2 linguri ulei de măsline","1 ceapă + 1 morcov + 1 țelină, toate tocate mărunt","200 ml vin alb sec","400 g roșii tocate","500 ml fond de vițel sau pui","1 frunză de dafin, câteva fire de cimbru","Pentru gremolata: coaja rasă de la 1 lămâie, 2 căței de usturoi tocați fin, un mănunchi mic de pătrunjel cu frunza plată, tocat fin"]},"howIsMade":{"hi":"शैंक्स को कागज़ से थपथपा कर सुखाएँ — गीला मांस सीयर होने के बजाय भाप बनाता है — नमक और काली मिर्च से ज़ोरदार ढंग से सीज़न करें और हलके आटे में लपेट कर अतिरिक्त झाड़ दें, फिर एक भारी ब्रेज़िंग पैन में मध्यम-तेज़ आँच पर आधा मक्खन और पूरा तेल झाग आने तक गरम करें, शैंक्स को रखें और 4 मिनट तक न छुएँ जब तक नीचे का हिस्सा गहरा भूरा न हो जाए, पलट कर दूसरा साइड करें, फिर एक प्लेट पर निकाल लें। आँच को मध्यम कर दें, बाक़ी मक्खन और soffritto (प्याज़-गाजर-अजवाइन डंठल) डालें, और हलके से 10 मिनट पकाएँ जब तक नर्म और किनारों पर सुनहरा न हो जाए, फिर शराब डालें, आँच बढ़ाएँ, और पैन के तले से कैरेमलाइज़ हुए हिस्सों को खुरचते हुए आधी तक रिड्यूस करें। टमाटर, तेज़पत्ता और थाइम मिलाएँ, शैंक्स को एक परत में पैन में वापस रखें, और मांस की लगभग दो-तिहाई ऊँचाई तक स्टॉक डालें — हड्डियाँ ऊपर खुली रहनी चाहिए ताकि मज्जा अंदर रहे — और बेहद हलकी उबाल पर लाएँ। ढक कर सबसे धीमी आँच पर या 160°C ओवन में 2 से 2½ घंटे तक ब्रेज़ करें, हर 30 मिनट पर शैंक्स को धीरे से पलट कर एकसमान पकने दें — जब चम्मच के दबाव से मांस हड्डी से अलग हो जाए और सॉस चमकदार ग्रेवी में सिमट जाए तब तैयार — फिर सावधानी से निकालें क्योंकि हड्डियाँ और मज्जा इस वक़्त नाज़ुक हैं। शैंक्स के विश्राम के दौरान, नीबू का छिलका, लहसुन और पार्सले मिला कर gremolata बनाएँ, हर प्लेट पर एक शैंक रखें, ऊपर से ख़ूब सॉस डालें, और कच्ची gremolata की एक भरी चुटकी से ताज पहनाएँ — उसका तीख़ापन समृद्धि को काटता है और यही इसे मिलानी osso buco बनाता है, सिर्फ़ ब्रेज़्ड वील नहीं — risotto alla milanese, polenta, या मज्जा के लिए ब्रेड के टुकड़े के साथ परोसें।","en":"Pat the shanks dry — wet meat steams instead of searing — season aggressively with salt and pepper and dust lightly in flour knocking off the excess, then heat half the butter and all the oil in a heavy braising pan over medium-high heat until foaming, lay the shanks in and do not touch them for 4 minutes until the bottom is deeply browned, flip and do the second side, then lift onto a plate. Lower the heat to medium, add the rest of the butter and the soffritto, and cook gently for 10 minutes until soft and golden at the edges, then pour in the wine, raise the heat, and reduce by half while scraping up the caramelised bits from the bottom of the pan. Stir in the tomatoes, bay leaf and thyme, return the shanks to the pan in a single layer, and pour in just enough stock to come about two-thirds of the way up the meat — the bones should stay exposed so the marrow stays in — and bring to a bare simmer. Cover and braise on the lowest heat or in a 160°C oven for 2 to 2½ hours, turning the shanks gently every 30 minutes so they cook evenly — they are done when the meat slumps off the bone at the press of a spoon and the sauce has thickened to a glossy gravy — then lift them out carefully because the bones and marrow are fragile at this point. While the shanks rest, stir together the lemon zest, garlic and parsley to make the gremolata, place a shank on each plate, spoon over plenty of sauce, and crown with a generous pinch of the raw gremolata — its sharpness cuts the richness and is what makes osso buco Milanese rather than just braised veal — serve with risotto alla milanese, polenta, or a piece of bread for the marrow."}},{"id":202,"servings":8,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":540,"prot":9,"carb":42,"fat":36,"fib":1},"origin":{"hi":"इटली","en":"Italy","ro":"Italia"},"name":{"hi":"तिरामिसु","en":"Tiramisu","ro":"Tiramisu"},"category":{"hi":"मिठाई","en":"Dessert","ro":"Desert"},"ingredients":{"hi":["500 ग्राम मस्कारपोने, कमरे के तापमान पर","5 बड़े अंडे, अलग किए हुए, कमरे के तापमान पर","100 ग्राम बारीक चीनी","250 मिली ठंडी तेज़ एस्प्रेसो कॉफ़ी (लगभग 5 शॉट)","2 बड़े चम्मच मीठी मार्साला या डार्क रम (वैकल्पिक, ट्रेविज़ो परंपरा)","300 ग्राम savoiardi (इतालवी फिंगर बिस्कुट — सख़्त वाले, नर्म नहीं)","ऊपर छिड़कने के लिए बिना चीनी का कोको पाउडर","कद्दूकस के लिए डार्क चॉकलेट का एक छोटा टुकड़ा (वैकल्पिक)","अंडे की सफ़ेदी के लिए एक चुटकी नमक"],"en":["500 g mascarpone, at room temperature","5 large eggs, separated, at room temperature","100 g caster sugar","250 ml strong cold espresso (about 5 shots)","2 tbsp Marsala (sweet) or dark rum (optional, traditional in Treviso)","300 g savoiardi (Italian ladyfingers — the firm kind, not the soft kind)","Unsweetened cocoa powder for dusting","A small piece of dark chocolate for shaving (optional)","Pinch of salt for the egg whites"],"ro":["500 g mascarpone, la temperatura camerei","5 ouă mari, separate, la temperatura camerei","100 g zahăr tos","250 ml espresso tare rece (aproximativ 5 ceșcuțe)","2 linguri Marsala dulce sau rom închis (opțional, tradițional la Treviso)","300 g savoiardi (pișcoturi italiene — cele ferme, nu cele moi)","Cacao amară pentru pudrare","O bucățică de ciocolată neagră pentru ras (opțional)","Un praf de sare pentru albușuri"]},"howIsMade":{"hi":"बड़े बाउल में अंडे की पीली ज़र्दी और चीनी को 4–5 मिनट तक — हाथ से या इलेक्ट्रिक बीटर से — तब तक फेंटें जब तक रंग हलका, झागदार और मात्रा नाटकीय रूप से तीन गुनी न हो जाए; जब आप उँगलियों के बीच रगड़ें तो चीनी पूरी तरह घुली होनी चाहिए — यहाँ कम फेंटना बाद में दानेदार तिरामिसु देता है। मस्करपोन को तीन बार में डालें, हर बार धीरे से फेंटते हुए, जब तक क्रीम चिकनी और चमकदार न हो जाए, फिर एक अलग साफ़ बाउल में अंडे के सफ़ेद हिस्से को एक चुटकी नमक के साथ तब तक फेंटें जब तक मज़बूत चमकदार चोटियाँ बनें जो फेंटनी उठाने पर आकार बनाए रखें, और एक बड़ी स्पैटुला से सफ़ेद हिस्से को मस्करपोन में तीन बार में फ़ोल्ड करें, हवा अंदर रखने के लिए केंद्र से बाहर की ओर पलटते हुए — तैयार क्रीम हलकी होनी चाहिए, लगभग बहने योग्य पर नर्म चोटियाँ बनाए रखती। ठंडे एस्प्रेसो और मार्साला को एक उथली डिश में मिलाएँ, फिर savoiardi को एक-एक करके डुबोएँ — बस ज़रा-सा, हर तरफ़ अधिकतम 2 सेकंड — वे स्पंज हैं, और बहुत ज़्यादा भीगे हुए लेडी फ़िंगर्स गाढ़ी लुगदी बन जाते हैं और क्रीम के बीच से रोते हैं, और उन्हें 22×30 सेमी डिश के तले में एक चुस्त परत में रखें। savoiardi पर आधी मस्करपोन क्रीम को एकसमान परत में फैलाएँ, फिर दोहराएँ — और एक चुस्त परत डुबोए हुए savoiardi की, फिर बाकी क्रीम ऊपर से, स्पैटुला से चिकनी की। क्लिंगफ़िल्म से ढक कर कम से कम 6 घंटे, बेहतर हो तो रात भर फ्रिज में रखें — उसी दिन खाया तिरामिसु अपने हिस्सों जैसा स्वाद देता है, रात भर रखा तिरामिसु एक मिठाई जैसा स्वाद देता है — परोसने से ठीक पहले ऊपर महीन छलनी से कोको पाउडर उदारता से छिड़कें, चाहें तो थोड़ी डार्क चॉकलेट कद्दूकस कर लें, और गरम चाक़ू से काटें, हर स्लाइस के बीच पोंछते रहें।","en":"Whisk the egg yolks with the sugar in a large bowl for 4–5 minutes — by hand or with an electric beater — until pale, foamy and dramatically tripled in volume; the sugar should be completely dissolved when you rub a little between your fingers, undermixing here gives you a grainy tiramisu later. Add the mascarpone in three batches, whisking gently after each, until the cream is smooth and glossy, then in a separate clean bowl whisk the egg whites with a pinch of salt to firm glossy peaks that hold their shape when the whisk is lifted, and fold the whites into the mascarpone in three additions with a large spatula, folding from the centre outwards to keep the air in — the finished cream should be light, almost pourable but holding soft peaks. Mix the cold espresso and Marsala in a shallow dish, then dip the savoiardi one at a time — just briefly, 2 seconds per side at most — they are sponges, and oversoaked ladyfingers turn to mush and weep through the cream, and lay them in a tight single layer in the bottom of a 22×30 cm dish. Spread half the mascarpone cream over the ladyfingers in an even layer, then repeat — another tight layer of dipped savoiardi, then the rest of the cream on top, smoothed level with the spatula. Cover with clingfilm and refrigerate at least 6 hours, ideally overnight — tiramisu eaten the same day tastes like its parts, tiramisu rested overnight tastes like one dessert — just before serving dust the top generously with cocoa pushed through a fine sieve, shave over a little dark chocolate if you like, and cut with a hot knife wiped between slices."}},{"id":203,"servings":4,"tipType":"pasta","pairingsType":"italian","nutrition":{"cal":520,"prot":22,"carb":76,"fat":14,"fib":3},"origin":{"hi":"इटली","en":"Italy","ro":"Italia"},"name":{"hi":"काचो ए पेपे","en":"Cacio e Pepe","ro":"Cacio e Pepe"},"category":{"hi":"पास्ता","en":"Pasta","ro":"Paste"},"ingredients":{"hi":["400 ग्राम tonnarelli या मोटे spaghetti","200 ग्राम Pecorino Romano, microplane पर बारीक कद्दूकस (Parmesan नहीं — वो उसी तरह नहीं पिघलता)","1 बड़ा भरा चम्मच साबुत काली मिर्च, ओखली में ताज़ी कूटी हुई (पहले से पिसी नहीं)","पास्ता के पानी के लिए समुद्री नमक (आम से कम — चीज़ ख़ुद नमकीन है)"],"en":["400 g tonnarelli or thick spaghetti","200 g Pecorino Romano, finely grated on a microplane (no Parmesan — it doesn't melt the same way)","1 heaped tablespoon whole black peppercorns, freshly cracked in a mortar (not pre-ground)","Sea salt for the pasta water (less than usual, since the cheese is salty)"],"ro":["400 g tonnarelli sau spaghete groase","200 g Pecorino Romano, ras fin pe microplane (fără Parmezan — nu se topește la fel)","1 lingură plină de boabe întregi de piper negru, proaspăt zdrobite în mojaru (nu măcinat în prealabil)","Sare de mare pentru apa pastelor (mai puțină decât de obicei, fiindcă brânza este sărată)"]},"howIsMade":{"hi":"कुटी हुई काली मिर्च को एक चौड़े सूखे पैन में मध्यम आँच पर 30 सेकंड के लिए तब तक भूनें जब तक उसकी तीखी ख़ुशबू सीधे नाक तक पहुँचने लगे, फिर आधा करछुल ठंडा पानी डालें ताकि पकाना रुके और एक मिर्ची वाला घोल बने। आँच से उतार कर अलग रख दें।\n\n3 लीटर हलके नमक वाले पानी को उबाल पर लाएँ और पास्ता को पैकेट पर लिखे समय से लगभग 1 मिनट कम पकाएँ — al dente से थोड़ा पहले रुकें; रोम में पास्ता बर्तन में नहीं, सॉस में पकना ख़त्म करता है।\n\nजब पास्ता पक रहा हो, बर्तन से एक मग भर स्टार्च वाला पास्ता पानी निकाल लें। एक चौड़े बाउल में, कद्दूकस किया Pecorino उस गरम पास्ता पानी की लगभग 4 बड़े चम्मच के साथ व्हिस्क से मिलाएँ — पानी को पहले कुछ सेकंड ठंडा होने दें, क्योंकि उबलता पानी सीधे चीज़ पर पड़े तो वह तुरंत गुठली बना लेता है — जब तक एक गाढ़ी, रिकोटा जैसी पेस्ट न बन जाए; ज़्यादा सख़्त हो तो एक और चम्मच पानी मिला कर ढीला करें।\n\nपास्ता को टांग से सीधे बर्तन से उस काली मिर्च वाले पैन में डालें (छानें मत), एक करछुल स्टार्च वाला पानी डालें और धीमी आँच पर 30 सेकंड तक ज़ोर से उलट-पुलट करें, जब तक पास्ता चमकीला और अच्छी तरह से कोट न हो जाए।\n\nपैन को आँच से उतार लें — Pecorino उबलने के तापमान से ऊपर तुरंत रेशेदार गुठलियों में सिमट जाता है — फिर चीज़ पेस्ट को ऊपर डालें और तेज़ी से फिर से उलट-पुलट करें, ज़रूरत हो तो एक चम्मच और पास्ता पानी डालते जाएँ, जब तक सॉस एक मलाईदार emulsion न बन जाए जो हर लच्छे से चिपका रहे। तुरंत प्लेट में निकालें, ऊपर एक और बार ताज़ी काली मिर्च पीस कर डालें; cacio e pepe जल्दी ठंडा हो जाता है — इसलिए प्लेटें गरम और खाने वाले मेज़ पर पहले से तैयार होने चाहिए।","en":"Toast the cracked pepper in a wide dry pan over medium heat for 30 seconds — until you can smell it sharply — and add half a ladle of cold water to stop the cooking and create a peppery slurry. Set aside off the heat.\n\nBring 3 L of lightly salted water to a boil and cook the pasta until just shy of al dente, about a minute less than the package says; in Rome the pasta finishes cooking in the sauce, not in the pot.\n\nWhile the pasta cooks, scoop out a mug of starchy water from the pot. In a wide bowl, whisk the grated Pecorino with about 4 tablespoons of the hot pasta water — let it cool a few seconds first, since boiling water on cheese clumps it instantly — until you have a thick, ricotta-like paste; loosen with another spoonful of water if it's too stiff.\n\nLift the pasta from the pot with tongs straight into the peppered pan (don't drain it), splash in a ladle of starchy water, and toss vigorously over low heat for 30 seconds, until the pasta is glossy and well coated.\n\nTake the pan off the heat — Pecorino above boiling point seizes into stringy clumps — pour over the cheese paste and toss again, fast, adding more pasta water by the spoonful if needed, until the sauce becomes a creamy emulsion that clings to every strand. Plate immediately with another crack of pepper on top; cacio e pepe cools quickly, so plates should be warm and diners at the table."}},{"id":204,"servings":4,"tipType":"meat","pairingsType":"indian","nutrition":{"cal":720,"prot":42,"carb":28,"fat":48,"fib":4},"origin":{"hi":"भारत","en":"India","ro":"India"},"name":{"hi":"बटर चिकन (मुर्ग़ मक्खनी)","en":"Butter Chicken (Murgh Makhani)","ro":"Butter Chicken (Murgh Makhani)"},"category":{"hi":"करी","en":"Curry","ro":"Curry"},"ingredients":{"hi":["बिना हड्डी के चिकन जांघें 800 ग्राम, 4 सेमी के टुकड़ों में कटे","मैरिनेड के लिए: 200 ग्राम फुल फैट दही, 2 बड़े चम्मच अदरक-लहसुन पेस्ट, 1 छोटा चम्मच कश्मीरी लाल मिर्च, 1 छोटा चम्मच गरम मसाला, आधे नींबू का रस, 2 बड़े चम्मच तटस्थ तेल, 1 छोटा चम्मच नमक","ग्रेवी के लिए: 800 ग्राम पके टमाटर (या 1 बड़े कैन कटे टमाटर), 60 ग्राम कच्चा काजू, 1 बड़ी प्याज़ चार टुकड़ों में, 4 लहसुन की कलियाँ, 3 सेमी अदरक, 4 हरी इलायची, 1 दालचीनी की डंडी, 4 लौंग, 1 तेज़पत्ता","80 ग्राम बिना नमक का मक्खन, 200 मिली हेवी क्रीम","1 बड़ा चम्मच कसूरी मेथी","1 छोटा चम्मच कश्मीरी मिर्च, 1 छोटा चम्मच गरम मसाला, 1 छोटा चम्मच चीनी, नमक","ऊपर डालने के लिए ताज़ा धनिया"],"en":["800 g boneless chicken thighs, cut into 4 cm pieces","For the marinade: 200 g full-fat yoghurt, 2 tbsp ginger-garlic paste, 1 tsp Kashmiri red chilli powder, 1 tsp garam masala, juice of half a lemon, 2 tbsp neutral oil, 1 tsp salt","For the gravy: 800 g ripe tomatoes (or 1 large can chopped tomatoes), 60 g raw cashews, 1 large onion quartered, 4 garlic cloves, 3 cm piece of ginger, 4 green cardamom pods, 1 cinnamon stick, 4 cloves, 1 bay leaf","80 g unsalted butter, 200 ml double cream","1 tbsp kasoori methi (dried fenugreek leaves)","1 tsp Kashmiri red chilli powder, 1 tsp garam masala, 1 tsp sugar, salt","Fresh coriander to finish"],"ro":["800 g pulpe de pui dezosate, tăiate în bucăți de 4 cm","Pentru marinadă: 200 g iaurt gras, 2 linguri pastă de ghimbir-usturoi, 1 linguriță boia Kashmiri, 1 linguriță garam masala, zeama de la o jumătate de lămâie, 2 linguri ulei neutru, 1 linguriță sare","Pentru sosul de bază: 800 g roșii coapte (sau o cutie mare de roșii tocate), 60 g caju crud, 1 ceapă mare în sferturi, 4 căței de usturoi, 3 cm bucată de ghimbir, 4 capsule de cardamom verde, 1 baton de scorțișoară, 4 cuișoare, 1 frunză de dafin","80 g unt nesărat, 200 ml smântână grasă","1 lingură kasoori methi (frunze uscate de schinduf)","1 linguriță boia Kashmiri, 1 linguriță garam masala, 1 linguriță zahăr, sare","Coriandru proaspăt pentru a încheia"]},"howIsMade":{"hi":"एक चौड़े बाउल में मैरीनेड मिलाएँ, चिकन डालें और हर टुकड़ा अच्छी तरह लपेट दें, फिर ढक कर कम से कम 4 घंटे, बेहतर रात भर फ्रिज में रखें। ग्रेवी के लिए, काजू को 100 मिली गरम पानी में 20 मिनट भिगोएँ; टमाटर, प्याज़, लहसुन, अदरक और साबुत मसाले एक भारी बर्तन में 200 मिली पानी के साथ डालें, उबाल पर लाएँ और ढक कर 20–25 मिनट तक तब तक पकाएँ जब तक टमाटर पूरी तरह से न पिघलें और प्याज़ बिल्कुल नर्म न हो जाए, फिर दालचीनी, इलायची, लौंग और तेज़पत्ता निकालें, और सब कुछ — भिगोए हुए काजू और उनके पानी समेत — एक मखमली प्यूरी में पीसें और छलनी से छानें। ब्रॉयलर को सबसे ऊँचा गरम करें, ट्रे में फ़ॉयल बिछाएँ, मैरीनेट किया चिकन एक परत में, टुकड़ों के बीच जगह छोड़ कर फैलाएँ, और हीट से 5–6 सेमी दूरी पर हर तरफ़ 6–8 मिनट तक तब तक भूनें जब तक किनारे जल कर काले न हो जाएँ और मांस बस-बस पका हो — किनारों को सचमुच गहरा होने दें। चौड़े पैन में मध्यम आँच पर मक्खन पिघलाएँ, छनी हुई ग्रेवी डालें और मिर्च पाउडर, चीनी और 1 छोटा चम्मच नमक डालें, अक्सर चलाते हुए 10 मिनट हलकी आँच पर पकाएँ जब तक रंग गहरे ईंट-नारंगी रंग का न हो जाए; क्रीम डालें, ग्रेवी मखमली होने तक चलाएँ, फिर भुना चिकन ट्रे के रस सहित डालें और सब को 4–5 मिनट और साथ में उबलने दें। हथेलियों के बीच kasoori methi को रगड़ कर पैन में डालें, गरम मसाला मिलाएँ और नमक-चीनी चखें, ऊपर से धनिया पत्ती छिड़कें, और naan या basmati चावल के साथ परोसें।","en":"Mix the marinade in a wide bowl, add the chicken and turn each piece until well coated, then cover and chill at least 4 hours, ideally overnight. For the gravy, soak the cashews in 100 ml of hot water for 20 minutes; put the tomatoes, onion, garlic, ginger and whole spices into a heavy pan with 200 ml of water, bring to a simmer and cook covered for 20–25 minutes until the tomatoes have collapsed and the onion is fully soft, then fish out the cinnamon, cardamom, cloves and bay leaf, and blend everything — including the soaked cashews and their water — to a velvety purée and pass through a sieve. Heat the broiler high, line a tray with foil, spread the marinated chicken in a single layer with space between the pieces and broil 5–6 cm from the heat for 6–8 minutes per side, until the edges are charred and the meat is just cooked through — let the edges go genuinely dark. Melt the butter in a wide pan over medium heat, pour in the strained gravy and add the chilli powder, sugar and a teaspoon of salt, simmer gently for 10 minutes stirring often until the colour deepens to a rich brick-orange; pour in the cream, stir until the gravy turns velvet, then slide in the charred chicken with any juices from the tray and let everything bubble together for 4–5 minutes more. Crush the kasoori methi between your palms over the pan, stir in the garam masala and taste for salt and sugar, scatter coriander leaves on top, and serve with naan or basmati rice."}},{"id":205,"servings":6,"tipType":"meat","pairingsType":"indian","nutrition":{"cal":780,"prot":38,"carb":78,"fat":32,"fib":3},"origin":{"hi":"भारत","en":"India","ro":"India"},"name":{"hi":"हैदराबादी मटन बिरयानी","en":"Hyderabadi Lamb Biryani","ro":"Biryani de miel din Hyderabad"},"category":{"hi":"मुख्य व्यंजन","en":"Main","ro":"Fel principal"},"ingredients":{"hi":["हड्डी सहित मटन कंधा या टांग 800 ग्राम, 4 सेमी के टुकड़ों में कटा","बासमती चावल 500 ग्राम, ठंडे पानी में 30 मिनट भिगो कर छाने हुए","4 बड़ी प्याज़, बहुत बारीक कटी (लगभग 600 ग्राम)","फुल फैट दही 200 ग्राम","देसी घी 50 ग्राम + तटस्थ तेल 80 मिली","अदरक-लहसुन पेस्ट 3 बड़े चम्मच","हरी मिर्च 2, लंबाई में चीरी","कश्मीरी लाल मिर्च 2 छोटे चम्मच, हल्दी 1 छोटा चम्मच, नमक 1 छोटा चम्मच","साबुत मसाले: दालचीनी 1 डंडी, हरी इलायची 4 + काली इलायची 2, लौंग 4, तेज़पत्ता 1, शाही ज़ीरा 1 छोटा चम्मच, साबुत काली मिर्च 1 छोटा चम्मच","एक चुटकी केसर 60 मिली गुनगुने फुल फैट दूध में भिगोया","1 नींबू का रस","कटा पुदीना 2 बड़े चम्मच और कटा धनिया 2 बड़े चम्मच","गुलाब जल 1 बड़ा चम्मच (वैकल्पिक, पारंपरिक)","ढक्कन सील करने के लिए नरम आटा का एक टुकड़ा या मोटी फ़ॉइल"],"en":["800 g bone-in lamb shoulder or leg, cut into 4 cm pieces","500 g basmati rice, soaked 30 minutes in cold water and drained","4 large onions, very thinly sliced (about 600 g)","200 g full-fat yoghurt","50 g ghee + 80 ml neutral oil","3 tbsp ginger-garlic paste","2 green chillies, slit lengthwise","2 tsp Kashmiri red chilli powder, 1 tsp turmeric, 1 tsp salt","Whole spices: 1 cinnamon stick, 4 green cardamom + 2 black cardamom, 4 cloves, 1 bay leaf, 1 tsp shahi jeera, 1 tsp black peppercorns","A pinch of saffron infused in 60 ml warm whole milk","Juice of 1 lemon","2 tbsp chopped mint and 2 tbsp chopped coriander","1 tbsp rose water (optional, traditional)","A piece of soft dough or a sheet of heavy foil for sealing"],"ro":["800 g spată sau pulpă de miel cu os, tăiată în bucăți de 4 cm","500 g orez basmati, înmuiat 30 de minute în apă rece și scurs","4 cepe mari, tăiate foarte subțire (aproximativ 600 g)","200 g iaurt gras","50 g ghee + 80 ml ulei neutru","3 linguri pastă de ghimbir-usturoi","2 ardei iuți verzi, despicați pe lungime","2 lingurițe boia Kashmiri, 1 linguriță turmeric, 1 linguriță sare","Mirodenii întregi: 1 baton de scorțișoară, 4 capsule cardamom verde + 2 cardamom negru, 4 cuișoare, 1 frunză de dafin, 1 linguriță shahi jeera, 1 linguriță boabe de piper negru","Un vârf de șofran infuzat în 60 ml lapte cald","Sucul de la 1 lămâie","2 linguri mentă tocată și 2 linguri coriandru tocat","1 lingură apă de trandafiri (opțional, tradițional)","O bucată de aluat moale sau o folie groasă pentru sigilare"]},"howIsMade":{"hi":"एक चौड़े और भारी पैन में मध्यम आँच पर घी और तेल गरम करें और कटी प्याज़ को 25–30 मिनट तक, बार-बार चलाते हुए, गहरे सुनहरे-भूरे (बिरिस्ता) रंग तक धीरे-धीरे भूनें, फिर काग़ज़ पर निकाल कर तेल पैन में रखें और परत के लिए आधी प्याज़ अलग रखें। मटन को दही, अदरक-लहसुन पेस्ट, हाथ में मसली हुई आधी तली प्याज़, मिर्च पाउडर, हल्दी, नमक, नीबू का रस और 1 छोटा चम्मच शाही जीरा के साथ मिलाएँ, अच्छी तरह मिला कर कम से कम 2 घंटे या रात भर फ्रिज में रखें; मैरीनेट किया मटन को बचाई हुई प्याज़ के तेल में वापस डालें, दालचीनी, इलायची, लौंग और तेज़पत्ता डालें, और ढक कर धीमी आँच पर 1 घंटे से 1 घंटा 15 मिनट तक पकाएँ, जब तक मटन नर्म न हो और ग्रेवी एक गाढ़ी परत में सिमट न जाए। एक गहरे बर्तन में अच्छी तरह नमक वाला पानी बाक़ी साबुत मसालों और 1 बड़े चम्मच तेल के साथ तेज़ उबाल पर लाएँ, भीगा बासमती डालें और सिर्फ़ 4–5 मिनट तक पकाएँ, जब तक चावल लंबे हो जाएँ और लगभग तीन-चौथाई पक जाएँ — बाक़ी भाप में पूरा होगा — फिर जल्दी और हलके से छानें। उसी पैन में मटन के ऊपर चावल को एकसमान फैलाएँ, ऊपर बची हुई तली प्याज़, कटी पुदीना और धनिया और हरी मिर्चें छिड़कें, फिर केसर वाला दूध सतह पर धीमी धारियों में डालें और रोज़वाटर अगर इस्तेमाल कर रहे हैं तो वो भी। ढक्कन को गीले आटे की पट्टी या कस के बंधी फॉयल से सील करें, सबसे धीमी आँच पर 25–30 मिनट रखें, फिर ढक्कन उठाए बिना आँच बंद करें और सील्ड अवस्था में 10 मिनट और आराम दें — सील को मेज़ पर तोड़ें, और एक लंबा चम्मच तले तक डाल कर सीधा ऊपर उठाएँ, ताकि हर हिस्से में चावल और मटन साथ-साथ निकलें, कभी मिक्स किए हुए नहीं।","en":"Heat the ghee and oil in a wide heavy pan over medium heat and fry the sliced onions slowly for 25–30 minutes, stirring often, until deeply golden brown (birista), then drain on paper, reserve the oil in the pan and keep half the onions for layering. Combine the lamb with the yoghurt, ginger-garlic paste, half of the fried onions crushed in your hand, chilli powder, turmeric, salt, lemon juice and a teaspoon of the shahi jeera, mix thoroughly and rest at least 2 hours or overnight in the fridge; tip the marinated lamb back into the reserved onion oil, add the cinnamon, cardamom, cloves and bay leaf, and cook covered over low heat for an hour to an hour and a quarter, until the lamb is tender and the gravy has reduced to a thick coating. Bring a deep pot of well-salted water to a rolling boil with the rest of the whole spices and a tablespoon of oil, add the soaked basmati and cook just 4–5 minutes until the grains have lengthened and are about three-quarters done — they finish in the steam — then drain quickly and gently. In the same pan over the lamb, spread the rice evenly, scatter the remaining fried onions, chopped mint and coriander, and the green chillies on top, then drizzle the saffron milk in slow streaks across the surface and the rose water if using. Seal the lid with a strip of wet dough or a tight wrap of foil, set on the lowest heat for 25–30 minutes, then turn off the flame without lifting the lid and rest sealed for another 10 minutes — break the seal at the table and plunge a long spoon to the bottom to lift straight up, so each portion comes out with both rice and meat, never stirred together."}},{"id":206,"servings":4,"tipType":"veg","pairingsType":"indian","nutrition":{"cal":480,"prot":22,"carb":18,"fat":36,"fib":5},"origin":{"hi":"भारत","en":"India","ro":"India"},"name":{"hi":"पालक पनीर","en":"Palak Paneer","ro":"Palak Paneer"},"category":{"hi":"करी","en":"Curry","ro":"Curry"},"ingredients":{"hi":["ताज़ा पालक 500 ग्राम (या जमा हुआ 250 ग्राम, पिघलाया हुआ)","पनीर 250 ग्राम, 2 सेमी के क्यूब्स में","1 बड़ी प्याज़, बारीक कटी","2 पके टमाटर, कटे (या 200 ग्राम कटे टमाटर)","3 लहसुन कलियाँ और 2 सेमी अदरक, साथ बारीक कुटे","2 हरी मिर्च","1 छोटा चम्मच जीरा","1 छोटा चम्मच धनिया पाउडर, 1 छोटा चम्मच कश्मीरी मिर्च, ½ छोटा चम्मच हल्दी, 1 छोटा चम्मच गरम मसाला","1 बड़ा चम्मच कसूरी मेथी","80 मिली क्रीम, 3 बड़े चम्मच घी","नमक स्वादानुसार","ऊपर डालने के लिए थोड़ा-सा ताज़ा अदरक, जूलियन कटा"],"en":["500 g fresh spinach (or 250 g frozen, defrosted)","250 g paneer, cut into 2 cm cubes","1 large onion, finely chopped","2 ripe tomatoes, chopped (or 200 g chopped tomatoes)","3 garlic cloves and 2 cm piece of ginger, minced together","2 green chillies","1 tsp cumin seeds","1 tsp coriander powder, 1 tsp Kashmiri chilli powder, ½ tsp turmeric, 1 tsp garam masala","1 tbsp kasoori methi (dried fenugreek leaves)","80 ml double cream, 3 tbsp ghee","Salt to taste","A small piece of fresh ginger, julienned, to finish"],"ro":["500 g spanac proaspăt (sau 250 g congelat, dezghețat)","250 g paneer, tăiat cuburi de 2 cm","1 ceapă mare, tocată mărunt","2 roșii coapte, tocate (sau 200 g roșii tocate)","3 căței de usturoi și o bucată de 2 cm de ghimbir, tocate împreună","2 ardei iuți verzi","1 linguriță semințe de chimion","1 linguriță coriandru pudră, 1 linguriță boia Kashmiri, ½ linguriță turmeric, 1 linguriță garam masala","1 lingură kasoori methi (frunze uscate de schinduf)","80 ml smântână grasă, 3 linguri ghee","Sare după gust","O bucățică mică de ghimbir proaspăt, tăiată julien, pentru finisat"]},"howIsMade":{"hi":"एक बड़े बर्तन में पानी उबालें, पालक को 90 सेकंड के लिए blanch करें और तुरंत बर्फ़ के पानी वाले बाउल में डालें, फिर छानें, हलके से निचोड़ें और एक हरी मिर्च तथा 2-3 बड़े चम्मच ठंडे पानी के साथ चिकनी प्यूरी में पीस लें। एक चौड़े पैन में 1 बड़ा चम्मच घी गरम करें और पनीर के टुकड़ों को मध्यम आँच पर 2–3 मिनट प्रत्येक तरफ़ हलके सुनहरे होने तक भूनें, फिर काग़ज़ पर निकालें या जब तक बाक़ी सब बन रहा है तब तक गुनगुने नमक वाले पानी में रखें। उसी पैन में बचा हुआ घी और जीरा डालें और 30 सेकंड चटकने दें, प्याज़ डालें और 8–10 मिनट तक नर्म और किनारों पर सुनहरा होने तक भूनें, फिर अदरक-लहसुन पेस्ट और चीरी हुई दूसरी हरी मिर्च डालें और 1 मिनट और भूनें। कटा टमाटर धनिया पाउडर, मिर्च पाउडर, हल्दी और 1 छोटा चम्मच नमक के साथ डालें और 6–8 मिनट तक भूनें जब तक मसाला जैम जैसा गाढ़ा न हो और तेल किनारों से अलग होने न लगे, फिर पालक प्यूरी और 100 मिली पानी डालें, अच्छे से मिलाएँ और 5 मिनट हलकी आँच पर पकाएँ। पनीर के टुकड़े ग्रेवी में डालें, क्रीम मिलाएँ, kasoori methi को हथेलियों के बीच रगड़कर पैन में डालें और गरम मसाला छिड़कें, 2 मिनट और गरम करें, नमक चखें, ऊपर से जुलिएन कटा अदरक डाल कर सजाएँ, और नान, पराठा या बासमती चावल के साथ परोसें।","en":"Bring a large pot of water to a boil, blanch the spinach for 90 seconds and transfer immediately to a bowl of ice water, then drain, squeeze gently and blend to a smooth purée with one of the green chillies and a few tablespoons of cold water. Heat a tablespoon of ghee in a wide pan and fry the paneer cubes over medium heat for 2–3 minutes per side until lightly gold, then lift onto paper or slip them into a bowl of warm salted water while everything else cooks. In the same pan add the remaining ghee and the cumin seeds and let them sizzle for 30 seconds, tip in the onion and cook 8–10 minutes until soft and golden at the edges, then add the ginger-garlic paste and the second slit green chilli and cook a minute more. Stir in the chopped tomato with the coriander, chilli powder, turmeric and a teaspoon of salt and cook 6–8 minutes until the masala is jammy and the oil starts to separate at the edges, then pour in the spinach purée and 100 ml of water, stir well and simmer gently for 5 minutes. Slide the paneer cubes into the gravy, swirl in the cream, crush the kasoori methi between your palms over the pan and sprinkle the garam masala, heat through for another 2 minutes, taste for salt, finish with julienned ginger on top, and serve with naan, paratha or basmati."}},{"id":207,"servings":6,"tipType":"meat","pairingsType":"indian","nutrition":{"cal":620,"prot":40,"carb":12,"fat":44,"fib":2},"origin":{"hi":"भारत","en":"India","ro":"India"},"name":{"hi":"रोगन जोश","en":"Rogan Josh","ro":"Rogan Josh"},"category":{"hi":"करी","en":"Curry","ro":"Curry"},"ingredients":{"hi":["हड्डी सहित मटन कंधा या टांग 1 किलो, 4 सेमी के टुकड़ों में कटा","सरसों का तेल 4 बड़े चम्मच","फुल फैट दही 200 ग्राम, चिकनी फेंटी","सूखी कश्मीरी लाल मिर्च 4, गुनगुने पानी में 20 मिनट भिगो कर पीस कर पेस्ट बनाई (या कश्मीरी मिर्च पाउडर 2 बड़े चम्मच)","सौंफ पाउडर 1 छोटा चम्मच","सोंठ (सूखी अदरक का पाउडर) 1 छोटा चम्मच","हींग ½ छोटा चम्मच","साबुत मसाले: हरी इलायची 8 + काली इलायची 2, दालचीनी की डंडी 1, लौंग 6, तेज़पत्ता 1","नमक 1 छोटा चम्मच","एक चुटकी केसर, 2 बड़े चम्मच गुनगुने दूध में भिगोया"],"en":["1 kg bone-in lamb shoulder or leg, cut into 4 cm pieces","4 tbsp mustard oil","200 g full-fat yoghurt, whisked smooth","4 dried Kashmiri red chillies, soaked in warm water 20 minutes and ground to a paste (or 2 tbsp Kashmiri chilli powder)","1 tsp fennel powder","1 tsp dried ginger powder (sonth)","½ tsp asafoetida (hing)","Whole spices: 8 green cardamom + 2 black cardamom, 1 cinnamon stick, 6 cloves, 1 bay leaf","1 tsp salt","A pinch of saffron, soaked in 2 tbsp warm milk"],"ro":["1 kg spată sau pulpă de miel cu os, tăiată în bucăți de 4 cm","4 linguri ulei de muștar","200 g iaurt gras, bătut neted","4 ardei roșii Kashmiri uscați, înmuiați 20 de minute în apă caldă și pisați pastă (sau 2 linguri boia Kashmiri)","1 linguriță pudră de fenicul","1 linguriță pudră de ghimbir uscat (sonth)","½ linguriță asafoetida (hing)","Mirodenii întregi: 8 capsule cardamom verde + 2 cardamom negru, 1 baton de scorțișoară, 6 cuișoare, 1 frunză de dafin","1 linguriță sare","Un vârf de șofran, infuzat în 2 linguri lapte cald"]},"howIsMade":{"hi":"एक भारी बर्तन में सरसों के तेल को बस धुआँ उठने तक गरम करें, फिर एक पल के लिए आँच से उतार लें — यह धुआँ कच्चेपन को कम कर देता है, बिना तेल जलाए — मध्यम आँच पर वापस रखें, साबुत मसाले और तेज़पत्ता डालें, और उन्हें 30 सेकंड तक तेल को महक देने दें। मटन को एक परत में डालें और हर तरफ़ 8–10 मिनट तक अच्छी तरह सुनहरा-भूरा होने दें (यह व्यंजन का एकमात्र भूरा करने का मौक़ा है, इसलिए रंग को सही ढंग से उभरने दें), हींग, सोंठ और सौंफ पाउडर मिलाएँ और उन्हें गरम तेल में मांस के साथ 1 मिनट और लिपटाएँ। दही को कश्मीरी मिर्च पेस्ट और 1 बड़े चम्मच ठंडे पानी के साथ फेंटें, फिर बर्तन में एक करछुल भर के डालते जाएँ, हर बार लगातार चलाते रहें — धीरे-धीरे डालने से दही फटता नहीं — नमक डालें, आँच कम करें और ढक कर 10 मिनट पकाएँ जब तक दही चमकीले लाल बेस में न घुल जाए। 500 मिली गरम पानी डालें, फिर से उबाल पर लाएँ, फिर सबसे धीमी आँच कर दें और ढक कर 1 घंटा 20 मिनट तक पकाएँ — हर 20 मिनट पर चलाएँ — जब तक मटन चम्मच की दबाव पर पिघले जैसा हो जाए और ग्रेवी पतली, चमकदार और गहरे महोगनी रंग की हो जाए; ख़त्म होने से 5 मिनट पहले केसर वाला दूध हलके से मिलाएँ, पूरी तरह न चलाएँ। आँच से उतार कर 10 मिनट आराम दें, फिर भाप वाले बासमती चावल के साथ परोसें — रोगन जोश एक सूप-जैसा व्यंजन है, चमकीले रंग और सुगंध से भरा, तीखा नहीं; तीख़ापन मांस से आता है, रंग मिर्च से, और सुगंध बाक़ी सब चीज़ों से।","en":"Heat the mustard oil in a heavy pan until it just begins to smoke, then pull it off the heat for a moment — letting it smoke neutralises the raw pungency without scorching — and return to medium heat, add the whole spices and bay leaf, and let them perfume the oil for 30 seconds. Add the lamb in a single layer and brown well on all sides for 8–10 minutes (this is the only browning the dish gets, so let the colour develop properly), then stir in the asafoetida, ginger powder and fennel powder and let them coat the meat in the hot oil for another minute. Whisk the yoghurt with the Kashmiri chilli paste and a tablespoon of cold water, then add it to the pan a ladleful at a time stirring continuously after each addition — going slowly keeps the yoghurt from splitting — add the salt, lower the heat and cook covered for 10 minutes until the yoghurt has melted into a glossy red base. Pour in 500 ml of hot water, bring back to a simmer, then drop the heat to its lowest and braise covered for an hour and 20 minutes, stirring every 20 minutes, until the lamb yields to a spoon and the gravy is thin, glossy and a deep mahogany red; swirl the saffron milk through 5 minutes before the end without fully stirring it out. Rest off the heat for 10 minutes before serving with steamed basmati — Rogan Josh is meant to be soup-like, brilliantly coloured and aromatic rather than spicy hot, the heat supplied by the meat, the colour by the chillies, and the perfume by everything else."}},{"id":208,"servings":8,"tipType":"veg","pairingsType":"indian","nutrition":{"cal":280,"prot":6,"carb":32,"fat":14,"fib":3},"origin":{"hi":"भारत","en":"India","ro":"India"},"name":{"hi":"समोसा","en":"Samosa","ro":"Samosa"},"category":{"hi":"नाश्ता","en":"Snack","ro":"Gustare"},"ingredients":{"hi":["आटे के लिए: 300 ग्राम मैदा, 1 छोटा चम्मच अजवायन, ½ छोटा चम्मच नमक, 60 मिली घी या तटस्थ तेल, 120 मिली ठंडा पानी","भरावन के लिए: 500 ग्राम मैले आलू (Russet जैसी क़िस्म), 100 ग्राम जमे मटर, 2 बड़े चम्मच तटस्थ तेल, 1 छोटा चम्मच जीरा, 1 हरी मिर्च बारीक कटी, 2 सेमी अदरक बारीक कटा","1 छोटा चम्मच धनिया पाउडर, 1 छोटा चम्मच गरम मसाला, ½ छोटा चम्मच कश्मीरी मिर्च, ½ छोटा चम्मच हल्दी, 1 छोटा चम्मच अमचूर, 1 छोटा चम्मच नमक","एक मुट्ठी ताज़ा धनिया, कटा","तलने के लिए लगभग 1 लीटर तटस्थ तेल","साथ में: इमली की चटनी और पुदीना-धनिया चटनी"],"en":["For the pastry: 300 g plain flour, 1 tsp ajwain (carom) seeds, ½ tsp salt, 60 ml ghee or neutral oil, 120 ml cold water","For the filling: 500 g floury potatoes (Maris Piper or Russet), 100 g frozen peas, 2 tbsp neutral oil, 1 tsp cumin seeds, 1 green chilli minced, 2 cm piece of ginger minced","1 tsp coriander powder, 1 tsp garam masala, ½ tsp Kashmiri chilli powder, ½ tsp turmeric, 1 tsp amchur (dried mango powder), 1 tsp salt","A handful of fresh coriander, chopped","About 1 L neutral oil for deep-frying","To serve: tamarind chutney and mint-coriander chutney"],"ro":["Pentru aluat: 300 g făină albă, 1 linguriță semințe de ajwain (chimen-aristotel), ½ linguriță sare, 60 ml ghee sau ulei neutru, 120 ml apă rece","Pentru umplutură: 500 g cartofi făinoși (Maris Piper sau Russet), 100 g mazăre congelată, 2 linguri ulei neutru, 1 linguriță semințe de chimion, 1 ardei iute verde tocat, 2 cm bucată de ghimbir tocat","1 linguriță coriandru pudră, 1 linguriță garam masala, ½ linguriță boia Kashmiri, ½ linguriță turmeric, 1 linguriță amchur (pudră de mango uscat), 1 linguriță sare","Un mănunchi de coriandru proaspăt, tocat","Aproximativ 1 l ulei neutru pentru prăjit","Pentru servit: chutney de tamarind și chutney de mentă-coriandru"]},"howIsMade":{"hi":"उँगलियों के पोरों से घी को मैदा, अजवायन और नमक के साथ इस तरह रगड़ें कि मिश्रण मोटे ब्रेडक्रंब जैसा हो जाए — यह जो वसा है, यही समोसे की पपड़ी को वो बबल-दार, बिस्कुट जैसी कुरकुरी सूरत देती है — ठंडा पानी एक-एक बड़ा चम्मच डाल कर सख़्त और चिकना आटा गूँधें (चपाती से नर्म पर ब्रेड के आटे से सख़्त), और ढक कर 30 मिनट आराम दें। आलू को छिलके सहित बस-बस गलने तक उबालें, छान कर छिलका उतारें, फिर काँटे की पीठ से मोटे-मोटे चूरें (आपको texture चाहिए, mash नहीं); एक चौड़े पैन में तेल गरम करें, जीरा डालें और चटकने दें, फिर अदरक और हरी मिर्च 30 सेकंड के लिए डालें, सूखे मसाले डाल कर हलका भूनें, फिर आलू, मटर, नमक, अमचूर और धनिया डाल कर 4–5 मिनट चलाते रहें जब तक मसाला हर टुकड़े पर चढ़ न जाए — शेप करने से पहले कमरे के तापमान पर ठंडा करें। आटे को 8 गोले बनाएँ, एक गोला लगभग 18 सेमी लंबे पतले अंडाकार में बेलें, फिर बीच से काट कर दो अर्धवृत्त बनाएँ; एक अर्धवृत्त लें, सीधी धार पर पानी की एक पतली रेखा ब्रश करें, और सीधी धार के दो कोनों को 1 सेमी ओवरलैप करते हुए जोड़ कर एक कोन बनाएँ, जोड़ को कस कर दबा कर सील करें। एक हाथ में कोन पकड़ें, आलू को तीन-चौथाई तक भरें, फिर खुली धार को एक तरफ़ छोटी सी प्लीट डाल कर मोड़ें और गीली उँगली से किनारा पूरी तरह बंद कर दें — यही छोटी प्लीट समोसे को उसकी पहचान वाली साइड रेज देती है और तलते वक़्त उसे खड़ा रहने में मदद करती है — बाक़ी भी इसी तरह बनाएँ। तलने का तेल 150°C तक गरम करें (आपकी अपेक्षा से कम, पर यही धीमी चढ़ाई पपड़ी पर बबल लाती है), समोसे को 3 या 4 के बैचों में तेल में डालें और हलके से पलटते हुए 6–7 मिनट तक हलका सुनहरा रंग आने तक तलें, आँच को 180°C तक बढ़ाएँ और 3–4 मिनट और तलें, जब तक गहरा सुनहरा और सही मायने में कुरकुरे न हो जाएँ, जाली पर निकाल कर तेल छानें और गरम-गरम इमली की चटनी और पुदीना-धनिया चटनी के साथ परोसें।","en":"Rub the ghee into the flour, ajwain and salt with your fingertips until the mixture resembles coarse breadcrumbs — the amount of fat is what gives samosa pastry its blistered, biscuit-crisp shell — then add the cold water a tablespoon at a time, mixing into a stiff smooth dough (softer than chapati but firmer than bread dough) and rest it covered for 30 minutes. Boil the potatoes in their skins until just tender, drain, peel and crush coarsely with the back of a fork (you want texture, not mash); heat the oil in a wide pan, add the cumin seeds and let them sizzle, then the ginger and green chilli for 30 seconds, stir in the dry spices and fry briefly, tip in the potato, peas, salt, amchur and coriander, and cook 4–5 minutes turning everything until the spices coat every piece — cool to room temperature before shaping. Divide the dough into 8 balls, roll one into a thin oval about 18 cm long and cut across the middle to make two half-circles; take one half, brush a thin line of water along the straight edge, and fold into a cone by bringing the two corners of the straight edge together so they overlap by 1 cm, pinching the seam tightly to seal. Hold the cone in one hand, fill it three-quarters with potato, then pleat the open edge by folding a small tuck on one side and sealing the rim shut with a damp finger — the tucked pleat creates the samosa's signature side ridge and helps it sit upright while cooking — and repeat with the rest. Heat the frying oil to 150°C (lower than you might expect, but the slow climb is what gives the shell its blisters), slip in the samosas in batches of 3 or 4 and fry 6–7 minutes turning gently until pale gold, then raise the heat to 180°C and fry another 3–4 minutes until deep golden and properly crisp, draining on a rack and serving hot with tamarind and mint chutneys."}},{"id":209,"servings":4,"tipType":"meat","pairingsType":"thai","nutrition":{"cal":620,"prot":32,"carb":22,"fat":44,"fib":5},"origin":{"hi":"थाईलैंड","en":"Thailand","ro":"Thailanda"},"name":{"hi":"ग्रीन करी (Gaeng Khiao Wan)","en":"Green Curry (Gaeng Khiao Wan)","ro":"Curry verde (Gaeng Khiao Wan)"},"category":{"hi":"करी","en":"Curry","ro":"Curry"},"ingredients":{"hi":["ग्रीन करी पेस्ट 4 बड़े चम्मच (घर पर बनाई हुई या Mae Ploy जैसी अच्छी थाई ब्रांड)","फुल फैट नारियल का दूध 400 मिली (Aroy-D आदर्श)","नारियल क्रीम 200 मिली (कैन के ऊपर वाली गाढ़ी परत, या 100 मिली + ऊपर से उठाई क्रीम)","चिकन की जांघें 500 ग्राम, 3 सेमी टुकड़ों में कटी","थाई बैंगन 4, चार टुकड़ों में (या 1 छोटा एशियाई बैंगन, क्यूब्स में)","मटर-बैंगन एक छोटी मुट्ठी (मुख्य रूप से सजावट, वैकल्पिक)","बांस के टुकड़े 100 ग्राम","कैफिर लाइम के पत्ते 4, डंठल हटा कर हाथ से फाड़े","लंबी लाल मिर्च 2, तिरछी पतली कटी","ताड़ की चीनी 1 बड़ा चम्मच (या हल्की ब्राउन शुगर)","थाई फिश सॉस 2 बड़े चम्मच","थाई तुलसी (होरपा) के पत्ते एक छोटी मुट्ठी","साथ में चमेली चावल"],"en":["4 tbsp green curry paste (homemade, or a good Thai brand like Mae Ploy)","400 ml full-fat coconut milk (Aroy-D is ideal)","200 ml coconut cream (the thick top layer from the can, or 100 ml plus the skimmed cream)","500 g chicken thighs, cut into 3 cm pieces","4 Thai eggplants, quartered (or 1 small Asian eggplant cubed)","A small handful of pea eggplants (mainly garnish, optional)","100 g bamboo shoots, sliced","4 kaffir lime leaves, torn (stem removed)","2 long red chillies, sliced thinly on the bias","1 tbsp palm sugar (or light brown sugar)","2 tbsp Thai fish sauce","A small handful of Thai basil leaves (horapha)","Jasmine rice to serve"],"ro":["4 linguri pastă curry verde (de casă sau o marcă thailandeză bună precum Mae Ploy)","400 ml lapte de cocos gras (ideal Aroy-D)","200 ml smântână de cocos (stratul gros de deasupra cutiei, sau 100 ml plus crema rămasă)","500 g pulpe de pui, tăiate în bucăți de 3 cm","4 vinete thailandeze, tăiate în sferturi (sau 1 vânătă asiatică mică, cuburi)","Un mic mănunchi de vinete-mazăre (în principal pentru garnitură, opțional)","100 g vârfuri de bambus, feliate","4 frunze de lămâi kaffir, rupte (codița înlăturată)","2 ardei roșii lungi, feliați subțire în diagonală","1 lingură zahăr de palmier (sau zahăr brun deschis)","2 linguri sos de pește thailandez","Un mic mănunchi de busuioc thailandez (horapha)","Orez iasomie pentru servit"]},"howIsMade":{"hi":"एक wok या भारी पैन में मध्यम आँच पर नारियल क्रीम डालें और 4–5 मिनट तक, बीच-बीच में चलाते हुए, तब तक पकाएँ जब तक तेल अलग न हो जाए और क्रीम पर तेल जैसी चमक न आ जाए — यह बेस वाला कदम ही थाई रेस्टोरेंट की ग्रीन करी और घर की पानी-पानी वाली ग्रीन करी के बीच फ़र्क़ है। फटी हुई क्रीम में ग्रीन करी पेस्ट डालें और 2–3 मिनट लगातार चलाते हुए भूनें — जब तक पेस्ट गहरा हो जाए, गलंगाल, लेमनग्रास और थाई तुलसी की ख़ुशबू उठने लगे, और तेल चमकीले हरे रंग का न हो जाए — रसोई से बैंकॉक की एक गली की ख़ुशबू आएगी। चिकन डालें और हर टुकड़े को पेस्ट में लपेट दें, 3–4 मिनट तक तब तक पकाएँ जब तक मांस आधा-सीलिंग न हो जाए, फिर नारियल का दूध डालें और हलकी उबाल पर लाएँ; बैंगन, बांस के टुकड़े और फटे कैफिर लाइम पत्ते डालें और बिना ढके 10–12 मिनट तक पकाएँ जब तक बैंगन नरम और चिकन बस-बस पका न हो। फिश सॉस और ताड़ की चीनी से स्वाद दें, बीच-बीच में चखें — करी एक साथ नमकीन, मीठी, जड़ी-बूटी जैसी और साफ़ हरी मिर्च की तीक्ष्णता मारनी चाहिए — फिर कटी लाल मिर्च और थाई तुलसी डालें, पैन को एक बार घुमाएँ, और 30 सेकंड बाद आँच से उतार लें ताकि तुलसी कटोरे में भी ताज़ी हरी रहे। उथले कटोरों में परोसें, साथ में चमेली चावल।","en":"In a wok or heavy pan over medium heat, spoon in the coconut cream and let it cook for 4–5 minutes, stirring occasionally, until the oil cracks out and the cream takes on a slick sheen — this foundation step is what separates Thai-restaurant green curry from the watery home version. Add the green curry paste to the split cream and fry for 2–3 minutes, stirring constantly, until the paste darkens, releases its perfume of galangal, lemongrass and Thai basil, and the oil turns a vivid green — the kitchen will smell like a Bangkok back street. Slide in the chicken and turn the pieces in the paste until coated, cook 3–4 minutes until the meat is half-sealed, then pour in the coconut milk and bring to a gentle simmer; add the eggplants, bamboo shoots and torn kaffir lime leaves, and simmer uncovered for 10–12 minutes until the eggplants are tender and the chicken is just cooked through. Season with the fish sauce and palm sugar, tasting as you go — the curry should hit salty, sweet, herbaceous and a clean green chilli heat all at once — then stir in the sliced red chillies and Thai basil, swirl the pan once and take it off the heat after 30 seconds so the basil stays bright in the bowl. Serve in shallow bowls with jasmine rice on the side."}},{"id":210,"servings":6,"tipType":"meat","pairingsType":"thai","nutrition":{"cal":680,"prot":36,"carb":38,"fat":42,"fib":6},"origin":{"hi":"थाईलैंड","en":"Thailand","ro":"Thailanda"},"name":{"hi":"मसामन करी","en":"Massaman Curry","ro":"Massaman"},"category":{"hi":"करी","en":"Curry","ro":"Curry"},"ingredients":{"hi":["मसामन करी पेस्ट 4 बड़े चम्मच (Mae Ploy भरोसेमंद ब्रांड है)","बीफ़ की पिंडली या चक 1 किलो, 5 सेमी क्यूब्स में","फुल फैट नारियल का दूध 800 मिली","नारियल क्रीम 200 मिली","मोम-गुणी आलू (Charlotte या Yukon Gold) 500 ग्राम, छिले और 4 सेमी टुकड़ों में","2 छोटी प्याज़, छिली और चार टुकड़ों में","भुने बिना नमक की मूँगफली 100 ग्राम (कुछ कुटी हुई सजावट के लिए)","साबुत मसाले: इलायची 5, दालचीनी की डंडी 1, लौंग 4, चक्र फूल 1, तेज़पत्ता 1","इमली पेस्ट 3 बड़े चम्मच (या विकल्प के तौर पर 1 नींबू का रस)","ताड़ की चीनी 3 बड़े चम्मच","थाई फिश सॉस 3 बड़े चम्मच","कैफिर लाइम के पत्ते 4, फटे हुए","साथ में चमेली चावल"],"en":["4 tbsp Massaman curry paste (Mae Ploy is reliable)","1 kg beef shin or chuck, cut into 5 cm cubes","800 ml full-fat coconut milk","200 ml coconut cream","500 g waxy potatoes (Charlotte or Yukon Gold), peeled and cut into 4 cm chunks","2 small onions, peeled and quartered","100 g roasted unsalted peanuts (a few crushed for garnish)","Whole spices: 5 cardamom pods, 1 cinnamon stick, 4 cloves, 1 star anise, 1 bay leaf","3 tbsp tamarind paste (or juice of 1 lime as a back-up)","3 tbsp palm sugar","3 tbsp Thai fish sauce","4 kaffir lime leaves, torn","Jasmine rice to serve"],"ro":["4 linguri pastă Massaman (Mae Ploy este o alegere sigură)","1 kg rasol sau pulpă de vită, tăiată în cuburi de 5 cm","800 ml lapte de cocos gras","200 ml smântână de cocos","500 g cartofi cu textură fermă (Charlotte sau Yukon Gold), curățați și tăiați în bucăți de 4 cm","2 cepe mici, curățate și tăiate în sferturi","100 g arahide prăjite nesărate (câteva zdrobite pentru ornat)","Mirodenii întregi: 5 capsule cardamom, 1 baton de scorțișoară, 4 cuișoare, 1 anason stelat, 1 frunză de dafin","3 linguri pastă de tamarind (sau zeama de la 1 lime de rezervă)","3 linguri zahăr de palmier","3 linguri sos de pește thailandez","4 frunze de lămâi kaffir, rupte","Orez iasomie pentru servit"]},"howIsMade":{"hi":"नारियल क्रीम को एक भारी बर्तन में मध्यम आँच पर डालें और 5 मिनट तक चलाते हुए तब तक पकाएँ जब तक तेल अलग न हो जाए और क्रीम चमकदार और हलकी दानेदार न लगे। मसामन पेस्ट और साबुत मसाले डालें और 3 मिनट भूनें — पेस्ट गहरा होगा और रसोई से दालचीनी, इलायची और भुने जीरे की ख़ुशबू उठेगी; मसालों का यह जल्दी खिल जाना ही मसामन को उसका फ़ारसी-झुकाव वाला गहरा स्वाद देता है। बीफ़ डालें और हर टुकड़े को पेस्ट में लपेट कर गहरे लाल रंग का होने तक चलाएँ, फिर नारियल का दूध, इमली पेस्ट और कैफिर लाइम के पत्ते डालें, बिल्कुल हल्की उबाल पर लाएँ, और ढक्कन थोड़ा खुला रख कर 1 घंटा 30 मिनट तक, हर 20 मिनट पर चलाते हुए, धीमी आँच पर पकाएँ — बीफ़ तब तैयार है जब चम्मच के दबाव से आसानी से अलग हो जाए पर आकार बनाए रखे। आलू, प्याज़ और मूँगफली डालें और बिना ढके 30 मिनट और पकाएँ, जब तक आलू नर्म और ग्रेवी चमकदार गहरे भूरे रंग की न हो जाए; फिश सॉस और ताड़ की चीनी आख़िर में डालें, नमकीन-मीठा-खट्टा वाला त्रिकोण ऐसा संतुलित करें कि स्वाद गहरा और गोलमटोल लगे, न ज़्यादा मीठा, न ज़्यादा तीखा। आँच से उतार कर 10 मिनट आराम दें, फिर उथले कटोरों में चमेली चावल के साथ परोसें, ऊपर कुछ कुटी मूँगफली छिड़कें — मसामन वो थाई करी है जो रात भर रखने पर और गहरी हो जाती है, और अगले दिन और भी अच्छी लगती है।","en":"Spoon the coconut cream into a heavy pot over medium heat and let it cook for 5 minutes, stirring, until the oil separates and the cream looks glossy and slightly grainy. Add the Massaman paste and the whole spices and fry for 3 minutes — the paste will darken and the kitchen should smell of cinnamon, cardamom and roasted cumin; this early bloom of the spices is what gives Massaman its Persian-inflected depth. Add the beef and turn it in the paste until every piece is dark red, pour in the coconut milk, tamarind paste and kaffir lime leaves, bring to a bare simmer and braise gently with the lid ajar for an hour and a half, stirring every 20 minutes — the beef is ready when it gives easily to a spoon but still holds its shape. Slide in the potatoes, onions and peanuts and continue cooking uncovered for another 30 minutes until the potatoes are tender and the gravy has thickened to a glossy rich brown; stir in the fish sauce and palm sugar at the end, balancing the salt-sweet-sour triangle until it tastes deep and round, neither too sweet nor too sharp. Rest off the heat for 10 minutes, then serve in shallow bowls with jasmine rice, scattered with a few crushed peanuts on top — Massaman is the Thai curry that gains depth overnight, and any leftovers taste better the next day."}},{"id":211,"servings":4,"tipType":"veg","pairingsType":"thai","nutrition":{"cal":180,"prot":6,"carb":28,"fat":6,"fib":4},"origin":{"hi":"थाईलैंड","en":"Thailand","ro":"Thailanda"},"name":{"hi":"सोम तम","en":"Som Tam","ro":"Som Tam"},"category":{"hi":"सलाद","en":"Salad","ro":"Salată"},"ingredients":{"hi":["हरा (कच्चा) पपीता 400 ग्राम, छीला और बहुत बारीक जूलियन कटा","चेरी टमाटर 4, आधे कटे","लंबी फलियाँ (yardlong) 2 या 4 हरी फलियाँ, 4 सेमी टुकड़ों में","लहसुन 2 कलियाँ, छिली","बर्ड्स आई मिर्च 2 (या स्वादानुसार)","ताड़ की चीनी 2 बड़े चम्मच","थाई फिश सॉस 2 बड़े चम्मच","1 नीबू (lime) का रस","इमली का गाढ़ा रस 1 बड़ा चम्मच","सूखी झींगा 1 बड़ा चम्मच","भुनी मूँगफली 2 बड़े चम्मच (कुछ कुटी, कुछ साबुत)","साथ में परोसने के लिए iceberg लेट्यूस या बंदगोभी के पत्ते (वैकल्पिक, पारंपरिक)"],"en":["400 g green (unripe) papaya, peeled and finely julienned","4 cherry tomatoes, halved","2 long beans (yardlong) or 4 green beans, cut into 4 cm lengths","2 garlic cloves, peeled","2 bird's eye chillies (or to taste)","2 tbsp palm sugar","2 tbsp Thai fish sauce","Juice of 1 lime","1 tbsp tamarind concentrate","1 tbsp dried shrimp","2 tbsp roasted peanuts (some crushed, some whole)","Iceberg lettuce or cabbage leaves to serve (optional, traditional)"],"ro":["400 g papaya verde (necoaptă), curățată și tăiată julienne foarte fin","4 roșii cherry, tăiate în jumătăți","2 fasole lungă (yardlong) sau 4 fire de fasole verde, tăiate în bucăți de 4 cm","2 căței de usturoi, curățați","2 ardei iuți bird's eye (sau după gust)","2 linguri zahăr de palmier","2 linguri sos de pește thailandez","Sucul de la 1 lime","1 lingură concentrat de tamarind","1 lingură creveți uscați","2 linguri arahide prăjite (unele zdrobite, altele întregi)","Frunze de salată iceberg sau varză pentru servit (opțional, tradițional)"]},"howIsMade":{"hi":"एक मिट्टी की ओखली (krok) या मज़बूत पत्थर की ओखली में लहसुन और मिर्च को साथ कूटें — पाउडर मत बनाएँ, बस उन्हें खोल दें — फिर ताड़ की चीनी डालें और थोड़ा और कूटें ताकि वो मिर्च के तेल में घुल जाए। फिश सॉस, नीबू का रस और इमली डालें, मूसल से चलाकर चीनी घोलें, फिर सूखी झींगा डालें और दो-तीन बार ठोकें ताकि वो ड्रेसिंग में चपटी होकर मिल जाएँ। लंबी फलियाँ और कटे टमाटर डालें और हलके से कूटें — हर एक पर पाँच-छह बार ठोकें, बस इतना कि वो थोड़े टूट जाएँ और उनका रस ड्रेसिंग में आ जाए — यहाँ मूसल मसाला बैठाने का औज़ार है, तोड़ने का नहीं। कद्दूकस किया पपीता दो बार में डालें, बीच-बीच में हलकी कुटाई और चम्मच से उलट-पुलट करते रहें, जब तक हर रेशा ड्रेसिंग में चमक न जाए लेकिन कुरकुरापन बना रहे, फिर मूँगफली डालें (साबुत क्रंच के लिए, कुटी हुई गहराई के लिए) और एक आख़िरी बार पलट दें। चखें — Som Tam को एक साथ चार स्वाद मारने चाहिए: खट्टा, नमकीन, मीठा, और एक उग्र मिर्ची-तीख़ापन — फिर उथले कटोरों में या लेट्यूस के पत्तों पर ढेर बना कर रखें, और चिपचिपे चावल या ग्रिल्ड चिकन के साथ तुरंत खाएँ।","en":"In a clay krok or sturdy stone mortar, pound the garlic and chillies together until bruised — not pulverised, just opened up — then add the palm sugar and pound a few more times to dissolve it into the chilli oil. Pour in the fish sauce, lime juice and tamarind, stir with the pestle until the sugar dissolves, then tip in the dried shrimp and pound a couple of times to flatten them into the dressing. Add the long beans and tomato halves and pound gently — five or six taps each, just enough to bruise them and release their juices into the dressing — the pestle here is a tool of seasoning, not destruction. Tip in the shredded papaya in two batches, alternating light pounding with turning everything with a spoon until each strand is glossy with the dressing but still crisp, then add the peanuts (whole for crunch, crushed for body) and toss one last time. Taste — Som Tam should hit four flavours at once: sour, salty, sweet and chilli-fierce — then pile into shallow bowls or onto lettuce leaves and eat immediately with sticky rice or grilled chicken."}},{"id":212,"servings":4,"tipType":"meat","pairingsType":"thai","nutrition":{"cal":720,"prot":32,"carb":60,"fat":38,"fib":4},"origin":{"hi":"थाईलैंड","en":"Thailand","ro":"Thailanda"},"name":{"hi":"खाओ सोई","en":"Khao Soi","ro":"Khao Soi"},"category":{"hi":"नूडल सूप","en":"Noodle soup","ro":"Tăiței în supă"},"ingredients":{"hi":["उत्तरी थाई khao soi करी पेस्ट 4 बड़े चम्मच (या रेड करी पेस्ट 3 बड़े चम्मच + करी पाउडर 1 छोटा चम्मच + हल्दी 1 छोटा चम्मच)","हड्डी सहित चिकन की जांघें 500 ग्राम या टुकड़ों में कटी चिकन लेग","फुल फैट नारियल का दूध 800 मिली","नारियल क्रीम 200 मिली","चिकन स्टॉक 500 मिली","थाई फिश सॉस 2 बड़े चम्मच","ताड़ की चीनी 1 बड़ा चम्मच","ताज़े अंडे वाले नूडल्स 400 ग्राम (या सूखे 300 ग्राम)","एक मुट्ठी नूडल्स तलने के लिए तटस्थ तेल","मेज़ पर निचोड़ने के लिए 2 नीबू (lime) का रस","गार्निश: कटी shallot, अचार वाली सरसों की पत्तियाँ, ताज़ा धनिया, नीबू के टुकड़े, मिर्च का तेल"],"en":["4 tbsp Northern Thai khao soi curry paste (or 3 tbsp red curry paste + 1 tsp curry powder + 1 tsp ground turmeric)","500 g bone-in chicken thighs or chicken legs cut into pieces","800 ml full-fat coconut milk","200 ml coconut cream","500 ml chicken stock","2 tbsp Thai fish sauce","1 tbsp palm sugar","400 g fresh egg noodles (or 300 g dried)","Neutral oil for deep-frying a handful of noodles","Juice of 2 limes, added at the table","Garnishes: sliced shallots, pickled mustard greens, fresh coriander, lime wedges, chilli oil"],"ro":["4 linguri pastă de curry Khao Soi din nordul Thailandei (sau 3 linguri pastă curry roșu + 1 linguriță curry pudră + 1 linguriță turmeric)","500 g pulpe de pui cu os sau pulpe întregi tăiate în bucăți","800 ml lapte de cocos gras","200 ml smântână de cocos","500 ml fond de pui","2 linguri sos de pește thailandez","1 lingură zahăr de palmier","400 g tăiței de ouă proaspeți (sau 300 g uscați)","Ulei neutru pentru a prăji o mână de tăiței","Sucul de la 2 lime, adăugat la masă","Garnituri: șalote feliate, frunze de muștar murate, coriandru proaspăt, felii de lime, ulei de chili"]},"howIsMade":{"hi":"एक भारी बर्तन में नारियल क्रीम मध्यम आँच पर 4–5 मिनट तक तब तक पकाएँ जब तक तेल अलग न हो जाए और क्रीम चमकदार न लगे, फिर khao soi पेस्ट डालें और 2–3 मिनट तक तब तक भूनें जब तक रंग गहरा हो जाए और रसोई में एक गहरी, भुनी हुई ख़ुशबू भर जाए — मध्य थाई करियों के मुक़ाबले भारी और मिट्टी जैसी, क्योंकि यह पेस्ट सूखे मसालों पर टिकी है। चिकन के टुकड़े डालें और पेस्ट में लपेट दें, नारियल का दूध और स्टॉक डालें, हल्की उबाल पर लाएँ और ढक्कन थोड़ा खुला रख कर 30–35 मिनट तक पकाएँ, जब तक चिकन हड्डी से अलग होने लायक नर्म न हो और शोरबा थोड़ा गाढ़ा न हो जाए; आख़िर में फिश सॉस और ताड़ की चीनी से स्वाद दें ताकि शोरबा गाढ़ा, हलका मीठा, और करी पेस्ट से आती हलकी खटास वाला हो। जब करी पक रही हो, ताज़े अंडे वाले नूडल्स की एक छोटी मुट्ठी लें, अतिरिक्त पानी झाड़ें, और 180°C तेल में 30–45 सेकंड तब तक तलें जब तक वो फूल कर सुनहरे न हो जाएँ — हर कटोरे के ऊपर रखा कुरकुरा ताज — फिर काग़ज़ पर निकाल लें। बाक़ी नूडल्स को सादे पानी में बस-बस नरम होने तक उबालें, जल्दी से छानें, और गहरे कटोरों में बाँट दें, ऊपर गरम करी डालें — हर कटोरे में कम से कम एक चिकन का टुकड़ा — फिर तले हुए नूडल्स ऊपर रखें। गार्निश को मेज़ पर घुमाएँ — shallot की कतरन, अचार वाली सरसों की पत्तियाँ, धनिया, आख़िर में निचोड़ने के लिए नीबू का एक टुकड़ा, और एक चम्मच मिर्च का तेल — यह व्यंजन कंट्रास्ट से जीता है (रेशम जैसा शोरबा, नीचे नरम नूडल्स, ऊपर कुरकुरे नूडल्स, कच्ची shallot की तीख़ी काट, अचार का खटास, नीबू की चमक), और हर कटोरा मेज़ पर ही बनता है।","en":"Heat the coconut cream in a heavy pot over medium heat for 4–5 minutes until the oil cracks out and the cream looks slick, then stir in the khao soi paste and fry for 2–3 minutes until it darkens and smells deeply toasted — heavier and earthier than central-Thai curries because the paste leans on dry spices. Add the chicken pieces and turn them in the paste until coated, pour in the coconut milk and stock, bring to a gentle simmer and cook with the lid ajar for 30–35 minutes until the chicken is meltingly tender and the broth has reduced a little; season with fish sauce and palm sugar towards the end so the broth is rich, gently sweet and faintly sour from the curry paste itself. While the curry simmers, take a small handful of the fresh egg noodles, shake off any excess water, and deep-fry in 180°C oil for 30–45 seconds until puffed and golden — the crispy crown for every bowl — then drain on paper. Boil the remaining noodles in plain water until just tender, drain quickly and divide between deep bowls, ladle over the hot curry with at least one piece of chicken per portion, and top with the fried noodles. Pass the garnishes round the table — sliced shallots, pickled mustard greens, coriander, a lime wedge to squeeze in last, and a spoon of chilli oil — the dish lives on contrast (silky soup, soft noodles below, crisp on top, raw shallot bite, pickle tang, lime brightness) and each bowl is built at the table."}},{"id":213,"servings":4,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":520,"prot":6,"carb":92,"fat":16,"fib":4},"origin":{"hi":"थाईलैंड","en":"Thailand","ro":"Thailanda"},"name":{"hi":"मैंगो स्टिकी राइस (Khao Niao Mamuang)","en":"Mango Sticky Rice (Khao Niao Mamuang)","ro":"Orez glutinos cu mango (Khao Niao Mamuang)"},"category":{"hi":"मिठाई","en":"Dessert","ro":"Desert"},"ingredients":{"hi":["थाई चिपचिपा चावल 300 ग्राम, ठंडे पानी में कम से कम 4 घंटे या रात भर भिगोया","फुल फैट नारियल का दूध 400 मिली","ताड़ की चीनी 80 ग्राम (या हल्की ब्राउन शुगर)","½ छोटा चम्मच नमक","1 पंडान का पत्ता, गाँठ में बँधा (वैकल्पिक, पारंपरिक)","2 पके पीले आम (Nam Dok Mai या Ataulfo), छिले और कटे","2 बड़े चम्मच भुने तिल या छिली मूँग दाल, सजावट के लिए","1 छोटा चम्मच चावल का आटा (वैकल्पिक, नमकीन टॉपिंग को गाढ़ा करने के लिए)"],"en":["300 g Thai glutinous (sticky) rice, soaked in cold water at least 4 hours or overnight","400 ml full-fat coconut milk","80 g palm sugar (or light brown sugar)","½ tsp salt","1 pandan leaf, tied in a knot (optional, traditional)","2 ripe yellow mangoes (Nam Dok Mai or Ataulfo), peeled and sliced","2 tbsp toasted sesame seeds or split mung beans, for garnish","1 tsp rice flour (optional, for thickening the salty topping)"],"ro":["300 g orez glutinos thailandez (lipicios), pus la înmuiat în apă rece minim 4 ore sau peste noapte","400 ml lapte de cocos gras","80 g zahăr de palmier (sau zahăr brun deschis)","½ linguriță sare","1 frunză de pandan, legată în nod (opțional, tradițional)","2 mango galbene coapte (Nam Dok Mai sau Ataulfo), curățate și feliate","2 linguri semințe de susan prăjite sau mazăre mungo decorticată, pentru garnitură","1 linguriță făină de orez (opțional, pentru a îngroșa topping-ul sărat)"]},"howIsMade":{"hi":"भिगोए हुए चावल छानें। एक स्टीमर की टोकरी में मसलिन कपड़ा या केले का पत्ता बिछाएँ, चावल उसमें डालें, और मध्यम उबाल पर ढक कर 20–25 मिनट तक भाप दें, आधे समय पर कपड़ा उठा कर चावल के ढेर को पलट दें ताकि एकसमान पके — दाने जब पारदर्शी, चमकदार और भीतर तक चबाने-योग्य नर्म हों, तब तैयार। जब चावल भाप में हो, एक छोटे पैन में 300 मिली नारियल का दूध, ताड़ की चीनी, नमक और गाँठ बँधे पंडान पत्ते को गरम करें, बस इतना चलाएँ कि चीनी घुल जाए — उबलने न दें; बचे हुए 100 मिली को नमकीन टॉपिंग के लिए अलग रखें। जब चावल भाप से निकले-निकले गरम हो, उसे एक चौड़े बाउल में पलटें, स्पैटुला से दो-तिहाई गरम मीठा नारियल दूध मिलाएँ कि हर दाना चमकदार हो जाए, फिर ढक कर 15–20 मिनट छोड़ दें ताकि चावल दूध को पी ले और नर्म पर्ल पुडिंग जैसी बनावट तक फूल जाए। नमकीन टॉपिंग के लिए, बचे 100 मिली नारियल दूध को एक भरी चुटकी नमक और 1 छोटा चम्मच चावल के आटे के साथ 2 मिनट तक, बस हल्का गाढ़ा होने तक उबालें। गरम नारियल वाले चावल को प्लेट पर ढेर बना कर रखें, बग़ल में आम के टुकड़े सजाएँ, ऊपर से नमकीन नारियल क्रीम डालें, भुने तिल या छिली मूँग दाल छिड़कें, और चम्मच से — हर निवाले में थोड़ा चावल और थोड़ा आम — खाएँ; गरम नारियल की मिठास और ठंडे फल की धार के बीच का यह कंट्रास्ट ही यह व्यंजन है।","en":"Drain the soaked rice; line a steamer basket with cheesecloth or banana leaf, tip in the rice and steam covered over a moderate boil for 20–25 minutes, lifting the cloth halfway to flip the mound so it cooks evenly — done when the grains are translucent, glossy and chewy-tender all the way through. While the rice steams, warm 300 ml of the coconut milk in a small saucepan with the palm sugar, salt and pandan leaf, stirring just enough to dissolve the sugar without bringing it to a boil; reserve the remaining 100 ml for the salty topping. When the rice comes hot off the steamer, tip it into a wide bowl, fold through two-thirds of the warm sweet coconut milk with a spatula until each grain glistens, then cover and rest 15–20 minutes so the rice drinks the milk and swells to a soft pearl-pudding consistency. For the salty topping, simmer the remaining 100 ml coconut milk with a generous pinch of salt and the teaspoon of rice flour for 2 minutes, just until it thickens lightly. Mound the warm coconut rice on a plate with the mango slices alongside, drizzle the salty coconut cream across the top, scatter toasted sesame seeds or split mung beans, and eat with a spoon, a little rice and a little mango in every bite — warm coconut-sweet against cool fruit-sharp is the dish itself."}},{"id":214,"tipType":"meat","pairingsType":"meat","origin":{"hi":"अंतर्राष्ट्रीय","en":"International","ro":"Internațional"},"name":{"hi":"लैम्ब स्टू","en":"Lamb Stew","ro":"Tocăniță de miel"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["800 ग्राम भेड़ का कंधा, टुकड़ों में","2 प्याज़","3 गाजर","3 आलू","2 लहसुन की कलियाँ","2 बड़े चम्मच टमाटर पेस्ट","500 मिली बीफ़ स्टॉक","थाइम, तेज़पत्ता","नमक, काली मिर्च, ज़ैतून का तेल"],"en":["800 g lamb shoulder, cubed","2 onions","3 carrots","3 potatoes","2 garlic cloves","2 tbsp tomato paste","500 ml beef stock","thyme, bay leaf","salt, pepper, olive oil"],"ro":["800 g pulpă de miel, cuburi","2 cepe","3 morcovi","3 cartofi","2 căței usturoi","2 linguri pastă de tomate","500 ml supă de carne","frunze de cimbru, dafin","sare, piper, ulei de măsline"]},"howIsMade":{"hi":"मेमने के कंधे को लगभग 4 सेमी के टुकड़ों में काटें — इतने बड़े कि लंबे पकाने के बाद भी मुलायम रहें और टूटें नहीं। उन्हें पूरी तरह सुखाएँ, उदारता से नमक और काली मिर्च लगाएँ, फिर बहुत हल्की मात्रा में मैदा से ढक दें ताकि ग्रेवी गाढ़ी हो। एक भारी कास्ट-आयरन बर्तन को तेल की पतली परत के साथ चमकने तक गरम करें, और मेमने को तीन-चार हिस्सों में बिना भीड़ किए गहरा भूरा होने तक भूनें — भीड़ करने पर मांस भाप में पक जाता है और गहरी परत नहीं बनती। हर हिस्से को प्लेट में निकाल लें। उसी चर्बी में बारीक कटा प्याज़ और लहसुन को पारदर्शी होने तक भूनें, टमाटर पेस्ट डालकर एक मिनट पकाएँ ताकि महक गोल हो जाए। मांस और उसका रस वापस डालें, गर्म स्टॉक इतना डालें कि बस ढक जाए, कुछ थाइम की टहनियाँ और एक तेजपत्ता डालें, हल्की उबाल लाएँ और सबसे धीमी आँच कर दें। ढक्कन लगाकर नब्बे मिनट पकाएँ — कभी भी ज़ोर का उबाल नहीं, बस हल्के बुलबुले — बीच में एक बार हिलाएँ। तिरछा कटा गाजर और मोमी आलू बड़े टुकड़ों में डालकर तीस-चालीस मिनट और पकाएँ, जब तक मेमना काँटे के स्पर्श से टूटने लगे और आलू अपनी आकृति बनाए रखें। चखें, नमक ठीक करें, तेजपत्ता निकाल लें। गहरे कटोरों में क्रिस्पी ब्रेड के साथ परोसें, और परोसने से पहले स्टू को आँच से उतारकर दस मिनट रहने दें ताकि शोरबा बँध जाए।","en":"Cut the lamb shoulder into roughly 4 cm cubes — large enough to stay tender through a long simmer without falling apart. Pat them completely dry and season generously with salt and pepper, then dust very lightly with flour to help the sauce thicken. Heat a heavy casserole or Dutch oven with a film of oil until it shimmers, and brown the lamb in three or four batches without crowding the pan — crowding steams the meat and you lose the deep crust. Set each batch aside on a plate. In the same fat, sweat finely chopped onion and garlic until translucent, then stir in tomato paste and let it cook a minute until it smells rounder. Return the lamb with any resting juices, pour in enough hot stock to just cover, add a few sprigs of thyme and a bay leaf, bring to a gentle simmer and lower the heat to the smallest possible. Cover and cook for ninety minutes — never let it boil, only bubble — stirring once. Add carrots cut on the bias and waxy potatoes in large chunks and cook another thirty to forty minutes, until the lamb pulls apart at the touch of a fork and the potatoes hold their shape. Taste, adjust salt, and lift out the bay. Serve in deep bowls with crusty bread, after letting the stew rest off the heat for ten minutes so the broth pulls together."}},{"id":215,"tipType":"salad","pairingsType":"salad","origin":{"hi":"यूनान","en":"Greece","ro":"Grecia"},"name":{"hi":"ग्रीक सलाद","en":"Greek Salad","ro":"Salată grecească"},"category":{"hi":"सलाद","en":"Salad","ro":"Salate"},"ingredients":{"hi":["4 पके टमाटर मोटे टुकड़ों में","1 बड़ा खीरा टुकड़ों में","1 हरी शिमला मिर्च","1 लाल प्याज़ पतले छल्ले","200 ग्राम फेटा चीज़ ब्लॉक","100 ग्राम कलामाता जैतून","2 बड़े चम्मच एक्स्ट्रा-वर्जिन ज़ैतून तेल","1 छोटा चम्मच सूखा ग्रीक ओरेगैनो","मोटा नमक"],"en":["4 ripe tomatoes, thickly sliced","1 large cucumber, sliced","1 green pepper","1 red onion, thinly ringed","200 g block feta","100 g Kalamata olives","2 tbsp extra-virgin olive oil","1 tsp dried Greek oregano","coarse salt"],"ro":["4 roșii coapte, tăiate felii groase","1 castravete mare, tăiat felii","1 ardei verde","1 ceapă roșie, tăiată rondele subțiri","200 g feta în bloc","100 g măsline Kalamata","2 linguri ulei de măsline extravirgin","1 linguriță oregano grecesc uscat","sare grunjoasă"]},"howIsMade":{"hi":"पके टमाटर मोटे काटें — कम-से-कम एक उँगली — फाँकों या टुकड़ों में, ताकि वे रस संभाले रखें, प्यूरी न बनें। खीरा अर्ध-चाँद, हरी शिमला मिर्च पतले छल्ले, लाल प्याज़ जितना पतला हो सके; तेज़ हो तो छल्लों को दस मिनट बर्फ़ीले पानी में रखें, तीखापन कम होगा पर कुरकुरापन बना रहेगा। सब चौड़े उथले बाउल में डालें, मोटे नमक की चुटकी डालें, और न मिलाएँ — ग्रीक इस सलाद को परतों में बनाते हैं, कभी नहीं हिलाते। साबुत कलामाता जैतून गुठली सहित बिखेरें। फेटा को बिना तोड़े एक पूरे टुकड़े के रूप में ऊपर रखें, ठीक वैसे जैसे क्रेटन ताबेर्ना में परोसा जाता है। एक्स्ट्रा-वर्जिन ज़ैतून तेल भरपूर डालें, फिर सूखा ओरेगैनो हथेलियों के बीच मसलकर पूरे सलाद पर छिड़कें। रस सोखने के लिए क्रिस्पी ब्रेड के साथ तुरंत परोसें।","en":"Slice ripe tomatoes thick — at least a finger across — into wedges or rounds, so they hold their juice rather than collapse into purée. Cut the cucumber into half-moons, the green pepper into thin rings, and the red onion paper-thin; if sharp, soak the rings in iced water for ten minutes to soften the bite while keeping the crunch. Combine in a wide, shallow bowl with a pinch of coarse salt and resist tossing — Greeks build this salad in layers, never mixed. Scatter the Kalamata olives whole, with their stones. Lay the feta on top as a single uncut slab, exactly as you'd be served in a Cretan taverna. Drizzle generously with extra-virgin olive oil, then shower with dried oregano rubbed between your palms to release the aroma. Serve immediately with crusty bread for mopping the juices."}},{"id":216,"tipType":"salad","pairingsType":"italian","origin":{"hi":"इटली","en":"Italy","ro":"Italia"},"name":{"hi":"कैप्रेज़ सलाद","en":"Caprese Salad","ro":"Salată Caprese"},"category":{"hi":"सलाद","en":"Salad","ro":"Salate"},"ingredients":{"hi":["3 पके टमाटर, टुकड़ों में","250 ग्राम बफ़ेलो मोज़रेला","ताज़ी तुलसी की पत्तियाँ","एक्स्ट्रा-वर्जिन ज़ैतून तेल","मोटा नमक","ताज़ी पिसी काली मिर्च","बाल्समिक सिरका (वैकल्पिक)"],"en":["3 ripe tomatoes, sliced","250 g buffalo mozzarella","fresh basil leaves","extra-virgin olive oil","coarse salt","freshly ground black pepper","balsamic vinegar (optional)"],"ro":["3 roșii coapte, tăiate felii","250 g mozzarella di bufala","frunze de busuioc proaspăt","ulei de măsline extravirgin","sare grunjoasă","piper negru proaspăt măcinat","oțet balsamic (opțional)"]},"howIsMade":{"hi":"मोज़ेरेला को परोसने से कम-से-कम तीस मिनट पहले फ्रिज से निकाल लें — ठंडी रहने पर इसकी मलाईदार बनावट खो जाती है और स्वाद सपाट हो जाता है। पके, सुगंधित टमाटर चुनें — Cuore di Bue से लेकर चेरी तक — बशर्ते वे गर्मियों की महक दें, और लगभग एक सेंटीमीटर मोटे टुकड़ों में काटें। मोज़ेरेला को भी उसी मोटाई में काटें। एक बड़ी सपाट प्लेट पर टमाटर और मोज़ेरेला के टुकड़े बारी-बारी से एक ही पंक्ति में थोड़ा सा ओवरलैप करते हुए रखें, और हर जोड़े के बीच एक साबुत तुलसी पत्ता रखें ताकि हरा रंग दिखे। एक्स्ट्रा-वर्जिन ज़ैतून तेल इतना डालें कि वह नीचे जमा हो जाए, फिर समुद्री नमक के कुछ फ्लेक्स और ताज़ी पिसी काली मिर्च छिड़कें। तुरंत कमरे के तापमान पर परोसें, क्रिस्पी ब्रेड के साथ। शुद्धतावादी बाल्समिक सिरका नहीं डालते — कैप्रेसे इसके बिना ही पैदा हुई और बिना ही सबसे अच्छी है।","en":"Take the mozzarella out of the fridge at least thirty minutes before serving — fridge-cold it loses its creaminess and the flavour stays flat. Choose ripe, fragrant tomatoes — anything from Cuore di Bue to cherries on the vine, as long as they smell of summer — and slice them about a centimetre thick. Cut the mozzarella into slices of the same thickness. On a large flat plate, alternate one slice of tomato with one of mozzarella in a single, slightly overlapping row, tucking a whole basil leaf between each pair so the green shows. Drizzle with extra-virgin olive oil until it pools at the base, season with a few flakes of sea salt and a turn of freshly cracked black pepper. Serve immediately at room temperature, with crusty bread. Purists refuse balsamic vinegar — Caprese was born without it and works best that way."}},{"id":217,"tipType":"pasta","pairingsType":"italian","origin":{"hi":"इटली","en":"Italy","ro":"Italia"},"name":{"hi":"लज़ानिए","en":"Lasagna","ro":"Lasagna"},"category":{"hi":"पास्ता","en":"Pasta","ro":"Paste"},"ingredients":{"hi":["300 ग्राम लज़ानिए शीट्स","500 ग्राम बीफ़ कीमा","1 प्याज़","2 लहसुन की कलियाँ","400 ग्राम टमाटर सॉस","300 मिली बेशामेल सॉस","150 ग्राम कद्दूकस Parmigiano","150 ग्राम मोज़रेला","नमक, काली मिर्च, ज़ैतून तेल"],"en":["300 g lasagna sheets","500 g beef mince","1 onion","2 garlic cloves","400 g tomato sauce","300 ml béchamel sauce","150 g Parmigiano grated","150 g mozzarella","salt, pepper, olive oil"],"ro":["300 g foi de lasagna","500 g vită tocată","1 ceapă","2 căței usturoi","400 g sos de roșii","300 ml sos béchamel","150 g Parmigiano ras","150 g mozzarella","sare, piper, ulei de măsline"]},"howIsMade":{"hi":"रागू से शुरू करें: एक्स्ट्रा-वर्जिन ज़ैतून तेल और मक्खन के एक टुकड़े में बारीक कटे प्याज़, गाजर और सेलरी को धीमी आँच पर दस मिनट तक भूनें — यह soffritto पूरे स्वाद की नींव है। आँच तेज़ करें, क़ीमा डालें और चम्मच की पीठ से तोड़ते हुए गहरा भूरा होने तक भूनें। एक गिलास रेड वाइन डालकर वाष्पीकृत होने दें, फिर टमाटर का passata, चुटकी भर नमक और कद्दूकस की हुई जायफल मिलाएँ। ढक्कन हटाकर सबसे धीमी आँच पर कम-से-कम एक घंटा — समय हो तो दो — पकाएँ, बीच-बीच में हिलाते रहें। साथ ही béchamel बनाएँ: मक्खन पिघलाएँ, मैदा डालें, एक मिनट पकाएँ, फिर गर्म दूध धीरे-धीरे डालते हुए व्हिस्क से लगातार हिलाएँ जब तक चिकनी और गाढ़ी न हो जाए; नमक और थोड़ा जायफल डालें। ओवन 180°C पर गरम करें। गहरी ट्रे के तल पर béchamel की पतली परत लगाएँ ताकि चिपके नहीं, फिर इस क्रम में परतें: पास्ता शीट, रागू, béchamel, मोटी मात्रा में कद्दूकस किया Parmigiano। कम-से-कम पाँच परतें बनाएँ, ऊपर béchamel और एक अंतिम Parmigiano की वर्षा। 35–40 मिनट बेक करें जब तक ऊपर सुनहरा और किनारे बुलबुले न छोड़ें। काटने से पहले पंद्रह मिनट विश्राम दें — यह अनिवार्य है, वरना परतें फिसल जाती हैं।","en":"Start with the ragù: gently soften finely chopped onion, carrot and celery in olive oil and a knob of butter for ten minutes — the soffritto is the base of all the flavour. Raise the heat, add the minced beef and brown it deeply, breaking it up with the back of a spoon. Pour in a glass of red wine and let it evaporate, then add the tomato passata, a pinch of salt and a grating of nutmeg. Cook uncovered on the lowest flame for at least one hour — two if you have time — stirring every so often. Meanwhile, make the béchamel: melt butter, whisk in flour, cook a minute, then gradually pour in warm milk while whisking until smooth and thickened; season with salt and a touch of nutmeg. Heat the oven to 180°C. Spoon a thin layer of béchamel into the base of a deep dish to prevent sticking, then layer in this order: pasta sheets, ragù, béchamel, a generous grating of Parmigiano. Repeat for at least five layers, ending with béchamel and a final shower of Parmigiano. Bake 35–40 minutes until the top is golden and the edges bubble. Rest fifteen minutes before cutting — this is non-negotiable, or the layers slide."}},{"id":218,"tipType":"salad","pairingsType":"salad","origin":{"hi":"फ़्रांस","en":"France","ro":"Franța"},"name":{"hi":"निसवाज़ सलाद","en":"Salade Niçoise","ro":"Salată Niçoise"},"category":{"hi":"सलाद","en":"Salad","ro":"Salate"},"ingredients":{"hi":["200 ग्राम तेल में डिब्बाबंद टूना","4 कड़े उबले अंडे","200 ग्राम हरी फलियाँ","300 ग्राम नए आलू","12 निसवाज़ ज़ैतून","4 एंकोवी फ़िले","2 टमाटर","2 बड़े चम्मच ज़ैतून तेल","वाइन सिरका, नमक, काली मिर्च"],"en":["200 g tinned tuna in oil","4 hard-boiled eggs","200 g green beans","300 g new potatoes","12 Niçoise olives","4 anchovy fillets","2 tomatoes","2 tbsp olive oil","wine vinegar, salt, pepper"],"ro":["200 g ton la conservă în ulei","4 ouă fierte tari","200 g fasole verde","300 g cartofi noi","12 măsline Niçoise","4 file de hamsii","2 roșii","2 linguri ulei de măsline","oțet de vin, sare, piper"]},"howIsMade":{"hi":"अंडों को ठंडे पानी से आठ मिनट उबालें, फिर तुरंत बर्फ़ीले पानी में डालें ताकि पकना रुक जाए और जर्दी मुलायम-सख्त रहे। नए आलू को साबुत नमक के पानी में तब तक उबालें जब तक चाकू की नोक बिना रोक के अंदर न जाए — लगभग पंद्रह मिनट — और गुनगुने में आधे काट लें ताकि वे ड्रेसिंग सोखें। हरी फलियों को खूब नमक डाले उबलते पानी में तीन मिनट उबालें, फिर बर्फ़ीले पानी में ठंडा करें ताकि वे कुरकुरी और चमकदार हरी रहें। एक बड़ी सपाट प्लेट पर साग का बिस्तर बिछाएँ और सब कुछ समूहों में बिना मिलाए सजाएँ — चौथाई अंडे, आधे आलू, फलियाँ, टमाटर के टुकड़े, टूना के टुकड़े, जैतून, ऊपर तिरछी रखी एंकोवी फिले। ज़ैतून तेल में थोड़ा वाइन सिरका डालकर फेटें, स्वाद डालें, और परोसने से ठीक पहले डालें। ठंडा करके, पर बर्फ़ीला नहीं — मेज़ पर लाएँ।","en":"Boil the eggs eight minutes from cold, then plunge straight into iced water to stop the cooking and keep the yolk just set. Cook the new potatoes whole in salted water until a knife tip slides in cleanly, around fifteen minutes, then halve them while still warm so they soak up the dressing. Blanch the green beans for three minutes in plenty of boiling salted water, then refresh in iced water so they stay snappy and bright. On a wide, flat plate, lay a bed of greens and arrange everything in groups rather than tossing — quartered eggs, potato halves, beans, tomato wedges, the tuna broken into chunks, olives, anchovy fillets draped across the top. Whisk olive oil with a splash of wine vinegar, season, and spoon over only just before serving. Bring to the table cool, not fridge-cold."}},{"id":219,"tipType":"meat","pairingsType":"meat","origin":{"hi":"रूस","en":"Russia","ro":"Rusia"},"name":{"hi":"बीफ़ स्ट्रोगानॉफ","en":"Beef Stroganoff","ro":"Boeuf Stroganoff"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["600 ग्राम बीफ़ टेंडरलॉइन, स्ट्रिप्स में","300 ग्राम बटन मशरूम","1 प्याज़","2 लहसुन की कलियाँ","200 मिली खट्टी क्रीम","2 बड़े चम्मच सरसों","200 मिली बीफ़ स्टॉक","2 बड़े चम्मच मक्खन","नमक, काली मिर्च, पार्सले"],"en":["600 g beef tenderloin, sliced into strips","300 g button mushrooms","1 onion","2 garlic cloves","200 ml sour cream","2 tbsp mustard","200 ml beef stock","2 tbsp butter","salt, pepper, parsley"],"ro":["600 g mușchi de vită, tăiat fâșii","300 g ciuperci champignon","1 ceapă","2 căței usturoi","200 ml smântână","2 linguri muștar","200 ml supă de vită","2 linguri unt","sare, piper, pătrunjel"]},"howIsMade":{"hi":"गोमांस के टेंडरलॉइन को रेशे के विपरीत पेंसिल से ज़्यादा मोटी न पट्टियों में काटें — मोटे टुकड़े इस छोटी पकाई के समय में सख्त रह जाते हैं। पूरी तरह सुखाएँ, नमक-काली मिर्च लगाएँ, और हल्की मैदा से ढक दें। एक चौड़ा पैन बहुत तेज़ गरम करें, मक्खन का एक टुकड़ा और तेल डालें, और मांस को दो-तीन बार में, बिना भीड़ किए, हर तरफ़ केवल तीस सेकंड सेंकें — बाहर सुनहरा, अंदर हल्का गुलाबी। प्लेट पर निकाल कर आराम दें। उसी पैन में आँच कम करें, बारीक कटे प्याज़ को मक्खन में नरम होने तक भूनें, फिर मशरूम डालें और पहले तीन मिनट बिना हिलाए गहरे रंग का होने दें। बीफ़ स्टॉक और थोड़ा-सा ब्रांडी (यदि हो) डालें, तले के सारे भूरे टुकड़े खुरचें और आधा होने तक उबालें। पैन को आँच से पूरी तरह उतार लें — यही महत्वपूर्ण क़दम है — और खट्टी क्रीम तथा सरसों डालकर चिकना होने तक मिलाएँ; अगर अभी उबला, क्रीम फट जाएगी। मांस और उसका रस वापस पैन में लौटाएँ, हल्के से घुमाकर गरम करें, नमक चखें और कटा हुआ अजमोद छिड़कें। तुरंत मक्खन लगे नूडल्स, आलू-प्यूरी या भाप के चावल पर परोसें।","en":"Cut the beef tenderloin into strips against the grain, no thicker than a pencil — thicker pieces stay tough in the short cook time. Pat them completely dry, season with salt and pepper, then dust lightly with flour. Heat a wide pan very hot, add a knob of butter and oil, and sear the beef in two or three batches without crowding the pan, just thirty seconds a side, until browned outside and still pink within. Lift onto a plate and rest. In the same pan, lower the heat and soften finely sliced onion in butter, then add the mushrooms and let them brown deeply without stirring for the first three minutes. Pour in the beef stock and a splash of brandy if you have it, scrape up every brown bit from the base, and reduce by half. Take the pan completely off the heat — the critical step — and stir in the sour cream and the mustard until smooth; if it boils now, the cream splits. Return the beef and any resting juices to the pan, swirl through to warm, taste for salt, and shower with chopped parsley. Serve immediately over buttered noodles, mash, or steamed rice."}},{"id":222,"tipType":"meat","pairingsType":"meat","origin":{"hi":"फ़्रांस","en":"France","ro":"Franța"},"name":{"hi":"कोक ओ वैन","en":"Coq au Vin","ro":"Coq au vin"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["1 साबुत चिकन, 8 टुकड़ों में","200 ग्राम पनचेटा या बेकन","250 ग्राम बटन मशरूम","200 ग्राम पर्ल अनियन","1 बोतल बरगंडी रेड वाइन","2 लहसुन की कलियाँ","2 गाजर","थाइम, तेज़पत्ता","मक्खन, मैदा, नमक, काली मिर्च, पार्सले"],"en":["1 whole chicken, cut into 8 pieces","200 g pancetta or bacon","250 g button mushrooms","200 g pearl onions","1 bottle red Burgundy wine","2 garlic cloves","2 carrots","thyme, bay leaf","butter, flour, salt, pepper, parsley"],"ro":["1 pui întreg, tăiat în 8 bucăți","200 g pancetta sau bacon","250 g ciuperci champignon","200 g ceapă mică","1 sticlă vin roșu Burgundia","2 căței usturoi","2 morcovi","cimbru, dafin","unt, făină, sare, piper, pătrunjel"]},"howIsMade":{"hi":"एक रात पहले, चिकन को आठ टुकड़ों में काटें और लाल बरगंडी वाइन में तेजपत्ता, थाइम, आधी प्याज़ और कुछ काली मिर्च के दानों के साथ डुबो दें; ढककर रात भर फ्रिज में रखें ताकि वाइन मांस में रिस जाए और मैरिनेड पक्षी की महक सोख ले। अगले दिन चिकन निकालें और हर टुकड़े को अच्छी तरह सुखाएँ — गीली त्वचा नहीं भुनती, यही यहाँ का बड़ा पाप है। मैरिनेड बचा कर रखें। एक भारी कास्ट-आयरन बर्तन में कटी हुई पंचेटा को कुरकुरा होने तक भूनें, निकाल लें; उसी चर्बी में चिकन को दो हिस्सों में, पहले त्वचा वाला हिस्सा नीचे रखते हुए, गहरे महोगनी रंग तक भूनें। निकालकर अलग रखें। उसी बर्तन में बारीक कटा प्याज़, लहसुन और गाजर भूनें, एक चम्मच भर मैदा छिड़कें और एक मिनट हिलाएँ, फिर सहेजी हुई मैरिनेड और एक कलछुल गहरा चिकन स्टॉक डालें, तले के सारे भूरे टुकड़े खुरचें। चिकन और पंचेटा वापस डालें, हल्की उबाल लाएँ, ढककर सबसे धीमी आँच पर — या 160°C ओवन में — साठ मिनट पकाएँ, जब तक मांस मुलायम हो पर हड्डी से अभी भी लगा रहे। साथ ही अलग-अलग कड़ाहियों में पर्ल प्याज़ को मक्खन में अम्बर रंग का और मशरूम को गहरे भूरे रंग का होने तक भूनें — कभी एक साथ नहीं, वरना एक-दूसरे को भाप में पका देंगे। अंतिम पंद्रह मिनट में दोनों को बर्तन में डालें, नमक चखें, आँच से उतारकर ठंडे मक्खन का एक टुकड़ा घुमाकर मिलाएँ और अजमोद छिड़कें। आलू-प्यूरी या मक्खन वाले नूडल्स के साथ परोसें, ताकि सॉस की हर बूँद पकड़ी जाए।","en":"The night before, joint the chicken into eight pieces and submerge in red Burgundy with bay, thyme, a halved onion and a few peppercorns; cover and refrigerate overnight so the wine penetrates the flesh and the marinade takes on the bird's perfume. Next day, lift the chicken out and pat each piece bone-dry — wet skin will not brown, which is the cardinal sin here. Reserve the marinade. In a heavy cast-iron pot, render diced pancetta until crisp; lift it out and brown the chicken in the rendered fat in two batches, skin-side first, until each piece is mahogany. Set aside. In the same pot, sweat finely chopped onion, garlic and carrot, scatter a heaped spoonful of flour over and stir for a minute, then pour in the reserved marinade and a ladle of dark chicken stock, scraping every brown trace from the bottom. Return the chicken and pancetta, bring to a gentle simmer, cover and cook on the lowest flame — or in a 160°C oven — for sixty minutes, until the meat is tender but still clings to the bone. While it cooks, sauté the pearl onions in butter until amber and the mushrooms in a separate pan until deeply browned — never together, or they steam each other. Slip both into the pot for the last fifteen minutes, taste for salt, finish with a knob of cold butter swirled in off the heat and a shower of parsley. Serve with mashed potato or buttered noodles to catch every drop of sauce."}},{"id":223,"tipType":"meat","pairingsType":"meat","origin":{"hi":"पोलैंड","en":"Poland","ro":"Polonia"},"name":{"hi":"बिगोस","en":"Bigos","ro":"Bigos"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["500 ग्राम सॉरक्राट, छाना","300 ग्राम ताज़ी गोभी, कतरी","400 ग्राम पोर्क शोल्डर, टुकड़े","200 ग्राम स्मोक्ड सॉसेज (kielbasa)","150 ग्राम बेकन","1 प्याज़","2 लहसुन की कलियाँ","3 सूखे आलूबुखारे","ऑलस्पाइस, तेज़पत्ता, पपरिका, नमक, काली मिर्च"],"en":["500 g sauerkraut, drained","300 g fresh cabbage, shredded","400 g pork shoulder, cubed","200 g smoked sausage (kielbasa)","150 g bacon","1 onion","2 garlic cloves","3 dried prunes","allspice, bay leaf, paprika, salt, pepper"],"ro":["500 g varză murată, scurtă","300 g varză proaspătă, tăiată","400 g porc (umăr), cuburi","200 g cârnați afumați (kielbasa)","150 g bacon","1 ceapă","2 căței usturoi","3 prune uscate","ienibahar, dafin, boia, sare, piper"]},"howIsMade":{"hi":"बिगोस परतों में बनता है — पोलैंड का हर रसोइया अपना क्रम रखता है, लेकिन सिद्धांत एक है: धैर्य। एक भारी बर्तन में, क्यूब्स में कटे बेकन को मध्यम आँच पर तब तक भूनें जब तक चर्बी पिघले और टुकड़े कुरकुरे हों, फिर निकालकर अलग रखें। उसी चर्बी में पोर्क शोल्डर के क्यूब्स को दो हिस्सों में बिना भीड़ किए हर तरफ़ गहरा सुनहरा होने तक सेंकें और निकाल लें। उसी चर्बी में बारीक कटा प्याज़ और लहसुन भूनें, फिर मांस और बेकन वापस डालें। यदि बहुत खट्टी हो तो साउरक्राउट को छानकर हल्का धो लें, और उसे ताज़ी कटी पत्तागोभी, कटी हुई kielbasa, बीज निकाले prunes, कुछ तेजपत्ते, हथेली में मसले हुए जुनिपर बेरीज, ऑलस्पाइस और मीठी पपरिका के साथ डालें। पानी इतना डालें कि बस ढक जाए, हल्की उबाल लाएँ, सबसे धीमी आँच कर दें, ढक्कन लगाकर दो-तीन घंटे के लिए भूल जाएँ; हर आधे घंटे में हिलाएँ और पत्तागोभी को रस में दबा दें। अंत में नमक चखें। बिगोस का असली राज़: रात भर फ्रिज में रखें और अगले दिन धीरे-धीरे गरम करें — स्वाद आपस में जुड़ते हैं, धुएँ की गहराई बढ़ती है, शोरबा गाढ़ा हो जाता है।","en":"Bigos is built in layers — every cook in Poland has their own order, but the principle is patience. In a heavy pot, render diced bacon over medium heat until the fat runs and the pieces crisp, then lift them out and reserve. Brown the cubed pork shoulder in the bacon fat in two batches without crowding, until each side is deeply golden, and remove. Soften finely chopped onion and garlic in the same fat, then return the meat with the bacon. Drain and rinse the sauerkraut briefly if very sour, and pile it in with the shredded fresh cabbage, the sliced kielbasa, the pitted prunes, a few bay leaves, several juniper berries crushed in the palm, allspice and sweet paprika. Pour in just enough water to barely cover, bring to a gentle simmer, then lower the heat right down, cover, and forget about it for two to three hours, stirring every half hour and pushing the cabbage down into the liquor. Taste and adjust salt at the end. The honest secret of bigos: cool it overnight in the fridge, then warm slowly the next day — the flavours marry, the smoke deepens, the broth concentrates."}},{"id":226,"tipType":"asian","pairingsType":"asian","origin":{"hi":"वियतनाम","en":"Vietnam","ro":"Vietnam"},"name":{"hi":"वियतनामी स्प्रिंग रोल्स","en":"Vietnamese Spring Rolls","ro":"Rulouri vietnameze proaspete"},"category":{"hi":"दोपहर का भोजन","en":"Lunch","ro":"Prânz"},"ingredients":{"hi":["12 राइस पेपर शीट्स (bánh tráng)","200 ग्राम पकाए छिले झींगे","200 ग्राम पका पोर्क बेली, स्लाइस","100 ग्राम पका राइस वर्मीसैली","1 खीरा","सलाद पत्ते","ताज़ा पुदीना","ताज़ा धनिया","होइसिन या nước chấm सॉस डिप के लिए"],"en":["12 rice paper wrappers (bánh tráng)","200 g cooked prawns, peeled","200 g cooked pork belly, sliced","100 g cooked rice vermicelli","1 cucumber","lettuce leaves","fresh mint leaves","fresh coriander leaves","hoisin or nước chấm sauce for dipping"],"ro":["12 foi de orez (bánh tráng)","200 g creveți fierți, decojiți","200 g piept de porc fiert, feliat","100 g tăiței de orez fierți","1 castravete","frunze de salată","frunze de mentă proaspătă","frunze de coriandru","sos hoisin sau nước chấm pentru servit"]},"howIsMade":{"hi":"लपेटना शुरू करने से पहले सब कुछ तैयार रखें — एक बार शुरू कर दिया तो रुक नहीं सकते। राइस वर्मीसेली को पैकेट के अनुसार उबालें, ठंडे पानी में पूरी तरह ठंडा होने तक धोएँ और अच्छी तरह छान लें। पकी हुई पोर्क बेली को पतले टुकड़ों में काटें; पकी झींगा को लंबाई में दो भागों में बाँटें ताकि गुलाबी हिस्सा रैपर की ओर दिखे — खूबसूरत लगता है। खीरे को बारीक तीलियों में काटें। जड़ी-बूटियाँ, बिना डंडी की लेट्यूस पत्तियाँ, वर्मीसेली, खीरा और प्रोटीन एक ट्रे में हाथ की पहुँच में रखें। एक उथले बाउल में गुनगुना — गरम नहीं — पानी भरें। एक राइस पेपर को सिर्फ़ पाँच सेकंड डुबाएँ; जब उसे थोड़े गीले किचन टॉवल पर रखें तब भी वह ठोस लगना चाहिए, और लपेटते-लपेटते वह पूरी तरह नरम हो जाएगा। आपके सबसे क़रीब वाले एक-तिहाई हिस्से पर एक छोटी लेट्यूस पत्ती, कुछ पुदीने और धनिये के पत्ते, चुटकी भर वर्मीसेली, खीरे की तीलियाँ और पोर्क का एक टुकड़ा रखें। निचले किनारे को भरावन के ऊपर मोड़ें, दोनों किनारों को अंदर मोड़ें, और जब अंतिम लपेट शुरू करें तब झींगा के दो हिस्सों को गुलाबी सिरे नीचे की ओर रखें ताकि वे रैपर से झलकें। कसकर लपेटें ताकि सील हो जाए। तैयार रोल्स को सूखने से बचाने के लिए एक नम कपड़े से ढकें, और हॉइसिन-मूँगफली सॉस या nước chấm के साथ परोसें।","en":"Prep everything before you start rolling — once you begin you can't pause. Cook the rice vermicelli per the packet, rinse under cold water until completely cool, and drain well. Slice the cooked pork belly thinly; have the cooked prawns split lengthwise so the pink side faces the wrapper for presentation. Cut the cucumber into matchsticks. Pile the herbs, lettuce leaves with their stems removed, vermicelli, cucumber and proteins on a tray within easy reach. Fill a shallow bowl with warm — not hot — water. Dip one rice paper for just five seconds; it should still feel firm when you lay it on a slightly damp tea towel, and it will finish softening as you build the roll. On the third closest to you, lay a small lettuce leaf, then a few mint and coriander leaves, a pinch of vermicelli, cucumber matchsticks and a slice of pork. Fold the bottom edge up over the filling, then fold the two sides in, and as you start the final roll lay two prawn halves pink-side-down on the wrapper so they show through the finished roll. Roll tightly to seal. Cover finished rolls with a damp cloth so they don't dry, and serve with hoisin-peanut sauce or nước chấm."}},{"id":227,"tipType":"fish","pairingsType":"seafood","origin":{"hi":"भूमध्यसागरीय","en":"Mediterranean","ro":"Mediterana"},"name":{"hi":"ग्रिल्ड सी ब्रीम","en":"Grilled Sea Bream","ro":"Dorada la grătar"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["2 साबुत सी ब्रीम (हर एक लगभग 500 ग्राम)","2 नींबू","4 लहसुन की कलियाँ","ताज़ा डिल और पार्सले","थाइम","एक्स्ट्रा-वर्जिन ज़ैतून तेल","मोटा नमक","ताज़ी पिसी काली मिर्च"],"en":["2 whole sea bream (about 500 g each)","2 lemons","4 garlic cloves","fresh dill and parsley","thyme","extra-virgin olive oil","coarse salt","freshly ground black pepper"],"ro":["2 dorade întregi (cca 500 g fiecare)","2 lămâi","4 căței usturoi","mărar și pătrunjel proaspăt","cimbru","ulei de măsline extravirgin","sare grunjoasă","piper negru proaspăt"]},"howIsMade":{"hi":"जो सबसे ताज़ी सी ब्रीम मिल सके वही ख़रीदें — आँखें साफ़, गलफड़े चटक लाल, मांस दबाने पर वापस उठने वाला। यदि मछली विक्रेता ने पहले नहीं किया तो शल्क उतारें और साफ़ करें, सिर और पूँछ रहने दें। एक तेज़ चाकू से दोनों तरफ़ की त्वचा पर तीन तिरछे चीरे लगाएँ, लगभग हड्डी तक — इससे गर्मी समान रूप से अंदर पहुँचती है और त्वचा ग्रिल पर मुड़ती नहीं। बीस मिनट पहले अंदर और बाहर अच्छी तरह नमक छिड़कें ताकि नमक मांस में बैठ जाए और सतह कुरकुरी सुनहरी सेंक के लिए सूख जाए। पेट में नींबू के टुकड़े, कुचले हुए लहसुन, सोआ, अजमोद और थोड़ी थाइम भर दें। बाहर एक्स्ट्रा-वर्जिन ज़ैतून तेल लगाएँ। तेज़ कोयले की आँच पर हर तरफ़ 6–8 मिनट सेंकें, मछली केवल तब पलटें जब वह ख़ुद ग्रिल से अलग हो जाए — ज़ोर लगाने पर त्वचा फट जाती है। काँटे की नोक से जब मांस हड्डी से उठने लगे, तब वह तैयार है। आँच से उतारकर दो मिनट रहने दें, फिर पूरी मछली को लकड़ी की प्लेट पर मेज़ पर लाएँ — अतिरिक्त नींबू के टुकड़े, ताज़ा ज़ैतून तेल और ग्रीक सलाद साथ में।","en":"Buy the freshest sea bream you can find — clear eyes, bright red gills, firm flesh that springs back when pressed. Scale and gut the fish if your fishmonger hasn't, leaving head and tail on. With a sharp knife, score three diagonal slashes through the skin on each side, almost to the bone — they let the heat penetrate evenly and stop the skin from curling on the grill. Salt generously inside the cavity and on the skin, twenty minutes before cooking, so the salt has time to season the flesh and dry the surface for crisp browning. Stuff the belly with lemon slices, smashed garlic cloves, dill, parsley and a few sprigs of thyme. Brush the outside with extra-virgin olive oil. Build a hot charcoal fire and grill 6–8 minutes per side, flipping only when the fish releases cleanly from the grate — force it and the skin tears. The flesh is ready when it lifts off the bone with the tip of a fork. Rest two minutes off the heat, then carry the whole fish to the table on a board with extra lemon wedges, a drizzle of new olive oil, and a Greek salad alongside."}},{"id":228,"tipType":"fish","pairingsType":"seafood","origin":{"hi":"फ़्रांस","en":"France","ro":"Franța"},"name":{"hi":"प्रोवांस सी बास","en":"Sea Bass Provençal","ro":"Lup de mare provensal"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["2 सी बास फ़िले (हर एक लगभग 200 ग्राम)","400 ग्राम चेरी टमाटर","12 काले निसवाज़ ज़ैतून","2 लहसुन की कलियाँ","1 बड़ा चम्मच केपर्स","1 रोज़मेरी की डाली","ताज़ा थाइम","ज़ैतून तेल, ड्राई व्हाइट वाइन","नमक, काली मिर्च, तुलसी"],"en":["2 sea bass fillets (about 200 g each)","400 g cherry tomatoes","12 black Niçoise olives","2 garlic cloves","1 tbsp capers","1 sprig rosemary","fresh thyme","olive oil, dry white wine","salt, pepper, basil"],"ro":["2 fileuri de lup de mare (cca 200 g fiecare)","400 g roșii cherry","12 măsline negre Niçoise","2 căței usturoi","1 lingură capere","1 ramură rozmarin","cimbru proaspăt","ulei de măsline, vin alb sec","sare, piper, busuioc"]},"howIsMade":{"hi":"मछली से शुरू करें: यदि चमड़ी सहित फिले इस्तेमाल कर रहे हैं, उन्हें तीस मिनट पहले फ्रिज से निकाल लें ताकि कमरे के तापमान पर आ जाएँ, और हर टुकड़े को किचन पेपर से अच्छी तरह सुखाएँ — ठंडी, गीली मछली असमान पकती है और रंग नहीं पकड़ती। दोनों ओर हल्का नमक छिड़ककर अलग रखें। ओवन को 200°C पर गरम करें। एक चौड़े, तेल लगे बर्तन में आधे काटे हुए चेरी टमाटर कटी सतह ऊपर रखते हुए, साबुत Niçoise काले जैतून, धोए हुए केपर्स, पतले कटे कुछ लहसुन की कलियाँ, थाइम की टहनियाँ और रोज़मेरी की एक टहनी सजाएँ। और अधिक ज़ैतून तेल डालें, एक गिलास सूखी वाइट वाइन डालें, नमक और ताज़ी पिसी काली मिर्च से तड़काएँ। दस मिनट ओवन में रखें — टमाटर फटकर अपना रस छोड़ेंगे, वाइन आधी रह जाएगी और लहसुन की तीखापन कम होगा; यही वह सुगंधित बिछौना है जो मछली को थामेगा। बर्तन निकालें, फिले को चमड़ी ऊपर रखते हुए टमाटरों के बीच रखें और ट्रे के रस का थोड़ा-सा ऊपर डालें। आठ-दस मिनट और सेंकें, जब तक मांस अपारदर्शी न हो जाए और काँटे की नोक से अलग होने लगे, और चमड़ी पर कुछ सुनहरे धब्बे बन जाएँ। चाकू की नोक से बीच जाँचें: यदि बिना रुकावट अंदर जाए तो तैयार है। दो मिनट रहने दें, हाथ से तोड़े तुलसी के पत्ते ऊपर बिखेरें, और बर्तन को क्रिस्पी ब्रेड के साथ मेज़ पर लाएँ ताकि प्रोवांसी सॉस सोखी जा सके — इसके बिना आधा भोजन ट्रे में ही रह जाएगा।","en":"Start with the fish: if using skin-on fillets, take them out of the fridge thirty minutes ahead to temper, and pat each piece bone-dry with kitchen paper — cold, wet fish cooks unevenly and won't brown. Salt lightly on both sides and set aside. Heat the oven to 200°C. In a wide oiled dish, lay halved cherry tomatoes cut-side up, whole Niçoise olives, rinsed capers, a few thinly sliced garlic cloves, thyme sprigs and a single sprig of rosemary. Drizzle generously with more olive oil, pour in a glass of dry white wine, season with salt and freshly cracked pepper. Slide into the oven for ten minutes — the tomatoes need to burst and release their juices, the wine reduces by half, and the garlic loses its sharpness; this is how the aromatic bed for the fish is built. Pull the dish out, lay the fillets skin-up among the tomatoes and spoon some of the pan juices over them. Return for eight to ten minutes, until the flesh turns opaque and flakes at the tip of a fork, and the skin takes on a few golden patches. Check the centre with a knife tip: if it slides in without resistance, it is done. Rest two minutes, scatter torn basil leaves on top, and bring the dish to the table with crusty bread to mop the Provençal sauce — without it, half the meal stays in the pan."}},{"id":229,"tipType":"meat","pairingsType":"italian","origin":{"hi":"इटली","en":"Italy","ro":"Italia"},"name":{"hi":"रोस्ट चिकन डियावोला","en":"Roast Chicken Diavola","ro":"Pui la cuptor alla diavola"},"category":{"hi":"रात का खाना","en":"Dinner","ro":"Cină"},"ingredients":{"hi":["1 साबुत चिकन, spatchcock किया","4 लहसुन की कलियाँ, कुचली","2 बड़े चम्मच कुटी लाल मिर्च (peperoncino)","1 छोटा चम्मच स्मोक्ड पपरिका","1 नींबू (रस और छिलका)","3 बड़े चम्मच ज़ैतून तेल","थाइम और रोज़मेरी","मोटा नमक, काली मिर्च"],"en":["1 whole chicken, spatchcocked","4 garlic cloves, crushed","2 tbsp crushed chilli flakes (peperoncino)","1 tsp smoked paprika","1 lemon (juice and zest)","3 tbsp olive oil","thyme and rosemary","coarse salt, black pepper"],"ro":["1 pui întreg, despicat (spatchcocked)","4 căței usturoi zdrobiți","2 linguri ardei iute zdrobit (peperoncino)","1 linguriță boia afumată","1 lămâie (suc și coajă)","3 linguri ulei de măsline","cimbru și rozmarin","sare grunjoasă, piper negru"]},"howIsMade":{"hi":"यदि क़साई ने न किया हो तो चिकन को स्पैचकॉक करें: छाती नीचे रखें, मज़बूत किचन कैंची से रीढ़ की हड्डी को दोनों तरफ़ से काट कर निकाल दें, पलटें और छाती की हड्डी पर ज़ोर से दबाएँ जब तक वह चटक न जाए और मुर्गा सपाट न बैठ जाए। एक बड़े बाउल में ज़ैतून तेल, कुचला हुआ लहसुन, स्मोक्ड पपरिका, मोटा नमक, नींबू का रस और छिल्का, और एक बेधड़क मात्रा में कुटी हुई मिर्च की फुलकियाँ फेंटें — यही पूरे व्यंजन का व्यक्तित्व है। मैरिनेड को दोनों तरफ़ और त्वचा की हर तह में मलें, और कमरे के तापमान पर कम-से-कम एक घंटा रखें, या गहराई से रचने के लिए रात भर फ्रिज में ढक कर रखें। ओवन को 220°C तक गरम करें, साथ में एक भारी ट्रे भी अंदर रखें ताकि चिकन रखने पर सतह से 'सीज़' की आवाज़ आए। चिकन को त्वचा ऊपर रखते हुए गरम ट्रे पर रखें और एक दूसरी भारी पैन या एलुमिनियम फ़ॉइल में लपेटी ईंट से ऊपर से दबा दें — असली डियावोला प्रेस, जो त्वचा को आँच से चिपकाए रखता है ताकि अधिकतम कुरकुरापन आए। 35–40 मिनट सेंकें जब तक त्वचा महोगनी रंग न पकड़ ले और जाँघ की हड्डी के पास तापमान 75°C न पढ़े। फ़ॉइल से हल्के से ढक कर दस मिनट रहने दें, जोड़ों पर काटें और अतिरिक्त नींबू व ट्रे के रस के साथ परोसें।","en":"Spatchcock the chicken if your butcher hasn't: lay it breast-down, snip out the backbone along both sides with sturdy kitchen shears, flip and press firmly on the breastbone until it cracks and the bird lies flat. In a wide bowl whisk olive oil, crushed garlic, smoked paprika, coarse salt, lemon juice and zest, and a defiant amount of crushed chilli flakes — the dish's whole personality. Rub the marinade into both sides and into every fold of the skin, then leave the bird at least one hour at room temperature, or overnight covered in the fridge for deeper penetration. Heat the oven to 220°C with a heavy roasting tray inside, so the chicken hits a sizzling surface. Lay the chicken skin-up on the hot tray and weigh it down with a second heavy pan or a foil-wrapped brick — the authentic diavola press, which forces the skin into contact with the heat for maximum crispness. Roast 35–40 minutes until the skin is mahogany and a probe in the thigh near the bone reads 75°C. Rest ten minutes loosely tented with foil, carve through the joints, and serve with extra lemon wedges and the pan juices spooned over."}}];export default recipes;